INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('ab0a079f-5478-469a-af2f-377ae51fb7a5', '～あっての', NULL, 'N1', '名A＋（が）あっての＋名B', '名A＋（が）あっての＋名B', '表示条件，“正因为有了A，才有B的存在”。', '前项和后项是不同的名词。强调前项的助词「が」可以省略，后项也会以「もの」「こと」的形式出现，如「～あってのことだ」「～あってのものだ」。\n意思与「～があるからこそ」相同，“正因为……才……”。\n固定用法：「命あっての 物[もの] 種[だね]」/有了生命才会有一切；留得青山在，不怕没柴烧。', 1, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('adc96af5-28b2-4373-94a7-5ffecf7594cf', 'ab0a079f-5478-469a-af2f-377ae51fb7a5', '山田監督は私の恩人です。今の私があるのも監督あってのことです。', '山田監督は私のおんじんです。今の私があるのも監督あってのことです。', '山田教练是我的恩人。正是因为有教练的帮助，才有今天的我。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('7aac49f9-71cc-406f-9447-200b56d866ca', 'ab0a079f-5478-469a-af2f-377ae51fb7a5', 'つらい治療に耐え、病気を克服することができたのは、家族の励ましがあってのことだ。', 'つらい治療に耐え、病気をこくふくすることができたのは、家族の励ましがあってのことだ。', '我之所以能够克服治疗的痛苦，战胜病魔，正是因为有家人的支持和鼓励。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('824ec031-d99c-411b-a79e-d4de107f4849', 'ab0a079f-5478-469a-af2f-377ae51fb7a5', 'こうして私たちが商売を続けられるのも、お客様あってのものと感謝しております。', 'こうして私たちがしょうばいを続けられるのも、お客様あってのものと感謝しております。', '正因为有客户的支持才能持续经营下去，对此我们深表感谢。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('2aa1c6ef-2d1e-4d30-843e-5e674ade842a', '～ 以[い] 外[がい]の 何[なに]ものでもない', NULL, 'N1', '名＋以外の何ものでもない', '名＋以外の何ものでもない', '表示强调，“不是别的，正是……”。', '用在句末，强调「～は～です」句型中的「です」部分。', 2, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('c21fcb27-c8d3-461b-9d21-659fda068b87', '2aa1c6ef-2d1e-4d30-843e-5e674ade842a', '彼女を悩ませているのは仕事のストレス以外のなにものでもない。', '彼女を悩ませているのは仕事のストレス以外のなにものでもない。', '使她烦恼的正是工作压力。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('ecd85ef9-b4e2-4da6-93d0-cc0e6496923d', '2aa1c6ef-2d1e-4d30-843e-5e674ade842a', 'この世で生き延びる力というのは学力以外のなにものでもない。', 'このよで生き延びる力というのは学力以外のなにものでもない。', '使我们能够在这个社会上生活下去的能力，不是其他的就是学习能力。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('0d975d82-1af8-4509-82aa-d9b5ad6749a1', '2aa1c6ef-2d1e-4d30-843e-5e674ade842a', '今回の交通事故の原因は運転手の不注意以外のなにものでもない。', '今回の交通事故の原因は運転手の不注意以外のなにものでもない。', '正是司机的疏忽大意酿成了这起交通事故。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('231220c7-b8bd-44d8-96ff-b7460d871faa', '～いかんで/いかんでは/いかんによっては', NULL, 'N1', '名（の）＋いかんで/いかんでは/いかんによっては', '名（の）＋いかんで/いかんでは/いかんによっては', '表示前后两项的关联，根据前项不同，后项会采取相应措施。“取决于……”“根据……”。', '该句型用在句中，表示中顿。\n前项接续名词时，「の」可以省略。\n「～いかんで」的后项多是某个决定。\n「～いかんでは/いかんによっては」表示“取决于前项，后项有可能会变化”，可以和「～かもしれない」「～こともある」等连用。\n用法与「～ 次[し] 第[だい]で（は）/次第によっては」相同。', 3, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('101471d9-b042-415b-a507-2e1cf420dd37', '231220c7-b8bd-44d8-96ff-b7460d871faa', '出席状況·学業成績のいかんでは、奨学金の支給を停止することもある。', '出席状況·学業成績のいかんでは、奨学金の支給を停止することもある。', '根据出席情况和学习成绩，有可能会停止发放奖学金。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('81a29099-da01-4d1f-b877-fc709ec08106', '231220c7-b8bd-44d8-96ff-b7460d871faa', 'われわれの考え方いかんで、善と悪が分かれる。', 'われわれの考え方いかんで、ぜんとあくがわかれる。', '看问题的角度不同，善恶的标准也会随之变化。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('077e1331-37bb-4caf-ae86-4dbe7407c001', '231220c7-b8bd-44d8-96ff-b7460d871faa', '向こうの対応のいかんによっては、更に強い措置を取るかもしれない。', '向こうの対応のいかんによっては、更に強いそちを取るかもしれない。', '取决于对方的处理方式，我方有可能采取更强硬的措施。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('4778409d-17eb-4150-9e5b-d19770f73914', '～いかんにかかっている/いかんだ', NULL, 'N1', '名（の）＋いかんにかかっている/いかんだ', '名（の）＋いかんにかかっている/いかんだ', '表示前后两项的关联，前项会如何取决于后项。“……（会怎样），要看…”“取决于……”。', '该句型用在句末。\n用法与「～ 次[し] 第[だい]だ」相同。', 4, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('f7f8b414-df06-4b6d-9181-ccc20f33ec41', '4778409d-17eb-4150-9e5b-d19770f73914', '試合で逆転できるかどうかは、選手たちの意志いかんだ。', '試合でぎゃくてんできるかどうかは、選手たちの意志いかんだ。', '比赛中能否反超对手，取决于队员们的意志。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('e4d174c0-8703-472c-b4e5-d42440f85fe6', '4778409d-17eb-4150-9e5b-d19770f73914', '先方に納得してもらえるかどうかは、結局解釈の仕方いかんだ。', 'せんぽうになっとくしてもらえるかどうかは、結局解釈の仕方いかんだ。', '能否得到对方客户的谅解，最终取决于解释说明的方法。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('26789cf1-1795-4fb7-93e3-0f0d296557ca', '4778409d-17eb-4150-9e5b-d19770f73914', '今回の不祥事をどう扱うかは社員の考え方いかんにかかっている。', '今回のふしょうじをどうあつかうかは社員の考え方いかんにかかっている。', '怎么处理这次的丑闻，取决于员工自己的看法。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('3a8adac4-f579-469c-9e45-86830c6e8c8f', '～いかんにかかわらず/いかんによらず/いかんをとわず', NULL, 'N1', '名（の）＋いかんにかかわらず/いかんによらず/いかんをとわず', '名（の）＋いかんにかかわらず/いかんによらず/いかんをとわず', '表示不论前项如何，后项都不改变。“不管……（如何）”“不论……（如何）”。', '「いかん」的汉字写作「 如[い] 何[かん]」，该句型多用于比较正式的场合。\n「～かかわらず/よらず」前面的助词要用「に」；「～とわず」前面的助词要用「を」。\n常与「学歴」「天候」「国籍」「出身」「成績」「理由」等词或者是一些包含正反两个方面意思的词，如「 晴[せい] 雨[う]」「 成[せい] 否[ひ]」「 合[ごう] 否[ひ]」「 採[さい] 否[ひ]」等一起使用。', 5, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('6cbb0e69-6806-4df2-add5-bcccf641afe2', '3a8adac4-f579-469c-9e45-86830c6e8c8f', '出席欠席のいかんによらず、同封した葉書にてお返事くださるようおねがいいたします。', 'しゅっせきけっせきのいかんによらず、どうふうしたはがきにてお返事くださるようおねがいいたします。', '不管出席与否，请在信封内的明信片里作出回复。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('bdc090e7-6620-480d-8197-4da6f65bcf71', '3a8adac4-f579-469c-9e45-86830c6e8c8f', '理由のいかんにかかわらず、無断欠勤は認めない。', '理由のいかんにかかわらず、むだんけっきんはみとめない。', '不论出于什么理由都不允许无故旷工。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('0fe95da3-7628-4a8f-8c4a-0cbfb2925904', '3a8adac4-f579-469c-9e45-86830c6e8c8f', '成否のいかんをとわず、やってみることが何より大切だ。', 'せいひのいかんをとわず、やってみることが何より大切だ。', '不管成功与否，最重要的是尝试着去做做看。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('e31465e0-0df7-420a-9d59-36d00c66c60c', 'いざ～となると', NULL, 'N1', 'いざ＋動辞書形＋となると', 'いざ＋動辞書形＋となると', '表示假设，“一旦真的要……的话，就会……”。', '和动词原形一起使用，表示一旦要付诸实际行动的话就会出现困难。', 6, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('f0ffb5a8-6c15-4742-8494-810e0d9d03aa', 'e31465e0-0df7-420a-9d59-36d00c66c60c', '店には多くの魅力的な品が並んでいたが、いざ買うとなるとなかなか決心がつかなかった。', '店には多くのみりょくてきなしながならんでいたが、いざ買うとなるとなかなかけっしんがつかなかった。', '虽然商店里摆满了很多有吸引力的商品，但是一旦要选起来，还是拿不定主意。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('efa3acbd-2912-49a7-8799-cc4af131e124', 'e31465e0-0df7-420a-9d59-36d00c66c60c', '簡単そうに見えるが、いざ自分でやるとなると、なかなかうまくいかないものだ。', '簡単そうに見えるが、いざ自分でやるとなると、なかなかうまくいかないものだ。', '虽然看似简单，但一旦自己去做，就不是那么容易。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('6a172c81-70bd-4799-9969-25dcc3506b0a', 'e31465e0-0df7-420a-9d59-36d00c66c60c', 'レシピを見るだけでは簡単そうだったが、いざ作るとなると、あれ？これでいいのかな？と思うことが何度もあった。', 'レシピを見るだけでは簡単そうだったが、いざ作るとなると、あれ？これでいいのかな？と思うことが何度もあった。', '只看菜谱似乎很简单，但一旦要去做，就会觉得心里没底。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('5ed8e43e-e3ce-44eb-95ad-9b31bc3ccc22', 'いざとなると/いざとなれば/いざとなったら', NULL, 'N1', '作为惯用短语单独使用。', '作为惯用短语单独使用。', '“一旦发生问题……”“一旦有情况……”“万一……”“到了关键时刻，就会……”“一旦……就会”。', '「いざとなると」的后项多描述事情的进展情况，表示“一旦到了关键时候，事情的进展就会……”之意。多用在事情的进展不如想象中的那么顺利或者出乎意料的情况。', 7, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('341d1ab2-37e7-4a38-b13e-ad8df2ef4590', '5ed8e43e-e3ce-44eb-95ad-9b31bc3ccc22', '何度も練習してきたが、いざとなるとなかなか思うとおりに進まない。', '何度も練習してきたが、いざとなるとなかなか思うとおりにすすまない。', '虽然练习了好多次，但是到了关键时刻，还是无法如自己所愿顺利进行。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('2ad1738c-b685-4a48-bcf3-727f5315ca95', '5ed8e43e-e3ce-44eb-95ad-9b31bc3ccc22', 'いざとなれば仕事をやめてふるさとに帰ることもできる。', 'いざとなれば仕事をやめてふるさとに帰ることもできる。', '万一真的待不下去了，可以辞职回老家。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('91e1698e-636e-4838-ba80-9845874dc72c', '5ed8e43e-e3ce-44eb-95ad-9b31bc3ccc22', 'いざとなったら110番に通報してください。', 'ひゃくとおばんにつうほうしてください。', '万一碰到麻烦，请打110报警。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('638eb1f0-b56b-4bc5-8197-2458bf02e3ed', '今[いま]ひとつ～（ない）', NULL, 'N1', '今[いま]ひとつ～（ない）', '今[いま]ひとつ～（ない）', '表示评价，“还差一点”“还有欠缺”。', '该句型也可以用「 今[いま] 一[いち]～ない」的形式。', 8, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('eaed3086-b1e4-47b1-8e46-9428458cf213', '638eb1f0-b56b-4bc5-8197-2458bf02e3ed', '昨日、話題のその映画を見たが、今ひとつ迫力が足りない気がした。', '昨日、話題のその映画を見たが、今ひとつ迫力が足りない気がした。', '昨天去看了最近成为话题的那部影片，但是我感觉震撼力还不够。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('0b825880-3436-49c6-a17c-6da50bb22b8a', '638eb1f0-b56b-4bc5-8197-2458bf02e3ed', '人気作家の最新作を読んではいるが、今ひとつうまく理解できない。', '人気作家の最新作を読んではいるが、今ひとつうまく理解できない。', '那位人气作家的最新作品我虽然读过了，但还是不太能理解。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('f2c09ce1-4482-45f6-aeaa-1250fb825e0c', '638eb1f0-b56b-4bc5-8197-2458bf02e3ed', 'このカバンは使い勝手はよいが、デザインが今ひとつだ。', 'このカバンはつかいがってはよいが、デザインが今ひとつだ。', '这个包用起来很方便，但是设计方面有所欠缺。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('0c36df9c-6e7d-49ee-8ad7-eff31b157ed7', '言[い]わずもがな', NULL, 'N1', '言わずもがな＋の＋名', '言わずもがな＋の＋名\n名＋は言わずもがな', '“不应该说的……”“不说为妙的……”。\n表示前后两项的关联，不仅前项，后项也是同样。“……自不必说，……（也）”。', '「言わずもがなだ」用在句末，意思是“不应该说的”。「言わずもがな＋の」修饰名词作定语，意思是“不应该说的……”“不说为妙的……”。\n「言わずもがなだ」与「言わないほうがいい」意思相同。\n「もがな」是一个终助词，出现在古典日语的文言体中，表示愿望。前面多用「ず」形接续。类似于「～があればいいなあ」「～といいなあ」，意思是“要是……就好了”。\n用法与「～は言うまでもなく～も」「～はもちろん」相同。', 9, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('307814cf-a96e-4fc6-a53c-57a46a732f75', '0c36df9c-6e7d-49ee-8ad7-eff31b157ed7', 'あんまり腹が立ったので、つい言わずもがなのことを言ってしまった。', 'あんまり腹が立ったので、つい言わずもがなのことを言ってしまった。', '因为太生气了，不由得说了些不该说的话。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('fd02db13-304e-4503-a5ec-4118e32f4b5d', '0c36df9c-6e7d-49ee-8ad7-eff31b157ed7', '皆の前で言わずもがなのことを言ってしまって後悔している。', '皆の前で言わずもがなのことを言ってしまって後悔している。', '在大家面前说了一些不该说的话，真是后悔。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('df8fa602-597e-4bad-993e-a0ccd1d8cb1a', '0c36df9c-6e7d-49ee-8ad7-eff31b157ed7', 'そんなことは言わずもがなだ。', 'そんなことは言わずもがなだ。', '那种事不说为妙。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('3756627c-18b4-4a68-a8dd-d470e35a7386', '0c36df9c-6e7d-49ee-8ad7-eff31b157ed7', '学生は言わずもがな、教師まで集まった。', '学生は言わずもがな、教師まで集まった。', '学生自不必说，连教师都到场了。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('619c3f9b-e74e-41af-8aba-f3f76763ddd8', '0c36df9c-6e7d-49ee-8ad7-eff31b157ed7', '彼は英語は言わずもがな、スペイン語もできる。', '彼は英語は言わずもがな、スペイン語もできる。', '英语自然不用说，他连西班牙语也会讲。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('a4801aa7-7e63-468f-8a95-e8151ced9819', '0c36df9c-6e7d-49ee-8ad7-eff31b157ed7', '若者は言わずもがな、お年寄りまでも彼女が出演するドラマに夢中になっている。', '若者は言わずもがな、お年寄りまでも彼女が出演するドラマに夢中になっている。', '年轻人自不必说，就连老年人也喜欢她演的连续剧。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('aea779b4-6f7e-43ef-b718-01a3b14ebc5e', '～（よ）うが/（よ）うと', NULL, 'N1', '～（よ）うが/（よ）うと', '～（よ）うが/（よ）うと', '表示假定条件的逆接，无论前项如何，后项都不会有太大变化。“无论……都……”“即使……也……”“不管……也……”。', '常与「どんなに」「いくら」「たとえ」「 誰[だれ]」「 何[なん]」等一些程度副词或疑问词一起使用。', 10, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('f0d3e027-9b3f-4e32-9410-cc325d28d8af', 'aea779b4-6f7e-43ef-b718-01a3b14ebc5e', '西川高校の森キャプテンは、次の対戦相手が優秀候補の北第一高校に決定したことについて、「たとえ相手がどういうチームだろうと精一杯やるだけです。」と語った。', 'にしかわ高校のもりキャプテンは、次のたいせん相手が優秀こうほせいいっぱいやるだけです。」とかたった。', '西川高中下场比赛的对手定下来是冠军的有力争夺者北第一高中，对此，西川高中的森教练说“无论对手是支什么样的队伍，我们都只有全力以赴。”', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('ab858891-992a-4d18-baca-5bbdd69112aa', 'aea779b4-6f7e-43ef-b718-01a3b14ebc5e', 'この仕事は誰がやろうが、結果は同じだと思う。', 'この仕事は誰がやろうが、結果は同じだと思う。', '我觉得这份工作不管谁去做，结果都是一样的。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('8a9293a6-9a55-4e91-a905-5cb77fea743f', 'aea779b4-6f7e-43ef-b718-01a3b14ebc5e', 'どんなに数学が得意だろうと、試験のときは油断してはならない。', 'どんなに数学が得意だろうと、試験のときはゆだんしてはならない。', '不管数学再怎么好，考试的时候也不能掉以轻心。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('c3dd8cac-0af2-4dcb-8d8c-fdd912301df3', '～（よ）うが～（よ）うが/（よ）うと～（よ）うと', NULL, 'N1', '～（よ）うが～（よ）うが/（よ）うと～（よ）うと', '～（よ）うが～（よ）うが/（よ）うと～（よ）うと', '表示假定条件的逆接，“无论……也好，……也好，都……”。', '前项和后项多为意思相对或者相反的词，意思与「～ても～ても」相同。\n「～（よ）うが～（よ）うが」和「～（よ）うと～（よ）うと」意思相同。前后两项所用的助词要一致，如「～が～が」「～と～と」。\n后项多用「～つもりだ/たい/変わらない/変えない/かまわない/勝手だ/自由だ」等一些表示决心、意志、评价、要求的表达方式。', 11, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('30455a3d-f73c-4170-8332-fdbc2449dc51', 'c3dd8cac-0af2-4dcb-8d8c-fdd912301df3', 'タバコの値段が上がろうと下がろうと、タバコを吸わない私にとってはどうでもいいことだ。', 'タバコの値段が上がろうと下がろうと、タバコを吸わない私にとってはどうでもいいことだ。', '无论香烟的价格上涨也好下跌也罢，对于不吸烟的我来说，是无所谓的事。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('4e698792-41fb-4939-a035-5c5ca7777eda', 'c3dd8cac-0af2-4dcb-8d8c-fdd912301df3', 'ほかの人に笑われようがバカにされようが、やりたいことをやるつもりです。', 'ほかの人に笑われようがバカにされようが、やりたいことをやるつもりです。', '被别人嘲笑也好，受歧视也好，我想做自己想做的事情。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('b956ed5a-96d8-4977-8976-f2efb1b1d37f', 'c3dd8cac-0af2-4dcb-8d8c-fdd912301df3', 'アクセサリーの値段は高かろうと安かろうと、つける人の好みと趣味だ。', 'アクセサリーの値段は高かろうと安かろうと、つける人のこのみと趣味だ。', '昂贵的首饰也好，便宜的首饰也好，只是看佩戴者的爱好和兴趣罢了。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('15abb219-9db6-47c1-b556-cb9e9f58cf5f', '～（よ）うが～まいが/（よ）うと～まいと', NULL, 'N1', '動意向形＋が＋動―まい形＋が', '動意向形＋が＋動―まい形＋が\n動意向形＋と＋動―まい形＋と', '表示假定条件的逆接，无论前项做或不做，结果都不会改变（后项都成立）。“无论是……还是……”“无论是否……都……”。', '该句型前后使用同一动词，前面接续动词的意志形，后面接续动词的「まい」形式。\n动词接续「～まい」时的变化方式。\n1类动词：動辞書形＋まい。如「帰るまい」。\n2类动词：動辞書形·ない形＋まい。如「食べるまい」「食べまい」。\n3类动词：動辞書形·ない形＋まい。如「するまい」「来るまい」「しまい」「来まい」。\n「～（よ）うが～まいが」和「～（よ）うと～まいと」意思相同，类似于「～ても～なくても～」。前后两项所用的助词要一致，如「～が～が」「～と～と」。\n后项多用「～つもりだ/たい/変わらない/変えない/かまわない/勝手だ/自由だ」等一些表示决心、意志、评价、要求的表达方式。', 12, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('8709e982-00e9-49ba-a5da-e5f94d703e96', '15abb219-9db6-47c1-b556-cb9e9f58cf5f', '周囲の人が反対しようとしまいと、私の気持ちは変わらない。', '周囲の人が反対しようとしまいと、私の気持ちは変わらない。', '不管周围的人反对与否，我的主意已定。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('9022fa3f-349b-4400-be77-ca11ba6a11a0', '15abb219-9db6-47c1-b556-cb9e9f58cf5f', '雨が降ろうが降るまいが、出かけるつもりだ。', '雨が降ろうが降るまいが、出かけるつもりだ。', '不管下不下雨，都要出去。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('219ec763-130c-4665-aec7-9f8e5af1d8cc', '15abb219-9db6-47c1-b556-cb9e9f58cf5f', '夏休みのキャンプに参加しようがしまいが、皆の自由だ。', '夏休みのキャンプに参加しようがしまいが、皆の自由だ。', '是否参加本次夏令营活动是大家的自由。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('2129e0b2-e6ef-48dd-a481-9ba36d89d1b8', '～（よ）うとも/くとも', NULL, 'N1', '～（よ）うとも/くとも', '～（よ）うとも/くとも', '表示假定条件的逆接，无论前项如何，或者不管前项到了什么程度，后项都不会有改变。“无论……都……”“即使……也……”“不管……也……”。', '常与「どんなに」「いくら」「たとえ」「誰」「何」等一些程度副词或疑问词一起使用，用法与「～ても/でも」相同。\n后项多用「～つもりだ/たい/変わらない/変えない/かまわない/勝手だ/自由だ」等一些表示决心、意志、评价、要求的表达方式。', 13, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('24ac37ab-5fac-4d93-967e-140bd25a1d11', '2129e0b2-e6ef-48dd-a481-9ba36d89d1b8', '周囲からどのような批判を浴びようとも、自らの考えを最後まで貫くべきだ。', '周囲からどのようなひはんをあびようとも、自らの考えを最後までつらぬくべきだ。', '无论遭受周围人怎样的批判的声音，我都应该将自己的想法贯彻到底。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('eb352aff-659a-4c15-b805-1f9ce8a275b4', '2129e0b2-e6ef-48dd-a481-9ba36d89d1b8', '母はどんなに辛くとも、決してぐちを言わなかった。', '母はどんなに辛くとも、決してぐちを言わなかった。', '母亲不管多么辛苦，从来不抱怨。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('d8de1552-592f-425e-9318-a2ae8acb5998', '2129e0b2-e6ef-48dd-a481-9ba36d89d1b8', 'どんなに反対されようとも、自分が正しいと思う道を進みたい。', 'どんなに反対されようとも、自分が正しいと思う道を進みたい。', '不管大家怎么反对，我会坚持走自己认为正确的路。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('1768890a-ebd5-455e-b14b-0ca40d3edb4c', '～（よ）うにも～ない', NULL, 'N1', '動意向形＋にも＋動ない形－ない', '動意向形＋にも＋動ない形－ない', '表示无法做到某事，“即使想……也不能……”“即使想……也没办法……”。', '前后为同一动词重复时，后项要用动词可能形的否定形式。如：「帰ろうにも帰れない」。\n固定用法：「言うに言えない」/没法讲述的；说不出口的。', 14, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('a24b3acc-0f4b-417c-b3b1-be7b7336a312', '1768890a-ebd5-455e-b14b-0ca40d3edb4c', '風邪で喉が痛くて、声を出そうにも出せない。', '風邪で喉が痛くて、声を出そうにも出せない。', '感冒了嗓子痛，即使想说话也发不出声音。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('6fae0579-d2db-4008-860b-15baece40837', '1768890a-ebd5-455e-b14b-0ca40d3edb4c', 'こんなに騒がしい部屋では、赤ん坊を寝かせようにも寝かせられない。', 'こんなにさわがしい部屋では、赤ん坊を寝かせようにも寝かせられない。', '房间里这么吵，想哄孩子睡觉也没有办法。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('38f54596-c184-4c8f-a66b-6b61ef3e450b', '1768890a-ebd5-455e-b14b-0ca40d3edb4c', '大きな声で助けを呼ぼうにも誰も来ない。', '大きな声で助けを呼ぼうにも誰も来ない。', '大声呼救也没有人出现。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('589006ed-0f9e-4a37-9790-45268574f56c', '1768890a-ebd5-455e-b14b-0ca40d3edb4c', '彼女が会社を辞めたのには、言うに言えない事情があったに違いない。', '彼女が会社を辞めたのには、言うに言えない事情があったに違いない。', '她之所以辞职一定有一些无法跟大家言明的原因。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('6d332de7-a85c-4ced-af19-98b86095ad3a', '～か 否[いな]か', NULL, 'N1', '動辞書形·た形/イ形/ナ形語幹（である）/名（である）＋か否か', '動辞書形·た形/イ形/ナ形語幹（である）/名（である）＋か否か', '“是否……”。', '是比较生硬的书面用语，一般不用在口语中。\n意思与「～かどうか」相同。', 15, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('2cf5f93d-39cb-4994-a9a7-72ccb40d8625', '6d332de7-a85c-4ced-af19-98b86095ad3a', 'その新たな雇用対策が有効であるかいなか、結果が出るのはまだ先のことだ。', 'その新たな雇用対策が有効であるかいなか、結果が出るのはまだ先のことだ。', '新的雇佣政策是否有效，要过一段时间才能知道。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('bd3356a1-9966-4f4e-b190-937f7da541d2', '6d332de7-a85c-4ced-af19-98b86095ad3a', '秘密を打ち明けるべきかいなかで悩んでいます。', '秘密を打ち明けるべきかいなかで悩んでいます。', '是否该把秘密讲出来呢，为此我感到烦恼。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('16bb6373-b7c7-4bfe-b22e-755f60182c63', '6d332de7-a85c-4ced-af19-98b86095ad3a', '不良少年たちのたむろ迷惑行為を通報するかいなかで迷った。', '不良少年たちのたむろ迷惑行為を通報するかいなかで迷った。', '犹豫着是否要将一群不良少年的非法聚集行为报警。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('45a12955-910c-4735-9924-cd8664df4250', '～ 限[かぎ]りだ', NULL, 'N1', '～ 限[かぎ]りだ', '～ 限[かぎ]りだ', '表示一种强烈的感情，“无比……”“非常……”“……极了”。', '常用「うれしい」「寂しい」「羨ましい」「残念な」「心細い」「悲しい」等一些表示情感的词。', 16, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('7945b602-1641-4c2a-871d-b2fb57b82621', '45a12955-910c-4735-9924-cd8664df4250', '自分の作品がこんなに大勢の人に評価されるとは、本当にうれしい限りだ。', '自分の作品がこんなに大勢の人に評価されるとは、本当にうれしい限りだ。', '自己的作品能够得到这么多人的好评让我很开心。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('5be70527-06d0-4a71-81f7-b2964a64915d', '45a12955-910c-4735-9924-cd8664df4250', '小学校からずっと仲のよかった彼女が遠くに引っ越すのは、寂しい限りだ。', '小学校からずっと仲のよかった彼女が遠くに引っ越すのは、寂しい限りだ。', '从小学开始关系一直很好的朋友要搬家到很远的地方，让我觉得很寂寞。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('4bb8a6f1-c259-4176-bfc9-1f3485f40b7c', '45a12955-910c-4735-9924-cd8664df4250', '一家揃って海外旅行に行くなんて、羨ましい限りだ。', 'いっかそろって海外旅行に行くなんて、羨ましい限りだ。', '全家人一起到国外旅行，真是让人无比羡慕。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('5213094a-3f5b-4c24-b0e7-a6eb0a981bef', '～が 最[さい] 後[ご]/たら最後', NULL, 'N1', '動た形＋が最後/ら最後', '動た形＋が最後/ら最後', '表示假定条件，“一旦……就……”。', '表示“某事一旦发生就必定……”的意思，后续为说话人意志或者必然发生的状况的表达方式。', 17, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('3f64b05c-80e7-4668-9f41-799487594da9', '5213094a-3f5b-4c24-b0e7-a6eb0a981bef', '信用というものは、いったん失ったが最後、取り戻すのは難しい。', '信用というものは、いったん失ったが最後、取り戻すのは難しい。', '信用一旦失去了，就难以挽回。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('9b3f18d3-277e-4945-822d-3798cad9e3ce', '5213094a-3f5b-4c24-b0e7-a6eb0a981bef', 'こんな貴重な本は、一度手放したがさいご、二度とこの手には戻って来ないだろう。', 'こんな貴重な本は、一度てばなしたがさいご、二度とこの手には戻って来ないだろう。', '如此珍贵的书，一旦脱手就再也无法找回来吧。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('28448e04-ec90-4c57-a9bc-0066dd4150ed', '5213094a-3f5b-4c24-b0e7-a6eb0a981bef', 'それを言ったら最後、君たち二人の友情は完全にこわれてしまうよ。', 'それを言ったら最後、君たち二人の友情は完全にこわれてしまうよ。', '一旦说出那句话，你俩的友谊就会彻底决裂的。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('f8dd17cb-b41d-4c84-b127-7c421859073b', '～かたがた', NULL, 'N1', '名＋かたがた', '名＋かたがた', '表示某个行为同时具有两个目的，“顺便……”。', '是比较正式的表达方式，意思与「～を兼ねて」相同。\n常与「ごあいさつ」「お礼」「お詫び」「お見舞い」「ご報告」等词一起使用。', 18, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('c40c2cca-b1db-43e0-8e01-45319eaa0e8b', 'f8dd17cb-b41d-4c84-b127-7c421859073b', '近くに用事があったものですから、先日のお礼かたがた伺いました。', '近くに用事があったものですから、先日のお礼かたがた伺いました。', '刚好到附近有点事，顺便过来拜访一下，表示对前几天的感谢。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('ff80488b-c749-4854-9fc9-a852f92334ad', 'f8dd17cb-b41d-4c84-b127-7c421859073b', '先日お世話になったお礼かたがた、部長のお宅にお寄りしました。', '先日お世話になったお礼かたがた、部長のお宅にお寄りしました。', '为了感谢前几天部长的帮助，顺便去了部长家一趟。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('442208c5-504e-499c-b680-c7d5954d31d8', 'f8dd17cb-b41d-4c84-b127-7c421859073b', '帰国のあいさつかたがたおみやげを持って先生のお宅を訪問した。', '帰国のあいさつかたがたおみやげを持って先生のお宅を訪問した。', '回国的时候为了问候老师，带了点礼物去老师家里拜访。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('0d1c1acc-6c21-4d20-9bb1-17175030bef5', '～かたわら', NULL, 'N1', '名＋の/動辞書形＋かたわら', '名＋の/動辞書形＋かたわら', '表示集中主要精力做某件事的同时，顺便做另外一件事。“一边……一边……”。', '常指主要的职业和副业的关系。\n「～かたわら」多用来描述长时间坚持做的事情，其用法与「～ながら」的用法不同。「～ながら」表示短时间内同时做两个动作。', 19, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('90ce22aa-0589-41da-b828-6b1dee6a4bfa', '0d1c1acc-6c21-4d20-9bb1-17175030bef5', '彼は歌手としての活動のかたわら、小説家としても活躍している。', '彼は歌手としての活動のかたわら、小説家としても活躍している。', '他作为歌手积极从事各种活动的同时，作为小说家也很活跃。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('fdb3f4a2-b2e3-4df0-991a-8f585efca5bc', '0d1c1acc-6c21-4d20-9bb1-17175030bef5', '彼は会社勤めのかたわら、福祉活動に積極的に取り組んでいる。', '彼は会社勤めのかたわら、福祉活動に積極的に取り組んでいる。', '他在上班的同时，还积极参加和福利事业有关的工作。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('0923e288-2167-4d1e-88bb-a81589425946', '0d1c1acc-6c21-4d20-9bb1-17175030bef5', 'A氏は不動産業を営むかたわら、暇を見つけてはボランティア活動をしている。', 'A氏は不動産業をいとなむかたわら、暇を見つけてはボランティア活動をしている。', 'A先生在经营房产的同时，还抽空参加志愿者活动。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('88292d72-fcce-4ed8-9047-d1295a9a8c4b', '～がてら', NULL, 'N1', '動ます形/名＋がてら', '動ます形/名＋がてら', '表示在进行某一动作的同时，也兼做其他。“顺便……”。', '「～がてら」的后面多用一些表示移动性的动词，如「行く」「買う」「寄る」等。\n与「～ついでに」意思相同，但是接续不同，「～ついでに」的接续是「名＋の/動辞書形·た形＋ついでに」。', 20, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('6957a807-a55a-45c0-b08b-79f81bda8ec5', '88292d72-fcce-4ed8-9047-d1295a9a8c4b', '週末にはドライブがてら、新しい博物館まで行ってみようと思う。', '週末にはドライブがてら、新しい博物館まで行ってみようと思う。', '我想周末去兜风的时候，顺便到新开的博物馆去看看。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('99a88dc2-686b-42cb-82de-5e245d5630d2', '88292d72-fcce-4ed8-9047-d1295a9a8c4b', '散歩がてら、ちょっとたばこを買ってきます。', '散歩がてら、ちょっとたばこを買ってきます。', '我出去散步的时候，顺便买包烟回来。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('fb48b699-6d2b-4f3e-8e2c-d07c430f17f0', '88292d72-fcce-4ed8-9047-d1295a9a8c4b', '近くにお越しの際は、遊びがてら、うちにお寄りください。', '近くにお越しのさいは、遊びがてら、うちにおよりください。', '有机会来附近的时候，请顺便到我家里坐坐。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('8ddd556f-2ccd-4ec1-ba28-dca9b57d7d9d', '～が 早[はや]いか', NULL, 'N1', '動辞書形·た形＋が早いか', '動辞書形·た形＋が早いか', '表示前项动作发生后紧接着进行下一个动作，或在某个瞬间发生了什么情况。“刚刚……就……”。', '后项多是以表示过去的时态「た」结束的句子，用来描述已经结束的事情。\n后项不能用表示决心、意志、愿望、命令的表达方式。', 21, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('7f851754-3d18-4356-acee-0b424b1047ee', '8ddd556f-2ccd-4ec1-ba28-dca9b57d7d9d', '授業終了のベルを聞くが早いか、生徒たちは教室を飛び出して行った。', '授業終了のベルを聞くが早いか、生徒たちは教室を飛び出して行った。', '下课铃声刚响学生们就飞奔出了教室。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('634ea2c0-72f7-4424-a01a-bf80dfe3f00d', '8ddd556f-2ccd-4ec1-ba28-dca9b57d7d9d', '子どもたちは動物園に着くが早いかおやつを食べだした。', '子どもたちは動物園に着くが早いかおやつを食べだした。', '孩子们刚到动物园就开始吃东西。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('0a0ce02b-16d5-44d0-b098-a407bc5aab33', '8ddd556f-2ccd-4ec1-ba28-dca9b57d7d9d', '彼女はとても忙しいらしい。食事をとるが早いか、仕事に向かった。', '彼女はとても忙しいらしい。食事をとるが早いか、仕事に向かった。', '她好像很忙，刚吃完饭就去工作了。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('ad9a0edd-4ad5-4800-b000-5cb7842e206c', '～からある/からする/からの', NULL, 'N1', '名＋からある/からする/からの', '名＋からある/からする/からの', '表示强调，强调大、多、重、长等。“足有……”“竟有……”“多达……”“高达……”“重达……”。', '「～からある」前面多用表示数量、长度、大小、长短、高矮等数量名词，「～からする」前面多用表示金额的数量词，「～からの」前面多用表示人数的数量词。\n「～からある」「～からする」既可以放在句中也可以放在句末，「～からの」用在句中。\n注意与「名＋からなる」的区别。「名＋からなる」的意思是“由……组成”。', 22, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('2d80ac2d-e29d-4875-83bb-e16ca22aba1e', 'ad9a0edd-4ad5-4800-b000-5cb7842e206c', '100キロからある荷物を3階まで運ぶには、足腰の強い人が3人は必要だ。', '100キロからある荷物を3階まで運ぶには、あしこしの強い人が3人は必要だ。', '要把重达100千克的行李搬上三楼，至少需要3个力气大的人。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('3439efbc-561d-4e53-be1e-e155827455e9', 'ad9a0edd-4ad5-4800-b000-5cb7842e206c', '身長2メートルからある男が、突然、目の前に現れた。', '身長2メートルからある男が、突然、目の前に現れた。', '一个高达2米的男人突然出现在我面前。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('a08afb0c-f506-4509-8590-b059cee3eb28', 'ad9a0edd-4ad5-4800-b000-5cb7842e206c', '彼女は40億円からする遺産を相続したそうだ。', '彼女は40億円からする遺産をそうぞくしたそうだ。', '听说她继承了多达40亿日元的遗产。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('abc2a5a0-38d8-4a85-b208-1b086668b746', 'ad9a0edd-4ad5-4800-b000-5cb7842e206c', 'きょうのスピーチ大会には500人からの人が集まった。', 'きょうのスピーチ大会には500人からの人が集まった。', '今天的演讲比赛聚集了500多人。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('9e2bec24-28d0-462f-a5a5-66bcd89cf3eb', 'ad9a0edd-4ad5-4800-b000-5cb7842e206c', '地震の被害を受けた地域に、10数名の専門家からなる救援隊が派遣された。', '地震の被害を受けた地域に、10数名の専門家からなる救援隊が派遣された。', '派遣了由数十名专家组成的救援队奔赴灾区。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('feac27ee-33c5-4898-af1f-6f0d192a3634', '～ 嫌[きら]いがある', NULL, 'N1', '名＋の/動辞書形＋嫌いがある', '名＋の/動辞書形＋嫌いがある', '表示倾向、特征，“有……的倾向”“有点……”。', '多指某个人的某种不好的特征，表示消极的意思。', 23, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('23116c33-2a91-419e-9d13-93ff6c3d983b', 'feac27ee-33c5-4898-af1f-6f0d192a3634', '彼はいつも物事を悲観的に考える嫌いがある。', '彼はいつも物事をひかん的に考える嫌いがある。', '他看问题有些消极。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('c6c087d2-509b-4fb8-ada2-bc91f16a60e3', 'feac27ee-33c5-4898-af1f-6f0d192a3634', '人は年をとると、周りの人の忠告に耳を貸さなくなる嫌いがある。', '人は年をとると、周りの人の忠告に耳を貸さなくなる嫌いがある。', '人上了年纪往往很难听进别人的忠告。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('d1e08ca8-47fc-4d30-8507-6c36c7ca59e0', 'feac27ee-33c5-4898-af1f-6f0d192a3634', '話をおもしろくするためだろうか、彼はものごとを大げさに言うきらいがある。', '話をおもしろくするためだろうか、彼はものごとを大げさに言うきらいがある。', '也许是为了使自己的话有意思，他讲话总喜欢夸张。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('62e4a530-e7df-4749-b0f5-e267f400993b', '～ 極[きわ]まる/極まりない', NULL, 'N1', 'ナ形語幹＋極まる/極まりない', 'ナ形語幹＋極まる/極まりない', '表示说话人很强烈的语气，“极其……”“非常……”。', '「極まる」与「極まりない」虽然形式上像反义词，但都表示“很……”“非常……”之意，既可以作定语修饰名词，也可以用在句末。\n「極まる」「極まりない」一般不用过去和否定的形式。如「極まりなかった」「極まらない」等就是错误的。\n固定用法：「失礼極まる態度」/极其失礼的态度，「危険極まる行為」/特别危险的行为，「残念極まりない」/十分遗憾。', 24, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('c199ea36-85d4-4792-b0ea-f53f5833e020', '62e4a530-e7df-4749-b0f5-e267f400993b', '自ら進んでプロジェクトを企画したのに、途中で辞めるなんて無責任きわまりない。', 'みずからすすんでプロジェクトを企画したのに、途中で辞めるなんて無責任きわまりない。', '自己主动提出的项目却在中途退出，太没有责任心了。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('919311be-18c4-45b5-88e7-e23e9076dbec', '62e4a530-e7df-4749-b0f5-e267f400993b', '食事をしているときまで、他人のたばこの煙を吸わされるのは、迷惑きわまりない。', '食事をしているときまで、他人のたばこのけむりを吸わされるのは、迷惑きわまりない。', '甚至连吃饭的时候都有人在旁边抽烟，实在让我不能忍受。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('cd5791ac-ea09-4e30-adcb-18fef5dea2c2', '62e4a530-e7df-4749-b0f5-e267f400993b', '私は、彼の失礼きわまりない態度に我慢できなかった。', '私は、彼の失礼きわまりない態度に我慢できなかった。', '他那种无礼的态度实在让我受不了。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('06ca24f0-1cbb-44a8-91cf-13ca2fd842c0', '～ごとき/ごとく/ごとし', NULL, 'N1', '～ごとき/ごとく/ごとし', '～ごとき/ごとく/ごとし', '表示比喻、举例，“像……一样”“如……”“就像……”。', '「～ごとき」用法与「～ような」相同，可以直接作定语修饰名词。\n「～ごとく」用法与「～ように」相同，用在句中后接动词、形容词、副词。\n「～ごとし」用法与「～ようだ」相同，放在句末。\n「～ごとき/ごとく/ごとし」是古典日语中文言体的用法。', 25, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('7614055c-b396-475e-98a8-f82af20777c8', '06ca24f0-1cbb-44a8-91cf-13ca2fd842c0', '「反省」とは、あたかも他人を眺めるがごとく自らを客観的に観察して行う精神活動である。', '「反省」とは、あたかも他人を眺めるがごとく自らを客観的に観察して行う精神活動である。', '所谓反省是指像观察他人那样客观地省察自己的精神活动。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('45c8c327-1631-4820-96e0-b30e00175085', '06ca24f0-1cbb-44a8-91cf-13ca2fd842c0', '暑い日に草むしりをしていたら、汗が滝のごとく流れてきた。', '暑い日に草むしりをしていたら、汗がたきのごとく流れてきた。', '在大热天拔草后，汗如雨下。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('91a7b895-7fa0-46a9-b34e-24a56004164f', '06ca24f0-1cbb-44a8-91cf-13ca2fd842c0', '犯人は飛ぶがごとき勢いで、逃げ出した。', 'いきおいで、逃げ出した。', '犯人飞一般地逃走了。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('2a865bb4-5b4d-414f-a810-a063ab7c6f7e', '06ca24f0-1cbb-44a8-91cf-13ca2fd842c0', '光陰矢のごとし。', 'こういんやのごとし。', '光阴似箭。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('bd61c129-8b57-4b1d-b3d6-b90d448acc60', '～ごとき/ごとく/ごとし', NULL, 'N1', '名＋ごとき', '名＋ごとき', '表示一种语气，“……之类的（又怎能……呢）”“……等（怎么能够……呢）”。', '用来描述别人时，表示轻视、否定之意；用来指自己时，表示自谦。\n在「ごとき」的两种不同的用法中，名词的接续方式也不一样，要注意。', 26, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('52065d45-1767-434f-8d65-cba054d39bc5', 'bd61c129-8b57-4b1d-b3d6-b90d448acc60', '私の気持ちが、あなたごときにわかるものか。', '私の気持ちが、あなたごときにわかるものか。', '我的心情，你岂能明白。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('dd6364e5-7e48-42d1-bb35-e891ad8bb548', 'bd61c129-8b57-4b1d-b3d6-b90d448acc60', 'わたしごとき新人にこんな大切な仕事ができるものかと心配です。', 'わたしごとき新人にこんな大切な仕事ができるものかと心配です。', '我很担心像我这样的新手能否胜任如此重要的工作。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('4b19c411-f3d0-43d7-9d61-52bc5c2fb86e', '～ことだし', NULL, 'N1', '動/イ形/ナ形/名の名詞修飾形＋ことだし', '動/イ形/ナ形/名の名詞修飾形＋ことだし', '用来陈述其中的一个理由，“也因为……”。', '后项多用判断、决定、要求、号召等表达方式，如「～ましょう」、「～ましょうか」等。', 27, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('f1a64190-de3a-4568-979b-f7316cd1b127', '4b19c411-f3d0-43d7-9d61-52bc5c2fb86e', '皆さんはもうお帰りになったことだし、そろそろ会場を片づけましょう。', '皆さんはもうお帰りになったことだし、そろそろ会場を片づけましょう。', '大家也差不多都走了，我们开始收拾会场吧。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('6febfb25-66a7-45d6-9225-1aaeecab3016', '4b19c411-f3d0-43d7-9d61-52bc5c2fb86e', '雨もやんだことだし、そろそろ帰りましょうか。', '雨もやんだことだし、そろそろ帰りましょうか。', '雨也停了，我们差不多回去吧。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('a4cc6263-5ab2-470b-a52d-a362c22716a2', '4b19c411-f3d0-43d7-9d61-52bc5c2fb86e', '全員そろったことだし、そろそろ会議を始めましょう。', '全員そろったことだし、そろそろ会議を始めましょう。', '人也到齐了，开始开会吧。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('8f9dea49-1364-4836-b9d9-3d186195660b', '～こととて', NULL, 'N1', '動/イ形/ナ形/名の名詞修飾形＋こととて', '動/イ形/ナ形/名の名詞修飾形＋こととて', '表示原因，“因为……所以……”。', '是比较正式的表达方式。\n常用「知らぬこととて」「はじめてのこととて」「新人のこととて」「わからないこととて」等，后项多用请多包涵、关照的表达方式。', 28, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('4399cba0-1f7c-4be6-8b17-871d5085a259', '8f9dea49-1364-4836-b9d9-3d186195660b', '連絡もなしにお客様がいらっしゃったが、急なこととて、何のおもてなしもできなかった。', '連絡もなしにお客様がいらっしゃったが、急なこととて、何のおもてなしもできなかった。', '客人事先没有联络突然造访，来不及准备，未能好好招待。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('4d8c5e73-aec5-453d-8d68-f5649e9fc2de', '8f9dea49-1364-4836-b9d9-3d186195660b', '新しい家を買うため見に行ったが、夜のこととて日当たりのことはわからなかった。', 'ひあたりのことはわからなかった。', '为了买房去看了一个地方，但因为是晚上去的，所以不知道房子的采光怎样。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('3e293099-a9b1-42e4-83a1-739ea90b0590', '8f9dea49-1364-4836-b9d9-3d186195660b', '昼間はにぎやかなこの町も、早朝のこととてあたりに人影はなかった。', '昼間はにぎやかなこの町も、そうちょうのこととてあたりにひとかげはなかった。', '因为是在清晨，平时热闹繁华的这条街上人影也见不到。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('a80b6aff-d68f-4a23-9ebd-882657d69f16', '～ことなしに', NULL, 'N1', '動辞書形＋ことなしに', '動辞書形＋ことなしに', '表示假定的条件，如果没有前项就很难有后项。“如果不……就（不能）……”“如果没有……就（无法）……”。\n表示附带关系，“没有……就……”。表示在没有做某件事的状态下，就进行了后项的动作。', '意思与「～がなくては/がなければ」相同，后项多用否定。\n用法与「～をしないまま」相同。', 29, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('479f98be-a558-4f2c-8cc9-c238acdc9582', 'a80b6aff-d68f-4a23-9ebd-882657d69f16', '農業での品種改良の技術は日々進歩している。しかし、どんなに優れた技術であっても自然への影響を考えることなしには進められない。', '農業での品種改良の技術はひび進歩している。しかし、どんなにすぐれた技術であっても自然への影響を考えることなしには進められない。', '农业的品种改良技术日新月异。但是如果不考虑对环境的影响，即使技术再好也是难以推广的。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('ee5e8246-697c-4daa-94c7-bb3b33ccda3f', 'a80b6aff-d68f-4a23-9ebd-882657d69f16', '人事部の許可を得ることなしに、勝手に休みを取ることはできない。', '人事部の許可を得ることなしに、勝手に休みを取ることはできない。', '没有得到人事部的批准，不能随便请假。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('1c4f262c-c321-449f-a7d1-43cefdd716cf', 'a80b6aff-d68f-4a23-9ebd-882657d69f16', '民意を問うことなしに、国民のための政策は作れない。', '民意を問うことなしに、国民のための政策は作れない。', '不去询问民意，就无法制定对国民有益的政策。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('55ca87ff-050d-4f62-9f7a-c6b96dbca712', 'a80b6aff-d68f-4a23-9ebd-882657d69f16', '親友は、細かい事情を聞くことなしに、私にお金を貸してくれた。', '親友は、細かい事情を聞くことなしに、私にお金を貸してくれた。', '好友没有询问具体细节，就把钱借给我了。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('41703efd-4072-4316-902c-252f79280d8e', 'a80b6aff-d68f-4a23-9ebd-882657d69f16', '彼はあいさつすることなしに、一人で帰国した。', '彼はあいさつすることなしに、一人で帰国した。', '他没有打声招呼就一个人回国了。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('6638c995-844d-424b-84bc-092b5bf17c1f', 'a80b6aff-d68f-4a23-9ebd-882657d69f16', '今月は一日も欠かすことなしに、出勤した。', '今月は一日も欠かすことなしに、出勤した。', '这个月一天也没有请假坚持上班。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('acb86c0e-901b-4b4d-a84a-d79cb00814ac', '～ことのないよう', NULL, 'N1', '動辞書形＋ことのないよう', '動辞書形＋ことのないよう', '表示目的，为了防止出现前项的情况应当采取措施。“为了不要……，（应该）……”。', '用法与「～ことがないように」相同。\n「こと」在句型中是一个形式名词，指前面的状态或者情况。', 30, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('e6ba8cfc-06e2-4492-8fc6-d9d2f95dbf32', 'acb86c0e-901b-4b4d-a84a-d79cb00814ac', '大学入試では、試験当日初めてその大学に行き、迷ってしまったということのないように、事前に見学しておくとよい。', '大学入試では、試験当日初めてその大学に行き、迷ってしまったということのないように、事前に見学しておくとよい。', '高考时，为了避免在考试当天因为找不到考场而迷路，最好提前去看一下。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('83fbe700-c02a-46a2-b85f-14c2621fb5bb', 'acb86c0e-901b-4b4d-a84a-d79cb00814ac', 'アパートの住人が突然追い出されることのないよう、保護する必要がある。', 'アパートのじゅうにんが突然追い出されることのないよう、保護する必要がある。', '为了使住在公寓里的人不会被突然赶出来，需要采取保护措施。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('01d2ddb8-643d-40be-b841-31b403fa602b', 'acb86c0e-901b-4b4d-a84a-d79cb00814ac', '残り少ない留学生活を思い残すことのないよう、充実した日々を送りたい。', '残り少ない留学生活を思い残すことのないよう、充実した日々を送りたい。', '希望自己能够充实地度过剩下的短暂的留学生活，不要留下遗憾。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('b9046149-e6ec-447a-b542-337696729911', 'acb86c0e-901b-4b4d-a84a-d79cb00814ac', '今回のことで会社の信用を失うことのないよう、しっかりした対応を求める。', '今回のことで会社の信用を失うことのないよう、しっかりした対応を求める。', '为了不要让公司的信誉因为这件事受到影响，需要认真进行处理。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('450fa4ba-dd0d-42d2-bd32-3b0ff5b7800d', 'acb86c0e-901b-4b4d-a84a-d79cb00814ac', '二度と同じミスを繰り返すことのないよう、指摘されたことをメモしておく。', '二度と同じミスを繰り返すことのないよう、指摘されたことをメモしておく。', '为了不要再犯同样的错误，把别人指出的问题记下来。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('6338e4e3-0b01-4adc-ae94-504fdb9caa88', '～こともあって', NULL, 'N1', '動/イ形/ナ形/名の名詞修飾形＋こともあって', '動/イ形/ナ形/名の名詞修飾形＋こともあって', '表示其中的一个原因，“也是由于……”“再加上……的原因”。', '列举其中某一方面的原因，后项多是对某个现象的解释。', 31, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('16b19c7f-d1f0-407f-a254-a69015d1ac93', '6338e4e3-0b01-4adc-ae94-504fdb9caa88', 'アルバイト先の仲間は、みんな年が近いこともあって同世代ならではの話でいつも盛り上がっています。', 'アルバイト先の仲間は、みんな年が近いこともあって同世代ならではの話でいつも盛り上がっています。', '也许因为年龄相近吧，能够和一起做兼职的朋友聊一些同龄人之间才有的话题，非常开心。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('024ac6c4-4ea4-4fce-ba99-ee0923ea0063', '6338e4e3-0b01-4adc-ae94-504fdb9caa88', '脚本があまりよくなかったこともあって、このドラマの視聴率は低かった。', 'きゃくほんがあまりよくなかったこともあって、このドラマの視聴率は低かった。', '可能是剧本不太好使得这部连续剧的收视率很低。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('f8aeebcf-cecc-47e5-9e21-f019942ea721', '6338e4e3-0b01-4adc-ae94-504fdb9caa88', 'フランス語を勉強したこともあって、一度はフランスに行ってみたかった。', 'フランス語を勉強したこともあって、一度はフランスに行ってみたかった。', '也许是因为自己之前学过法语，所以很想去一次法国。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('f974a214-3891-47d6-9ae7-9320779e0abb', '～ 始[し] 末[まつ]だ', NULL, 'N1', '動辞書形＋始末だ', '動辞書形＋始末だ', '表示结果，“最终（沦落到）……”“到了……的地步”。', '多表示不好的结果。\n固定用法：「この始末だ」/沦落到如此地步。', 32, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('4d303c58-516e-4f62-a28b-63b70109728a', 'f974a214-3891-47d6-9ae7-9320779e0abb', '体を鍛えようとジョギングを始めたが、走りすぎて膝を痛めてしまい、病院に通う始末だ。', '体を鍛えようとジョギングを始めたが、走りすぎてひざを痛めてしまい、病院に通う始末だ。', '因为想锻炼身体开始了慢跑，但是可能运动量过大伤到了膝盖，最终弄到要去医院的地步。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('bb4cc98d-a898-4b4f-bb19-ad14706eebb4', 'f974a214-3891-47d6-9ae7-9320779e0abb', '彼は本当に仕事をする気があるのかどうか、疑いたくなる。遅刻はする、約束は忘れる、ついには居眠り運転で事故を起こす始末だ。', '彼は本当に仕事をする気があるのかどうか、疑いたくなる。遅刻はする、約束は忘れる、ついにはいねむり運転で事故を起こす始末だ。', '他到底是不是真的想工作，这点很让我怀疑。迟到不说，还忘记约定，最终竟然在开车的时候打盹引发了交通事故。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('2da5d6d3-dcfd-4a09-bea2-5f9bd8b1290d', 'f974a214-3891-47d6-9ae7-9320779e0abb', 'あの二人は犬猿の仲で、ちょっとしたことでも、すぐ口論になる始末だ。', 'あの二人はけんえんのなかで、ちょっとしたことでも、すぐこうろんになる始末だ。', '他们俩简直是水火不容，一点小事都会闹到吵架的地步。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('c9caf304-f827-47e9-8000-a7573a7cd32a', '～ずくめ', NULL, 'N1', '名＋ずくめ', '名＋ずくめ', '表示状态，“尽是……”“全是……”“无一例外……”。', '「ずくめ」后面接续名词时用「の」，可作定语修饰体言。「ずくめだ」用在句末。\n固定用法：「いいことずくめ」/全是好事，「ごちそうずくめ」/全是好吃的，「規則ずくめ」/尽是规矩，「黒ずくめ」/一身全黑的（服装）。', 33, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('6ffec1ca-873a-4bc2-92ec-f40db670da2b', 'c9caf304-f827-47e9-8000-a7573a7cd32a', 'この燃料は、空気も汚さないし、費用も安く抑えられる。本当にいいことずくめだ。', 'このねんりょうは、空気も汚さないし、費用も安くおさえられる。本当にいいことずくめだ。', '这种燃料既不会污染空气，价格也相对便宜，真是有很多优点。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('faf4d74c-e5e2-474a-b1c8-4ee43cf9acd1', 'c9caf304-f827-47e9-8000-a7573a7cd32a', '今年は、息子の結婚、孫の誕生と、めでたいことずくめの一年だった。', '今年は、息子の結婚、まごの誕生と、めでたいことずくめの一年だった。', '今年儿子也结婚了，孙子也出生了，真是好事连连。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('2e3fd0e5-893f-4223-9435-9a61cb12c5ae', 'c9caf304-f827-47e9-8000-a7573a7cd32a', 'うちの学校は規則ずくめで、窮屈でしかたがない。', 'うちの学校は規則ずくめで、きゅうくつでしかたがない。', '我们学校规矩太多让人觉得太受束缚。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('75f6b2a3-0154-4f7b-bfa2-5d03e7897583', '～ずじまいだ', NULL, 'N1', '動ない形＋ずじまいだ', '動ない形＋ずじまいだ\n（する→せず＋じまいだ）', '表示结果，“最终未能……”“结果还是没能……”。', '原本想做的事情因为某种原因未能实现，表达一种遗憾，后悔，自责之情。\n用来描述已经结束的事情，后项多用过去时。', 34, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('5475c4af-f23b-4866-a7e3-8c45e88e62f8', '75f6b2a3-0154-4f7b-bfa2-5d03e7897583', 'いなくなったペットを懸命に探したが、結局、その行方はわからずじまいだった。', 'いなくなったペットを懸命に探したが、結局、そのゆくえはわからずじまいだった。', '到处寻找走丢的宠物，最终还是没有找到。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('8006a318-2c4b-4f60-807f-581793af4622', '75f6b2a3-0154-4f7b-bfa2-5d03e7897583', '有名な観光地の近くまで行ったのに、忙しくてどこへも寄らずじまいだった。', '有名な観光地の近くまで行ったのに、忙しくてどこへもよらずじまいだった。', '虽然经过了很有名的观光地，但是时间太紧什么地方也没去成。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('02401dc4-e83c-4de4-8283-9fc7d9c48caf', '75f6b2a3-0154-4f7b-bfa2-5d03e7897583', '連休明けのせいか、今日はエンジンがかからずじまいで一日が終わった。', 'れんきゅうあけのせいか、今日はエンジンがかからずじまいで一日が終わった。', '也许是长假刚刚结束，还没有找回工作状态一天就结束了。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('706a0641-2343-41e6-863f-9a9eb3bbd991', '～ずにはおかない/ないではおかない', NULL, 'N1', '動ない形＋ずにはおかない/ないではおかない', '動ない形＋ずにはおかない/ないではおかない\n（する→せずにはおかない/しないではおかない）', '表示对事情的评价或者一种强烈的意志。“肯定会使……”“必然会引起……”“一定会让……”。', '「～ずにはおかない」的用法与「～ないではおかない」相同。\n固定用法：「感動させずにはおかない」/必定会使……感动，「言わせずにはおかない」/必定要让其说出来。', 35, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('915d0f76-197b-4665-8bb8-94a71dcc1ef8', '706a0641-2343-41e6-863f-9a9eb3bbd991', 'この絵は本当に素晴らしい。見る者を感動させずにはおかないだろう。', 'この絵は本当に素晴らしい。見る者を感動させずにはおかないだろう。', '这幅画很棒，一定会使看的人感动。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('00676987-9b53-4f6e-bf6d-dddcd3f883e7', '706a0641-2343-41e6-863f-9a9eb3bbd991', 'この映画は評判が高く、見る者を感動させずにはおかないだろう。', 'この映画は評判が高く、見る者を感動させずにはおかないだろう。', '这部电影深受好评，一定会使观众感动。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('edaa416f-8c80-415b-b538-8cb7b8153b15', '706a0641-2343-41e6-863f-9a9eb3bbd991', '新企画の中止が決まろうとしているが、担当した者たちは反対しないではおかないだろう。', '新企画の中止が決まろうとしているが、担当した者たちは反対しないではおかないだろう。', '听说新的企划方案即将被否决，方案的负责人一定会反对吧。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('bf15dce0-3115-42b6-bec4-2109d9a3e01f', '706a0641-2343-41e6-863f-9a9eb3bbd991', '息子は一流の音楽家になるといって家を出た。大変だが、きっと目的を達成しないではおかないだろう。', '息子は一流の音楽家になるといって家を出た。大変だが、きっと目的を達成しないではおかないだろう。', '儿子说自己要成为一流的音乐家，所以离开了家。尽管很辛苦，但我想他一定会实现自己的梦想吧。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('aa4d285f-e271-4df0-a165-b6bf269c1710', '706a0641-2343-41e6-863f-9a9eb3bbd991', '今回の事件は、政府の外交政策に影響を与えないではおかないだろう。', '今回の事件は、政府の外交政策に影響を与えないではおかないだろう。', '这次的事件必定会给政府的外交政策带来很大的影响吧。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('e293bf74-c2c0-4aab-b7ce-e8150f838748', '～ずにはすまない/ないではすまない', NULL, 'N1', '動ない形＋ずにはすまない/ないではすまない', '動ない形＋ずにはすまない/ないではすまない\n（する→せずにはすまない/しないではすまない）', '表示从自己的责任感、周围的情况、社会性的常识等方面考虑，必须要做某事。“一定要……”“不……的话（心里过意不去）”“不……的话说不过去”。', '「～ずにはすまない」的用法与「～ないではすまない」相同。\n常与「謝る」「弁償する」「責任を取る」「返す」等动词一起使用。', 36, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('a6352ec4-0e5b-4705-86fa-fea44a8a3042', 'e293bf74-c2c0-4aab-b7ce-e8150f838748', 'あの社員は客の金を使ったのだから処罰されずにはすまないだろう。', 'あの社員は客の金を使ったのだからしょばつされずにはすまないだろう。', '那个员工挪用了顾客的资金，一定会被惩罚的吧。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('5d6b9bcd-73f4-4bec-8f3f-28d7fb689aa9', 'e293bf74-c2c0-4aab-b7ce-e8150f838748', '自分が悪いことをしたんだから、謝らないではすまないだろう。', '自分が悪いことをしたんだから、謝らないではすまないだろう。', '自己做了错事不道歉不行。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('4da0f587-5219-43b5-9e82-bc6d9d12dffe', 'e293bf74-c2c0-4aab-b7ce-e8150f838748', '自分のせいで、相手に損害を与えたのだから、弁償せずにはすまない。', '自分のせいで、相手に損害を与えたのだから、べんしょうせずにはすまない。', '因为自己的原因给对方造成了损失，不赔偿的话会过意不去。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('6ce41d44-debb-4d3d-b133-74e11abac847', '～ 術[すべ]がない', NULL, 'N1', '動辞書形＋術がない', '動辞書形＋術がない', '表示无可奈何、没有任何办法。“没有办法做到……”。', '「術」在句型中的意思是“方法”。\n固定用法：「成す術がない」/无计可施，毫无办法。\n类似语法：「動ます形＋ようがない」意思是“即使想……也没办法……”。', 37, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('e672fef1-4665-4746-8060-227ad5fa6671', '6ce41d44-debb-4d3d-b133-74e11abac847', '前代未聞の金融危機で、失業者が続出し、政府も経済の悪化に成す術がない。', 'ぜんだいみもんの金融危機で、失業者がぞくしゅつし、政府も経済の悪化になす術がない。', '受到前所未有的金融危机的冲击，失业人数不断增加，政府也对经济状况的恶化束手无策。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('a616b5fa-4f97-490e-816d-5bc7d56a072f', '6ce41d44-debb-4d3d-b133-74e11abac847', 'こんなに壊れては、もう直す術がない。', 'こんなに壊れては、もう直す術がない。', '都坏成这样了，已经没法修了。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('9960f003-624c-4302-9e5c-cc0f57c57165', '6ce41d44-debb-4d3d-b133-74e11abac847', 'ことここに至っては、もう成す術がない。', 'ことここに至っては、もう成す術がない。', '事已至此，没有办法。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('4c1c6469-db33-45f0-a547-5525874dc96b', '～（で）すら', NULL, 'N1', '名＋（で）すら', '名＋（で）すら', '表示强调，“甚至……”“连……”。', '「すら」前面的助词「で」可以省略。「で」用来提示主语，强调前面的内容。', 38, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('9c7749ab-45f0-4c7e-a0d7-110764731b6e', '4c1c6469-db33-45f0-a547-5525874dc96b', 'この地域の再開発に自分がかかわることになろうとは想像すらしていなかった。', 'この地域の再開発に自分がかかわることになろうとは想像すらしていなかった。', '从未想过自己会和这个地区的开发产生关联。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('9e162fbc-cc4d-402b-b80b-91448eb22414', '4c1c6469-db33-45f0-a547-5525874dc96b', 'あの患者は重い病気のため、一人では食事すらできない。', 'あのかんじゃは重い病気のため、一人では食事すらできない。', '那位患者的病情很重，甚至没法自己进食。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('59d77d65-a3ec-44cc-a581-3fd05da2618e', '4c1c6469-db33-45f0-a547-5525874dc96b', '彼女は寝る時間や食事する時間すら惜しんで、勉強に没頭している。', '彼女は寝る時間や食事する時間すら惜しんで、勉強にぼっとうしている。', '她废寝忘食地埋头于学习之中。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('e3aa3ba8-1c9c-4e08-9577-08faf4c8db72', '4c1c6469-db33-45f0-a547-5525874dc96b', 'そんなことは子どもですら知っている。', 'そんなことは子どもですら知っている。', '那么简单的事情连孩子都知道。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('c19c594a-5ae6-4e27-b6af-4805d5cb824d', '～そばから', NULL, 'N1', '動辞書形·た形＋そばから', '動辞書形·た形＋そばから', '表示一种状态的重复出现，“刚……就……”。', '「そば」的本意是“在旁边”，这里指刚刚做出了前项的努力，但是马上就出现后项的情况。\n常用一些固定的表达方式，如：「掃除するそばから散らかす」/刚打扫过又弄乱了，「習うそばから忘れる」/刚学了又忘了，「もらうそばから使う」/刚拿到就用了。', 39, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('e5135f10-86ff-4915-ba89-231d74f0ac9b', 'c19c594a-5ae6-4e27-b6af-4805d5cb824d', '私は語学の才能がないようで、新しい言葉を習うそばから忘れてしまう。', '私は語学の才能がないようで、新しい言葉を習うそばから忘れてしまう。', '我可能是没有语言天赋，新单词总是学了就忘。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('d8774332-1aa7-4dee-93e2-054ea9a77de4', 'c19c594a-5ae6-4e27-b6af-4805d5cb824d', 'もう遅刻しないと言ったそばからまた遅れるなんて、彼は何を考えているのだろう。', 'もう遅刻しないと言ったそばからまた遅れるなんて、彼は何を考えているのだろう。', '真不知道他是怎么想的，刚说了不迟到却又迟到了。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('8f2798ae-9f84-48ce-b7eb-64f7b06ce5c3', 'c19c594a-5ae6-4e27-b6af-4805d5cb824d', '片付けるそばから子どもが部屋を散らかすので、いやになってしまう。', '片付けるそばから子どもが部屋を散らかすので、いやになってしまう。', '刚收拾好的房间又被孩子弄乱了，真是烦人。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('ea9dd300-13f5-467e-ae7e-7136c9df4d7c', '～そびれる', NULL, 'N1', '動ます形＋そびれる', '動ます形＋そびれる', '表示结果，由于某种原因错过了做某事，或者未能完成某事。“错过机会最终没能……”。', '「動ます形＋そびれる」构成复合动词。', 40, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('4c51cc60-6a15-4e42-86dc-b739efa9fc5a', 'ea9dd300-13f5-467e-ae7e-7136c9df4d7c', 'ぜひ見ようと思っていた映画だったのに、忙しくて行きそびれた。', 'ぜひ見ようと思っていた映画だったのに、忙しくて行きそびれた。', '本来很想看的一部电影因为太忙没有去成。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('f350ba4a-b723-46c7-8a84-02ea4bf675b0', 'ea9dd300-13f5-467e-ae7e-7136c9df4d7c', '今日はあいにくの曇り空で中秋の名月を撮りそびれた。', '今日はあいにくのくもりぞらでちゅうしゅうのめいげつを撮りそびれた。', '今天刚好是阴天，未能拍下中秋节的明月。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('6f77bd51-01bd-48b1-91ef-958010f84d60', 'ea9dd300-13f5-467e-ae7e-7136c9df4d7c', '毎年「今年こそは」と思いながらも、買いそびれるものがある。', '毎年「今年こそは」と思いながらも、買いそびれるものがある。', '每年都有想买但是没有买成的东西。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('dfbde58d-8ccf-4d37-b212-166b0937bc97', '（ひとり）～だけでなく/のみならず', NULL, 'N1', '（ひとり＋）名/動·イ形·ナ形の名詞修飾形＋だけでなく/のみならず', '（ひとり＋）名/動·イ形·ナ形の名詞修飾形＋だけでなく/のみならず', '表示不限定，不仅前项，后项也如此。“不仅……（而且）……”。', '「ひとり」表示强调，可以省略。\n前项和后项是互为对照，并列或类似的内容。', 41, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('39ddbeb1-166e-4820-8f71-79c22f6f082a', 'dfbde58d-8ccf-4d37-b212-166b0937bc97', '留学する以上は、勉強だけでなく、その国の文化を学んだり交流をしたりしたいと思う。', '留学する以上は、勉強だけでなく、その国の文化を学んだり交流をしたりしたいと思う。', '我想既然要去留学，就不仅要学习，也要去体验异国的文化，与当地的人交流。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('e274a95d-8d7f-4986-bbe9-38fc80c7ea86', 'dfbde58d-8ccf-4d37-b212-166b0937bc97', '高齢化の問題は、ひとり西欧諸国のみならず、新興国でも深刻化してきた。', 'せいおうしょこくのみならず、しんこうこくでも深刻化してきた。', '不只是在西方各国，在一些新兴国家，人口老龄化的问题也严重了起来。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('76904623-76cd-48b8-8763-d54a6ff202f4', 'dfbde58d-8ccf-4d37-b212-166b0937bc97', '公共の場所でタバコを吸うのはひとり本人にとって有害であるだけでなく、周りの人にとっても迷惑なものである。', '公共の場所でタバコを吸うのはひとり本人にとって有害であるだけでなく、周りの人にとっても迷惑なものである。', '在公共场所吸烟不仅有害本人身体健康，也会影响到周围的人。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('0d17ddc0-1130-4e00-9953-88a9b8cff6d5', '～だけましだ', NULL, 'N1', '～だけましだ', '～だけましだ', '“幸好……”“好在……”。', '该句型多用于评价已经发生的某件不好的事情，表示尽管情况不太好，但幸亏没有更糟糕的意思。', 42, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('2f9dddd6-3ec2-48a1-a673-73d48b7761b0', '0d17ddc0-1130-4e00-9953-88a9b8cff6d5', '石油の価格が上がったために、わが社の業績は下がった。しかし、損失が出ないだけまだましだ。', '石油の価格が上がったために、わが社の業績は下がった。しかし、損失が出ないだけまだましだ。', '因为石油价格上涨，我们公司的业绩有所下滑，但是好在没有什么亏损。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('14f56c57-2345-4227-b769-9a0cb1b42a95', '0d17ddc0-1130-4e00-9953-88a9b8cff6d5', '今年は景気が非常に悪く、ボーナスが出なかった。しかし、給料がもらえるだけましだ。', '今年は景気が非常に悪く、ボーナスが出なかった。しかし、給料がもらえるだけましだ。', '今年的经济非常不景气，没有年终奖。但幸好能拿到工资。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('b99acc61-0fd7-4634-904c-df977d33ef02', '0d17ddc0-1130-4e00-9953-88a9b8cff6d5', '泥棒にかなりの額の現金をとられはしたが、命をとられなかっただけましだ。', '泥棒にかなりの額の現金をとられはしたが、命をとられなかっただけましだ。', '被小偷偷走了很大金额的现金，但好在没有危及性命。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('77812f04-b9fa-4eb7-a8ce-012e098b8262', 'ただ～のみだ', NULL, 'N1', 'ただ～のみだ', 'ただ～のみだ', '表示限定，“只能……”“只好是……”。', '「ただ」强调没有其他办法只能如此。\n「のみ」也可以单独使用，表示限定。意思是“只有……”“只能……”。', 43, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('be78a094-36c2-4829-a346-e08aa0c473da', '77812f04-b9fa-4eb7-a8ce-012e098b8262', '事故はあまりにも突然で、私は何もできず、ただ呆然とするのみだった。', 'ぼうぜんとするのみだった。', '事故发生得太突然，我只是呆呆地在那里，什么也没能做。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('ae6b29ce-1d1e-4a4d-9fc5-b637810165ae', '77812f04-b9fa-4eb7-a8ce-012e098b8262', '一歩も後退できない。ただ前進あるのみだ。', '一歩も後退できない。ただ前進あるのみだ。', '一步也不能后退，只能前进。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('676fa562-783c-4930-bc1f-c688fba309ac', '77812f04-b9fa-4eb7-a8ce-012e098b8262', '今はただ事件の行方不明者の無事を祈るのみだ。', '今はただ事件のゆくえふめいしゃの無事をいのるのみだ。', '现在只能为事故中的失踪者祈祷。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('ca66f139-c799-40a9-a52a-ed3b5ea24492', '77812f04-b9fa-4eb7-a8ce-012e098b8262', '人はとかく自身に都合がいい意見にのみ耳を傾けるきらいがある。', '人はとかく自身に都合がいい意見にのみ耳をかたむけるきらいがある。', '人们往往只能听进自己觉得听起来顺耳的意见。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('5b2746c8-a12d-4e33-b5d7-aafc7caef713', '～たところで', NULL, 'N1', '動た形＋ところで', '動た形＋ところで', '表示假定条件的逆接，假设前项的条件成立，也未必会出现后项的结果。“即使……也（未必）……”。', '常与「いくら」「どんなに」「たとえ」「 今[いま] 更[さら]」等词一起使用。', 44, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('c7063934-91b3-4ac0-8692-a4b9bf0b8474', '5b2746c8-a12d-4e33-b5d7-aafc7caef713', '社長一人が必死になったところで、この会社が大きく変わるとは思えない。', '社長一人が必死になったところで、この会社が大きく変わるとは思えない。', '就算社长一个人很努力，公司也难以发展壮大。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('7232de5e-7841-4687-9a76-0541cbbd8a54', '5b2746c8-a12d-4e33-b5d7-aafc7caef713', 'あの企業が相手では、高層ビル建設の反対運動をしたところで、建設の計画は中止にならないだろう。', 'あの企業が相手では、高層ビル建設の反対運動をしたところで、建設の計画は中止にならないだろう。', '如果是由那家公司主导的话，即使大家开展反对高楼建设的活动，他们也不会终止开发计划的。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('a2f8aa67-9c6f-470d-80cf-099bb6e3499d', '5b2746c8-a12d-4e33-b5d7-aafc7caef713', 'いくら頑張ったところで、運命を変えることができない。', 'いくら頑張ったところで、運命を変えることができない。', '再怎么努力也没法改变自己的命运。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('5111bf23-66e9-4ff1-856e-e58a8726cbbc', '～だに', NULL, 'N1', '～だに', '～だに', '表示强调，“就连……”“压根（没）……”“连……都……”。', '「だに」是文语助动词，意思相当于「も/すら/さえ」。\n后项多和表示否定的词连用。\n常和「想像する」「考える」「聞く」「思う」「口に出す」等词一起使用。\n固定用法：「夢にだに思わなかった」/做梦也没有想到。', 45, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('1f155900-5425-4030-a608-ebdc1109fbfb', '5111bf23-66e9-4ff1-856e-e58a8726cbbc', '地震のことなど想像するだに恐ろしい。', '地震のことなど想像するだに恐ろしい。', '光是想一想发生地震就觉得很可怕。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('ebbcd4f4-083c-4d3a-a71f-43eb53b3d210', '5111bf23-66e9-4ff1-856e-e58a8726cbbc', '子どものころ、死については考えるだに恐ろしかった。', '子どものころ、死については考えるだに恐ろしかった。', '小时候，光是想到死亡就觉得可怕。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('bd4a1b57-5964-4452-89e2-9f1d7a522b20', '5111bf23-66e9-4ff1-856e-e58a8726cbbc', '自分が政治家になろうとは、想像だにしていなかった。', '自分が政治家になろうとは、想像だにしていなかった。', '从未想过自己会成为政治家。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('bb4a6aec-1450-4434-a064-414f2f3de365', '～ためしがない', NULL, 'N1', '動た形＋ためしがない', '動た形＋ためしがない', '表示从未做过某事或者未曾有过某种经历。“从来没有……”“不曾……”。', '该句型多用于描述某人的行为或某种情况，暗含不满、责难的语气。\n类似的句型还有「～た覚えはない」。', 46, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('3fba5eda-4464-446f-8ecc-efc2a638d8a3', 'bb4a6aec-1450-4434-a064-414f2f3de365', '宝くじなんて、一度も当たったためしがない。', '宝くじなんて、一度も当たったためしがない。', '彩票我是一次也没中过。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('e289e401-3b04-47c9-b0fc-abbc08fa37ad', 'bb4a6aec-1450-4434-a064-414f2f3de365', '時間にルーズな彼は、デートに時間通りに来たためしがない。', '時間にルーズな彼は、デートに時間通りに来たためしがない。', '不守时的他约会从未准时过。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('0e278b85-16f5-4f97-bcd6-136cd5a2797c', 'bb4a6aec-1450-4434-a064-414f2f3de365', '入社以来、あの厳しい佐々木課長に褒められたためしがない。', '入社以来、あの厳しいささき課長に褒められたためしがない。', '进入公司以来从未被严格的佐佐木课长表扬过。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('8bf21085-df38-441d-a445-69ee500da6f7', '～たらきりがない/ばきりがない', NULL, 'N1', '動た形＋らきりがない', '動た形＋らきりがない\n動ば形＋きりがない', '表示“若是……的话，就没完没了”“一旦……，就没完没了”。', '该句型表示“若说起某事，话就长了”或者“同类的事情举不胜举”之意。', 47, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('a844a015-c534-418e-9912-0f4ac2456c9c', '8bf21085-df38-441d-a445-69ee500da6f7', 'この計画の問題点をあげればきりがないが、大事なのは解決策を考えることだ。', 'この計画の問題点をあげればきりがないが、大事なのは解決策を考えることだ。', '提起这个计划的问题点那是举不胜举，但重要的是考虑解决方案。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('9a134e30-531a-4084-b147-46023f40068b', '8bf21085-df38-441d-a445-69ee500da6f7', '隣のおばさんは息子さんの自慢話を言い出したらきりがない。', '隣のおばさんは息子さんの自慢話を言い出したらきりがない。', '隔壁家的阿姨一夸起自己的儿子就没完没了。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('59605f1c-047e-4949-8091-8e2ad6af6920', '8bf21085-df38-441d-a445-69ee500da6f7', '贅沢を言えばきりがないので、もっと現実的に考えよう。', 'ぜいたくを言えばきりがないので、もっと現実的に考えよう。', '奢望起来没有止境，还是想得现实点吧。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('2af7583e-48e0-479c-85c4-f81cdaf2a1ac', '～たりとも', NULL, 'N1', '名＋たりとも', '名＋たりとも', '表示强调，强调很小、很少、很弱。“就连……也不能”。', '前面常用最小的数量词。\n「～たりとも」中的「も」表示强调，意思是“就连……也不”，意思与「～も～ない」相同。', 48, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('a6a4a5ee-3de2-4ccf-bb37-24f1a59c3325', '2af7583e-48e0-479c-85c4-f81cdaf2a1ac', '医者は手術の間、一瞬たりとも気が抜けない。', '医者は手術の間、一瞬たりとも気が抜けない。', '医生在做手术的时候片刻也不能大意。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('5bbe972c-d206-4a47-b7ab-538618be79de', '2af7583e-48e0-479c-85c4-f81cdaf2a1ac', '募金で集めたお金は一円たりとも無駄にできない。', 'ぼきんで集めたお金は一円たりとも無駄にできない。', '募集的资金一块钱也不能浪费。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('29167607-125d-447e-bfc6-708361863425', '2af7583e-48e0-479c-85c4-f81cdaf2a1ac', '猫の子一匹たりとも、ここを通らせないぞ。', '猫の子一匹たりとも、ここを通らせないぞ。', '就连一只小猫也不会放过去。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('0836d4a4-a93a-4209-a719-efd2bb228a8a', '～たる/たるもの', NULL, 'N1', '名＋たる/たるもの', '名＋たる/たるもの', '表示对某种特殊身份或者从事某种职业的人的要求和希望。“作为……，（应该）……”。', '前面常用表示职业、身份、地位的名词。如：「政治家」「公務員」「警官」「選手」「教師」「医者」等。', 49, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('c85d6ccb-a7c4-42d8-9c87-4e64bf1500e1', '0836d4a4-a93a-4209-a719-efd2bb228a8a', '国民の生活をより良いものにすること、それが政治家たる者の使命だと考えます。', '国民の生活をより良いものにすること、それが政治家たる者の使命だと考えます。', '使国民过上更好的生活是政治家的使命所在。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('49e24c88-1d5a-4fe3-bfcf-dfc271a49de6', '0836d4a4-a93a-4209-a719-efd2bb228a8a', '警官たる者、そのような犯罪にかかわってはいけない。', '警官たる者、そのような犯罪にかかわってはいけない。', '作为警官，不能牵扯到那样的犯罪案件中。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('dbe06ac4-a973-4395-83c8-f1c086f97a6b', '0836d4a4-a93a-4209-a719-efd2bb228a8a', '選手たるもの、試合においては堂々と戦え。', '選手たるもの、試合においてはどうどうとたたかえ。', '作为运动员，就应该光明磊落地参加比赛。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('9aaf4b1c-a6fc-4054-b4ba-96b714e9b258', '～つ～つ', NULL, 'N1', '動ます形＋つ＋動ます形＋つ', '動ます形＋つ＋動ます形＋つ', '表示两个动作交替进行，“一会儿……一会儿……”“或……或……”。', '前后一般是意义相对或者相反的词。\n固定用法：「 行[い]きつ 戻[もど]りつ」/走来走去，「 浮[う]きつ 沈[しず]みつ」/时而浮起时而沉下，「 追[お]いつ 追[お]われつ」/你追我赶，「 押[お]しつ 押[お]されつ」/你推我挤，「 組[く]んづ 解[ほぐ]れつ」/互相厮打，「 差[さ]しつ 差[さ]されつ」/互相敬酒，「 持[も]ちつ 持[も]たれつ」/互相帮助，「 矯[た]めつ 眇[すが]めつ」/仔细端详。', 50, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('fe1e3c15-aa60-422d-a248-01f61c56a23e', '9aaf4b1c-a6fc-4054-b4ba-96b714e9b258', '事実を言おうか言うまいか、廊下を行きつ戻りつ考えた。', '事実を言おうか言うまいか、廊下を行きつ戻りつ考えた。', '在走廊上来回踱步，考虑着要不要说出真相。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('b5eb68f5-9cbb-40d5-bc2e-cfce900e5d22', '9aaf4b1c-a6fc-4054-b4ba-96b714e9b258', 'ラッシュアワーの時間なので、地下鉄の車内は乗客で押しつ押されつしている。', 'ラッシュアワーの時間なので、地下鉄の車内は乗客で押しつ押されつしている。', '因为是上下班高峰时间，地铁车厢内乘客们挤来挤去。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('8b153b3f-714c-4140-b258-fc6e26c0d61a', '9aaf4b1c-a6fc-4054-b4ba-96b714e9b258', '今夜はゆっくり二人きりで、差しつ差されつ朝まで飲みましょう。', '今夜はゆっくり二人きりで、差しつ差されつ朝まで飲みましょう。', '今晚就我们俩互相敬酒，喝到天明。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('dfe406c3-c4a7-4b82-8990-2a4e784c493f', '～であれ/であろうと', NULL, 'N1', '名＋であれ/であろうと', '名＋であれ/であろうと', '表示假定条件的逆接，无论前项如何，后项都不改变。“无论……如何，都（不）……”“不管……怎样，都（不）……”。', '常与「たとえ」「どんな」「何」等词连用。\n前项可以是一个极端的例子，意思是“即使……，后项的原则也不变”。', 51, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('8478c81d-bdac-4e65-80ec-9e739e3790e2', 'dfe406c3-c4a7-4b82-8990-2a4e784c493f', 'どんな悪人であろうと、心のどこかに良心は残っているはずだ。', 'どんなあくにんであろうと、心のどこかにりょうしんは残っているはずだ。', '即便是再坏的人，其良心也没有完全泯灭。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('1d39e950-fe06-47af-8367-7820edb9fb38', 'dfe406c3-c4a7-4b82-8990-2a4e784c493f', 'うそをつくとは、どんな理由であれ、許されない。', 'うそをつくとは、どんな理由であれ、許されない。', '不论出于什么理由都不允许撒谎。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('6d7fe5a4-cf49-45f2-9836-ae61292da2ea', 'dfe406c3-c4a7-4b82-8990-2a4e784c493f', 'たとえ子どもであれ、自分のしたことは自分で責任をとらなければならない。', 'たとえ子どもであれ、自分のしたことは自分で責任をとらなければならない。', '即使是孩子，也应该对自己所做的事情负责。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('81c4197b-866a-4ece-8b51-720ace8e8520', '～であれ～であれ/～であろうと～であろうと/～だろうが～だろうが', NULL, 'N1', '名A＋であれ/であろうと/だろうが、名B＋であれ/であろうと/だろうが', '名A＋であれ/であろうと/だろうが、名B＋であれ/であろうと/だろうが', '表示假定条件的逆接，无论前项如何，后项的要求都是一样的。“无论是……还是……，都……”。', '列举互为对照，并列，或者类似的内容。\n后项常用「～なければならない」「～べきだ」「～てはいけない」等句型。', 52, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('abc45cf1-4587-434a-92ce-2618b6152fca', '81c4197b-866a-4ece-8b51-720ace8e8520', '国会議員だろうが、公務員だろうが、税金は納めなければならない。', '国会議員だろうが、公務員だろうが、税金は納めなければならない。', '不管是国会议员也好，还是公务员也好，都要纳税。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('9cef5426-5df0-45ff-b846-1e8d938cfb6c', '81c4197b-866a-4ece-8b51-720ace8e8520', '正社員であれ、パートであれ、仕事に対する責任は変わらない。', '正社員であれ、パートであれ、仕事に対する責任は変わらない。', '正式员工也好，临时工也好，对工作的责任是一样的。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('3e9afb7c-fb87-4677-aa70-a992f0a015ad', '81c4197b-866a-4ece-8b51-720ace8e8520', '貧乏であれ、お金持ちであれ、自分の夢を失ってはいけない。', '貧乏であれ、お金持ちであれ、自分の夢を失ってはいけない。', '贫穷也好，富有也好，都不能忘记自己的梦想。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('abd138eb-4d92-4bb4-a814-b6b29ce3173d', '～てからというもの', NULL, 'N1', '動て形＋からというもの', '動て形＋からというもの', '表示自从某件事情发生后，后项发生了很大的变化。“自从……之后”。', '后项是对已经发生的变化的描述，常用过去时。', 53, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('38743bf9-a48c-4164-a9bd-6b563a4b4c50', 'abd138eb-4d92-4bb4-a814-b6b29ce3173d', 'Eメールを使うようになってからというもの、ほとんど手紙を書かなくなった。', 'Eメールを使うようになってからというもの、ほとんど手紙を書かなくなった。', '自从开始使用E-mail之后，几乎不写信了。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('0fd93f7a-7586-4eb2-90b7-88d73642e01e', 'abd138eb-4d92-4bb4-a814-b6b29ce3173d', 'この道具を一度使ってからというもの、あまりの便利さに手放せなくなってしまった。', 'この道具を一度使ってからというもの、あまりの便利さに手放せなくなってしまった。', '这个工具很方便，一旦用过后就很难放弃不用。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('12c7c880-8d5e-44fe-92d8-b89c12c37f96', 'abd138eb-4d92-4bb4-a814-b6b29ce3173d', '彼は結婚してからというもの、人が変わったようにまじめになった。', '彼は結婚してからというもの、人が変わったようにまじめになった。', '他自从结婚后就像变了一个人似的，认真了起来。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('72a99bce-a0bc-4cf0-a823-d790eabd9688', '～てしかるべきだ', NULL, 'N1', '動て形＋しかるべきだ', '動て形＋しかるべきだ', '表示做某事本是理所应当的，但是目前的状态却不是如此。“理应……”“应当……”。', '意思与「～（する）のが当然だ」「～（する）のが当たり前だ」相同。\n多用来表示说话人针对现状提出的建议、主张。', 54, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('b5936ac7-8409-4d9d-a451-43f5e2ad74bf', '72a99bce-a0bc-4cf0-a823-d790eabd9688', '所得が低い人には、税金の負担を軽くするなどの措置がとられてしかるべきだ。', 'しょとくが低い人には、税金の負担を軽くするなどの措置がとられてしかるべきだ。', '应该采取措施减轻低收入人群的税收负担。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('34f3b496-21fd-4a2f-9169-8e6e7da07b09', '72a99bce-a0bc-4cf0-a823-d790eabd9688', '先輩にはそれ相応の敬意を払ってしかるべきだ。', '先輩にはそれそうおうの敬意を払ってしかるべきだ。', '对前辈应当有应有的尊重。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('4417ae24-2f50-465d-8c92-1c3223027827', '72a99bce-a0bc-4cf0-a823-d790eabd9688', 'そもそも哲学というのは日常生活の中にこそ、生まれてしかるべきなのだ。', 'そもそも哲学というのは日常生活の中にこそ、生まれてしかるべきなのだ。', '哲学原本应该是源于日常生活的。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('0c0573c6-11d4-444e-9b8b-424457c3ae79', '～でなくてなんだろう', NULL, 'N1', '名＋でなくてなんだろう', '名＋でなくてなんだろう', '表示强调，“不是……又是什么呢”“这就是……”。', '该句型多用在句末，表示说话人强烈的语气，不能用作主语。', 55, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('aa62e9c7-0543-4f06-b444-ad27b1cea11d', '0c0573c6-11d4-444e-9b8b-424457c3ae79', 'たった三歳でこんなに難しい曲を見事に演奏してしまうとは、これが天才でなくてなんだろう。', 'たった三歳でこんなに難しい曲を見事に演奏してしまうとは、これが天才でなくてなんだろう。', '才3岁就能如此娴熟地弹奏这么难的曲子，不是天才又是什么呢？', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('8f1d5985-1aa2-4672-8116-197e03cac54b', '0c0573c6-11d4-444e-9b8b-424457c3ae79', '戦争で多くの人が殺されているなんて、これが悲劇でなくてなんだろう。', '戦争で多くの人が殺されているなんて、これが悲劇でなくてなんだろう。', '战争中很多人被杀害，这不是悲剧又是什么呢？', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('fdc87208-9301-4d65-85e1-883062332847', '0c0573c6-11d4-444e-9b8b-424457c3ae79', 'こんなにみごとな絵が、芸術でなくてなんだろう。', 'こんなにみごとな絵が、芸術でなくてなんだろう。', '这么好的画不是艺术又是什么呢？', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('5545a267-a667-4210-a455-ef75b134b843', '0c0573c6-11d4-444e-9b8b-424457c3ae79', '彼女のためなら何でもする。これが愛でなくてなんだろう。', '彼女のためなら何でもする。これが愛でなくてなんだろう。', '只要是为了她什么事情都愿意做，这不是爱又是什么呢？', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('47e1b5fb-0e46-41fb-8276-3071cdc269c7', '～ではあるまいし/じゃあるまいし', NULL, 'N1', '～ではあるまいし/じゃあるまいし', '～ではあるまいし/じゃあるまいし', '表示原因、理由，“又不是……（所以没必要）……”。', '「～じゃあるまいし」是「～ではあるまいし」的口语形式。', 56, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('bf3220e2-d1c1-4ea5-b411-e48a5ddfc53e', '47e1b5fb-0e46-41fb-8276-3071cdc269c7', '夫「週末の旅行、このスーツケースでどうかなあ？」妻「何週間も海外に行くわけじゃあるまいし、今度はそんなに大きいスーツケースは要らないんじゃない？」', '夫「週末の旅行、このスーツケースでどうかなあ？」妻「何週間も海外に行くわけじゃあるまいし、今度はそんなに大きいスーツケースは要らないんじゃない？」', '丈夫：“周末的旅行，用这个行李箱怎么样？”\n妻子：“又不是要去国外好几周，这次应该不需要那么大的箱子吧？”', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('70e164d4-5caa-479f-87d6-d890719041f8', '47e1b5fb-0e46-41fb-8276-3071cdc269c7', '子どもではあるまいし、もう少し冷静に話し合うべきだ。', '子どもではあるまいし、もう少し冷静に話し合うべきだ。', '又不是小孩子，所以讲话时要更冷静一些。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('2bbcf9d6-e6cf-4182-8739-59fa8bcdfb1f', '47e1b5fb-0e46-41fb-8276-3071cdc269c7', '航空、レジャー関連企業が若者に人気があるという。海外旅行が珍しい時代ではあるまいし、どうして若者はそういった企業に行きたがるのだろうか。', '航空、レジャー関連企業が若者に人気があるという。海外旅行が珍しい時代ではあるまいし、どうして若者はそういった企業に行きたがるのだろうか。', '听说航空、娱乐等行业很受年轻人欢迎。现在去国外旅行并不困难，为何年轻人会偏好这些行业呢？', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('ae6c1715-cfb1-4db8-a5d8-6ac47893df9d', '47e1b5fb-0e46-41fb-8276-3071cdc269c7', '期末レポートといっても別に外国語で書くんじゃあるまいし、そんなに心配しなくていいよ。', '期末レポートといっても別に外国語で書くんじゃあるまいし、そんなに心配しなくていいよ。', '虽说是要交期末报告，但是不需要用外语写，所以没必要那么担心。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('effa4678-af34-497a-a429-0ce106db84a1', '～てはかなわない', NULL, 'N1', '～てはかなわない', '～てはかなわない', '强调主观的一种情绪、感受，“……的话，让人受不了”“如果……的话，就没有办法了”。', '「～かなわない」在句型中的意思是「～我慢できない」。\n「～ちゃかなわない」是「～てはかなわない」的口语形式。', 57, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('b1141dc4-be24-41cc-bcf0-ccaa92dd7b93', 'effa4678-af34-497a-a429-0ce106db84a1', 'おもしろいと言われたからといって、同じ冗談を何度も聞かされちゃかなわない。', 'おもしろいと言われたからといって、同じ冗談を何度も聞かされちゃかなわない。', '有趣是有趣，但是总讲同一个笑话也会让人受不了。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('1bba6d49-1c9c-496a-8364-f7793a6f6d8a', 'effa4678-af34-497a-a429-0ce106db84a1', '夏は体の調子を崩しやすく、私にとっては冬のほうが過ごしやすい。そうは言っても、毎日こう寒くてはかなわない。', '夏は体の調子を崩しやすく、私にとっては冬のほうが過ごしやすい。そうは言っても、毎日こう寒くてはかなわない。', '因为夏天容易吃坏肚子，对我而言冬天更容易度过。虽说如此，每天这么冷也会让人受不了。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('c359ead5-08b5-456d-9f56-cff951eaa0b3', 'effa4678-af34-497a-a429-0ce106db84a1', '仕事が好きだからといって、毎日残業続きではかなわない。', '仕事が好きだからといって、毎日残業続きではかなわない。', '虽然喜欢这份工作，但是每天加班的话还是会受不了。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('10db558b-8582-4b5a-a6d9-f44441a1936e', '～ては～ては', NULL, 'N1', '動て形＋は＋動て形＋は', '動て形＋は＋動て形＋は', '表示动作或者现象的重复出现，“……又……，……又……”。', '使用相同的动词，按照相同顺序反复出现，如「書いては消し、書いては消し」。两个动词前后颠倒使用也可以，如「食べては寝、寝ては食べ」，“吃了睡，睡了吃”。\n固定用法：「作っては壊し、作っては壊し」「降ってはやみ、降ってはやみ」「書いては消し、書いては消し」「食べては寝、寝ては食べる」。', 58, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('1070aaf8-f98b-4085-8bd9-b6fcef10a5f2', '10db558b-8582-4b5a-a6d9-f44441a1936e', '休み中、食べては眠り、食べては眠りの連続で、すっかり太ってしまった。', '休み中、食べては眠り、食べては眠りの連続で、すっかり太ってしまった。', '休假的时候，一直过着吃了睡，睡了吃的生活，胖了很多。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('a9db94f4-0c53-4f80-a44e-5899f93fcfdb', '10db558b-8582-4b5a-a6d9-f44441a1936e', '降ってはやみ降ってはやみの天気が続いている。', '降ってはやみ降ってはやみの天気が続いている。', '这些天总是下下停停，停停下下，阴雨不断。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('da753d7c-109f-4efa-b712-418cda5a6142', '10db558b-8582-4b5a-a6d9-f44441a1936e', '書いては消し、書いては消しながら、やっと期末レポートを完成した。', '書いては消し、書いては消しながら、やっと期末レポートを完成した。', '写了又擦掉，擦了又写，总算写完了期末报告。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('8b01d27c-3a3d-4468-85dc-c21f0a582119', '～て 憚[はばか]らない', NULL, 'N1', '動て形＋憚らない', '動て形＋憚らない', '用来描述他人的言论，“公然断言……”“毫不顾忌……”“肆无忌惮地说……”。', '「 憚[はばか]らない」是「憚る」的否定形式，意思是“毫不顾忌”。\n常与「言う」「宣伝する」「公言する」「断言する」等动词一起使用，多表示消极的意思。', 59, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('f3c9d86b-2032-4cda-a715-2cfb1c8b9c18', '8b01d27c-3a3d-4468-85dc-c21f0a582119', 'その新人候補は、今回の選挙に必ず当選してみせると断言してはばからない。', 'その新人候補は、今回の選挙に必ず当選してみせると断言してはばからない。', '初登政治舞台的人竟然大胆宣称自己一定会在选举中胜出。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('3dec990b-a044-46b8-a21f-fcbaa656cb47', '8b01d27c-3a3d-4468-85dc-c21f0a582119', 'あの監督はいつも今シーズンは優勝すると言ってはばからない。', 'あの監督はいつも今シーズンは優勝すると言ってはばからない。', '那个教练一直公然宣称自己带的队在本赛季一定会获得冠军。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('280151a8-1143-4421-8df2-82c4750db043', '8b01d27c-3a3d-4468-85dc-c21f0a582119', '無知は個性だと宣伝してはばからない人がいる。', '無知は個性だと宣伝してはばからない人がいる。', '有人公开宣称无知是一种个性。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('0736405c-aa3b-42ad-af93-33f567e1f031', '～てはやりきれない', NULL, 'N1', '～てはやりきれない', '～てはやりきれない', '强调主观的感受和情绪，表示某事让人无法忍受、无法接受，“……的话，让人受不了”“……的话，接受不了”。', '「やりきれない」的意思是“……做不完”“……忍受不了”“……应付不了”，可以单独使用。', 60, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('c197b3f5-bc3f-45f6-b6cc-4d8f1528b55e', '0736405c-aa3b-42ad-af93-33f567e1f031', 'こう寒くてはやりきれない。', 'こう寒くてはやりきれない。', '这么冷真让人受不了。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('4d767300-6076-41cc-a021-e3f25a911d0c', '0736405c-aa3b-42ad-af93-33f567e1f031', '毎日文句ばかり聞かされてはやりきれない。', '毎日文句ばかり聞かされてはやりきれない。', '每天听到的尽是抱怨，真是受不了。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('2d43ff48-6c73-46b6-88f0-581dfacd9460', '0736405c-aa3b-42ad-af93-33f567e1f031', '実力が足りなかったといえばそれまでだが、このように採用を拒否されてはやりきれない。', '実力が足りなかったといえばそれまでだが、このように採用をきょひされてはやりきれない。', '说是实力不够也就罢了，但是像这样被拒绝还是让人无法接受。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('8780e39e-f9d9-4b14-8fb7-469c11ec895c', '0736405c-aa3b-42ad-af93-33f567e1f031', '金詰りでどうにもやりきれない。', 'かねづまりでどうにもやりきれない。', '资金周转出了问题，无法应付。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('0feb988f-4534-45ca-86c0-6d58c1633443', '～てまで', NULL, 'N1', '動て形＋まで', '動て形＋まで', '表示程度。“甚至不惜……”。为达到某种目的，甚至不惜做出超乎寻常的事情。', '意思与「名＋までして」相同。\n既可表示对某种行为的批判、责备，也可表示积极的意思。', 61, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('c1cae226-096c-4f57-a005-fbeb957612ce', '0feb988f-4534-45ca-86c0-6d58c1633443', '趣味を持つのは良いことだと思いますが、家庭を犠牲にしてまでとなると、それはちょっと問題です。', '趣味を持つのは良いことだと思いますが、家庭を犠牲にしてまでとなると、それはちょっと問題です。', '有兴趣爱好是好的，但如果到了牺牲家庭的份上，那就有问题了。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('f7d97027-444e-479c-8e35-00e42f7b7275', '0feb988f-4534-45ca-86c0-6d58c1633443', '借金してまで遊びに行ったと聞いて、あきれてしまった。', 'しゃっきんしてまで遊びに行ったと聞いて、あきれてしまった。', '听说他（她）甚至不惜借钱出去玩，真是让人无法理解。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('efa6363c-8d16-4df6-8655-342b5f5373c0', '0feb988f-4534-45ca-86c0-6d58c1633443', '最近の祭りは以前ほど活気がなくなってきた。仕事を休んでまで行く必要はないだろう。', '最近の祭りは以前ほどかっきがなくなってきた。仕事を休んでまで行く必要はないだろう。', '现在的节日庆祝活动不像以前那么有意思，没必要请假去参加。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('d8b4310f-659d-4647-9f14-4e0a1f48dfe1', '0feb988f-4534-45ca-86c0-6d58c1633443', '自分の信念を捨ててまで他人に従うことはない。', '自分の信念を捨ててまで他人に従うことはない。', '没必要为了迎合别人而放弃自己的信念。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('34a18c46-60ff-460b-bc62-fd638abe3964', '～ても 差[さ]し 支[つか]えない', NULL, 'N1', '～ても 差[さ]し 支[つか]えない', '～ても 差[さ]し 支[つか]えない', '表示不影响、没有妨碍。“即使……也没有关系”。', '意思与「～てもかまわない」相同。「～てもさしつかえない」是更为正式的表达方式。\n「差し支えない」的意思是“没有影响、不妨碍”。', 62, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('b9b61776-08f5-4de8-b2c3-7eb3a6f0ddb0', '34a18c46-60ff-460b-bc62-fd638abe3964', '手術後の経過が順調だったら、来週は散歩に出てもさしつかえない。', '手術後の経過が順調だったら、来週は散歩に出てもさしつかえない。', '手术过后如果恢复得好，下周出去散步也没有关系。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('d2f6afc7-2091-4360-bafe-993b10e7b778', '34a18c46-60ff-460b-bc62-fd638abe3964', '具合が悪かったら、今日は早退してもさしつかえない。', '具合が悪かったら、今日は早退してもさしつかえない。', '身体不舒服的话，今天早一点回去也没有关系。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('d245ea62-0f28-4add-80d3-8aa9d0acf0d2', '34a18c46-60ff-460b-bc62-fd638abe3964', 'この書類は部内で使うから、判子を押さなくてもさしつかえない。', 'この書類は部内で使うから、はんこを押さなくてもさしつかえない。', '这份文件只在部门内使用，不盖章也没有关系。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('d2ff29d2-e868-4277-b46c-8460fe69e598', '～でもしたら', NULL, 'N1', '動ます形＋でもしたら', '動ます形＋でもしたら', '表示假设，“一旦……的话，就会……”、“如果……就（糟了）……”。', '用于举出某个不好的例子，带有“万一发生某种情况就糟了”的语感。', 63, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('f40c2969-e394-4d1b-a7d8-4f9e7f7bb505', 'd2ff29d2-e868-4277-b46c-8460fe69e598', '子ども「お母さん、来週の日曜日、さくら山に行ってもいい？」母親「だめよ。今の季節、あの山にハチがたくさん出るのよ。万が一、刺されでもしたら大変でしょ。」', '子ども「お母さん、来週の日曜日、さくら山に行ってもいい？」母親「だめよ。今の季節、あの山にハチがたくさん出るのよ。万が一、刺されでもしたら大変でしょ。」', '孩子：“妈妈，下周日，我可以去樱山吗？”\n母亲：“那可不行！这个季节，那座山上有很多蜜蜂，一不小心被蜇了就糟了。”', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('415cbc08-b36f-4375-968f-cc241528221a', 'd2ff29d2-e868-4277-b46c-8460fe69e598', 'おじいさんの古時計、触らないで。壊しでもしたら大変なことになるからね。', 'おじいさんの古時計、触らないで。壊しでもしたら大変なことになるからね。', '爷爷的旧手表，你可别碰。要是弄坏了可就糟了。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('420fa9ca-70b2-4771-9e03-185b70690db2', 'd2ff29d2-e868-4277-b46c-8460fe69e598', '今度また何かトラブルを起こしでもしたら、辞めてもらうよ。', '今度また何かトラブルを起こしでもしたら、辞めてもらうよ。', '今后如果你再出什么问题就会让你辞职走人。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('fd13cd96-51e7-437d-a788-449514c60bdf', '～ても 知[し]らない', NULL, 'N1', '動て形＋も知らない', '動て形＋も知らない', '“如果（你）继续……的话，我可不管了”“如果再……的话，可就……”。', '「～ても知らない」多用来警告、提醒对方如果这个状态继续下去会出现严重的后果。', 64, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('912c4478-6d1d-4f14-842f-c1f6bf5e363b', 'fd13cd96-51e7-437d-a788-449514c60bdf', 'こうやって毎日休まずに働いては体を壊しても知らない。', 'こうやって毎日休まずに働いては体を壊しても知らない。', '像这样一天都不休息地工作，把身体弄垮了我可不管你。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('2ffa5e7e-f541-4320-81f3-de777e993420', 'fd13cd96-51e7-437d-a788-449514c60bdf', '授業をサボってばかりいては、試験に落ちても知らない。', '授業をサボってばかりいては、試験に落ちても知らない。', '一直逃课的话，考试不及格我可不管了。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('0bbbb941-722e-4203-8fa3-f0b300791ea7', 'fd13cd96-51e7-437d-a788-449514c60bdf', '朝食ぬきでは、胃を壊しても知らないぞ。', '朝食ぬきでは、胃を壊しても知らないぞ。', '不吃早饭的话，把胃弄坏了我可不管你。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('cf899f8f-d5bd-44f0-b39c-38edc070469c', '～でもって', NULL, 'N1', '名＋でもって', '名＋でもって', '表示手段和方法，“用……”“以……”“凭借……”。', '多用在口语中。\n用法和表示手段、方式的「～をもって」相似。', 65, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('c514bcd1-e08d-465f-a0e5-903c62489672', 'cf899f8f-d5bd-44f0-b39c-38edc070469c', '行為でもって誠意を示すことだ。', '行為でもって誠意を示すことだ。', '应该通过行为表现自己的诚意。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('195d10f2-b918-4c56-b280-a37aa8eb05d8', 'cf899f8f-d5bd-44f0-b39c-38edc070469c', '言葉だけでは足りない。行動でもって証明してください。', '言葉だけでは足りない。行動でもって証明してください。', '光说是不行的，要通过行动来证明。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('3f27ff22-3319-40bd-9f15-ac6e691b6131', 'cf899f8f-d5bd-44f0-b39c-38edc070469c', '金でもって始末できないこともある。', '金でもって始末できないこともある。', '有些事情不是单靠钱就能够解决的。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('5df9f246-d6a6-498c-b189-de890e55c713', 'cf899f8f-d5bd-44f0-b39c-38edc070469c', '面接の結果は書面をもってお知らせします。', '面接の結果は書面をもってお知らせします。', '面试的结果会以书面形式通知。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('90a18745-7253-4ff9-8e9a-9009f636d613', '～てもどうにもならない/てもどうなるものでもない', NULL, 'N1', '動て形＋も＋どうにもならない/どうなるものでもない', '動て形＋も＋どうにもならない/どうなるものでもない', '表示假定条件的逆接，即使做了前项也解决不了问题。“即使……也无济于事”。', '用法与「～てもしかたがない」相同。', 66, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('83845835-cc0f-4aa1-9edf-8190e61b452f', '90a18745-7253-4ff9-8e9a-9009f636d613', '今さら反対してもどうなるものでもない。', '今さら反対してもどうなるものでもない。', '事到如今再反对也无济于事。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('26b7fc7e-6d6a-440f-8ab1-1e59048c8543', '90a18745-7253-4ff9-8e9a-9009f636d613', '過ぎたことを後悔してもどうにもならない。', '過ぎたことを後悔してもどうにもならない。', '已经过去的事情，即使后悔也没用。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('7a526ce7-a23e-4f41-8a76-1b00155c0af7', '90a18745-7253-4ff9-8e9a-9009f636d613', '負けたことを反省してもどうなるものでもない。', '負けたことを反省してもどうなるものでもない。', '已经输了再去反省也没有用。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('10bc5224-e094-40e3-891a-964338710ee4', '～てもともとだ', NULL, 'N1', '～てもともとだ', '～てもともとだ', '表示内心的一种想法，“……的话也无所谓”“原本也没有抱太大希望……”。', '用于“可能性不大的事情”或者“挑战过却失败了”等场合。\n多表示“即使失败了也不会吃亏，所以要敢于尝试”的意思。\n惯用「だめでもともとだ/だめもと」（不行也无所谓）。', 67, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('560f5b34-bb91-47ad-bc01-385cd0898afa', '10bc5224-e094-40e3-891a-964338710ee4', '採用の条件には合わないけど、だめでもともとだから、この会社に履歴書を出してみよう。', '採用の条件には合わないけど、だめでもともとだから、この会社に履歴書を出してみよう。', '虽然不符合招聘条件，但是抱着试一试的心态给这家公司投了简历。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('26bcdfb0-bacd-40b1-a587-2d02cbdc4447', '10bc5224-e094-40e3-891a-964338710ee4', 'だめでもともとだから、思い切って彼女に告白してみた。', 'だめでもともとだから、思い切って彼女にこくはくしてみた。', '就算被拒绝也无所谓，就试着鼓起勇气跟她告白了。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('bdf26178-8c61-45d3-abd5-6e72e9cd813c', '10bc5224-e094-40e3-891a-964338710ee4', 'あのチームが相手だったら負けてもともとだ。とにかく全力を尽くすことができればそれでいい。', 'あのチームが相手だったら負けてもともとだ。とにかく全力を尽くすことができればそれでいい。', '对手是那个队的话输了也没什么，只要尽力了就行。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('500b5eb7-7fbd-4763-8c06-70fabf6dc946', '～でも 何[なん]でもない/くも何ともない', NULL, 'N1', '名/ナ形語幹＋でも何でもない', '名/ナ形語幹＋でも何でもない\nイ形―く＋も何ともない', '表示强烈的否定，“一点也不……”“根本不……”“什么都不……”。', '表达强烈的否定、批判、不满的语气。\n多用在口语中，用来评价某人某事。', 68, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('c3947c1b-43ba-4e33-a1a9-01a001347208', '500b5eb7-7fbd-4763-8c06-70fabf6dc946', '私に言わせれば、あんな人は政治家でも何でもない。', '私に言わせれば、あんな人は政治家でも何でもない。', '要让我来说的话，那种人根本不能算是政治家。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('0718cdf5-3a5e-43fc-a9af-4f1e76edf9cf', '500b5eb7-7fbd-4763-8c06-70fabf6dc946', '彼は病気でも何でもない。ただずる休みしたいだけかもしれない。', '彼は病気でも何でもない。ただずる休みしたいだけかもしれない。', '他根本不是生病了，也许只是想偷懒休息一下罢了。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('55990559-9f9a-4650-80a3-4d80adb1ee7b', '500b5eb7-7fbd-4763-8c06-70fabf6dc946', 'そんなの痛くも何ともないよ。', 'そんなの痛くも何ともないよ。', '那一点（小伤）一点儿也不疼。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('0c26d079-dbd4-45fb-976f-d1817bb7c15b', '～ても 始[はじ]まらない', NULL, 'N1', '動て形＋も始まらない', '動て形＋も始まらない', '表示假定条件的逆接，多指前项的动作没有太大意义。“即使……也无济于事”。', '用法与「～ても仕方がない」「～てもどうなるものでもない」「～てもどうにもならない」相同。', 69, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('0652bd00-c880-4306-9d24-764226f61eb3', '0c26d079-dbd4-45fb-976f-d1817bb7c15b', 'いまさら担当者を責めても始まらない。', 'いまさら担当者を責めても始まらない。', '事到如今再去责备负责人也无济于事。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('8a33045a-4045-4200-bddf-c187b1c07295', '0c26d079-dbd4-45fb-976f-d1817bb7c15b', '同じことをいつまで議論しても始まらない。', '同じことをいつまで議論しても始まらない。', '一直讨论同一件事也无济于事。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('209833ab-4c7d-4aaa-8137-8bd423e5f538', '0c26d079-dbd4-45fb-976f-d1817bb7c15b', 'どうにもならないことを悩んでいても始まらない。', 'どうにもならないことを悩んでいても始まらない。', '为这种没有办法的事情烦恼也没用。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('7764ee75-2349-43a2-a67e-bc25c8f1e34e', '～てやまない', NULL, 'N1', '動て形＋やまない', '動て形＋やまない', '表达强烈的愿望和一种心情，“……不已”“非常……”“衷心地……”。', '常与「祈る」「期待する」「願う」「愛する」「尊敬する」等动词一起使用。', 70, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('b00a2500-9a74-4533-b948-e42eda80b188', '7764ee75-2349-43a2-a67e-bc25c8f1e34e', '多くの困難にも負けず、努力を続けている彼女はすばらしい。私は彼女の成功を願ってやまない。', '多くの困難にも負けず、努力を続けている彼女はすばらしい。私は彼女の成功を願ってやまない。', '尽管挫折不断但还是坚持努力的她让人佩服。我衷心希望她能够获得成功。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('984c53b5-8d92-4e92-8f57-e789ded2925a', '7764ee75-2349-43a2-a67e-bc25c8f1e34e', '結婚する二人の今後の幸せを願ってやまない。', '結婚する二人の今後の幸せを願ってやまない。', '衷心祝愿二位婚后生活幸福。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('9cebc6cb-a9d0-4a9d-bc83-e958f8bbe1a7', '7764ee75-2349-43a2-a67e-bc25c8f1e34e', '皆さんの健康と幸せを祈ってやみません。', '皆さんの健康と幸せを祈ってやみません。', '衷心祝愿大家身体健康，生活幸福美满。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('6efb95cd-56a7-4798-a4ce-2a69b0010a93', '7764ee75-2349-43a2-a67e-bc25c8f1e34e', '尊敬してやまない佐藤先生の講演会に行った。', '尊敬してやまない佐藤先生の講演会に行った。', '去参加了我很尊敬的佐藤老师的演讲会。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('ac06e35b-3217-4baa-8bc4-5b78644f10c0', '～と（が） 相[あい]まって/も相まって', NULL, 'N1', '名A＋と＋名B＋と（が）相まって', '名A＋と＋名B＋と（が）相まって\n名A＋が＋名B＋と相まって\n名B＋も相まって', '表示附加关系，两个因素相互作用，使得状态和效果更加明显。“A和B相辅相成、相互作用，（使得）……（更加）”。', '助词的使用可以有如下几种形式「～AはBとあいまって」「～AとBがあいまって」「～AとBとがあいまって」。\n第一个因素有时在句中并没有明确提及，而是用「～Bもあいまって」的形式，只提到第二个因素。意思是“……（原本就）……，再加上B的影响……所以就……”。', 71, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('b241e884-5b99-42d2-9411-afdbe4cba7fb', 'ac06e35b-3217-4baa-8bc4-5b78644f10c0', 'この家具は、複雑なデザインが華やかな色彩と相まって、素晴らしい製品となっている。', 'この家具は、複雑なデザインがはなやかなしきさいと相まって、素晴らしい製品となっている。', '这套家具繁复的设计和华丽的色彩相得益彰，成为一件精彩绝伦的作品。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('42ba4878-5aa1-462f-bcff-e10d0a83a0ae', 'ac06e35b-3217-4baa-8bc4-5b78644f10c0', '急速な少子化は、高齢者の増加とあいまって、日本の人口構造を大きく変えてきている。', '急速な少子化は、高齢者の増加とあいまって、日本の人口構造を大きく変えてきている。', '少子化的加剧加上高龄者的增加，使得日本的人口结构发生了巨大变化。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('f55ba91e-ba16-44a3-a4ea-0a108740931c', 'ac06e35b-3217-4baa-8bc4-5b78644f10c0', '厳しい経済状況もあいまって、就職は非常に困難だった。', '厳しい経済状況もあいまって、就職は非常に困難だった。', '也是受到严峻的经济形势的影响，今年的就业情况十分困难。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('0b742093-8af6-44b9-9823-80408c395248', 'ac06e35b-3217-4baa-8bc4-5b78644f10c0', 'ふるさとを歌ったこの曲は、子どものころの思い出とあいまって、私の心に深く響く。', 'ふるさとを歌ったこの曲は、子どものころの思い出とあいまって、私の心に深くひびく。', '歌唱故乡的这首曲子勾起了我对童年的回忆，深深地打动了我。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('e21cfd9c-edb9-43cc-a048-ca999e08d178', '～とあって', NULL, 'N1', '動普通形/イ形/ナ形語幹/名＋とあって', '動普通形/イ形/ナ形語幹/名＋とあって', '表示因果关系。“因为……”“由于……”。', '由于前项的特殊情况，所以出现了后项的现象。\n后项不能用命令、推测、祈使、劝诱等表达方式。\n接续名词和形容动词时，「だ」可以省略。', 72, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('8b76696d-bab4-4e8d-9c59-d1acd61dcafe', 'e21cfd9c-edb9-43cc-a048-ca999e08d178', '人気作家A氏の講演会が無料とあって、多くのファンが詰めかけた。', '人気作家A氏の講演会が無料とあって、多くのファンがつめかけた。', '因为人气作家A氏的演讲是免费的，所以很多粉丝都赶过来了。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('83428cf9-f7eb-48a6-b267-f505969d61c7', 'e21cfd9c-edb9-43cc-a048-ca999e08d178', '連休とあって、遊園地は相当な混雑だったようだ。', '連休とあって、遊園地は相当なこんざつだったようだ。', '因为是长假期间，游乐场好像十分拥挤。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('06d76d24-61e4-425d-9e10-c31320117877', 'e21cfd9c-edb9-43cc-a048-ca999e08d178', '人気俳優がくるとあって、このイベントのチケットはあっという間に売り切れた。', '人気俳優がくるとあって、このイベントのチケットはあっという間に売り切れた。', '因为有很受欢迎的演员来参加这个活动，门票瞬间就卖完了。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('6f13b629-f16f-48f1-bb12-dac918ce66b9', 'e21cfd9c-edb9-43cc-a048-ca999e08d178', '人気映画の上映初日とあって、映画館の入り口の前には長い行列ができた。', '人気映画のじょうえいしょにちとあって、映画館の入り口の前には長いぎょうれつができた。', '因为是一部很受欢迎的电影的首映日，所以电影院的门口排起了长队。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('8185cb96-0833-4bc8-82f5-d665c481fe82', '～とあっては', NULL, 'N1', '動辞書形/名＋とあっては', '動辞書形/名＋とあっては', '表示假设，用来描述某种特别的情况，“若是……的话，就会……”。后项叙述在那种状态下应该采取的行动或者发生的事情。', '后项常用「～なければならない」「～ないわけにはいかない」「～ないはずがない」「～ 断[ことわ]れない」等表达方式。', 73, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('3d87299e-1765-40cc-90da-29c5146c6c39', '8185cb96-0833-4bc8-82f5-d665c481fe82', '新幹線の新型車両が初めて一般に公開されるとあっては、鉄道ファンの私としては、見に行かないわけにはいかない。', 'しんかんせんのしんがたしゃりょうが初めて一般にこうかいされるとあっては、鉄道ファンの私としては、見に行かないわけにはいかない。', '新干线的新车型首次向公众展示的话，作为火车迷的我，不可能不去看。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('bbb04540-573b-4283-99e4-62330c656b59', '8185cb96-0833-4bc8-82f5-d665c481fe82', '上司の指示とあっては、仕事の内容が気に入らなくてもやらなければならない。', '上司の指示とあっては、仕事の内容が気に入らなくてもやらなければならない。', '若是上司的命令，就算工作的内容不太喜欢也必须要做。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('dc6757a0-1e99-4cc5-b6d4-dddcca931708', '8185cb96-0833-4bc8-82f5-d665c481fe82', '大好きなアイドル歌手がコンサートを開くとあっては、何とかして見に行かなければいけない。', '大好きなアイドル歌手がコンサートを開くとあっては、何とかして見に行かなければいけない。', '自己很喜欢的偶像歌手要开演唱会的话，无论如何也要想办法去看一下。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('347f3cd9-a797-4077-9e23-695eff2a00b7', '～とあれば', NULL, 'N1', '動普通形/イ形/ナ形語幹/名＋とあれば', '動普通形/イ形/ナ形語幹/名＋とあれば', '表示假设，如果为了前项的事情，可以尽最大努力或者既然前项如此，就不得不做后项的事情。“如果是……”“既然是……就（不得不）……”。', '接续名词和形容动词时，「だ」可以省略。\n固定用法：「～のためとあれば」/若是为了……', 74, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('aab394ac-304e-4f10-b1ce-3363b8c5a27d', '347f3cd9-a797-4077-9e23-695eff2a00b7', '彼は、お金のためとあれば、どんな仕事でも引き受ける。', '彼は、お金のためとあれば、どんな仕事でも引き受ける。', '若是为了钱，他什么工作都会接受。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('acad140b-13c8-4b31-849f-dca87753a398', '347f3cd9-a797-4077-9e23-695eff2a00b7', '大学時代の指導教官の頼みとあれば、断るわけにはいかない。', '大学時代の指導教官のたのみとあれば、断るわけにはいかない。', '如果是大学时代的指导教官的请求，就不太好回绝。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('01209046-a345-4f50-b41b-15faccdeb271', '347f3cd9-a797-4077-9e23-695eff2a00b7', '誰も手伝ってくれないとあれば、一人でやるしかない。', '誰も手伝ってくれないとあれば、一人でやるしかない。', '如果没有人帮忙的话，只能一个人做了。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('708cbc71-c3be-445d-908c-78ba0a1a5596', '347f3cd9-a797-4077-9e23-695eff2a00b7', '親は子どものためとあれば、できる限りのことをするものです。', '親は子どものためとあれば、できる限りのことをするものです。', '父母为了孩子的话无论什么事都会尽力而为的。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('608beca2-c6b5-40e1-b134-9393c75eadca', '～といい～といい', NULL, 'N1', '名A＋といい＋名B＋といい', '名A＋といい＋名B＋といい', '表示对事物的评价，“无论（A的方面）也好，B（的方面）也好……，都……”。', '其中A和B是用来描述同一对象的两个不同的侧面，后项用总体评价。', 75, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('fee7e7b7-3685-489f-bb1e-7ed744be1e2e', '608beca2-c6b5-40e1-b134-9393c75eadca', 'この家は、広さといい、価格といい、新婚夫婦にぴったりだ。', 'この家は、広さといい、価格といい、新婚夫婦にぴったりだ。', '这套房子总面积也好，价格也好，对于新婚夫妇来说都是最合适不过了。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('a5d6b0e2-daf5-488b-8cbb-db5aeb3c2557', '608beca2-c6b5-40e1-b134-9393c75eadca', 'あの店の服は、品質といい、デザインといい、申し分ない。', 'あの店の服は、品質といい、デザインといい、もうしぶんない。', '那家店的服装无论是质量方面，还是设计方面，都无可挑剔。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('3aa3bd15-08a8-40e4-89e5-b84d2932131a', '608beca2-c6b5-40e1-b134-9393c75eadca', 'A社のパソコンは値段といい、機能といい、競争力がある。', 'A社のパソコンは値段といい、機能といい、競争力がある。', 'A公司的电脑无论在价格方面还是在性能方面都很有竞争力。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('563ba927-3126-4fee-a841-5b0112d05c8f', '～という', NULL, 'N1', '名A＋という＋名A', '名A＋という＋名A', '表示强调，“所有的……全都……”“……全部都……”。', '同一名词重复出现，强调整体的状态。\n是书面的文学性的表达方式，强调“所有的全都……”。', 76, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('6844341e-5a41-4da2-951c-920b927763eb', '563ba927-3126-4fee-a841-5b0112d05c8f', '学校が始まる日の朝、道路という道路は車であふれていた。', '学校が始まる日の朝、道路という道路は車であふれていた。', '学校开学的那天早上，所有的路上都是车。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('38d3dede-fb6a-465a-be7b-c9962718c7db', '563ba927-3126-4fee-a841-5b0112d05c8f', '家という家はクリスマスツリーを飾り付けて、クリスマスイブの喜びを表わしている。', '家という家はクリスマスツリーを飾り付けて、クリスマスイブの喜びを表わしている。', '家家户户都装饰着圣诞树，庆祝着平安夜。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('f09e6ede-d88a-41c0-9bab-c3efbdcb8257', '563ba927-3126-4fee-a841-5b0112d05c8f', '子どものいたずらで、壁という壁は全部落書きされている。', '子どものいたずらで、壁という壁は全部らくがきされている。', '所有的墙壁全是孩子恶作剧式的乱写乱画。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('2a7d1474-414a-4d03-a7e7-a5af3f58ebad', '～というか～というか', NULL, 'N1', '～というか～というか', '～というか～というか', '表示对人或事情的评价，“不知道该说是……好呢，还是说是……好呢，总之……”“是……呢，还是……呢，总之……”。', '对前项中提到的人或者事情，列举一些自己的感受或者印象。后项多是总结性的评价。\n区别「～といい～といい」的用法。「～といい～といい」是列举同一对象的两个侧面，只能接续名词。「～というか～というか」是列举自己对前项的人或事的感受和评价，可以接续形容词、动词等。', 77, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('30bba108-3943-48ad-b21f-f1f5d966ae92', '2a7d1474-414a-4d03-a7e7-a5af3f58ebad', '一人であんな危険な場所へ行くとは、無茶というか、無知というか、とにかく私には理解できない。', '一人であんな危険な場所へ行くとは、むちゃというか、むちというか、とにかく私には理解できない。', '独自一人跑到那么危险的地方，说她是胡闹呢，还是说她是无知呢，总之我无法理解。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('7478f9c4-8c35-4ea4-a777-77afddbe7d7b', '2a7d1474-414a-4d03-a7e7-a5af3f58ebad', 'そのときの彼の表情は寂しいというか、情けないというか、はっきり言葉で説明できない。', 'そのときの彼の表情は寂しいというか、情けないというか、はっきり言葉で説明できない。', '那个时候他的神情很寂寞，又像是在难过自责的样子，总之无法用语言形容。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('f066343b-e9dc-40e6-8970-5740c2cc1a02', '2a7d1474-414a-4d03-a7e7-a5af3f58ebad', 'このドラマの最終回については、がっかりしたというか、理解できないというか、複雑な気持ちでいっぱいだ。', 'このドラマの最終回については、がっかりしたというか、理解できないというか、複雑な気持ちでいっぱいだ。', '对这个电视剧的结局不知该说是失望好，还是说难以理解，总之心情很复杂。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('102fa7a9-3660-4a66-a4a9-c8637b3db839', '～というところだ/といったところだ', NULL, 'N1', '動辞書形/名＋というところだ/といったところだ', '動辞書形/名＋というところだ/といったところだ', '表示界限、范围，“大概是……”“大致上……”“最多不过是……”。', '前面常用表示程度、数量、级别的词。\n强调“再多、再好也不过如此”的语气。', 78, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('d46a9bb2-5850-4556-ab29-010b031ac805', '102fa7a9-3660-4a66-a4a9-c8637b3db839', 'A「頂上までどのぐらいかかりますか。」B「大人の私で2時間半といったところでしたから、お子さん連れなら、半日かかるかもしれませんね。」', 'A「頂上までどのぐらいかかりますか。」B「大人の私で2時間半といったところでしたから、お子さん連れなら、半日かかるかもしれませんね。」', 'A：“到山顶大约要多长时间？”\nB：“像我这样的大人要两个半小时的话，您带着孩子大概需要半天吧。”', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('e03d8ace-f7e0-47fe-8200-873b223aab15', '102fa7a9-3660-4a66-a4a9-c8637b3db839', '自分で料理を作るといっても、せいぜいサラダとかゆで卵といったところだ。', '自分で料理を作るといっても、せいぜいサラダとかゆで卵といったところだ。', '说是自己会做饭，但最多不过是会做些色拉和煮鸡蛋而已。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('03fd3498-9659-4915-9781-b80c51f6d6f3', '102fa7a9-3660-4a66-a4a9-c8637b3db839', '日本滞在経験のある彼だが、日本語でできるのは挨拶や自己紹介といったところだ。', '日本滞在経験のある彼だが、日本語でできるのは挨拶や自己紹介といったところだ。', '尽管他曾经在日本待过，但是所会的日语不过是一些寒暄和自我介绍罢了。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('649adbb7-ce01-429b-82df-2ccbe2284ea4', '102fa7a9-3660-4a66-a4a9-c8637b3db839', '今年の売り上げは、まあまあといったところだ。', '今年の売り上げは、まあまあといったところだ。', '今年的销售额只能说是过得去。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('0cdce2f1-a2d3-4c30-a7ce-4319bbbbd02a', '～というもの', NULL, 'N1', 'ここ/この＋名＋というもの', 'ここ/この＋名＋というもの', '描述最近很长的一段时间内一直处于某种状态，“这段时间以来……”。', '常用表示最近一段时间的名词，如「ここ1か月間」「この1週間」等。\n后面的状态多是非正常的、与以往不同的、偏向消极方面的。', 79, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('efa052b1-5e79-4c69-8df6-f2f718ed9dd5', '0cdce2f1-a2d3-4c30-a7ce-4319bbbbd02a', '彼女はここ1か月間というもの、授業を休んでいる。', '彼女はここ1か月間というもの、授業を休んでいる。', '她这一个月以来，一直没来上课。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('cb26a09a-8001-4014-b175-701e92c417cc', '0cdce2f1-a2d3-4c30-a7ce-4319bbbbd02a', '田中さんは、この1週間というもの、仕事どころではないようだ。', '田中さんは、この1週間というもの、仕事どころではないようだ。', '田中这个星期以来，心思都不在工作上。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('a8fb3935-bf9f-4496-b534-1c4ed840c022', '0cdce2f1-a2d3-4c30-a7ce-4319bbbbd02a', 'この一か月間というもの、仕事が忙しくて朝ごはんをろくに食べていない。', 'この一か月間というもの、仕事が忙しくて朝ごはんをろくに食べていない。', '这一个月以来，工作太忙了，都没怎么好好吃早饭。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('2687a465-d51e-4cfa-b637-3c216a118997', '～といえども', NULL, 'N1', '動普通形/イ形/ナ形/名＋といえども', '動普通形/イ形/ナ形/名＋といえども', '表示让步转折，承认前项的事实，但是后项的问题还是未能解决。“即使……也……”“虽说……但是……”。或者举出某个特殊的例子“就连……也（不能）……”“虽说……但还是（无法）……”。', '接续名词、形容动词时，「だ」可以省略。\n用法与「～といっても」相同，后项多用否定。', 80, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('abb81667-484d-4f56-b718-6009fd0589b3', '2687a465-d51e-4cfa-b637-3c216a118997', '仕事がたまっていて、連休といえども毎日出社しなければならない。', '仕事がたまっていて、連休といえども毎日出社しなければならない。', '因为很多工作都没有处理完，即使是放长假，也要每天来上班。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('7b6a5f45-22f5-4526-b304-d847d15e4017', '2687a465-d51e-4cfa-b637-3c216a118997', '国際政治の専門家といえども、日々変化する世界情勢を分析するのは難しい。', '国際政治の専門家といえども、日々変化する世界情勢を分析するのは難しい。', '就算是国际政治方面的专家，对于瞬息万变的国际形势也很难作出准确的分析。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('dd384a88-be7c-4d8c-b2a8-a67ff4806626', '2687a465-d51e-4cfa-b637-3c216a118997', '近年、医学がめざましい進歩を遂げたといえども、治せない病気がある。', '近年、医学がめざましい進歩をとげたといえども、治せない病気がある。', '近年来，虽然医学的发展有了惊人的进步，但还是有无法治愈的病。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('079f792b-dd3f-417b-899a-c80b5377c026', '～と 言[い]えなくもない', NULL, 'N1', '動普通形/イ形/ナ形語幹/名＋と言えなくもない', '動普通形/イ形/ナ形語幹/名＋と言えなくもない', '表示消极的肯定，有某种可能性或者可以那样评价。“也可以说是……”“也能说是……”。', '用双重的否定表示消极的肯定。', 81, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('97f3b643-6126-4296-a853-51269ebb1f5b', '079f792b-dd3f-417b-899a-c80b5377c026', 'A「最近、彼はまじめに仕事をしていますか。」B「まあ、前よりはまじめになったといえなくもないんですが。」', 'A「最近、彼はまじめに仕事をしていますか。」B「まあ、前よりはまじめになったといえなくもないんですが。」', 'A：“最近他工作认真吗？”\nB：“啊，不能不说比以前好点了，但是……”', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('c681da55-ba2f-44c1-8c03-93b44b576cc8', '079f792b-dd3f-417b-899a-c80b5377c026', 'A「彼女の歌はプロ並みだね。」B「うーん。まあ、そうと言えなくもないけど…」', 'A「彼女の歌はプロ並みだね。」B「うーん。まあ、そうと言えなくもないけど…」', 'A：“她唱歌真好听，简直是专业水平。”\nB：“嗯，你要这样说的话也不是不行，但是……”', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('58446150-dcf4-41ad-aa5f-3d2b2379bb3a', '079f792b-dd3f-417b-899a-c80b5377c026', '今の生活は充実にしているといえなくもないが、何か物足りない感じがする。', '今の生活は充実にしているといえなくもないが、何かものたりない感じがする。', '现在的生活也能算得上是充实的，但总感觉有点美中不足的地方。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('c177baad-c541-4586-b804-26c246af96a0', '～といったらありはしない/といったらありゃしない/といったらない', NULL, 'N1', '動辞書形/イ形/ナ形語幹/名＋といったら（ありはし）ない', '動辞書形/イ形/ナ形語幹/名＋といったら（ありはし）ない', '用来强调心情或者描述一种状态，“……极了”“没有比……更……”。', '接续动词和名词时，常用表示程度和状态的词。', 82, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('ab75c042-d8d5-4145-b10f-3c27ca875a91', 'c177baad-c541-4586-b804-26c246af96a0', '企画立案というのは苦しい作業だが、自分の案が採用されたときのうれしさといったらない。', 'きかくりつあんというのは苦しい作業だが、自分の案がさいようされたときのうれしさといったらない。', '做企划案是很辛苦的工作，但是自己的方案被采纳时真是开心极了。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('a6149869-1c73-41d7-a0cb-244a9317e0dc', 'c177baad-c541-4586-b804-26c246af96a0', 'ここ1週間の忙しさといったらなかったよ。食事をする時間もろくにとれなかったんだ。', 'ここ1週間の忙しさといったらなかったよ。食事をする時間もろくにとれなかったんだ。', '这一周真是忙得不可开交，甚至连好好吃顿饭的时间都没有。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('e9e0cfac-55af-4e9f-bc82-358d53638994', 'c177baad-c541-4586-b804-26c246af96a0', '彼の部屋の汚さといったらありゃしない。', '彼の部屋の汚さといったらありゃしない。', '他的房间别提有多脏了。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('79cd9eac-01ca-4d79-93f1-e59c0e44e28b', '～ったらない/ったらありゃしない', NULL, 'N1', 'イ形/ナ形語幹/名＋ったらない/ったらありゃしない', 'イ形/ナ形語幹/名＋ったらない/ったらありゃしない', '“极其……”“非常……”“无比……”，是「といったらありゃしない」的口语形式。', '「～といったらありはしない」的口语形式是「～ったらない」「～ったらありゃしない」「～といったらない」等。', 83, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('a1b35d61-64e3-4ad7-a6bc-3240b818ffb4', '79cd9eac-01ca-4d79-93f1-e59c0e44e28b', 'みんなの前で派手に転んで、恥ずかしいったらなかった。', 'みんなの前で派手に転んで、恥ずかしいったらなかった。', '在大家面前狠狠地摔了一跤，别提有多难为情了。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('dfbc3398-1cef-4bf6-9075-44a410106ba1', '79cd9eac-01ca-4d79-93f1-e59c0e44e28b', 'こんな複雑な書類を何十枚も書かなきゃいけないなんて、面倒くさいったらない。', 'こんな複雑な書類を何十枚も書かなきゃいけないなんて、面倒くさいったらない。', '这么繁琐的文件要写几十张真是麻烦。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('0478aabc-2d46-4b6d-a0dd-58efe646452e', '79cd9eac-01ca-4d79-93f1-e59c0e44e28b', '結婚が決まったときの彼女の喜びようったらありゃしなかった。', '結婚が決まったときの彼女の喜びようったらありゃしなかった。', '结婚定下来了的时候，她的喜悦之情简直难以形容。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('56abf4c4-0110-4219-bb9f-1d4648f1d473', '～といって～ない/といった～ない', NULL, 'N1', 'これ＋といって～ない', 'これ＋といって～ない\nこれ＋という/といった＋名＋ない', '“并没有特别值得一提的……”。', '也可以用「疑問詞＋といって～ない」。', 84, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('6bee2060-dc28-45fe-a182-f152dfcf8d60', '56abf4c4-0110-4219-bb9f-1d4648f1d473', '今週の新聞にはこれといってたいしたニュースは載っていない。', '今週の新聞にはこれといってたいしたニュースは載っていない。', '这一周的报纸上并没有什么特别值得一提的新闻。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('ff687654-71ff-4406-b350-f62b81630040', '56abf4c4-0110-4219-bb9f-1d4648f1d473', '食べ物に関してはこれといった好き嫌いはないんですが、着るものにはこだわりがあります。', '食べ物に関してはこれといった好き嫌いはないんですが、着るものにはこだわりがあります。', '虽然在吃的方面没有什么挑剔的，但是在穿的方面很讲究。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('e9ae1801-9ce7-4d94-b69b-4283dbd9fda3', '56abf4c4-0110-4219-bb9f-1d4648f1d473', '今度の同窓会は誰といって会いたい人もいないので、行かないことにした。', '今度の同窓会は誰といって会いたい人もいないので、行かないことにした。', '这次的同学会我并没有特别想见的人，所以决定不去了。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('1fe64ded-ff4f-4e2d-a9f6-32bc55d58e79', '～といわず～といわず', NULL, 'N1', '名A＋といわず＋名B＋といわず', '名A＋といわず＋名B＋といわず', '表示列举，其中A和B是两个具有代表性的事物，暗示其他的也是如此。“不论……还是……”“……也好……也好”。', '区别「～といい～といい」与「～といわず～といわず」的不同之处。「～といい～といい」的后项多是指说话人的主观评价，而「～といわず～といわず」的后项多是客观存在的事实。', 85, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('6db72f27-7009-49f5-a97e-f2444acc513d', '1fe64ded-ff4f-4e2d-a9f6-32bc55d58e79', '部屋の中の物は、机といわず、いすといわず、めちゃくちゃに壊されていた。', '部屋の中の物は、机といわず、いすといわず、めちゃくちゃに壊されていた。', '房间里的桌子也好，椅子也好，都被毁坏得乱七八糟。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('4a9d2be9-5b3e-4a62-a938-01af902e584d', '1fe64ded-ff4f-4e2d-a9f6-32bc55d58e79', '昼といわず夜といわず、為替相場は時々刻々と変わっている。', '昼といわず夜といわず、かわせそうばじじこっこくと変わっている。', '白天也好晚上也好，外汇市场的行情一直在变化着。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('7bb5245a-9e42-4575-9562-edcb4b74965b', '1fe64ded-ff4f-4e2d-a9f6-32bc55d58e79', '今の若者は休み時間といわず食事中といわずいつも携帯電話を離さない。', '今の若者は休み時間といわず食事中といわずいつも携帯電話を離さない。', '现在的年轻人无论是休息的时间还是吃饭的时间，都离不开手机。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('98eebd63-8661-4b4d-ba1c-ccf0e283ebba', '～と（は） 打[う]って 変[か]わって', NULL, 'N1', '名＋と（は）打って変わって', '名＋と（は）打って変わって', '表示和过去相比发生了根本性的变化，而且这种变化大多在短时间内发生，让人惊讶。与过去形成鲜明的对比。“和……截然不同”“和……大不一样”。', '前面常用「以前」「昨日」等表示时间的词，或者「これまで」「それまで」等。', 86, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('b7c00fbb-5edb-4e29-806f-fae1b4fb5224', '98eebd63-8661-4b4d-ba1c-ccf0e283ebba', 'その作家は、これまでの心温まる恋愛小説とはうってかわって、ミステリー小説を発表した。', 'その作家は、これまでの心温まる恋愛小説とはうってかわって、ミステリー小説を発表した。', '那位作家一改之前的纯爱小说风格，发表了悬疑小说。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('b4c05954-5cee-49b5-bcfa-c3bafb901bc3', '98eebd63-8661-4b4d-ba1c-ccf0e283ebba', 'その議員は当選後、選挙前とはうってかわって、優柔不断な発言を繰り返す。', 'その議員は当選後、選挙前とはうってかわって、ゆうじゅうふだんな発言をくりかえす。', '那位议员当选后和选举前判若两人，说话总是优柔寡断。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('5e7bcabc-de8c-4974-a715-fbc5bc2f47ab', '98eebd63-8661-4b4d-ba1c-ccf0e283ebba', '彼女は課長に昇進してから、それまでとはうってかわって強気になってきた。', '彼女は課長にしょうしんつよきになってきた。', '她晋升课长后跟过去判若两人，变得强硬起来。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('601db1aa-5fe4-43ee-a22c-98ecede87780', '98eebd63-8661-4b4d-ba1c-ccf0e283ebba', '昨日のどしゃ降りとは打って変わって、今日は晴天だった。', '昨日のどしゃぶりとは打って変わって、今日は晴天だった。', '和昨天的倾盆大雨不同，今天是晴天。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('78b33156-4905-44ac-8d18-2939491eb8b5', '～（か）と 思[おも]いきや', NULL, 'N1', '名＋だ/動普通形/イ形/ナ形＋（か）と思いきや', '名＋だ/動普通形/イ形/ナ形＋（か）と思いきや', '表达一种惊讶、意外的语气。“原以为……但出乎意料的是……”“本来以为……却……”“刚刚……就……”。', '后项的结果与前项的预料往往不同或者相反。', 87, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('b9adda90-3798-4ae2-9fa1-c80ecbbbe828', '78b33156-4905-44ac-8d18-2939491eb8b5', '昨日行ったそば屋は、たくさん人が並んでいたので待たされるかと思いきや、意外にもすぐに席に案内された。', '昨日行ったそば屋は、たくさん人が並んでいたので待たされるかと思いきや、意外にもすぐに席に案内された。', '昨天去的荞麦面店，因为有很多人排着队，原以为会等很久，结果出乎意料地马上被带到了座位。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('ede12d27-90b5-4bad-8ccd-e05a62a7c6ac', '78b33156-4905-44ac-8d18-2939491eb8b5', '新番組でこれまでにない役柄を演じる上田秋さん。役作りに悩んでいるのかと思いきやそうでもないという。', '新番組でこれまでにない役柄を演じるうえだあきさん。役作りに悩んでいるのかと思いきやそうでもないという。', '上田秋要在新节目中挑战她迄今为止从未演过的角色。我原以为她一定在为角色的扮演而苦恼，但好像也并不是如此。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('cba6f725-f655-4da4-9e99-88d949b50ea0', '78b33156-4905-44ac-8d18-2939491eb8b5', '今日は暑くなるかと思いきや、むしろ寒いぐらいだった。', '今日は暑くなるかと思いきや、むしろ寒いぐらいだった。', '我想今天应该会变热的，可谁知还有点冷了。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('e2b1f061-a4e6-4759-908f-4f6ff3987e72', '～ときたら', NULL, 'N1', '名＋ときたら', '名＋ときたら', '提示主语，“提到……就……”“说起……就……”。', '前面多接续人名，后项为否定、责难的内容。\n「～ときたら」一般用来表示负面的评价。', 88, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('26af9dcc-8125-4263-8e52-2b6924a8c1c5', 'e2b1f061-a4e6-4759-908f-4f6ff3987e72', '電車でお年寄りに席を譲ろうとしない高校生を見て、父は「近ごろの若者ときたら、困ったものだ。」と嘆いていた。', '電車でお年寄りに席を譲ろうとしない高校生を見て、父は「近ごろの若者ときたら、困ったものだ。」となげいていた。', '看到电车里不给老人让座的高中生，父亲感叹道：“现在的年轻人真是让人头疼。”', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('ab4cd90a-e3cf-4d87-b14f-3a28e56f2b15', 'e2b1f061-a4e6-4759-908f-4f6ff3987e72', 'まったく、うちの犬ときたら！泥棒が入ってきても、寝ていたんですよ。', 'まったく、うちの犬ときたら！泥棒が入ってきても、寝ていたんですよ。', '我们家的狗真是没用！有小偷进来也没反应，居然还在睡。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('cf06df85-91b1-40ed-b4f3-3095da21a3cd', 'e2b1f061-a4e6-4759-908f-4f6ff3987e72', '最近の若い親ときたら子どもが電車の中で騒いでいても、ちっとも注意しようとしない。', '最近の若い親ときたら子どもが電車の中で騒いでいても、ちっとも注意しようとしない。', '最近的年轻父母真是的，看着孩子们在电车里吵闹也不管。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('375a8c4c-724c-4621-8dbd-9e24f18ab1eb', '～ところを', NULL, 'N1', '～ところを', '～ところを', '表示时间、场景、状况等，“当……的时候”“在……之中”。', '后面常用寒暄用语，如「お邪魔してすみません」「ありがとうございます」等，或者一些动词的被动语态。如「見られる」「見つけられる」「 目[もく] 撃[げき]される」「発見される」「邪魔される」「 妨[さまた]げられる」「注意される」「呼び止められる」「 捕[つか]まえられる」「 逮[たい] 捕[ほ]される」等。', 89, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('bf7f0534-2a06-4ab6-bfbd-d364d0c97213', '375a8c4c-724c-4621-8dbd-9e24f18ab1eb', 'お忙しいところを、恐れ入りますが、どうかよろしくお願い申し上げます。', 'お忙しいところを、恐れ入りますが、どうかよろしくお願い申し上げます。', '在您百忙之中实在是抱歉，这件事情就拜托您了。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('daa1a4d1-607b-40ef-aa2d-5b62f83aa34a', '375a8c4c-724c-4621-8dbd-9e24f18ab1eb', '犯人は買い物をしていたところを警官に逮捕された。', '犯人は買い物をしていたところを警官に逮捕された。', '犯人正在买东西的时候被警察抓住了。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('05328af8-f8ea-4dd0-8b94-a16f091f7304', '375a8c4c-724c-4621-8dbd-9e24f18ab1eb', '皆さんお楽しみのところをお邪魔してすみませんが、もう時間です。', '皆さんお楽しみのところをお邪魔してすみませんが、もう時間です。', '很抱歉在大家玩得正开心的时候，打扰一下，已经到时间了。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('329280ea-f627-4bc4-a1bf-03aafa388ad3', '～としたことが', NULL, 'N1', '名＋としたことが', '名＋としたことが', '用来批评某人做了一些与其自身能力不符的事情或者用来自嘲、自我批评。“像……那样的人，（竟然）……”“作为……却……”。', '「～としたことが」前面接续的名词是人名，前项描述其平时的状态，后项描述的行为多与平时的表现不符，表达一种意外、惊讶的语气。', 90, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('1fe124e5-5f4d-4205-b5b5-1156be9f5755', '329280ea-f627-4bc4-a1bf-03aafa388ad3', 'いつも用心深い彼女としたことが、もう少しでキャッチセールスにかかるところだった。', 'いつもようじんぶかい彼女としたことが、もう少しでキャッチセールスにかかるところだった。', '平时总是小心谨慎的她，差点就被街头传销骗了。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('1be82e98-d75a-4790-8586-f599024444f6', '329280ea-f627-4bc4-a1bf-03aafa388ad3', '私としたことが、こんなつまらないミスをするとは…。', '私としたことが、こんなつまらないミスをするとは…。', '我居然犯了这么愚蠢的错误……', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('a919d28f-aefe-4cfb-bfc2-a10ca397988c', '329280ea-f627-4bc4-a1bf-03aafa388ad3', 'クラスでいつも一位をとる彼としたことが、志願大学に落ちたとは。', 'クラスでいつも一位をとる彼としたことが、志願大学に落ちたとは。', '在班上总是考第一名的他居然没有考上报考的大学……', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('b30cd9de-299f-4d11-ae96-124f19ba3f20', '～としたって/としたところで/にしたところで/にしたって', NULL, 'N1', '～としたって/としたところで/にしたところで/にしたって', '～としたって/としたところで/にしたところで/にしたって', '表示让步转折，即使在前项的条件下，后项也不成立。“即使……也……”“就算……也……”。', '「～としたって」「～にしたって」是「～としたところで」「～にしたところで」在口语中的表达方式。\n该句型也可以与疑问词一起使用，意思是“无论……也……”“不管……也……”。', 91, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('86c39436-4cc2-4b4e-8d8c-3e92b339d227', 'b30cd9de-299f-4d11-ae96-124f19ba3f20', 'いくら少人数としたって、パーティーをするにはこの部屋は狭すぎる。', 'いくら少人数としたって、パーティーをするにはこの部屋は狭すぎる。', '即使人数再少，要开派对的话，这个房间也太小了。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('b4e37630-8485-4f72-be25-fbed12b5b362', 'b30cd9de-299f-4d11-ae96-124f19ba3f20', '社長にしたところで、今回の改革案に疑問を抱いているらしい。', '社長にしたところで、今回の改革案に疑問を抱いているらしい。', '好像就连社长也对这次的改革方案持有疑问。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('f5c09867-238f-49d6-bbd8-9c9413d47c1a', 'b30cd9de-299f-4d11-ae96-124f19ba3f20', '気に入った物件が見つかったとしたって、買うだけの頭金が足りない。', '気に入った物件が見つかったとしたって、買うだけのあたまきんが足りない。', '就算找到了中意的房子，也不够付首付。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('d21443d6-b241-429e-90c1-27e91d8933e6', '～として～ない', NULL, 'N1', '名＋として～ない', '名＋として～ない', '表示全面否定，“没有（一人）……”“没有（一个）……”“没有（一天）……”“没有（一刻）……”“从来没有……过”。', '前面常接续最小的数量词，如「一人」「一日」「 一[いっ] 刻[こく]」「 一[いっ] 着[ちゃく]」等。后面的谓语用否定形。\n句型的意思与「全然～ない」相同。', 92, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('91cd4224-dfb4-4737-bceb-583880c8c5ef', 'd21443d6-b241-429e-90c1-27e91d8933e6', '今回の期末試験では、一人として満点をとる生徒はいなかった。', '今回の期末試験では、一人として満点をとる生徒はいなかった。', '这次的期末考试没有人考满分。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('5feb8349-b8de-4bf5-9de3-1e316b94bab0', 'd21443d6-b241-429e-90c1-27e91d8933e6', '面接の服装を買いにそのデパートに行ったけど、一着として私に似合いそうな服は見当たらなかった。', '面接の服装を買いにそのデパートに行ったけど、いっちゃくとして私に似合いそうな服はみあたらなかった。', '为了买面试穿的衣服去了那家百货商店，但是没有找到一套适合自己的。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('1713d082-d3cb-4fae-a4ea-efa86142579d', 'd21443d6-b241-429e-90c1-27e91d8933e6', 'あの事件が起きて以来、一日として心の休まる日はない。', 'あの事件が起きて以来、一日として心の休まる日はない。', '自从发生了那件事，就没有过一天安宁的日子。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('4127872e-a1ae-4153-8d14-9e5cb00231cb', '～とて', NULL, 'N1', '名＋とて', '名＋とて', '表示假定条件的逆接，“即使……也不例外”“即使是……也……”“甚至……”“就连……”。', '前面主要接续人名。\n意思与「～としても」相同，但「～とて」是比较生硬的表达方式。', 93, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('0287b134-2b09-4cdd-a44a-86068db16847', '4127872e-a1ae-4153-8d14-9e5cb00231cb', '常に冷静な彼とてやはり人間だから、感情的になってしまうこともあるのだろう。', '常に冷静な彼とてやはり人間だから、感情的になってしまうこともあるのだろう。', '尽管他平时很冷静，但是也有情绪化的时候吧。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('28667a2f-c82a-4f97-8f51-9afe2061b195', '4127872e-a1ae-4153-8d14-9e5cb00231cb', '最近の電気製品は機能が多すぎる。開発者たちとてすべての機能が必要とは思わないのではないか。', '最近の電気製品は機能が多すぎる。開発者たちとてすべての機能が必要とは思わないのではないか。', '最近的电器功能实在太多，就算是开发商也未必会认为所有的功能都有必要吧。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('c0a79228-9fb4-44f2-87e9-b68cff4bde89', '4127872e-a1ae-4153-8d14-9e5cb00231cb', '私とて試合に負けたことに悔しい。', '私とて試合に負けたことに悔しい。', '输掉了比赛，我也很懊恼。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('8e3cab29-5e89-4e1e-a1a2-e7fc0ab2df88', '～とて', NULL, 'N1', '名＋だ/動た形＋とて', '名＋だ/動た形＋とて', '表示假定条件的逆接，无论前项怎样，后项的原则都是一样的。“即使……也……”“即便……也……”“就算……也……”。', '常与「たとえ」「どんなに」「いくら」等词一起使用。', 94, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('f935e62e-10c4-47c7-9ceb-52ea0332e3c4', '8e3cab29-5e89-4e1e-a1a2-e7fc0ab2df88', 'たとえ病気だとて試験に欠席してはいけない。', 'たとえ病気だとて試験に欠席してはいけない。', '就算生病了也不能缺考。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('350876f2-7c97-46dd-9870-ad78038f7c27', '8e3cab29-5e89-4e1e-a1a2-e7fc0ab2df88', 'いくら頼んだとて、できないことはできない。', 'いくらたのんだとて、できないことはできない。', '再怎么拜托，不能做的事情就是不能做。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('335f8c1c-1bdd-4b55-9d64-739761edc25e', '8e3cab29-5e89-4e1e-a1a2-e7fc0ab2df88', 'どんなに後悔したとて、過ぎたことは今さらどうしようもない。', 'どんなに後悔したとて、過ぎたことは今さらどうしようもない。', '就算再怎么后悔，对于已经过去的事情也没有办法。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('3b00c79b-c904-4fa1-af22-98f18a70c208', '～とは/なんて', NULL, 'N1', '動普通形/イ形/ナ形語幹/名＋とは/なんて', '動普通形/イ形/ナ形語幹/名＋とは/なんて', '表示出现意外的情况时的惊讶、意外的语气。“居然……”。', '口语中常用「なんて」，「とは」「なんて」后面的内容可以省略。', 95, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('6ae556a7-b8d2-421e-8944-087c168fc1fd', '3b00c79b-c904-4fa1-af22-98f18a70c208', 'うちの娘は、なぜあんなに買い物に時間がかかるのか。ブラウス1枚選ぶだけのことなのに4時間もかかるとは、全くあきれてしまった。', 'うちの娘は、なぜあんなに買い物に時間がかかるのか。ブラウス1枚選ぶだけのことなのに4時間もかかるとは、全くあきれてしまった。', '不明白为什么我女儿在购物上要花费那么多的时间。光选一件罩衫居然要花费四个小时，真是无语了。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('d0b26082-f13b-4dee-a156-b43626e17526', '3b00c79b-c904-4fa1-af22-98f18a70c208', '普段はおとなしい彼があんなに怒るとは、よほどひどいことを言われたのだろう。', '普段はおとなしい彼があんなに怒るとは、よほどひどいことを言われたのだろう。', '平时性格温和的他居然发那么大的脾气了，想必对方说了很过分的话吧。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('c8e43bed-6a6b-471e-bd59-a76db1733812', '3b00c79b-c904-4fa1-af22-98f18a70c208', 'この地域の再開発に自分がかかわることになろうとは想像すらしていなかった。', 'この地域の再開発に自分がかかわることになろうとは想像すらしていなかった。', '从没想过自己居然会参与到这个地区的开发与建设中来。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('57b63006-8d25-4bc7-b523-abd8fec1f24a', '3b00c79b-c904-4fa1-af22-98f18a70c208', '20歳にもなって、そんな簡単なこともできないなんて。', '20歳にもなって、そんな簡単なこともできないなんて。', '都20岁了连这么简单的事情都不会做，真是的。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('933c833b-7cdf-4f84-a3d8-fce724cb00ea', '～とはいうものの/とは 言[い]い 条[じょう]', NULL, 'N1', '動普通形/イ形/ナ形語幹/名＋とはいうものの/とは言い条', '動普通形/イ形/ナ形語幹/名＋とはいうものの/とは言い条', '表示让步转折，承认前项，但是后项的事态仍然没有改变。“虽说……但是……”。', '「～とは 言[い]い 条[じょう]」是比较生硬的表达方式。', 96, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('e3fd3a15-74c4-4406-80ec-a451c8831e95', '933c833b-7cdf-4f84-a3d8-fce724cb00ea', '大学時代はフランス文学専攻だった。とはいうものの、フランス語はほとんどしゃべれない。', '大学時代はフランス文学専攻だった。とはいうものの、フランス語はほとんどしゃべれない。', '大学时代虽然学的是法国文学，但是基本不会讲法语。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('255e1e26-5b12-40a0-9c84-7eae5da16f25', '933c833b-7cdf-4f84-a3d8-fce724cb00ea', '人は過去に戻れない。とはいうものの、昔のことを思い出すとつい懐かしくなってしまう。', '人は過去に戻れない。とはいうものの、昔のことを思い出すとつい懐かしくなってしまう。', '人没法回到过去，虽说如此，但是一想起过去的事情就会觉得很怀念。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('d31cdd59-b4b2-4731-9019-740ceea0998c', '933c833b-7cdf-4f84-a3d8-fce724cb00ea', '男女平等の世の中とは言い条、職場においてはまだ差別が残っている。', 'だんじょびょうどうのよのなかとは言い条、職場においてはまだ差別が残っている。', '虽说是男女平等的社会，但是在职场中仍然存在歧视。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('66ed391a-91aa-4d09-809c-b1e05c0df2ec', '～とはいえ', NULL, 'N1', '動普通形/イ形/ナ形語幹/名＋とはいえ', '動普通形/イ形/ナ形語幹/名＋とはいえ', '表示让步转折，肯定前项事实，但是实际上并非如此。“虽说……但是……”“尽管……可是……”。', '多表示后项的结果与前项的情况不一致。', 97, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('395d6cde-0db6-46b9-bc09-f38d3d12fcc0', '66ed391a-91aa-4d09-809c-b1e05c0df2ec', '土地の値段が下がったとはいえ、都心の住宅は簡単に買えるものではない。', '土地の値段が下がったとはいえ、都心の住宅は簡単に買えるものではない。', '虽说土地的价格有所下调，但是要在市中心买房不是那么简单的事情。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('b87a4d3b-273a-4892-a536-03294e5914ad', '66ed391a-91aa-4d09-809c-b1e05c0df2ec', '80歳の祖母は、この間階段で転んで足を痛め、歩くのが不自由になってしまった。とはいえ、全く歩けないということではないので、家事をするには問題ないとのことだ。', '80歳の祖母は、この間階段で転んで足を痛め、歩くのが不自由になってしまった。とはいえ、全く歩けないということではないので、家事をするには問題ないとのことだ。', '80岁的祖母前不久因为在楼梯上摔了一跤伤到了脚，走路变得不太方便。虽说如此，也并不是完全不能走，说是做家务没有问题。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('19b24117-00ca-43f9-9680-2b677856cc5b', '66ed391a-91aa-4d09-809c-b1e05c0df2ec', '仕事が山のようにあって、日曜日とはいえ、出社しなければならない。', '仕事が山のようにあって、日曜日とはいえ、出社しなければならない。', '工作堆积如山，就算是周末也不得不去公司加班。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('c21cb0e5-d6a8-4b07-a24e-b947888dcd6a', '66ed391a-91aa-4d09-809c-b1e05c0df2ec', '春になったとはいえ、まだまだ寒い日が続いている。', '春になったとはいえ、まだまだ寒い日が続いている。', '虽然已经到了春天，但还是很冷。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('ac70a736-b8d4-4f4e-b25b-04925ee114e9', '～とばかりに', NULL, 'N1', '～とばかりに', '～とばかりに', '用来描述对方的动作、神态、表情等。“像……的样子”“几乎就要……似的”。', '接续名词，形容动词的时候，可以去掉「だ」。\n虽然对方没有直接用语言来表达，但是其动作、神态、表情透露出某种信息。', 98, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('1b2a1706-f27d-400d-b659-bf07a6f56e09', 'ac70a736-b8d4-4f4e-b25b-04925ee114e9', '天まで届けとばかりに、声をかぎりに歌った。', '天まで届けとばかりに、声をかぎりに歌った。', '仿佛是要让自己的歌声直冲云霄似的，她开始引吭高歌。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('13648270-0ed8-47de-a378-48db2953581e', 'ac70a736-b8d4-4f4e-b25b-04925ee114e9', '山田さんは、意見を求められると、待っていましたとばかりに自分の説を展開し始めた。', '山田さんは、意見を求められると、待っていましたとばかりに自分の説を展開し始めた。', '询问山田意见的时候，他仿佛已经等了很久似的，迫不及待地开始陈述自己的观点。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('151acd85-b85c-4018-aa9e-a9979707c5fb', 'ac70a736-b8d4-4f4e-b25b-04925ee114e9', '彼は出て行けとばかりに、ドアを開けた。', '彼は出て行けとばかりに、ドアを開けた。', '他好像跟我说“出去！”似的，把门打开了。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('8bd27ea3-a4c8-4a6b-b2c5-a9dac15645f5', '～とまではいかないが/とまではいかないとしても', NULL, 'N1', '動普通形/イ形/ナ形語幹/名＋とまではいかないが/とまではいかないとしても', '動普通形/イ形/ナ形語幹/名＋とまではいかないが/とまではいかないとしても', '表示前后两项的对比，就算达不到前项的程度，但是至少会做到后项的事情。“虽然达不到……的程度，但是（至少）……”。', '前项的程度比后项高。', 99, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('c6b9f869-fa33-49f8-907f-a0ff7491a3b1', '8bd27ea3-a4c8-4a6b-b2c5-a9dac15645f5', '毎日とまではいかないが、週に2、3回は掃除をしようと思う。', '毎日とまではいかないが、週に2、3回は掃除をしようと思う。', '即使做不到每天打扫，但是每周至少要打扫两三次。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('4ad0bb5a-f3b8-40ee-a621-3189c744b28f', '8bd27ea3-a4c8-4a6b-b2c5-a9dac15645f5', '絶対とまではいかないとしても、成功する確率は高いと思う。', '絶対とまではいかないとしても、成功する確率は高いと思う。', '即使没有绝对成功的把握，但是机会还是很大的。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('d6f4bf48-0ed2-4be8-a1c4-27163ee7aefc', '8bd27ea3-a4c8-4a6b-b2c5-a9dac15645f5', '仕事が見つかって、快適な生活とまではいかないが、なんとか生きていける。', '仕事が見つかって、快適な生活とまではいかないが、なんとか生きていける。', '找到工作后，虽然还不能说生活有多舒适，但好歹能过下去。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('e1d88e8d-c745-4749-a4dd-aadf452c5cb2', '～とまでは 言[い]わないが/とまでは言わないとしても', NULL, 'N1', '動普通形/イ形/ナ形語幹/名＋とまでは言わないが/とまでは言わないとしても', '動普通形/イ形/ナ形語幹/名＋とまでは言わないが/とまでは言わないとしても', '表示前后两项的对比，就算不要求做到前项，但是至少应该要做后项。“即使不说……但至少……”。', '「～言わないが」在句型中的意思是“虽然不要求……”。', 100, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('50ee1aca-f87e-4e0c-af30-1024648372d2', 'e1d88e8d-c745-4749-a4dd-aadf452c5cb2', '君自身の問題だから、「やめてしまえ」とまでは言わないが、いまいちど考え直してみたらどうだろうか。', '君自身の問題だから、「やめてしまえ」とまでは言わないが、いまいちど考え直してみたらどうだろうか。', '这是你自己的问题，即使不说让你现在就停手不做，但至少应该再考虑一下吧。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('affd7e82-3c10-49b9-8b00-5f5495014970', 'e1d88e8d-c745-4749-a4dd-aadf452c5cb2', '例の単価のことですが、10％とまでは言わないが、もう少し負けてくれませんか。', '例の単価のことですが、10％とまでは言わないが、もう少し負けてくれませんか。', '之前提到的单价的问题，不敢要求您下降10％，但是能不能再便宜一点呢。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('f80fca0c-f871-4074-a429-5472f2170410', 'e1d88e8d-c745-4749-a4dd-aadf452c5cb2', '全部一人で解決しろとまでは言わないが、できる限りの努力をしてもらいたい。', '全部一人で解決しろとまでは言わないが、できる限りの努力をしてもらいたい。', '虽然不要求你一个人解决所有问题，但是希望你能做出自己尽可能的努力。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('3f412a6e-ea4b-4d1e-9d70-0089cbf17b22', '～ともあろうものが', NULL, 'N1', '名＋ともあろうものが', '名＋ともあろうものが', '表示有一定社会地位、职位或者身份的人做出了与其身份、地位不符合的事情。“身为……竟然……”“是那样身份的人，却……”。', '常与「国会議員」「大統領」「教師」「医者」「警官」等名词一起使用。\n表达一种失望、吃惊、愤怒、难以置信的语气。', 101, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('0d8f2517-b7c8-4cd9-8ddd-f23b9d316765', '3f412a6e-ea4b-4d1e-9d70-0089cbf17b22', '大学の学長ともあろうものが、賄賂を受け取るなんて、驚いた。', '大学の学長ともあろうものが、わいろを受け取るなんて、驚いた。', '作为一所大学的校长，却收受贿赂，让人惊讶。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('cce050c7-32dc-4790-b281-d43b339a3883', '3f412a6e-ea4b-4d1e-9d70-0089cbf17b22', '警察官ともあろうものが、強盗を働くとは。', '警察官ともあろうものが、ごうとうを働くとは。', '作为警官却去抢劫，真是没有想到。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('52b3c642-69fa-48e3-9d4b-2e4e2a2abf71', '3f412a6e-ea4b-4d1e-9d70-0089cbf17b22', '国会議員ともあろうものが、平気で脱税行為を行うなんて。', '国会議員ともあろうものが、平気でだつぜい行為を行うなんて。', '作为国会议员，竟然若无其事地偷税漏税，真是不能原谅。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('3777bc35-39d0-46ab-aeb1-ae0fedc5785c', '～ともなく/ともなしに', NULL, 'N1', '動辞書形＋ともなく/ともなしに', '動辞書形＋ともなく/ともなしに', '表示无意间做某事的时候，突然发现了意外的、新的情况。“漫不经心地……”“无意识地……”。', '常用「見る」「聞く」「眺める」「考える」等表示人的意志行为的动词，表示该动作不是具备明确的意图和目的而进行的。\n也可以与「何」「どこ」等疑问词连用，表示漫无目的的行为。\n注意语法的形式，只能用「ともなく」「ともなしに」。「ともないで」「ともなくて」都是错误的。', 102, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('469eb4b8-6dce-4e8f-a16a-8cfaaea6bd07', '3777bc35-39d0-46ab-aeb1-ae0fedc5785c', '電車の窓から外を見るともなく見ていたら、高校時代の同級生の姿が目に入った。', '電車の窓から外を見るともなく見ていたら、高校時代の同級生の姿が目に入った。', '无意间看窗外的时候突然发现了高中时代同班同学的身影。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('d54b1941-2fbc-4162-b1fb-a1c0747a6f49', '3777bc35-39d0-46ab-aeb1-ae0fedc5785c', '母は、ぼんやり、テレビを見るともなしに見ていた。', '母は、ぼんやり、テレビを見るともなしに見ていた。', '母亲漫不经心地看着电视。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('e7d8f5a6-e6a7-4553-8053-9785e1c7f43d', '3777bc35-39d0-46ab-aeb1-ae0fedc5785c', '喫茶店で、となりの席の話を聞くともなく聞いていたら、うちの会杜のことだったので驚いた。', '喫茶店で、となりの席の話を聞くともなく聞いていたら、うちの会杜のことだったので驚いた。', '在咖啡厅里无意间听到邻座讲的话，讲的居然是我们公司的事情，让我很惊讶。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('1c0082bf-b4e9-4d9a-b900-cf756ed003bb', '3777bc35-39d0-46ab-aeb1-ae0fedc5785c', 'どこへ行くともなく、ぶらぶらと歩き出した。', 'どこへ行くともなく、ぶらぶらと歩き出した。', '一个人漫无目的地走了出去。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('1ac2380e-07bf-4c0c-b639-03fe005c9135', '～ともなると/ともなれば', NULL, 'N1', '動辞書形/名＋ともなると/ともなれば', '動辞書形/名＋ともなると/ともなれば', '表示评价的角度，“一到……的时候”“一旦……的话”。', '前面常用表示年龄、时间、作用、事情等名词或者动词。意思是“到了……情况下，就会……”。', 103, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('e4fbd5ca-ab45-4ace-bea8-8d3eabef27ee', '1ac2380e-07bf-4c0c-b639-03fe005c9135', '大寺院の本格的な修理ともなると、かかる経費も相当なものだろう。', 'だいじいんの本格的な修理ともなると、かかる経費も相当なものだろう。', '一旦要全面维修大寺院的话，就需要很多的经费吧。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('aefd777d-a568-4341-ba8d-f1f89940b66a', '1ac2380e-07bf-4c0c-b639-03fe005c9135', '私の家のまわりに、歴史のある神社やお寺が多く、海にも近いため、有名な観光地になっている。休日ともなると、朝から観光客の車で道路が渋滞する。', '私の家のまわりに、歴史のあるじんじゃやおてらが多く、海にも近いため、有名な観光地になっている。休日ともなると、朝から観光客の車で道路が渋滞する。', '我家周边有很多历史悠久的神社和寺院，离海边也很近，所以成为有名的观光地。一到假日，从大清早开始路上就全是过来观光的车辆，很拥堵。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('6ea98b1a-8e98-4cfb-8016-381523a9e553', '1ac2380e-07bf-4c0c-b639-03fe005c9135', '社会人ともなると、服装や言葉遣いにも気をつけなければならない。', '社会人ともなると、服装やことばづかいにも気をつけなければならない。', '走上社会后要注意自己的服装和用语。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('c52dd374-511e-416c-a203-11d2b99591a0', '～と/に～を 重[かさ]ねて', NULL, 'N1', '名A＋と/に＋名B＋を重ねて', '名A＋と/に＋名B＋を重ねて', '“反复……”“屡次……”“历经……”。表示经过反复尝试终于得到了某种来之不易的结果。', '前后可以用意义相近的名词或者是同一名词。', 104, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('c834a5e8-6534-411a-beae-cf1ddbc0583b', 'c52dd374-511e-416c-a203-11d2b99591a0', '努力と工夫を重ねて、やっと満足のいく作品に仕上げた。', '努力と工夫を重ねて、やっと満足のいく作品に仕上げた。', '经过不断的努力和反复钻研，终于完成了令人满意的作品。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('9b4d01fe-cc86-4b47-8d48-ec052446c893', 'c52dd374-511e-416c-a203-11d2b99591a0', '修正に修正を重ねて、最終版の企画書を提出した。', '修正に修正を重ねて、最終版の企画書を提出した。', '经过反复修改才交出这份最终版的企划书。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('18c8aa85-7bf2-49f4-8f46-3fef3f52c355', 'c52dd374-511e-416c-a203-11d2b99591a0', '苦労に苦労を重ねて、ようやく目的地にたどり着いた。', '苦労に苦労を重ねて、ようやく目的地にたどり着いた。', '历经千辛万苦终于到达了目的地。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('da08a2f0-6b17-4cd1-8519-83d331db4b52', '～ないではない/ないでもない', NULL, 'N1', '～ないではない/ないでもない', '～ないではない/ないでもない', '表示前项所提及的事情也是有可能的，但是往往很难实现。“并不是不……”“并非是……”“不是不……”。', '用双重的否定表示消极的肯定。', 105, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('2cb7aba9-3f38-414e-baf9-8e9013068de9', 'da08a2f0-6b17-4cd1-8519-83d331db4b52', '彼の論文は、構成にはまだ少し問題がある気がしないでもないが、内容自体はだいぶよくなったと思う。', '彼の論文は、こうせいにはまだ少し問題がある気がしないでもないが、内容じたいはだいぶよくなったと思う。', '我也觉得他的论文在结构上还有点问题，但内容本身已经改善很多了。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('47a7ea19-af0b-4de5-90f7-17d657d0b3e0', 'da08a2f0-6b17-4cd1-8519-83d331db4b52', '時には、一人になりたいと思うことがないでもない。', '時には、一人になりたいと思うことがないでもない。', '有时候也不是不想一个人独处。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('fc94b4b0-a69c-4846-8efe-a4e5f9fc5fd0', 'da08a2f0-6b17-4cd1-8519-83d331db4b52', '家族と一緒に旅行に行きたい気もないではないが、なかなかその時間が取れない。', '家族と一緒に旅行に行きたい気もないではないが、なかなかその時間が取れない。', '也不是不想和家人一起出去旅行，但是始终抽不出时间来。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('3bad7bbb-0962-4d7d-822c-1ad562013f2b', '～ないまでも', NULL, 'N1', '動ない形＋ないまでも', '動ない形＋ないまでも', '表示前后两项的对比，即使达不到前项的程度，但至少要做到后项或者至少要达到后项的标准。“即使做不到……但（至少）……”“即使不能说是……但至少是……”。', '一般用「AないまでもB」的形式，A是程度较高的内容。但是不要求做到A的程度，只要求做到B。', 106, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('a36c2e1b-63a3-4e98-bd40-f991969bc651', '3bad7bbb-0962-4d7d-822c-1ad562013f2b', 'きのうの演奏は、最高の出来とは言えないまでも、かなり良かったと思う。', 'きのうの演奏は、最高の出来とは言えないまでも、かなり良かったと思う。', '昨天的演奏虽然不能说是最好的，但是也相当不错。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('2d4026b7-f05a-4beb-bb14-a72a7e131a30', '3bad7bbb-0962-4d7d-822c-1ad562013f2b', 'プロのコックとは言わないまでも、彼の料理の腕はなかなかのものだ。', 'プロのコックとは言わないまでも、彼の料理の腕はなかなかのものだ。', '虽然不能说是职业厨师的水平，但他做菜的本领相当不错。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('e4fc25ea-0229-41a9-a7dc-133005ee8c51', '3bad7bbb-0962-4d7d-822c-1ad562013f2b', '週末まで残業しなさいとは言わないまでも、せめて平日くらいはきちんと出勤したほうがいいんじゃないですか。', '週末まで残業しなさいとは言わないまでも、せめて平日くらいはきちんと出勤したほうがいいんじゃないですか。', '即使不要求周末加班，但是至少要保证平时的出勤吧。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('4f323a08-fb42-4f13-abad-0da008ac7850', '～ないものでもない', NULL, 'N1', '動ない形＋ないものでもない', '動ない形＋ないものでもない', '表示在某个前提条件下，后项也有可能成立。“不是不……”“未必不……”“有可能……”。', '意思与「～なくもない」相同。\n用双重否定表示消极的肯定。', 107, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('4b5b47ad-6c44-4836-be7d-ed9b8b615ff0', '4f323a08-fb42-4f13-abad-0da008ac7850', '「私が悪かった」と素直に謝れば、許してやらないものでもない。', '「私が悪かった」と素直に謝れば、許してやらないものでもない。', '只要你能够坦率地承认是自己不对，我也不是不原谅你。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('536febab-85f6-41e6-8126-1bf5fa97d2af', '4f323a08-fb42-4f13-abad-0da008ac7850', '大変な困難を伴う仕事だが、夜を徹して行えば、できないものでもない。', '大変な困難を伴う仕事だが、夜をてっして行えば、できないものでもない。', '虽然这个工作有很大难度，但是熬夜做的话也并非完成不了。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('334b5af8-c742-478e-a793-d46965dc4314', '4f323a08-fb42-4f13-abad-0da008ac7850', 'そんなに頼むのなら、その仕事を代わってやらないものでもない。', 'そんなに頼むのなら、その仕事を代わってやらないものでもない。', '你这么求我的话，我也不是不替你做。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('434fafbf-972a-42a2-8f0d-22cf7cc49577', '～ながらに/ながらの', NULL, 'N1', '動ます形/名＋ながらに/ながらの', '動ます形/名＋ながらに/ながらの', '表示状态，“保持……的状态”“一边……一边……”。', '常用「居る」「生まれる」「生きる」等动词和「昔」「いつも」「涙」等名词。\n「～ながらに」后面常用动词、形容词、形容动词、副词等。「～ながらの」后面接续名词。', 108, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('8bcbcb41-3c77-4f79-ae7e-91f6d6e7f7c8', '434fafbf-972a-42a2-8f0d-22cf7cc49577', '彼は自らのつらい体験を涙ながらに語った。', '彼はみずからのつらい体験を涙ながらに語った。', '他含泪诉说了自己悲惨的遭遇。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('4e5e14bc-96aa-4b10-905e-dc54bca3a010', '434fafbf-972a-42a2-8f0d-22cf7cc49577', '国に早く対策をたててほしいと、被害者たちは涙ながらに訴えた。', 'うったえた。', '受害者们含着泪说，希望国家早日制订解决方案。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('5c951216-5684-4f1a-aee8-345c2e897492', '434fafbf-972a-42a2-8f0d-22cf7cc49577', '今日は会社の同僚といつもながらのところで夕食を済ませた。', '今日は会社の同僚といつもながらのところで夕食を済ませた。', '今天和公司的同事们在老地方吃了晚饭。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('4b3bc604-d403-451b-84ac-0fe349d2ed9d', '～ながらも', NULL, 'N1', '～ながらも', '～ながらも', '表示逆接，“虽然……但是……”“尽管……但是……”。', '意思与「～けれども/が」相同。', 109, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('63d1ad27-6726-4058-9c01-8466b6343c27', '4b3bc604-d403-451b-84ac-0fe349d2ed9d', '先月、父に手作りの箸をプレゼントした。長くてなんだか使いにくいと言いながらも毎日使っているところを見ると気に入ってくれているのかもしれない。', '先月、父に手作りの箸をプレゼントした。長くてなんだか使いにくいと言いながらも毎日使っているところを見ると気に入ってくれているのかもしれない。', '上个月我送了父亲我自己亲手做的筷子。虽然父亲说太长了不太好用，但他每天都在用，这样看来他可能还挺喜欢的。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('6ba39055-5bf6-492d-b5e0-e9cac6db642e', '4b3bc604-d403-451b-84ac-0fe349d2ed9d', '様々な苦難にあいながらも、あきらめないで最後までやり抜いた。', '様々な苦難にあいながらも、あきらめないで最後までやり抜いた。', '虽然碰到了各种各样的困难，但是没有放弃坚持到了最后。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('8431051d-8c90-4ec8-ab79-1317979e0b7e', '4b3bc604-d403-451b-84ac-0fe349d2ed9d', '彼は、貧しいながらも、温かい家庭で育った。', '彼は、貧しいながらも、温かい家庭で育った。', '他在一个尽管贫寒但是很温暖的家里长大。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('de8b9748-2b4e-4f46-adde-78f533f54702', '～なくして（は）', NULL, 'N1', '名＋なくして（は）', '名＋なくして（は）', '表示假设，“如果没有……，就（不能）……”。', '意思与「～がなければ」相同。「は」表示强调，后项多用否定。', 110, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('171cda6b-2e78-44fd-a9fa-f4a8bc94af9a', 'de8b9748-2b4e-4f46-adde-78f533f54702', '「努力なくして成功はない」という言葉は、祖父の口癖だ。', '「努力なくして成功はない」という言葉は、そふのくちぐせだ。', '“不努力就不会成功”，这句话是爷爷的口头禅。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('9bc5eaa9-a583-4629-b7f3-9f83b75fd0ba', 'de8b9748-2b4e-4f46-adde-78f533f54702', '国の経済は、鉄道やトラックなどによる貨物の輸送に依存している。国全体に広がる交通網なくしては、1日たりとも成り立たない。', '国の経済は、鉄道やトラックなどによる貨物のゆそうに依存している。国全体に広がるこうつうもうなくしては、1日たりとも成り立たない。', '国家的经济发展在很大程度上依赖铁路和卡车等货物运输。没有了覆盖全国范围的交通网，一天也难以维持下去。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('41f9d8f6-afb3-495c-89db-34c055404f4e', 'de8b9748-2b4e-4f46-adde-78f533f54702', '苦難に満ちたあの人の人生は、涙なくしては語れない。', '苦難に満ちたあの人の人生は、涙なくしては語れない。', '他的人生充满了苦难，讲他的故事就会忍不住流泪。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('c8635979-093c-40d7-b264-89ec94cda457', 'de8b9748-2b4e-4f46-adde-78f533f54702', '市民の皆さんの協力なくしては、ゴミ問題の解決はありえません。', '市民の皆さんの協力なくしては、ゴミ問題の解決はありえません。', '没有市民的配合是无法解决垃圾问题的。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('8956b3b7-9488-4739-8e2c-5321073afdde', '～なくはない/なくもない', NULL, 'N1', '～なくはない/なくもない', '～なくはない/なくもない', '表示前项的事情也是有可能的或者前项的动作行为也是成立的。“也有可能……”“也不是不……”。', '常用「言える」「考える」「思う」「認める」「感じる」「気がする」等有关思考、知觉的动词。', 111, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('66d6f1d2-30a9-4fb5-9b15-551fbebc3058', '8956b3b7-9488-4739-8e2c-5321073afdde', '子供「自分のパソコンが欲しいよ。ねえ、駄目？」母親「ゲームじゃなくて勉強に使うんなら、考えなくもないけど。」', '子供「自分のパソコンが欲しいよ。ねえ、駄目？」母親「ゲームじゃなくて勉強に使うんなら、考えなくもないけど。」', '孩子：“我想要一台自己的电脑，行吗？”\n母亲：“如果不是用来打游戏，而是用于学习的话，我也可以考虑一下。”', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('01f19d95-6d4a-473b-8193-311d1776026d', '8956b3b7-9488-4739-8e2c-5321073afdde', '山本さんは、ある日突然会社をやめて周りを驚かせたが、あの人の性格を考えると、理解できなくはない。', '山本さんは、ある日突然会社をやめて周りを驚かせたが、あの人の性格を考えると、理解できなくはない。', '山本有一天突然提出辞职，让周围的人很惊讶。但是考虑到他的性格，也不是不能理解。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('4d4e1cdb-556f-4ea2-a82e-80799c810e09', '8956b3b7-9488-4739-8e2c-5321073afdde', '彼の気持ちは分からなくもないが、ただその行為には賛成できない。', '彼の気持ちは分からなくもないが、ただその行為には賛成できない。', '他的心情我不是不理解，但是那种行为我不赞成。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('76bfe24e-c6ef-4e61-870f-e3feb4f875d4', '～なしには/なしでは', NULL, 'N1', '名＋なしには/なしでは', '名＋なしには/なしでは', '表示假定，“如果没有……就不能……”。', '意思与「～がないでは」相同，后项多用否定。', 112, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('6e436e8b-f374-4a2f-8f8b-517977d7bd8b', '76bfe24e-c6ef-4e61-870f-e3feb4f875d4', '教授の助言なしには、この研究の成功はなかった。', '教授の助言なしには、この研究の成功はなかった。', '如果没有教授的建议，这个研究将无法获得成功。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('6f1ffc92-198a-4252-ac69-78ac6df0eee2', '76bfe24e-c6ef-4e61-870f-e3feb4f875d4', '先生方のご指導や友人の助けなしには、論文を書き上げられなかっただろう。', '先生方のご指導や友人の助けなしには、論文を書き上げられなかっただろう。', '如果没有老师们的指导和朋友的帮助，自己也无法写出这篇论文。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('c17b6ff1-87d9-4609-b56a-7885ffed7e6a', '76bfe24e-c6ef-4e61-870f-e3feb4f875d4', '今回のアンケート調査では、インターネットなしでは、生きていけないと答えた若者が84％を占めている。', '今回のアンケート調査では、インターネットなしでは、生きていけないと答えた若者が84％を占めている。', '在本次的问卷调查中，回答说没有网络就无法生活的年轻人占据84％。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('bcd3c2e1-e595-4d41-82df-78ec91c532fd', '～なしに', NULL, 'N1', '～なしに', '～なしに', '表示附带关系，“没有……的状态下，就……”。', '意思与「～をしないで」「～がないままで」相同。\n也可以用「名＋もなしに」，「も」表示强调。', 113, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('5d23c75d-eeff-4c87-9c5d-8213c0b6d8fc', 'bcd3c2e1-e595-4d41-82df-78ec91c532fd', '連絡もなしにお客様がいらっしゃったが、急なこととて、何のおもてなしもできなかった。', '連絡もなしにお客様がいらっしゃったが、急なこととて、何のおもてなしもできなかった。', '因为客人事先没有联络突然造访，所以未能好好招待。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('f183747b-f2d8-4d67-bf10-7c9238f4a6b9', 'bcd3c2e1-e595-4d41-82df-78ec91c532fd', 'ノックなしに私の部屋に入らないでください。', 'ノックなしに私の部屋に入らないでください。', '未敲门的话请不要进我的房间。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('993cea0c-96c2-44bc-b8c5-41160b708245', 'bcd3c2e1-e595-4d41-82df-78ec91c532fd', '彼はひと言のあいさつなしに帰国した。', '彼はひと言のあいさつなしに帰国した。', '他没有打声招呼就回国了。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('678781af-83a4-4f63-844c-f4fb3b12dc28', '～ならいざしらず', NULL, 'N1', '名＋ならいざしらず', '名＋ならいざしらず', '表示前后两项的比较。“如果……的话，另当别论，但是……的话（就很严重了）”“如果……的话，还情有可原，但是……（是不能允许的）”。', '用于对某个行为的批判。前后两项形成对比，前项还可以原谅，后项是不能允许的。\n类似用法还有「なら/はともかく」「なら/はべつだが」「なら/はまだしも」。', 114, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('1ffce73a-176f-4c75-9550-2e4900d31ed0', '678781af-83a4-4f63-844c-f4fb3b12dc28', '小学生ならいざしらず、大学生がこんな簡単な計算ができないなんて信じられない。', '小学生ならいざしらず、大学生がこんな簡単な計算ができないなんて信じられない。', '小学生的话还情有可原，大学生连这么简单的计算都会算错简直难以置信。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('ec896fbc-2e43-445c-ba99-ec2f72135c1f', '678781af-83a4-4f63-844c-f4fb3b12dc28', '新入社員ならいざしらず、入社8年にもなる君がこんなミスをするとは信じられない。', '新入社員ならいざしらず、入社8年にもなる君がこんなミスをするとは信じられない。', '若是新员工的话还情有可原，你进公司都8年了还犯这种错误，简直让人难以置信。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('0c0137c4-12f7-4382-90d3-7369290c8d58', '678781af-83a4-4f63-844c-f4fb3b12dc28', '子どもならいざしらず、大の大人がこんなミスをするなんて、許せない。', '子どもならいざしらず、大の大人がこんなミスをするなんて、許せない。', '若是孩子的话还情有可原，一个大人居然犯这种错误真是不能原谅。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('6b0a7d81-07b3-463e-9a20-7145c8ef72cd', '678781af-83a4-4f63-844c-f4fb3b12dc28', '遅刻ならともかく、無断欠勤などもってのほかだ。', '遅刻ならともかく、むだんけっきんなどもってのほかだ。', '迟到的话还情有可原，但是无故旷工实在是岂有此理。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('53dfabc6-df25-48c8-8d37-df276e7f1884', '678781af-83a4-4f63-844c-f4fb3b12dc28', '1年に1回ぐらいならまだしもこんなにしょっちゅう停電するようでは、普段の生活にもさしつかえる。', '1年に1回ぐらいならまだしもこんなにしょっちゅう停電するようでは、普段の生活にもさしつかえる。', '一年一次的话还情有可原，但是如此频繁地停电会影响到正常生活的。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('eee09f46-d263-4887-baa5-e37ac47d2654', '～ならでは/ならではの', NULL, 'N1', '名＋ならでは/ならではの', '名＋ならでは/ならではの', '多用于强调地方的特色、某人独有的才能、某个群体、某个区域所独有的特征等。“只有……才具备的……”“……独特的……”。', '该句型多表示积极的含义。\n常以「～ならでは～ない」「～ならではの」的形式出现，表示“除了……之外，就不能……”或者是“……独有的特色、才能”等。', 115, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('ad752c4b-1fb5-4cd1-9ed6-b16b71465f22', 'eee09f46-d263-4887-baa5-e37ac47d2654', '100年の伝統を誇るこの旅館のサービスには、老舗旅館ならではの細やかな心遣いが感じられる。', '100年の伝統を誇るこの旅館のサービスには、しにせ旅館ならではの細やかな心遣いが感じられる。', '有着百年传统的这家旅店，能让人感受到传统老字号旅店所特有的那种周到的服务。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('57ceab37-d0f8-4c2a-9c65-6ddf38a7d35b', 'eee09f46-d263-4887-baa5-e37ac47d2654', 'アルバイト先の仲間は、みんな年が近いこともあって、同世代ならではの話でいつも盛り上がっています。', 'アルバイト先の仲間は、みんな年が近いこともあって、同世代ならではの話でいつも盛り上がっています。', '做兼职的地方因为大家彼此年纪相仿，能够讲一些同龄人之间的话题，所以气氛总是很热闹。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('6540fd0c-f461-435a-a61a-1694eae7b998', 'eee09f46-d263-4887-baa5-e37ac47d2654', '友人の家でごちそうになった料理は、家庭料理ならではの素朴な味わいだった。', 'そぼくな味わいだった。', '在朋友家吃的那顿饭有家常菜独有的朴素的味道。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('fc48e48c-831a-4217-8a27-ffbab27ba318', 'eee09f46-d263-4887-baa5-e37ac47d2654', '日本全国、その地方ならではの名産がある。', '日本全国、その地方ならではの名産がある。', '在日本全国都有当地的特产。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('2fe44dbc-f433-4268-bf66-1ec440a88b02', '～なり', NULL, 'N1', '動辞書形＋なり', '動辞書形＋なり', '表示前项的动作结束后，紧接着进行后项的动作。“一……就……”。', '后项多是没有预想到的情况。\n句子的时态多用过去时，描述已经结束的事情。', 116, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('5be60ae6-b1f6-4b78-bac9-3097070f9df2', '2fe44dbc-f433-4268-bf66-1ec440a88b02', '私の料理を一口食べるなり、父は変な顔をして席を立ってしまった。', '私の料理を一口食べるなり、父は変な顔をして席を立ってしまった。', '刚吃了我做的菜，父亲马上就变了脸色，立刻离席而去。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('888f0954-2b3a-43cb-af4c-e8563d6c2d80', '2fe44dbc-f433-4268-bf66-1ec440a88b02', '「あっ、だれかおぼれてる」と言うなり、彼は川に飛び込んだ。', '「あっ、だれかおぼれてる」と言うなり、彼は川に飛び込んだ。', '“不好了，有人溺水了”，他话音未落，就跳进了河里。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('11d2d9ce-3c52-49ed-ac28-7bac5e38f47e', '2fe44dbc-f433-4268-bf66-1ec440a88b02', '娘は家に帰ってくるなり、泣き出した。', '娘は家に帰ってくるなり、泣き出した。', '女儿一回家就哭了起来。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('5fde86e5-6613-406d-b00f-0a47eb1fd837', '～なりとも', NULL, 'N1', '名＋なりとも', '名＋なりとも', '表示列举，从几个事物中举出一个作为例子。“……之类的”“……什么的”。', NULL, 117, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('9737f036-81ee-4547-b43c-8fb9f834cde6', '5fde86e5-6613-406d-b00f-0a47eb1fd837', '時間があったら、電話なりとも、かけてくれればいい。', '時間があったら、電話なりとも、かけてくれればいい。', '有时间的时候，打个电话过来什么的就可以了。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('fc5ad8e3-ac94-40ec-9044-8b12fa30ee79', '5fde86e5-6613-406d-b00f-0a47eb1fd837', 'ちょっと上がってお茶なりとも召し上がってください。', 'ちょっと上がってお茶なりとも召し上がってください。', '上去坐坐喝杯茶。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('ac289603-b26f-4966-a6db-ca2ba29b1f6c', '～なりとも', NULL, 'N1', '名＋なり 何[なん]なりと', '名＋なり 何[なん]なりと', '列举其中的一项，暗示其他。“不管……”“无论……”。', '固定用法：「どこへなりとも」/不管去哪里，「誰となりと」/不论和谁，「なんなりと」/无论什么。', 118, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('fcd6b826-5b8f-4a5e-bd47-7f55b0898e81', 'ac289603-b26f-4966-a6db-ca2ba29b1f6c', '悩みなり何なりとお申し付けください。', '悩みなり何なりとお申し付けください。', '有烦恼或者什么都可以提出来。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('96d5478a-2eac-4e90-a17b-0d43a9198987', 'ac289603-b26f-4966-a6db-ca2ba29b1f6c', '何なりとお好きなものを持って帰るといい。', '何なりとお好きなものを持って帰るといい。', '可以带自己喜欢的东西回去。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('36f99a19-dc67-4ab9-bdb5-9663b15d3121', '～なり～なり', NULL, 'N1', '動辞書形/名＋なり', '動辞書形/名＋なり', '表示列举，“……也好，……也好”“可以……或者……”。', '常用「AなりBなり」的形式，列举互为对照、并列或者类似的两项内容。', 119, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('74431db1-1992-4641-aa9c-187b65336294', '36f99a19-dc67-4ab9-bdb5-9663b15d3121', 'わからない単語があったら、辞書を引くなりだれかに聞くなりして調べておきなさい。', 'わからない単語があったら、辞書を引くなりだれかに聞くなりして調べておきなさい。', '有不懂的单词可以查查词典或者是问问别人。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('397a1bbf-4181-4ac5-800f-b0c443f7b043', '36f99a19-dc67-4ab9-bdb5-9663b15d3121', '休日には映画を見るなり、音楽会に行くなりして、気分転換を図ったほうがいい。', '休日には映画を見るなり、音楽会に行くなりして、きぶんてんかんをはかったほうがいい。', '周末可以去看看电影，听听音乐会，换一下心情。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('62608c60-49b2-4c9e-96ed-b88477c60ab9', '36f99a19-dc67-4ab9-bdb5-9663b15d3121', '友だちなり家族なり誰か信頼できる人に相談したい。', '友だちなり家族なり誰か信頼できる人に相談したい。', '朋友也好家人也好，想跟自己信赖的人商量一下。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('032a9e95-2b80-4ff9-b357-f0c329097d8b', '～なりに/なりの', NULL, 'N1', '動普通形/イ形/ナ形/名＋なりに/なりの', '動普通形/イ形/ナ形/名＋なりに/なりの', '表示判断的立场，“以……（某人）自己的方式”“与……相应的”“与……相符的”。', '前面接续名词、形容动词时「だ」要省略。\n「～なりに」后面接续动词、形容词、副词，「なりの」后面接续名词。\n常用「それなりの」「それなりに」/尽管不充分，但是与之相应地做了……', 120, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('b246bb2a-803c-4ce6-ad53-63f3b34ba23e', '032a9e95-2b80-4ff9-b357-f0c329097d8b', '今回の京都旅行は、天気が悪い日が多かったが、行きたかったお寺にも行けたし、それなりに楽しめた。', '今回のきょうと旅行は、天気が悪い日が多かったが、行きたかったお寺にも行けたし、それなりに楽しめた。', '这次的京都之旅，虽然有好多天天气不好，但是也去到了想去的寺院，还算是玩得挺开心的。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('28d86b95-3930-46c0-bae1-9ec183af491c', '032a9e95-2b80-4ff9-b357-f0c329097d8b', '現行の制度における問題点を、私なりに整理してみました。', '現行の制度における問題点を、私なりに整理してみました。', '对于现行制度中的问题，我试着以自己的方式整理了一下。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('d55c7c57-837c-44c8-a81c-bd88efeba783', '032a9e95-2b80-4ff9-b357-f0c329097d8b', '的確かどうかわかりませんが、この問題について私なりの考えを述べたいと思います。', '的確かどうかわかりませんが、この問題について私なりの考えを述べたいと思います。', '不知道准确与否，我想就这个问题谈一下自己的看法。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('8b021844-060a-4b22-b712-0d971fb647e1', '032a9e95-2b80-4ff9-b357-f0c329097d8b', '私が事業で成功できたのは、自分なりに工夫を重ねたからだと思います。', '私が事業で成功できたのは、自分なりに工夫を重ねたからだと思います。', '我觉得自己之所以能够在事业上获得成功，是因为以自己的方式做了很多努力。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('c7889004-8c45-4df1-862a-c6ece4247777', '032a9e95-2b80-4ff9-b357-f0c329097d8b', 'それなりの努力はしたつもりだ。', 'それなりの努力はしたつもりだ。', '我认为自己做出了相应的努力。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('869135cc-cfe9-4e26-9547-460a4018dc93', '～に 値[あたい]する/に値しない', NULL, 'N1', '動辞書形/名＋に値する/に値しない', '動辞書形/名＋に値する/に値しない', '表示值不值得做某事。“值得……”“不值得……”。', '常用「見る」「読む」「賞賛する」「推薦する」「考慮」「同情」「検討」等。', 121, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('0f3b8449-f980-464f-8993-8a403a37e4d1', '869135cc-cfe9-4e26-9547-460a4018dc93', 'そんなことは彼にとっては一顧だに値しない。', 'そんなことは彼にとってはいっこだに値しない。', '他对这种事情根本不屑一顾。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('8c054f1d-e7dc-48a9-80e4-a825d80d52a7', '869135cc-cfe9-4e26-9547-460a4018dc93', 'その映画はストーリーもよくできていて、画面もきれいなので、見るに値する。', 'その映画はストーリーもよくできていて、画面もきれいなので、見るに値する。', '那部电影故事情节不错，画面也很漂亮，值得一看。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('1f26b1bd-a6b8-4e9e-857f-bbdcba2809a8', '869135cc-cfe9-4e26-9547-460a4018dc93', '彼の行為は賞賛に値する。', '彼の行為は賞賛に値する。', '他的行为值得称赞。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('603d0200-b277-49d7-b5c2-4ec99c98e643', '～に（は）あたらない', NULL, 'N1', '動辞書形/名＋に（は）あたらない', '動辞書形/名＋に（は）あたらない', '表示没有必要做某事。“不必……”“用不着……”。', '常用「驚く」「非難する」等动词。\n前项多用表示原因，“因为……，（所以没必要）……”。', 122, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('b8f8cbd0-ace1-48ac-8a51-e1afc01bf540', '603d0200-b277-49d7-b5c2-4ec99c98e643', '彼なりにできるだけの努力をしたのだから、いい結果を出せなかったとしても、非難するにはあたらない。', '彼なりにできるだけの努力をしたのだから、いい結果を出せなかったとしても、非難するにはあたらない。', '他已经尽可能地做出了努力，即使没有好的结果也没必要指责。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('27adf1c7-2d10-4d6b-8cb1-94d486135b76', '603d0200-b277-49d7-b5c2-4ec99c98e643', '優秀な田中君のことだから、論文を1週間で仕上げたと聞いても驚くにはあたらない。', '優秀な田中君のことだから、論文を1週間で仕上げたと聞いても驚くにはあたらない。', '田中很优秀，即使他一周之内完成了论文也不足为奇。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('041d0e13-2167-4c96-8281-54550b27d078', '603d0200-b277-49d7-b5c2-4ec99c98e643', 'あの作家は天才なのだから、わずか三日間で作品を完成したからといって、驚くにはあたらない。', 'あの作家は天才なのだから、わずか三日間で作品を完成したからといって、驚くにはあたらない。', '那位作家是一个天才，三天之内完成作品也不足为奇。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('4c7032db-00a8-449b-a31d-7eec036a626a', '～にあって（は）/にあっても', NULL, 'N1', '名＋にあって（は）/にあっても', '名＋にあって（は）/にあっても', '描述某种场合、时间、情况，“处于……”“在……之下”。', '常用表示时间、机会、场所、状况、场合的名词。\n「～にあっては」用作顺接；「～にあっても」常和疑问词搭配使用，用作逆接，意思是“即使在……的条件下，也……”。', 123, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('197687ff-d011-4339-8146-1f7722c6aa26', '4c7032db-00a8-449b-a31d-7eec036a626a', '情報技術や交通手段の発達などで異文化の交流が活発化した現代にあってはこれまでの考え方にこだわらず異なる価値観を理解しようとする姿勢を持つことが重要である。', '情報技術や交通手段の発達などでいぶんかの交流がかっぱつかした現代にあってはこれまでの考え方にこだわらずことなるかちかんを理解しようとするしせいを持つことが重要である。', '随着信息技术和交通方式的进步，现代社会中不同文化之间的交流越来越频繁，在当今这个时代，不拘泥于迄今为止的想法，尝试着去理解不同的价值观，具备这种心态很重要。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('5cc554d0-6a36-4c16-b00c-965598d85cc7', '4c7032db-00a8-449b-a31d-7eec036a626a', 'どのような困難な状況にあっても、あきらめてはいけない。', 'どのような困難な状況にあっても、あきらめてはいけない。', '不管在多么困难的情况下，也不能放弃。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('4cec7afe-3dea-4606-9432-44fa37e7cc33', '4c7032db-00a8-449b-a31d-7eec036a626a', '当時は会社の経営が困難を極めた時代だった。そのため、父は責任者という立場にあって寝る時間も惜しんで働かなければならなかった。', '当時は会社の経営が困難をきわめた時代だった。そのため、父は責任者という立場にあって寝る時間も惜しんで働かなければならなかった。', '当时公司的经营正是极其困难的时候。正因为如此，父亲作为负责人，不得不废寝忘食地工作。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('bcdf0438-150c-4297-9ce9-6b5d9184c3bb', '4c7032db-00a8-449b-a31d-7eec036a626a', '動物の世界にあっても、親子の情愛は変わらないものだ。', '動物の世界にあっても、親子の情愛は変わらないものだ。', '即使在动物的世界里，亲子之爱也是不变的。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('a1782441-a0b4-4013-a926-449ff57caf9d', '～に 至[いた]って/に至る', NULL, 'N1', '動辞書形/名＋に至って/に至る', '動辞書形/名＋に至って/に至る', '表示程度、结果、范围等。“到……为止”。', '「～に至って」用在句中，「～に至る」用在句末。\n常用「～に至ってはじめて」「～に至って、やっと～」等形式。意思是“直到……，才……”“直到……终于……”。', 124, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('b6bcbb30-7df2-4eec-b07e-d6a9591e4d49', 'a1782441-a0b4-4013-a926-449ff57caf9d', 'X交通のバス線路が一部廃止される問題で、会社側から地域住民に対し、路線を廃止するに至った経緯及び今後の対応について、説明がなされた。', 'X交通のバスせんろが一部はいしされる問題で、会社側からちいきじゅうみんいきさつおよび今後のたいおうについて、説明がなされた。', '因为X交通的公交车线路部分被废除的问题，由公司方向地区居民作出了有关决定废除线路的来龙去脉以及今后的应对措施的情况说明。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('d367129d-0b94-45a8-a81c-65c03b154546', 'a1782441-a0b4-4013-a926-449ff57caf9d', '証拠となる書類が発見されるにいたって、彼はやっと自分の罪を認めた。', '証拠となる書類が発見されるにいたって、彼はやっと自分の罪を認めた。', '直到找到了能成为证据的文件，他才终于承认了自己的罪行。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('5f762e6b-767e-4c80-b8a0-8ac9baaf5758', 'a1782441-a0b4-4013-a926-449ff57caf9d', '彼らが興した会社は発展を続け、海外に支店を出すに至った。', '彼らがおこした会社は発展を続け、海外に支店を出すに至った。', '他们一起兴办的公司规模越来越大，甚至在国外开了分店。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('22d9e834-dd80-495d-9050-4a0ec668a83d', '～に 至[いた]っては', NULL, 'N1', '動辞書形/名＋に至っては', '動辞書形/名＋に至っては\n名＋に至っては', '表示顺接，“既然事情已经到了……的地步”。\n“提到……”“谈到……”，用于引出话题。', '后项一般是事态的进一步发展，或者是相关对策、措施。\n固定用法：「ことここにいたっては」/事已至此。', 125, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('cd438da3-5cc6-4f81-9ddb-e3040723de0f', '22d9e834-dd80-495d-9050-4a0ec668a83d', 'ここまで業績が悪化するに至っては、工場の閉鎖もやむを得ないと判断した。', 'ここまで業績が悪化するに至っては、工場のへいさもやむを得ないと判断した。', '业绩恶化到如此程度，工厂也只好关闭。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('aca42faa-a6be-42c7-abc3-73feb93fc58f', '22d9e834-dd80-495d-9050-4a0ec668a83d', '問題がこじれてしまう前に対策を立てるべきだったのに、ことここに至ってはどうしようもない。', '問題がこじれてしまう前に対策を立てるべきだったのに、ことここに至ってはどうしようもない。', '原本应该在事态没有恶化之前就制定对策的，但是事已至此没有办法了。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('d2b1b86c-45b0-4a11-9133-1407057bce0e', '22d9e834-dd80-495d-9050-4a0ec668a83d', 'ことここに至っては、仕事をやめてもう一度やり直すしかないでしょう。', 'ことここに至っては、仕事をやめてもう一度やり直すしかないでしょう。', '事已至此，只好辞职，从头开始。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('01f13b1d-acb5-4188-a065-9bbb9a5633ee', '22d9e834-dd80-495d-9050-4a0ec668a83d', 'そのことに至っては、後ほどまたお話しします。', 'そのことに至っては、後ほどまたお話しします。', '关于那件事，我们之后再谈。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('73c7f880-debb-4090-976b-8570a7870d4c', '22d9e834-dd80-495d-9050-4a0ec668a83d', '数学の問題に至っては、私もお手上げだ。', '数学の問題に至っては、私もお手上げだ。', '关于数学方面的问题，我也没辙。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('43acc599-6d7f-47bd-b4cf-c61b5ea1ab30', '～に 至[いた]っても', NULL, 'N1', '動辞書形/名＋に至っても', '動辞書形/名＋に至っても', '表示逆接，即使到了某个极端的阶段，仍然（没有）改变。“即使……也……”。', '后面常用「まだ」「なお」「いまだに」等副词。', 126, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('076c7cd7-be68-40be-b3c9-b25527a438f3', '43acc599-6d7f-47bd-b4cf-c61b5ea1ab30', '彼は警察に逮捕されるにいたっても、なお自分の罪を認めなかった。', '彼は警察に逮捕されるにいたっても、なお自分の罪を認めなかった。', '直到被警察逮捕了他也没有认罪。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('fb7250bd-b1e4-4df9-a2da-6696d99ac1c3', '43acc599-6d7f-47bd-b4cf-c61b5ea1ab30', '皆に批判されるにいたっても、彼は自分の生き方を変えようとしなかった。', '皆に批判されるにいたっても、彼は自分の生き方を変えようとしなかった。', '即使被所有人批判，他也没有改变自己的生活方式。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('b66a33f5-28b8-410d-9c00-a052d722337c', '43acc599-6d7f-47bd-b4cf-c61b5ea1ab30', '株価がここまで下落するに至っても、彼はまだあきらめていないらしい。', 'かぶかがここまでげらくするに至っても、彼はまだあきらめていないらしい。', '股价下跌到如此程度，他好像仍然没有放弃。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('3a996511-f6ba-48bd-9703-46df6b849597', '～に 至[いた]るまで', NULL, 'N1', '動辞書形/名＋に至るまで', '動辞書形/名＋に至るまで', '表示程度、范围等。“从……到……”“甚至连……也……”“以至于……”。', '常与「から」一起使用，强调“从……到……全部……”。', 127, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('98d0ef54-dd06-46f0-90ed-08fc2fccd198', '3a996511-f6ba-48bd-9703-46df6b849597', '結婚をひかえ、家具はもちろん、皿やスプーンに至るまで新しいのを買いそろえた。', '結婚をひかえ、家具はもちろん、皿やスプーンに至るまで新しいのを買いそろえた。', '为了准备结婚，家具自不必说，连餐具之类也全部重新购买了。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('fd66b36b-b518-4e78-a5b3-3c2e5762abe6', '3a996511-f6ba-48bd-9703-46df6b849597', '帰宅途中、夕立にあい、頭から足先に至るまで全身びしょ濡れになった。', '帰宅途中、ゆうだちにあい、頭からあしさきに至るまで全身びしょぬれになった。', '回家途中遇到雷雨，从头到脚全身都淋湿了。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('9a5c6cd7-4276-4f1f-81bd-3c608f2c58a8', '3a996511-f6ba-48bd-9703-46df6b849597', '彼の自伝には奥さんとの出会いから結婚に至るまでの馴れ初めが詳しく書いてある。', '彼の自伝には奥さんとの出会いから結婚に至るまでのなれそめが詳しく書いてある。', '他的自传中详细记载了和妻子从相识到结婚的恋爱经过。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('c81c6a3c-88f3-4769-be84-4fcee7724bc2', '～に 負[お]うところが多い/に負うところが大きい', NULL, 'N1', '名＋に負うところが多い/に負うところが大きい', '名＋に負うところが多い/に負うところが大きい', '表示承蒙某人某事的恩惠，“得益于……”“多亏了……”。', '「負う」在语法中的意思是“得益于……”“多亏了……”。', 128, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('184dd44e-3d7c-4f8d-8d48-60b97a687c16', 'c81c6a3c-88f3-4769-be84-4fcee7724bc2', 'この研究の成功はチームメンバーの協力に負うところが大きい。', 'この研究の成功はチームメンバーの協力に負うところが大きい。', '本次研究的成功，很大程度上得益于各位组员的鼎力相助。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('44e97c82-8282-4015-8554-6c2a7560f9ef', 'c81c6a3c-88f3-4769-be84-4fcee7724bc2', '売上げの右肩上がりの上昇は販売部門全員の努力に負うところが多い。', '売上げのみぎかたあがりのじょうしょうは販売部門全員の努力に負うところが多い。', '销售业绩的直线上升得益于销售部门全体员工的努力。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('6ff52de5-460f-4b52-ae91-3146b5266222', 'c81c6a3c-88f3-4769-be84-4fcee7724bc2', 'この会社に入ったのは大学時代の先生の推薦に負うところが多い。', 'この会社に入ったのは大学時代の先生のすいせんに負うところが多い。', '能够进这家公司得益于大学时代的老师的推荐。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('afbcec7e-8686-405c-b955-e9bc60da0222', '～におかれましては', NULL, 'N1', '名＋におかれましては', '名＋におかれましては', '提示前项的人或事，“关于……”“至于……”。', '前面多用身份、地位比较高的人名或者是对方所属的机构的尊称（如：「貴社」）的名词后面，主要用于问候其健康状况、经营状况等场合。\n该句型是比较郑重的书面用语，多用在信件往来、商务书信里面。\n「～におかれましては」是尊他语，意思与「は」相同。与之相关联的表达是「～といたしましては」，是自谦的表达。如「弊社といたしましては～」/“对于我们公司来说……”。', 129, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('18f4447c-042d-427a-93f8-90132f655319', 'afbcec7e-8686-405c-b955-e9bc60da0222', '先生におかれましては、お変わりなくお過ごしのことと存じます。', '先生におかれましては、お変わりなくお過ごしのこととぞんじます。', '老师一切都好。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('8db792d1-2a00-454d-886c-50e15af68d6a', 'afbcec7e-8686-405c-b955-e9bc60da0222', '貴社におかれましては益々ご清栄のこととお慶び申し上げます。', 'ますますごせいえいのこととおよろこび申し上げます。', '恭祝贵公司生意兴隆。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('976d81fa-4ee9-4547-9d14-627274f19814', 'afbcec7e-8686-405c-b955-e9bc60da0222', '皆様におかれましてはますますご健勝のことと心よりお慶び申し上げます。', '皆様におかれましてはますますごけんしょうのことと心よりお慶び申し上げます。', '祝愿大家身体健康。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('0ebb2b8f-2676-4703-bfef-c52988118ba6', '～には 及[およ]ばない', NULL, 'N1', '動辞書形/名＋には及ばない', '動辞書形/名＋には及ばない', '表示没有必要做某事，“不必……”“没必要……”。', '意思与「ことはない」相同。\n固定用法：「言うに及ばず」/不用说', 130, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('480b1ecc-5069-44b2-93b3-430dfdd35a72', '0ebb2b8f-2676-4703-bfef-c52988118ba6', '検査では何の異常も見つからなかったので、心配するには及ばない。', '検査では何の異常も見つからなかったので、心配するには及ばない。', '在检查中没有发现任何异常情况，不必担心。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('b599ba58-4ed4-4287-a5be-c2dbab2672f7', '0ebb2b8f-2676-4703-bfef-c52988118ba6', 'みんな知っていることだから、わざわざ説明するには及ばない。', 'みんな知っていることだから、わざわざ説明するには及ばない。', '大家都知道的事情，没必要再解释。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('fb29ee6b-54be-4278-8cb1-0a44328bfe1f', '0ebb2b8f-2676-4703-bfef-c52988118ba6', '当たり前のことをしただけです。お礼を言われるには及びません。', '当たり前のことをしただけです。お礼を言われるには及びません。', '只是做了自己应该做的事情，没必要向我道谢。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('0e1cdd39-a89d-4912-a7b2-a6cb9f5f85c8', '0ebb2b8f-2676-4703-bfef-c52988118ba6', '連休中、海や山は言うに及ばず、公園や博物館まで親子連れであふれていた。', '連休中、海や山は言うに及ばず、公園や博物館までおやこづれであふれていた。', '放长假的时候，别说海边或者山上了，就连公园和博物馆里也全是带着孩子的父母们。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('510b506a-8055-443c-8040-8564cbf24f51', '～に（は） 及[およ]ばない', NULL, 'N1', '名＋に（は）及ばない', '名＋に（は）及ばない', '表示无法企及、无法达到某种程度或者比不上前项。“比不上……”“不及……”。', '意思与「～にはかなわない」相同。', 131, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('cedbac09-8e66-42d6-a027-fc425d8f0a9c', '510b506a-8055-443c-8040-8564cbf24f51', 'どんなに頑張っても、彼女の語学力には及ばない。', 'どんなに頑張っても、彼女の語学力には及ばない。', '在外语能力方面，再怎么努力也比不上她。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('380bb8be-17b1-4725-bda1-58e288e9ab43', '510b506a-8055-443c-8040-8564cbf24f51', '数学にかけては、彼に及ばない。', '数学にかけては、彼に及ばない。', '在数学方面比不上他。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('aaa66f30-0a88-4731-80da-87aeae45d811', '～に 欠[か]かせない/が欠かせない', NULL, 'N1', '名＋に欠かせない/が欠かせない', '名＋に欠かせない/が欠かせない', '“在……方面不可或缺的”“必不可少的”。', '意思与「～にとってなくてはならない」相同。', 132, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('16acb4e8-7286-4ae2-8951-42ff464421b0', 'aaa66f30-0a88-4731-80da-87aeae45d811', '異文化間の交流には、相手を理解しようという姿勢が欠かせない。', '異文化間の交流には、相手を理解しようというしせいが欠かせない。', '要想增进不同文化之间的交流，努力去理解对方的态度至关重要。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('0efb51c4-6d32-4050-868d-c2a03b5cb342', 'aaa66f30-0a88-4731-80da-87aeae45d811', '国際交流を進めるには、相手を理解しようとする姿勢がかかせない。', '国際交流を進めるには、相手を理解しようとする姿勢がかかせない。', '要想促进国际交流，就要努力去理解对方，这种态度至关重要。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('5d0a3866-1672-472c-b11c-de6d099a4652', 'aaa66f30-0a88-4731-80da-87aeae45d811', 'お花見に欠かせないものといえば、手作りのお弁当でしょう。', 'お花見に欠かせないものといえば、手作りのお弁当でしょう。', '说起赏花时必不可少的东西，我想那就是亲手做的便当吧。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('5279c7a4-57f2-4ae9-bd8c-add367c8b241', 'aaa66f30-0a88-4731-80da-87aeae45d811', '彼はわが社にとって欠かせない優秀な人材である。', '彼はわが社にとって欠かせない優秀な人材である。', '他是我们公司必不可少的优秀人才。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('3ccbba27-fb51-43c0-a035-9e03f59e8d64', '～にかかったら/にかかっては/にかかると', NULL, 'N1', '名＋にかかったら/にかかっては/にかかると', '名＋にかかったら/にかかっては/にかかると', '提示主语，“说到……”“提到……”。', '前面多用表示人或者人的言行的名词，指某人的态度、行为、语言达到某种程度，无人能及。', 133, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('1fc40552-cd85-4c4e-a322-e685f9e29a92', '3ccbba27-fb51-43c0-a035-9e03f59e8d64', '彼の毒舌にかかっては、誰も太刀打ちできない。', '彼のどくぜつにかかっては、誰もたちうちできない。', '他说话之刻薄，简直无人能及。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('b9700247-3b2c-40aa-b3a3-b2f7a95d214b', '3ccbba27-fb51-43c0-a035-9e03f59e8d64', '彼女にかかっては、嫌なことも言えなくなる。', '彼女にかかっては、嫌なことも言えなくなる。', '对象是她的话，连自己讨厌的事情也说不出口。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('e18cf774-9b91-485a-aece-d0ba1f6147e2', '3ccbba27-fb51-43c0-a035-9e03f59e8d64', '彼女の早口にかかっては、誰も比べものにならない。', '彼女の早口にかかっては、誰も比べものにならない。', '她讲话语速之快，无人能比。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('f31defea-28c6-4d3e-9ab6-37b174573b18', '～にかかっている', NULL, 'N1', '～にかかっている', '～にかかっている', '表示前后两项的关联，后项会产生什么样的结果，全凭前项的条件。“取决于……”“全凭……”。', '意思与「～いかんにかかっている」相同。', 134, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('3f50d7b9-de36-4684-8b60-6f54dc90fd83', 'f31defea-28c6-4d3e-9ab6-37b174573b18', '今年卒業できるかどうかは、これからの頑張りにかかっている。', '今年卒業できるかどうかは、これからの頑張りにかかっている。', '今年能否顺利毕业，取决于你们今后的努力情况。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('8502a17b-d188-4f38-8adf-5952621376db', 'f31defea-28c6-4d3e-9ab6-37b174573b18', '君たちが成功するかどうかは、与えられたチャンスをどう使うかにかかっている。', '君たちが成功するかどうかは、与えられたチャンスをどう使うかにかかっている。', '能否获得成功，关键看你们如何把握住机会。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('198f0581-a755-4de1-b32c-3c02e7e41abc', 'f31defea-28c6-4d3e-9ab6-37b174573b18', '物事の成否は人の考え方にかかっている。', '物事のせいひは人の考え方にかかっている。', '事情成功与否，取决于人们的想法。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('8f2a75cd-ae2b-41d6-9aea-9699d3073fcc', '～に限ったことではない', NULL, 'N1', '名＋に限ったことではない', '名＋に限ったことではない', '“不是……所独有的问题”。', '该句型也可以用「～に限った問題ではない」的形式。', 135, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('6005fd0d-4b93-4ad0-9770-29e7af341b40', '8f2a75cd-ae2b-41d6-9aea-9699d3073fcc', 'これはクラス全員の問題なので、何も彼女に限ったことではない。', 'これはクラス全員の問題なので、何も彼女に限ったことではない。', '这是全班同学都有的问题，并不是她一个人的问题。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('5958d20f-4edc-4dcc-bd54-2cfe04b6e556', '8f2a75cd-ae2b-41d6-9aea-9699d3073fcc', '品質問題はこのメーカーに限ったことではなく、業界全体の問題だ。', '品質問題はこのメーカーに限ったことではなく、業界全体の問題だ。', '质量问题并非这个厂商一家的问题，而是整个行业的问题。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('956560e3-ab42-451d-9f92-6a19a132111a', '8f2a75cd-ae2b-41d6-9aea-9699d3073fcc', '試合などの時の誤審は何もプロサッカーに限ったことではない。', '試合などの時のごしんは何もプロサッカーに限ったことではない。', '比赛中的误判并非职业足球所独有的问题。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('9ac916ca-5ade-4424-8a3a-25a5a9332dce', '～にかこつけて', NULL, 'N1', '名＋にかこつけて', '名＋にかこつけて', '“以……为托词”“以……为借口”。', '多指以前项的事由为借口，去做另外一件事。', 136, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('6701fdf3-fc83-4c4b-8aae-1aa4990dcb4e', '9ac916ca-5ade-4424-8a3a-25a5a9332dce', '父の病気にかこつけて、会議への出席を断った。', '父の病気にかこつけて、会議への出席を断った。', '以父亲生病为借口，拒绝出席会议。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('4074151d-6f62-48c8-89e7-8c0811bab702', '9ac916ca-5ade-4424-8a3a-25a5a9332dce', '病気にかこつけて、一日会社をサボった。', '病気にかこつけて、一日会社をサボった。', '以生病为由，请了一天假。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('cb82c19d-d4a5-4b41-847e-360f69f35344', '9ac916ca-5ade-4424-8a3a-25a5a9332dce', '出張にかこつけて、海外旅行を楽しんできた。', '出張にかこつけて、海外旅行を楽しんできた。', '以出差为由，去国外玩了一趟。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('69376613-fe43-4548-9ae2-23f2704058c8', '～にかたくない', NULL, 'N1', '動辞書形/名＋にかたくない', '動辞書形/名＋にかたくない', '“不难想象……”“不难察觉……”“很容易就……”。', '常用「想像する」「察する」「理解する」等词。', 137, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('ed99d4fe-2720-4332-a275-e8efcc50e2de', '69376613-fe43-4548-9ae2-23f2704058c8', '審査員が彼の作品を見て、そのすばらしさに驚いたことは、想像にかたくない。', '審査員が彼の作品を見て、そのすばらしさに驚いたことは、想像にかたくない。', '不难想象，评委们看到他那么优秀的作品，一定会惊讶的。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('da330fe4-8e42-431b-815b-869cdbbd0db8', '69376613-fe43-4548-9ae2-23f2704058c8', '彼が秘密を外部にもらしたことは想像にかたくない。', '彼が秘密を外部にもらしたことは想像にかたくない。', '不难想象，一定是他把秘密泄露出去的。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('c8c684d7-1403-41a0-a90a-7d0b80197e86', '69376613-fe43-4548-9ae2-23f2704058c8', '子どもを亡くした親の悲しみは察するにかたくない。', '子どもを亡くした親の悲しみはさっするにかたくない。', '失去孩子的父母的悲痛之情不难察觉。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('94f36b19-4a22-4a84-85e5-f7ed6fcb4c26', '～にかまけて', NULL, 'N1', '名＋にかまけて', '名＋にかまけて', '“忙于……”。', '表示忙于做某事，无暇顾及其他；或者只顾做某事，忽略了其他。', 138, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('ea088c97-fd1f-4e43-bac8-dc34d079c4dc', '94f36b19-4a22-4a84-85e5-f7ed6fcb4c26', '仕事にかまけて、子どもの面倒を見る時間もない。', '仕事にかまけて、子どもの面倒を見る時間もない。', '忙于工作无暇照顾孩子。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('f7686e15-ac18-445d-8717-8bd829628e9f', '94f36b19-4a22-4a84-85e5-f7ed6fcb4c26', '子どもにかまけて、本を読む時間もない。', '子どもにかまけて、本を読む時間もない。', '忙于照顾孩子，连读书的时间都没有。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('acd23ce1-40e3-4f54-9c7c-8ac2fc1da2ba', '94f36b19-4a22-4a84-85e5-f7ed6fcb4c26', '日々の雑務にかまけて、ごく当たり前のことも忘れているような気がする。', '日々のざつむにかまけて、ごく当たり前のことも忘れているような気がする。', '每天忙于日常的琐事，好像连最基本的东西也忘记了。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('c751f5cb-7c2c-4010-811c-fe8bf5b37346', '～に 越[こ]したことはない', NULL, 'N1', '～に 越[こ]したことはない', '～に 越[こ]したことはない', '“最好是……”“莫过于……”“……的话就再好不过了”。多用在表示一些常识性的东西或者认为是理所当然的事情。', NULL, 139, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('e942af60-c723-4afe-9720-d791fc86a239', 'c751f5cb-7c2c-4010-811c-fe8bf5b37346', '申請書の提出締め切りは明日の午後4時だが、早めに出せればそれにこしたことはない。', '申請書の提出締め切りは明日の午後4時だが、早めに出せればそれにこしたことはない。', '提交申请书的截止日期是明天下午4点，但是如果能够早一点提交的话最好不过了。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('6d49094d-beca-46a2-a711-baa026ae356c', 'c751f5cb-7c2c-4010-811c-fe8bf5b37346', '体は丈夫にこしたことはない。', '体は丈夫にこしたことはない。', '身体结实是再好不过了。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('b7f0c171-cb3b-4807-959c-aa4cd591acc9', 'c751f5cb-7c2c-4010-811c-fe8bf5b37346', '試験は満点を取るに越したことはない。', '試験は満点を取るに越したことはない。', '能考到满分当然是最好了。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('25948f1f-1baa-4e5d-88c7-754eecd3d540', '～に 如[し]くはない', NULL, 'N1', '動辞書形/名＋に如くはない', '動辞書形/名＋に如くはない', '“不如……”“最好……”。', '表示在某方面没有比之更好的，或者是用来提建议。', 140, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('f430ad1d-83c3-455d-803f-07298bfc33bf', '25948f1f-1baa-4e5d-88c7-754eecd3d540', 'このあたりは夜になると、物騒になるので、用心するにしくはない。', 'このあたりは夜になると、ぶっそうになるので、ようじんするにしくはない。', '这一带到了晚上就很乱，最好要小心。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('a11d0891-eaa5-438f-a339-475a036f6cc7', '25948f1f-1baa-4e5d-88c7-754eecd3d540', '歴史にかけては、彼にしくはない。', '歴史にかけては、彼にしくはない。', '在历史方面我不如他。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('156d9a68-272a-481c-89a5-bdf8c158d47c', '25948f1f-1baa-4e5d-88c7-754eecd3d540', '逃げるにしくはなし。', '逃げるにしくはなし。', '三十六计，走为上策。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('1114f3ab-83bb-4694-9d5b-a8a4a9844825', 'にして', NULL, 'N1', '名＋にして', '名＋にして', '表示时间、次数等，“在……的时候”“在某个时间段”。', '前面常用表示时间、年龄、次数的数量词。', 141, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('44fe5326-cdc1-4b1c-987d-17b572c74901', '1114f3ab-83bb-4694-9d5b-a8a4a9844825', 'この試験は非常に難しく、私も4回目にしてようやく合格できた。', 'この試験は非常に難しく、私も4回目にしてようやく合格できた。', '这个考试非常难，我也是考了四次才通过的。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('8ab8c0f8-28a3-44f6-916d-c0c326ebb73e', '1114f3ab-83bb-4694-9d5b-a8a4a9844825', '彼は40歳にして父親になった。', '彼は40歳にして父親になった。', '他在40岁当了父亲。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('510939bf-616c-455e-bf80-7f12b72a9640', '1114f3ab-83bb-4694-9d5b-a8a4a9844825', '三十にして立つ。', '三十にして立つ。', '三十而立。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('69461d97-6129-4594-8714-9c4d06decc8c', 'AにしてB', NULL, 'N1', '名＋にして', '名＋にして', '表示并列，“既是……又是……”“……的同时”。', NULL, 142, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('d989eae0-aee4-4774-bf47-bae9d1e80aff', '69461d97-6129-4594-8714-9c4d06decc8c', '彼は医者にして作家でもある。', '彼は医者にして作家でもある。', '他既是医生也是一名作家。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('36f74da0-7c3c-4fcd-8246-3a0af19e6c6d', '69461d97-6129-4594-8714-9c4d06decc8c', 'そのタレントは歌手にして映画監督でもある。', 'そのタレントは歌手にして映画監督でもある。', '那艺人既是歌手也是电影导演。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('83705cd6-0288-44bb-913c-32b30174be9f', '～にしてはじめて', NULL, 'N1', '名＋にしてはじめて', '名＋にしてはじめて', '表示条件、限定。“只有……才……”。', NULL, 143, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('e65e727e-fe1c-4ee6-b81e-9cfaf7c828d5', '83705cd6-0288-44bb-913c-32b30174be9f', 'この味は母にしてはじめて出せる味だ。', 'この味は母にしてはじめて出せる味だ。', '这个味道只有妈妈才能做出来。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('967cabcd-5f8b-40fd-8006-771dd8dd8b12', '83705cd6-0288-44bb-913c-32b30174be9f', 'そんな驚異的な発明は彼のような天才にしてはじめてできることだ。', 'そんな驚異的な発明は彼のような天才にしてはじめてできることだ。', '那么了不起的发明只有像他那样的天才才能做得到。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('95398c82-3cba-48b7-b011-0d59e03087f3', '～にして～（ない）', NULL, 'N1', '名＋にして～（ない）', '名＋にして～（ない）', '表示逆接，“就连……也……（没有做到）”。', '后项多用否定的表达。', 144, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('8798bd45-9c71-4e50-858b-95e01044b366', '95398c82-3cba-48b7-b011-0d59e03087f3', 'ノーベル平和賞を受賞したT氏は、少年時代、劣等生だったという。あの人にしてそうなのだから、わが子が劣等生だからといって深刻に悩む必要もない。', 'ノーベル平和賞を受賞したT氏は、少年時代、劣等生だったという。あの人にしてそうなのだから、わが子がれっとうせいだからといって深刻に悩む必要もない。', '听说得过诺贝尔和平奖的T先生在少年时代也曾经是差生。就连那个人也如此，所以没必要为自己的孩子学习成绩不好而烦恼。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('ff37cc86-0449-478f-a5d9-de43acb22910', '95398c82-3cba-48b7-b011-0d59e03087f3', '先生にして解けない問題なので、生徒たちができないのも無理はない。', '先生にして解けない問題なので、生徒たちができないのも無理はない。', '就连老师都没有解答出来的问题，学生不会也情有可原。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('c2867d63-5d25-4dcb-bb65-af1030eba02e', '～に 忍[しの]びない', NULL, 'N1', '動辞書形＋に忍びない', '動辞書形＋に忍びない', '表示对于某件事情难以忍受或者觉得很痛心。“不忍心……”“不堪……”。', '固定用法：「見るに忍びない」/惨不忍睹。', 145, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('2bf8d9aa-6cb1-4e58-84dc-1e9099a86ebb', 'c2867d63-5d25-4dcb-bb65-af1030eba02e', '事故の被害者たちの姿はあまりにも気の毒で見るにしのびない。', '事故の被害者たちの姿はあまりにも気の毒で見るにしのびない。', '事故受害者的样子简直惨不忍睹。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('f32fa69a-9e73-4878-bdcf-18ee31bedc01', 'c2867d63-5d25-4dcb-bb65-af1030eba02e', '両親を失った赤ちゃんの泣き声は聞くにしのびない。', '両親を失った赤ちゃんの泣き声は聞くにしのびない。', '失去父母的婴儿的哭声听起来让人揪心。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('fa963b00-3599-4d5e-af31-d6a537699a8c', 'c2867d63-5d25-4dcb-bb65-af1030eba02e', '一口もしなかった料理は捨てるにしのびない。', '一口もしなかった料理は捨てるにしのびない。', '一口都没吃的菜，让人舍不得扔。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('c140f255-6f67-454b-9ebe-a0bea7b8f430', '～に 準[じゅん]じ/に準じて/に準じる', NULL, 'N1', '名＋に準じ/に準じて/に準じる', '名＋に準じ/に準じて/に準じる', '表示以前项的规格和标准处理后项事情。“以……为标准”“按照……对待”。', '「準じる」可写作「準ずる」。\n「～に準じ」「～に準じて」用在句中，「～に準じる」用在句末。', 146, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('e747f2d8-76a4-405a-8ad5-3abb1def7553', 'c140f255-6f67-454b-9ebe-a0bea7b8f430', 'うちの会社はアルバイトの人にも、正社員に準ずる待遇を与えている。', 'うちの会社はアルバイトの人にも、正社員に準ずる待遇を与えている。', '我们公司对于兼职人员也给予同正式工一样的待遇。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('25ee9a61-8c0c-43d2-8015-c55e965d9587', 'c140f255-6f67-454b-9ebe-a0bea7b8f430', '毎年の業務の実績及び勤務時間に準じて、ボーナスを決める。', '毎年の業務の実績及び勤務時間に準じて、ボーナスを決める。', '根据每年的实际业绩和上班时间来决定年终奖。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('2c89ab24-e5a8-4f44-b4d7-0ec377fdcdc3', 'c140f255-6f67-454b-9ebe-a0bea7b8f430', '経験年数に準じて手当てを出す。', '経験年数に準じて手当てを出す。', '根据工龄来决定津贴。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('bb26092e-9cdd-48ea-9027-79c9c761bc8d', '～に 即[そく]して/に即した/に則して/に則した', NULL, 'N1', '名＋に即して/に即した/に則して/に則した', '名＋に即して/に即した/に則して/に則した', '表示根据、依据。“按照……”“依据……”。表示规矩、规则时，常写作「に則して」「に則した」。', '「～に即して」后面接续动词、形容词、副词。「～に即した」后面接续名词，作定语。\n该句型前面接续表示规则、法律等的名词时，也可写作「～に則して/に則した」的形式。', 147, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('1ed8219c-7fbb-4927-a5b7-403f0927cb9a', 'bb26092e-9cdd-48ea-9027-79c9c761bc8d', 'このような規則は、実態に即して柔軟に適用すべきだ。', 'このような規則は、実態に即して柔軟に適用すべきだ。', '这个原则应该根据实际情况，灵活运用。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('90da97ac-168c-4f9b-a249-127edc5597d8', 'bb26092e-9cdd-48ea-9027-79c9c761bc8d', '新聞には、事実に即して、正確な情報を提供してほしい。', '新聞には、事実に即して、正確な情報を提供してほしい。', '报纸应该依据事实，提供准确情报。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('8db07e7f-546d-4472-aec2-96128fb20b53', 'bb26092e-9cdd-48ea-9027-79c9c761bc8d', '町の再開発をいっきょに進めるのには無理がある。実状に即した計画を練らなければならない。', '町の再開発をいっきょに進めるのには無理がある。実状に即した計画を練らなければならない。', '想要一次性地完成城市的开发建设有点困难，还是应该从实际情况出发制订计划。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('b951d536-fbb9-437a-8c8c-b9b7a6d14304', '～にたえる', NULL, 'N1', '動辞書形/名＋にたえる', '動辞書形/名＋にたえる', '表示前项的某事、某物具有一定的价值，“值得……”。', '常用「見る」「聞く」「鑑賞する」「評価」「賞賛」「批判」等词，指某事、某物具有那样的价值。', 148, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('d81ff2a2-2876-4412-8c36-a5fc2129e857', 'b951d536-fbb9-437a-8c8c-b9b7a6d14304', '最近のCDは品質がよく、厳しい音楽家の耳にも十分にたえるだろう。', '最近のCDは品質がよく、厳しい音楽家の耳にも十分にたえるだろう。', '最近的CD音质非常好，就连很严格的音乐家也挑不出什么毛病。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('e2ca2bfb-133c-49f6-aed4-b29db956825c', 'b951d536-fbb9-437a-8c8c-b9b7a6d14304', '彼の今回の作品は、専門家が鑑賞するにたえるできであった。', '彼の今回の作品は、専門家が鑑賞するにたえるできであった。', '他这次的作品值得专家鉴赏。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('52e9088e-215f-4556-9d6c-a9980b244cd5', 'b951d536-fbb9-437a-8c8c-b9b7a6d14304', 'わが社が開発したこの機種は、多くのユーザーの評価にたえるものだ。', 'わが社が開発したこの機種は、多くのユーザーの評価にたえるものだ。', '我们公司开发的这种型号的商品，深受用户好评。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('f92ba45e-96b1-4256-99f2-211e82f8213d', '～にたえない', NULL, 'N1', '動辞書形＋にたえない', '動辞書形＋にたえない\n名＋にたえない', '表示评价，“无法……”“不值得……”。\n表示一种情感，“非常……”“极其……”。', '常用「見る」「聞く」等词。\n常用「感謝」「同情の念」「悲しみ」「喜び」等词。', 149, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('0a8cbd4c-49e5-4b33-b666-0d627f3add71', 'f92ba45e-96b1-4256-99f2-211e82f8213d', '美しかった森林が、開発のためすべて切り倒され、見るにたえない。', '美しかった森林が、開発のためすべて切り倒され、見るにたえない。', '曾经很美丽的森林因为开发的缘故全部被砍伐，让人看不下去。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('2be28f04-786a-42e3-b5d0-70f283916474', 'f92ba45e-96b1-4256-99f2-211e82f8213d', 'あの役者のきざな格好は、まったく見るにたえない。', 'あの役者のきざな格好は、まったく見るにたえない。', '那个演员的样子太矫揉造作，让人看不下去。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('ae306fa3-c89b-410d-8ef4-cd70bfeee9c4', 'f92ba45e-96b1-4256-99f2-211e82f8213d', 'この番組はひどくて見るにたえない。', 'この番組はひどくて見るにたえない。', '这个节目太糟糕了简直看不下去。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('2de45ee7-f131-4f10-a310-12814a414425', 'f92ba45e-96b1-4256-99f2-211e82f8213d', '聞くにたえない惡口を言っている。', '聞くにたえない惡口を言っている。', '说着一些让人听不下去的坏话。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('7e32316a-bfa4-44ea-974d-c1ccefef5379', 'f92ba45e-96b1-4256-99f2-211e82f8213d', 'いろいろお世話になりました。感謝にたえません。', 'いろいろお世話になりました。感謝にたえません。', '承蒙您多方关照，不胜感谢。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('11ccf79c-3a92-4fdc-a4a6-585f3a264b3f', 'f92ba45e-96b1-4256-99f2-211e82f8213d', '息子が無事退院できて、親として喜びにたえません。', '息子が無事退院できて、親として喜びにたえません。', '儿子能够平安地出院，作为父母无比高兴。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('ab9fee99-f37b-4aad-ae2d-e0b58084c359', '～に 足[た]りる/に足る', NULL, 'N1', '動辞書形/名＋に足りる/に足る', '動辞書形/名＋に足りる/に足る', '表示评价，某事、某物达到了某种程度或者要求。“值得……”“足以……”。', '常用「信頼」「満足」「推薦する」等词。', 150, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('b5a91561-4a3c-4996-a80e-318aac6024d4', 'ab9fee99-f37b-4aad-ae2d-e0b58084c359', '合格と認められるにたる成績を示さなかった者には再試験を課す。', '合格と認められるにたる成績を示さなかった者には再試験をかす。', '没有及格的人要参加补考。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('9947dc54-51f8-46a7-a324-66f8edaa300e', 'ab9fee99-f37b-4aad-ae2d-e0b58084c359', '先日提出された調査報告は信頼に足るものではなかった。', '先日提出された調査報告は信頼に足るものではなかった。', '上次提交的调查报告不足为信。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('84c7b2f9-c6fa-4a08-8c29-8afa7f8a806c', 'ab9fee99-f37b-4aad-ae2d-e0b58084c359', 'この作品の芸術的価値は高く、十分、今回の展覧会に出品するにたる。', 'この作品の芸術的価値は高く、十分、今回の展覧会に出品するにたる。', '这件作品的艺术价值很高，值得参展。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('2e8bd7b6-1c9a-4d7d-9e62-e5087a3e3b34', '～に 足[た]りない/に足らない', NULL, 'N1', '動辞書形/名＋に足りない/に足らない', '動辞書形/名＋に足りない/に足らない', '表示评价，某事、某物不足以那样去做。“不值得……”“不足以……”。', '常用「恐れる」「信頼する」「気にする」等词。', 151, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('71f8a75a-c4b9-4b56-bdf2-b6e428e20533', '2e8bd7b6-1c9a-4d7d-9e62-e5087a3e3b34', '相手チームは実力が足りないので、恐れるに足らない。', '相手チームは実力が足りないので、恐れるに足らない。', '对手实力欠缺，不足为惧。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('58a1c3d0-2d34-4305-b092-7f74eb486ffc', '2e8bd7b6-1c9a-4d7d-9e62-e5087a3e3b34', 'あんな人は信頼するに足りない。', 'あんな人は信頼するに足りない。', '那种人不值得相信。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('d2e54e2e-3ee4-4399-9ca5-64157ceca11f', '2e8bd7b6-1c9a-4d7d-9e62-e5087a3e3b34', 'そんなことは取るに足らない。', 'そんなことは取るに足らない。', '那种事情不值一提。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('84bf6c80-c614-4d0f-b052-70c5bc68ca20', '～に 照[て]らして', NULL, 'N1', '名＋に照らして', '名＋に照らして', '表示动作、行为的依据，“依照……”“对照……”。', '常用「 憲[けん] 法[ぽう]」「法律」「規則」「ルール」等表示规章制度的名词。', 152, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('7624c0f7-3550-447a-8a2e-cab162f4717c', '84bf6c80-c614-4d0f-b052-70c5bc68ca20', '法律に照らして処分する。', '法律に照らして処分する。', '依法判处。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('8d92efcf-fa05-4212-9f22-09f52aa2c94a', '84bf6c80-c614-4d0f-b052-70c5bc68ca20', '憲法に照らして、国民の権利と自由を保障する。', '憲法に照らして、国民の権利と自由を保障する。', '依据宪法保障国民的权利和自由。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('3ae7cb8e-bb0f-498b-9443-2f95f5ef9b34', '84bf6c80-c614-4d0f-b052-70c5bc68ca20', '違法行為については、社則に照らして処分すべきだ。', '違法行為については、社則に照らして処分すべきだ。', '依据公司规定对违法行为进行惩处。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('dfbe1b07-e305-4212-9793-e2b67322ee85', '～にとどまらず', NULL, 'N1', '名（＋だけ/のみ）＋にとどまらず', '名（＋だけ/のみ）＋にとどまらず', '“不仅停留在……而且（还波及）……”。表示不仅限定在某项范围内，甚至还涉及其他的地域和空间。', '常用表示范围、时间、区域的名词。', 153, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('4f03b7cb-0763-44a3-94be-5e5de3e92b16', 'dfbe1b07-e305-4212-9793-e2b67322ee85', '火山の噴火の影響は、ふもとにとどまらず、周辺地域全体に及んだ。', 'かざんの噴火の影響は、ふもとにとどまらず、周辺地域全体におよんだ。', '火山爆发不仅影响到山脚地带，还波及周边地区。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('107eca6f-2989-47e4-86d2-fc1d15027abd', 'dfbe1b07-e305-4212-9793-e2b67322ee85', '不登校現象は70年代を通して大都市にとどまらず、地方にまで波及していった。', 'ふとうこう現象は70年代を通して大都市にとどまらず、地方にまではきゅうしていった。', '在70年代，拒绝上学问题不仅出现在大城市，甚至波及了各个地方。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('deba48eb-fef8-4fd0-a60e-029149b95614', 'dfbe1b07-e305-4212-9793-e2b67322ee85', '障害者の雇用創出だけにとどまらず自立のお手伝いをしなければならない。', '障害者のこようそうしゅつだけにとどまらず自立のお手伝いをしなければならない。', '不仅要为残疾人创造就业机会，还要设法帮助他们自立。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('b2926706-b8e2-4721-bfa6-676d81544fb6', '～に 則[のっと]って', NULL, 'N1', '名＋に則って', '名＋に則って', '表示动作、行为的依据，“依据……”“按照……”“效法……”“遵照……”。', '常用「慣例」「先例」「習慣」「常識」等表示传统观念、习惯做法的名词。', 154, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('d237fee6-9996-4265-a422-4eaae05d4f8e', 'b2926706-b8e2-4721-bfa6-676d81544fb6', '国際的に承認された原則に則って、契約を結びました。', '国際的に承認された原則に則って、契約を結びました。', '依据国际公认的原则签订了合同。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('809b3984-911f-4834-b998-8f4e2d9fd2d1', 'b2926706-b8e2-4721-bfa6-676d81544fb6', 'この議事録は慣例に則って作りました。', 'このぎじろくは慣例に則って作りました。', '这份会议记录是依照惯例制作的。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('64cd6b30-d8c0-4b08-a390-83bb4fe5d2f7', 'b2926706-b8e2-4721-bfa6-676d81544fb6', '古式に則って、結婚式を行いました。', 'こしきに則って、結婚式を行いました。', '效法古礼，举办了婚礼。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('3182ebdb-e198-4430-95aa-fef0c3afcb5b', '～には 無[む] 理[り]がある', NULL, 'N1', '動辞書形/名＋には無理がある', '動辞書形/名＋には無理がある', '“……方面有不合理的地方”“……有行不通的地方”“……方面有不切合实际的地方”。', NULL, 155, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('7481f7cc-cf4b-4a32-a835-6f0d3856b530', '3182ebdb-e198-4430-95aa-fef0c3afcb5b', 'ただ3か月でこのプロジェクトを完成するには無理がある。', 'ただ3か月でこのプロジェクトを完成するには無理がある。', '想在三个月之内完成这个项目有点困难。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('127966a7-8e19-440b-bb4d-682ed5ce9e39', '3182ebdb-e198-4430-95aa-fef0c3afcb5b', '今度の計画には無理がある。', '今度の計画には無理がある。', '这次的计划有不合理的地方。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('3bd7d692-8c6c-4b78-a20c-5335379f9a7e', '3182ebdb-e198-4430-95aa-fef0c3afcb5b', '君の話には無理がある。', '君の話には無理がある。', '你说得有点勉强。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('3651a31c-d530-4de5-aef9-e3c7184135ec', '～にひきかえ/にひきかえて', NULL, 'N1', '～にひきかえ/にひきかえて', '～にひきかえ/にひきかえて', '表示对比，“与……相反”“与……不同”。', '前后两项为对照性的人或事。\n也可用「それにひきかえ」/与前项不同。', 156, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('657a4e12-3904-4ef6-b34f-bd19accec241', '3651a31c-d530-4de5-aef9-e3c7184135ec', '若いころは一日中テニスをしても何ともなかった。それにひきかえ、最近は一時間やっただけで足が動かなくなってしまう。', '若いころは一日中テニスをしても何ともなかった。それにひきかえ、最近は一時間やっただけで足が動かなくなってしまう。', '年轻的时候打一整天网球也没关系。与此相反，现在仅仅运动一个小时腿就累得动不了。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('adb8c0ae-0d3b-46b1-b875-9bc7911eff61', '3651a31c-d530-4de5-aef9-e3c7184135ec', '彼の給料は1か月40万円だ。それにひきかえ、私の給料はなんと安いことか。', '彼の給料は1か月40万円だ。それにひきかえ、私の給料はなんと安いことか。', '他每个月的工资是40万日元。和他相反，我的工资真是太少了。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('9f483212-2b03-41f1-915e-b4e1ced5b21f', '3651a31c-d530-4de5-aef9-e3c7184135ec', '弟が社交的なタイプなのにひきかえて、兄は人前に出るのを嫌うタイプだ。', '弟が社交的なタイプなのにひきかえて、兄は人前に出るのを嫌うタイプだ。', '弟弟是个擅长交际的人，哥哥却不太喜欢与人交往。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('bf1c1aa8-4bbd-4c56-9138-34f14b3a2977', '～にもほどがある', NULL, 'N1', '～にもほどがある', '～にもほどがある', '用于告诫对方做事情要适可而止或者表示“实在太过分”的语气。“……也应该有个度”“……也应该有分寸”。', '固定用法：「 冗[じょう] 談[だん]にもほどがある」/开玩笑也要有度。', 157, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('974f48db-f9f0-4e07-993a-8f8bb9d9827f', 'bf1c1aa8-4bbd-4c56-9138-34f14b3a2977', '中村「山田さんは本当に猫が好きなんだね。今日のバッグも猫の絵柄だし。」山田「うん。でも、あんまり持ち物が猫柄ばかりなんで、家族から『猫好きにもほどがあるだろう。』って言われたりする。」', '中村「山田さんは本当に猫が好きなんだね。今日のバッグも猫のえがらだし。」山田「うん。でも、あんまりもちものがねこがらばかりなんで、家族から『ねこずきにもほどがあるだろう。』って言われたりする。」', '中村：“山田你真是喜欢猫啊，今天带的包也是猫的图案。”\n山田：“是啊。不过因为东西都是猫的图案，所以家里人有时会说我‘就算喜欢猫也要有个度吧’。”', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('aff37e49-f0ca-43dc-8184-dd3281c535fa', 'bf1c1aa8-4bbd-4c56-9138-34f14b3a2977', '先輩に対して、あんな失礼なことを言うなんて、無神経にもほどがある。', '先輩に対して、あんな失礼なことを言うなんて、むしんけいにもほどがある。', '居然对前辈讲那么失礼的话，真是太迟钝了。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('cb6ff93b-38d1-4de1-a803-6a4ba0c6e114', 'bf1c1aa8-4bbd-4c56-9138-34f14b3a2977', 'こんなミスをするなんて、いいかげんにもほどがある。', 'こんなミスをするなんて、いいかげんにもほどがある。', '居然犯这种错误，草率行事也应该有个度吧。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('a3f08a51-5029-4fe3-8a1c-0ade895fd921', '～にも 増[ま]して', NULL, 'N1', '動·イ形·ナ形の名詞修飾形＋の/名＋にも増して', '動·イ形·ナ形の名詞修飾形＋の/名＋にも増して', '“比……更加……”“超过……”。', '常用「AにもましてB」的形式，“比起A，B更加……”。\n固定用法：「以前にもまして」「前にもまして」「いつにもまして」「誰にもまして」。', 158, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('ca3c97fe-9d13-46f4-be02-3cd510ff1e77', 'a3f08a51-5029-4fe3-8a1c-0ade895fd921', '今回のイベントは、前回にもまして好評だった。', '今回のイベントは、前回にもまして好評だった。', '这次活动获得了比上次更好的评价。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('540a6cd1-f159-494d-a63c-ad25990837e8', 'a3f08a51-5029-4fe3-8a1c-0ade895fd921', '大学生の就職は、今年は去年にもまして、さらに厳しい状況になることが予想される。', '大学生の就職は、今年は去年にもまして、さらに厳しい状況になることが予想される。', '大学生的就业情况，今年会比去年更加严峻。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('5e03427d-324e-477a-bfb5-1b8165721f22', 'a3f08a51-5029-4fe3-8a1c-0ade895fd921', 'あの家の息子は父親から会社を任されて、前にもまして仕事に励むようになった。', 'あの家の息子は父親から会社を任されて、前にもまして仕事に励むようになった。', '他自从继承了父亲的公司后在工作方面比以前更加认真了。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('f74e8e2e-8b2d-4404-a800-f3b2baef73b1', '～によるところが大きい', NULL, 'N1', '名＋によるところが大きい', '名＋によるところが大きい', '表示前后两项的关联，某件事情在很大程度上依赖后项，跟后项有密不可分的关系。“得益于……”“多亏了……”“主要依赖于……”“原因在于……”。', '意思与「～に負うところが大きい/多い」相近。但是「～によるところが大きい」既可以表示积极的意思也可以表示消极的意思。「～に負うところが大きい/多い」的意思是“得益于……”，多表示积极的意思。', 159, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('a5127f6a-682c-462a-be5b-486653926572', 'f74e8e2e-8b2d-4404-a800-f3b2baef73b1', 'かつて映画スターであった山田氏が初挑戦で知事選に勝利したのは、能力というより、人気と知名度によるところが大きい。', 'かつて映画スターであった山田氏が初挑戦で知事選に勝利したのは、能力というより、人気と知名度によるところが大きい。', '山田曾经是电影明星，他（她）第一次参选知事就获得了成功，与其说是凭借实力，不如说很大程度上得益于他（她）的人气和知名度。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('da8b4189-e7a8-4078-835b-842b577ff5a0', 'f74e8e2e-8b2d-4404-a800-f3b2baef73b1', '彼の成功は父親の助力によるところが大きい。', '彼の成功は父親の助力によるところが大きい。', '他的成功很大程度上得益于他父亲的帮助。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('cbe9b0bd-d2f7-43da-b884-e772aae58c0c', 'f74e8e2e-8b2d-4404-a800-f3b2baef73b1', '試験に合格できたのは先生の指導によるところが大きい。', '試験に合格できたのは先生の指導によるところが大きい。', '之所以能够通过这次考试多亏了老师的指导。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('96003974-7363-4cc2-a18a-26be00f7d0df', 'f74e8e2e-8b2d-4404-a800-f3b2baef73b1', '今の不況は金融政策の失敗によるところが大きい。', '今の不況は金融政策の失敗によるところが大きい。', '现在的不景气很大程度上是由于金融政策的失败。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('1f9a29b3-34a5-475f-9b69-7885054651aa', '～の 至[いた]りだ', NULL, 'N1', '名＋の至りだ', '名＋の至りだ', '表示达到极致、处于最高状态的语气，“非常……”“……至极”。多用一些固定搭配。', '固定用法：「光栄の至り」/无上的光荣，「 若[わか] 気[げ]の至り」/无比幼稚，「赤面の至り」/无比羞愧，「感激の至り」/无比感激。\n是比较郑重的表达方式。', 160, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('16fdd584-b531-4ad5-bbb7-68474ef7b895', '1f9a29b3-34a5-475f-9b69-7885054651aa', 'こんな立派な賞をいただいて、光栄の至りです。', 'こんな立派な賞をいただいて、光栄の至りです。', '能够得到如此大奖无比的光荣。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('f12c0003-8e85-44c9-9d64-0186eaaf8f38', '1f9a29b3-34a5-475f-9b69-7885054651aa', '皆の前で仕事上のミスを指摘されて、赤面の至りだ。', '皆の前で仕事上のミスを指摘されて、せきめんの至りだ。', '在大家面前被指出工作上的错误，让我羞愧到满脸通红。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('9c2b5e31-1e99-45db-acb4-32fbb4345750', '～の 極[きわ]みだ', NULL, 'N1', '名＋の極みだ', '名＋の極みだ', '表示程度达到了极限，“极其……”“……至极”“没有比……更……”。', '固定用法：「疲労の極み」/极其疲劳，「遺憾の極み」/极为遗憾，「感激の極み」/无比感激，「贅沢の極み」/极其奢侈。', 161, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('f0307aae-e3b8-4242-8ac8-a025fa64be64', '9c2b5e31-1e99-45db-acb4-32fbb4345750', '世界的に有名な俳優と握手できたなんて、感激のきわみだ。', '世界的に有名な俳優と握手できたなんて、感激のきわみだ。', '能够和世界著名的演员握手让我十分激动。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('29ad6c54-0ca8-4bcf-8510-60853762384a', '9c2b5e31-1e99-45db-acb4-32fbb4345750', '残業続きで、疲労の極みに達している。', '残業続きで、疲労の極みに達している。', '持续加班，让我筋疲力尽。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('babf1817-b2fa-454d-ba0a-f46a7a53bd12', '9c2b5e31-1e99-45db-acb4-32fbb4345750', '遠いところをわざわざお越しいただき、感激の極みです。', '遠いところをわざわざお越しいただき、感激の極みです。', '您特意远道而来让我十分感动。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('ee57e1ad-f1ce-4fbb-8848-607c0aa5c7c0', '～のなんの', NULL, 'N1', '動辞書形/ナ形語幹/イ形/名＋のなんの', '動辞書形/ナ形語幹/イ形/名＋のなんの', '列举其中一个有代表性的言论，“又是说……又是说什么的”“说这说那的”。', '多用来列举他人的负面言论。', 162, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('c94389ef-0491-44b3-a93d-78d02db3e622', 'ee57e1ad-f1ce-4fbb-8848-607c0aa5c7c0', '彼は足が痛いのなんのと理由をつけては、サッカーの練習をさぼっている。', '彼は足が痛いのなんのと理由をつけては、サッカーの練習をさぼっている。', '他又是说脚痛又是说什么的，经常不参加训练。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('fece5977-ff12-498f-a4e1-74bd6d0927b7', 'ee57e1ad-f1ce-4fbb-8848-607c0aa5c7c0', 'お腹がすいたのなんのといって騒ぐ。', 'お腹がすいたのなんのといって騒ぐ。', '又是说肚子饿了又是说什么的，一个劲地吵。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('064f5676-2c42-4896-8b5d-a5b5de910333', 'ee57e1ad-f1ce-4fbb-8848-607c0aa5c7c0', '給料が低いのなんのと文句ばかり言っている。', '給料が低いのなんのと文句ばかり言っている。', '又是说工资低又是说什么的，尽是抱怨。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('8c520c8b-613d-4267-a61a-ae9114318549', '（ただ）～のみならず/のみか', NULL, 'N1', '（ただ）～のみならず/のみか', '（ただ）～のみならず/のみか', '表示不限定，不仅前项，后项也是如此。“不仅……”“不只……”。', '「ただ」表示强调，后面多与「も」连用。\n前项和后项是互为对照，并列或类似的内容。\n「のみか」也可以表示“不仅……（而且）”的意思。用法与「～だけでなく～も/まで/さえ」相同。', 163, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('b73c3781-6e6c-48bd-992d-ae1c4b833f86', '8c520c8b-613d-4267-a61a-ae9114318549', 'チンパンジーは人間の模倣をするのみならず、互いに協力して共同作業をしているらしいという報告もある。', 'チンパンジーは人間のもほうをするのみならず、互いに協力して共同作業をしているらしいという報告もある。', '据报告讲，黑猩猩不仅能够模仿人类的动作，而且还能够相互配合完成某项活动。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('71b8bdd0-1c8e-45be-a313-e6f8b7ed0570', '8c520c8b-613d-4267-a61a-ae9114318549', 'この映画の主人公はただ勇敢であるのみならず、優しい心の持ち主でもある。', 'この映画の主人公はただ勇敢であるのみならず、優しい心のもちぬしでもある。', '这部电影的主人公不仅勇敢还很善良。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('39d3ccee-a5bf-4de0-b6df-5e3208bba149', '8c520c8b-613d-4267-a61a-ae9114318549', '大災害により財産のみか肉親までも失った。', 'にくしんまでも失った。', '这次的大灾难使我不仅失去了财产还失去了亲人。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('005c7fdb-c333-4f41-abd7-a83a1a0b5610', '～はおろか', NULL, 'N1', '動普通形＋の/名＋はおろか', '動普通形＋の/名＋はおろか', '表示附加关系，“别说……，就连……（都不会）”“不用说……，就连……（都不会）”。', '常用「Aはおろか、Bも～ない」的形式，后面多用否定的表达方式，常与「～も/さえ/すら」等呼应使用。A是程度较高的内容，意思是“别说程度较高的A了，就连程度较低的B都没有达到”。', 164, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('46b7cad0-99c8-4d2c-b7c1-f280a143a48a', '005c7fdb-c333-4f41-abd7-a83a1a0b5610', '腰を痛めてしまい、歩くことはおろか立つことも難しい。', '腰を痛めてしまい、歩くことはおろか立つことも難しい。', '伤到腰了，别说是走路了就算站立也觉得困难。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('1c3b2c61-1936-421b-b7ab-a3aa327371fd', '005c7fdb-c333-4f41-abd7-a83a1a0b5610', '腰に痛みがあると、運動はおろか日常生活でもいろいろ不便なことが多い。', '腰に痛みがあると、運動はおろか日常生活でもいろいろ不便なことが多い。', '腰部有疼痛的话，别说是运动了，即使是日常生活也存在诸多不便。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('d283b65a-b064-4058-b30d-5cb25b6d42a0', '005c7fdb-c333-4f41-abd7-a83a1a0b5610', '父も母も海外旅行はおろか国内さえもほとんど見て回ったことがない。', '父も母も海外旅行はおろか国内さえもほとんど見て回ったことがない。', '父母亲别说是国外旅行了，就连国内的地方也没怎么去过。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('047d0fd4-43ea-4884-bb39-c078eb21495c', '～ばこそ', NULL, 'N1', '～ばこそ', '～ばこそ', '强调原因，正因为前项才有了后项的结果或者正因为前项才做了后项的事情。“正因为……才……”。', '意思与「～からこそ」相同。', 165, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('636f9ee8-b436-4edb-ad0a-803beca9916d', '047d0fd4-43ea-4884-bb39-c078eb21495c', '将棋は好きなら上達する。将棋が好きだということ自体がすでに才能なのであって、好きだという気持ちがあればこそ強くなれるのだ。', 'しょうぎは好きなら上達する。将棋が好きだということ自体がすでにさいのうなのであって、好きだという気持ちがあればこそ強くなれるのだ。', '日本象棋你喜欢的话就会进步。喜欢日本象棋本身就是一种才能。正因为喜欢，棋艺才会越来越强。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('2ac4ff13-3b81-4c26-a0c2-26cc67d2e9c2', '047d0fd4-43ea-4884-bb39-c078eb21495c', '彼女の働きがあればこそ、計画が順調に進んでいるのだ。', '彼女の働きがあればこそ、計画が順調に進んでいるのだ。', '正是因为有了她的努力，计划才会如此顺利。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('c216c06d-f6bc-46dd-b2ed-0873d2c61e76', '047d0fd4-43ea-4884-bb39-c078eb21495c', '子どものためと思えばこそ、留学の費用は子ども自身に用意させたのです。', '子どものためと思えばこそ、留学の費用は子ども自身に用意させたのです。', '正是为孩子着想，才让他自己负担留学的费用。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('d94644d5-c5e1-41a2-beb4-509779d5fd41', '～はさておき/はさておいて', NULL, 'N1', '名＋はさておき/はさておいて', '名＋はさておき/はさておいて', '表示其他的事情暂时先放一放，先处理最重要的问题。“其他的事情暂且不论，首先……”。', '惯用表达「何はさておき/何はさておいて」/其他事情暂且不论。', 166, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('ba518162-3a9b-44ff-baea-2923af2f98db', 'd94644d5-c5e1-41a2-beb4-509779d5fd41', '実現できるかどうかはさておき、まずは新商品のアイディアをみんなで出してみよう。', '実現できるかどうかはさておき、まずは新商品のアイディアをみんなで出してみよう。', '至于能否实现另当别论，大家先想想新产品的创意。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('bfef4d0f-9272-4690-9d1e-00ea1c459dcd', 'd94644d5-c5e1-41a2-beb4-509779d5fd41', '今日の会議は新しい企画のことはさておいて、まず先月の仕事のまとめから入りましょう。', '今日の会議は新しい企画のことはさておいて、まず先月の仕事のまとめから入りましょう。', '今天的会议暂且不谈新的企划方案，先从上个月的工作总结开始吧。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('85cee0cb-cb0a-4074-98c1-defe4e63e568', 'd94644d5-c5e1-41a2-beb4-509779d5fd41', '社員旅行の件ですが、費用のことはさておいて、まず日程について検討してみましょう。', '社員旅行の件ですが、費用のことはさておいて、まず日程について検討してみましょう。', '关于员工旅行一事，费用方面暂且不论，首先讨论一下日程的问题吧。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('ccf99f06-9fa3-47dc-b0df-ec6a1bcc20c7', '～ 弾[はず]み', NULL, 'N1', '～ 弾[はず]み', '～ 弾[はず]み', '“在……的时候”“刚一……就……”。', '该句型多用于句中，可以用「～弾みに/弾みで」的形式。\n多表示由于惯性或者某动作的余势，后项发生了意想不到的事情。', 167, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('94ecfd01-bafb-4307-b82e-798363e7dbfe', 'ccf99f06-9fa3-47dc-b0df-ec6a1bcc20c7', '転んだ弾みに、テーブルに頭をぶつけてしまった。', '転んだ弾みに、テーブルに頭をぶつけてしまった。', '在摔倒时不小心头撞上了桌子。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('0c38a550-1714-4324-ae9d-6424a9ae4e97', 'ccf99f06-9fa3-47dc-b0df-ec6a1bcc20c7', '森田選手は飛び上がって頭でボールをゴールへ叩き込もうとした弾みに、ほかの選手とぶつかった。', '森田選手は飛び上がって頭でボールをゴールへ叩き込もうとした弾みに、ほかの選手とぶつかった。', '森田选手跳起来头球射门的时候和其他选手撞在一起了。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('7bfe5081-e9bb-48db-a166-af4cce6b9dd9', 'ccf99f06-9fa3-47dc-b0df-ec6a1bcc20c7', 'バスの急ブレーキの弾みで、立っていた乗客が転倒するなどして軽いけがを負った。', 'バスの急ブレーキの弾みで、立っていた乗客がてんとうするなどして軽いけがを負った。', '公交车急刹车使得站着的乘客摔倒受了轻伤。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('3974bfeb-b45c-400b-875b-dc95821bb674', '～はそっちのけで/をそっちのけで', NULL, 'N1', '名＋はそっちのけで/をそっちのけで', '名＋はそっちのけで/をそっちのけで', '表示把本应该做的事情放在一边，而去做其他事情。“抛开……不管”“不顾……”。', '「～はそっちのけで」中的「は」表示强调。', 168, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('c2c5a974-3efb-4394-a4a6-bc18b5644b20', '3974bfeb-b45c-400b-875b-dc95821bb674', '大学4年生の弟は就職のことはそっちのけで、毎日パソコンゲームに熱中している。', '大学4年生の弟は就職のことはそっちのけで、毎日パソコンゲームにねっちゅうしている。', '大四的弟弟不去找工作，整天在家玩电脑游戏。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('9c4b670f-cbe3-45a7-b7d3-bc9c0b68214b', '3974bfeb-b45c-400b-875b-dc95821bb674', '彼女は本業をそっちのけで、副業に精を出している。', '彼女は本業をそっちのけで、副業に精を出している。', '她把本职工作抛在一边，一心扑在副业上。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('be8618a9-15f8-4562-aa6b-c434bca4ccc8', '3974bfeb-b45c-400b-875b-dc95821bb674', '生徒たちは教師の注意をそっちのけでおしゃべりに夢中だ。', '生徒たちは教師の注意をそっちのけでおしゃべりに夢中だ。', '学生们把老师讲的话当耳边风，一个劲儿地闲聊。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('fb91aa4c-023f-449e-9d15-67a53a7695c9', '～ばそれまでだ', NULL, 'N1', '動ば形＋それまでだ', '動ば形＋それまでだ', '表示假定条件，“……的话，也就完了”“……的话，也就没有意义了”。', '也可以用「～たらそれまでだ」的形式，意思与「～ならそれまでだ」相同。', 169, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('6e059e2d-bcca-4f2a-9f6f-2c7fa72c66e0', 'fb91aa4c-023f-449e-9d15-67a53a7695c9', 'どんなに美しい花でも、散ってしまえばそれまでだ。', 'どんなに美しい花でも、散ってしまえばそれまでだ。', '再美丽的花凋零了也就不再美丽了。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('57e26407-1bcd-487a-b040-0373e167698a', 'fb91aa4c-023f-449e-9d15-67a53a7695c9', 'この精密機械は水に弱い。水がかかればそれまでだ。', 'このせいみつきかいは水に弱い。水がかかればそれまでだ。', '这种精密仪器很怕水，一旦沾水了就报废了。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('ffc73009-78eb-41a5-8c3a-e80f4c5e839f', 'fb91aa4c-023f-449e-9d15-67a53a7695c9', '勉強よりまず命のことを考えるべきだ。試験に合格しても、病気になってしまったらそれまでだ。', '勉強よりまず命のことを考えるべきだ。試験に合格しても、病気になってしまったらそれまでだ。', '比起学习，身体健康更重要。如果把身体拖垮了，即使通过了考试也没有多大意义。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('4252c6cb-6abf-44ec-8d41-c3f03eec08d6', '～ 羽[は] 目[め]になる/羽目に 陥[おちい]る', NULL, 'N1', '～ 羽[は] 目[め]になる/羽目に 陥[おちい]る', '～ 羽[は] 目[め]になる/羽目に 陥[おちい]る', '表示因为某种原因，使某人或者某事陷入了困境之中。“落到……地步”“陷入……境地”。', '「～羽目に陥る」「～羽目になる」在句子中多用过去时，用于描述已经发生的事情。', 170, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('945872fa-ca14-4d56-8bb6-e0fa4224dfe2', '4252c6cb-6abf-44ec-8d41-c3f03eec08d6', 'うっかりしてデータを消してしまったので、もう一度入力するはめになった。', 'うっかりしてデータを消してしまったので、もう一度にゅうりょくするはめになった。', '一不小心把数据弄丢了，只能重新输入。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('ac47c4c1-df88-4a43-8d4b-837aa5410c26', '4252c6cb-6abf-44ec-8d41-c3f03eec08d6', '就職活動に失敗して苦しい羽目に陥った。', '就職活動に失敗して苦しい羽目に陥った。', '找不到工作情况十分糟糕。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('a1284b9e-5914-4e1d-a9ad-6ea7913b6c84', '4252c6cb-6abf-44ec-8d41-c3f03eec08d6', '途中でガソリンが切れたので、バイクを引きずって家に帰る羽目になった。', '途中でガソリンが切れたので、バイクを引きずって家に帰る羽目になった。', '半路上没油了，只能推着摩托车回家。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('d0c81b30-0fdb-4ed9-b103-ba79ba7b2c21', '～べからず', NULL, 'N1', '動辞書形＋べからず', '動辞書形＋べからず\n（する→すべからず/するべからず）', '表示禁止，“禁止……”“不要……”。', '多用于布告、招牌、告示牌、标语等。', 171, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('14608716-14fd-40e0-869c-ad88c768a348', 'd0c81b30-0fdb-4ed9-b103-ba79ba7b2c21', '『危険！工事中につき、立ち入るべからず。』', '『危険！工事中につき、立ち入るべからず。』', '危险！施工中请勿进入。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('7b6d7770-9aa3-4816-9293-f905f2f9a0ea', 'd0c81b30-0fdb-4ed9-b103-ba79ba7b2c21', 'お寺の入り口に「ここより中には入るべからず」と書かれていたので、見学はあきらめるしかなかった。', 'お寺の入り口に「ここより中には入るべからず」と書かれていたので、見学はあきらめるしかなかった。', '寺院门口贴着“禁止入内”，所以只能放弃参观。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('7ba92de7-69fd-47cd-9429-ec1f4c10b67f', 'd0c81b30-0fdb-4ed9-b103-ba79ba7b2c21', '初心忘れるべからず。', 'しょしんわすれるべからず。', '勿忘初衷。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('6052d853-62f9-468b-bc65-af6b430566ad', '～べからざる', NULL, 'N1', '動辞書形＋べからざる＋名', '動辞書形＋べからざる＋名\n（する→すべからざる/するべからざる）', '表示禁止，“不应该做的……”。', '「～べからざる」不能用在句末，只能作为定语修饰名词，是古典日语中文言体的表达方式。', 172, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('36acd125-0b7e-4f36-b17a-5c22970cc880', '6052d853-62f9-468b-bc65-af6b430566ad', '企業から多額のお金を受け取るなんて、政治家として許すべからざる行為だ。', '企業から多額のお金を受け取るなんて、政治家として許すべからざる行為だ。', '作为一名政治家，接受企业的巨额贿赂是不能被允许的行为。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('e266f21b-295d-4712-86d3-4da02d43babd', '6052d853-62f9-468b-bc65-af6b430566ad', '彼はうちの会社にとって欠くべからざる人材だ。', '彼はうちの会社にとって欠くべからざる人材だ。', '他是我们公司不可缺少的人才。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('bdf9163e-b436-4742-8970-c94481bcf572', '6052d853-62f9-468b-bc65-af6b430566ad', '学生としては勉強に励むべし。', '学生としては勉強に励むべし。', '学生必须专心学习。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('1e3c1cba-5068-4ddd-8466-c12b97864c91', '～べく', NULL, 'N1', '動辞書形＋べく', '動辞書形＋べく\n（する→すべく/するべく）', '表示目的，“为了……”“想要……”。', '「～べく」只能用在句中，表示目的。意思与「～ために」相同。\n后项用表示某个具体动作的动词，如「行く」「引越す」「行う」「訪ねる」等。不用描述状态的动词，如「増える」「減る」等。', 173, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('3b783d7c-5b52-4a16-9545-127377afe272', '1e3c1cba-5068-4ddd-8466-c12b97864c91', 'ウイルスの感染経路を明らかにすべく、調査が行われた。', 'ウイルスの感染けいろを明らかにすべく、調査が行われた。', '为了弄清楚病毒的感染途径进行了调查。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('f2dd1741-bf5d-4f67-bf6b-22631c6928ea', '1e3c1cba-5068-4ddd-8466-c12b97864c91', '兄は締め切りに間に合わせるべく、昼も夜も論文に取り組んでいる。', '兄は締め切りに間に合わせるべく、昼も夜も論文に取り組んでいる。', '为了赶上截止日期，哥哥不分昼夜地写着论文。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('798233e8-1228-4be2-9acf-833cd938854d', '1e3c1cba-5068-4ddd-8466-c12b97864c91', '彼を見舞うべく病院を訪ねた。', '彼を見舞うべく病院を訪ねた。', '为了探望他到医院去了。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('59c8f889-7c3e-474c-8a5d-6e18ae9384be', '～べくして', NULL, 'N1', '動辞書形＋べくして', '動辞書形＋べくして', '表示一种必然性，“该（发生）的就（发生）了”“……的出现是必然的”。', '固定用法：「動辞書形＋べくして＋動た形」，前后使用同一个动词，表示某事的发生、出现是必然的。', 174, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('4e5c50f4-3b1c-42fa-9b1a-ae0cdd859b4a', '59c8f889-7c3e-474c-8a5d-6e18ae9384be', 'この機械の危険性は以前から何度も指摘されていた。この事故は起こるべくして起こったといえる。', 'この機械の危険性は以前から何度も指摘されていた。この事故は起こるべくして起こったといえる。', '这次机器的危险性以前就被指出来过，所以这次事故的发生可以说是必然的。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('f6e9861f-5fd3-4db4-8a6e-408daae4d7dc', '59c8f889-7c3e-474c-8a5d-6e18ae9384be', '彼は練習に練習を重ねてきて、勝つべくして勝ったのだ。', '彼は練習に練習を重ねてきて、勝つべくして勝ったのだ。', '他的获胜不是偶然的，是通过不断的练习才取得的。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('eb71a528-4c57-49c2-8828-2b9f64190b14', '～べくもない', NULL, 'N1', '動辞書形＋べくもない', '動辞書形＋べくもない\n（する→すべくもない/するべくもない）', '表示否定，“做不到……”“不可能……”。', '是比较生硬的文言体的表达方式。\n常和「望むべくもない」一起使用。“无法指望……”“不指望……”。', 175, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('4e0773ea-53bf-401e-9da3-cc2b86749942', 'eb71a528-4c57-49c2-8828-2b9f64190b14', '主力が抜けているので、優勝は望むべくもない。', '主力が抜けているので、優勝は望むべくもない。', '主力队员没有上场，夺冠没有指望。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('cb89aace-d952-416b-9899-fb9d3fa0a6d8', 'eb71a528-4c57-49c2-8828-2b9f64190b14', '多勢に無勢では勝つべくもない。', 'たぜいにぶぜいでは勝つべくもない。', '寡不敌众。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('c08b2053-1567-45fb-9cfb-0ab989bd00f7', '～まじき', NULL, 'N1', '動辞書形＋まじき', '動辞書形＋まじき', '表示出于某种身份，不应该做某事，“作为……不应该有的行为”。', '常用「～としてあるまじきこと」「～としてやるまじきこと」等固定搭配。意思是“作为……不应该有的行为”“作为……不应该做的事”。\n要注意「～まじき」的接续方式，常用「動辞書形＋まじき＋名」的形式，表示“不应该做的事情”，意思与「動辞書形＋べき＋名」相反。', 176, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('5775de85-b200-4d85-aa80-a5e37f2ece60', 'c08b2053-1567-45fb-9cfb-0ab989bd00f7', '彼の言動は社会人としてあるまじきもので、とうてい許すことはできない。', '彼の言動は社会人としてあるまじきもので、とうてい許すことはできない。', '他的言行举止是作为一个成年人不该有的，不能允许。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('bed53aa6-9dae-4678-aa52-05a319903525', 'c08b2053-1567-45fb-9cfb-0ab989bd00f7', '彼のやったことは、人としてあるまじき残酷な行為だ。', '彼のやったことは、人としてあるまじき残酷な行為だ。', '他所做的事情极为残忍，简直不是一个正常人能够做得出来的。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('aeb4e8a4-de0f-432b-a602-7ef1e57c7920', 'c08b2053-1567-45fb-9cfb-0ab989bd00f7', '患者のプライバシーをほかの人に漏らすなんて、医者としてあるまじきことだ。', '患者のプライバシーをほかの人に漏らすなんて、医者としてあるまじきことだ。', '作为一名医生，泄露患者的隐私是不能允许的行为。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('e8d3d4a2-34d4-4436-b462-fbc6afdcd774', '～までして', NULL, 'N1', '名＋までして', '名＋までして', '表示一些极端的行为，“甚至到了……的地步”“不惜……”。', '既可以批判“为达目的不择手段”的行为，也可以表示“以极大的牺牲为代价从而达到某个目的”。\n意思与「動て形＋まで」相同。', 177, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('4e43ba51-f0af-4106-a402-e3e88581d23d', 'e8d3d4a2-34d4-4436-b462-fbc6afdcd774', 'この絵は、昔父が借金までして手に入れたものです。', 'この絵は、昔父が借金までして手に入れたものです。', '这幅画是父亲曾经不惜借钱购得的。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('2a3ebeae-2331-48ab-9dae-caed880d221b', 'e8d3d4a2-34d4-4436-b462-fbc6afdcd774', '徹夜までしてがんばったのに、テストでいい点が取れなかった。', '徹夜までしてがんばったのに、テストでいい点が取れなかった。', '虽然通宵学习，但是在考试中也没能取得好成绩。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('7b79e0e8-642a-43c3-b81c-08fc5f4835c5', 'e8d3d4a2-34d4-4436-b462-fbc6afdcd774', '自然破壊までして、地域の経済を発展させる必要はない。', '自然破壊までして、地域の経済を発展させる必要はない。', '没有必要为了发展经济而去破坏自然环境。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('0ba7995c-9826-4109-b7fb-61c1840cd8fa', '～までだ/までのことだ', NULL, 'N1', '動辞書形·た形＋までだ/までのことだ', '動辞書形·た形＋までだ/までのことだ\n動辞書形＋までだ/までのことだ', '表示程度轻，“只不过……罢了”“只是……而已”。\n表示别无选择，“只好……”“只有……”。', '用于解释某个行为的目的。\n意思与「ただ～だけだ」相同。\n表示没有其他选择只能够那样做；或者没有办法，只好下决心做某事。\n意思与「～しかない」相同。', 178, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('1c6a1d3d-1ba4-4c99-be58-bf5748f3f418', '0ba7995c-9826-4109-b7fb-61c1840cd8fa', '私は率直な感想を述べたまでです。特定の人を批判する意図はありません。', '私はそっちょくな感想を述べたまでです。特定の人を批判するいとはありません。', '我只是说出了自己最真实的想法，并不是特别针对某人。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('225052b7-0134-403b-8e27-8a679ec89700', '0ba7995c-9826-4109-b7fb-61c1840cd8fa', '就職が決まらなくても困らない。アルバイトをして生活するまでだ。', '就職が決まらなくても困らない。アルバイトをして生活するまでだ。', '找不到工作也没关系，那样的话只不过要靠打工来维持生计而已。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('066d7d8e-c288-4778-b260-246b85cdf383', '0ba7995c-9826-4109-b7fb-61c1840cd8fa', '念のため、確認するまでのことだ。', '念のため、確認するまでのことだ。', '只是为了慎重起见确认一下罢了。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('e2318ec9-b1e2-45a2-865c-46e1457aa1bf', '0ba7995c-9826-4109-b7fb-61c1840cd8fa', '彼らにはあまり関係ないかもしれないが、一応知らせたまでだ。', '彼らにはあまり関係ないかもしれないが、一応知らせたまでだ。', '跟他们可能关系不大，只是通知一下罢了。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('502275c1-3898-46f2-bbdc-682946a95a2e', '0ba7995c-9826-4109-b7fb-61c1840cd8fa', '試験は終わった。あとはただ結果を待つまでだ。', '試験は終わった。あとはただ結果を待つまでだ。', '考试已经结束了，接下来就是等待出结果了。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('8a73cc74-b8fd-4d4a-938c-7c715ac1a888', '0ba7995c-9826-4109-b7fb-61c1840cd8fa', '留守なら仕方がない。また今度来るまでのことだ。', '留守なら仕方がない。また今度来るまでのことだ。', '既然不在家的话就没有办法了，只好下次再来。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('c9d0ccd6-8d63-4dc6-88ba-e400878a4f58', '0ba7995c-9826-4109-b7fb-61c1840cd8fa', '終電に乗り遅れたので、歩いて帰るまでのことだ。', '終電に乗り遅れたので、歩いて帰るまでのことだ。', '错过了末班车，只能走着回去。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('73609993-0a65-4d5d-9cca-7c9e6f87036f', '～までもなく/までもない', NULL, 'N1', '動辞書形＋までもなく/までもない', '動辞書形＋までもなく/までもない', '“没有必要……”“用不着……”。', '「～までもなく」用在句中，后接动词、形容词、副词。「～までもない」用于句末。\n意思与「～ことはない」相同。', 179, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('eb92fb9b-a9ee-43d8-8485-a16a42828b43', '73609993-0a65-4d5d-9cca-7c9e6f87036f', 'そんな遠い店まで買いに行くまでもないよ。電話で注文すればすぐ届くんだから。', 'そんな遠い店まで買いに行くまでもないよ。電話で注文すればすぐ届くんだから。', '没必要特意大老远地跑到店里去买，打个电话订一下就能送上门。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('27f17921-26ac-47a2-a323-960e57ea335d', '73609993-0a65-4d5d-9cca-7c9e6f87036f', 'わざわざ言われるまでもなく、私は自分の責任を認めている。', 'わざわざ言われるまでもなく、私は自分の責任を認めている。', '不用别人特意指出，我也承认自己的责任。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('3ce7a527-956e-4bdb-94a6-6438203da2b1', '73609993-0a65-4d5d-9cca-7c9e6f87036f', '孫が無事生まれたとの知らせに、彼が喜んだのは言うまでもない。', '孫が無事生まれたとの知らせに、彼が喜んだのは言うまでもない。', '知道了孙子平安无事地出生，他的喜悦之情无以言表。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('8e24faaf-a2cd-4f86-a24f-6951bd2a3e03', '73609993-0a65-4d5d-9cca-7c9e6f87036f', '今度の交渉は計画どおりに進んでいるので、社長が乗り出すまでもない。', '今度の交渉は計画どおりに進んでいるので、社長が乗り出すまでもない。', '这次的谈判正按照计划进行，不需要社长亲自出马。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('84c603d6-3999-436a-86e6-095bd6742762', '～まみれ', NULL, 'N1', '名＋まみれ', '名＋まみれ', '表示状态，“全是……”“满是……”“浑身都是……”。', '指物体表面沾满了什么东西的状态，多指脏的或者不好的东西。\n常用「血まみれ」「汗まみれ」「泥まみれ」「油まみれ」「埃まみれ」等。', 180, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('761c3823-d4e4-4cf5-b8fe-cbb31a26a159', '84c603d6-3999-436a-86e6-095bd6742762', '汗まみれになって働いても、もらえる金はわずかだ。', '汗まみれになって働いても、もらえる金はわずかだ。', '虽然每天忙得满头大汗，但是收入微薄。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('e8b50f2d-b7a9-468d-b014-81de740e3111', '84c603d6-3999-436a-86e6-095bd6742762', '小さい頃、よく泥まみれになって弟とけんかをしたものだ。', '小さい頃、よく泥まみれになって弟とけんかをしたものだ。', '小时候经常满身是泥地跟弟弟打架。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('4f0189bc-8231-4288-946e-19719354e8cd', '84c603d6-3999-436a-86e6-095bd6742762', '押し入れの中から埃まみれの昔のアルバムが見つかった。', '押し入れの中からほこりまみれの昔のアルバムが見つかった。', '从壁橱里找出了满是灰尘的过去的相册。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('c2eb3738-ed92-426b-9bdb-1bd64ff455a1', '～めく', NULL, 'N1', '名＋めく', '名＋めく', '表示某种状态和特征，“带有……的气息”“变成……的样子”“有一点……的感觉”。', '用在句中表示中顿时用「～めいて」，作定语修饰名词时「～めいた＋名」。\n常用「春めいてきた」「夏めいた服装」「謎めいた言葉」「皮肉めいた言い方」等固定的表达方式。', 181, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('0cfa7c94-9c69-49ec-a5bd-9eb31329a726', 'c2eb3738-ed92-426b-9bdb-1bd64ff455a1', '雪がとけて、野の花が咲き始め、日差しも春めいてきた。', '雪がとけて、野の花が咲き始め、日差しも春めいてきた。', '冰雪消融，花儿绽放，阳光明媚，春天的脚步近了。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('fee6641f-2c68-487c-8717-6224d335321a', 'c2eb3738-ed92-426b-9bdb-1bd64ff455a1', '彼女は謎めいたことばを残して、その場を去った。', '彼女は謎めいたことばを残して、その場を去った。', '她留下了谜一般的话，离开了那个地方。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('7a389e29-f5c6-47c1-af1b-e4e0d61d39f4', 'c2eb3738-ed92-426b-9bdb-1bd64ff455a1', 'そんな皮肉めいた言い方をしないでください。', 'そんな皮肉めいた言い方をしないでください。', '请不要用这种话里带刺的讲话方式。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('6c32d445-ee5d-47f8-afb1-3526997a01a6', '～も 顧[かえり]みず/を顧みず', NULL, 'N1', '名＋も顧みず/を顧みず', '名＋も顧みず/を顧みず', '表示不顾某种危险性，坚持做某事。“不顾……”“不管……”。', '固定用法：「命を顧みず」/不顾生命危险，「危険を顧みず」/不顾危险，「健康を顧みず」/牺牲了健康。\n多表示积极的意思。', 182, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('862ae712-4c79-4299-a228-f0e7018a8de4', '6c32d445-ee5d-47f8-afb1-3526997a01a6', 'カメラマンは自らの命もかえりみず戦場に向かった。', 'カメラマンは自らの命もかえりみず戦場に向かった。', '摄影师们不顾生命危险奔赴战场。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('17318846-4197-47ee-9182-be9e6b74f883', '6c32d445-ee5d-47f8-afb1-3526997a01a6', '自らの危険を顧みず、仲間を救おうとした。', '自らの危険を顧みず、仲間を救おうとした。', '为了救同伴不顾自己的危险。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('81281c88-b4eb-4511-9b4d-1182e23aeed9', '6c32d445-ee5d-47f8-afb1-3526997a01a6', '家族のことも自分の健康もかえりみず懸命に会社のために働いた。', '家族のことも自分の健康もかえりみず懸命に会社のために働いた。', '为了工作牺牲了自己的家庭甚至身体健康。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('35c1e023-0105-4f60-81e2-6c766190c3f2', '～もさることながら', NULL, 'N1', '名＋もさることながら', '名＋もさることながら', '表示前后两项的关联，相比前项，后项更加……。“……自不必说，……更是如此”“……不用说，尤其是……更加……”。', '常用「AもさることながらB」的形式，意思是“A自不必说，B更加……”。\n后项多与「～大切だ」「～が最も～」「～が一番～」「～が第一」等表达方式连用。', 183, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('67baab78-9120-4baa-942e-c9b94894062c', '35c1e023-0105-4f60-81e2-6c766190c3f2', 'このドラマの人気は、ストーリーもさることながら俳優の演技力によるところが大きいといえる。', 'このドラマの人気は、ストーリーもさることながら俳優のえんぎりょくによるところが大きいといえる。', '这部电视剧很受欢迎，其故事情节自不必说，更主要的原因可以说是在于演员的演技。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('57533782-9c89-40d4-b57c-8f631bd1ec70', '35c1e023-0105-4f60-81e2-6c766190c3f2', 'このパソコンは、価格や性能もさることながら、デザインが良いので人気がある。', 'このパソコンは、価格や性能もさることながら、デザインが良いので人気がある。', '这个电脑不仅价格和性能不错，而且设计也很好，很有人气。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('3e867205-538e-48f2-8b82-1ecacbffec7d', '35c1e023-0105-4f60-81e2-6c766190c3f2', 'ごみを減らすためには、市や町の取り組みもさることながら、個人の心がけもやはり大切だ。', 'ごみを減らすためには、市や町の取り組みもさることながら、個人の心がけもやはり大切だ。', '为了减少垃圾量，市政府和区政府的努力自不必说，个人的努力也是很重要的。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('30fe5731-f52c-49ea-95be-f3e6d2ff3702', '～も 同[どう] 然[ぜん]だ/も同然の', NULL, 'N1', '～も 同[どう] 然[ぜん]だ/も同然の', '～も 同[どう] 然[ぜん]だ/も同然の', '“几乎等同于……”“几乎跟……一样”。', '多用一些固定表达。「～も同然だ」用在句末，「～も同然の」用在句中，后面接续名词。', 184, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('8ebccd73-9d01-4b89-a8ca-6e4fe65de2df', '30fe5731-f52c-49ea-95be-f3e6d2ff3702', 'あとは表紙をつけるだけだから、クラスの文集はもうできたのも同然だ。', 'あとは表紙をつけるだけだから、クラスの文集はもうできたのも同然だ。', '最后只需要装订封面就行了，这本班级作文集等于说是完成了。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('585d7a97-817b-451c-a4f5-c49b6a35b65f', '30fe5731-f52c-49ea-95be-f3e6d2ff3702', '彼とは家族も同然の付き合いをしている。', '彼とは家族も同然の付き合いをしている。', '跟他的交情就像家人一样。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('6f7d4378-6565-4761-b790-2a51a4ca357b', '30fe5731-f52c-49ea-95be-f3e6d2ff3702', 'ただも同然の値段で古い本を売り出した。', 'ただも同然の値段で古い本を売り出した。', '用等于白送的价格卖了旧书。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('7c524d3c-8fcc-48ae-80e1-70d7bc84dc42', '～ものと 思[おも]われる', NULL, 'N1', '動/イ形/ナ形の名詞修飾形＋ものと思われる', '動/イ形/ナ形の名詞修飾形＋ものと思われる', '表示大多数人的看法，“在大家看来……”“人们一般认为……”。', '一般用在比较严肃的会话或文章中。', 185, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('99221bec-e146-459f-bc7c-d934d569e229', '7c524d3c-8fcc-48ae-80e1-70d7bc84dc42', '今回の調査で事故の原因が明らかになるものと思われる。', '今回の調査で事故の原因が明らかになるものと思われる。', '人们认为经过调查事故的真相会浮出水面。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('28b8b280-be34-47d7-9f3a-e9009c6ad23b', '7c524d3c-8fcc-48ae-80e1-70d7bc84dc42', 'この状況では、あまりいい結果は期待できないものと思われる。', 'この状況では、あまりいい結果は期待できないものと思われる。', '从这个状况来看结果不会太理想。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('af070864-1310-44e8-ba4f-2cd0772b0f89', '7c524d3c-8fcc-48ae-80e1-70d7bc84dc42', '犯人は海外へ逃亡したものと思われる。', '犯人は海外へとうぼうしたものと思われる。', '人们认为犯人是逃往了国外。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('6487ea5f-b499-4380-9140-84c59a599189', '～ものを', NULL, 'N1', '動/イ形/ナ形の名詞修飾形＋ものを', '動/イ形/ナ形の名詞修飾形＋ものを', '表示对已经发生的事情的一种假设，“要是……就好了”“早知道……就好了”。', '表示对已经发生的事情的一种不满、后悔、遗憾的情绪。\n可以直接用在句末，省略后文的情况很多。\n固定表达「～ばいいものを」「～たらいいものを」“要是……的话就好了”。', 186, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('c28895eb-7e9f-4677-994a-75d734400fb7', '6487ea5f-b499-4380-9140-84c59a599189', '検査を受けていればすぐに治ったものを、痛みを我慢して検査に行かなかったことが悔やまれる。', '検査を受けていればすぐに治ったものを、痛みを我慢して検査に行かなかったことがくやまれる。', '早一点去检查的话很快就能好的。真后悔当初为什么要忍痛不去检查。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('267f175e-4ca5-4e98-89ac-a9e5c19436b9', '6487ea5f-b499-4380-9140-84c59a599189', 'だれかに相談すれば簡単に解決できたものを、どうして一人で悩んでいたのだろう。', 'だれかに相談すれば簡単に解決できたものを、どうして一人で悩んでいたのだろう。', '跟大家商量一下的话很快就能解决的问题，为什么要一个人在那里烦恼呢？', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('47df59e2-6748-42e4-9f46-e8c27e8d5f64', '6487ea5f-b499-4380-9140-84c59a599189', '電話をしてくれれば、迎えに行ったものを。', '電話をしてくれれば、迎えに行ったものを。', '要是打个电话给我的话，就去接你了。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('27e94d29-1a58-417e-906d-fed77d2ede9f', '～や/や否や', NULL, 'N1', '動辞書形＋や/や否や', '動辞書形＋や/や否や', '表示前项的动作结束后，后项的动作紧接着发生，或者马上发生什么事情。“刚刚……立刻……”“几乎与此同时……”。', '类似的表达有「～が早いか」「～なり」「～たとたんに」等。\n句子的时态多用过去时，描述已经结束的事情。', 187, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('200b6b6c-405c-4629-ad3f-0f95ed56750c', '27e94d29-1a58-417e-906d-fed77d2ede9f', '電車が駅に止まり、ドアが開くやいなや彼は飛び出していった。', '電車が駅に止まり、ドアが開くやいなや彼は飛び出していった。', '电车进站后门刚开，他就冲了出去。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('66d3a305-4980-4311-896c-aef4a9705fca', '27e94d29-1a58-417e-906d-fed77d2ede9f', 'いたずらをしていた生徒たちは、教師が来たと見るやいっせいに逃げ出した。', 'いたずらをしていた生徒たちは、教師が来たと見るやいっせいに逃げ出した。', '调皮玩耍的孩子们一看见老师来了就一溜烟地跑开了。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('9e540104-da01-4bd0-8a7b-4df2050ff31c', '27e94d29-1a58-417e-906d-fed77d2ede9f', '娘は家へ帰るや否やおなかが減ったと言って、冷蔵庫をのぞき込んだ。', '娘は家へ帰るや否やおなかが減ったと言って、冷蔵庫をのぞき込んだ。', '女儿一回家就说肚子饿了，打开冰箱看了一下。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('8894e007-108c-4371-83d6-11fd092f7c52', '～ 矢[や] 先[さき]に', NULL, 'N1', '～ 矢[や] 先[さき]に', '～ 矢[や] 先[さき]に', '“正要……的时候”“正当……的时候”。', '该句型表示前后项间隔的时间较短，正要做某事刚完成某事的时候就发生了后项。\n后项多为意外的情况发生。', 188, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('49186113-7b9a-48a3-92b9-f7891530a18a', '8894e007-108c-4371-83d6-11fd092f7c52', '高橋選手は400メートル走でゴールに着く矢先に転んでしまい、惜しくも金メダルを逃がした。', '高橋選手は400メートル走でゴールに着く矢先に転んでしまい、惜しくも金メダルを逃がした。', '高桥选手在跑400米快到终点的时候摔倒了，很遗憾地错失了金牌。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('5d6ab725-665d-4c82-add1-071e79d02e2b', '8894e007-108c-4371-83d6-11fd092f7c52', 'やっとマイホームを手に入れ、これからは幸せな生活が続くと信じた矢先に、夫が病気で倒れた。', 'やっとマイホームを手に入れ、これからは幸せな生活が続くと信じた矢先に、夫が病気で倒れた。', '好不容易有了自己的房子，想着今后可以过幸福生活的时候，丈夫却病倒了。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('b3d332a3-0e3d-4016-bc90-74f4658aceba', '8894e007-108c-4371-83d6-11fd092f7c52', '机を片付けて帰ろうとした矢先に、課長に会議室へ呼ばれた。', '机を片付けて帰ろうとした矢先に、課長に会議室へ呼ばれた。', '正收拾好桌子准备回去的时候，被课长叫到会议室去了。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('938a5678-15ce-49af-9252-89dc97473b40', '～やしない/はしない', NULL, 'N1', '動ます形/名＋やしない/はしない', '動ます形/名＋やしない/はしない', '“不是……”“不会……”。', '该句型用于强调否定的语气。\n多用于口语。', 189, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('f051e913-54c2-4af7-8cf9-b10e8b87689d', '938a5678-15ce-49af-9252-89dc97473b40', 'いかなる理論でも、データによって実証されなければ多くの人に受け入れられはしない。', 'いかなる理論でも、データによって実証されなければ多くの人に受け入れられはしない。', '无论什么理论，如果得不到数据佐证的话也不会被很多人接受吧。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('41df8138-053d-4dfb-8bdc-8bc46c59cbee', '938a5678-15ce-49af-9252-89dc97473b40', 'どんなに苦しくても、自分が選んだ道だから後悔はしない。', 'どんなに苦しくても、自分が選んだ道だから後悔はしない。', '再怎么辛苦，这是我自己选择的路，所以我不会后悔。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('065be483-1972-4ea2-abe3-7dc55229543e', '938a5678-15ce-49af-9252-89dc97473b40', '彼女は芯の強い人で、試合に負けても皆の前で涙を見せやしなかった。', '彼女は芯の強い人で、試合に負けても皆の前で涙を見せやしなかった。', '她是一个很坚强的人，即使比赛输了也没有在大家面前流过泪。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('cf5be085-9025-440b-9292-7e6dafa34473', 'やれ～やれ～', NULL, 'N1', 'やれ＋名、やれ＋名', 'やれ＋名、やれ＋名', '表示列举，“什么……啦，什么……啦”。', '用于列举两个具有代表性的事物，后面进行综合性的描述。\n多表示消极的意思。', 190, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('eb3f2aee-298e-41d8-92fd-7c88015bf43c', 'cf5be085-9025-440b-9292-7e6dafa34473', '彼女は最近やれ剣道だ、やれ茶道だとお忙しそうだ。', '彼女は最近やれ剣道だ、やれ茶道だとお忙しそうだ。', '她最近又是学剑道又是学茶道好像很忙。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('2235e9d4-d374-486c-9704-1189c0ff3566', 'cf5be085-9025-440b-9292-7e6dafa34473', '日本で部屋を借りる場合、やれ敷金だやれ礼金だと、いろいろお金がかかる。', 'しききんだやれ礼金だと、いろいろお金がかかる。', '在日本租房子又是押金又是礼金的，很多地方都需要花钱。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('385c2c25-4a49-4429-8c0e-8f810a0d793f', 'cf5be085-9025-440b-9292-7e6dafa34473', '今月はやれ子どもの日だやれ娘の誕生日だと、お祝いが重なる。', '今月はやれ子どもの日だやれ娘の誕生日だと、お祝いが重なる。', '这个月又是儿童节又是女儿的生日，都是要庆祝的日子。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('b9e791a7-8c9c-40ed-bedb-05c3c08422ae', '～（が）ゆえ（に）/ゆえの', NULL, 'N1', '～（が）ゆえ（に）/ゆえの', '～（が）ゆえ（に）/ゆえの', '表示原因、理由，“由于……”“因为……”。', '「～ゆえ（に）」后接动词、形容词、副词，「～ゆえの」后接名词，「～ゆえに」也作为接续词单独使用。\n「～ゆえに」「～ゆえの」是古典日语中文言体的表达方式。', 191, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('300d50c9-5904-43b6-8b4b-33754927c59a', 'b9e791a7-8c9c-40ed-bedb-05c3c08422ae', '全国の名産品を電話一本で自宅まで届けてくれるサービスが、その手軽さゆえに人気を集めている。', '全国の名産品を電話一本で自宅まで届けてくれるサービスが、そのてがるさゆえに人気を集めている。', '只要打个电话就可以将全国各地的特产送上家门，这种服务十分便利很受欢迎。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('7bec55fe-c1f0-46df-8615-00d4eccdae08', 'b9e791a7-8c9c-40ed-bedb-05c3c08422ae', '彼女は若いときに両親を亡くし、20代で父親の工場を継いで、倒産の危機を経験した。それゆえに、工場経営の厳しさを知り尽くしている。', '彼女は若いときに両親を亡くし、20代で父親の工場を継いで、倒産の危機を経験した。それゆえに、工場経営の厳しさを知り尽くしている。', '她很小的时候父母双亡，20岁左右开始继承父亲的工厂，经过了工厂倒闭的危机。正因为这样，她自己深深知道工厂经营的艰难。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('0d274acd-3f7d-4680-b41a-0870bd4fd5a2', 'b9e791a7-8c9c-40ed-bedb-05c3c08422ae', '部下を評価する立場になると、優しすぎるがゆえに、思い悩む人も少なくない。', '部下を評価する立場になると、優しすぎるがゆえに、思い悩む人も少なくない。', '要对下属进行评估的时候，有很多人因为自己的标准太宽松了而感到烦恼。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('784fd7c0-ee4c-4ebd-8b0d-f1cbcb7af79b', '～ようによっては', NULL, 'N1', '動ます形＋ようによっては', '動ます形＋ようによっては', '表示前后两项的关联，前项的方式、方法、观点不同，后项的结果也不一样。“要看怎么……”“取决于……（的方法）”“根据……的方式”。', '常用「考えようによっては」「やりようによっては」「見ようによっては」等。', 192, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('de2a9930-2d03-4e3e-82a7-396d810c41cd', '784fd7c0-ee4c-4ebd-8b0d-f1cbcb7af79b', '昔から「毒も使いようによっては薬になる」と言われてきた。', '昔から「どくも使いようによっては薬になる」と言われてきた。', '自古以来，人们就常说“使用得当的话，毒药也能入药”。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('4d3b88ba-3b11-4c9c-8816-2b06662b095b', '784fd7c0-ee4c-4ebd-8b0d-f1cbcb7af79b', 'やりようによっては、その仕事はもっと簡単に済ませることができる。', 'やりようによっては、その仕事はもっと簡単に済ませることができる。', '换个方法，这个工作其实可以更简单地完成。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('8f8ac5c8-0c20-4d24-83b4-9f4a3dc88364', '784fd7c0-ee4c-4ebd-8b0d-f1cbcb7af79b', 'この古新聞も、使いようによっては、何かの役に立つのではないかと思いますが。', 'この古新聞も、使いようによっては、何かの役に立つのではないかと思いますが。', '我觉得旧报纸也能发挥作用，这取决于使用的方法。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('2d13ac36-bfa7-485e-89f8-9956158ed371', '～をおいて', NULL, 'N1', '名＋をおいて', '名＋をおいて', '表示限定，“除了……之外，（没有）……”。', '前面常接续人名、地名等。\n后项多用否定的表达。\n固定用法：「何をおいても」/无论什么情况。', 193, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('dc606579-53f2-4c51-9e23-2055ea7faa01', '2d13ac36-bfa7-485e-89f8-9956158ed371', '新しく住宅開発を進めるなら、この地域をおいてほかにはない。', '新しく住宅開発を進めるなら、この地域をおいてほかにはない。', '想要开发新的住宅区的话，除了这个地方没有更好的选择。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('135ff002-0a36-4cb3-83cb-01f796410b62', '2d13ac36-bfa7-485e-89f8-9956158ed371', '彼をおいて、この仕事を任せられる人間はいないだろう。', '彼をおいて、この仕事を任せられる人間はいないだろう。', '除了他之外没有人能够做这份工作。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('02ff0de4-f76b-44fe-9c22-5b3d6f0c5f79', '2d13ac36-bfa7-485e-89f8-9956158ed371', 'わが社の危機を救える人は、あの人をおいてほかにはいるだろうか。', 'わが社の危機を救える人は、あの人をおいてほかにはいるだろうか。', '除他之外没有其他人能够挽救公司的危机。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('79d51591-9a8c-4b73-b7b6-6a753ddf56ab', '～を 押[お]して/を 押[お]し 切[き]って', NULL, 'N1', '名＋を押して/を押し切って', '名＋を押して/を押し切って', '表示克服困难，或者不顾大家的反对坚持做某事。“不顾……的反对”“冒着……”。', '既可表示积极的意思也可表示消极的意思。\n常用「反対を押して」「病気を押して」等固定的表达方式。', 194, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('3b76ae7e-166b-4664-9a41-c9fd3f9b9686', '79d51591-9a8c-4b73-b7b6-6a753ddf56ab', '私の妹は両親の反対をおして結婚した。', '私の妹は両親の反対をおして結婚した。', '妹妹不顾父母的反对结婚了。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('e30a7392-40b9-4ba8-82f3-5a3c2b2b25ba', '79d51591-9a8c-4b73-b7b6-6a753ddf56ab', 'お忙しいのは承知しておりますが、そこを押してお願いいたします。', 'お忙しいのは承知しておりますが、そこを押してお願いいたします。', '我知道您很忙，但是请您抽出点时间来。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('6aed08a8-65da-4582-895f-e6069c5f5e7d', '79d51591-9a8c-4b73-b7b6-6a753ddf56ab', '病気を押し切って、会議に出席した。', '病気を押し切って、会議に出席した。', '抱病出席了会议。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('635dc4e3-da93-4176-8cfa-16cb0b79c669', '～を限りに', NULL, 'N1', '名＋を限りに', '名＋を限りに', '表示时间的结束，“以……为截止日期”“到……为止”。\n表示尽自己最大的可能，“以……为最大限度”“尽最大的……”。', '常用「今日」「今回」「今月」等表示时间的词。\n常用「声を限りに」「力を限りに」等固定表达。\n也可以用「声を限りに」「力を限りに」等形式。', 195, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('3c9fe622-f0b8-4fd8-959f-110a89b851bd', '635dc4e3-da93-4176-8cfa-16cb0b79c669', '鈴木アナウンサーはきょうのサッカーの試合の中継放送をかぎりに引退した。', '鈴木アナウンサーはきょうのサッカーの試合の中継放送をかぎりに引退した。', '铃木先生直播完今天的足球比赛节目后就引退了。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('d9a46fe6-f44f-4254-8d3b-9ca1584d4164', '635dc4e3-da93-4176-8cfa-16cb0b79c669', '今日を限りにタバコをやめることにした。', '今日を限りにタバコをやめることにした。', '从今天开始戒烟。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('cebdaeb7-35bb-465b-9979-3aee2b62d4a9', '635dc4e3-da93-4176-8cfa-16cb0b79c669', 'このグループは今回のコンサートを限りに解散することになった。', 'このグループは今回のコンサートを限りに解散することになった。', '这个组合在这次演唱会结束后就要解散了。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('8b520e66-60f4-48a9-8d1a-80b827f6edd6', '635dc4e3-da93-4176-8cfa-16cb0b79c669', '天まで届けとばかりに、声を限りに歌った。', '天まで届けとばかりに、声を限りに歌った。', '仿佛希望歌声直达云霄似的，尽最大声音歌唱。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('9f88a8ba-de42-41dd-bfa1-9c3f79890e64', '635dc4e3-da93-4176-8cfa-16cb0b79c669', '応援団は声を限りに、声援を送った。', '応援団は声を限りに、声援を送った。', '助威队以最大的声音进行了声援。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('874b84c2-8bae-49cc-b2cd-a9119f3961b6', '635dc4e3-da93-4176-8cfa-16cb0b79c669', '力を限りに、ゴールに向かって走っていました。', '力を限りに、ゴールに向かって走っていました。', '尽全力跑向终点。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('ef38893d-382e-404f-9a2c-89a67dfcf18c', '635dc4e3-da93-4176-8cfa-16cb0b79c669', '声の限りに助けを呼んだ。', '声の限りに助けを呼んだ。', '尽最大的声音呼救。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('46564289-1101-4113-92b7-15009f5aa90c', '～を 皮[かわ] 切[き]りに（して）', NULL, 'N1', '名＋を皮切りに（して）', '名＋を皮切りに（して）', '表示以某项活动、某事为开端相继发生了类似的事情，“以……为开端”。', '区别类似语法「～をはじめとして」/以……为首。', 196, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('961c5974-d885-4146-b955-17fd1f48a8b7', '46564289-1101-4113-92b7-15009f5aa90c', 'その会社は、先週発表した新車をかわきりに、次々と新しい車を発表するそうだ。', 'その会社は、先週発表した新車をかわきりに、次々と新しい車を発表するそうだ。', '听说那个公司自从上周推出一款新车后，又相继推出了一系列的新车。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('d4383078-b996-40b8-92a2-6468a496bcc5', '46564289-1101-4113-92b7-15009f5aa90c', '当劇団は評判がよく、明日の公演をかわきりに、今年は10都市を回る予定である。', 'とうげきだんは評判がよく、明日の公演をかわきりに、今年は10都市を回る予定である。', '这个剧团的评价不错，以明天的公演为开端，今年之内准备在十个城市公演。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('9587501c-42b9-4731-9b59-d9dba752b101', '46564289-1101-4113-92b7-15009f5aa90c', '上海を皮切りにして全国10か所でコンサートを開くことになりました。', '上海を皮切りにして全国10か所でコンサートを開くことになりました。', '以上海为开端，在全国十多个地方开音乐会。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('f56ab7f6-b8a0-47cd-a722-c1ac99e8ed45', '～を 機[き]に', NULL, 'N1', '名＋を機に', '名＋を機に', '表示前后两项的关联，“以……为契机”“借……的机会”。', '用法与「～を 契[けい] 機[き]に」「～をきっかけに」相同。', 197, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('2f225d0e-710d-4842-9b8b-9bd5a338f03d', 'f56ab7f6-b8a0-47cd-a722-c1ac99e8ed45', '山川鉄道は、3月で開業90周年を迎えるのを機に、最新型車両を導入し、15日から営業運転を開始する。', '山川鉄道は、3月で開業90周年を迎えるのを機に、最新型車両を導入し、15日から営業運転を開始する。', '山川铁路公司在三月份迎来了公司创建90周年的纪念日，以此为契机，公司购买了最新的车型，预计从15号开始投入运营。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('9673a7e8-acf1-4ac0-a57e-b9c1009b116e', 'f56ab7f6-b8a0-47cd-a722-c1ac99e8ed45', '入院したのを機に、お酒をやめた。', '入院したのを機に、お酒をやめた。', '以住院为契机戒了酒。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('d7589ac0-c758-4a33-a7fa-b86ab0527f0c', 'f56ab7f6-b8a0-47cd-a722-c1ac99e8ed45', '当社は十周年を機に新商品を発表しました。', '当社は十周年を機に新商品を発表しました。', '以公司十周年庆为契机，发布了新商品。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('68d00bae-2d3a-4da2-b391-c851ae982891', 'f56ab7f6-b8a0-47cd-a722-c1ac99e8ed45', '結婚を機に、仕事をやめて家庭に入った。', '結婚を機に、仕事をやめて家庭に入った。', '我以结婚为契机辞职做家庭主妇了。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('a49a0022-e506-457d-836f-6df0c11f3c38', '～を 禁[きん]じ 得[え]ない', NULL, 'N1', '名＋を禁じ得ない', '名＋を禁じ得ない', '强调一种感情、情绪，“不禁……”“忍不住……”。', '常与「涙」「怒り」「同情」「戸惑い」等名词一起使用。', 198, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('8b3e0152-0c65-4b03-8b13-e58ad40e555b', 'a49a0022-e506-457d-836f-6df0c11f3c38', 'この事件の犯人には、強い怒りを禁じ得ない。', 'この事件の犯人には、強いいかりを禁じ得ない。', '对于这起事件的犯人深恶痛绝。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('b7ecff50-80cc-4d88-80a9-9a2edcb7551b', 'a49a0022-e506-457d-836f-6df0c11f3c38', '私たちは、彼の突然の辞職に、戸惑いを禁じえない。', '私たちは、彼の突然の辞職に、とまどいを禁じえない。', '我们对于他的突然辞职感到很困惑。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('0030cf23-1960-4c51-b0e8-5ff924d342fb', 'a49a0022-e506-457d-836f-6df0c11f3c38', 'あんまりにも悲しい場面に涙を禁じえなかった。', 'あんまりにも悲しい場面に涙を禁じえなかった。', '这个画面太悲伤，让人忍不住流泪。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('fa8edd0b-2773-4019-b103-cfaf95f69e30', '～を 蔑[ないがし]ろにする', NULL, 'N1', '名＋を蔑ろにする', '名＋を蔑ろにする', '“轻视……”“瞧不起……”“把……不当一回事”。', '意思与「～を 無[む] 視[し]する」相同。', 199, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('a015a2d3-a1c4-4708-bd4c-97b46d290ada', 'fa8edd0b-2773-4019-b103-cfaf95f69e30', '人の意見をないがしろにする。', '人の意見をないがしろにする。', '完全忽视别人的意见。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('9103f064-0588-481d-a353-4b42cd141c30', 'fa8edd0b-2773-4019-b103-cfaf95f69e30', '人のせっかくの好意をないがしろにする。', '人のせっかくの好意をないがしろにする。', '完全不顾别人的好意。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('74704543-a5d0-4803-a295-d9c2e95d9eb5', 'fa8edd0b-2773-4019-b103-cfaf95f69e30', '社員の福祉をないがしろにして、目の前の利益だけを求めてはいけない。', '社員の福祉をないがしろにして、目の前の利益だけを求めてはいけない。', '忽视员工的福利而只追求眼前的利益，这是不行的。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('ac848b16-6a95-4196-9681-72d6af447d30', '～をなおざりにして', NULL, 'N1', '名＋をなおざりにして', '名＋をなおざりにして', '表示随便应付某事，不认真的意思。“轻视……”“忽视……”。', '意思与「～をいいかげんにして」相同。', 200, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('e613b823-4bcf-453b-83aa-47b1e4664df5', 'ac848b16-6a95-4196-9681-72d6af447d30', '子どものしつけをなおざりにしていては、将来は大変なことになるよ。', '子どものしつけをなおざりにしていては、将来は大変なことになるよ。', '如果忽视了孩子的教育，今后会有很严重的问题。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('91b2f44f-e7ff-4c79-bfd9-45a8765a2574', 'ac848b16-6a95-4196-9681-72d6af447d30', 'どんなことがあっても、仕事をなおざりにしてはいけない。', 'どんなことがあっても、仕事をなおざりにしてはいけない。', '不管发生什么事，在工作方面都不能玩忽职守。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('b7f3c28b-bfd6-44b0-bd05-8d515c27bd8e', '～を 控[ひか]え/を控えて/を控えた', NULL, 'N1', '名＋を控え/を控えて/を控えた', '名＋を控え/を控えて/を控えた', '“面临……”“……即将来临之际”。', '前面常用表示时间的名词。\n既可以用「卒業式を控え」，也可以用「卒業式を一か月に控え」的形式。', 201, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('1b9122cf-0de9-4431-b9fc-e85c72612c14', 'b7f3c28b-bfd6-44b0-bd05-8d515c27bd8e', '田中君は先週ずっと授業を休んでいて、試験を受けなかった。卒業を控えた身でありながら、海外へ遊びに行っていたらしい。', '田中君は先週ずっと授業を休んでいて、試験を受けなかった。卒業を控えた身でありながら、海外へ遊びに行っていたらしい。', '田中上周一直请假没有参加考试，都快毕业了还去了国外旅行。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('8fa937d1-1be1-4e73-8a68-7d0454ccc7c2', 'b7f3c28b-bfd6-44b0-bd05-8d515c27bd8e', '駅前の新しい喫茶店は、明日の開店をひかえてすっかり準備が整い、あとは客を待つばかりになっている。', '駅前の新しい喫茶店は、明日の開店をひかえてすっかり準備がととのい、あとは客を待つばかりになっている。', '车站前面那家新的咖啡厅明天就要开张了，现在已经做好了一切准备，只等客人来。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('1bc642f5-7ad4-43b1-a63b-5fd36d8d67af', 'b7f3c28b-bfd6-44b0-bd05-8d515c27bd8e', '結婚式を一か月後にひかえ、いろいろな準備で忙しい。', '結婚式を一か月後にひかえ、いろいろな準備で忙しい。', '一个月后就要结婚了，现在有很多事情要准备，很忙。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('29200c1e-959f-4e65-9936-24aa67433a31', '～を 踏[ふ]まえ/を踏まえて', NULL, 'N1', '名＋を踏まえ/を踏まえて', '名＋を踏まえ/を踏まえて', '“依据……”“根据……”“立足于……”“考虑到……”。', '常与「現状」「実情」「状況」等词一起使用。', 202, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('2752ab11-206a-423e-b02f-6a3ebc193deb', '29200c1e-959f-4e65-9936-24aa67433a31', '現在の状況を踏まえて、今後の計画を考え直す必要がある。', '現在の状況を踏まえて、今後の計画を考え直す必要がある。', '依据现在的情况，有必要重新考虑今后的计划。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('fea0e85c-2e79-4166-82c2-001aab486ab2', '29200c1e-959f-4e65-9936-24aa67433a31', '今年度の反省をふまえて、来年度の計画を立てなければならない。', '今年度の反省をふまえて、来年度の計画を立てなければならない。', '必须在对本年度的情况进行总结的基础上制订明年的计划。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('5b48daba-bf31-424b-bca4-8ff53e4087a9', '29200c1e-959f-4e65-9936-24aa67433a31', '各家庭の実情を踏まえて、補助金を配るべきだ。', '各家庭の実情を踏まえて、ほじょきんを配るべきだ。', '应该根据每个家庭的实际情况发放补助金。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('20e2b5a3-9026-4a49-9861-755fb8a573df', '～を 振[ふ]り 出[だ]しに', NULL, 'N1', '名＋を振り出しに', '名＋を振り出しに', '“以……为开端”“以……为起点”。', NULL, 203, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('4d09ae72-34de-4c13-a2f9-06f5694004ec', '20e2b5a3-9026-4a49-9861-755fb8a573df', '彼は小学校の教師を振り出しに社会に出た。', '彼は小学校の教師を振り出しに社会に出た。', '他以小学老师为起点走上了社会。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('d53c0cfd-b603-4007-9d31-e368aa8fbda0', '20e2b5a3-9026-4a49-9861-755fb8a573df', '総理大臣は中国を振り出しにアジア諸国を訪問した。', 'そうりだいじんは中国を振り出しにアジア諸国を訪問した。', '总理大臣先后访问了中国以及其他亚洲国家。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('98beec0e-91dd-43cb-bb86-a83dc0eebf92', '～を 経[へ]て', NULL, 'N1', '名＋を経て', '名＋を経て', '“经过……”“通过……”。', '常与表示地点、途径、流程的名词一起使用。', 204, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('efbe36d9-1b83-4108-ab18-f30c1a10f21a', '98beec0e-91dd-43cb-bb86-a83dc0eebf92', '新しい条約は、議会の承認を経て認められた。', '新しい条約は、議会のしょうにんを経て認められた。', '这个新条约经过议会的同意被批准了。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('59382ed5-d70f-49f4-ac92-353fead25e73', '98beec0e-91dd-43cb-bb86-a83dc0eebf92', '香港を経て日本に行く。', '香港を経て日本に行く。', '经过香港去日本。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('127d721b-a494-4408-aa38-e0567b388496', '98beec0e-91dd-43cb-bb86-a83dc0eebf92', '正式の手続きを経て、この大学に入った。', '正式の手続きを経て、この大学に入った。', '办理了正式的手续之后进入了这所大学。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('0f9fdd73-199c-42b8-856c-c79412a07a4c', '～をもって/をもちまして', NULL, 'N1', '名＋をもって/をもちまして', '名＋をもって/をもちまして', '表示时间的开始、结束，“以……（为起始点）”“于……开始”“于……结束”。', '用于寒暄等比较正式的场合。\n在宣布会议结束、告知时间时，也可用「～をもちまして」。', 205, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('e8f70ecf-cf51-4a1c-b66a-366209addbe5', '0f9fdd73-199c-42b8-856c-c79412a07a4c', '誠に勝手ながら、当店は10月30日をもって開店いたしました。', '誠に勝手ながら、当店は10月30日をもって開店いたしました。', '我们公司在10月30日开店了。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('1c4c146f-deb8-44f3-a573-1be086281e99', '0f9fdd73-199c-42b8-856c-c79412a07a4c', '今回のシンポジウムは本日をもって終了いたします。', '今回のシンポジウムは本日をもって終了いたします。', '本次研讨会在今天结束。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('a1d95b5e-89f2-4b2d-a504-2f87dcaa4cab', '0f9fdd73-199c-42b8-856c-c79412a07a4c', '7時をもちまして、本日の営業を終了いたします。', '7時をもちまして、本日の営業を終了いたします。', '我们店的营业将在7点结束。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('c0d739a6-446d-423c-8f65-7120da786f4f', '～をもって', NULL, 'N1', '名＋をもって', '名＋をもって', '表示手段、方式、状态等，“以……”“凭借……”“带着……”。', '也可以用「～をもってすれば」/凭借……的话，「～をもってしても」/即使凭借……也……', 206, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('7d334de3-2d3d-4651-880e-cb50afc96920', 'c0d739a6-446d-423c-8f65-7120da786f4f', '身をもって日系企業の文化を体験した。', 'みをもって日系企業の文化を体験した。', '亲身体验了日企的文化。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('f6fe2db0-842b-4917-a716-d5d8e9703c88', 'c0d739a6-446d-423c-8f65-7120da786f4f', '面接の結果はメールをもってお知らせします。', '面接の結果はメールをもってお知らせします。', '面试的结果会以邮件形式通知。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('7edaf529-8156-4b1f-b5b7-4597e9391de6', 'c0d739a6-446d-423c-8f65-7120da786f4f', '自信をもって、頑張っていきましょう。', '自信をもって、頑張っていきましょう。', '满怀信心地去努力吧。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('8eb0e05c-6952-427d-ba9f-1cd903472820', 'c0d739a6-446d-423c-8f65-7120da786f4f', '彼の語学力を持ってすれば、今度の試験に合格するのは問題ないだろう。', '彼の語学力を持ってすれば、今度の試験に合格するのは問題ないだろう。', '从他的语言能力来看，通过这次的考试应该没有问题吧。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('ece0fd01-df51-474a-8ac2-a702c7826316', 'c0d739a6-446d-423c-8f65-7120da786f4f', 'これは、彼女の実力を持ってしても解決できなかった問題だ。', 'これは、彼女の実力を持ってしても解決できなかった問題だ。', '这是以她的实力也无法解决的问题。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('546d0656-7ea5-4435-a353-2f5eabf84847', '～をものともせずに', NULL, 'N1', '名＋をものともせずに', '名＋をものともせずに', '表示克服困难，坚持做某事。“克服困难……”“不顾……”。', '该句型多表示积极的意思。', 207, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('81c7f923-0e58-4aee-86b1-51536fba75df', '546d0656-7ea5-4435-a353-2f5eabf84847', '彼はたび重なる困難をものともせず、前に進んでいった。', '彼はたび重なる困難をものともせず、前に進んでいった。', '他克服了重重困难前行。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('f7846823-63ab-42d8-8aaf-0c4090b3bddf', '546d0656-7ea5-4435-a353-2f5eabf84847', '周囲の反対をものともせず、兄はいつも自分の意思を通してきた。', '周囲の反対をものともせず、兄はいつも自分の意思を通してきた。', '哥哥不顾周围人的反对，总是坚持按照自己的想法做事情。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('afe42129-329c-4259-a134-bfaf8dfb1291', '546d0656-7ea5-4435-a353-2f5eabf84847', '彼女は周りの反対をものともせずに、自分の信じる道を歩み続けてきた。', '彼女は周りの反対をものともせずに、自分の信じる道を歩み続けてきた。', '尽管周围的人都反对，但她还是坚持走自己认为正确的路。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('6c1cc2f7-de29-453b-9914-455f7b1d880e', '546d0656-7ea5-4435-a353-2f5eabf84847', '悪天候をものともせずに、試合を続けることにした。', 'あくてんこうをものともせずに、試合を続けることにした。', '尽管天气恶劣，依然决定坚持比赛。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('a09d4321-29df-469a-99c0-ed6ad16b6bd4', '～を 余[よ] 儀[ぎ]なくさせる', NULL, 'N1', '名＋を余儀なくさせる', '名＋を余儀なくさせる', '表示使役，前项事态的发生，迫使后项不得不改变。“迫使……”“迫使……不得不……”', '「余儀ない」是一个形容词，意思是“无可奈何……”“不得不……”，和「させる」一起使用，表示使役。\n常用「Aは/がBを余儀なくさせた」「Aは/がBに～を余儀なくさせた」的形式，因为A这种情况，迫使B不得不……\n多指突发的、不好的事态，句末一般用过去时，描述已经发生的事情。\n主要用在文章中，是比较生硬的表达方式。', 208, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('25185106-1be4-42d1-811c-a5e5f49ce432', 'a09d4321-29df-469a-99c0-ed6ad16b6bd4', '両国関係の悪化が、プロジェクトの中止を余儀なくさせた。', '両国関係の悪化が、プロジェクトの中止を余儀なくさせた。', '因为两国关系的恶化，使得这个项目被迫终止。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('944177f8-0b3c-44b4-8732-fde0990c6919', 'a09d4321-29df-469a-99c0-ed6ad16b6bd4', 'この会社に入ってわずか一か月だったが、家の事情が彼に辞職を余儀なくさせた。', 'この会社に入ってわずか一か月だったが、家の事情が彼に辞職を余儀なくさせた。', '刚进公司一个月，就因为家里的事情迫使他不得不辞职。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('103b3132-5d60-43d6-863d-a615e8a71791', 'a09d4321-29df-469a-99c0-ed6ad16b6bd4', '台風の上陸が、出発予定のフライトの延期を余儀なくさせた。', '台風の上陸が、出発予定のフライトの延期を余儀なくさせた。', '台风的登陆，使得本来要出发的航班被迫延期。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('7400ab37-93a8-49a4-8b5a-7461164a135f', '～を 余[よ] 儀[ぎ]なくされる', NULL, 'N1', '名＋を余儀なくされる', '名＋を余儀なくされる', '表示被动，某人或者某事因为突发状况，被迫改变。“被迫……”。', '「余儀ない」是一个形容词，意思是“无可奈何……”“不得不……”，和「される」一起使用，表示被动。\n常用「Bは/がAに余儀なくされた」、「Bは/がAに～を余儀なくされた」的形式，因为A这种情况，B被迫……\n多指突发的、不好的事态，句末一般用过去时，描述已经发生的事情。\n主要用在文章中，是比较生硬的表达方式。', 209, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('1e37777f-3ee9-4cb7-9a5d-73bd4460a6b3', '7400ab37-93a8-49a4-8b5a-7461164a135f', '不正な取引が明らかになり、その取引に関わった会社役員は辞職を余儀なくされた。', '不正な取引が明らかになり、その取引に関わった会社役員は辞職を余儀なくされた。', '非法交易的情况被证实属实，牵涉其中的董事被迫辞职。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('f746e8a9-f6e2-46ad-b915-8b4e68e965b9', '7400ab37-93a8-49a4-8b5a-7461164a135f', '道路拡張の工事のために、この周辺の人々は引越しを余儀なくされた。', '道路拡張の工事のために、この周辺の人々は引越しを余儀なくされた。', '因为道路扩张工程，周边的人不得不搬迁。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('96e98799-498c-4456-8f17-f8fd39bf7714', '7400ab37-93a8-49a4-8b5a-7461164a135f', '前政権が崩壊してからというもの、この国では中小企業の倒産、大手の企業の合併が続き、多くの人が職場を離れることを余儀なくされている。', '前政権が崩壊してからというもの、この国では中小企業の倒産、おおての企業のがっぺいが続き、多くの人が職場を離れることを余儀なくされている。', '自从前面的政权倒台之后，这个国家中小企业相继破产，大型企业相继合并，很多人被迫离开职场，流离失所。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('0e1d3966-f8dc-4574-b546-687facc47771', '～をよそに', NULL, 'N1', '名＋をよそに', '名＋をよそに', '“不顾……”“不管……”。', '多表示消极的意思。', 210, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('66c7153d-8be0-460f-a7ea-d3e18013e859', '0e1d3966-f8dc-4574-b546-687facc47771', 'あの人は周りの心配をよそに、好き勝手に振舞っていた。', 'あの人は周りの心配をよそに、好き勝手にふるまっていた。', '他做事任意草率，完全不考虑周围人的担心。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('67617b01-5896-4765-bda7-b40a0f923111', '0e1d3966-f8dc-4574-b546-687facc47771', '親の期待をよそに、子どもたちは毎日ゲームに熱中している。', '親の期待をよそに、子どもたちは毎日ゲームに熱中している。', '孩子不顾父母的期待，整天沉迷于游戏之中。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('02c9f7bd-05a4-4655-8401-35fa73c31963', '0e1d3966-f8dc-4574-b546-687facc47771', '住民の反対運動が盛り上がるのをよそに、高層ホテルの建設工事はどんどん進められている。', '住民の反対運動が盛り上がるのをよそに、高層ホテルの建設工事はどんどん進められている。', '声势浩大的居民反对运动被完全忽视，高层宾馆的施工仍在继续。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('58a97704-c79b-4371-b114-abba98522dc2', '～んがため（に）/んがための', NULL, 'N1', '動ない形＋んがため（に）/んがための', '動ない形＋んがため（に）/んがための\n（する→せんがため）', '表示积极的目的，“为了……”。', '「～んがために」后面接续动词、形容词、副词等。「～んがための」后面接续名词。\n后面不能用请求、命令、禁止、号召等表达方式。\n是比较生硬的表达方式。', 211, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('3382c266-4c8e-493f-89fc-df8aaa047dc5', '58a97704-c79b-4371-b114-abba98522dc2', '夢をかなえんがため、日々努力している。', '夢をかなえんがため、日々努力している。', '为了实现梦想，每天都在努力。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('aad62644-9e10-496b-8b06-5ef75e0074eb', '58a97704-c79b-4371-b114-abba98522dc2', '国会に法案を通さんがために、首相は根回し工作を開始した。', '国会に法案をとおさんがために、首相はねまわしこうさくを開始した。', '为了在国会通过这个法案，首相开始做起了动员工作。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('f2a7d286-93e4-4529-b5c7-92d1780ed17b', '58a97704-c79b-4371-b114-abba98522dc2', '人間は生きんがために、心ならずも悪事を行ってしまう場合がある。', '人間は生きんがために、心ならずも悪事を行ってしまう場合がある。', '人们为了活下去，有时候会做一些并非出自本意的坏事。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('196da4a2-519b-44a6-8b10-c4cf95a05635', '～んじゃなかった', NULL, 'N1', '動辞書形＋んじゃなかった', '動辞書形＋んじゃなかった', '“不该……的”“早知道就不……了”。', '该句型多用于口语中，对已经发生的事情表示遗憾、后悔。', 212, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('189aadf5-2fd6-41fa-ac3f-55f798461995', '196da4a2-519b-44a6-8b10-c4cf95a05635', 'このソファースペースとるし、デザインもいまいちなんだから、最初から買うんじゃなかった。', 'このソファースペースとるし、デザインもいまいちなんだから、最初から買うんじゃなかった。', '这个沙发又占地方，设计也不好看，起初就不该买的。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('7fccb2c5-8b54-4b30-84af-d25356b8591f', '196da4a2-519b-44a6-8b10-c4cf95a05635', 'こんなことになるなんて思わなかった。彼女に話すんじゃなかった。', 'こんなことになるなんて思わなかった。彼女に話すんじゃなかった。', '真没想到事情会变成这个样子，真不该跟她说。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('75de29bd-4c3a-4225-92a9-36390e6f9740', '196da4a2-519b-44a6-8b10-c4cf95a05635', 'ああ、100万円も負けた。彼女の儲け話なんて聞くんじゃなかったの。', 'ああ、100万円も負けた。彼女のもうけばなしなんて聞くんじゃなかったの。', '唉，输了100万日元。真不该听她说的什么赚钱之类的话的。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('a5e5ca49-0524-461f-89cd-ca5040e203a1', '～んだって/んですって', NULL, 'N1', '～んだって/んですって', '～んだって/んですって', '表示传闻、转述，“据说……”。', '「～だって」用于同辈之间或者对下辈所讲的话，「～ですって」用于对长辈或者上级所讲的话。', 213, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('13cb6cfa-5fde-4c64-a8b8-d859fc54dd15', 'a5e5ca49-0524-461f-89cd-ca5040e203a1', '太田さんは来月から北海道に転勤するんだって。', '太田さんは来月から北海道に転勤するんだって。', '听说太田下个月要调到北海道去了。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('3f9ed0c5-4280-44ea-826c-bac9bffbe1bf', 'a5e5ca49-0524-461f-89cd-ca5040e203a1', 'あの方が新しく就任する部長なんだって。', 'あの方が新しく就任する部長なんだって。', '听说那位就是新上任的部长。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('e0d81722-e7c8-4786-8079-977356d2fb37', 'a5e5ca49-0524-461f-89cd-ca5040e203a1', '彼女は仕事を辞めたんですって。', '彼女は仕事を辞めたんですって。', '听说她辞职了。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('05a592e3-8f31-4825-b3a0-6f224d91248c', '～んばかりに/んばかりの/んばかりだ', NULL, 'N1', '動ない形＋んばかりに/んばかりの/んばかりだ', '動ない形＋んばかりに/んばかりの/んばかりだ\n（する→せんばかり）', '表示样态，“几乎显出……的样子”“几乎就要……”。', '「～んばかりに」后面接续动词、形容词、副词。「～んばかりの」后接续名词。「んばかりだ」用在句末。\n不能用在描述说话人自己的神态、动作、表情等情况。', 214, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('177a4773-8cba-4f36-b1c8-b1c1edcd889b', '05a592e3-8f31-4825-b3a0-6f224d91248c', '自分は関係ないといわんばかりの夫の言動に腹が立った。', '自分は関係ないといわんばかりの夫の言動に腹が立った。', '丈夫说得好像跟自己没有关系似的，他的这种言行让我极为生气。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('4f77a8b0-1226-452a-a1cd-5a6f59b46cc1', '05a592e3-8f31-4825-b3a0-6f224d91248c', 'ビデオカメラの調子が悪いので、メーカーに電話した。すると、言葉づかいは丁寧だったが、私の使い方が悪いと言わんばかりだった。', 'ビデオカメラの調子が悪いので、メーカーに電話した。すると、言葉づかいは丁寧だったが、私の使い方が悪いと言わんばかりだった。', '摄影机有点问题，所以我给厂商打了电话。他们讲话倒是很客气，但是却好像在说是因为我的操作不得当才出现这种问题似的。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('f78dff6d-6254-4335-97d4-01d9c3a69953', '05a592e3-8f31-4825-b3a0-6f224d91248c', '彼女は泣かんばかりに、「元気でね」と言いながら手を振った。', '彼女は泣かんばかりに、「元気でね」と言いながら手を振った。', '她眼泪快要流下来的样子，挥了挥手说了声保重。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('2d52b2a5-30ee-4cc7-8392-b185cd258d92', '～あげく（に）', NULL, 'N2', '動た形/名－の＋あげく（に）', '動た形/名－の＋あげく（に）', '表示结果，“最后……”。', '后项的结果一般带有消极的意义。除了「～あげく」的形式之外，还有「～あげくのはてに」的形式，与「～あげく」的意思相同，但是后项的结果比「～あげく」更为严重，可用于连接两个句子，有接续词的功能。', 215, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('6611912e-61a7-44c5-b88a-6bd8fe21581f', '2d52b2a5-30ee-4cc7-8392-b185cd258d92', 'プリンターの調子が悪くなり、製造会社に電話で問い合わせたら、向こうの担当者に、あれこれ質問に答えさせられたあげく、対応できないと言われた。', 'プリンターのちょうしが悪くなり、せいぞうがいしゃに電話で問い合わせたら、向こうのたんとうしゃに、あれこれ質問に答えさせられたあげく、たいおうできないと言われた。', '打印机出了点问题，我打电话咨询了生产商，但对方负责人问来问去，让我回答了半天，最后却说他们没法处理。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('cdc015a9-f051-4273-8ea9-fc65a36a7b39', '2d52b2a5-30ee-4cc7-8392-b185cd258d92', '彼女はいろいろと悩んだあげく結婚をやめてしまった。', '彼女はいろいろとなやんだあげく結婚をやめてしまった。', '她烦恼了许久，最后没有结婚。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('30903a3e-4faa-4106-b12f-8742a716117e', '2d52b2a5-30ee-4cc7-8392-b185cd258d92', 'どの大学に留学しようかと、さんざん悩んだあげく、A大学に決めた。', 'どの大学に留学しようかと、さんざん悩んだあげく、A大学に決めた。', '为去哪个大学留学而烦恼，最后决定去A大学。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('7f05d1b6-0062-4627-a1c0-b8b1043a5b5f', '～あまり（に）', NULL, 'N2', '～あまり（に）', '～あまり（に）', '表示由于程度过甚，导致（了）某种结果。“由于过度……因而……”。', '常与表示状态或感情的词一起使用，如「忙しさ（忙碌）」「 驚[おどろ]き（惊讶）」「うれしさ（高兴）」「喜び（喜悦）」「悲しみ（悲伤）」「 感[かん] 激[げき]（感激、感动）」「 心[しん] 配[ぱい]（担心）」等。', 216, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('dc760737-f6dd-47e2-bb19-c6c50690f230', '7f05d1b6-0062-4627-a1c0-b8b1043a5b5f', '何でも完全にやろうと思うあまりに、体を壊す人がいる。', '何でもかんぜんにやろうと思うあまりに、体を壊す人がいる。', '有些人因为做任何事情都过于追求完美，而弄坏了身体。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('9fd9d54c-e53d-47d0-9130-d061deda6acc', '7f05d1b6-0062-4627-a1c0-b8b1043a5b5f', '試験の結果を気にするあまり、夜眠れなくなってしまった。', '試験の結果を気にするあまり、夜ねむれなくなってしまった。', '由于太在意考试结果，晚上失眠了。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('a97a8ee6-10ce-4b32-bda0-c42c0b69ee60', '7f05d1b6-0062-4627-a1c0-b8b1043a5b5f', '彼女は一番行きたかった大学に合格し、うれしさのあまり、跳び上がった。', '彼女は一番行きたかった大学に合格し、うれしさのあまり、とびあがった。', '她考上了自己最想去的大学，由于太开心了，蹦了起来。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('ba2a1bf6-5945-4701-a67c-68d8d4dcc65d', '～ 以[い] 上[じょう]（は）', NULL, 'N2', '～ 以[い] 上[じょう]（は）', '～ 以[い] 上[じょう]（は）', '前项表示确定的事实，“既然……就……”。', '后项常接表示决心、义务、建议、推量等表达说话人意志的内容。', 217, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('ecbe4fa6-26bb-4eac-9917-f28bbeeebdb4', 'ba2a1bf6-5945-4701-a67c-68d8d4dcc65d', 'エネルギーの問題がこれほど深刻になった以上、世界各国が協力して、ただちに対策をたてるべきだ。', 'エネルギーの問題がこれほどしんこくになった以上、世界かっこくがきょうりょくして、ただちにたいさくをたてるべきだ。', '既然能源问题已经如此严峻，世界各国就应该联合起来，立即采取对策。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('9b3247fc-9e4f-4ff3-92a9-305424e25d6c', 'ba2a1bf6-5945-4701-a67c-68d8d4dcc65d', '留学する以上は、勉強だけでなく、その国の文化を学んだり交流をしたりしたいと思う。', '留学する以上は、勉強だけでなく、その国の文化をまなんだりこうりゅうをしたりしたいと思う。', '既然去留学了，就不仅是学习，我还想了解该国的文化，并与该国的人们进行交流。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('101a076d-ab94-44cf-bd1e-392496b7eda4', 'ba2a1bf6-5945-4701-a67c-68d8d4dcc65d', 'もう酒は飲まないと決めた以上は、どんなに誘われても絶対にそれを守りたい。', 'もう酒は飲まないと決めた以上は、どんなにさそわれても絶対にそれを守りたい。', '既然已经决定不再喝酒了，再怎么被邀请，我也坚决不喝。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('464af148-c516-42c9-b399-2889f86b40d8', '～ 上[うえ]は', NULL, 'N2', '動辞書形·た形＋上は', '動辞書形·た形＋上は', '前项表示既定的事实，“既然……就……”。', '与「～以上（は）」的用法相同，“既然……”的语气比「～以上（は）」更强烈。', 218, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('03f1a19b-f6db-466c-89bb-8e8b5e2bc28e', '464af148-c516-42c9-b399-2889f86b40d8', '事態がこうなった上は、もう彼一人に任せてはおけない。', 'じたいがこうなった上は、もう彼一人にまかせてはおけない。', '既然事态发展到这一步，就不能再交给他一个人去做了。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('f3cd7247-160e-4d01-8e2b-3114c634da84', '464af148-c516-42c9-b399-2889f86b40d8', '目標を決めた上は、それに向かって前向きに行動しなければならない。', 'もくひょうを決めた上は、それにむかってまえむきにこうどうしなければならない。', '既然已经确定目标，就必须朝着这个目标积极地行动。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('ddc1c6b7-7890-4a46-b2b9-453467779031', '464af148-c516-42c9-b399-2889f86b40d8', 'こうなった上は、覚悟を決めて最後まで頑張るしかない。', 'こうなった上は、かくごを決めて最後まで頑張るしかない。', '既然事已至此，就只好做好思想准备，坚持努力到最后了。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('7a927af5-100e-46eb-b800-2cf86c4a91c3', '～（よ）うではないか/（よ）うじゃないか', NULL, 'N2', '動意向形＋ではないか/じゃないか', '動意向形＋ではないか/じゃないか', '表示建议或劝诱，“让我们……吧”。', '包含强烈的呼吁、号召的语气，「～（よ）うではありませんか」是其礼貌的表达方式。', 219, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('4fb396b5-1bd9-48d6-83c0-36f9472999f6', '7a927af5-100e-46eb-b800-2cf86c4a91c3', '食糧不足で困っている人たちに、できる限りの援助をしようではないか。', 'しょくりょうぶそくで困っている人たちに、できる限りのえんじょをしようではないか。', '让我们尽最大努力去援助那些因粮食不足而处于困境的人吧。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('d419ad62-5ed1-4f24-9e95-dd582498a47f', '7a927af5-100e-46eb-b800-2cf86c4a91c3', 'この本に載っているレストランはとてもおいしそうだ。みんなで行ってみようじゃないか。', 'この本にのっているレストランはとてもおいしそうだ。みんなで行ってみようじゃないか。', '这本书上刊登的餐厅看起来很好吃。大家一起去看看吧。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('6999a42e-5e2f-4672-9a1f-a771e104d749', '7a927af5-100e-46eb-b800-2cf86c4a91c3', '家にばかりいないで映画でも見に行こうじゃないか。', '家にばかりいないで映画でも見に行こうじゃないか。', '不要一直待在家里，去看看电影什么的吧。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('c7456f31-2e38-484b-b93e-317c4366136e', '～ 得[う]る/ 得[え]ない', NULL, 'N2', '動ます形＋得る', '動ます形＋得る\n動ます形＋得ない', '表示可能性，“能……”。\n表示没有某种可能性，“不可能……”。', '「～得る」表示可能性，而不表示能力。而动词的可能态「～れる/られる」既可以表示可能性，又可以表示能力。如表示“会说中文”时，只能用「中国語が話せる」，而不能用「中国語が話しうる」。\n「～得る」一般用于书面语，其否定形式是「～得ない」。「ありうる（能有，应该有）」比较常用。\n属于书面语，但是「ありえない」在口语中常用。', 220, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('e639550b-0617-461b-a51b-01415a545c68', 'c7456f31-2e38-484b-b93e-317c4366136e', 'このまま海面の上昇が続けば、これらの島々が海の中に沈んでしまうこともありうる。', 'このままかいめんのじょうしょうがつづけば、これらのしまじまが海の中にしずんでしまうこともありうる。', '如果海平面照这样不断上升的话，这些岛屿有可能会沉没到大海之中。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('7c79dd10-d061-4ecb-b0af-5fc4dcb0149e', 'c7456f31-2e38-484b-b93e-317c4366136e', '彼の取った態度は、わたしには十分理解しうるものであった。', '彼の取ったたいどは、わたしにはじゅうぶん理解しうるものであった。', '我很能理解他所采取的态度。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('15fb51db-5e02-4546-8637-2e9f5e45884c', 'c7456f31-2e38-484b-b93e-317c4366136e', '今度のサッカーの決勝戦では、どんなことでも起こりうる。', '今度のサッカーのけっしょうせんでは、どんなことでも起こりうる。', '这次的足球决赛，什么情况都有可能发生。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('a0c91e13-5729-417f-bbce-8782d4a931b5', 'c7456f31-2e38-484b-b93e-317c4366136e', '他人の夢の中に潜入して、アイディアを盗むなんてありえない話だ。', '他人の夢の中にせんにゅうして、アイディアをぬすむなんてありえない話だ。', '潜入别人的梦里，窃取别人的点子什么的，简直是天方夜谭。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('c1fabbae-07f5-461c-a0d8-6b6b1b032a38', 'c7456f31-2e38-484b-b93e-317c4366136e', '根性がないと、この目標を達しえないでしょう。', 'こんじょうがないと、このもくひょうをたっしえないでしょう。', '没有毅力的话是无法达成这个目标的吧。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('7309ada5-dbc5-410b-ba59-5e87528509d4', 'c7456f31-2e38-484b-b93e-317c4366136e', '株式相場がこれからどう動くか予測し得ない。', 'かぶしきそうばがこれからどううごくかよそくえない。', '无法预测股票行情今后将如何变化。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('0a326fcd-2c6d-4f49-8af4-6619def055c0', '～ 甲[か] 斐[い]があって/甲斐がある/甲斐がない/甲斐もなく', NULL, 'N2', '動た形/名－の＋甲斐がある/甲斐がない/甲斐もなく', '動た形/名－の＋甲斐がある/甲斐がない/甲斐もなく', '“有……的价值、回报”“没有白……”。', '「～かいがなく/かいもなく」是「～かいがない」在句中的中顿形式。', 221, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('94164203-efbe-4a75-962c-e3b8b703b6ee', '0a326fcd-2c6d-4f49-8af4-6619def055c0', '3時間待ったかいがあって、雨がやみ、美しい景色を見ることができた。', '3時間待ったかいがあって、雨がやみ、美しいけしきを見ることができた。', '三个小时没有白等，雨停了，欣赏到了美丽的风景。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('16091750-8659-49b2-ac24-6435a683410a', '0a326fcd-2c6d-4f49-8af4-6619def055c0', '応援の甲斐もなく、私のクラスのチームは一勝もできなかった。', 'おうえんの甲斐もなく、私のクラスのチームはいっしょうもできなかった。', '啦啦队的加油助威也没有起作用，我们队未能赢得一场比赛。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('bbb37d70-1d22-4b70-af82-0c6c4bdc4b5b', '0a326fcd-2c6d-4f49-8af4-6619def055c0', '必死の練習のかいもなく、オリンピックの代表選手には選ばれなかった。', 'ひっしの練習のかいもなく、オリンピックのだいひょうせんしゅにはえらばれなかった。', '没有被选为奥运会参赛选手，拼命练习都白费了。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('04f3f3ed-3016-490e-b5d4-866a5756e1c8', '～がきっかけで/がきっかけになって/をきっかけに（して）/をきっかけとして', NULL, 'N2', '動普通形－の/名＋がきっかけで/がきっかけになって/をきっかけに（して）/をきっかけとして', '動普通形－の/名＋がきっかけで/がきっかけになって/をきっかけに（して）/をきっかけとして', '“以……为契机、机会”。', '「～がきっかけで/がきっかけになって」有“……成为了契机”的含义，「～をきっかけに/をきっかけとして」有“以……为契机”的含义，两种形式有细微差别。', 222, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('104866d9-47e6-4323-b989-b487d3b4164b', '04f3f3ed-3016-490e-b5d4-866a5756e1c8', '恵まれない子どもたちの姿を見たのがきっかけで、この支援活動を始めたのです。', 'めぐまれない子どもたちの姿を見たのがきっかけで、このしえんかつどうを始めたのです。', '自从看到这些穷苦的孩子们的样子，我就开始了这项援助活动。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('3afd4d2d-6675-4857-96aa-d63be5af6c88', '04f3f3ed-3016-490e-b5d4-866a5756e1c8', '田中さんは、あるパーティーで友達から一人の女性を紹介された。それをきっかけに、田中さんはその女性と交際を始めたそうだ。', 'たなかさんは、あるパーティーで友達から一人の女性をしょうかいされた。それをきっかけに、田中さんはその女性とこうさいを始めたそうだ。', '在一次聚会上，朋友给田中介绍了一位小姐。据说以此为契机，田中开始和那位小姐交往了。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('68743908-1684-4027-91da-de715f294fe3', '04f3f3ed-3016-490e-b5d4-866a5756e1c8', '引っ越しをきっかけに、家具を買い換えた。', 'ひっこしをきっかけに、かぐをかいかえた。', '以搬家为契机，换了新家具。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('22f0cc43-e679-40c9-aab4-fa77a285a66b', '～ 限[かぎ]り（は）', NULL, 'N2', '動辞書形·可能形/名－の＋限り', '動辞書形·可能形/名－の＋限り', '表示最大限度，“尽量……”“竭尽……”。\n表示条件，“只要……就……”。', '表示达到极限，惯用表达有「力の限り（用尽全力）」「声の限り（发出最大声音）」「命の限り（拼命地）」「 見[み] 渡[わた]す限り（视线范围之内）」。\n表示在前项状态持续的期间，会发生后项的情况或状态，包含“如果前项条件不成立，后项的状态也有可能发生变化”的意思。', 223, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('8938e324-7eed-4abd-8059-24590122533c', '22f0cc43-e679-40c9-aab4-fa77a285a66b', '父は仕事が生きがいで、定年後も働ける限りは働きたいと言っている。', '父は仕事が生きがいで、ていねんごも働ける限りは働きたいと言っている。', '父亲视工作为生存的意义，说退休之后只要还能工作就想继续工作。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('8e21d002-927f-49e5-b66e-f757258bde3f', '22f0cc43-e679-40c9-aab4-fa77a285a66b', '思いつくかぎりのアイデアはすべて出したが、社長は認めてくれなかった。', '思いつくかぎりのアイデアはすべて出したが、社長はみとめてくれなかった。', '能想到的主意都提出来了，但都没有得到社长的认可。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('a039f558-60db-48b2-841e-9844e2fd90fb', '22f0cc43-e679-40c9-aab4-fa77a285a66b', '山奥で道に迷い、声の限りに助けを求めた。', 'やまおくで道に迷い、声の限りにたすけをもとめた。', '在深山里迷了路，竭力求救。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('ff4ccf70-16ef-4011-86e2-94a49b85bea3', '22f0cc43-e679-40c9-aab4-fa77a285a66b', '生きているかぎり、うれしいことも悲しいことも必ずある。', '生きているかぎり、うれしいことも悲しいことも必ずある。', '只要活着，就一定会有开心的事情和悲伤的事情。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('71f92b54-117a-4ecd-8e62-7e177e19a5f4', '22f0cc43-e679-40c9-aab4-fa77a285a66b', '定年になっても元気な限り、働き続けたいと思っている人が増えている。', 'ていねんになっても元気な限り、はたらきつづけたいと思っている人が増えている。', '即使退休，只要身体硬朗，就想继续工作的人在增加。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('e470e012-a409-4f41-8538-08cae828a5f7', '22f0cc43-e679-40c9-aab4-fa77a285a66b', '医者であるかぎり、患者を助けるために必死に頑張らなければならない。', 'いしゃであるかぎり、かんじゃを助けるためにひっしに頑張らなければならない。', '只要身为医生，就必须为了救助患者而拼命努力。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('25db733a-9a10-45b2-bed4-7908d21d9a69', '～ 限[かぎ]りでは', NULL, 'N2', '動辞書形·た形·ている形＋限りでは', '動辞書形·た形·ている形＋限りでは', '表示在某个限定的范围之内，“据……所知”“据……调查”等。', '常与「見る（看见）」「知る（知道）」「聞く（听）」「調べる（调查）」等表示认知的动词搭配使用，是说话人保有余地的说法，包含“在……范围内是这样的，但在这个范围之外是什么情况就不知道了”的意思。', 224, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('8acece69-bdc2-408b-abf6-d1dd52069415', '25db733a-9a10-45b2-bed4-7908d21d9a69', 'きのう私が調べた限りでは、工場の機械に問題はなかった。', 'きのう私が調べた限りでは、こうじょうのきかいに問題はなかった。', '据我昨天的调查，工厂的机器没有问题。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('ada15b2b-41a1-4dda-8d82-2c9d9c89afe0', '25db733a-9a10-45b2-bed4-7908d21d9a69', 'わたしの見る限りでは、彼は信頼できる人物だ。', 'わたしの見る限りでは、彼はしんらいできるじんぶつだ。', '在我看来，他是一个值得信赖的人。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('a0795493-3deb-4aed-89f2-932a46330eca', '25db733a-9a10-45b2-bed4-7908d21d9a69', '私が聞いた限りでは、双方はまだ合意に達していない。', '私が聞いた限りでは、そうほうはまだごういにたっしていない。', '据我所听到的，双方尚未达成一致。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('d03827ac-295f-4885-97a5-0b8f89865d2d', '～が 契[けい] 機[き]で/が契機になって/を契機に（して）/を契機として', NULL, 'N2', '動普通形－の/名＋が契機で/が契機になって/を契機に（して）/を契機として', '動普通形－の/名＋が契機で/が契機になって/を契機に（して）/を契機として', '“以……为契机、机会”。', '与包含「きっかけ」的几个句型意思相同，属于书面语。', 225, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('15aa7a5e-2862-4a39-a1c4-880681d7a658', 'd03827ac-295f-4885-97a5-0b8f89865d2d', '数週間の入院生活で、健康の大切さを実感した。これを契機に、もっと健康に気をつけて生活しようと決心した。', '数週間のにゅういん活で、健康の大切さをじっかんした。これを契機に、もっと健康に気をつけて生活しようと決心した。', '通过几个星期的住院生活，我切身体会到了健康的重要性，决定以此为契机，在生活中更加注意健康。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('1630c747-bc2a-4e54-8000-5af0f9dd1d23', 'd03827ac-295f-4885-97a5-0b8f89865d2d', '会社名が変わるのを契機に社員の制服も新しくすることが決められた。', 'かいしゃめいが変わるのを契機に社員のせいふくも新しくすることが決められた。', '以更改公司名称为契机，员工的制服也决定换成新的了。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('50dcbdb8-2c19-4e85-9404-47faafd6fbf5', 'd03827ac-295f-4885-97a5-0b8f89865d2d', '今回の業務提携を契機に、今後さまざまな分野での交流が期待される。', '今回のぎょうむていけいを契機に、今後さまざまなぶんやでの交流がきたいされる。', '以这次的业务合作为契机，期待今后在各个领域的交流。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('e6e82649-308e-4725-98d3-58398865d197', '～かけだ/かける', NULL, 'N2', '動ます形＋かけだ/かける', '動ます形＋かけだ/かける', '表示某动作开始后还没有结束，“没……完”“……做到一半”。', '既可以表示具体的动作做到一半没有结束（如第一和第二个例句），也可以表示某个状态已经开始发生（如第三个例句）。\n「～かけだ」用在句末结句；「～かけの」后面接名词；「～かける」可用在句中修饰名词，也可用在句末结句。', 226, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('10909dcb-504c-4c16-916d-8d99715355f4', 'e6e82649-308e-4725-98d3-58398865d197', 'テーブルの上に食べかけのケーキがおいてある。', 'テーブルの上に食べかけのケーキがおいてある。', '桌上放着没吃完的蛋糕。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('48f0c35f-5893-466e-afff-deb31a467e49', 'e6e82649-308e-4725-98d3-58398865d197', 'テーブルの上においた読みかけの本を母がかたづけてしまった。', 'テーブルの上においた読みかけの本を母がかたづけてしまった。', '母亲把放在桌上看到一半的书给收起来了。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('fe6c7a49-b477-4a2f-b623-4e7026fcd998', 'e6e82649-308e-4725-98d3-58398865d197', '家の前で死にかけていた野良猫を拾って動物病院に連れていった。', 'のらねこをひろってどうぶつびょういんにつれていった。', '在家门前捡到一只快死的野猫，带它去了动物医院。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('317ee636-404d-40eb-815b-0df3eb459f0f', '～がちだ', NULL, 'N2', '動ます形/名＋がちだ', '動ます形/名＋がちだ', '表示倾向，“容易……”“往往会……”。', '表示容易发生某种负面的、消极的事情。\n「～がち」的活用相当于ナ形容词。「～がちだ」用在句末结句；「～がちの/な」后面接名词。\n「～がち」前面接名词时表示容易产生该名词所表示的状态；接动词时，表示频繁发生某种行为，强调发生次数多。', 227, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('f8deec4e-e9c4-42c5-ac2f-bb8fdd607190', '317ee636-404d-40eb-815b-0df3eb459f0f', '「自分がされてうれしいことは相手もうれしい」とつい思ってしまいがちだが、相手が嫌がる場合もあるので、気をつけようと思う。', '「自分がされてうれしいことは相手もうれしい」とつい思ってしまいがちだが、相手がいやがる場合もあるので、気をつけようと思う。', '人总有这种倾向，认为“如果做了那些别人为自己做会令自己开心的事情，对方也会开心”，但其实对方有时候会觉得讨厌，所以我想要引起注意。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('1bfc5472-5cae-472a-8cd1-a44668dc865a', '317ee636-404d-40eb-815b-0df3eb459f0f', 'あの学生は体が弱くて、授業を休みがちだ。', 'あの学生は体が弱くて、授業を休みがちだ。', '那个学生身体虚弱，经常请假不来上课。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('576e9501-8914-418f-8e5e-c42316823750', '317ee636-404d-40eb-815b-0df3eb459f0f', '先日、病気がちのおばを見舞いに行った。', 'せんじつ、病気がちのおばを見舞いに行った。', '前些天我去看了体弱多病的姨妈。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('deb894d2-b9f6-4a19-a56e-08081465c479', '～かというと/かといえば', NULL, 'N2', '～かというと/かといえば', '～かというと/かといえば', '“至于是否……”“是不是……就……”。', NULL, 228, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('1bb3b0dc-3fd9-4181-a98f-1b9e99309e90', 'deb894d2-b9f6-4a19-a56e-08081465c479', '文章がうまければ誰でも作家になれるかというと、そんなことはない。', 'ぶんしょうがうまければ誰でも作家になれるかというと、そんなことはない。', '是不是文章写得好就都能成为作家，其实并不是那样。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('9eb3f077-24ef-41da-9d59-2ba8bb6edceb', 'deb894d2-b9f6-4a19-a56e-08081465c479', 'きのう財布を忘れて出かけたが、困ったかといえば、それほどでもなかった。', 'きのう財布を忘れて出かけたが、困ったかといえば、それほどでもなかった。', '昨天出门忘了带钱包，要说是否很不便，其实也还好。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('c71574d1-27fe-41d8-8a6a-7fc4ebc0fc57', 'deb894d2-b9f6-4a19-a56e-08081465c479', '歌を聞くのが好きだが、歌うのが上手なのかといえば、そうでもない。', '歌を聞くのが好きだが、歌うのが上手なのかといえば、そうでもない。', '虽然喜欢听歌，但要说是不是很会唱歌，其实也并非如此。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('86837ff7-d722-4bc0-8668-b8292e6cf9f1', '～かと 思[おも]えば', NULL, 'N2', '動辞書形·た形/名＋かと思えば', '動辞書形·た形/名＋かと思えば\n動辞書形＋かと思えば', '“原以为……却……”。\n表示并列，“既……又……”。', '后项是与说话人预想相反的事情。\n常与「ある/いる」搭配使用，构成「～かと思えば～もある/いる」，表示“既有……又有……”。', 229, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('a0f037e7-cb85-4faf-8139-a4d299a03566', '86837ff7-d722-4bc0-8668-b8292e6cf9f1', '9月に入ってやっと涼しくなったかと思えば、また急に暑くなったりして残暑が厳しい。', '9月に入ってやっと涼しくなったかと思えば、また急に暑くなったりしてざんしょがきびしい。', '到了九月份，原以为终于要凉快了，却突然变热，秋老虎还很厉害。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('cfc44961-5862-419e-a58c-1be15c6eeb9d', '86837ff7-d722-4bc0-8668-b8292e6cf9f1', '息子は学校から帰ってきたかと思えば、またすぐ遊びに出かけていった。', '息子は学校から帰ってきたかと思えば、またすぐ遊びに出かけていった。', '原以为儿子从学校回来了，却又马上出去玩了。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('5e7b1b09-e680-4879-b2ae-e674e0170f48', '86837ff7-d722-4bc0-8668-b8292e6cf9f1', '老後を一人で生きることを選ぶ熟年夫婦がいるかと思えば、新しい旅立ちに向けて、退職後豪華な旅行に出る夫婦もいる。', 'ろうごを一人で生きることをえらぶじゅくねんふうふがいるかと思えば、新しいたびだちにむけて、たいしょくごごうかな旅行に出る夫婦もいる。', '有的中老年夫妻选择独自一人度过晚年，也有些夫妻打算一同踏上新的旅程———退休后参加豪华旅游。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('1d873afb-15c0-4f48-91fe-d694ff2cd468', '86837ff7-d722-4bc0-8668-b8292e6cf9f1', '百歳を越えて生きる人がいるかと思えば、一歳になることもなく、この世を去る赤ん坊もいる。', 'ひゃくさいをこえて生きる人がいるかと思えば、いっさいになることもなく、このよをさるあかんぼうもいる。', '既有活过百岁的寿星，也有还不到一岁就离开人世的婴儿。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('99283290-bea8-4b20-8ebe-97f65f3dec84', '86837ff7-d722-4bc0-8668-b8292e6cf9f1', '拾った落し物をわざわざ交番まで届けにいく人がいるかと思えば、人の物を盗む者もいる。', '拾ったおとしものをわざわざこうばんまで届けにいく人がいるかと思えば、人の物をぬすむ者もいる。', '有人捡到了东西特地交去派出所，却也有人偷别人的东西。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('409b06e5-c06b-4051-a926-cf021936a8d6', '～か～ないかのうちに', NULL, 'N2', '動辞書形＋か＋動ない形－ない＋かのうちに', '動辞書形＋か＋動ない形－ない＋かのうちに', '表示两件事情几乎同时发生，“刚……就……”“还没……就……”。', '使用同一个动词的肯定和否定形式。\n前后项的两个动作几乎是同时发生，并且包含了“前项动作甚至还没有完成就发生了后项的动作”的意思。\n用于描述已经发生的事实，后项不能是表示命令、意志、推量、否定的内容，并且只能是过去时。', 230, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('f1d95206-bf74-4c4e-bb53-707fe78eb188', '409b06e5-c06b-4051-a926-cf021936a8d6', 'ピクニックの日の朝、娘はとてもうれしそうにしていた。「いってきます」と言い終わるか終わらないかのうちに玄関を飛び出していった。', 'げんかんをとびだしていった。', '要去野餐的那天早上，女儿显得非常高兴。刚说完“我走了”，就跑出了大门。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('d0b57892-b513-424c-b996-26d69774e8fd', '409b06e5-c06b-4051-a926-cf021936a8d6', '先生の講義が終わるか終わらないかのうちに、ノートや教科書を閉じて片付けはじめる学生もいる。', '先生のこうぎが終わるか終わらないかのうちに、ノートや教科書を閉じて片付けはじめる学生もいる。', '老师的课还没结束，就有学生把笔记本和教科书合上开始整理东西了。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('55e276fc-679e-45d6-aab8-7cdff6c1fbb3', '409b06e5-c06b-4051-a926-cf021936a8d6', '電車に乗るか乗らないかのうちに、ドアが閉まってしまった。', '電車に乗るか乗らないかのうちに、ドアが閉まってしまった。', '刚乘上电车，门就关上了。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('9f766d7f-e29a-4b8c-930f-7e5838dfb222', '～かねる/かねない', NULL, 'N2', '動ます形＋かねる', '動ます形＋かねる\n動ます形＋かねない', '“很难……”“难以……”。\n表示可能，“有可能……”。', '包含了“即使想做某事也很难做到”的意思。惯用表达有「決めるに決めかねる（难以决定）」「見るに見かねて（不忍目睹）」。\n属于书面语，用于礼貌地、委婉地拒绝别人的要求等，如「分かりかねます（不知道）」「出来かねます（不能）」。\n用肯定的形式来表示否定的意义。\n相当于「～かもしれない」，不同的是「～かねない」一般表示可能带来负面的、不好的结果。', 231, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('b204c0c2-67f0-42f0-8f85-bfb83dbb9577', '9f766d7f-e29a-4b8c-930f-7e5838dfb222', '面接試験ではどんな質問が出るのかと聞かれたが、そのようなことを聞かれてもちょっと答えかねる。', '面接試験ではどんな質問が出るのかと聞かれたが、そのようなことを聞かれてもちょっと答えかねる。', '有人问我面试时会提什么样的问题，这样的问题我很难回答。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('0cd226af-3e72-4d51-8dc7-b098557ab32f', '9f766d7f-e29a-4b8c-930f-7e5838dfb222', '労働条件の変更について会社から説明を受けたが、私はどうも納得しかねる。', 'ろうどうじょうけんのへんこうについて会社から説明を受けたが、私はどうもなっとくしかねる。', '有关劳动条件的变更虽然已经听取了公司方的说明，但我还是难以接受。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('ff9bdb37-24cd-4c30-857d-547015ebdd70', '9f766d7f-e29a-4b8c-930f-7e5838dfb222', 'ご要望には応じかねますので、ご了承ください。', 'ごようぼうにはおうじかねますので、ごりょうしょうください。', '我们很难满足您的要求，请见谅。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('d901a1ba-ff28-45eb-867c-4b49bc346528', '9f766d7f-e29a-4b8c-930f-7e5838dfb222', 'A「あんなに大きなけがをしたんだから、危険なことはもう二度とやらないでしょうね。」B「いや、彼だったらまたやりかねないよ。」', 'A「あんなに大きなけがをしたんだから、きけんなことはもう二度とやらないでしょうね。」B「いや、彼だったらまたやりかねないよ。」', 'A：“受了那么严重的伤，以后应该不会再做这么危险的事情了吧。”\nB：“不，是他的话，以后还有可能再做的。”', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('3a8b1d3e-617b-45f9-8509-58bda86da317', '9f766d7f-e29a-4b8c-930f-7e5838dfb222', '適度なスポーツは健康にいいといわれるが、やりすぎると体をこわしかねない。', 'てきどなスポーツは健康にいいといわれるが、やりすぎると体をこわしかねない。', '适当的运动有益健康，但是运动过度也可能会损坏身体。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('c4b05830-bf35-41cc-9ccb-9767a314506a', '9f766d7f-e29a-4b8c-930f-7e5838dfb222', '私は忘れっぽいほうなので、こんな所に傘を置いておくと、帰りにまた忘れかねない。', '私は忘れっぽいほうなので、こんな所に傘を置いておくと、帰りにまた忘れかねない。', '我属于比较健忘的，如果把伞放在这种地方，很可能回去的时候就忘记了。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('4d1e68be-7736-4cad-808b-2541afcf0791', '～かのようだ', NULL, 'N2', '動普通形＋かのようだ', '動普通形＋かのようだ', '“就像……一样”。', '包含了“虽然实际上不是这样，但是表现得就像是那样”的意思。「～かのようだ」用在句末结句；「～かのような」后面接名词；「～かのように」用在句中作状语。', 232, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('e3f7654b-d549-46c1-b17c-dcde3d631679', '4d1e68be-7736-4cad-808b-2541afcf0791', 'もう秋になるのに、今日の暑さはまるで真夏に戻ったかのようでエアコンをつけた家も多かったらしい。', 'もう秋になるのに、今日の暑さはまるでまなつに戻ったかのようでエアコンをつけた家も多かったらしい。', '已经要入秋了，但今天热得就像是回到了盛夏一般，似乎有很多人家里都开了空调。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('ce80fd57-c82c-45cf-a184-6e463707fe75', '4d1e68be-7736-4cad-808b-2541afcf0791', '賞をもらったのは弟だというのに、彼女の喜ぶようすは自分が賞をもらったかのようだ。', 'しょうをもらったのは弟だというのに、彼女の喜ぶようすは自分が賞をもらったかのようだ。', '虽然得奖的是弟弟，但她就像是自己得了奖一样高兴。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('cc5b73d6-46c2-40fe-88a0-0f82d9fd9472', '4d1e68be-7736-4cad-808b-2541afcf0791', 'この人形はとてもよく作られていて、生きているかのようだ。', 'このにんぎょうはとてもよく作られていて、生きているかのようだ。', '这个玩偶做得很逼真，就像是活的一样。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('80f30c0f-7cf0-43d2-962c-f5d3fb510717', '～からいいようなものの', NULL, 'N2', '文の普通形＋からいいようなものの', '文の普通形＋からいいようなものの', '“（因为……）幸好（这次）……”。', '包含了“虽然这次避免了某种不好的事态的发生，但是并不能掉以轻心”的意思。类似的句型还有「～からよかったものの」。', 233, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('2c259c17-3cf9-402f-a936-a5828e24b4f1', '80f30c0f-7cf0-43d2-962c-f5d3fb510717', 'この大事な資料が見つかったからいいようなものの、万が一、紛失したらどうするんだ。', 'この大事な資料が見つかったからいいようなものの、まんがいち、ふんしつしたらどうするんだ。', '幸好找到了这份重要的资料，万一找不到该怎么办。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('3c71507e-1d9c-4d43-b0e6-21e254ac3e7b', '80f30c0f-7cf0-43d2-962c-f5d3fb510717', '火事にならなかったからいいようなものの、これからたばこの火の始末に注意してください。', 'かじにならなかったからいいようなものの、これからたばこのひのしまつに注意してください。', '幸好没有发生火灾，今后要注意熄灭烟头。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('530ce689-2364-4250-ad3b-118c501dbbe5', '80f30c0f-7cf0-43d2-962c-f5d3fb510717', '今回は事故が起こらなかったからいいようなものの、これからよく注意しないといけないですね。', '今回は事故が起こらなかったからいいようなものの、これからよく注意しないといけないですね。', '幸好这次没发生事故，以后一定要注意。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('bafe29cd-e9e4-4953-b7f2-8ba55cf4d817', '80f30c0f-7cf0-43d2-962c-f5d3fb510717', 'あなたがたまたま確認してくれたからよかったものの、もう少しで原稿の締め切りに間に合わなくなるところだった。', 'あなたがたまたまかくにんしてくれたからよかったものの、もう少しでげんこうのしめきりに間に合わなくなるところだった。', '幸好你碰巧帮我确认，否则差一点就要赶不上交稿日期了。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('0d0f19d1-2116-4d77-9354-de5cb66d707d', '～からこそ', NULL, 'N2', '文の普通形＋からこそ', '文の普通形＋からこそ', '强调原因，“正因为……”。', '「こそ」表示强调，接在表示原因的「から」后面用来强调这个原因很重要，包含“不是因为别的，就是因为这个原因”的意思，是说话人主观的判断，因此不能用于表示客观的原因。\n一般不用于表示负面的原因。', 234, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('76c188cd-3b7d-4a01-85ec-317d39c66daf', '0d0f19d1-2116-4d77-9354-de5cb66d707d', '電子メールが普及している今の時代であるからこそ、手書きの手紙に温かい気持ちを感じる。', '電子メールがふきゅうしている今の時代であるからこそ、手書きの手紙に温かい気持ちを感じる。', '正因为当今时代电子邮件相当普及，手写的信才让人倍感温馨。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('24c60275-4e15-469e-8a54-acabfb4c93df', '0d0f19d1-2116-4d77-9354-de5cb66d707d', '田中監督が選手たちに厳しくするのは、一度は優勝を経験させたいと願うからこそだ。', 'たなかかんとくが選手たちに厳しくするのは、一度は優勝を経験させたいと願うからこそだ。', '田中教练对运动员们很严厉，正是因为想让他们体验一下夺冠的滋味。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('3c1c6bd3-67e4-4f3c-ae75-e385550217a6', '0d0f19d1-2116-4d77-9354-de5cb66d707d', '好きなことを職業にする人が多いが、私は映画が好きだからこそ、職業にはしないことにした。', '好きなことをしょくぎょうにする人が多いが、私は映画が好きだからこそ、職業にはしないことにした。', '很多人把喜欢的事情当成自己的职业，而我正是因为喜欢电影，才没有把它当成我的职业。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('0022236a-f84d-4995-804d-7ad78bc7f2bf', '～からして', NULL, 'N2', '名＋からして', '名＋からして', '表示判断的依据，“单从……来看”。', '表示某一事物包含多个因素，仅从其中一个因素去判断整体，包含“别的怎么样先不说，单从这一点看就……”的意思。', 235, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('11161adc-7099-48c0-9bff-fdb8b4e3755d', '0022236a-f84d-4995-804d-7ad78bc7f2bf', '私は彼のことが大嫌いだ。彼の話し方や服装からしてがまんならない。', '私は彼のことがだいきらいだ。彼の話し方やふくそうからしてがまんならない。', '我很讨厌他。光是他说话的方式和着装就很受不了。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('7cf6234e-4a35-4421-96c2-4dc685976374', '0022236a-f84d-4995-804d-7ad78bc7f2bf', '田中さんのプランは、その発想からして独特だ。', 'たなかさんのプランは、そのはっそうどくとくだ。', '田中的计划，单从创意来看就很独特。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('f492f0fb-7b43-452f-8d1b-0fdbf5c1dad5', '0022236a-f84d-4995-804d-7ad78bc7f2bf', 'このレストラン、雰囲気からして結構高そうだね。', 'このレストラン、ふんいきけっこう高そうだね。', '这家餐厅，单从氛围来看就好像很贵。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('d5c5f291-4ed8-4948-aa04-cf8b8c41d75d', '～からといって', NULL, 'N2', '文の普通形＋からといって', '文の普通形＋からといって', '表示转折，“不能因为……就……”“虽说……但是……”。', '相当于「～だけの理由で」，前项提出一个原因，后项对其进行否定，认为这个原因不成立或不充分。口语中也可以简单说成「～からって」。', 236, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('4252511b-527e-4109-a049-0e6db81fdaa6', 'd5c5f291-4ed8-4948-aa04-cf8b8c41d75d', 'しばらく連絡がないからといって、そんなに心配することないよ。', 'しばらく連絡がないからといって、そんなに心配することないよ。', '虽说有一段时间没有联系了，但是也没必要那么担心。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('67d286f5-6f0e-4adb-90c5-a85e84bbb698', 'd5c5f291-4ed8-4948-aa04-cf8b8c41d75d', '一度ぐらい断られたからといって、そんなに簡単にあきらめないでください。', '一度ぐらいことわられたからといって、そんなに簡単にあきらめないでください。', '不要因为一次被拒绝就轻易放弃。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('fa0abe96-0bd4-4484-b0f3-60aca50b7b8c', 'd5c5f291-4ed8-4948-aa04-cf8b8c41d75d', 'いくらお金がたくさんあるからといって、使いすぎるのはよくない。', 'いくらお金がたくさんあるからといって、使いすぎるのはよくない。', '不管再怎么有钱，挥霍总归是不好的。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('e6ec464f-77ed-4ecf-beb9-8fc7ded5a3a3', '～からには', NULL, 'N2', '～からには', '～からには', '“既然……就……”。', '与「～以上は」「～上は」意思相同。口语中可简单说成「～からは」。', 237, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('55caf0b6-190e-4e91-916c-be22ad1bc69c', 'e6ec464f-77ed-4ecf-beb9-8fc7ded5a3a3', 'いったん引き受けたからには、納得できる仕事をしたい。', 'いったん引き受けたからには、なっとくできる仕事をしたい。', '既然答应做这项工作，就想把它做好。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('4e454e83-7b47-489c-a6a2-cc22d9ee156a', 'e6ec464f-77ed-4ecf-beb9-8fc7ded5a3a3', '何回も話し合ってみんなで決めたことだ。決めたからには成功するように頑張ろう。', '何回も話し合ってみんなで決めたことだ。決めたからには成功するように頑張ろう。', '这是大家讨论了几次决定下来的事情。既然已经决定了，就让我们为了成功而努力吧。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('3ca1ea97-3c27-4ef5-94af-ff91eec6d90e', 'e6ec464f-77ed-4ecf-beb9-8fc7ded5a3a3', '約束したからには、どんなことがあっても守らなければならない。', '約束したからには、どんなことがあっても守らなければならない。', '既然已经约好了，无论发生什么事情都必须要遵守。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('fc4c305a-ab0b-4da2-bc53-93ffa1705369', '～ 代[か]わりに', NULL, 'N2', '動/イ形/ナ形/名の名詞修飾形＋代わりに', '動/イ形/ナ形/名の名詞修飾形＋代わりに', '表示代替，交换。\n表示事物相反的两面，“虽然……但是……”。', '接名词时，表示代替某人去做某事。接动词时，常常表示“回报，补偿，交换条件”等。\n表示某个事物既有前项积极的一面，也有后项消极的一面，而且两者是相互关联的，往往存在一定程度的因果关系。', 238, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('fa767767-431b-4250-abe9-93d2cc9c3697', 'fc4c305a-ab0b-4da2-bc53-93ffa1705369', 'スーツケースを貸すかわりに、食事をごちそうしてもらった。', 'スーツケースをかすかわりに、食事をごちそうしてもらった。', '我借行李箱给他，（作为回报）他请我吃了饭。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('f396adf6-1fc3-47f5-8d64-5b629c00ed73', 'fc4c305a-ab0b-4da2-bc53-93ffa1705369', 'ノートを貸してもらったかわりに、昼ごはんをごちそうしよう。', 'ノートを貸してもらったかわりに、昼ごはんをごちそうしよう。', '你借了笔记给我，（作为回报），我请你吃午饭吧。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('8511e326-ace5-4209-99c1-876fff933360', 'fc4c305a-ab0b-4da2-bc53-93ffa1705369', '山田先生の授業は試験を受けるかわりに、レポートを出してもよいことになっている。', 'やまだ先生の授業は試験を受けるかわりに、レポートを出してもよいことになっている。', '山田老师的课可以以提交小论文的形式代替考试。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('628d54e8-da84-4ab5-bc93-09cbe74d71de', 'fc4c305a-ab0b-4da2-bc53-93ffa1705369', 'この仕事は安定しているかわりに、給料があまり高くない。', 'この仕事はあんていしているかわりに、給料があまり高くない。', '这份工作虽然很稳定，但工资不怎么高。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('385fdb87-b4d3-444e-a506-57bfcab9ce58', 'fc4c305a-ab0b-4da2-bc53-93ffa1705369', 'インターネットの普及でさまざまな情報が手に入るかわりに、人とのコミュニケーションが少なくなった。', 'インターネットのふきゅうでさまざまなじょうほうが手に入るかわりに、人とのコミュニケーションが少なくなった。', '由于互联网的普及人们可以得到各种各样的信息，但与人的交流却变少了。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('4b508219-ab23-4182-a71d-2e7549f7f7d3', 'fc4c305a-ab0b-4da2-bc53-93ffa1705369', '都市化が進んでいく中で、面倒くさい近所づきあいから解放されたかわりに、子育ての援助者を失っていく。', 'としかが進んでいく中で、めんどうくさいきんじょづきあいからかいほうされたかわりに、こそだてのえんじょしゃをうしなっていく。', '在城市化不断发展的过程中，人们虽然摆脱了近邻之间麻烦的交往，但也失去了养育孩子的援助者。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('b36669ea-d72f-4350-8acd-d34fb9abbc80', '～ 気[ぎ] 味[み]', NULL, 'N2', '動ます形/名＋気味', '動ます形/名＋気味', '表示倾向，程度，“稍微……”“有点儿……”。', '一般用于说话人自己的感觉，并且多用于表示不好的事情。', 239, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('a1fc030b-0f68-497b-a487-9573d890b58c', 'b36669ea-d72f-4350-8acd-d34fb9abbc80', 'このところ忙しくて少し疲れぎみだから、今日は早く帰ることにした。', 'このところ忙しくて少し疲れぎみだから、今日は早く帰ることにした。', '最近很忙，感觉有点儿累，所以决定今天早点回去。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('43699422-207a-47d8-8afb-23ada42e97d8', 'b36669ea-d72f-4350-8acd-d34fb9abbc80', '昨日から風邪気味で、だるくて何もする気になりません。', '昨日から風邪気味で、だるくて何もする気になりません。', '昨天开始有点儿感冒，身体乏力，什么都不想干。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('3368029e-0575-4c17-93aa-66c2671f472f', 'b36669ea-d72f-4350-8acd-d34fb9abbc80', '最近食べ過ぎのせいか、太り気味だ。', 'さいきんべ過ぎのせいか、ふとり気味だ。', '最近大概是吃多了，感觉有点儿胖了。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('f7b2935d-c4ff-49a4-9a86-a23542978ba8', '～きり/きりだ', NULL, 'N2', '動辞書形·た形/名＋きり', '動辞書形·た形/名＋きり\n動た形＋きり/きりだ', '表示限定，“只有……”。\n表示前项发生以后，就再也没有发生后项。“一……就再没……”。', '表示限定时，相当于「～だけ」。\n表示发生前项之后，其状态一直持续，并且再也没有发生后项。\n「～きりだ」用在句末结句，暗示之后再也没有发生过前项的事情。「～きりで」用在句中中顿，表示再也没有发生后项表示的某件事。\n惯用表达有「寝たきり」，表示“卧床不起”。', 240, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('422b034b-4071-4d11-948a-35e0587331cc', 'f7b2935d-c4ff-49a4-9a86-a23542978ba8', '赤ちゃんが生まれてから、夫婦二人きりで旅行するなんて不可能だ。', '赤ちゃんが生まれてから、ふうふ二人きりで旅行するなんてふかのうだ。', '孩子出生以后，就不可能夫妻两个人去旅游了。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('3bd93786-e146-4103-b4b4-cd9e8a6d9899', 'f7b2935d-c4ff-49a4-9a86-a23542978ba8', '一回きりの人生だから、楽しく過ごしたい。', 'いっかいきりのじんせいだから、楽しく過ごしたい。', '人生只有一次，所以想开心地度过。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('d1afd4f1-0b0d-4297-9ad8-7fb1b5dc21ab', 'f7b2935d-c4ff-49a4-9a86-a23542978ba8', '今朝の新聞は見出を読んだきりで、具し体的な内容はまだ読んでいない。', 'けさの新聞はみだを読んだきりで、ぐしたいてきなないようはまだ読んでいない。', '今天早上的报纸只看了标题，具体内容还没看。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('58c6edb5-58c1-4a43-8e95-0099ec1d8323', 'f7b2935d-c4ff-49a4-9a86-a23542978ba8', '田中「あれ？木村さん、だいぶ髪が伸びましたね。」木村「ええ、半年前に切ったきり一度も切ってないんですよ。」', '田中「あれ？木村さん、だいぶ髪がのびましたね。」木村「ええ、はんとし前に切ったきり一度も切ってないんですよ。」', '田中：“咦？木村，你头发长了很多嘛。”\n木村：“是啊，自从半年前剪过之后就一次都没剪过。”', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('36c97441-3856-46e0-98d4-55586c0346c9', 'f7b2935d-c4ff-49a4-9a86-a23542978ba8', 'こんな難しい曲はひけませんよ。ギターは20年前に習ったきりですから。', 'こんな難しいきょくはひけませんよ。ギターは20年前にならったきりですから。', '这么难的曲子我可弹不了。我已经二十年没碰过吉他了。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('c4150d17-4d0c-454e-88cb-bc577a023fb3', 'f7b2935d-c4ff-49a4-9a86-a23542978ba8', '本田さんとは20年前に一度会ったきりだ。', 'ほんださんとは20年前に一度会ったきりだ。', '我与本田自二十年前见过一面之后就再也没有见过。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('d6738def-e1e4-484a-85d2-7971025c79e4', '～げ', NULL, 'N2', '動ます形/イ形語幹/ナ形語幹＋げ', '動ます形/イ形語幹/ナ形語幹＋げ', '表示样态，“像……似的”“看上去……”。', '「～げ」表示从人或事物的外观上加以判断，给人以某种感觉，活用相当于ナ形容词。', 241, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('ac5ec11f-a55b-46da-8b55-97f87d87314e', 'd6738def-e1e4-484a-85d2-7971025c79e4', '彼女は彼の告白に恥ずかしげに「いいよ」と答えた。', '彼女は彼のこくはくに恥ずかしげに「いいよ」と答えた。', '对他的告白，她有点害羞地回答“好的”。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('cac77384-0425-4861-8543-a728be6aa927', 'd6738def-e1e4-484a-85d2-7971025c79e4', '彼女は何か言いたげな顔をしてこちらを見ている。', '彼女は何か言いたげな顔をしてこちらを見ている。', '她好像想说什么似的看着我。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('19e84858-b9c0-42fb-ad97-b585557554df', 'd6738def-e1e4-484a-85d2-7971025c79e4', '喫茶店に入ると、退屈げに雑誌のページをめくっている彼の姿が目に映った。', '喫茶店に入ると、たいくつげに雑誌のページをめくっている彼の姿が目に映った。', '一走进咖啡厅就看到了正在无聊地翻着杂志的他。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('827362ac-3695-4d6e-a743-f5aa95d1a4e9', '～ことから', NULL, 'N2', '～ことから', '～ことから', '表示原因或依据。“因为……”；“从……来看”。', '可以表示前项是后项的原因（如第一和第二个例句），还可以表示前项是后项的依据（如第三个例句）。', 242, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('ee5ea19d-4fc0-4773-9ccf-1defc2b15e3b', '827362ac-3695-4d6e-a743-f5aa95d1a4e9', '彼は何でもよく知っていることから、友達に「博士」と呼ばれている。', '彼は何でもよく知っていることから、友達に「はかせ」と呼ばれている。', '因为他什么都很懂，所以被朋友们称为“博士”。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('b4ab5cd8-b896-4d45-8200-d337c5f44b8e', '827362ac-3695-4d6e-a743-f5aa95d1a4e9', '都心では、子どもが少なくなっていることから、学校の数も減りつつある。', 'としんでは、子どもが少なくなっていることから、学校の数も減りつつある。', '在城市，由于儿童的数量在逐渐减少，所以学校的数量也不断减少。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('37155df8-350e-4cc3-bfba-09d6d604ebc2', '827362ac-3695-4d6e-a743-f5aa95d1a4e9', '指紋が一致したことから、彼は犯人に特定された。', 'しもんがいっちしたことから、彼ははんにんにとくていされた。', '因指纹吻合，他被认定为罪犯。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('1fd8279a-918e-4cfa-affd-a8cb228f3274', '～ことだから', NULL, 'N2', '名＋の＋ことだから', '名＋の＋ことだから', '表示说话人判断的依据，“因为是……”。', '一般接在表示人物的名词后面，表示该人物具有某种特征，说话人通过对他的这一性格特征的了解做出某种判断，包含“因为他是这样的一个人，所以……”的意思。', 243, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('28ce1e64-ec3f-4194-8158-ad9de22791da', '1fd8279a-918e-4cfa-affd-a8cb228f3274', 'スポーツなら何でもやる鈴木さんのことだから、きっとスキーも上手でしょう。', 'スポーツなら何でもやるすずきさんのことだから、きっとスキーも上手でしょう。', '铃木什么运动都参加，想必也很擅长滑雪吧。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('f50e49af-95d4-469b-86b5-1a97aef44360', '1fd8279a-918e-4cfa-affd-a8cb228f3274', '山田さんはもともと世話好きで、誰に対しても親切だ。そんな彼女のことだから、困っている友達をほうっておけなかったのだろう。', 'やまださんはもともとせわずきで、誰に対してもしんせつだ。そんな彼女のことだから、困っている友達をほうっておけなかったのだろう。', '山田本来就是个热心肠的人，对谁都很热情。这样的她，是不会对处于困境的朋友视而不见的吧。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('3bb929f6-6963-4fac-ba93-2ec902e72603', '1fd8279a-918e-4cfa-affd-a8cb228f3274', '「山本さんは遅いですね。」「ええ。でも、まじめなあの人のことだから必ず来ますよ。」', '「やまもとさんは遅いですね。」「ええ。でも、まじめなあの人のことだから必ず来ますよ。」', '“山本可真慢呀。”\n“是啊。但他是个认真严谨的人，所以肯定会来的。”', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('271c4281-a3ee-48e6-904e-89e77b07dc88', '～ことなく', NULL, 'N2', '動辞書形＋ことなく', '動辞書形＋ことなく', '表示否定，“不……”。', '相当于「～ないで/ずに」，属于书面语。', 244, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('9edfdebf-0ea8-40d6-9b74-9474ed11cbfa', '271c4281-a3ee-48e6-904e-89e77b07dc88', '失敗を恐れることなく、行動してほしい。', 'しっぱいをおそれることなく、こうどうしてほしい。', '希望你做事情不要害怕失败。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('6ed26c50-529b-41ee-8fe1-8650bb85f309', '271c4281-a3ee-48e6-904e-89e77b07dc88', '日本人は、自分の意見をあまり主張しないと言われている。周りの雰囲気に流されることなく、言いにくいこともはっきり言うべきだ。', '日本人は、自分の意見をあまりしゅちょうしないと言われている。周りのふんいきに流されることなく、言いにくいこともはっきり言うべきだ。', '都说日本人不怎么说出自己的想法。我觉得不要受周围的氛围的影响，即使是很难说出口的事情也应该讲清楚。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('4bf0b639-1859-4b6e-8e60-f69e01a2e369', '271c4281-a3ee-48e6-904e-89e77b07dc88', '彼は1日も休むことなく小説を書き続けている。', '彼は1日も休むことなく小説を書き続けている。', '他不停地写着小说，一天都没有休息过。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('584aabc6-1725-4307-be26-9f06bbc50350', '～ごとに', NULL, 'N2', '動辞書形/名＋ごとに', '動辞書形/名＋ごとに', '“每……”“每当……”。', '表示反复出现的完整的事情的每一次。以前项为单位，或每逢前项出现就会呈现后项的状态或出现后项的结果。', 245, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('9ee6eaa3-89ca-4a55-b46a-153a0e484e55', '584aabc6-1725-4307-be26-9f06bbc50350', '毎朝、配達員が家ごとに新聞を配る。', '毎朝、はいたついんが家ごとに新聞を配る。', '每天早晨，配送人员都会挨家挨户地送报纸。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('1124c1ac-699f-452d-9275-63baf3001709', '584aabc6-1725-4307-be26-9f06bbc50350', 'この目覚まし時計は5分ごとに鳴るように設定されている。', 'このめざましどけいは5分ごとに鳴るようにせっていされている。', '这个闹钟被设定为每隔五分钟响一次。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('813843ac-331a-4b26-b75f-23848abe9dc2', '584aabc6-1725-4307-be26-9f06bbc50350', '秋は一雨ごとに涼しくなるという季節だ。', '秋はひとあめごとに涼しくなるという季節だ。', '秋天就是一阵秋雨一阵凉的季节。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('b95217cd-0b37-4a4f-b89f-975906444737', '～ことにはならない', NULL, 'N2', '動た形＋ことにはならない', '動た形＋ことにはならない', '“不能当作……”“不能算作……”。', '一般用在句末结句。', 246, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('a62d35ee-b113-4c16-8fbc-696217c63215', 'b95217cd-0b37-4a4f-b89f-975906444737', '本やインターネットの資料を写しただけではレポートを書いたことにはならない。', '本やインターネットの資料をうつしただけではレポートを書いたことにはならない。', '如果只是照抄书本或者网上的资料的话，不能算是写了小论文。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('9757244e-0f75-496e-9c9f-a561efc31d67', 'b95217cd-0b37-4a4f-b89f-975906444737', '正式な手続きを踏まないと、入社したことにはならない。', 'せいしきなてつづきをふまないと、にゅうしゃしたことにはならない。', '没有办理正式的手续就不能算作是入职。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('7ee3f790-b72b-4650-bd2b-e8526a1ee188', 'b95217cd-0b37-4a4f-b89f-975906444737', 'やり終わった作業の見直しまでしないと、仕事をやり遂げたことにはならない。', 'やり終わったさぎょうのみなおしまでしないと、仕事をやりとげたことにはならない。', '做完的工作如果没有重新检查一遍的话，就不能认为是完成了工作。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('14f369d6-0c53-4f68-826a-d7034f01faed', '～ことは～が', NULL, 'N2', '動/イ形の名詞修飾形＋ことは＋動/イ形普通形＋が', '動/イ形の名詞修飾形＋ことは＋動/イ形普通形＋が\nナ形語幹－な＋ことは＋ナ形語幹＋だ＋が', '表示让步，“……是……，但……”。', '表示虽然承认前项，但并不能给予肯定，后项提出消极的方面。\n前后项是使用同一个动词或同一个イ形、ナ形。', 247, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('94dd05dd-1e63-48f7-9a27-6b5738ccb00a', '14f369d6-0c53-4f68-826a-d7034f01faed', 'レポートは最後まで書いたことは書いたんですが、まだ足りない部分もあります。', 'レポートはさいごまで書いたことは書いたんですが、まだ足りないぶぶんもあります。', '报告写是写完了，但是还有不足的地方。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('337c698b-f558-4ef1-810e-933df26446c4', '14f369d6-0c53-4f68-826a-d7034f01faed', 'このレストランはおいしいことはおいしいが、値段が高すぎる。', 'このレストランはおいしいことはおいしいが、値段が高すぎる。', '这家餐厅的菜好吃是好吃，就是太贵了。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('427572ba-e74f-4bab-909b-03a240510eb4', '14f369d6-0c53-4f68-826a-d7034f01faed', 'スペイン語はわかることはわかるが、話し方が早いとうまく理解できない。', 'スペイン語はわかることはわかるが、話し方が早いとうまくりかいできない。', '西班牙语懂是懂一些，但如果说得快的话就无法很好地理解。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('adb4f4da-48b4-4361-87ab-b180247a1b03', '～ 際[さい]は/際に（は）', NULL, 'N2', '～ 際[さい]は/際に（は）', '～ 際[さい]は/際に（は）', '“在……时候”；“借……时机”。', '语气比「～とき」更书面，并且带有“时机、契机”的意思。', 248, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('f426480e-f789-43d1-af46-c56b8883ae90', 'adb4f4da-48b4-4361-87ab-b180247a1b03', '外出する際は、必ず鍵をかけるようにしてください。', 'がいしゅつする際は、必ず鍵をかけるようにしてください。', '外出的时候请一定把门锁好。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('d6bbefc5-3243-47e9-8879-9a9f29aef9d9', 'adb4f4da-48b4-4361-87ab-b180247a1b03', 'お近くにお越しの際には、ぜひわが家にお寄りください。', 'お近くにおこしの際には、ぜひわがやにおよりください。', '您经过我家附近的时候，请一定到我家来玩。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('e91db061-b066-46ba-9ea1-6bc28a63184d', 'adb4f4da-48b4-4361-87ab-b180247a1b03', '先月帰省した際に、高校の先生を訪ねた。', 'せんげつきせいした際に、こうこうの先生を訪ねた。', '上个月回老家时，借机去拜访了高中的老师。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('61f7984b-12cc-42a5-a2d2-5137fb914e17', '～ざるを 得[え]ない', NULL, 'N2', '動ない形＋ざるを得ない', '動ない形＋ざるを得ない\n（する→せざるを得ない）', '“不得不……”。', '属于书面语，表示除此之外别无他法。包含“本来不想做，但是迫于某种压力或原因而不得不去做”的意思。', 249, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('6e58cbe7-d0ab-4e42-a9ca-87af060149b4', '61f7984b-12cc-42a5-a2d2-5137fb914e17', '台風が近づいているので、明日からの旅行は、残念だが延期せざるを得ない。', 'たいふうが近づいているので、明日からの旅行は、残念だがえんきせざるを得ない。', '因为台风临近，虽然很遗憾，但明天开始的旅行不得不延期了。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('20b9efa7-e06b-476f-97a8-8ce0899877db', '61f7984b-12cc-42a5-a2d2-5137fb914e17', '2回も同じ間違いをするとは、注意が足りなかったと言わざるをえない。', '2回も同じまちがいをするとは、ちゅういが足りなかったと言わざるをえない。', '两次都犯了同样的错误，不得不说是不够注意。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('7c9f9b23-d12c-43b1-ac07-4ebc67f9bfce', '61f7984b-12cc-42a5-a2d2-5137fb914e17', '日本で生活をするのなら、漢字を覚えざるをえない。', '日本で生活をするのなら、かんじを覚えざるをえない。', '在日本生活的话，就不得不去学汉字。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('3cab7ada-9af7-4e0d-96f2-c7f4de163fe6', '～ 次[し] 第[だい]', NULL, 'N2', '動ます形＋次第', '動ます形＋次第', '表示前项刚一实现，马上就进行后项，“一……就（会）……”。', '前项一般是表示事情的自然经过或实际情况，后项是有意识的、积极的行为。由于后项是即将要做的事情，所以不能用过去时。', 250, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('388d4098-cbd3-4529-99ba-9697c1499b28', '3cab7ada-9af7-4e0d-96f2-c7f4de163fe6', '（広告で）現在、数量限定半額セールを実施中。商品がなくなり次第終了しますので、お早めに。', '（こうこくで）現在、数量げんていはんがくセールをじっしちゅうしゅうりょうしますので、お早めに。', '（广告）现在正在进行半价优惠，数量有限。商品售罄活动即止，请尽早行动。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('4ccfc11b-6fad-4907-afae-391766ab7921', '3cab7ada-9af7-4e0d-96f2-c7f4de163fe6', '検査の結果がわかり次第、ご連絡いたします。', 'けんさの結果がわかり次第、ごれんらくいたします。', '检查的结果一出来，我们会马上与您联系。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('fb64b0dd-704f-4e1f-90bd-8f002528fb2b', '3cab7ada-9af7-4e0d-96f2-c7f4de163fe6', '参加者の名前がわかり次第、教えていただけませんか。', 'さんかしゃの名前がわかり次第、教えていただけませんか。', '知道参加者名字之后，您能不能马上告诉我？', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('a134ff96-506e-4e68-a2f8-4cce4e5bf4cb', '～ 次[し] 第[だい]だ/次第で（は）', NULL, 'N2', '動/イ形/ナ形の名詞修飾形＋次第だ/次第で', '動/イ形/ナ形の名詞修飾形＋次第だ/次第で\n名＋次第だ/次第で（は）', '表示原委、情况。\n表示根据，“取决于……”“要看……来定”。', '解释事情发展至此的原委和经过，属于书面语。「～次第で」用在句中中顿；「～次第だ」用在句末结句。\n「～次第だ」用于句末；「～次第で（は）」用于句中。也有「～次第によって（は）」的形式，表示“根据……情况”。', 251, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('b7df5dd7-0361-41fd-8ddc-7782a3fec97e', 'a134ff96-506e-4e68-a2f8-4cce4e5bf4cb', '先日お伝えした日程に誤りがありましたので、今回、改めてご連絡を差し上げた次第です。', 'せんじつお伝えしたにっていにあやまりがありましたので、今回、あらためてご連絡をさしあげた次第です。', '由于前几天与您说的日期有误，所以现在再次和您联系。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('c5961cd2-3c49-4c41-9483-e75903e71156', 'a134ff96-506e-4e68-a2f8-4cce4e5bf4cb', '以上のような次第で、来週の社員旅行は延期にさせていただきます。', '以上のような次第で、来週の社員旅行はえんきにさせていただきます。', '由于上述情况，将下周的员工旅行延期。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('20c6c0de-c299-49e3-a168-ff7ac6c3c6d5', 'a134ff96-506e-4e68-a2f8-4cce4e5bf4cb', '父が病気のため、実家の豆腐屋を引き継いだ次第だ。', '父が病気のため、じっかのとうふやをひきついだ次第だ。', '由于父亲生病，我就继承了老家的豆腐店。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('44fcfa61-c2f2-4f8c-9ddb-5a81722753f2', 'a134ff96-506e-4e68-a2f8-4cce4e5bf4cb', 'あしたハイキングに行くかどうかは、お天気次第だ。', 'あしたハイキングに行くかどうかは、お天気次第だ。', '明天去不去郊游取决于天气。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('d44d96df-ea7e-4e74-8bc3-78a601983cb7', 'a134ff96-506e-4e68-a2f8-4cce4e5bf4cb', 'この製品は、アイデア次第でいろいろな使い方ができます。', 'このせいひんは、アイデア次第でいろいろな使い方ができます。', '这个产品，根据不同的构想可以有不同的使用方法。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('4b483617-a4ee-4230-86f0-72e72b66794c', 'a134ff96-506e-4e68-a2f8-4cce4e5bf4cb', '頼み方次第ではあの人もこの仕事を手伝ってくれるかもしれない。', '頼み方次第ではあの人もこの仕事を手伝ってくれるかもしれない。', '这项工作他也许也会帮忙的，就看如何拜托他了。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('d8ca0ce1-e751-4c96-9632-b04f36a699bf', '～ 末[すえ]（に）', NULL, 'N2', '動た形/名－の＋末（に）', '動た形/名－の＋末（に）', '表示结果，“经过……最后……”。', '包含“经过一番……最后终于……”的意思，强调经过了一个很长的过程，最后得出某个结论或者产生某个结果。', 252, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('20ef485d-2698-4a7f-85bf-de60e1ed476b', 'd8ca0ce1-e751-4c96-9632-b04f36a699bf', '鉄道会社と自治体による長期間の議論の末に、新駅の建設が決定された。', '鉄道会社とじちたいによるちょうきかんのぎろんの末に、しんえきの建設が決定された。', '铁路公司和自治团体进行了长时间的讨论，最终决定建设新车站。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('2d8bf439-81e2-4b25-ac8c-3f43921009ce', 'd8ca0ce1-e751-4c96-9632-b04f36a699bf', 'あれこれ悩んだ末に、ABC大学を志望校に決めた。', 'あれこれ悩んだ末に、ABC大学をしぼうこうに決めた。', '烦恼了许久，最终决定将ABC大学作为志愿填报的学校。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('1ba85421-6ce9-4d5a-ba86-f0b163586ba0', 'd8ca0ce1-e751-4c96-9632-b04f36a699bf', 'この新しい薬は、何年にもわたる研究の末に作り出されるものだ。', 'つくりだされるものだ。', '这种新药，是经过好几年的研究制造出来的。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('6b352738-e0ab-464d-afea-16f20e0a5eac', '～ずにすむ/ないですむ/なくてすむ', NULL, 'N2', '動ない形＋ずにすむ', '動ない形＋ずにすむ\n動ない形＋ないですむ\n動ない形＋なくてすむ\n（する→せずにすむ/しないですむ）', '“不……（也可以解决）”“不用……就可以了”。', '可以表示“不必做原本预定要做的事情”（如第一个例句和第三个例句），也可以表示“避免了可能会发生的事情”（如第二个例句）。', 253, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('bc82cd17-4a4f-483c-962b-2de05294c998', '6b352738-e0ab-464d-afea-16f20e0a5eac', '幸い友人が冷蔵庫をくれたので、新しいのを買わなくてすんだ。', 'さいわいゆうじんがれいぞうこをくれたので、新しいのを買わなくてすんだ。', '幸好朋友送给了我一台冰箱，所以我就不用买新的了。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('5710f14b-13db-490b-b0ad-ae03586b798b', '6b352738-e0ab-464d-afea-16f20e0a5eac', '今朝乗っていた電車が一時運転見合わせになったけど、早めに家を出たので遅刻せずにすんだ。', '今朝乗っていた電車がいちじうんてんみあわせになったけど、はやめに家を出たので遅刻せずにすんだ。', '今天早上乘的电车停止运行了一段时间，但因为提早出了门，所以没有迟到。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('008209a8-c211-44ea-b899-dc0b1c63ec67', '6b352738-e0ab-464d-afea-16f20e0a5eac', '今回は風邪の症状が軽かったので、病院に行かずに済んだ。', '今回は風邪のしょうじょうがかるかったので、病院に行かずに済んだ。', '这次的感冒症状很轻，所以没用得着去医院。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('9e039b25-9b73-48d5-a9a4-092e3afbf201', '～ずにはいられない/ないではいられない', NULL, 'N2', '動ない形＋ずにはいられない', '動ない形＋ずにはいられない\n動ない形＋ないではいられない\n（する→せずにはいられない/しないではいられない）', '表示迫切的心情，“不得不……”“不能不……”。', '表示控制不住做某事的心情或如果不做某事，心里会很不舒服。', 254, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('55c24836-2a39-49f6-ac71-d7e1dbae93fe', '9e039b25-9b73-48d5-a9a4-092e3afbf201', '書類のミスがあまり多かったので、担当者に文句を言わずにはいられなかった。', 'しょるいのミスがあまり多かったので、たんとうしゃにもんくを言わずにはいられなかった。', '由于文件上错误太多，所以不得不对负责人抱怨几句。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('daf0b08e-4528-40cf-9b74-a22784bf83c3', '9e039b25-9b73-48d5-a9a4-092e3afbf201', 'お世話になった先生が突然入院されたと聞いて、私は心配で病院に行かずにはいられなかった。', 'おせわになった先生がとつぜんにゅういんされたと聞いて、私は心配で病院に行かずにはいられなかった。', '听到关照过我的老师突然住院的消息，很是担心，忍不住要去看他。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('02087bd9-d95f-4f0b-9ba9-4445a875f710', '9e039b25-9b73-48d5-a9a4-092e3afbf201', '台風の被害にあった人々のため、一日も早い生活環境の整備を願わずにはいられない。', '台風のひがいにあった人々のため、一日も早い生活かんきょうのせいびを願わずにはいられない。', '由衷希望为那些在台风中受难的群众尽早完善其生活环境。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('74df7629-529f-47b8-927b-a60db0a671b8', '～たいばかりに/ほしいばかりに', NULL, 'N2', '動ます形＋たいばかりに', '動ます形＋たいばかりに\n名＋が＋ほしいばかりに', '表示原因，“就是因为想……”。', '表示为了实现某种急切的愿望而不辞辛劳去做某事，或者不择手段去做某事，包含“一心想……”的意思。', 255, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('5387c973-bce9-43fb-9d88-5f5986316577', '74df7629-529f-47b8-927b-a60db0a671b8', 'ブランドバッグを手に入れたいばかりに、夏休みは一生懸命アルバイトをした。', 'ブランドバッグを手に入れたいばかりに、夏休みはいっしょうけんめいアルバイトをした。', '就是因为想买名牌包，暑假才拼命打工的。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('6ccbbf8b-2dca-4b65-b50b-f771f7ed543c', '74df7629-529f-47b8-927b-a60db0a671b8', '好きな歌手のコンサートを見に行きたいばかりに、病気にかこつけて休みを取った。', '好きな歌手のコンサートを見に行きたいばかりに、病気にかこつけて休みを取った。', '就是因为想去看喜欢的歌手的演唱会，才以生病为借口请假的。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('db4c0499-f97b-4036-a429-24ecc9de28d3', '74df7629-529f-47b8-927b-a60db0a671b8', '仕事を早く終わらせたいばかりに、昼休みも取らずに頑張った。', '仕事を早く終わらせたいばかりに、昼休みも取らずに頑張った。', '就是因为想早点把工作做完，中午没有休息在努力干活。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('5d93d982-669d-4fc9-aa48-8b1dfee79bdb', '～だけあって/だけに/だけのことはある', NULL, 'N2', '～だけあって/だけに/だけのことはある', '～だけあって/だけに/だけのことはある', '“与……相称”“不愧是……”；“到底没白……”。\n“正因为……更加……”。\n“正因为……反倒……”。', '表示与其身份、地位、经历等相称，后项对其进行正面的评价。此时，「だけ/だけあって/だけに/だけのことはある」等几种形式都能使用，常与「さすがに」呼应使用。\n相当于「～だけに、なおさら」，表示“正因为前项的原因，后项才更加……”，此时一般使用「だけに」。\n相当于「～だけに、かえって」，表示“正因为……反而更加……”。此时一般使用「だけに」。', 256, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('baeb274f-6a68-455e-89b5-41534cd29283', '5d93d982-669d-4fc9-aa48-8b1dfee79bdb', '多くの観光客が訪れるだけあって、確かに山からの眺めはすばらしかった。', '多くのかんこうきゃくがおとずれるだけあって、確かに山からの眺めはすばらしかった。', '这里不愧是游客云集的地方，从山上眺望的景色的确很美。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('8bfb4c3c-9d71-46e0-a648-8df26c737f8f', '5d93d982-669d-4fc9-aa48-8b1dfee79bdb', '彼はチームのキャプテンだけあって、みんなに信頼されている。', '彼はチームのキャプテンだけあって、みんなにしんらいされている。', '他不愧是队长，大家都很信赖他。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('4fe3e85a-bb6b-4b56-8858-29a67324b476', '5d93d982-669d-4fc9-aa48-8b1dfee79bdb', '彼女は英語の発音がとてもきれいで、アメリカへ留学しただけのことはある。', '彼女は英語のはつおんがとてもきれいで、アメリカへ留学しただけのことはある。', '她的英语发音很好听，到底没白去美国留学。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('3a69de2a-2881-47ff-b1b2-2ad8d7760e53', '5d93d982-669d-4fc9-aa48-8b1dfee79bdb', '山に登るのに苦労しただけに、頂上で見た風景は最高だった。', '山に登るのに苦労しただけに、ちょうじょうで見たふうけいはさいこうだった。', '正因为登山的过程很辛苦，爬到山顶后看到的风景才觉得格外美丽。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('21cd3477-8d16-45c4-9bc0-9ab95d682fa7', '5d93d982-669d-4fc9-aa48-8b1dfee79bdb', '妹はもともと体が弱いだけに、風邪を引いても心配だ。', '妹はもともと体が弱いだけに、風邪を引いても心配だ。', '正因为妹妹身体本来就很虚弱，所以就算是感冒也让人担心。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('f0d75af8-e082-4f2a-8486-d2ff5ff5cda4', '5d93d982-669d-4fc9-aa48-8b1dfee79bdb', 'こちらは壊れやすいものだけに、取り扱いには十分気をつけてください。', 'こちらは壊れやすいものだけに、とりあつかいには十分気をつけてください。', '这件物品因为容易损坏，所以请轻拿轻放。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('e44cebe0-2123-45a1-80d3-af4befaf1e78', '5d93d982-669d-4fc9-aa48-8b1dfee79bdb', '体に自信があるだけに、かえって無理をして体を壊してしまった。', '体に自信があるだけに、かえってむりをして体を壊してしまった。', '正因为对身体有信心，所以反倒逞强弄坏了身体。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('ae3f32ae-f5a9-46f5-a999-debd9031bcea', '5d93d982-669d-4fc9-aa48-8b1dfee79bdb', '優勝することを期待していただけに、負けたときの失望は大きかった。', 'ゆうしょうすることをきたいしていただけに、負けたときのしつぼうは大きかった。', '正因为一直很期待取得胜利，所以失败时非常失望。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('9829f046-3378-43ea-9c84-7b6bc437f76c', '5d93d982-669d-4fc9-aa48-8b1dfee79bdb', '鈴木課長は普段静かなだけに、怒り出すとすごく怖い。', 'すずき課長は普段静かなだけに、怒り出すとすごくこわい。', '正因为铃木课长平时很温和，生起气来十分吓人。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('4e08c1b3-a063-4cd1-a913-0ae20fd8cf6b', '～たところ', NULL, 'N2', '動た形＋ところ', '動た形＋ところ', '表示做了前项的动作之后，发生或发现了后项的结果。', '相当于「～たら」。', 257, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('fa7654d7-d37c-4960-9cad-f66224cc361f', '4e08c1b3-a063-4cd1-a913-0ae20fd8cf6b', '仕事の合間にときどき遠くを見るようにしたところ、目が疲れにくくなった。', '仕事のあいまにときどき遠くを見るようにしたところ、目が疲れにくくなった。', '工作的间隙有时会望望远处，这样眼睛就不容易疲劳了。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('0e1ba55a-af3c-4597-91cc-54759dc26f2d', '4e08c1b3-a063-4cd1-a913-0ae20fd8cf6b', '山田さんの家へ遊びに行ったところ、ちょうど川本さんがきていた。', 'やまださんの家へ遊びに行ったところ、ちょうどかわもとさんがきていた。', '我去山田家玩，结果川本也来了。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('d337f5df-5a44-4de7-abe1-9ad4376707d1', '4e08c1b3-a063-4cd1-a913-0ae20fd8cf6b', '会場の問い合わせをしたところ、地図を送ってくれた。', 'かいじょうの問い合わせをしたところ、地図を送ってくれた。', '我咨询了一下会场的情况，就给我寄来了地图。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('ba0a4cc6-5426-48cf-9401-b13f0d02de97', '～たところが', NULL, 'N2', '動た形＋ところが', '動た形＋ところが', '表示逆接，“然而……”“虽然……可是……”。', '表示逆接时，一定要用「～たところが」的形式，后项的结果是与预想、期待相反的。', 258, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('2fd7019a-1004-433b-92c6-b8bf10486d27', 'ba0a4cc6-5426-48cf-9401-b13f0d02de97', '田中さんならわかるだろうと思って聞いてみたところが、彼にもわからないという。', 'たなかさんならわかるだろうと思って聞いてみたところが、彼にもわからないという。', '我想田中的话大概会知道的，就问了问，可他说他也不知道。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('e24467a2-67f2-46f2-b460-df602ee90ad8', 'ba0a4cc6-5426-48cf-9401-b13f0d02de97', '今朝は早めに出かけたところが、交通事故に巻き込まれ遅刻してしまった。', 'けさははやめに出かけたところが、こうつうじこにまきこまれ遅刻してしまった。', '今天早上提早出门，可遇到交通事故，迟到了。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('fef11f6f-fca1-4207-be30-134dbe096d33', 'ba0a4cc6-5426-48cf-9401-b13f0d02de97', '昔住んでいた町を訪ねたところが、様子がすっかり変わっていて迷ってしまった。', 'むかし住んでいた町を訪ねたところが、ようすがすっかり変わっていて迷ってしまった。', '去了过去住过的街道，完全变了样，都不认识了。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('eeef08d1-9b22-4498-ac25-897e3a86b1a4', '～たところで', NULL, 'N2', '動た形＋ところで', '動た形＋ところで', '“即使……也……”，表示逆接。', '该句型表示即便像前项那样也未必能达到期待的结果，后项多为否定的表达方式。该句型经常与「たとえ/どんなに/いくら」等词一起使用。', 259, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('bf8ba433-c64a-4e0e-b16d-07a56b596b99', 'eeef08d1-9b22-4498-ac25-897e3a86b1a4', 'どんなに一生懸命働いたところで、生活は楽にならないだろう。', 'どんなに一生懸命働いたところで、生活はらくにならないだろう。', '再怎么拼命工作，生活也不会变得轻松的吧。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('069e3ae3-335e-41f3-b5e7-db0088b95d5f', 'eeef08d1-9b22-4498-ac25-897e3a86b1a4', 'もともと勉強する気がないのなら、大学を受けてみたところで何の意味があるのか。', 'もともと勉強する気がないのなら、大学を受けてみたところで何のいみがあるのか。', '如果原本就没心思学习，那就算参加了大学入学考试又有何意义呢？', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('df896f5f-5cc7-4d88-8ae0-e417d9d07a09', 'eeef08d1-9b22-4498-ac25-897e3a86b1a4', 'いくら話し合ったところで、この問題を解決することはできません。', 'いくら話し合ったところで、この問題をかいけつすることはできません。', '再怎么协商，这个问题也是没法解决的。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('8041ed1b-037a-4b5f-9564-5034bb724da1', '～たとたん（に）', NULL, 'N2', '動た形＋とたん（に）', '動た形＋とたん（に）', '“一……就……”“刚……就……”。', '前项刚一发生接着就发生了后项，后项多是意料之外的事情，并且是说话人亲历的已经发生了的事情，因此句末只能是过去时。\n后项不能是表示命令、意志、推量、否定的内容。', 260, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('78d66e14-c5b6-4cb7-882e-26fb0836d520', '8041ed1b-037a-4b5f-9564-5034bb724da1', '事務所のかぎをしめたとたんに、中で電話が鳴りはじめた。', 'じむしょのかぎをしめたとたんに、中で電話が鳴りはじめた。', '刚刚把事务所的门锁上，里面的电话就响起来了。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('66fd40ed-a465-4121-a179-282662f179a6', '8041ed1b-037a-4b5f-9564-5034bb724da1', '国から来た手紙を見たとたん、彼女は泣き出してしまった。', '国から来た手紙を見たとたん、彼女は泣き出してしまった。', '她一看到从老家寄来的信，就哭起来了。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('0880df2b-28c5-4aa6-831c-583599e7f7d9', '8041ed1b-037a-4b5f-9564-5034bb724da1', '暑くなったとたん、ビールの売れ行きがよくなった。', '暑くなったとたん、ビールのうれゆきがよくなった。', '天一热，啤酒的销路就变好了。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('29aa85a2-dc64-4dd8-b1c6-822559909cb2', '～ついでに', NULL, 'N2', '～ついでに', '～ついでに', '“顺便……”。', '主要是做前项的事情，顺便做后项的事情。「ついでに」也有作为接续词的功能。', 261, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('c79ecdc2-0ebe-450e-982c-825fe37ab500', '29aa85a2-dc64-4dd8-b1c6-822559909cb2', '展覧会に行ったついでに近くの公園をぶらぶら散歩してきた。', 'てんらんかいに行ったついでに近くの公園をぶらぶら散歩してきた。', '去展览会时顺便去附近的公园悠闲地散了会儿步。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('2cbf21dc-b835-4209-b9c6-f5cb9c7c9e34', '29aa85a2-dc64-4dd8-b1c6-822559909cb2', '母は駅まで客を送っていったついでに買い物をしてきた。', '母は駅まで客を送っていったついでに買い物をしてきた。', '妈妈送客人去车站，顺便买了点东西回来。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('76fc0fbf-da47-4977-b404-fe7b065c6d16', '29aa85a2-dc64-4dd8-b1c6-822559909cb2', '札幌出張のついでに、雪祭りを見物した。', 'さっぽろ出張のついでに、ゆきまつりをけんぶつした。', '去札幌出差，顺便去参观了冰雪节。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('4e0a2bbe-def3-4229-91b8-8614f33e9561', '～っこない', NULL, 'N2', '動ます形＋っこない', '動ます形＋っこない', '表示强烈的否定，“不可能……”。', '一般用于口语，表示对某件事发生的可能性进行强烈的否定。', 262, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('6939c743-d498-461c-b7c7-cb5111717610', '4e0a2bbe-def3-4229-91b8-8614f33e9561', 'こんなに弱い選手ばかりでは、次の試合に勝てっこない。', 'こんなに弱い選手ばかりでは、次の試合に勝てっこない。', '尽是这么弱的选手的话，是无法在下次的比赛中获胜的。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('880ef63a-28e3-4729-94b4-40a80cdf9ac9', '4e0a2bbe-def3-4229-91b8-8614f33e9561', 'この話は、今初めてあなただけにしたんだから、あなたが言わなければ、ほかの人は知りっこないよ。', 'この話は、今初めてあなただけにしたんだから、あなたが言わなければ、ほかの人は知りっこないよ。', '这件事情我第一次说，而且只告诉了你，所以如果你不说的话，别的人是不可能知道的。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('def6d540-feab-4ebc-b215-3aaabd272546', '4e0a2bbe-def3-4229-91b8-8614f33e9561', '1日10時間も勉強するなんて、私にはできっこないよ。', '1日10時間も勉強するなんて、私にはできっこないよ。', '一天学习十个小时，我可做不到。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('36cb09c0-11ac-4d0f-b0d1-fccb2c6ec4ab', '～つつ（も）', NULL, 'N2', '動ます形＋つつ', '動ます形＋つつ\n動ます形＋つつ（も）', '表示两个动作同时进行，“一边……一边……”。\n表示逆接，“虽然……但是……”。', '相当于「～ながら」，表示进行一个动作的同时进行另外一个动作，比「～ながら」更书面化。注意此时要用「つつ」，不用「つつも」。\n相当于「～けれども/のに」。表示逆接时「も」可用可不用。', 263, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('9063b2d2-b4a9-4a57-a2c5-f25600606fe1', '36cb09c0-11ac-4d0f-b0d1-fccb2c6ec4ab', '辞書を引きつつ英字新聞を読んでいる。', 'えいじ新聞を読んでいる。', '一边查字典一边看英文报纸。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('5c28a1f3-1d98-445b-848b-561aebf9af1a', '36cb09c0-11ac-4d0f-b0d1-fccb2c6ec4ab', '資金のことを考えつつ、工事を進めていく。', 'しきんのことを考えつつ、こうじをすすめていく。', '一面考虑资金的问题，一面去开展工程。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('c9e3f4ce-9178-4ea6-8fd0-ffba823129ae', '36cb09c0-11ac-4d0f-b0d1-fccb2c6ec4ab', 'もう起きなければと思いつつも、なかなか起きられない。', 'もう起きなければと思いつつも、なかなか起きられない。', '虽然想着得起床了，但是怎么也起不来。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('511bb495-1e58-48c1-ae1e-d4c43c4d5732', '36cb09c0-11ac-4d0f-b0d1-fccb2c6ec4ab', 'タバコは体に悪いと知りつつも、つい吸ってしまう。', 'タバコは体に悪いと知りつつも、つい吸ってしまう。', '虽然知道抽烟对身体不好，但还是忍不住去抽。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('55a2ee76-2788-4e45-a103-b77be6aeda2a', '36cb09c0-11ac-4d0f-b0d1-fccb2c6ec4ab', '口では「頑張る」と言いつつも、心の中では落ちてもいいと思っていた。', '口では「頑張る」と言いつつも、心の中では落ちてもいいと思っていた。', '虽然嘴上说“我会努力的”，但心里却想着即使没考上也没关系。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('968e80dd-ed64-480b-84d7-5d30c148066b', '～つつある', NULL, 'N2', '動ます形＋つつある', '動ます形＋つつある', '“正在……”。', '表示某个动作正在进行中，或者某个变化在不断发展。', 264, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('5832e36d-7886-4f29-95d7-046d8d9657de', '968e80dd-ed64-480b-84d7-5d30c148066b', '環境問題への関心が高くなり、車ではなく電車を利用する人が増えつつある。', 'かんきょうもんだいへのかんしんが高くなり、車ではなく電車をりようする人が増えつつある。', '对环境越来越关心，不开车而去乘电车的人在不断增加。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('a7e7ff82-011d-4397-b5ca-3dfd7aaab931', '968e80dd-ed64-480b-84d7-5d30c148066b', '多くの国で公害が年々ひどくなっているが、一方では、それをなくすために、技術協力をする国々も増えつつある。', '多くの国でこうがいがねんねんひどくなっているが、いっぽうでは、それをなくすために、ぎじゅつきょうりょくをするくにぐにも増えつつある。', '在很多国家，公害问题日益严重，而另一方面，为消除公害而进行技术合作的国家也在不断增加。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('085f184e-3303-4ae0-a04d-b1aa3aba6bf8', '968e80dd-ed64-480b-84d7-5d30c148066b', '政府は景気が緩やかに回復しつつあると発表した。', 'せいふはけいきがゆるやかにかいふくしつつあるとはっぴょうした。', '政府宣布经济形势正在平缓复苏。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('68365bb6-ec1f-49ac-add0-33fa62d2d989', '～っぱなし', NULL, 'N2', '動ます形＋っぱなし', '動ます形＋っぱなし', '前面接续自动词，表示主体的某一动作、状态一直持续。“一直……”。\n前面接续他动词，表示做了某一一次性的动作，该动作形成的状态一直持续着。“一直……”。', '常用「立ちっぱなし（一直站着）」「座りっぱなし（一直坐着）」「動きっぱなし（一直忙着）」等。\n多用于负面的评价。\n常用「置きっぱなし」「出しっぱなし」「開けっぱなし」等。', 265, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('203496dc-0719-4fae-924a-aa11ee103e14', '68365bb6-ec1f-49ac-add0-33fa62d2d989', '電車の中はあいにく空席がなくて、ずっと立ちっぱなしだった。', '電車の中はあいにくくうせきがなくて、ずっと立ちっぱなしだった。', '刚好没有空位置，所以在电车里一直站着。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('fc01006a-64fa-468b-ac58-1bc59edbe6fb', '68365bb6-ec1f-49ac-add0-33fa62d2d989', 'この物件は値段が高すぎるせいか、借りる人がいなくて、半年ぐらい空きっぱなしだ。', 'このぶっけんは値段が高すぎるせいか、借りる人がいなくて、はんとしぐらいあきっぱなしだ。', '这套房子可能是价格太贵，没有人愿意租，一直空了半年。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('a7f36747-853d-47d6-85ae-638d76104102', '68365bb6-ec1f-49ac-add0-33fa62d2d989', '母は働き者で、朝から晩まで動きっぱなしだ。', '母ははたらきもので、朝からばんまで動きっぱなしだ。', '妈妈闲不住，从早到晚一直在忙。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('fb6d57d2-27b9-48e0-86b3-978d6a36115e', '68365bb6-ec1f-49ac-add0-33fa62d2d989', '妹「お兄ちゃん、部屋の電気、つけっぱなしだよ。」兄「あ、ごめん、ごめん。」', '妹「お兄ちゃん、部屋の電気、つけっぱなしだよ。」兄「あ、ごめん、ごめん。」', '妹妹：“哥，你房间的灯一直开着。”\n哥哥：“啊，不好意思，不好意思。”', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('80ca024a-4822-41ea-85e9-dd1135a701c5', '68365bb6-ec1f-49ac-add0-33fa62d2d989', '水を出しっぱなしにして、歯を磨くのはもったいないですよ。', '水を出しっぱなしにして、はをみがくのはもったいないですよ。', '刷牙的时候一直开着水龙头的话很浪费水。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('ab393b5a-c270-42df-b6fa-4d84db98e3e7', '68365bb6-ec1f-49ac-add0-33fa62d2d989', 'ドアを開けっぱなしにして出かけました。', 'ドアを開けっぱなしにして出かけました。', '开着门就出去了。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('01713bd8-67cc-43b1-8e73-b408f8358d08', '～っぽい', NULL, 'N2', '動ます形/イ形語幹/名＋っぽい', '動ます形/イ形語幹/名＋っぽい', '表示有某种感觉或倾向，“看上去……”“感觉……”；“容易……”。', '接在名词和イ形容词的后面表示具有前面的名词或形容词所表示的性质，接在动词后面表示容易产生该动词所表示的行为。\n「～っぽい」的活用相当于イ形容词。\n惯用表达有「子どもっぽい（孩子气的）」「白っぽい（发白的）」「水っぽい（水分过多的；掺水的）」「熱っぽい（感觉有点发烧）」「湿っぽい（潮湿的；阴郁的）」「安っぽい（廉价的）」「忘れっぽい（健忘的）」「怒りっぽい（易怒的）」「飽きっぽい（容易厌倦的）」。', 266, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('e1a24996-bd59-48ab-b73a-df197b6b56dd', '01713bd8-67cc-43b1-8e73-b408f8358d08', '大人のくせに、そんなつまらないことでけんかするのは子どもっぽい。', '大人のくせに、そんなつまらないことでけんかするのは子どもっぽい。', '明明是大人了，却为了那么无聊的事情大发脾气，真是很孩子气。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('0b3c3c9c-6020-4558-b9ae-f2b298953f4b', '01713bd8-67cc-43b1-8e73-b408f8358d08', '叔父の持ち込んだもうけ話は、どうもうそっぽいです。', 'おじのもちこんだもうけ話は、どうもうそっぽいです。', '叔叔说的有关赚钱的事情，感觉像是骗人的。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('fc3a627f-c83e-46ed-af9f-a0bbf0fb4929', '01713bd8-67cc-43b1-8e73-b408f8358d08', '私は忘れっぽいほうなので、こんな所に傘を置いておくと、帰りにまた忘れかねない。', '私は忘れっぽいほうなので、こんな所に傘を置いておくと、帰りにまた忘れかねない。', '我属于比较健忘的，所以如果把伞放在这种地方，很有可能回去的时候就忘记了。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('a6ca90ec-236e-405b-9cc7-47d006a13dfb', '～てからでないと/てからでなければ', NULL, 'N2', '動て形＋からでないと/からでなければ', '動て形＋からでないと/からでなければ', '表示如果不先做前项，就无法做后项。“如果不先……就……”。', '前项是后项实现的前提条件。', 267, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('458e114e-5eb4-48af-b3b2-56c2e601969c', 'a6ca90ec-236e-405b-9cc7-47d006a13dfb', '哲学Ⅱの授業は、哲学Ⅰの単位を取得してからでないと、受けることができません。', 'てつがくⅡの授業は、哲学Ⅰの単位を取得してからでないと、受けることができません。', '不先取得哲学Ⅰ这门课的学分，就没法上哲学Ⅱ这门课。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('d61bbf0b-922f-4d6e-b620-13073a69b6a6', 'a6ca90ec-236e-405b-9cc7-47d006a13dfb', '今日の宿題が終わってからでないと、遊びにいけない。', '今日の宿題が終わってからでないと、遊びにいけない。', '如果不先把今天的作业做完的话，就不能去玩。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('5a19050e-06f9-4c01-8b64-a95532361979', 'a6ca90ec-236e-405b-9cc7-47d006a13dfb', 'となりの子どもはうちへ帰るとすぐ宿題を終わらせ、部屋を片付ける。となりのうちでは、そうしてからでないと、遊びに行かせてもらえないのだ。', 'となりの子どもはうちへ帰るとすぐ宿題を終わらせ、部屋を片付ける。となりのうちでは、そうしてからでないと、遊びに行かせてもらえないのだ。', '隔壁家的孩子一回家马上把作业完成，然后收拾房间。在他们家，要是不先做完这些的话，就不让孩子出去玩。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('84063059-6664-4093-9181-9ac50496cd0e', '～てでも', NULL, 'N2', '動て形＋でも', '動て形＋でも', '表示采取强硬的手段，“就是……也要……”。', '表示为了达到某一目的而采取强硬的手段，后项表达了说话人强烈的愿望和意志。', 268, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('ade70e2e-5fbd-4a3d-8c2b-eedc91b153f7', '84063059-6664-4093-9181-9ac50496cd0e', '大企業の社長という地位を捨ててでも、私にはやりたいことがある。', 'だいきぎょうの社長というちいをすててでも、私にはやりたいことがある。', '就算是舍弃大公司社长的地位，我也有我想做的事情。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('6d523f36-cadd-44fd-9e1f-72bdf382e689', '84063059-6664-4093-9181-9ac50496cd0e', '今日の会合には、どんな手段を使ってでも時間通りに到着しなければならない。', '今日のかいごうには、どんなしゅだんを使ってでも時間どおりにとうちゃくしなければならない。', '今天的会议，无论用什么手段，都必须按时到达。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('982ccdb2-212e-4624-9200-d1ca348f579a', '84063059-6664-4093-9181-9ac50496cd0e', '家を売ってでも子どもの手術の費用を用意したい。', '家を売ってでも子どものしゅじゅつのひようをよういしたい。', '就是卖房子，也要凑齐孩子的手术费用。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('ba9a73de-6f6c-4e27-8813-e453f5c09bd9', '～（の）ではあるまいか', NULL, 'N2', '動/イ形普通形－の', '動/イ形普通形－の\nナ形語幹/名（－なの） ＋ではあるまいか', '“不是……吗”“难道不是……”“会不会……”。', '说话人委婉地表达自己的主张，比「～（の）ではないか」更书面化。', 269, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('ba867976-c219-4d8e-9ef2-a64c4d0878f9', 'ba9a73de-6f6c-4e27-8813-e453f5c09bd9', 'わたしがビジネスでこれまで訪ねたことのある国は、すでに50を超えているのではあるまいか。', 'わたしがビジネスでこれまで訪ねたことのある国は、すでに50を超えているのではあるまいか。', '迄今为止我因商务原因到访的国家已经超过50个了吧。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('c86d7c00-a6b2-49f4-9fbd-8ddf39c52fb5', 'ba9a73de-6f6c-4e27-8813-e453f5c09bd9', '彼は最初から何もかも全部わかっていたのではあるまいか。', '彼は最初から何もかも全部わかっていたのではあるまいか。', '他是不是一开始就知道所有的事情啊？', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('419bf79f-6670-4258-a961-e19d404766ff', 'ba9a73de-6f6c-4e27-8813-e453f5c09bd9', '今の若者たちは他人を思いやる心を失いつつあるのではあるまいか。', '今の若者たちはたにんを思いやる心をうしないつつあるのではあるまいか。', '现在的年轻人是不是越来越缺乏关怀他人的那份心了呢？', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('7bb4d34f-eb91-4a26-be8e-c5b026fe7813', '～てはいられない', NULL, 'N2', '動て形＋はいられない', '動て形＋はいられない', '“不能……”。', '表示迫于某种情况，不能再继续以前的状态，或急于想做某件事情，包含危机感或紧迫感等。', 270, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('e6c65695-8bac-474a-824f-dad28c5f04fc', '7bb4d34f-eb91-4a26-be8e-c5b026fe7813', '仕事が予定より遅れている。だから、今度の日曜日は、仕事を休んではいられない。', '仕事がよていより遅れている。だから、今度の日曜日は、仕事を休んではいられない。', '工作晚于原定计划。所以，这个周日不能休息了。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('15ef1240-6bdb-4905-96fa-5c510c2d9be3', '7bb4d34f-eb91-4a26-be8e-c5b026fe7813', '事の真相を知った以上、もう黙ってはいられない。', '事のしんそうを知った以上、もうだまってはいられない。', '既然知道了真相，就不能再沉默下去了。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('6e842ac6-816d-4e76-9132-ff29af6dcfaa', '7bb4d34f-eb91-4a26-be8e-c5b026fe7813', '来週は大事な期末試験なので、のんびりしてはいられない。', 'らいしゅうは大事なきまつ試験なので、のんびりしてはいられない。', '下周就是重要的期末考试了，不能再像平时那样悠闲了。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('76b97c02-b7a9-42b4-b97f-741393f7dd05', '～てばかりはいられない/てばかりもいられない', NULL, 'N2', '動て形＋ばかりはいられない/ばかりもいられない', '動て形＋ばかりはいられない/ばかりもいられない', '表示不能总是以某种状态继续下去，“（也）不能总是……”。', '常与表示感情的词搭配使用，包含了说话人对现状的不安，“不能总是这么下去，不能沉浸在……当中”。', 271, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('906fb50f-0e35-4b9c-8da3-de6aaec05900', '76b97c02-b7a9-42b4-b97f-741393f7dd05', 'どんなに辛くても、泣いてばかりもいられない。もっと強く生きていかなければならない。', 'どんなにつらくても、泣いてばかりもいられない。もっと強く生きていかなければならない。', '无论多痛苦，也不能总是哭，必须要更坚强地活下去。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('b3aebbb1-b5ef-43ea-be0d-5c77b0fbe6ca', '76b97c02-b7a9-42b4-b97f-741393f7dd05', '体の調子が悪いからといって、このまま会社を休んでばかりはいられない。', '体のちょうしが悪いからといって、このまま会社を休んでばかりはいられない。', '虽说最近身体状况不太好，但不能总是这样请假不去上班。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('17568c6b-2f2a-43e9-92cc-5dc7a2dfa66d', '76b97c02-b7a9-42b4-b97f-741393f7dd05', '今日の試合に勝ったからといって喜んでばかりはいられない。来週は決勝戦だ。', '今日の試合に勝ったからといって喜んでばかりはいられない。来週はけっしょうせんだ。', '虽说今天赢了，但不能总是沉浸在喜悦当中。下周就是决赛了。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('cb01c357-4b25-4358-889f-e01ca345c4de', '～てはじめて', NULL, 'N2', '動て形＋はじめて', '動て形＋はじめて', '“在……之后才……”。', '经过前项的事情之后，对过去没有在意的事情有了新的认识或感悟；或是有了前项作为基础，后项才能得以实现。前项是后项发生的理由或者契机。', 272, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('1f6e55db-1f3b-41c2-9aa3-779ded0b6a67', 'cb01c357-4b25-4358-889f-e01ca345c4de', '国民の、政治に対する信頼があってはじめて政治家は指導力を発揮できるのだ。', 'こくみんの、政治に対するしんらいがあってはじめて政治家はしどうりょくをはっきできるのだ。', '只有国民相信政治，政治家才能发挥其指导力。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('a1065778-c246-495f-b668-22e5c53158e8', 'cb01c357-4b25-4358-889f-e01ca345c4de', '外国で生活をしてはじめて自分の国の良さがわかった。', '外国で生活をしてはじめて自分の国の良さがわかった。', '在国外生活之后才明白自己国家的好处。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('28e9e65e-ef34-49e4-89e3-3422c225219e', 'cb01c357-4b25-4358-889f-e01ca345c4de', '一人で暮らすようになってはじめて、家族がどんなにありがたいかがわかった。', '一人で暮らすようになってはじめて、家族がどんなにありがたいかがわかった。', '一个人生活之后才明白家庭的可贵。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('9b95edb1-d5a8-4da5-b18d-94d0a680deef', '～ではすまされない', NULL, 'N2', '名/動普通形（－の）＋ではすまされない', '名/動普通形（－の）＋ではすまされない', '“如果……的话，是不能解决问题的”“如果……的话，是不行的”。', '表示某项事情是不能迁就的、不被允许的。', 273, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('4bd9b481-61a9-42e1-ae18-4ec9c46cace8', '9b95edb1-d5a8-4da5-b18d-94d0a680deef', '課長である以上、そんな大事なことを知らなかったではすまされないだろう。', '課長である以上、そんな大事なことを知らなかったではすまされないだろう。', '作为课长，出了这么大的事情却不知道怎么行呢？', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('fceaa5e5-495d-4158-a1b3-6a18f9a76ed2', '9b95edb1-d5a8-4da5-b18d-94d0a680deef', '管理層の人間として、マネジメントに関する基本の知識を知らないではすまされない。', 'かんりそうの人間として、マネジメントに関する基本の知識を知らないではすまされない。', '作为管理层，缺乏管理的基本知识是不行的。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('782d4a4d-b8ba-4fab-bf4c-1bbee15ab36c', '9b95edb1-d5a8-4da5-b18d-94d0a680deef', 'この物語はただの笑い話ではすまされないと思うところがある。', 'このものがたりはただのわらいばなしではすまされないと思うところがある。', '这个故事有些地方发人深省，并不只会让人一笑而过。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('5f463d47-13d4-4d50-9516-27f37765d5ab', '～てまで', NULL, 'N2', '動て形＋まで', '動て形＋まで', '表示程度，“甚至不惜……”。', '为达到某种目的，甚至不惜做出超乎寻常的事情。', 274, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('32c2b77e-ff1f-4173-8fe4-61b7d54ad274', '5f463d47-13d4-4d50-9516-27f37765d5ab', '借金してまで遊びに行ったと聞いて、あきれてしまった。', 'しゃっきんしてまで遊びに行ったと聞いて、あきれてしまった。', '听说甚至不惜借钱出去玩，我真的是无语了。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('71997ffa-e1f6-40e0-b1af-26d959030735', '5f463d47-13d4-4d50-9516-27f37765d5ab', '最近の祭りは以前ほど活気がなくなってきた。仕事を休んでまで行く必要はないだろう。', '最近の祭りは以前ほどかっきがなくなってきた。仕事を休んでまで行く必要はないだろう。', '最近的庙会活动不像以前那样充满生机了。没必要请假去参加吧。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('a26f38d8-b5c1-4938-bbf1-7f2385ebd041', '5f463d47-13d4-4d50-9516-27f37765d5ab', '君はカンニングをしてまでいい点を取りたかったのか。', '君はカンニングをしてまでいい点を取りたかったのか。', '你为了考一个好成绩就不惜作弊吗？', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('413b4a8c-2a9c-4131-b230-f9c4dd131070', '～ということだ', NULL, 'N2', '文の普通形＋ということだ', '文の普通形＋ということだ', '表示得出某个结论，“就是……”“也就是说……”。\n表示传闻，“听说……”。', '「こと」在这里表示“事情”。前项提出一个事实，作为充分的依据，由此得出后项的结论。\n相当于「～そうだ」，直接引用的感觉很强。', 275, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('00cd19b2-9892-468a-912e-60e2b4e4e824', '413b4a8c-2a9c-4131-b230-f9c4dd131070', '父はまだ海外出張から帰ってきていない。つまり今日の私の卒業式には参加できないということだ。', '父はまだかいがい出張から帰ってきていない。つまり今日の私の卒業式には参加できないということだ。', '爸爸去国外出差还没有回来，也就是说不能参加我今天的毕业典礼了。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('be2ac7e5-0589-45e9-aadc-303736c17be1', '413b4a8c-2a9c-4131-b230-f9c4dd131070', 'こんな時間になっても橋本君は姿を現さない。今日も遅刻ということだね。', 'こんな時間になってもはしもとくんはすがたをあらわさない。今日も遅刻ということだね。', '到了这个时间桥本都还没来，就是说他今天又要迟到了。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('95fcbc47-261d-488c-95b5-2e0b9439aa33', '413b4a8c-2a9c-4131-b230-f9c4dd131070', 'コーチの話では、彼が試合に出れば、優勝は間違いないということだ。', 'コーチの話では、彼が試合に出れば、ゆうしょうはまちがいないということだ。', '听教练说，如果他参加比赛的话，肯定会赢。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('a91fc3b6-504a-4cf2-a592-61f764437e48', '413b4a8c-2a9c-4131-b230-f9c4dd131070', '田中さんは通勤途中で交通事故に巻き込まれたということだ。', 'たなかさんはつうきんとちゅうで交通事故にまきこまれたということだ。', '听说田中在上班的路上遇到了交通事故。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('e4f29553-fdc3-45a5-bcea-b4490e692327', '～というものだ', NULL, 'N2', '動/イ形普通形/ナ形語幹/名＋というものだ', '動/イ形普通形/ナ形語幹/名＋というものだ', '“也就是……”“这就是所谓的……”。', '表示对事物的本质特征进行评价、断定、解说等。', 276, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('7a6c7126-bcf1-4a9a-b78e-56180b1a1028', 'e4f29553-fdc3-45a5-bcea-b4490e692327', 'この新しい電池は、光と熱のエネルギーを利用しようというものだ。', 'この新しいでんちは、光と熱のエネルギーを利用しようというものだ。', '这种新电池，就是想要使用光能和热能。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('917fb3c3-9680-4624-a3c9-cd0fa3decb90', 'e4f29553-fdc3-45a5-bcea-b4490e692327', '相手の話も聞かずに自分の主張だけ通そうとするなんて、それはわがままというものだ。', '相手の話も聞かずに自分のしゅちょうだけとおそうとするなんて、それはわがままというものだ。', '不听对方说的话只想一味坚持自己的主张，这正是任性。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('8a8fd7ed-2e48-415f-ad78-015ec21ad0af', 'e4f29553-fdc3-45a5-bcea-b4490e692327', '自分のことだけではなく、相手の立場に立って考えることのできる人、それが大人というものだ。', '自分のことだけではなく、相手の立場に立って考えることのできる人、それが大人というものだ。', '不是光考虑自己，会站在对方的立场上来考虑，这才是真正意义上的成年人。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('e481785f-3329-43bf-bc7d-96c8d06d9be4', '～というものではない/というものでもない', NULL, 'N2', '文の普通形＋というものではない/というものでもない', '文の普通形＋というものではない/というものでもない', '表示否定，“并非……”。', '表示说话人认为某个想法或说法并不全面。「～というものでもない」比「～というものではない」否定的语气要稍微弱一些。', 277, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('400dbbc4-d43d-47e1-97ea-a5c982a9f6ff', 'e481785f-3329-43bf-bc7d-96c8d06d9be4', '勝負は勝てばよいというものではない。どんな勝ち方をしたのかが重要である。', 'しょうぶは勝てばよいというものではない。どんな勝ち方をしたのかが重要である。', '说到胜负，并不是取得胜利了就好。以什么方法取得胜利是很重要的。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('22b6be99-926c-4c91-ae72-cfd39f362a0c', 'e481785f-3329-43bf-bc7d-96c8d06d9be4', '物を売る時は、値段が安ければいいというものではなく、商品の質を第一に考えるべきだ。', '物を売る時は、値段が安ければいいというものではなく、しょうひんのしつをだいいちに考えるべきだ。', '卖东西的时候，并非只要价格便宜就好，应该首先考虑商品的质量。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('b03ebebf-1e2d-489e-9881-e75775e8d65d', 'e481785f-3329-43bf-bc7d-96c8d06d9be4', '医者の話によると、この病気はすぐによくなるというものではないらしい。', '医者の話によると、この病気はすぐによくなるというものではないらしい。', '听医生说，这个病似乎不会马上好。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('7464e7f8-ff68-4959-9691-dee63fc1d0ea', '～というより', NULL, 'N2', '～というより', '～というより', '“与其说……，还不如说……”。', '名词和ナ形后面不接「だ」，直接接「というより」也可以。', 278, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('7047752a-7439-427d-b0de-66bd1c4f9f21', '7464e7f8-ff68-4959-9691-dee63fc1d0ea', '駅から家までバスに乗らずに歩くのは、節約というより健康のためだ。', '駅から家までバスに乗らずに歩くのは、せつやくけんこうのためだ。', '从车站到家里这段路，不乘巴士而是步行，与其说是为了省钱，不如说是为了健康。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('f8df6136-09e0-43a4-a306-8b662ed1f3bb', '7464e7f8-ff68-4959-9691-dee63fc1d0ea', '山田さんは書物が大好きで、技術者というより学者といったほうがいい。', 'やまださんはしょもつが大好きで、ぎじゅつしゃがくしゃといったほうがいい。', '山田很喜欢书，与其说是技术人员，不如说是学者更恰当。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('39c8d767-9d11-4703-8780-b28b04ee9373', '7464e7f8-ff68-4959-9691-dee63fc1d0ea', '仕事ができないというより、仕事をしたくないといったほうが適当だと思う。', '仕事ができないというより、仕事をしたくないといったほうがてきとうだと思う。', '我觉得与其说是做不了这份工作，不如说是不想做更恰当。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('1b96b4fc-fbe7-451e-bda0-29684277cc87', '～といっても 過[か] 言[ごん]ではない/といっても 言[い]い 過[す]ぎではない', NULL, 'N2', '文の普通形＋といっても過言ではない/といっても言い過ぎではない', '文の普通形＋といっても過言ではない/といっても言い過ぎではない', '表示评价，“即便……说也不为过”。', NULL, 279, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('3945df5f-f4a4-40f4-9e15-e6a0d6f80ab6', '1b96b4fc-fbe7-451e-bda0-29684277cc87', '最先端の実験設備を持ったABC研究所の研究施設は、日本一といっても過言ではないだろう。', 'さいせんたんのじっけんせつびを持ったABC研究所の研究施設は、日本一といっても過言ではないだろう。', '将拥有最先进的实验设备的ABC研究所的研究设施说成是日本第一也不为过。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('59a1f02b-3f43-463f-a330-4e67ec36f323', '1b96b4fc-fbe7-451e-bda0-29684277cc87', '山田監督は私の恩人です。今の私があるのも山田監督あってのことだといっても過言ではありません。', 'やまだかんとくは私のおんじんです。今の私があるのも山田監督あってのことだといっても過言ではありません。', '山田导演是我的恩人，可以说多亏有山田导演才有今天的我。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('84269e58-1730-4b33-a363-01b384ea46f4', '1b96b4fc-fbe7-451e-bda0-29684277cc87', 'インターネットの普及とともに、あらゆる情報が溢れていて、人々は情報の洪水に投げ出されているといっても言い過ぎではないだろう。', 'インターネットのふきゅうとともに、あらゆる情報があふれていて、人々は情報のこうずいになげだされているといっても言い過ぎではないだろう。', '随着网络的普及，各种信息泛滥，可以说人们被扔入了信息洪流之中也不为过。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('bd92f53d-27af-4f73-8e45-10c1edb69eda', '～（か）と 思[おも]うと/（か）と思ったら', NULL, 'N2', '動た形＋（か）と思うと/（か）と思ったら', '動た形＋（か）と思うと/（か）と思ったら\n動辞書形·た形＋（か）と思うと/（か）と思ったら', '表示事情几乎同时发生，“刚……就……”。\n表示结果与说话人预想的相反，“原以为……却……”。', '表示前项的事情发生以后，紧接着发生了后项的事情，并且后项多为意料之外的事情，包含说话人惊讶的语气。\n只能用于描述客观事实或他人的情况，不能用于说话人自身的行为。\n用于描述现实的状况，后项不能是表示命令、意志、否定的内容。\n后项表示与说话人预想相反的事情。', 280, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('198c3d56-49cc-4e78-b67e-18546291585f', 'bd92f53d-27af-4f73-8e45-10c1edb69eda', '息子は、朝学校に行く際に、必ずと言っていいほど忘れ物をしている。出かけたかと思うとすぐ忘れ物を取りに帰ってくる。', '息子は、朝学校に行くさいに、必ずと言っていいほど忘れ物をしている。出かけたかと思うとすぐ忘れ物を取りに帰ってくる。', '儿子早上去学校的时候，总是丢三落四。刚一出门就又返回来拿落下的东西。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('cbbcdcb8-eb2a-4df2-b054-3de01cb7ddf3', 'bd92f53d-27af-4f73-8e45-10c1edb69eda', '急に空が暗くなったかと思うと、激しく雨が降り始めた。', '急に空が暗くなったかと思うと、激しく雨が降り始めた。', '天空刚一暗下来，马上就下起了大雨。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('c1e3fd22-74ba-490f-b62e-6689d696e388', 'bd92f53d-27af-4f73-8e45-10c1edb69eda', '赤ちゃんは、泣いていたかと思ったら、もう笑っている。', '赤ちゃんは、泣いていたかと思ったら、もう笑っている。', '小宝宝刚还在哭呢，现在已经破涕为笑了。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('4c554d4a-46fd-4866-bb2e-ea94da0b7ec4', 'bd92f53d-27af-4f73-8e45-10c1edb69eda', '妹は、今勉強を始めたかと思ったら、もう居間でテレビを見ている。', '妹は、今勉強を始めたかと思ったら、もういまでテレビを見ている。', '我原以为妹妹现在已经开始学习了，可结果她却在客厅看电视。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('a8eacf54-5a99-4551-beff-6563e25a3782', 'bd92f53d-27af-4f73-8e45-10c1edb69eda', '私は最近新しいアパートに引っ越したが、駅の近くだから便利だろうと思ったらそうでもない。', '私は最近新しいアパートに引っ越したが、駅の近くだから便利だろうと思ったらそうでもない。', '我最近搬了新家，原以为因为离车站近会很方便吧，可结果却并非如此。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('700bd6a0-7693-4b8f-a49b-fe2847a96a9a', 'bd92f53d-27af-4f73-8e45-10c1edb69eda', 'やっと仕事が終わったと思ったら、また新しい仕事を頼まれた。', 'やっと仕事が終わったと思ったら、また新しい仕事を頼まれた。', '原以为工作终于结束了，可又被安排了新的工作。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('e423c894-d421-4679-a137-bc870e0b79b2', '～とか/とかいう', NULL, 'N2', '文の普通形/名＋とか/とかいう', '文の普通形/名＋とか/とかいう', '表示不确定，“说是……什么的”。', '表示把听到的内容传达给别人，但是对传达的内容不是很确定。「～とかいう」后面可以接名词。', 281, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('3feb00f5-b9c8-4aad-a9d2-b227a278e3b8', 'e423c894-d421-4679-a137-bc870e0b79b2', 'A「もう無理だよ、私には5キロなんて走れないよ。」B「まだ500メートルだよ。なんでそうやってすぐ、もうだめとか言うの。」', 'A「もう無理だよ、私には5キロなんて走れないよ。」B「まだ500メートルだよ。なんでそうやってすぐ、もうだめとか言うの。」', 'A“不行了，我可跑不了五公里。”\nB“这才只有500米呢。为什么你老是这样，刚做就说不行什么的呢？”', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('9bf98719-329a-4b59-9497-6d7179ebf424', 'e423c894-d421-4679-a137-bc870e0b79b2', '中村さんとかいう人から電話が入ってきた。', 'なかむらさんとかいう人から電話が入ってきた。', '一个叫中村的什么人打过电话来。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('2afd76c6-5ebd-4500-9cbd-fb0dddb18301', 'e423c894-d421-4679-a137-bc870e0b79b2', '鈴木さんは今日は病気で仕事を休むとか。', 'すずきさんは今日は病気で仕事を休むとか。', '铃木说是今天生病要请假什么的。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('ea2a7f5d-e5ac-4612-9bf4-4e436c52d9ca', '～とかいうことだ/とかいう 話[はなし]だ', NULL, 'N2', '文の普通形＋とかいうことだ/とかいう話だ', '文の普通形＋とかいうことだ/とかいう話だ', '表示不确定的传闻，“好像听说……”。', '表示传闻，虽然说话人不是很清楚，但是听说过这么一件事情。', 282, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('2d8e948d-f10a-4c05-874a-d04a6cb98dea', 'ea2a7f5d-e5ac-4612-9bf4-4e436c52d9ca', 'ニュースによると今年の冬は例年より寒いとかいうことだ。', 'ニュースによると今年の冬はれいねんより寒いとかいうことだ。', '好像听报道说今年的冬天会比往年冷。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('bcb79676-653e-45d4-85dc-499473ce7b0e', 'ea2a7f5d-e5ac-4612-9bf4-4e436c52d9ca', '田中さんは結婚したら仕事をやめるとかいう話だ。', 'たなかさんは結婚したら仕事をやめるとかいう話だ。', '据说田中结婚后会辞掉工作。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('71a75537-bada-46a8-a817-7a3834bab0ec', '～とかで', NULL, 'N2', '文の普通形＋とかで', '文の普通形＋とかで', '表示听到的理由，“说是因为……什么的”。', '表示从别人那里听到的某种原因、理由，常用于口语。「とか」表示传闻，「で」表示原因。', 283, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('547178e3-78f5-46d0-81ea-a30ab13f3e1b', '71a75537-bada-46a8-a817-7a3834bab0ec', '夜、パーティーに行くとかで、小川さんはすごくすてきな服を着てきました。', '夜、パーティーに行くとかで、おがわさんはすごくすてきな服を着てきました。', '晚上，小川说是要去参加晚会什么的，穿着很漂亮的衣服来了。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('f7a9c06a-c76f-4f1a-85bc-5e43e02f693b', '71a75537-bada-46a8-a817-7a3834bab0ec', '台風が近づいているとかで、飛行機が欠航になった。', 'たいふうが近づいているとかで、飛行機がけっこうになった。', '说是因为有台风逼近，飞机停飞了。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('d72e2c4b-b0b6-4e94-ac83-46f8d7f71145', '～どころか', NULL, 'N2', '動/イ形/ナ形の名詞修飾形', '動/イ形/ナ形の名詞修飾形\n名＋どころか', '表示从根本上进行否定，“哪里……”“别说……”。', '后项内容多与前项叙述的事实相反，从根本上否定了前项，并且提出程度更深的后项，“不但不……反而更加……”。', 284, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('87d397d8-a197-4729-93fd-151c687e25f0', 'd72e2c4b-b0b6-4e94-ac83-46f8d7f71145', '野党の追及に対し、大臣は満足な回答ができなかったどころか、質問の内容すら理解できていなかった。', 'やとうのついきゅうに対し、だいじんは満足な回答ができなかったどころか、質問のないようすら理解できていなかった。', '对于在野党的追究，大臣非但没能给出令人满意的回答，就连问题的内容他都没能理解。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('a1c0a523-78d0-4afb-93f2-16c7d469f671', 'd72e2c4b-b0b6-4e94-ac83-46f8d7f71145', '最近は多忙で、旅行どころか、コンサートに行く暇もない。', '最近はたぼうで、旅行どころか、コンサートに行く暇もない。', '最近太忙了，不要说去旅游了，就连去音乐会的工夫都没有。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('529c3342-2dd8-417b-a910-bb40978b03e0', 'd72e2c4b-b0b6-4e94-ac83-46f8d7f71145', '医者には二、三日で治ると言われたが、よくなるどころかますます悪くなってきた。', 'いしゃには二、三日で治ると言われたが、よくなるどころかますます悪くなってきた。', '医生说两三天能好，哪里好了，反而越来越严重了。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('24dc3f03-a697-40a1-ad95-962271c66c31', '～ところだった', NULL, 'N2', '動辞書形＋ところだった', '動辞書形＋ところだった', '“差一点就……”“险些……”。', '可以用「もう少しで/あやうく」等来加强语气，表示“差一点就……”。', 285, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('8f118055-a5a4-4bc2-8203-477995e57b6d', '24dc3f03-a697-40a1-ad95-962271c66c31', 'ちゃんと前を見て運転してよ。今、となりの車にぶつかるところだったよ。本当にあぶなかったんだから。', 'ちゃんと前を見てうんてんしてよ。今、となりの車にぶつかるところだったよ。本当にあぶなかったんだから。', '开车时好好看着前面。刚才差一点就撞到旁边的车子了，真是很危险。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('39428a2c-a8c6-455d-884c-8cc5e549d8b1', '24dc3f03-a697-40a1-ad95-962271c66c31', '床が濡れていることに気づかず、もう少しで倒れるところだった。', 'ゆかがぬれていることに気づかず、もう少しでたおれるところだった。', '没注意到地板湿了，差点儿就摔倒了。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('73de1a42-4f39-40ec-a5a8-35447060b8da', '24dc3f03-a697-40a1-ad95-962271c66c31', '気がつくのが遅かったら、あやうく火事になるところだったよ。', '気がつくのが遅かったら、あやうく火事になるところだったよ。', '如果发现晚了，险些就酿成火灾了。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('c8b33718-92ea-49ba-b57d-28e9f6e82820', '～どころではない', NULL, 'N2', '動辞書形·ている形/名＋どころではない', '動辞書形·ている形/名＋どころではない', '表示不是做某事的场合，“不是……的时候”“哪能……”。', '强调目前没有时间、金钱或精力去做某事。', 286, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('3ac45476-475b-4a84-a99d-0d6f81a6ddb5', 'c8b33718-92ea-49ba-b57d-28e9f6e82820', '以前は、月に1回ぐらい美術館に好きな絵を見に行く時間があった。今はそれどころではなく、仕事に追われる毎日だ。', 'いぜんは、月に1回ぐらい美術館に好きな絵を見に行く時間があった。今はそれどころではなく、仕事に追われる毎日だ。', '以前还有时间一个月去一次美术馆，看自己喜欢的画。现在哪有那个闲工夫，每天工作都忙不完。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('996797e6-45bd-440f-8ab1-c469b97164c4', 'c8b33718-92ea-49ba-b57d-28e9f6e82820', 'せっかく古い友達が訪ねてきたのに、仕事に追われていっしょに酒を飲むどころではなかった。', 'せっかく古い友達が訪ねてきたのに、仕事に追われていっしょに酒を飲むどころではなかった。', '老朋友好不容易来访，可我却忙于工作，根本谈不上一起喝酒叙旧。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('65b4cc78-c8c9-4d38-96ab-2e9636fa1e39', 'c8b33718-92ea-49ba-b57d-28e9f6e82820', 'わたしは仕事でしばしば出張するので、あちこち旅行できていいとみんなに言われるが、いつも忙しくて見物どころではない。', 'わたしは仕事でしばしば出張するので、あちこち旅行できていいとみんなに言われるが、いつも忙しくてけんぶつどころではない。', '因为工作关系我会经常出差，大家都说我能四处旅游真好，但总是很忙，根本没办法观光。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('213550df-fc90-4fee-8153-75b8f945b5a5', '～ところに/ところへ', NULL, 'N2', '動辞書形·た形·ている形＋ところに/ところへ', '動辞書形·た形·ている形＋ところに/ところへ', '“正当……的时候”。', '表示正在做某事时发生了另外一件事情，多是出乎意料的事情。惯用表达有「いいところに来ましたね」，表示“你来得正是时候”。', 287, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('339a5729-83d8-48ba-92d1-291463b59658', '213550df-fc90-4fee-8153-75b8f945b5a5', 'お弁当を持って、ピクニックに出かけようとしたところに、雨が降ってきた。', 'おべんとうを持って、ピクニックに出かけようとしたところに、雨が降ってきた。', '正当带着便当要去野餐的时候，下起雨来了。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('5e032fac-43ad-49a5-83bf-f60cdaec0b82', '213550df-fc90-4fee-8153-75b8f945b5a5', '外国の町で、道に迷って困っていたところに、警察が通りかかった。', '外国の町で、道に迷って困っていたところに、けいさつがとおりかかった。', '在国外的城市，正当迷路不知所措时，警察刚好经过。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('ccba354e-47b1-4b51-9f57-96fd161d2604', '213550df-fc90-4fee-8153-75b8f945b5a5', 'ちょうど彼女のうわさをしているところへ、本人がやってきた。', 'ちょうど彼女のうわさをしているところへ、ほんにんがやってきた。', '正在谈论有关她的传闻时，当事人就过来了。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('76d1e4ac-63be-4ca0-931c-8a314cc4bd0a', '～ところを', NULL, 'N2', '動辞書形·た形·ている形＋ところを', '動辞書形·た形·ている形＋ところを', '“正当……的时候”。', '后项的动词很有限，多是「見られる（被看见）」「見つかる（被发现）」「捕まる（被抓住）」这些表示看到或发现等意义的动词，对前项叙述的行为有制止或阻挡等意思。', 288, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('1d4ed482-8c22-4b71-bcba-898435da13b5', '76d1e4ac-63be-4ca0-931c-8a314cc4bd0a', '授業中マンガを読んでいるところを先生に見つかった。', 'じゅぎょうちゅうマンガを読んでいるところを先生に見つかった。', '上课看漫画的时候，被老师发现了。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('b2233bc5-457b-4ee5-bc4c-1c0f9310a6fd', '76d1e4ac-63be-4ca0-931c-8a314cc4bd0a', '犯人は駅前で買い物をしているところを、警察に捕まった。', 'はんにんはえきまえで買い物をしているところを、けいさつにつかまった。', '罪犯正在车站前面买东西的时候，被警察逮捕了。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('27ddbabc-ff50-4c1d-b7dd-a52c8d924e57', '～ところを 見[み]ると', NULL, 'N2', '動た形·ている形＋ところを見ると', '動た形·ている形＋ところを見ると', '“从……来看”。', '前项提出某个事实，说话人根据这一事实做出后项的判断。', 289, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('9afe6814-b65d-4df7-9a85-975cdf0d4ee2', '27ddbabc-ff50-4c1d-b7dd-a52c8d924e57', '朝からニコニコしているところをみると、何かいいことがあったに違いない。', '朝からニコニコしているところをみると、何かいいことがあったに違いない。', '从早上开始就笑眯眯的，看样子一定有什么好事情。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('3c254c64-4abf-47ab-9e8d-1dde9d33fdbc', '27ddbabc-ff50-4c1d-b7dd-a52c8d924e57', '彼があんなに喜んでいるところをみると、彼の成績はかなり上がったに違いない。', '彼があんなに喜んでいるところをみると、彼のせいせきはかなり上がったに違いない。', '看他那么高兴，就知道他的成绩一定提高了不少。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('4ba0c5aa-6662-456b-bc37-3effc58a0de4', '27ddbabc-ff50-4c1d-b7dd-a52c8d924e57', '店の前に長い行列ができているところをみると、大変人気のラーメン屋のようだ。', '店の前に長いぎょうれつができているところをみると、大変人気のラーメン屋のようだ。', '从这家店门前排着很长的队来看，好像是一家很受欢迎的拉面店。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('d733e669-5b7b-4b63-adb4-90e863a68849', '～としか 言[い]いようがない', NULL, 'N2', '文の普通形＋としか言いようがない', '文の普通形＋としか言いようがない\nナ形語幹/名＋としか言いようがない', '表示强调，“只能说是……”。', '是「～しか～ない」和「動ます形＋よう」两个句型的结合，表示“没有别的说法”“只能这么说”。', 290, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('fc667597-e5cc-47d3-b24b-73e86f3d2762', 'd733e669-5b7b-4b63-adb4-90e863a68849', 'あんなに巨大な建物を大昔の人が造ったとは、不思議としか言いようがない。', 'あんなにきょだいな建物をおおむかしの人がつくったとは、ふしぎとしか言いようがない。', '古代的人建造出这么庞大的建筑，只能说是不可思议。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('b27e79ed-d7a9-4362-9511-e139300b8746', 'd733e669-5b7b-4b63-adb4-90e863a68849', '大きな交通事故で軽い怪我で済んだのは幸運としか言いようがない。', '大きな交通事故で軽い怪我で済んだのはこううんとしか言いようがない。', '在这么重大的交通事故中只受了点轻伤，只能说是幸运。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('d7eeb8b1-d942-45ab-a373-2dc62bc18486', 'd733e669-5b7b-4b63-adb4-90e863a68849', 'この病気が治ったことは奇跡だとしか言いようがない。', 'この病気がなおったことはきせきだとしか言いようがない。', '这种病治好了只能说是奇迹。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('2877f4e9-bc5c-4bbb-9118-f664f251f6f9', '～としたら/とすれば/とすると', NULL, 'N2', '文の普通形＋としたら/とすれば/とすると', '文の普通形＋としたら/とすれば/とすると', '表示假设，“如果……”。', '可以表示假定条件或既定条件，后项可以表示自然而然的结果、判断、推量、疑问等内容。', 291, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('b1f2c991-e549-40eb-ac75-e3127cfc5ffe', '2877f4e9-bc5c-4bbb-9118-f664f251f6f9', '人は通勤に多くの時間を使っている。かりに通勤に往復2時間かけるとすると、1年間で480時間も通勤に使っている計算になる。', '人はつうきんに多くの時間を使っている。かりに通勤におうふく2時間かけるとすると、1年間で480時間も通勤に使っているけいさんになる。', '人们在上下班上花去了很多的时间。假设上下班往返需要两个小时，那算下来一年就得花去480个小时。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('b738700a-f07f-4a3f-9d4a-5c1f43f0061f', '2877f4e9-bc5c-4bbb-9118-f664f251f6f9', '内容がわからない話を長時間聞かなければならないとしたら、大人だって耐えられないことでしょう。', '内容がわからない話を長時間聞かなければならないとしたら、大人だってたえられないことでしょう。', '如果不得不长时间听一些不知所云的话，即便是成年人也是无法忍耐的吧。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('24a72146-10bc-4260-8eb9-5cb1fecee858', '2877f4e9-bc5c-4bbb-9118-f664f251f6f9', '1年間の休暇がとれたとしたら、どんなことがしたいですか。', '1年間の休暇がとれたとしたら、どんなことがしたいですか。', '如果可以休一年的假，你想做什么？', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('36b3d479-d83c-48b5-84a5-96163a645494', '～とともに', NULL, 'N2', '～とともに', '～とともに', '表示伴随，“随着……”“与……的同时”。', '表示随着前项的变化，后项也随着发生变化，或者前项与后项同时发生。前面接名词时一般是接包含动作意义的名词。', 292, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('36dde3ad-5301-4fe9-9365-92cd8a3d107b', '36b3d479-d83c-48b5-84a5-96163a645494', 'ことばは生き物であると言われる。時代の移り変わりとともに、語の形や意味が少しずつ変化する。', 'ことばは生き物であると言われる。時代のうつりかわりとともに、ごのかたちやいみが少しずつ変化する。', '人们常说语言是有生命的事物。随着时代的变迁，词语的形式和意义也在一点点地变化。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('1b6b78d2-341a-49da-ab22-8ed0e516331b', '36b3d479-d83c-48b5-84a5-96163a645494', '都市では、人口の増加とともに、住宅問題が深刻になってきた。', '都市では、人口の増加とともに、じゅうたく問題がしんこくになってきた。', '城市里，在人口不断增加的同时，住房问题也越来越严峻。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('04b39847-d043-4a70-b9bb-3fcc6b8f4d0a', '36b3d479-d83c-48b5-84a5-96163a645494', '自動車の普及とともに交通渋滞の問題も顕在化してきた。', 'じどうしゃのふきゅうこうつうじゅうたいの問題もけんざいかしてきた。', '随着汽车的普及，交通堵塞问题也凸显出来了。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('9ebf00cf-1b81-4280-8d89-bd3d4baa2c78', '～とは 限[かぎ]らない', NULL, 'N2', '文の普通形＋とは限らない', '文の普通形＋とは限らない', '“不见得……”“未必……”。', '有时和「～からといって」搭配使用，表示“虽说……也未必……”。\n前面可以接否定形式，构成「～ないとは限らない」，表示“……未必不”，此时相当于「～かもしれない」，即“有可能……”。如第二个例句。', 293, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('6ff097c8-b72d-4df6-99fd-e2d6d932337d', '9ebf00cf-1b81-4280-8d89-bd3d4baa2c78', '実力のあるチームがいつも勝つとは限らない。試合はやってみなければわからないのだ。', 'じつりょくのあるチームがいつも勝つとは限らない。試合はやってみなければわからないのだ。', '有实力的队伍未必会赢。不比赛看看，就不知道谁会赢。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('f9340750-25e4-41bf-8e76-fdf1b317fd8d', '9ebf00cf-1b81-4280-8d89-bd3d4baa2c78', 'しっかり鍵をかけないと、泥棒に入られないとも限らないから注意してください。', 'しっかり鍵をかけないと、どろぼうに入られないとも限らないから注意してください。', '如果不好好上锁的话，说不定小偷会溜进来的，要当心。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('3839698c-7095-4f91-8b90-53db464eb1fd', '9ebf00cf-1b81-4280-8d89-bd3d4baa2c78', '習慣や考え方は人によって異なるので、自分にとっての常識は他人にとっての非常識でないとも限らない。', 'しゅうかんや考え方は人によってことなるので、自分にとってのじょうしきは他人にとってのひじょうしきでないとも限らない。', '习惯与思维方式因人而异，对自己而言的常识对别人来说未必不是不懂事理。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('a16241eb-485c-4b47-9b10-555006f903fa', '～ない 限[かぎ]り', NULL, 'N2', '動ない形－ない＋限り', '動ない形－ない＋限り', '“只要不……，就……”“除非……否则就……”。', '相当于「～なければ」。后项常与否定的表达方式呼应使用，即「～ない限り～ない」，表示“只要不……就不……”。', 294, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('46e3f10f-3b16-4167-a66f-d47b34131fd7', 'a16241eb-485c-4b47-9b10-555006f903fa', 'この地方は人口がだんだん減っていて、何か対策を立てない限り、今後も増えることはないだろう。', 'このちほうは人口がだんだん減っていて、何かたいさくを立てない限り、こんごも増えることはないだろう。', '这个地区的人口在逐渐减少，如果不采取对策的话，今后也不会增加吧。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('b164150b-ca2c-4e87-aaf6-0892e36a19f8', 'a16241eb-485c-4b47-9b10-555006f903fa', '大都会は危険だと言われているが、ここは夜遅く一人で歩かないかぎり、安全である。', 'だいとかいはきけんだと言われているが、ここは夜遅く一人で歩かないかぎり、あんぜんである。', '虽然人们都说大城市很危险，但是在这里，只要不在深夜一个人走路，还是安全的。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('8ec06ec7-8f08-425a-b363-fc091dfc8bf0', 'a16241eb-485c-4b47-9b10-555006f903fa', '資金の問題を解決しないかぎり、この工事を続けられない。', 'しきんの問題をかいけつしないかぎり、このこうじを続けられない。', '除非解决资金问题，否则这项工程将无法继续进行。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('b57ed9e9-1e03-4c2b-87d5-185844ec3771', '～ないことには', NULL, 'N2', '～ないことには', '～ないことには', '“如果不……（就不……）”。', '后项与否定的表达方式呼应使用，前项是后项成立的必要条件，没有前项，就无法实现后项。', 295, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('09bc6635-241d-4273-b336-526648efeecc', 'b57ed9e9-1e03-4c2b-87d5-185844ec3771', '事実を確認しないことには、何とも申し上げられません。', 'じじつをかくにんしないことには、なんとももうしあげられません。', '如果不确认事实的话，我们无法发表任何言论。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('73373c1a-7e31-4add-aee6-2da7bec80b57', 'b57ed9e9-1e03-4c2b-87d5-185844ec3771', '一度行ってみないことには、どんな所かわからないだろう。', '一度行ってみないことには、どんな所かわからないだろう。', '如果不去一次看看的话，就无法知道那是一个什么样的地方吧。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('576b8769-3b2f-45d2-84e0-fef8e7197b08', 'b57ed9e9-1e03-4c2b-87d5-185844ec3771', '文章を書くということは、何かを表現することであり、自分は何を表現したいのか、それをはっきりさせないことには何も書けない。', '文章を書くということは、何かをひょうげんすることであり、自分は何を表現したいのか、それをはっきりさせないことには何も書けない。', '写文章就是表达一定的内容。如果不弄清楚自己想要表达什么，是写不出任何东西来的。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('a973e28a-c149-4dc0-8750-a4e14d679f4b', '～ないことはない/ないこともない', NULL, 'N2', '～ないことはない/ないこともない', '～ないことはない/ないこともない', '表示有某种可能性，“不是不……”“有可能……”。', '表示并不是完全没有某种可能性。双重否定表示肯定，但并不是正面的肯定，而是消极的肯定，表示有某种可能性。', 296, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('10f1ffd0-2abd-4da8-b085-b865a34b2633', 'a973e28a-c149-4dc0-8750-a4e14d679f4b', '「山田さんのふるさとは雪がたくさん降るところだから、スキーはお得意でしょ。」「うーん、できないことはないけど、もう何年もやってないから…。」', '「やまださんのふるさとは雪がたくさん降るところだから、スキーはお得意でしょ。」「うーん、できないことはないけど、もう何年もやってないから…。」', '“山田，你的家乡是个经常下雪的地方，所以你应该很会滑雪吧。”\n“嗯，会是会，只是已经很多年没有滑过了，所以……”', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('99990cbf-5de3-45ec-8853-aaf95834ebd3', 'a973e28a-c149-4dc0-8750-a4e14d679f4b', '私も留学していたことがありますから、あなたの苦労がわからないこともありません。', '私も留学していたことがありますから、あなたのくろうがわからないこともありません。', '我也曾经留过学，所以我不是不了解你的辛苦。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('1f5964f4-7584-4eb4-8abb-76b221ccf3c1', 'a973e28a-c149-4dc0-8750-a4e14d679f4b', '行きたくないことはないんですが、今日は、時間がないんです。', '行きたくないことはないんですが、今日は、時間がないんです。', '我也不是不想去，只是今天没有时间。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('d97e6c1c-18e1-4c18-9188-eda2079215d2', '～ないではない/ないでもない', NULL, 'N2', '～ないではない/ないでもない', '～ないではない/ないでもない', '表示并非完全没有，“并非不……”“也不是不……”。', '与「～ないことはない/ないこともない」相同。', 297, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('5bc69ae9-d922-44d8-897b-d4406346c966', 'd97e6c1c-18e1-4c18-9188-eda2079215d2', '彼の論文は、構成にはまだ少し問題がある気がしないでもないが、内容自体はだいぶよくなったと思う。', '彼の論文は、こうせいにはまだ少し問題がある気がしないでもないが、内容じたいはだいぶよくなったと思う。', '我并不是不觉得他的论文在结构上还存在一些问题，但我觉得内容本身已经好多了。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('c2c3e0bc-b083-46ff-88c6-8fd579be9c9c', 'd97e6c1c-18e1-4c18-9188-eda2079215d2', '彼女の今までの苦労を知っているので、留学が決まった時あれほど喜んだ気持ちがわからないでもない。', '彼女の今までのくろうを知っているので、留学が決まった時あれほど喜んだ気持ちがわからないでもない。', '我深知她迄今为止所吃的苦，所以也不是不理解留学确定下来时她那么高兴的心情。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('2b1da71e-70e2-4b03-97f9-b18713630990', 'd97e6c1c-18e1-4c18-9188-eda2079215d2', 'この方法は正しくないではないが、一番簡単な方法ではない。', 'このほうほうただ正しくないではないが、一番簡単な方法ではない。', '这个方法不是不对，但不是最简便的方法。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('99af9558-4042-4332-8b4d-8f30d031b0a5', '～ながら（も）', NULL, 'N2', '動ます形/イ形/ナ形語幹/名＋ながら（も）', '動ます形/イ形/ナ形語幹/名＋ながら（も）', '表示逆接，“虽然……但是……”。', '相当于「～けれども/が」。', 298, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('17208ee8-d192-4dd3-8494-330c7c361f26', '99af9558-4042-4332-8b4d-8f30d031b0a5', '新作映画について中田一郎監督は、「現実的でありながらも、詩的な雰囲気を失わないよう意識した。」と語る。', 'しんさくえいがについてなかたいちろうかんとくは、「げんじつてきでありながらも、してきなふんいきをうしなわないよういしきした。」とかたる。', '中田一郎导演关于新拍的电影是这样说的:“我们有意识地让这部电影很现实，但又不失诗意。”', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('afad1588-6d7c-4226-961d-cec3a0365470', '99af9558-4042-4332-8b4d-8f30d031b0a5', 'あの経営者は、不良品と知りながら製品を販売していた。', 'あのけいえいしゃは、ふりょうひんせいひんをはんばいしていた。', '那个经营者明知道是次品，却还在销售。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('22d7cdfb-5d34-4bbc-beda-e0b0d4e74c82', '99af9558-4042-4332-8b4d-8f30d031b0a5', '全力を出しましたが、残念ながら、優勝できませんでした。', 'ぜんりょくを出しましたが、残念ながら、優勝できませんでした。', '虽然使出了全力，但很遗憾还是没能取胜。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('ec5c0551-4879-46bd-9f90-9ee797723726', '～なくはない/なくもない', NULL, 'N2', '～なくはない/なくもない', '～なくはない/なくもない', '表示并不是完全没有某种事情，“不是不……”。', '接名词时，一般接在表示心情或意志等的名词后面，表示并不是完全没有那个意思或心情。', 299, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('0df75d89-7d15-4312-a7af-702fae85e12a', 'ec5c0551-4879-46bd-9f90-9ee797723726', '子供「自分のパソコンが欲しいよ。ねえ、駄目？」母親「ゲームじゃなくて勉強に使うんなら、考えなくもないけど。」', '子供「自分のパソコンが欲しいよ。ねえ、駄目？」母親「ゲームじゃなくて勉強に使うんなら、考えなくもないけど。」', '孩子：“我想要有自己的电脑，怎么样，可以吗？”\n母亲：“如果不是玩游戏，是用于学习的话，也不是不考虑。”', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('62b9d6d6-2102-444b-9b10-d06cfcdd5506', 'ec5c0551-4879-46bd-9f90-9ee797723726', '山本さんは、ある日突然会社をやめてまわりを驚かせたが、あの人の性格を考えると、理解できなくはない。', 'やまもとさんは、ある日突然会社をやめてまわりを驚かせたが、あの人のせいかくを考えると、理解できなくはない。', '山本有一天突然辞职了，让大家吃了一惊。不过从他的性格来看，也并非不能理解。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('79d5ac4e-ee0a-4cee-af96-f4d16c12373b', 'ec5c0551-4879-46bd-9f90-9ee797723726', '結婚するつもりはなくもないが、仕事が安定してからのほうがいいだろう。', '結婚するつもりはなくもないが、仕事があんていしてからのほうがいいだろう。', '也不是不打算结婚，只是觉得等工作安定之后再结婚比较好。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('e8627704-607e-43e8-bed7-8509fe4f9746', '～ならともかく', NULL, 'N2', '動辞書形/イ形/ナ形語幹/名＋ならともかく', '動辞書形/イ形/ナ形語幹/名＋ならともかく', '“如果是……则另当别论”。', '表示如果是前项的情况，还可以理解或者还情有可原，但如果是后项的情况就很难接受了。后项提出比前项程度更高的情况。', 300, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('f2593b47-03d1-4511-bdaf-c6bec39c23bb', 'e8627704-607e-43e8-bed7-8509fe4f9746', '（店で）A「このシャツ、かわいい。でも、会社に着ていくには派手かな。」B「うん。デートで着るならともかく、仕事には派手すぎるよ。」', '（店で）A「このシャツ、かわいい。でも、会社に着ていくにははでかな。」B「うん。デートで着るならともかく、仕事には派手すぎるよ。」', '（在店里）A：“这件衬衫真好看。但是，穿着去上班是不是有点花哨啊。”\nB：“嗯。要是穿着去约会倒没什么，去上班的话太过花哨了。”', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('29f6daee-fff6-4edf-af5a-4d5f62cc67c6', 'e8627704-607e-43e8-bed7-8509fe4f9746', '遅刻ならともかく、無断欠勤などもってのほかだ。', '遅刻ならともかく、むだんけっきんなどもってのほかだ。', '如果是迟到也就罢了，招呼都不打就不来上班真是岂有此理。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('b346eac0-0fab-457a-9210-e66bba055574', 'e8627704-607e-43e8-bed7-8509fe4f9746', 'このレストラン、会社の接待ならともかく、自分のお金で行くには高すぎる。', 'このレストラン、会社のせったいならともかく、自分のお金で行くには高すぎる。', '这家餐厅，如果是公司招待客人去则另当别论，自己花钱去的话就太贵了。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('fc7a9d59-1513-4aca-9432-cbc97ef10e1d', '～にあたって/にあたり', NULL, 'N2', '動辞書形/名＋にあたって/にあたり', '動辞書形/名＋にあたって/にあたり', '表示在某个重要的时刻，“值此……之际”“在……的时候”。', '「～にあたって/にあたり」用在句中中顿；「～にあたっての」后面接名词。多用于致辞或感谢信等正式的场合。', 301, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('92fdad13-9f70-41bc-ac12-96a63c118fb9', 'fc7a9d59-1513-4aca-9432-cbc97ef10e1d', '新年を迎えるにあたって、一年の計画を立てた。', 'しんねんを迎えるにあたって、一年のけいかくをたてた。', '在迎接新年之际，制订了一年的计划。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('cce35667-8a1d-4f50-8c8e-c7219b03d1e5', 'fc7a9d59-1513-4aca-9432-cbc97ef10e1d', '原子力発電所の建設にあたって、住民との話し合いが持たれた。', 'げんしりょくはつでんしょのけんせつにあたって、じゅうみんとのはなしあいがもたれた。', '在建核电站的时候，我们同当地居民进行了沟通。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('362b4f44-6d0c-4ea6-961b-341d936d2502', 'fc7a9d59-1513-4aca-9432-cbc97ef10e1d', '先輩は面接にあたっての注意事項を教えてくれた。', '先輩は面接にあたってのちゅういじこうを教えてくれた。', '前辈告诉了我一些面试时的注意事项。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('65b6dc07-df31-4390-b998-730b55628404', '～に 応[おう]じて（は）/に応じ', NULL, 'N2', '名＋に応じて（は）/に応じ', '名＋に応じて（は）/に応じ', '“根据……”“按照……”。', '表示根据前项，后项会发生变化，包含“如果前项发生变化，后项也随之变化”的意思。「～に応じて/に応じ」用在句中中顿；「～に応じた」后面接名词。', 302, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('50aade89-b082-460f-99ac-32f1db1b3a9d', '65b6dc07-df31-4390-b998-730b55628404', 'このレストランは、客の予算に応じていくつかのコースを用意してくれる。', 'このレストランは、客のよさんに応じていくつかのコースをよういしてくれる。', '这家餐厅根据客人的预算准备了几个套系的菜。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('6c7ba00b-b420-4071-8dfc-da1c5b4e1090', '65b6dc07-df31-4390-b998-730b55628404', '旅行のプランは、お客様のご希望に応じて変更できます。', 'へんこうできます。', '旅行的计划可以根据客户的要求来变更。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('5cbac8ec-0c31-4cce-9bbb-1fc5399e0ff0', '65b6dc07-df31-4390-b998-730b55628404', 'うちの会社は年に2回評価を行って、その評価に応じて昇進が決まる。', 'うちの会社は年に2回ひょうかをおこなしょうしんが決まる。', '我们公司一年进行两次考核，根据考核结果来决定升职。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('e23fd190-771d-490e-b683-93a6d7e1e41b', '～に（は）かかわらず/に（は）かかわりなく', NULL, 'N2', '～に（は）かかわらず/に（は）かかわりなく', '～に（は）かかわらず/に（は）かかわりなく', '“不管……”“无论……”。', '接名词时，一般接表示天气、性别、年龄等含有种类、程度差异的名词，如「 天[てん] 候[こう]/  年[ねん] 齢[れい]/  晴[せい] 雨[う]/  性[せい] 別[べつ]/  地[ち] 位[い]/能力」等，表示不管是哪一种，都无所谓。\n接动词、イ形容词和ナ形容词时，一般接在两个表示对立的词的后面，如「する·しない/好き·嫌い/上手·下手/良し·悪し/いい·悪い」，两个词的后面还可以接「か」，如第三个例句也可以说成「出席するかしないか」。', 303, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('a47600ea-85c6-42a9-a186-5a1ad3b7e061', 'e23fd190-771d-490e-b683-93a6d7e1e41b', '好きか嫌いかにかかわらず、この仕事は必ずしなければならない。', '好きか嫌いかにかかわらず、この仕事は必ずしなければならない。', '不管喜不喜欢，都必须做这个工作。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('be953b2e-8527-4402-af4d-a3c9974681ef', 'e23fd190-771d-490e-b683-93a6d7e1e41b', '天候にかかわらず、あすの午後2時から試合を行います。', 'てんこうにかかわらず、あすの午後2時から試合を行います。', '无论天气如何，明天下午两点开始进行比赛。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('bafb7bcf-7b46-4048-9b2d-d12b6fb4184b', 'e23fd190-771d-490e-b683-93a6d7e1e41b', '出席するしないにかかわらず、お返事をお願いします。', '出席するしないにかかわらず、お返事をお願いします。', '无论出不出席，都请您回信。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('3b17e212-9bff-47a6-886c-7368ddb65ce1', '～にかかわる', NULL, 'N2', '名＋にかかわる', '名＋にかかわる', '“与……有关”“涉及……”，表示影响到、关系到某人或某事。', '表示前后两项之间的关联，多用于直接结句的场合。', 304, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('e94f9a40-e305-4d96-96a1-606c8cec43d4', '3b17e212-9bff-47a6-886c-7368ddb65ce1', '野菜の輸入規則の緩和は農業政策の根本にかかわる。', '野菜のゆにゅうきそくのかんわは農業政策のこんぽんにかかわる。', '蔬菜进口管制的放宽，关系到农业政策的根本。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('17fb0270-bd78-4f46-9631-6462134127ea', '3b17e212-9bff-47a6-886c-7368ddb65ce1', '首相は誰になるかは、日本の将来にかかわることだ。', '首相は誰になるかは、日本のしょうらいにかかわることだ。', '谁当首相是事关日本未来走向的大事。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('9d403f2f-be18-44aa-922c-ea51b62cdba6', '3b17e212-9bff-47a6-886c-7368ddb65ce1', '市役所では市民の生活にかかわるさまざまな相談に応じている。', 'しやくしょではしみんの生活にかかわるさまざまなそうだんにおうじている。', '市政府应对与市民生活相关的方方面面的咨询。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('f0663e49-ff50-4de5-af2c-eff340df6cee', '～に 限[か ぎ]って/に限り', NULL, 'N2', '名＋に限って/に限り', '名＋に限って/に限り', '表示限定，“只限于……”“只有……”。', '「～に限って」「～に限り」用在句中中顿；「～に限る」用在句末结句。', 305, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('ef9c43a9-01fa-495b-80c8-8e96f0703a9e', 'f0663e49-ff50-4de5-af2c-eff340df6cee', 'おはがきをお送りくださった皆様の中から100名様に限り、すてきな商品をプレゼントいたします。', 'おはがきをお送りくださった皆様の中から100名様に限り、すてきな商品をプレゼントいたします。', '我们将从寄来明信片的顾客当中，选定100人赠送精美的礼品。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('d3510ffc-fe98-472f-a69c-a1d518ca9a8e', 'f0663e49-ff50-4de5-af2c-eff340df6cee', '毎週火曜日に限って、映画は半額になります。', '毎週火曜日に限って、映画ははんがくになります。', '只有每周周二，电影半价。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('da88b042-e1fa-49f7-8a21-ee00ebd2fd6d', 'f0663e49-ff50-4de5-af2c-eff340df6cee', '今回の応募作品は著作権を侵害しないものに限る。', '今回のおうぼさくひんはちょさくけんをしんがいしないものに限る。', '这次应征的作品不得侵犯他人著作权。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('116a9493-42a8-4afd-bf30-e9b16c9128ff', '～に 限[かぎ]って', NULL, 'N2', '名＋に限って', '名＋に限って', '“唯独……”“偏偏……”。', '包含“其他时候一般都不怎么发生的情况，偏偏在关键时刻发生了”的意思，后项往往是意想不到的事情。', 306, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('73f4b3cb-0128-431e-b23b-87ecbf436814', '116a9493-42a8-4afd-bf30-e9b16c9128ff', 'ときどき家の中がものすごく散らかってしまうことがある。そんなときに限って、突然客が訪ねてきたりする。', 'ときどき家の中がものすごくちらかってしまうことがある。そんなときに限って、とつぜん客が訪ねてきたりする。', '家里偶尔会很乱。偏偏在这种时候，会突然有客人来访。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('91948240-fad5-4abe-ab82-f48c89b3acee', '116a9493-42a8-4afd-bf30-e9b16c9128ff', '大切な用事があって遅刻してはいけない時に限って、寝坊してしまう。', '大切な用事があって遅刻してはいけない時に限って、ねぼうしてしまう。', '偏偏在有重要的事情不能迟到的时候会睡过头。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('a172bc5f-47b1-4865-b286-303b6238022c', '116a9493-42a8-4afd-bf30-e9b16c9128ff', '予習していないときに限って、先生に当てられる。', 'よしゅうしていないときに限って、先生にあてられる。', '偏巧在没有预习的时候，被老师点到。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('9c44c643-0e36-4ce7-af3f-13312e012109', '～に 限[かぎ]らず', NULL, 'N2', '名＋に限らず', '名＋に限らず', '“不仅……而且……”。', '表示不局限于某个范围之内，后项常与「～も」等呼应使用。', 307, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('5fe26858-4edd-4cb8-8f58-c71a18b85181', '9c44c643-0e36-4ce7-af3f-13312e012109', 'あの選手は子供のころ、サッカーに限らず、スポーツならなんでも得意だったそうだ。', 'あの選手は子供のころ、サッカーに限らず、スポーツならなんでも得意だったそうだ。', '听说那位选手小时候，不仅擅长足球，只要是体育项目都很拿手。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('70aeb591-2e7d-44e2-a495-d75dc5284e65', '9c44c643-0e36-4ce7-af3f-13312e012109', '東京ディズニーランドは子どもに限らず、大人にも大人気だ。', '東京ディズニーランドは子どもに限らず、大人にもだいにんきだ。', '东京的迪士尼乐园不仅受孩子们喜爱，也很受大人们的欢迎。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('c311734c-c2fb-4e6a-b579-ff32bca8dd22', '9c44c643-0e36-4ce7-af3f-13312e012109', '今日のセミナーは就職活動中の学生に限らず、新入生の私たちにも役に立った。', '今日のセミナーはしゅうしょくかつどうちゅうの学生に限らず、新入生の私たちにも役に立った。', '今天的讲座不仅对正在找工作的学生有帮助，我们新生也受益匪浅。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('01ba7ee9-3c68-4135-9350-be8c9c1e7ea7', '～に 限[かぎ]る', NULL, 'N2', '動辞書形·ない形－ない/名＋に限る', '動辞書形·ない形－ない/名＋に限る', '“最好是……”。', '相当于「～のが一番いい」，一般是被普遍认可的事情。', 308, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('b877e7a6-2473-4577-b451-fad2bd279606', '01ba7ee9-3c68-4135-9350-be8c9c1e7ea7', '私の祖父は、風邪をひいても、「風邪のときはあたたかくして早く寝るに限る。」と言って病院に行かない。', '私の祖父は、風邪をひいても、「風邪のときはあたたかくして早く寝るに限る。」と言って病院に行かない。', '我的祖父，即便是感冒了也不会去医院，他会说“感冒的时候穿暖和一点、早点睡，那才是最好的。”', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('a2f29209-712d-4c97-84ec-d4a9c2869786', '01ba7ee9-3c68-4135-9350-be8c9c1e7ea7', '疲れたときは、寝るに限ります。', '疲れたときは、寝るに限ります。', '累的时候，最好是睡一觉。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('49d85342-ad6b-4df8-913a-714ccadbf3fc', '01ba7ee9-3c68-4135-9350-be8c9c1e7ea7', '寒い日は、熱々の鍋に限る。', '寒い日は、あつあつの鍋に限る。', '寒冷的天里，吃热腾腾的火锅是最好的。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('455a4748-a98c-4416-81bc-6242785a438f', '～にかけては/にかけても', NULL, 'N2', '名＋にかけては/にかけても', '名＋にかけては/にかけても', '“在……方面”。', '相当于「～についていえば、一番いい」。后项一般是说话人对某人或某物的正面评价，表示“某人或某物在……方面是最优秀的，最好的”。', 309, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('e0410af5-e272-4e2c-9cd5-f39767f9c546', '455a4748-a98c-4416-81bc-6242785a438f', '村田「青木くんって、本当に面白い人だよね。」西野「うん。彼、人を笑わせることにかけては天才だからね。」', 'むらた「あおきくんって、本当に面白い人だよね。」にしの「うん。彼、人を笑わせることにかけては天才だからね。」', '村田：“青木这个人还真是有趣啊。”\n西野：“嗯。他在逗笑别人这一方面是个天才啊。”', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('e40ff298-b11f-4a3d-a9a0-fee7712a8dff', '455a4748-a98c-4416-81bc-6242785a438f', '値段は別として、味の良さにかけては、このレストランが一番だ。', '値段は別として、味の良さにかけては、このレストランが一番だ。', '价格暂且不说，在味道方面，这家餐厅是最好的。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('c3b514b1-a6bf-46a7-b2b5-0510ace12d29', '455a4748-a98c-4416-81bc-6242785a438f', '弟は勉強はできないが、泳ぎにかけては誰にも負けない。', '弟は勉強はできないが、およぎにかけては誰にも負けない。', '弟弟学习不好，但在游泳方面不会输给任何人。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('794cbef8-993d-4470-8638-f10561099dde', '～に 決[き]まっている', NULL, 'N2', '～に 決[き]まっている', '～に 決[き]まっている', '表示比较确切的推测，“一定……”“肯定……”。', '类似于「～に違いない」。常用于口语。', 310, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('6f8eeba2-8317-40ba-a8c1-4a9fe37de944', '794cbef8-993d-4470-8638-f10561099dde', '同じ値段なら、質がいいほうがたくさん売れるに決まっている。', '同じ値段なら、しつがいいほうがたくさん売れるに決まっている。', '如果价格一样，那肯定是质量好的比较畅销。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('249688ba-d8f2-4dcb-a852-de98e1acdf6a', '794cbef8-993d-4470-8638-f10561099dde', '子どもが大人と相撲をしたって、負けるに決まっている。', '子どもが大人とすもうをしたって、負けるに決まっている。', '小孩子就算和大人进行相扑，也肯定会输。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('79bab349-aff3-4d94-86c4-b51c1092bdcf', '794cbef8-993d-4470-8638-f10561099dde', '今度の選挙では、実力も人気もあるあの若い候補が勝つに決まっている。', '今度のせんきょでは、じつりょくも人気もあるあの若いこうほが勝つに決まっている。', '这次选举，一定是那个既有实力又有人气的年轻的候选人获胜。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('e3e600d9-f17b-4d3a-b99a-7267a548e5ac', '～に 加[くわ]えて/に加え', NULL, 'N2', '名＋に加えて/に加え', '名＋に加えて/に加え', '表示添加，“加上……”“而且……”。', '「～に加えて」常常和「～も」呼应使用，构成「～に加えて、～も」的形式。', 311, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('c0cbbd75-6b0a-41b9-8dff-3a539bfb55f6', 'e3e600d9-f17b-4d3a-b99a-7267a548e5ac', '今年は作物の生育がよくないそうだ。夏の低温に加えて、雨が少なかったのが原因だと考えられている。', '今年はさくもつのせいいくがよくないそうだ。夏のていおんに加えて、雨が少なかったのが原因だと考えられている。', '据说今年农作物的生长不好。原因是夏季气温过低，加上雨水不足。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('abf0998e-dc95-4537-abec-146dc9d6b214', 'e3e600d9-f17b-4d3a-b99a-7267a548e5ac', 'のどの痛みに加えて、咳や熱も出てきたので会社を休むしかない。', 'のどのいたみに加えて、せきや熱も出てきたので会社を休むしかない。', '喉咙痛，还咳嗽、发烧，所以只有请假了。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('578eec1d-10a3-4949-b22a-3da75ef8681c', 'e3e600d9-f17b-4d3a-b99a-7267a548e5ac', '原油の高騰に加えて、農産物も値上がりした。', 'げんゆのこうとうに加えて、のうさんぶつもねあがりした。', '原油价格暴涨，农作物的价格也上涨了。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('774d3521-1caf-4151-b617-3c954c7a495d', '～に 応[こた]えて/に応え', NULL, 'N2', '名＋に応えて/に応え', '名＋に応えて/に応え', '表示响应，报答，“响应……”“应……”。', '常接在「 要[よう] 望[ぼう]/要求/期待」等词的后面，表示响应这些要求，或实现这些期待。「～に応えて/に応え」用在句中中顿。', 312, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('a8ef0542-a68f-46eb-ba79-409deaa3e0a4', '774d3521-1caf-4151-b617-3c954c7a495d', 'この美術館では、利用者の声に応えて、夏期の開館時間を1時間延長することにします。', 'この美術館では、りようしゃの声に応えて、かきの開館時間を1時間えんちょうすることにします。', '这个美术馆响应使用者的要求，决定将夏季开馆时间延长一小时。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('5cd1571c-a31b-4e2a-986f-6fb4119338f2', '774d3521-1caf-4151-b617-3c954c7a495d', '消費者の要求に応えて、よい製品を作っていかなければならない。', 'しょうひしゃのようきゅうに応えて、よいせいひんを作っていかなければならない。', '应消费者的要求，我们必须做出更好的产品。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('53e3d973-8433-4866-8922-24d432a515ca', '774d3521-1caf-4151-b617-3c954c7a495d', 'コーチは、これまで選手を育てることにすべてのエネルギーを注いできた。選手たちはこれに応えて、今年の大会で次々と新記録を出した。', 'コーチは、これまでせんしゅを育てることにすべてのエネルギーをそそいできた。選手たちはこれに応えて、今年の大会でつぎつぎとしんきろくを出した。', '教练迄今为止把自己所有的精力都倾注在了培养运动员上。作为回报，运动员们在今年的大赛中不断地创造新的纪录。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('9a204a0a-895a-45a8-9d3c-a0e095f1b15d', '～に 際[さい]して/に際し', NULL, 'N2', '動辞書形/名＋に際して/に際し', '動辞書形/名＋に際して/に際し', '“当……之际”“在……的时候”。', '包含“以某件事情为契机”的意思，属于书面语。「～に際して/に際し」用在句中中顿；「～に際しての」后面接名词。与「～にあたって/にあたり」类似。\n「～に際して」等同于「～際は」，如第一个例句中的「ご利用に際して」可以说成「ご利用の際は」。「～際は」前面接「動辞書形/名－の」。', 313, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('fd7587a8-7504-45d4-bbe3-311df06a5a46', '9a204a0a-895a-45a8-9d3c-a0e095f1b15d', '図書館のご利用に際しては、以下の点にご注意ください。', '図書館のご利用に際しては、いかの点にご注意ください。', '在使用图书馆的时候，请注意以下几点。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('096e96a3-9884-495c-9ebc-16a00f5e05a0', '9a204a0a-895a-45a8-9d3c-a0e095f1b15d', '契約に際して必要な書類をお知らせください。', 'けいやくひつようなしょるいをお知らせください。', '请告知签合同时所需的文件。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('22fc67cf-ec0e-4faa-aa99-7ddf5b55b818', '9a204a0a-895a-45a8-9d3c-a0e095f1b15d', '先生から卒業に際してのお別れのことばをいただきました。', '先生から卒業に際してのお別れのことばをいただきました。', '老师在毕业时跟我们说了很多临别的话语。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('a78d3379-c87b-437e-9e1b-82e014318652', '9a204a0a-895a-45a8-9d3c-a0e095f1b15d', '当日の受付の際は、招待状をお出しください。', 'とうじつのうけつけの際は、しょうたいじょうをお出しください。', '当天请在签到时出示邀请函。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('9e16e752-c038-4452-abc4-4f056dc3098e', '～に 先[さき] 立[だ]って/に先立ち', NULL, 'N2', '名＋に先立って/に先立ち', '名＋に先立って/に先立ち', '表示时间上的先后，“在……之前”“先于……”。', '表示在前项之前先做好后项，属于书面语。「～に先立って/に先立ち」用在句中中顿。', 314, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('27b30ece-7bb7-4e31-a92a-e17f718f0826', '9e16e752-c038-4452-abc4-4f056dc3098e', '会議の開始に先立って、新しいメンバーが紹介された。', '会議のかいしに先立って、新しいメンバーが紹介された。', '在会议开始前，先介绍了新的成员。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('5e33fbb2-fdd6-4138-9f7a-3e108b66d661', '9e16e752-c038-4452-abc4-4f056dc3098e', '今から野球大会を行います。試合開始に先立って、会長からごあいさつをいただきます。', '今から野球たいかいを行います。しあいかいしに先立って、かいちょうからごあいさつをいただきます。', '现在开始棒球比赛。在比赛开始之前，由会长致辞。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('f6509298-b34b-49f3-9771-5bc5d0fbe91d', '9e16e752-c038-4452-abc4-4f056dc3098e', '映画の一般公開に先立ち、プレミア試写会を行う予定だ。', '映画のいっぱんこうかいに先立ち、プレミアししゃかいを行う予定だ。', '预定在电影正式上映之前，举行首映礼。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('61885823-3081-47a4-a121-49aeb94fc7ff', '～に 従[したが]って/に従い', NULL, 'N2', '動辞書形/名＋に従って/に従い', '動辞書形/名＋に従って/に従い', '“按照……”“根据……”。\n“随着……”。', '前面经常为表示人、指示、规则等意义的名词，包含“遵从、服从”的意思。「～に従って/に従い」用在句中中顿。\n后项随着前项的变化而发生变化。', 315, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('256bc907-3de6-4845-aa0b-b759e90cdf44', '61885823-3081-47a4-a121-49aeb94fc7ff', '会議での決定に従って、来月から新製品の生産を開始することになった。', '会議でのけっていに従って、らいげつからしんせいひんのせいさんをかいしすることになった。', '根据会议做出的决定，下个月开始生产新产品。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('40a29ccc-727a-4356-b2f2-204519972685', '61885823-3081-47a4-a121-49aeb94fc7ff', '火災発生時は、係員の指示に従って冷静に行動してください。', 'かさいはっせいじは、かかりいんのしじれいせいにこうどうしてください。', '发生火灾时，请按照乘务员的指令冷静地采取行动。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('7cf90e84-1495-4db7-9d7f-536b0479e42c', '61885823-3081-47a4-a121-49aeb94fc7ff', '作業の手順はマニュアルに従って行わなければならない。', 'さぎょうのてじゅんはマニュアルに従って行わなければならない。', '工作的流程必须按照操作指南来进行。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('3900e6d6-6d72-4792-845c-f02b6b094031', '61885823-3081-47a4-a121-49aeb94fc7ff', '医学が進歩するに従って、平均寿命が延びた。', 'いがくがしんぽするに従って、へいきんじゅみょうがのびた。', '随着医学进步，人们的平均寿命延长了。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('2a9e1150-52a4-4664-9972-eabbf93bec42', '61885823-3081-47a4-a121-49aeb94fc7ff', '国の経済が発展するに従って、人々の暮らしもよくなってきた。', '国の経済が発展するに従って、ひとびとの暮らしもよくなってきた。', '随着国家经济的发展，人们的生活也越来越好了。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('1424edba-98ab-4ae5-8731-f6d8dfdd6c49', '61885823-3081-47a4-a121-49aeb94fc7ff', 'インターネットの普及に従って、情報共有化も進んでいる。', 'インターネットのふきゅうに従って、じょうほうきょうゆうかもすすんでいる。', '随着互联网的普及，信息共享化也不断发展。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('7bcea7f3-83f5-4453-acab-292ad4c304ed', '～にしたら/にすれば/にしても', NULL, 'N2', '名＋にしたら/にすれば/にしても', '名＋にしたら/にすれば/にしても', '表示立场，“从……立场来看”“在……看来”。', '接在表示人物的名词后面，表示站在他人的立场去推测他人的想法，注意不能用于表示站在说话人的立场。「～にしても」表示“即使从……来看”。', 316, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('199f0698-f375-4bd7-af55-bf2bf106220a', '7bcea7f3-83f5-4453-acab-292ad4c304ed', '不調だった山中選手がついにゴールを決めた。彼にしたら「もし、またミスをしたら」というプレッシャーは相当あったはずだ。', 'ふちょうだったやまなか選手がついにゴールを決めた。彼にしたら「もし、またミスをしたら」というプレッシャーはそうとうあったはずだ。', '一度状态不佳的山中选手终于胜局已定。于他而言，“如果再次失误的话”这样的压力应该是很大的吧。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('69dbd340-8a4e-42e2-9645-fcac005ab86c', '7bcea7f3-83f5-4453-acab-292ad4c304ed', '留学は今すぐではなく、大学を卒業してからにします。両親にしても、そのほうが安心でしょう。', '留学は今すぐではなく、大学を卒業してからにします。両親にしても、そのほうがあんしんでしょう。', '我打算等到大学毕业以后再去留学，而不是现在马上就去。即便是父母，也认为那样更放心吧。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('12c4b1c6-4a7b-462c-8369-ec01e7021dae', '7bcea7f3-83f5-4453-acab-292ad4c304ed', '突然父の病気を告げられて、彼女にしたらきっとショックだっただろう。', '突然父の病気をつげられて、彼女にしたらきっとショックだっただろう。', '突然被告知父亲的病情，对她而言一定是个打击吧。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('4df8c157-7589-424b-9f4a-6939606e5f58', '～にしては', NULL, 'N2', '～にしては', '～にしては', '表示评价的标准，“就……而言”。', '表示后项与前项叙述的事实不成比例，即从前项的事实出发进行某种合理的推测，可后项所表示的结果与这种推测并不相符。用于对他人或物的评价，不能用于说话人自己的事情。', 317, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('93f03cbb-4aa9-4fd9-b51b-c7ab51e6dc56', '4df8c157-7589-424b-9f4a-6939606e5f58', 'この子は小学生にしてはずいぶんしっかりしている。', 'この子は小学生にしてはずいぶんしっかりしている。', '这个孩子还是个小学生，却很是沉稳。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('ff50c890-6682-4ae9-9f35-5c72a9c28294', '4df8c157-7589-424b-9f4a-6939606e5f58', '初めてケーキを作ったにしては、上手にできましたね。', '初めてケーキを作ったにしては、上手にできましたね。', '就第一次做蛋糕而言，算是做得很不错了。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('ea7a055d-75d1-4084-83fb-884746a523ed', '4df8c157-7589-424b-9f4a-6939606e5f58', '彼は、タクシー運転手にしては道を知らない。', '彼は、タクシーうんてんしゅにしては道を知らない。', '他作为出租车司机而言算是不认路的。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('fb8380e8-9b60-4c12-9de4-3d4f2bf5071f', '～にしろ/にせよ/にしても', NULL, 'N2', '動/イ形普通形＋にしろ/にせよ/にしても＋動/イ形普通形＋にしろ/にせよ/にしても', '動/イ形普通形＋にしろ/にせよ/にしても＋動/イ形普通形＋にしろ/にせよ/にしても\nナ形語幹/名（－である）＋にしろ/にせよ/にしても＋ナ形語幹/名（－である）＋にしろ/にせよ/にしても', '表示让步，“即使……”“无论……”。\n“无论……还是……”。', '常与「どんなに/いくら」等词搭配使用，与「～ても/でも」类似。\n提出具有相反和对立意义的两个事物，表示“无论是哪一方面都……”。', 318, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('7093e743-4b87-4681-a805-a9e7f1493d07', 'fb8380e8-9b60-4c12-9de4-3d4f2bf5071f', 'この計画をこのまま進めるかやめるかいずれにしても早急に結論を出す必要があるだろう。', 'この計画をこのまますすそうきゅうにけつろんを出す必要があるだろう。', '是依照现状继续推进这个计划还是放弃，无论怎样，都有必要尽快给出结论吧。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('9a96ceae-274d-44a6-a299-f7a2a255a5bf', 'fb8380e8-9b60-4c12-9de4-3d4f2bf5071f', 'たった三日の旅行にせよ、準備は必要だ。', 'たった三日の旅行にせよ、じゅんびはひつようだ。', '即使是三天的旅行，也需要准备一下。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('a2d8988b-3785-4c1f-94fb-c25683498d8c', 'fb8380e8-9b60-4c12-9de4-3d4f2bf5071f', 'どんなに強そうに見える人にしても、心に弱いところがあるはずだ。', 'どんなに強そうに見える人にしても、心に弱いところがあるはずだ。', '无论是外表看起来多坚强的人，内心也应该有脆弱的地方。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('4a1238a1-d913-498b-9e96-ae42106fff73', 'fb8380e8-9b60-4c12-9de4-3d4f2bf5071f', '出席するにしろ欠席するにしろ、招待状の返事は早く出したほうがいい。', 'しゅっせきけっせきするにしろ、しょうたいじょうの返事は早く出したほうがいい。', '无论出席与否，收到邀请函后都请尽早回复。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('b6196832-e680-4204-8e0b-b096c2fd0d50', 'fb8380e8-9b60-4c12-9de4-3d4f2bf5071f', '引き受けるにしろ引き受けないにしろ、なるべく早く決めたほうがいい。', 'ひきうけるにしろ引き受けないにしろ、なるべく早く決めたほうがいい。', '无论是接受还是不接受，最好尽早决定下来。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('07e805f7-370f-47d8-a972-dc90d196a96b', 'fb8380e8-9b60-4c12-9de4-3d4f2bf5071f', '卒業後就職するにせよ、進学するにせよ、早く決めないといけない。', 'そつぎょうご就職するにせよ、しんがくするにせよ、早く決めないといけない。', '毕业后，无论是工作还是继续深造，都必须要尽早决定。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('ac9d3240-4775-44f5-b609-57e8a9fbd128', '～に 過[す]ぎない', NULL, 'N2', '～に 過[す]ぎない', '～に 過[す]ぎない', '“只不过……而已”。', '表示程度轻，常与「ただ/ほんの」等呼应使用。', 319, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('f232df8c-e913-4dc6-93a5-e07d694c5673', 'ac9d3240-4775-44f5-b609-57e8a9fbd128', '北川市は、かつては人口5千人の小さな村にすぎなかったが、今では人口50万人の大都市だ。', 'きたがわしは、かつてはじんこう5千人の小さな村にすぎなかったが、今では人口50万人の大都市だ。', '北川市曾经只不过是个拥有五千人口的小村镇，但现在已经是拥有五十万人口的大都市了。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('4aee0a4f-73f3-498b-9766-15a7f14ee4a6', 'ac9d3240-4775-44f5-b609-57e8a9fbd128', '人間の脳に関する研究で明らかになったことはまだほんの一部に過ぎないとはいえ、その研究は着実に進んできた。', '人間ののうに関する研究であきらかになったことはまだほんのいちぶに過ぎないとはいえ、その研究はちゃくじつにすすんできた。', '虽说在有关人的大脑的研究中了解到的还只不过是其中的一部分，但是这些研究正在稳步地向前发展。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('31d23a01-2bb6-40b2-aff3-c9d5b299a8e6', 'ac9d3240-4775-44f5-b609-57e8a9fbd128', 'これは、多くの不正の一つに過ぎない。まだたくさんの不正が隠されているはずだ。', 'これは、多くのふせいの一つに過ぎない。まだたくさんの不正がかくされているはずだ。', '这只是许多不正当行为中的一个而已，应该还有很多不正当行为没有暴露出来。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('c5c8f8e7-8dd5-483e-b8dc-de761ca5223f', '～に 相[そう] 違[い]ない', NULL, 'N2', '～に 相[そう] 違[い]ない', '～に 相[そう] 違[い]ない', '表示断定，“一定……”“肯定……”。', '表示说话人非常有把握，常用于书面语，与「～に 違[ちが]いない」用法相同。', 320, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('45577a06-9ffb-4361-8060-410508b51259', 'c5c8f8e7-8dd5-483e-b8dc-de761ca5223f', '服装はいつもとだいぶ違うが、やっぱりあれは田中さんに相違ない。', 'ふくそうはいつもとだいぶ違うが、やっぱりあれはたなかさんに相違ない。', '虽然穿着与平时大不相同，但是那个人肯定是田中。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('4fe43d02-79e3-41ea-914f-e9f42f40fb34', 'c5c8f8e7-8dd5-483e-b8dc-de761ca5223f', 'この地域の水汚染の問題を根本から解決するのは難しいに相違ない。', 'このちいきのみずおせんの問題をこんぽんから解決するのは難しいに相違ない。', '从根本上解决这个地区的水污染问题肯定是很难的。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('11101747-f64b-473f-985b-0d62b1bb00ee', 'c5c8f8e7-8dd5-483e-b8dc-de761ca5223f', '以上、上に申し上げたことは、事実に相違ありません。', '以上、上にもうしあげたことは、じじつに相違ありません。', '以上所述均为事实。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('8651b0a9-67f5-4468-811e-7ff5a4d589c5', '～に 沿[そ]って/に沿い', NULL, 'N2', '名＋に沿って/に沿い', '名＋に沿って/に沿い', '“沿着……”；“按照……”。', '「～に沿って」用在句中中顿；「～に沿った」后面接名词。', 321, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('9039aa49-99f2-4868-9b8b-b81ee7c3be0f', '8651b0a9-67f5-4468-811e-7ff5a4d589c5', '通りに沿って食べ物を売る店が並んでいる。', 'とおりに沿って食べ物を売る店がならんでいる。', '沿着马路，有很多卖食品的商店。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('4651863d-441b-4f3a-a53c-76242b29626c', '8651b0a9-67f5-4468-811e-7ff5a4d589c5', '会社の経営方針に沿って、来年度の計画を立てる。', '会社のけいえいほうしんに沿って、らいねんどの計画を立てる。', '根据公司的经营方针，制订下个年度的计划。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('40196195-c104-414e-8451-0e57a6638638', '8651b0a9-67f5-4468-811e-7ff5a4d589c5', 'この地域の実態に沿った対策を講じなければならない。', 'このちいきのじったいたいさくをこうじなければならない。', '必须制定符合当地实际情况的对策。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('c49e765b-9dd6-4d73-a997-826e49f268e5', '～に 違[ちが]いない', NULL, 'N2', '～に 違[ちが]いない', '～に 違[ちが]いない', '表示断定，“一定……”“肯定……”。', '表示说话人根据事实做出非常肯定的判断。与「～に 相[そう] 違[い]ない」相同。', 322, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('8eeed631-6505-43f3-82b7-3f38b192527f', 'c49e765b-9dd6-4d73-a997-826e49f268e5', '合計がこんなに大きい数字になるなんて、だれかが計算を間違えたに違いない。', 'ごうけいがこんなに大きい数字になるなんて、だれかがけいさんを間違えたに違いない。', '总计变成这么大的数字，肯定是谁算错了。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('c093e099-f277-442c-875f-29820f7a77e2', 'c49e765b-9dd6-4d73-a997-826e49f268e5', '水の汚染をこのままにしておくと、地球環境はますます悪くなるに違いない。', '水のおせんをこのままにしておくと、ちきゅうかんきょうはますます悪くなるに違いない。', '水污染的问题就这样放任不管的话，地球的环境肯定会日益恶化。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('e8792cf6-96ef-4d51-b966-d3e42cd95c1c', 'c49e765b-9dd6-4d73-a997-826e49f268e5', '彼は日本に10年以上住んでいたので、日本語のレベルが高いに違いない。', '彼は日本に10年以上住んでいたので、日本語のレベルが高いに違いない。', '他在日本生活了十多年，日语水平一定很高。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('c003779a-78cb-4e62-a97f-635ef8b6b5af', '～につき', NULL, 'N2', '名＋につき', '名＋につき', '“每……”。\n表示原因，“因为……”。', '有“平均分配”的意思。\n是很郑重的表示原因的用法，常用于通知、告示、书信等。', 323, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('f865088b-bf43-4096-aa5d-7f0d934600c2', 'c003779a-78cb-4e62-a97f-635ef8b6b5af', 'アルバイト料は、昼は1時間につき800円ですが、深夜は1000円です。', 'アルバイトりょうは、ひるは1時間につき800円ですが、しんやは1000円です。', '兼职的工资，白天是每小时800日元，深夜是每小时1000日元。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('d52a9515-834d-4116-a271-236d44657d7a', 'c003779a-78cb-4e62-a97f-635ef8b6b5af', '水道代は1か月につき3000円かかります。', 'すいどうだいは1か月につき3000円かかります。', '每个月水费要花费三千日元。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('aef0c169-10ee-474f-9974-8de86298ab2f', 'c003779a-78cb-4e62-a97f-635ef8b6b5af', 'この幼稚園は子ども10人につき一人の先生が配置されている。', 'このようちえんは子ども10人につき一人の先生がはいちされている。', '这个幼儿园，每十个孩子配备一名教师。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('d65aebb4-bccd-470a-8a8b-621e9c90697b', 'c003779a-78cb-4e62-a97f-635ef8b6b5af', '昼休みにつき、事務所は1時まで休みです。', '昼休みにつき、じむしょは1時まで休みです。', '午休时间，事务所一点钟以后上班。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('654df286-f844-4d67-ac51-e7be5d957bbb', 'c003779a-78cb-4e62-a97f-635ef8b6b5af', 'ただいま水道工事中につき、1週間休ませていただきます。', 'ただいますいどうこうじちゅうにつき、1週間休ませていただきます。', '由于正在维修下水道，暂停营业一个星期。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('09c6ada1-32e8-46d5-8e73-c9c7df549d3f', '～につけ/につけては/につけても', NULL, 'N2', '動辞書形/名＋につけ/につけては/につけても', '動辞書形/名＋につけ/につけては/につけても\n動辞書形/イ形/名＋につけ＋動辞書形/イ形/名＋につけ', '“每当……就……”。\n“不论……还是……都……”。', '常与「見る/聞く/考える」等动词搭配使用，后项一般是表示感情或思考等的内容。有「何かにつけ（动不动，每当有什么契机）」「 何[なに] 事[ごと]につけても（无论什么场合）」「それにつけても（总之；真是）」这样的惯用表达。\n列举两个具有对立意义的词，表示“无论是哪种情况”，偶尔也能列举并列意义的词。多为惯用表达，使用范围比较小。', 324, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('cae7d945-7337-48d4-b839-3b98f69471af', '09c6ada1-32e8-46d5-8e73-c9c7df549d3f', '今は都会になってしまったが、数年前までこのあたりは畑ばかりの田舎だった。それにつけても時の流れのなんと早いことか。', '今はとかいになってしまったが、数年前までこのあたりははたけばかりのいなかだった。それにつけても時の流れのなんと早いことか。', '这一带现在已经发展成城市了，但在几年前还是只有农田的乡村。时光飞逝啊。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('2b6df4e0-0e78-4a8e-a27e-0d146c08747b', '09c6ada1-32e8-46d5-8e73-c9c7df549d3f', 'この写真を見るにつけ、子どもの頃を思い出す。', 'この写真を見るにつけ、子どもの頃を思い出す。', '每当看到这张照片，我就会想起小时候的事情。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('5ac1dd5e-bab1-48c2-9419-5610679147b0', '09c6ada1-32e8-46d5-8e73-c9c7df549d3f', '社長は常に会社の状況をつかんでおかなければならない。いいにつけ、悪いにつけ、現状を報告させる必要がある。', '社長はつねに会社のじょうきょうをつかんでおかなければならない。いいにつけ、悪いにつけ、げんじょうをほうこくさせるひつようがある。', '社长必须时常掌握公司的状况。无论是好事还是坏事，都需要让下属汇报实情。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('6c9354e1-b062-4df6-835c-c1c6eb697cf3', '09c6ada1-32e8-46d5-8e73-c9c7df549d3f', '雨につけ、雪につけ、あの人は毎日30分のジョギングを続ける。', '雨につけ、雪につけ、あの人は毎日30分のジョギングを続ける。', '无论是下雨还是下雪，那个人都坚持每天慢跑30分钟。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('90bd1a7c-ddae-47bb-a553-15402d587df1', '09c6ada1-32e8-46d5-8e73-c9c7df549d3f', '彼はうれしいにつけ、悲しいにつけ、よくお酒を飲む。', '彼はうれしいにつけ、悲しいにつけ、よくお酒を飲む。', '他不管是高兴还是悲伤，都经常喝酒。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('ccad9461-e6e5-4232-a058-7a5a90bacf67', '～に 伴[ともな]って/に伴い', NULL, 'N2', '動辞書形/名＋に伴って/に伴い', '動辞書形/名＋に伴って/に伴い', '表示伴随，“随着……”。', '属于书面语，表示随着前项发生的变化，连带着发生后项的变化。「～に伴って/に伴い」用在句中中顿；「～に伴う」后面接名词。', 325, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('b970a65f-4141-4e9d-9dff-cb4c055905e0', 'ccad9461-e6e5-4232-a058-7a5a90bacf67', 'その島は、森林の減少に伴って、鳥や動物の数が減ってきている。', 'その島は、しんりんのげんしょうに伴って、鳥や動物の数が減ってきている。', '随着森林的减少，那个岛上的鸟类和动物的数量也在减少。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('373d6b2d-80f0-47c1-9557-7f5eb15d4c0b', 'ccad9461-e6e5-4232-a058-7a5a90bacf67', '現代の医学は進歩している。それに伴って、平均寿命が延びている。', 'げんだいのいがくはしんぽしている。それに伴って、へいきんじゅみょうがのびている。', '现代医学在不断进步。与此同时，人们的平均寿命也在延长。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('1ecfa59a-82e8-44fb-b55c-0803a0f36f7f', 'ccad9461-e6e5-4232-a058-7a5a90bacf67', '都心の人口増加に伴う住宅問題は深刻化している。', 'としんの人口ぞうかじゅうたくもんだいはしんこくかしている。', '中心城区的人口增加所带来的住房问题越来越严峻。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('160b81e5-20f3-40c1-8fec-384791f09a97', '～に 反[はん]して/に反し', NULL, 'N2', '名＋に反して/に反し', '名＋に反して/に反し', '“与……相反”。', '多与「期待/ 予[よ] 想[そう]/予測/ 命[めい] 令[れい]/ 意[い] 思[し]」等词搭配使用，表示结果与此相反。「～に反して/に反し」用在句中中顿；「～に反する」后面接名词。', 326, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('3fec7e3b-bd25-4a85-8200-1fe46eb92ecd', '160b81e5-20f3-40c1-8fec-384791f09a97', '政府は、今年こそ経済がよくなると予測していた。しかし、この予測に反して、12月になった今も相変わらずよくなっていない。', 'せいふは、今年こそ経済がよくなるとよそくしていた。しかし、この予測に反して、12月になった今もあいかわらずよくなっていない。', '政府预计今年经济会好转。但是，与预测相反，现在到了十二月份还是没有好转。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('afd1343b-936f-4f33-a99c-87418e869e6b', '160b81e5-20f3-40c1-8fec-384791f09a97', 'けさの天気予報では午後から晴れると言っていた。ところが、予報に反して、雨が降り続いている。', 'けさの天気よほうでは午後から晴れると言っていた。ところが、予報に反して、雨がふりつづいている。', '今天的天气预报说下午开始转晴。可与预报相反，还是在不停地下雨。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('9fb5346d-c054-4074-9fe7-c680cfc8b5f0', '160b81e5-20f3-40c1-8fec-384791f09a97', 'ルールに反する行為は失格となります。', 'こういはしっかくとなります。', '违反规则将失去比赛资格。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('a43813e0-5b56-4c8e-935e-bdd7e938e2ab', '～にほかならない', NULL, 'N2', '名＋にほかならない', '名＋にほかならない\n動/イ形普通形＋からにほかならない\nナ形語幹/名＋だ/である＋からにほかならない', '表示断定和强调，“正是……”“不外乎……”。\n强调原因，“正是因为……”。', '强调“除此之外，没有其他”。「～にほかならない」相当于「～だ」。\n强调“不是因为别的，正是因为这个原因”。「～からにほかならない」相当于「～からだ」。', 327, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('252410f5-4778-4c45-8403-7f6c2f22fcbf', 'a43813e0-5b56-4c8e-935e-bdd7e938e2ab', 'このイベントが成功したのは、周囲の支援とメンバー全員の努力の結果にほかならない。', 'このイベントが成功したのは、しゅういのしえんとメンバー全員の努力の結果にほかならない。', '这次活动取得成功，正是周围的人的支持和全体成员努力的结果。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('c4ff2f2f-1d12-4bb3-8c7c-671548205f07', 'a43813e0-5b56-4c8e-935e-bdd7e938e2ab', '今回の失敗の原因は、準備不足にほかならない。', '今回の失敗の原因は、じゅんびぶそくにほかならない。', '这次失败的原因无外乎是准备不充分。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('b722f82e-2a00-4077-a72d-6940fc399d7d', 'a43813e0-5b56-4c8e-935e-bdd7e938e2ab', '病気の時まっ先に見舞いに来てくれたのは、彼の友情の表れにほかならない。', '病気の時まっさきにみまいに来てくれたのは、彼のゆうじょうのあらわれにほかならない。', '我生病的时候他最先来探望我，这无疑是他的友情的表现。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('c268c3d0-9d24-44f0-88da-92b4c057dded', 'a43813e0-5b56-4c8e-935e-bdd7e938e2ab', 'その問題についていろいろな意見が出ているが、それは、みんなが関心を持っているからにほかならない。', 'その問題についていろいろな意見が出ているが、それは、みんながかんしんを持っているからにほかならない。', '关于这个问题，大家提出了很多意见，这正是因为大家对这个问题很关注。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('e22f3dc1-f51b-4302-a2c1-5ba51b1009da', 'a43813e0-5b56-4c8e-935e-bdd7e938e2ab', '途中で投げ出さず、最後までやりぬいたのは、家族の支えがあったからにほかならない。', 'とちゅうでなげださず、最後までやりぬいたのは、家族のささえがあったからにほかならない。', '正是因为有家人的支持，我才没有中途放弃，坚持到了最后。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('3da4943d-808d-4227-b171-7ffa0d5201c1', '～にもかかわらず', NULL, 'N2', '～にもかかわらず', '～にもかかわらず', '表示转折，“虽然……但是……”“尽管……却……”。', '后项的结果与根据前项的事实做出的推测不同。', 328, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('6ec6cb92-f00f-4cc0-9d83-d1bca4e38b22', '3da4943d-808d-4227-b171-7ffa0d5201c1', '駅前に新しくできたラーメン屋はいつも込んでいる。昨日も大雨にもかかわらず行列ができていた。', 'えきまえに新しくできたラーメン屋はいつも込んでいる。昨日もおおあめぎょうれつができていた。', '车站附近新开的拉面馆总是很多人。昨天尽管下大雨，但还是有人排队。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('856f77e9-e5a8-4c44-a7be-f700d82d82f5', '3da4943d-808d-4227-b171-7ffa0d5201c1', '彼は、夏休み中にもかかわらず、毎日図書館で勉強している。', '彼は、夏休みちゅうにもかかわらず、毎日図書館で勉強している。', '虽然是暑假，但他却每天在图书馆学习。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('17da7437-178e-4d01-a4f7-bb00b0e68412', '3da4943d-808d-4227-b171-7ffa0d5201c1', '野球大会の当日は、激しい雨が降っていた。それにもかかわらず大会は実施された。', 'やきゅうたいかいのとうじつは、激しい雨が降っていた。それにもかかわらず大会はじっしされた。', '棒球比赛当天，下了很大的雨。尽管如此，比赛还是照常进行了。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('12dad765-272b-4daf-992c-b55fda68ce8e', '～に 基[もと]づいて/に基づき', NULL, 'N2', '名＋に基づいて/に基づき', '名＋に基づいて/に基づき', '表示根据，“按照……”“根据……”。', '「～に基づいて/に基づき」用在句中中顿；「～に基づく/に基づいた」后面接名词。', 329, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('565a415c-8af9-415d-8c37-81fc25a74f2e', '12dad765-272b-4daf-992c-b55fda68ce8e', '調査結果に基づいて、論文を書く。', 'ちょうさけっかに基づいて、ろんぶんを書く。', '根据调查结果来写论文。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('e3d6fb0d-5440-49f6-b595-2a8ff2b9d076', '12dad765-272b-4daf-992c-b55fda68ce8e', 'これまでの研究に基づいてレポートをまとめた。', 'これまでの研究に基づいてレポートをまとめた。', '根据迄今为止的研究来总结出了报告。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('2b942f65-4039-422a-9e0d-35f5cb15dcfd', '12dad765-272b-4daf-992c-b55fda68ce8e', 'この作品は、実際に起こった事件の記録に基づいて描かれており、その内容が非常に感動的だったので、多くの人たちに強い印象を与えた。', 'この作品は、実際に起こった事件のきろくえがかれており、その内容が非常にかんどうてきだったので、多くの人たちに強いいんしょうを与えた。', '该作品是根据实际发生的事件来描写的，其内容十分感人，给很多人留下了深刻的印象。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('4b11b08b-2b1a-492b-89a8-af6cf82e7475', '～にわたって/にわたり', NULL, 'N2', '名＋にわたって/にわたり', '名＋にわたって/にわたり', '表示时间和空间的范围，“涉及……”“一直……”。', '强调“时间之长，范围之广”。「～にわたって/にわたり」用在句中中顿；「～にわたる/にわたった」后面接名词。', 330, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('89230be9-5ea8-4f20-984d-69fce6eac56f', '4b11b08b-2b1a-492b-89a8-af6cf82e7475', '踏切事故のために、2時間にわたり、電車がストップしました。', 'ふみきり事故のために、2時間にわたり、電車がストップしました。', '因为岔道口的事故，电车足足停了两个小时。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('5bd7d6b4-1a1b-4096-ad67-52bdd8b72744', '4b11b08b-2b1a-492b-89a8-af6cf82e7475', '公園の整備を求める住民と役所の話し合いは、10年長期にわたった。', '公園のせいびを求めるじゅうみんとやくしょのはなしあいは、10年ちょうきにわたった。', '为了完善公园设施，居民与政府之间展开了为期十年的协商。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('5c3868bc-9a8f-4f19-b43d-64e6430b1632', '4b11b08b-2b1a-492b-89a8-af6cf82e7475', 'ここから200メートルにわたって桜の並木が続いている。', 'ここから200メートルにわたって桜のなみきがつづいている。', '从这里往前200米的路两旁并排种着樱花树。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('003407ae-9855-4072-9c9d-5c87fecfba22', '～ 抜[ぬ]きで/抜きに/を抜きにして/は抜きにして', NULL, 'N2', '名＋抜きで/抜きに/を抜きにして/は抜きにして', '名＋抜きで/抜きに/を抜きにして/は抜きにして', '“省去……”“去掉……”。', '包含“省去一般情况下会有的东西”的意思。「～は抜きにして」相当于「～抜きで」，如例句中的「かたいあいさつは抜きにして」可以说成「かたいあいさつ抜きで」。', 331, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('d54f157c-9895-4cdf-bd13-a457b95f7e9c', '003407ae-9855-4072-9c9d-5c87fecfba22', '冗談ぬきでまじめに考えてください。', 'じょうだんぬきでまじめに考えてください。', '不要开玩笑了，请认真考虑。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('0362c407-0b00-4607-9a3d-4b27ae9803fd', '003407ae-9855-4072-9c9d-5c87fecfba22', 'かたいあいさつはぬきにして、さっそく乾杯しましょう。', 'かたいあいさつはぬきにして、さっそくかんぱいしましょう。', '免去繁琐的致辞，赶快干杯吧。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('12e0b009-7806-4cd7-ba42-8fa73f9ce320', '003407ae-9855-4072-9c9d-5c87fecfba22', '今日は時間がありません。あいさつは抜きにしてさっそく会議を始めましょう。', '今日は時間がありません。あいさつは抜きにしてさっそく会議を始めましょう。', '今天没有时间了。不讲客套话，马上开始会议吧。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('799b6eaa-0355-463d-bc14-619259adaf07', '～ 抜[ぬ]きでは/抜きには/を抜きにしては', NULL, 'N2', '名＋抜きでは/抜きには/を抜きにしては', '名＋抜きでは/抜きには/を抜きにしては', '“省去……的话”“（如果）没有……就不……”。', '「～抜きでは/抜きには/を抜きにしては」后面一定要与否定的表达方式呼应使用，如第三个例句中，由于前面用了「～を抜きにしては」，所以后面是否定形式「語れない」。', 332, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('a536c9ca-d3ae-4e2c-88f0-4c98ffa1f219', '799b6eaa-0355-463d-bc14-619259adaf07', 'この論文は先生の指導抜きには完成できない。', 'この論文は先生のしどうかんせいできない。', '这篇论文没有老师的指导是无法完成的。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('f20ee246-2a22-452e-b5e0-43529572f41a', '799b6eaa-0355-463d-bc14-619259adaf07', '契約更新の件に関しては、部長抜きでは決められない。', 'けいやくこうしんの件に関しては、部長抜きでは決められない。', '有关更新合同的事宜，部长不在是无法决定的。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('e32b7120-6278-4ab4-b686-c085fdf77a80', '799b6eaa-0355-463d-bc14-619259adaf07', 'この町の発展は観光事業を抜きにしては語れない。', 'このまちの発展はかんこうじぎょうかたれない。', '抛开旅游事业的话，这个城市的发展就无从谈起。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('f20e8394-d60b-49e9-a6aa-dc6c86f6868d', '～ 抜[ぬ]く', NULL, 'N2', '動ます形＋抜く', '動ます形＋抜く', '表示将某个动作做完，“……到底”“一直……”。', '包含“克服困难坚持到最后”的意思。', 333, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('b97b15a5-eb54-4f27-8f21-3a196f9f70e2', 'f20e8394-d60b-49e9-a6aa-dc6c86f6868d', 'あの人もずいぶん悩みぬいて、会社をやめることを決めたんでしょう。', 'あの人もずいぶん悩みぬいて、会社をやめることを決めたんでしょう。', '那个人也是经过一番苦思之后才决定了辞职的吧。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('3bfb1cf6-26cd-4213-b76c-b0d39d87fccb', 'f20e8394-d60b-49e9-a6aa-dc6c86f6868d', 'マラソン大会に出場するからには、よく練習をして42.195kmを走りぬきたい。', 'マラソン大会にしゅつじょうするからには、よく練習をして42.195kmを走りぬきたい。', '既然要参加马拉松比赛，就想好好练习，跑完42.195公里。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('bde7e453-8ef7-4589-8a6e-f31786f86c97', 'f20e8394-d60b-49e9-a6aa-dc6c86f6868d', '競争が激しい広告業界では新しい発想が生き抜くカギになる。', 'きょうそうが激しいこうこくぎょうかいでは新しいはっそうが生き抜くカギになる。', '在竞争激烈的广告界，新的创意成了生存下去的关键因素。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('344b4e99-aea8-4f31-b300-9435b7b7e136', '～のみならず', NULL, 'N2', '～のみならず', '～のみならず', '“不仅……，（而且……）”。', '相当于「～だけでなく」，可与「ただ」呼应使用，构成「ただ～のみならず」的句型。', 334, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('22e0d5a3-8fcf-420a-85d1-4b8ae2f23165', '344b4e99-aea8-4f31-b300-9435b7b7e136', '担当者のみならず、会社全体で不正な売買を行っていた。', 'たんとうしゃのみならず、会社ぜんたいでふせいなばいばいを行っていた。', '不仅是相关负责人，全公司都在进行非法交易。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('4b763083-d006-4c74-9f9d-2e05d1d4a9b6', '344b4e99-aea8-4f31-b300-9435b7b7e136', '最近、出生率の低下がいろいろ問題になっているが、この問題は、日本のみならず、ほかの国にもあるようだ。', '最近、しゅっしょうりつのていかがいろいろ問題になっているが、この問題は、日本のみならず、ほかの国にもあるようだ。', '最近，出生率低引起了很多问题，但这个问题并不仅仅是在日本，在其他国家也存在。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('03b37502-39e2-4a53-9976-c07c6bc3e1de', '344b4e99-aea8-4f31-b300-9435b7b7e136', 'このカメラは高性能であるのみならず、メモリーカードの容量も大きい。', 'このカメラはこうせいのうであるのみならず、メモリーカードのようりょうも大きい。', '这个相机不仅摄影性能好，存储卡的容量也很大。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('859be66a-8483-4a04-86d2-a56e0a3c3f96', '～のもとで/のもとに', NULL, 'N2', '名＋のもとで/のもとに', '名＋のもとで/のもとに', '表示范围，“在……下”。', '表示抽象的意义，包含“在某人的影响力涉及的范围之内”的意思。属于书面语，后面接名词时可用「～のもとでの＋名」的形式。', 335, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('5d28058f-86fc-4d53-9882-c8e841c959c7', '859be66a-8483-4a04-86d2-a56e0a3c3f96', '試合直前の打ち合わせをしようと、選手たちはコーチのもとに集まった。', '試合ちょくぜんの打ち合わせをしようと、選手たちはコーチのもとに集まった。', '比赛之前运动员们聚集在教练身边开碰头会。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('bdf887f1-d98d-4a46-bbef-3cc8fe5151e9', '859be66a-8483-4a04-86d2-a56e0a3c3f96', '坂本さんの論文は大変すばらしい。山田教授の指導のもとに修正を重ねた結果だということだ。', 'さかもとさんの論文は大変すばらしい。やまだきょうじゅのしどうしゅうせいをかさねた結果だということだ。', '坂本的论文很优秀。这是在山田教授的指导下不断修改的结果。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('1260f49a-56b8-45e4-86c0-a8b058d74504', '859be66a-8483-4a04-86d2-a56e0a3c3f96', '渡辺先生のもとで、日本の古典文学を研究している。', 'わたなべ先生のもとで、日本のこてんぶんがくを研究している。', '在渡边老师的指导下，研究日本的古典文学。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('519daa77-9b3c-48e1-b11c-7cc58e88ba7b', '～の 名[な]のもとに', NULL, 'N2', '名＋の名のもとに', '名＋の名のもとに', '“以……为名”“在……的名义之下”。', '属于「～のもとに」句型中的一种。多用于负面的事情，有“以……作为借口”的意思。', 336, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('a99baa6e-c3b9-48f0-bfc1-5960a18b4a4c', '519daa77-9b3c-48e1-b11c-7cc58e88ba7b', '「開発」の名のもとに大規模な森林破壊が進んでいる。', '「かいはつだいきぼなしんりんはかいがすすんでいる。', '以“开发”为名，大量的森林不断被破坏。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('d4771642-13f6-434a-bb0b-c2903266e05b', '519daa77-9b3c-48e1-b11c-7cc58e88ba7b', '自由と正義の名のもとに戦争が繰り返されている。', 'じゆうとせいぎせんそうがくりかえされている。', '以自由和正义之名不断发动战争。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('b521ec7d-0cf4-4723-9d60-ef580e37187b', '～ばかりか', NULL, 'N2', '～ばかりか', '～ばかりか', '表示递进，“不但……”“不只是……”。', '类似于「～だけでなく」「～のみならず」「～ばかりでなく」，此时常常与「～も/まで/さえ」呼应使用（如第一和第二个例句）。\n还可以接在「動ない形－ない」的后面，表示“不但不……反而……”，即否定前项，并提出程度更高的后项。', 337, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('1730e6f1-791d-4df9-a362-28d9783fa0a0', 'b521ec7d-0cf4-4723-9d60-ef580e37187b', '彼は、銀行からの借金が数百万円もあって、返せずにいるという。そればかりか友人たちからも相当のお金を借りているらしい。', '彼は、銀行からのしゃっきんゆうじんたちからもそうとうのお金を借りているらしい。', '听说他从银行借了几百万，还还不起。不仅如此，好像还从朋友那儿借了不少钱。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('465c16b3-1592-4ca3-811d-4e58d4dec869', 'b521ec7d-0cf4-4723-9d60-ef580e37187b', '若いころはお金がなくて、その日の食事にも困ることがあった。そんなとき下宿のおばさんは、私に食事をごちそうしてくれたばかりか、しばらく暮らせるだけのお金まで貸してくれた。', '若いころはお金がなくて、その日の食事にも困ることがあった。そんなときげしゅくのおばさんは、私に食事をごちそうしてくれたばかりか、しばらく暮らせるだけのお金まで貸してくれた。', '年轻的时候没钱，有时甚至连吃饭都成问题。那时，房东阿姨不但请我吃饭，甚至还借给我一段时间的生活费。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('44676ee4-8525-464c-9e59-b6fd0c571af3', 'b521ec7d-0cf4-4723-9d60-ef580e37187b', '薬を飲んでも、風邪は治らないばかりか、もっとひどくなってきた。', '薬を飲んでも、風邪はなおらないばかりか、もっとひどくなってきた。', '吃了药，感冒不但没好，反而加重了。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('c9adb639-b3f6-45ad-8dc4-42d7247519a9', '～ばかりに', NULL, 'N2', '～ばかりに', '～ばかりに', '表示不好的原因，“就是因为……”“正因为……”。', '后项多表示意料之外的、不好的结果。', 338, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('b0ed6480-607c-48a7-8a2f-e16b5117b67f', 'c9adb639-b3f6-45ad-8dc4-42d7247519a9', 'みんなの前でパソコンが得意だなんて話すんじゃなかった。よけいなことを言ったばかりにクラス会の案内状作りを頼まれてしまった。', 'みんなの前でパソコンが得意だなんて話すんじゃなかった。よけいなことを言ったばかりにクラス会のあんないじょうづくりを頼まれてしまった。', '真不该在大家面前说自己电脑很擅长。就因为多嘴，结果被安排去制作班会的邀请函。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('e8c9cb84-75e1-4e51-9151-33bca8d2ce14', 'c9adb639-b3f6-45ad-8dc4-42d7247519a9', 'パーティーの場所を聞いたばかりに、手伝いを頼まれてしまった。', 'パーティーの場所を聞いたばかりに、手伝いを頼まれてしまった。', '就因为问了派对举行的场所，被拜托去帮忙。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('a079320d-efc8-4750-a671-3df9030686db', 'c9adb639-b3f6-45ad-8dc4-42d7247519a9', '父は学歴がなかったばかりに、相当苦労したそうだ。', '父はがくれきがなかったばかりに、そうとうくろうしたそうだ。', '据说父亲就因为没有学历，受了很多苦。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('4e958b24-5c19-4e7f-b76f-8b61f2af0edf', '～はともかく（として）', NULL, 'N2', '名＋はともかく（として）', '名＋はともかく（として）', '“……暂且不谈”“先不说……”。', '表示先考虑后项，而不考虑前项。', 339, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('b74fa47b-4135-4c6a-92eb-8c2db10ecb9d', '4e958b24-5c19-4e7f-b76f-8b61f2af0edf', 'このレストラン、ちょっと高いんですけど、値段はともかく味はいいですね。', 'このレストラン、ちょっと高いんですけど、値段はともかく味はいいですね。', '这家餐厅的菜有点贵，不过撇开价格不说，味道还是不错的。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('30e125c3-af80-4c3e-bdc4-dece66fdf5c5', '4e958b24-5c19-4e7f-b76f-8b61f2af0edf', 'この店の料理は、味はともかく量は多い。', 'この店の料理は、味はともかく量は多い。', '这家店的菜，味道怎么样暂且不说，分量是挺足的。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('18fd1ef6-255d-4068-891f-149a3d8d6a4b', '4e958b24-5c19-4e7f-b76f-8b61f2af0edf', '結果はともかくとして、全員が精一杯力を出し切ったすばらしい試合だった。', '結果はともかくとして、全員がせいいっぱい力をだしきったすばらしい試合だった。', '结果怎样暂且不说，这是一场大家都拼尽了全力的精彩的比赛。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('82c3cbcc-22f6-41ec-8956-ddcfce6d3a72', '～は 別[べつ]として', NULL, 'N2', '～は 別[べつ]として', '～は 別[べつ]として', '“……另当别论”“……暂且不论”。', '与「～は別にして」相同。', 340, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('3dec177b-d791-4b43-9ce5-22dac038a6c3', '82c3cbcc-22f6-41ec-8956-ddcfce6d3a72', 'ほかの科目は別として、数学はとても得意だ。', 'ほかのかもくは別として、数学はとても得意だ。', '其他科目就另当别论了，数学是很擅长的。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('4da1978a-c854-4b7e-8478-9230ffc3b6ea', '82c3cbcc-22f6-41ec-8956-ddcfce6d3a72', 'おいしいかどうかは別として一度食べてみたいと思う。', 'おいしいかどうかは別として一度食べてみたいと思う。', '好不好吃暂且不说，我想去尝尝看。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('a459abca-c1c4-47e6-9267-9a3825ac31c6', '82c3cbcc-22f6-41ec-8956-ddcfce6d3a72', '得意かどうかは別として、サッカーが大好きだ。', '得意かどうかは別として、サッカーが大好きだ。', '擅不擅长暂且不说，我是很喜欢足球的。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('d8b5c09d-5b95-4860-baf5-5c64da74bf90', '～はもちろん/はもとより', NULL, 'N2', '名＋はもちろん/はもとより', '名＋はもちろん/はもとより', '“……自不必说”“不用说……”。', '「～はもとより」比「～はもちろん」更书面化。前项是比较具有代表性的事物，后项是与前项同一范畴的其他事物。常和「も/まで/でも」等呼应使用，构成「～はもちろん/はもとより～も/まで/でも」的形式。', 341, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('6f9e3fa8-52b8-4467-865a-aacff6412d51', 'd8b5c09d-5b95-4860-baf5-5c64da74bf90', 'わたしたちの学校には指導熱心な先生方が多いが、中でも、経験豊富な山田先生は生徒はもとより保護者からの信頼も厚い。', 'わたしたちの学校にはしどうねっしんな先生方が多いが、中でも、けいけんほうふな山田先生はせいとほごしゃからのしんらいも厚い。', '我们学校里有很多老师都很热心地指导我们，其中，经验丰富的山田老师不仅受到学生的爱戴，学生家长也都非常信赖他。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('4f02862e-5301-44d9-b1d8-2bc884c3d3f3', 'd8b5c09d-5b95-4860-baf5-5c64da74bf90', '面接試験では、話し方はもちろん、服装などにも気をつける必要がある。', 'めんせつ試験では、話し方はもちろん、ふくそうなどにも気をつける必要がある。', '面试时，说话的方式就不用说了，着装也需要注意。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('50f0c649-be6b-419b-9422-d8adb1144112', 'd8b5c09d-5b95-4860-baf5-5c64da74bf90', '最近、日本では大学生はもちろん、小学生までパソコンを使うようになった。', '最近、日本では大学生はもちろん、小学生までパソコンを使うようになった。', '最近在日本，大学生就不用说了，连小学生都开始用电脑了。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('56e40866-5f8e-4102-9e67-79bfe338e1c8', '～ 反[はん] 面[めん]/半面', NULL, 'N2', '～ 反[はん] 面[めん]/半面', '～ 反[はん] 面[めん]/半面', '“另一方面……”。', '表示同一事物的正反两面，即前项是叙述积极的一面，后项是叙述消极的一面。另外，「その反面（では）」常用于连接两个句子，表示“而另一方面”。', 342, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('41013df7-010a-4f7c-abd3-cf9551a6dfdf', '56e40866-5f8e-4102-9e67-79bfe338e1c8', '現代の若者は、子どもの時からテレビやインターネットなどでさまざまな情報に接する機会が多い。その反面、実物を見たりさわったりする体験が不足している。', 'げんだいのわかものは、子どもの時からテレビやインターネットなどでさまざまなじょうほうにせっするきかいが多い。その反面、じつぶつを見たりさわったりするたいけんがふそくしている。', '现在的年轻人从小时候开始就有很多机会通过电视和互联网去接触各种各样的信息。另一方面，看到和接触实物的体验却很缺乏。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('af47dc25-6962-4c63-961a-e27656a03a2d', '56e40866-5f8e-4102-9e67-79bfe338e1c8', 'この車は、空気を汚さない反面、価格が高いという欠点がある。', 'この車は、空気をよごさない反面、かかくが高いというけってんがある。', '这个车，不污染空气，但也有价格昂贵的缺点。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('57be98e8-c717-4d60-b3ea-4d806ca8ab45', '56e40866-5f8e-4102-9e67-79bfe338e1c8', 'この布は水に強い反面、熱には弱い。', 'この布は水に強い反面、熱には弱い。', '这种布料防水性很强，但不耐热。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('a763145c-a451-40ae-b01e-f6b7f0dd2be1', '～ほか（は）ない/よりほか（は）ない/ほかしかたがない', NULL, 'N2', '動辞書形＋ほか（は）ない/よりほか（は）ない/ほかしかたがない', '動辞書形＋ほか（は）ない/よりほか（は）ない/ほかしかたがない', '表示不得已做某事，“只有……”“只好……”。', '与「～しか～ない」相同，包含“虽然心里不想这么做，但是别无他法，不得已去做”的意思。', 343, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('1e187f19-e5b3-4f15-b4c4-869815ede548', 'a763145c-a451-40ae-b01e-f6b7f0dd2be1', 'その人を雇うかどうかは書類だけでは決められないから、結局は実際に本人に会って判断するよりほかはない。', 'その人をやとうかどうかはしょるいだけでは決められないから、けっきょくはじっさいにほんにんに会ってはんだんするよりほかはない。', '单凭资料没法决定是否雇用那个人，所以最终只能见见本人之后来判断。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('f558507b-527f-4b0f-92d6-0cfa5570837e', 'a763145c-a451-40ae-b01e-f6b7f0dd2be1', '夫も子どもも亡くなってしまって、たった一人の弟に頼るほかない。', '夫も子どももなくなってしまって、たった一人の弟にたよるほかない。', '丈夫和孩子都去世了，只能依靠唯一的一个弟弟。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('db697479-f1fc-4516-995f-40e4ef364fa5', 'a763145c-a451-40ae-b01e-f6b7f0dd2be1', '終電がなくなったので、タクシーで帰るほかしかたがない。', 'しゅうでんがなくなったので、タクシーで帰るほかしかたがない。', '末班车也没了，只好打车回去了。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('20d26e63-5e09-4bd6-9bb7-23a2437dc8aa', '～まい/まいか', NULL, 'N2', '動辞書形＋まい/まいか', '動辞書形＋まい/まいか\n動2ない形＋まい/まいか\n（する→するまい/すまい/するまいか/すまいか）\n（くる→くるまい/こまい/くるまいか/こまいか）', '表示否定的意志，“不想……”“不会……”。\n表示否定的推测，“不会……吧”“也许不……”。', '相当于「～ないようにしよう/ないつもりだ」，表示说话人的决心和意志。\n「～まい」相当于「～ないだろう」，如第一个例句中的「信じまい」可以说成「信じないだろう」。「～まいか」常用于「～（の）ではあるまいか」，相当于「～（の）ではないか」，表示“难道不是……吗”，用反问的形式来表示肯定，是说话人表达自己的主张的说法。如第二个例句中，说话人实际上是认为「お客様と相談する必要がある」。', 344, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('633b3850-581d-43ee-a6e7-678156044794', '20d26e63-5e09-4bd6-9bb7-23a2437dc8aa', '日本へ来てしばらくは、国へ電話はかけるまいと思っていたが、今日はさびしくてたまらず、ついかけてしまった。', '日本へ来てしばらくは、国へ電話はかけるまいと思っていたが、今日はさびしくてたまらず、ついかけてしまった。', '原本想刚来日本的这段时间不要打电话回国的，但今天实在是太寂寞了，忍不住打了电话。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('c6087935-e241-462a-94f1-9c405d66501e', '20d26e63-5e09-4bd6-9bb7-23a2437dc8aa', 'あんなところは二度と行くまい。', 'あんなところは二度と行くまい。', '那种地方再也不去了。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('d89f82c4-7517-41df-ab82-cb6ca015103a', '20d26e63-5e09-4bd6-9bb7-23a2437dc8aa', 'あいつと大喧嘩をして、もう二度と会うまいと決心した。', 'あいつとおおげんかをして、もう二度と会うまいとけっしんした。', '和那个家伙大吵了一架，决定再也不见他了。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('d860371d-25e2-45a9-b9f3-9ffeba15b173', '20d26e63-5e09-4bd6-9bb7-23a2437dc8aa', '面倒だが、やはりこの仕事は断れない。引き受けるしかあるまい。', 'めんどうだが、やはりこの仕事はことわれない。引き受けるしかあるまい。', '虽然很麻烦，但我还是没法推掉这项工作。只能接下来了吧。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('db449e24-a368-40aa-9400-0503cbf3504d', '20d26e63-5e09-4bd6-9bb7-23a2437dc8aa', '自分の目で確かめない限り、そんな恐ろしいことはだれも信じまい。', '自分の目でたしかめない限り、そんなおそろしいことはだれも信じまい。', '如果不是自己亲眼看到，那么恐怖的事情恐怕谁也不会相信的吧。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('dad0b429-f493-4ac8-8bca-e778aab39b0a', '20d26e63-5e09-4bd6-9bb7-23a2437dc8aa', 'この件についてお客様と相談する必要があるのではあるまいか。', 'このけんについておきゃくさまとそうだんするひつようがあるのではあるまいか。', '这件事情难道不需要和客户商量吗？', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('7b3ba9ec-c010-418e-9ef3-1b5ef9cf9485', '～まま（に）', NULL, 'N2', '動辞書形/名－の＋まま（に）', '動辞書形/名－の＋まま（に）\n動られる（受身）＋まま（に）', '表示随心所欲，“任凭……”“听凭……”。\n表示任凭别人摆布，“任凭……”。', '可以搭配的词很有限，多为惯用表达，如「足の向くまま/気の向くまま/思うまま」表示随自己所想，有“想怎么样就怎么样”的意思。\n表示处于很被动的立场，没有了自己的主观判断，后项多带有消极的意义。还可以用「動受身＋が＋まま（に）」的形式。', 345, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('1c2a40f3-6913-4664-bb53-7a96fccefdd2', '7b3ba9ec-c010-418e-9ef3-1b5ef9cf9485', '足の向くまま散策に出かける。', '足のむさんさくに出かける。', '走到哪儿算哪儿，就那样随心所欲地去散步。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('d8e294c4-1cb7-4969-a81d-a52dbd5c80b1', '7b3ba9ec-c010-418e-9ef3-1b5ef9cf9485', 'このブログは自分の身の回りの出来事を気のままに書いたものだ。', 'このブログは自分のみのまわりの出来事を気のままに書いたものだ。', '在这个博客上随心所欲地写一些自己身边发生的事情。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('b19634fc-48a3-4a6d-96b7-297771288044', '7b3ba9ec-c010-418e-9ef3-1b5ef9cf9485', '日記というのは、日々の生活を感じたまま、思ったままに書くものだ。', '日記というのは、日々の生活を感じたまま、思ったままに書くものだ。', '日记就是将自己在平日生活里的所想写下来的东西。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('96c2b54f-7c0b-438f-a66f-e1c492dbc232', '7b3ba9ec-c010-418e-9ef3-1b5ef9cf9485', '店員に勧められるままに高価なバッグを買ってしまい、後悔している。', '店員にすすこうかなバッグを買ってしまい、こうかいしている。', '任凭店员推荐买了昂贵的手提包，现在很是后悔。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('577b6335-92d6-41eb-b87b-9016e4768df5', '7b3ba9ec-c010-418e-9ef3-1b5ef9cf9485', '店員に勧められるまま、大きいソファーを買ってしまった。', '店員に勧められるまま、大きいソファーを買ってしまった。', '听凭店员推荐，买了很大的沙发。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('a116d376-6dbe-4564-ab94-d476928727bc', '7b3ba9ec-c010-418e-9ef3-1b5ef9cf9485', '友だちに誘われるまま、マンガの同好会に入った。', '友だちに誘われるまま、マンガのどうこうかいに入った。', '听朋友劝诱，加入了漫画爱好者协会。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('9f2ebc31-1fd9-4728-85ff-0892e824874f', '～もかまわず', NULL, 'N2', '動普通形－の/名＋もかまわず', '動普通形－の/名＋もかまわず', '表示不把某事放在心上，“不顾……”。', '第二个例句的「人目もかまわず」是惯用表达，表示“不顾及别人的目光”。', 346, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('032c925f-7529-4237-916a-36710e0ea6c5', '9f2ebc31-1fd9-4728-85ff-0892e824874f', '彼は、けがをした足が痛むのもかまわず、工事現場を見てまわった。', '彼は、けがをした足がいたむのもかまわず、こうじげんばを見てまわった。', '他不顾脚伤的疼痛，视察了施工现场。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('acf44335-8d28-4be0-a162-9a265008ba4a', '9f2ebc31-1fd9-4728-85ff-0892e824874f', '電車の中で人目もかまわず、化粧をする女性がいる。', '電車の中でひとめもかまわず、けしょうをする女性がいる。', '有些女性不顾众目睽睽在电车中化妆。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('3f539b97-a84f-4109-8930-467f31cb120c', '9f2ebc31-1fd9-4728-85ff-0892e824874f', 'びしょ濡れになるのもかまわず、家出した猫を探し回った。', 'びしょぬれになるのもかまわず、いえでした猫をさがしまわった。', '不顾浑身被淋湿，四处寻找离家出走的猫。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('b1ec338a-238a-4d99-be7b-609d0016b849', '～も 当[とう] 然[ぜん]だ', NULL, 'N2', '～も 当[とう] 然[ぜん]だ', '～も 当[とう] 然[ぜん]だ', '“……也是理所当然的”。', '说话人站在旁观者的立场，根据前项的事实或理由，认为后项也是理所当然或可以理解的。', 347, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('7387eff1-48f1-4fd1-b3ea-c781c3c5ddd1', 'b1ec338a-238a-4d99-be7b-609d0016b849', '3週間も水をやらなかったのだから、花が枯れてしまうのも当然だ。', '3週間も水をやらなかったのだから、花がかれてしまうのも当然だ。', '因为三个星期没浇水，花枯掉了也是理所当然的。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('220b5c58-0fb7-4f43-8804-d0a3fd158c68', 'b1ec338a-238a-4d99-be7b-609d0016b849', '大事な書類をなくしたんだから、上司に叱られるのも当然だ。', '大事な書類をなくしたんだから、じょうしに叱られるのも当然だ。', '把重要文件弄丢了，被上司斥责也是理所当然的。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('ec785f42-882b-4016-aa38-57645e2482b8', 'b1ec338a-238a-4d99-be7b-609d0016b849', 'あんなひどいことを言われては、彼が怒るのも当然だ。', 'あんなひどいことを言われては、彼が怒るのも当然だ。', '别人对他说了那么过分的话，他生气也是理所当然的。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('a7674642-7f0c-48f8-87bb-12e353fd6e88', '～も～なら～も～だ', NULL, 'N2', '名＋も＋ナ形語幹/名＋なら＋名＋も＋名＋だ', '名＋も＋ナ形語幹/名＋なら＋名＋も＋名＋だ', '表示双方都不好，都不像样。', '表示A、B双方都不像样，都不好。惯用表达有「親も親なら子も子だ/夫も夫なら妻も妻だ」等。', 348, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('bb24ef04-7a0c-40df-a9e7-dadd15d73225', 'a7674642-7f0c-48f8-87bb-12e353fd6e88', 'あそこの家の父親は、毎日朝から酒を飲んで暴れている。息子は、仕事もせず賭けごとに夢中になっている。まったく、父も父なら子も子だ。', 'あそこの家の父親は、毎日朝から酒を飲んであばれている。息子は、仕事もせずかけごとに夢中になっている。まったく、父も父なら子も子だ。', '那家的父亲，每天从早上就开始喝酒胡闹。儿子也不工作，沉迷于赌博。真是有其父必有其子。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('21a5ecd2-2939-434f-a56a-90e07e5a276c', 'a7674642-7f0c-48f8-87bb-12e353fd6e88', '夜中に夫婦喧嘩をして近所に迷惑をかけるなんて、夫も夫なら妻も妻だ。', 'よなかにふうふげんかをしてきんじょに迷惑をかけるなんて、夫も夫なら妻も妻だ。', '夫妻俩大半夜吵架打扰到邻居，丈夫也不好妻子也有问题。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('4a0e524d-ee2d-4207-be34-71a7403ebd7a', '～ものか/もんか', NULL, 'N2', '動/イ形/ナ形の名詞修飾形＋ものか/もんか', '動/イ形/ナ形の名詞修飾形＋ものか/もんか', '表示强烈的否定，“怎么会……呢”“不会……”。', '表示说话人再也不做某事的强烈的意志。口语中常用，还有更随便的说法「～もんか」。女性常用「～ものですか/もんですか」的形式。', 349, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('035d3057-b472-48bf-bf03-0df1a18e6ed7', '4a0e524d-ee2d-4207-be34-71a7403ebd7a', '注文も計算も間違えるような、あんなレストランには、もう二度と行くものか。', 'ちゅうもんもけいさんも間違えるような、あんなレストランには、もう二度と行くものか。', '那种把点的菜弄错，结账也出错的餐厅我再也不会去了。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('70496955-5e88-4cae-b308-dcc861cbd296', '4a0e524d-ee2d-4207-be34-71a7403ebd7a', '私は歌が上手ですって。上手なもんですか。あなたのほうがずっと上手ですよ。', '私は歌が上手ですって。上手なもんですか。あなたのほうがずっと上手ですよ。', '你说我唱歌唱得好？哪里唱得好了，你比我唱得好多了。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('6f5b60b1-ccf0-41f0-9774-f22f5d8197d2', '4a0e524d-ee2d-4207-be34-71a7403ebd7a', 'あんな高いレストランは二度と行くものか。', 'あんな高いレストランは二度と行くものか。', '那么贵的餐厅谁还会再去啊。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('08edb379-5e61-44fe-a770-8ca05c045670', '～ものがある', NULL, 'N2', '動/イ形/ナ形の名詞修飾形＋ものがある', '動/イ形/ナ形の名詞修飾形＋ものがある', '表示评价和感受，“有……的一面”“的确很……”。', '表示具有某种因素，让说话人有某种感觉。常用「～には～ものがある」的形式，前面一般接现在时。', 350, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('d5c88c09-51bb-4dfe-91f7-3694988ff024', '08edb379-5e61-44fe-a770-8ca05c045670', 'こんな単純な作業を3時間も続けるのは、つらいものがある。', 'こんなたんじゅんなさぎょうを3時間も続けるのは、つらいものがある。', '这么简单的操作要持续三个小时，真是很无聊。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('28681968-390c-4723-b366-ecaad27ceb4c', '08edb379-5e61-44fe-a770-8ca05c045670', '彼女の演奏には、人の心を動かすものがある。', '彼女のえんそうには、人の心をうごかすものがある。', '她的演奏很打动人心。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('9e3e5d6c-2fba-4c98-b7f8-b32e34b4720f', '08edb379-5e61-44fe-a770-8ca05c045670', '彼は、性格は別として、絵の才能には見るべきものがある。', '彼は、性格は別として、絵のさいのうには見るべきものがある。', '且不论他的性格如何，在绘画方面他确实有值得我们欣赏的才能。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('db2adcc1-ec3f-43eb-9ede-b5f4679e6f5d', '～ものだから', NULL, 'N2', '～ものだから', '～ものだから', '表示原因，“因为……”。', '口语中还可以说「（だって）～もんだから」，用于解释、辩解。', 351, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('80a4561d-18a6-4df1-8aff-feb64a124f6c', 'db2adcc1-ec3f-43eb-9ede-b5f4679e6f5d', '娘があまりに楽しみにしていたものだから、遊園地に行けなくなったことをすぐには言い出せなかった。', '娘があまりに楽しみにしていたものだから、ゆうえんちに行けなくなったことをすぐには言い出せなかった。', '因为女儿一直很期待，所以去不了游乐园这件事没能马上说出口。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('9fa2c785-3b07-4411-8dc0-1bd2317c0a23', 'db2adcc1-ec3f-43eb-9ede-b5f4679e6f5d', '以前から欲しかった本がやっと手に入ったものだから、早速徹夜しておわりまで読んでしまった。', '以前から欲しかった本がやっと手に入ったものだから、さっそくてつやしておわりまで読んでしまった。', '因为很早以前就想要的一本书终于弄到手了，所以赶紧通宵读完了。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('b4faa295-e49e-4e14-8330-1b80c4d38f5e', 'db2adcc1-ec3f-43eb-9ede-b5f4679e6f5d', '言葉が通じないものだから、友達ができない。', '言葉がつうじないものだから、友達ができない。', '因为语言不通，所以交不到朋友。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('2ec83241-794e-4c9d-97f4-fa7546e36610', '～ものではない', NULL, 'N2', '動辞書形＋ものではない', '動辞書形＋ものではない', '表示从道德、社会常识出发，给予忠告和劝说，“不应该……”“不要……”。', '是「～ものだ」的第一种用法，即表示一般常识时的否定形式。', 352, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('d62fcc95-f890-4e83-bfc1-9dab37539674', '2ec83241-794e-4c9d-97f4-fa7546e36610', '常識のある大人なら、目上の人に対して失礼なことを言うものではない。', 'じょうしきのある大人なら、めうえの人に対して失礼なことを言うものではない。', '如果是有常识的大人的话，就不应该对长辈说出无礼的话。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('77dd4c8e-38d0-40b4-a35e-3f38158610d7', '2ec83241-794e-4c9d-97f4-fa7546e36610', '希望する会社に就職できなかったくらいで、そんなにがっかりするものではない。', '希望する会社に就職できなかったくらいで、そんなにがっかりするものではない。', '没能到理想的公司工作，不要因为这么点事情就垂头丧气。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('0ee68054-2435-4347-8657-8d701f817452', '2ec83241-794e-4c9d-97f4-fa7546e36610', '消費者を騙すようなことをするものではない。', 'しょうひしゃをだますようなことをするものではない。', '不应该做那些欺骗消费者的事情。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('1aed50d8-eca5-46c2-8376-aea785494597', '～ものなら', NULL, 'N2', '動可能形＋ものなら', '動可能形＋ものなら\n動意向形＋ものなら', '表示假设，“如果能……的话”。\n表示假设，“如果要……的话”。', '表示虽然是可能性很小，几乎无法实现的事情，但说话人还是有强烈的愿望。\n后项一般是比较严重的事情，而且是说话人能预料到的某种结果。', 353, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('640128fd-141e-4195-8283-8dfee5292e10', '1aed50d8-eca5-46c2-8376-aea785494597', '山田「今度の連休、木村さんは温泉に行くみたいだよ。森さんはどこかに行かないの？」森「行けるものなら行きたいけど、今度の連休は仕事が入っちゃったんだよね。」', '山田「今度の連休、木村さんは温泉に行くみたいだよ。森さんはどこかに行かないの？」森「行けるものなら行きたいけど、今度の連休は仕事が入っちゃったんだよね。」', '山田：“这次的连休，木村好像要去泡温泉。森你去哪里吗？”\n森：“如果能去的话我也想去啊，但是这次的连休已经安排了工作了啊。”', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('d65d24bf-2e56-4fb8-88f6-a5a3e9e6b342', '1aed50d8-eca5-46c2-8376-aea785494597', 'あの日の記憶を消せるものなら消してしまいたい。', 'あの日のきおくをけせるものなら消してしまいたい。', '如果可以的话，真想把那天的记忆给消除了。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('4f43c0d0-a42c-48e1-8b14-48f123d8f765', '1aed50d8-eca5-46c2-8376-aea785494597', '外国にいる子どもが病気だと聞いて心配しない親はいない。できるものなら、すぐに看病に行ってやりたいと思うだろう。', '外国にいる子どもが病気だと聞いて心配しない親はいない。できるものなら、すぐにかんびょうに行ってやりたいと思うだろう。', '听说在国外的孩子生病了，没有哪个父母不担心的。如果可以的话，应该很想马上去照顾的吧。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('35d14450-dc36-4a19-8115-9d362992148e', '1aed50d8-eca5-46c2-8376-aea785494597', '昔は親に反抗しようものなら、すぐに叩かれたものだ。', '昔は親にはんこうしようものなら、すぐにたたかれたものだ。', '以前如果要反抗父母的话，马上就会被斥责的。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('4ef44a88-009e-4189-8d1f-55df8ac90544', '1aed50d8-eca5-46c2-8376-aea785494597', '母の作った料理に文句をつけようものなら、次の日から食事を作ってもらえない。', '母の作った料理にもんくをつけようものなら、次の日から食事を作ってもらえない。', '要是对妈妈做的菜挑三拣四的话，她第二天就不会做给我吃了。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('25a3085e-d0d1-48bd-9be9-7acd1920eb8d', '1aed50d8-eca5-46c2-8376-aea785494597', '本当のことを彼女に言おうものなら、きっとパニックになるだろう。', '本当のことを彼女に言おうものなら、きっとパニックになるだろう。', '要是把真相告诉她的话，一定会惊慌失措的吧。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('d54bd227-f4ff-4091-a4a6-42c36f5fd186', '～ものの', NULL, 'N2', '～ものの', '～ものの', '表示转折，“虽然……但是……”。', '「～とはいうものの」为惯用句型，表示“虽说……”。', 354, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('177df769-3abc-4933-a322-167a73c0af72', 'd54bd227-f4ff-4091-a4a6-42c36f5fd186', 'あの映画は一度見たものの、話の筋がまったくわからなかった。', 'あの映画は一度見たものの、話のすじがまったくわからなかった。', '那部电影虽然看过一次，但完全没明白它在说什么。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('e03e3b87-27a5-4068-a699-01e053ccf2f4', 'd54bd227-f4ff-4091-a4a6-42c36f5fd186', '若い人に人気のあるゲームだというのでやってはみたものの、わたしには無理だった。', '若い人に人気のあるゲームだというのでやってはみたものの、わたしには無理だった。', '因为是很受年轻人喜欢的游戏，所以我就玩了玩，但觉得没什么意思。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('974b49cd-c030-44f5-ac67-c529dd827d7e', 'd54bd227-f4ff-4091-a4a6-42c36f5fd186', '3日でレポートを書くとは言ったものの、3日ではとても書けなかった。', '3日でレポートを書くとは言ったものの、3日ではとても書けなかった。', '虽然我说了三天之内把报告写好，但三天还是没能写好。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('421109a5-9d85-4c08-b3d7-d12e5221e923', '～も～ば～も', NULL, 'N2', '名＋も＋動ば形/イ形ば形＋名＋も', '名＋も＋動ば形/イ形ば形＋名＋も\n名＋も＋ナ形語幹/名＋なら＋名＋も', '“既……又……”。', '列举多个事项或多种属性。', 355, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('18e9665a-876e-4188-814b-d4b3b6fa2dcb', '421109a5-9d85-4c08-b3d7-d12e5221e923', 'うちの子はまだ中学生だが、料理も作れば、洗濯もしてくれる。', 'うちの子はまだ中学生だが、料理も作れば、せんたくもしてくれる。', '我孩子虽然还是中学生，但是既会做饭，又帮我洗衣服。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('d5738500-a36d-46f3-ba73-fcac877c5800', '421109a5-9d85-4c08-b3d7-d12e5221e923', 'このバッグは値段も手頃なら、デザインもかわいくてすぐ買ってしまった。', 'てごろなら、デザインもかわいくてすぐ買ってしまった。', '这个包价格适中，设计也很可爱，我马上就买了下来。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('f91f764f-377f-47fa-8a1f-bdfd36f9dd51', '～やら～やら', NULL, 'N2', '動辞書形/イ形/名＋やら＋動辞書形/イ形/名＋やら', '動辞書形/イ形/名＋やら＋動辞書形/イ形/名＋やら', '表示列举，“又是……又是……”“一会儿……一会儿……”。', '从几项中列举两项，包含“又是这样，又是那样”的感觉。', 356, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('e73e22c7-bd37-43d5-bcd2-13b4b64b05a3', 'f91f764f-377f-47fa-8a1f-bdfd36f9dd51', 'ポケットにはハンカチやらガムやらが入っている。', 'ポケットにはハンカチやらガムやらが入っている。', '口袋里装着手帕啦口香糖啦之类的东西。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('88c52f9d-158a-4419-b39e-93c513e8fba9', 'f91f764f-377f-47fa-8a1f-bdfd36f9dd51', '彼に突然プロポーズされて、びっくりするやらうれしいやらでとても複雑な気持ちだ。', '彼に突然プロポーズされて、びっくりするやらうれしいやらでとてもふくざつな気持ちだ。', '突然被男友求婚，又是吃惊，又是高兴，心情很复杂。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('50d4814f-f0e4-4f94-a5b6-8ddcc0f78ebd', 'f91f764f-377f-47fa-8a1f-bdfd36f9dd51', '今日は財布を落とすやらレポートを忘れるやら、散々な一日だった。', '今日は財布を落とすやらレポートを忘れるやら、さんざんな一日だった。', '今天又是丢钱包，又是忘带报告，真是狼狈的一天。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('03ee6b2d-1e87-4724-b4a5-74443c9ff5d2', '～ようで', NULL, 'N2', '～ようで', '～ようで', '“看上去好像……，但……”。', '后项多与「実は/本当は/実際は」等搭配使用，表示“看上去……实际上（并不是这样）……”。', 357, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('ba95caf8-d8e6-4dee-96d9-0241a6ad6ef4', '03ee6b2d-1e87-4724-b4a5-74443c9ff5d2', '彼は冷静なようで、本当はあわてものなんです。', '彼はれいせいなようで、本当はあわてものなんです。', '他看上去好像沉着冷静，可实际上是个冒失鬼。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('154147bc-c745-43d2-93a6-9c040098ad88', '03ee6b2d-1e87-4724-b4a5-74443c9ff5d2', '敬語の使い方はわかっているようで実は間違って使っていることが意外と多い。', 'けいごじつは間違って使っていることがいがいと多い。', '敬语的用法看上去好像都懂，但实际上误用的情况出乎意料得多。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('1e24c8d1-da35-4e96-878d-165421ca1a04', '03ee6b2d-1e87-4724-b4a5-74443c9ff5d2', 'この料理は一見簡単なようで、実際作ってみると案外難しい。', 'この料理はいっけん簡単なようで、じっさい作ってみるとあんがい難しい。', '这道菜看起来很简单，但实际做起来却出乎意料得难。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('df1c753a-3320-4d46-9f27-751e76b16f58', '～ようでは', NULL, 'N2', '動辞書形·ない形－ない＋ようでは', '動辞書形·ない形－ない＋ようでは', '表示假设，“如果……的话，那就……”。', '后项一般接不好的，与期望相反的事物，或者接「～ない/難しい/困る/だめだ」等。', 358, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('4e53fa2c-aae4-47b7-a89b-3c8ee60ebccd', 'df1c753a-3320-4d46-9f27-751e76b16f58', '締め切り直前になってテーマを変えるようでは、いい論文は書けないだろう。', 'しめきりちょくぜんになってテーマを変えるようでは、いいろんぶんは書けないだろう。', '在截止日期快到的时候改变主题的话，是写不出好论文的吧。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('d2935416-10df-4129-95d1-3c536c0fa3a0', 'df1c753a-3320-4d46-9f27-751e76b16f58', 'この程度の練習で文句を言うようでは次の試合に勝てないぞ。', 'このていどの練習でもんくを言うようでは次の試合に勝てないぞ。', '如果这点训练都要抱怨的话，下次比赛可赢不了！', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('8bd63d98-da2e-4801-ad51-d1b043589dec', 'df1c753a-3320-4d46-9f27-751e76b16f58', 'こんな簡単な問題が解決できないようでは、困る。', 'こんな簡単な問題がかいけつできないようでは、困る。', '如果这么简单的问题都解决不了的话就难办了。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('e341fa09-f59c-4490-9d60-ab750dc38b22', '～ようなら（ば）/ようだったら/ようであれば', NULL, 'N2', '～ようなら（ば）/ようだったら/ようであれば', '～ようなら（ば）/ようだったら/ようであれば', '表示假定，“如果……”。', '是「～ようだ」的假定形，「～ようだったら」也可以说成「～ようでしたら」。', 359, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('99f647c9-4a97-4407-94f5-3eb8966cf16c', 'e341fa09-f59c-4490-9d60-ab750dc38b22', '（ホームページで）Q：ゲームをしていたら、急に画面が暗くなってしまいました。どうしたらいいでか。A：一度電源を切り、1分くらい経ってからまたつけてみてください。ただし、同じことが何度も繰り返されるようならば故障です。修理を依頼してください。', '（ホームページで）Q：ゲームをしていたら、急にがめんが暗くなってしまいました。どうしたらいいでか。A：一度でんげんを切り、1分くらいたってからまたつけてみてください。ただし、同じことが何度もくりかえこしょうです。しゅうりをいらいしてください。', '（在主页上）Q：正在玩游戏的时候，突然屏幕就变暗了。应该怎么办呢？\nA：先切断电源，等过了一分钟左右再试着打开。但是，如果同样的情况反复多次出现那就是故障了。请找人修理。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('a10f761a-9eb2-4324-91f9-dd00b66b5af3', 'e341fa09-f59c-4490-9d60-ab750dc38b22', '明日もまた仕事を休むようなら、会社をやめてもらいます。', '明日もまた仕事を休むようなら、会社をやめてもらいます。', '如果明天还不来上班的话，就不要来了（你就递辞呈吧）。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('8c75b9f8-8472-4b82-8e0f-7f0c3527d966', 'e341fa09-f59c-4490-9d60-ab750dc38b22', '体の具合が悪いようだったら病院に行ってください。', '体のぐあいが悪いようだったら病院に行ってください。', '如果身体不舒服的话，就去医院看看。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('f7be8b48-9371-4855-9045-cdd4123762c8', 'e341fa09-f59c-4490-9d60-ab750dc38b22', '医者「明日になっても熱が下がらないようであれば、この薬を飲んでください。」', '医者「明日になっても熱が下がらないようであれば、この薬を飲んでください。」', '医生“到了明天体温还是不降的话，请服用这个药。”', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('1edac072-5a5d-4065-b40b-c23d1da9ff80', '～わりに（は）', NULL, 'N2', '動/イ形/ナ形/名の名詞修飾形＋わりに（は）', '動/イ形/ナ形/名の名詞修飾形＋わりに（は）', '表示比较的基准，“虽然……但是……”；“比起……”。', '表示由前项应该理所当然地预想到某个结果，可实际上却不是这个结果。后项与前项不成比例，不协调，类似于「～にしては」。', 360, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('81e20450-3bb7-49a2-96b8-6dd0cfb3d478', '1edac072-5a5d-4065-b40b-c23d1da9ff80', 'そのアルバイトは、仕事が大変できついわりに給料が安いよ。', 'そのアルバイトは、仕事が大変できついわりに給料が安いよ。', '那份兼职，工作很辛苦，工资却很低。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('1db72ac4-c688-4640-86bc-a2cd755827d9', '1edac072-5a5d-4065-b40b-c23d1da9ff80', '調査の結果、若者の言葉づかいにきびしいわりには、40代、50代の人の多くが言葉の正確な意味を理解していないことがわかった。', '調査の結果、若者の言葉づかいにきびしいわりには、40代、50代の人の多くが言葉のせいかくないみをりかいしていないことがわかった。', '调查结果表明，很多四十几岁、五十几岁的人对年轻人的措辞要求很严格，但他们自己都没有理解词的正确含义。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('3072eb8f-7b52-4054-9104-d8f239dd4e33', '1edac072-5a5d-4065-b40b-c23d1da9ff80', 'このレストランは高いわりにはうまいとは言えない。', 'このレストランは高いわりにはうまいとは言えない。', '这家饭店消费很高但却算不上好吃。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('24fae9d7-3611-42ca-b518-f53ef75e7e5b', '～をかねて', NULL, 'N2', '名＋をかねて', '名＋をかねて', '“兼有……的目的”“顺带着……”。', '表示在做某事的同时兼顾了另外一个目的。', 361, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('501af1e1-0fcd-4a6c-be4d-9d8e92c02699', '24fae9d7-3611-42ca-b518-f53ef75e7e5b', '冬場のトレーニングをかねて、友人と雪合戦に取り組んだ。', 'ふゆばのトレーニングをかねて、友人とゆきがっせんにとりくんだ。', '为了顺带做一下冬天的运动，和朋友一起打起了雪仗。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('3b050959-08b3-4f22-974f-fc0b7c6bb8a3', '24fae9d7-3611-42ca-b518-f53ef75e7e5b', '中小企業に関する情報収集をかねて、説明会に参加した。', 'ちゅうしょうきぎょうに関する情報しゅうしゅうをかねて、せつめいかいに参加した。', '为了顺带收集中小企业的相关信息，参加了说明会。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('cc79e3c0-7ca6-4871-9046-20824ad2f0e2', '24fae9d7-3611-42ca-b518-f53ef75e7e5b', '飲食店の勉強をかねて、アルバイトとして働き始めた。', 'いんしょくてんの勉強をかねて、アルバイトとして働き始めた。', '为了顺带学习一下餐饮业知识，开始在餐馆里打工。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('3e7cd285-3e94-4191-9848-868866777867', '～を 中[ちゅう] 心[しん]に（して）/を中心として', NULL, 'N2', '名＋を中心に（して）/を中心として', '名＋を中心に（して）/を中心として', '“以……为中心”“把……作为重点”。', '后面接名词时，可以用「～を中心とする/を中心とした/を中心にした」的形式。', 362, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('e35db2fc-1bd5-47bd-8386-897dd4dd9a6a', '3e7cd285-3e94-4191-9848-868866777867', 'この作者の作品は、若い女性を中心に読まれている。', 'このさくしゃのさくひんは、若いじょせいを中心に読まれている。', '这位作家的作品是以年轻的女性为主要的读者群。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('4f59ce1c-142f-4fd0-9fa2-e60b551b18f2', '3e7cd285-3e94-4191-9848-868866777867', '午前中は文法を勉強する。午後は会話を中心に勉強することになっている。', '午前中は文法を勉強する。午後は会話を中心に勉強することになっている。', '上午学习语法，下午以学习会话为主。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('4bf951a4-7388-4bc4-8acd-df9c3faa3716', '3e7cd285-3e94-4191-9848-868866777867', '弊社は関東地方を中心に事業を展開しております。', 'へいしゃはかんとうちほうじぎょうをてんかいしております。', '本公司以关东地区为中心开展事业。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('fab45b93-2b56-42e6-af5e-6175c7fa9318', '～を 通[つう]じて/を 通[とお]して', NULL, 'N2', '名＋を通じて/を通して', '名＋を通じて/を通して', '表示整个范围。\n表示中介或手段，“通过……”。', '接在时间名词的后面，表示整个期间。此时一般用「～を通じて」比较多。\n前面的名词充当中介，起到了积极的作用。', 363, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('0cc3ab0a-3e3b-4216-bef7-8ccd50d9ee95', 'fab45b93-2b56-42e6-af5e-6175c7fa9318', 'この地域は一年を通じて暖かくて、とても過ごしやすい。', 'このちいきは一年を通じて暖かくて、とても過ごしやすい。', '这里一年到头都很暖和，很适合居住。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('8c629acd-c7d4-4616-b252-5e69fa004c76', 'fab45b93-2b56-42e6-af5e-6175c7fa9318', '一生を通じて学び続けることが大事だ。', 'いっしょうまなびつづけることが大事だ。', '一生不断地去学习是很重要的。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('28323d7e-a768-4cca-b425-6f2dec0480c4', 'fab45b93-2b56-42e6-af5e-6175c7fa9318', '佐藤さんご夫妻とは、山口さんを通じて知り合いました。', 'さとうさんごふさいとは、やまぐちさんを通じて知り合いました。', '我是通过山口认识了佐藤夫妇的。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('fad36fec-6d13-46b9-a392-467e34194373', 'fab45b93-2b56-42e6-af5e-6175c7fa9318', '先輩を通して、入学試験の案内をもらった。', '先輩を通して、にゅうがくしけんのあんないをもらった。', '通过学长，拿到了入学考试的指南。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('d80685e9-8b50-470b-995a-87b0b8847cfb', 'fab45b93-2b56-42e6-af5e-6175c7fa9318', 'このレポートは実態調査を通して得た情報をまとめたものだ。', 'このレポートはじったいちょうさえたじょうほうをまとめたものだ。', '这份报告是将实况调查得到的信息总结而成的。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('ad352e2b-4da9-4da1-b629-2a0aa177bff7', '～を 問[と]わず/は問わず', NULL, 'N2', '名＋を問わず/は問わず', '名＋を問わず/は問わず', '“无论……”“不管……”。', '前面经常接表示正反意义的名词或者包含程度差异的名词，如「 男[だん] 女[じょ]/  昼[ちゅう] 夜[や]/  有[う] 無[む]/ 年[ねん] 齢[れい]/  性[せい] 別[べつ]」等。', 364, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('5959b4bd-a250-449d-85ea-2a47cd020689', 'ad352e2b-4da9-4da1-b629-2a0aa177bff7', '（広告で）川西ピアノ教室では、初心者、経験者を問わず、どなたにでも丁寧に指導します。', '（こうこくで）かわにしピアノ教室では、しょしんしゃ、経験者を問わず、どなたにでも丁寧に指導します。', '（广告）在川西钢琴教室，不管您是初学者还是曾经学习过，我们对每位都会耐心指导。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('ac5f7911-2064-4896-8da3-da9e4f79f210', 'ad352e2b-4da9-4da1-b629-2a0aa177bff7', '私たちのサークルは、ゴルフの経験の有無をとわず、だれでも入れます。', '私たちのサークルは、ゴルフの経験のうむをとわず、だれでもはいれます。', '我们这个社团对有没有打高尔夫球的经验没有要求，谁都可以加入。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('a1b9d1c5-155b-487c-9e46-5e367e837134', 'ad352e2b-4da9-4da1-b629-2a0aa177bff7', 'この公園では、季節を問わず美しい花が見られます。', 'この公園では、季節を問わず美しい花が見られます。', '在这个公园，无论哪个季节都可以看到美丽的花。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('ff120e26-60a2-46e3-afca-0901d58a4366', '～を 除[のぞ]いて（は）/を除き', NULL, 'N2', '名＋を除いて（は）/を除き', '名＋を除いて（は）/を除き', '“除……之外”。', '属于书面语，用法类似于「～のほか」。', 365, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('c7f31c60-a6a7-4e29-a9cc-08eeff699d6e', 'ff120e26-60a2-46e3-afca-0901d58a4366', 'この仕事は楽だし、給料もいいし、通勤時間が長いことをのぞいては文句ない。', 'この仕事は楽だし、給料もいいし、つうきんじかんもんくない。', '这份工作很轻松，工资也高，除了上下班时间长点之外没有什么好抱怨的。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('a4f6ee1b-f635-4c68-9ff2-1fe9c6c0354d', 'ff120e26-60a2-46e3-afca-0901d58a4366', '商品の品質に問題がある場合を除いて、返品はお受けできません。', 'しょうひんのひんしつに問題がある場合を除いて、へんぴんはお受けできません。', '除了商品的质量问题以外我们不接受退货。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('95a37412-36ac-43a5-be75-b793abdf2151', 'ff120e26-60a2-46e3-afca-0901d58a4366', '日曜日を除いて、毎日働いている。', '日曜日を除いて、毎日働いている。', '除了星期天，每天都工作。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('87d39f1b-8e35-4da9-b2b9-b9e013351121', '～をめぐって/をめぐり', NULL, 'N2', '名＋をめぐって/をめぐり', '名＋をめぐって/をめぐり', '“围绕……”。', '使用范围有一定限制，后项多与「議論する/討論する/ 争[あらそ]う/ 対[たい] 立[りつ]する」等动词搭配使用。\n「～をめぐって/をめぐり」用在句中中顿；「～をめぐる」后面接名词。', 366, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('ae8d6e9b-ed9d-41c2-a8c0-dd6f72ef3f02', '87d39f1b-8e35-4da9-b2b9-b9e013351121', 'その政治家がスピーチで言った一言をめぐって、さまざまな議論がわき起こっている。', 'そのせいじかがスピーチで言ったひとことをめぐって、さまざまなぎろんがわき起こっている。', '围绕那位政治家演说时说的一句话，展开了各种各样的议论。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('fd371a77-aefb-44b8-b951-2b792bf2d519', '87d39f1b-8e35-4da9-b2b9-b9e013351121', '外国人社員の労働条件をめぐって、会社側と労働者側が対立している。', '外国人社員のろうどうじょうけんをめぐって、かいしゃがわとろうどうしゃがわがたいりつしている。', '围绕外国籍员工的劳动条件，劳资双方对立起来。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('f48759e9-fd81-4452-b90b-7d2623f927c1', '87d39f1b-8e35-4da9-b2b9-b9e013351121', '医療制度の改革をめぐる議論が高まっている。', 'いりょうせいどのかいかくぎろんがたかまっている。', '围绕医疗制度的改革，讨论越来越激烈。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('7a9aeada-5d8e-4aec-a72c-e0996224b9b6', '～をもとに（して）', NULL, 'N2', '名＋をもとに（して）', '名＋をもとに（して）', '“以……为基础”“以……为依据”。', '用法类似于「～に 基[もと]づいて」。「～をもとにしての」后面接名词。', 367, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('2d31da0b-edc0-4d5f-ba73-1f08790dd9d1', '7a9aeada-5d8e-4aec-a72c-e0996224b9b6', '昨日見たドラマは、実際にあった話をもとに作られたそうだ。', '昨日見たドラマは、じっさいにあった話をもとに作られたそうだ。', '据说昨天看的电视剧是根据真实的故事而制作的。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('fbd6cd18-c33d-4513-b3f8-e80467324ad3', '7a9aeada-5d8e-4aec-a72c-e0996224b9b6', '日本語のクラスは、テストの点数と今までの学習期間をもとに決定される。', '日本語のクラスは、テストのてんすうと今までのがくしゅうきかんけっていされる。', '根据考试的分数和之前的学习时间来决定日语班的分班。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('344b3b67-4d93-4a31-bdfe-7a8a80d6c6e2', '7a9aeada-5d8e-4aec-a72c-e0996224b9b6', '平仮名とカタカナは漢字をもとにして作られたものだ。', 'ひらがなとカタカナはかんじをもとにして作られたものだ。', '平假名和片假名是以汉字为基础创造出来的。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('6005fd0c-8e08-45d1-8ce2-6def529a50f7', 'お/ご～いただけませんか', NULL, 'N2', 'お/ご～いただけませんか', 'お/ご～いただけませんか', '“能否请您……”，表示礼貌地请求对方为自己一方做某事。', NULL, 368, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('1a1b25bc-cdc0-46ab-a6fd-b8674c7265e2', '6005fd0c-8e08-45d1-8ce2-6def529a50f7', '少々お待ちいただけませんか。', 'しょうしょうお待ちいただけませんか。', '能否请您稍等片刻？', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('9f353718-426f-4804-bc3e-d39e02fc69c0', '6005fd0c-8e08-45d1-8ce2-6def529a50f7', 'すみませんが、約束の時間をご変更いただけませんか。', 'へんこういただけませんか。', '对不起，能否请您改一下约定的时间？', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('3ecbee4a-a8b4-452f-9c97-c9636b24e4a0', '6005fd0c-8e08-45d1-8ce2-6def529a50f7', '皆様にはご迷惑をおかけいたしますが、どうかご理解いただけないでしょうか。', 'みなさまにはごめいわくをおかけいたしますが、どうかご理解いただけないでしょうか。', '给大家添麻烦了，敬请谅解。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('537ef72d-0bc8-4285-937b-e1bb28333658', 'お/ご～ 願[ねが]えませんか', NULL, 'N2', 'お/ご～ 願[ねが]えませんか', 'お/ご～ 願[ねが]えませんか', '礼貌地请求对方做某事。', '除了「～願う」之外，还有「～願えないでしょうか」、「～願えませんか」等多种形式。', 369, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('a73d2435-4d27-4e65-a8bf-90bff7ed0eae', '537ef72d-0bc8-4285-937b-e1bb28333658', 'お忙しいところ申し訳ありませんが、何とかお引き受け願えませんでしょうか。', 'お忙しいところもうしわけありませんが、何とかお引き受け願えませんでしょうか。', '在您百忙之中实在不好意思，无论如何能否请您接受呢？', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('0da30cb3-e933-4af0-b98c-85e02e4c7e6b', '537ef72d-0bc8-4285-937b-e1bb28333658', 'この資料の翻訳にご協力願えませんか。', 'きょうりょく願えませんか。', '请您帮忙翻译一下这份资料好吗？', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('7ac0d95c-9f9e-4d08-a826-61db9df1fc46', '537ef72d-0bc8-4285-937b-e1bb28333658', '電話があったことをお伝え願えませんか。', 'つたえ願えませんか。', '请您转告他我打过电话来好吗？', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('525c8fe8-a176-4e7b-b86a-40f1fea0720c', 'お/ご～ 申[も う]し 上[あ]げる', NULL, 'N2', 'お/ご～ 申[も う]し 上[あ]げる', 'お/ご～ 申[も う]し 上[あ]げる', '比「お/ご～する/いたす」更谦恭的表达方式。', '使用范围比较小，常见「お願い申し上げます」、「お詫び申し上げます」等固定的用法。', 370, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('b426770d-3580-4cc5-99c0-be964af7b586', '525c8fe8-a176-4e7b-b86a-40f1fea0720c', '「このたびは、私どもの商品発送ミスにより、お客様に大変ご迷惑をおかけしましたことを深くお詫び申し上げます。申し訳ございませんでした。」', '「このたびは、わたくしどものしょうひんはっそうわび申し上げます。申し訳ございませんでした。」', '这次由于我们的商品发送错误，给顾客带来了很大的麻烦，在此深表歉意。实在对不起。”', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('37ae9241-adec-4f7c-ac60-7ac3277e41da', '525c8fe8-a176-4e7b-b86a-40f1fea0720c', 'お願い申し上げます。', 'お願い申し上げます。', '拜托了。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('06b7afc3-62b1-43c9-853e-8f1d847a598d', '525c8fe8-a176-4e7b-b86a-40f1fea0720c', '大変ご迷惑をおかけしたことをお詫び申し上げます。', '大変ごめいわくわび申し上げます。', '给您添麻烦了，真是很抱歉。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('507d766f-0941-4e5c-9382-c900b43bb8e5', '～（さ）せていただけませんか', NULL, 'N2', '動使役形－て形＋いただけませんか', '動使役形－て形＋いただけませんか', '“能否允许我……”“请让我……”，表示请求上级或者长辈允许自己做某事。', '表示委婉的请求，自谦语的固定表达方式。', 371, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('13c61003-4108-4e7f-a3e7-8d79f27f6f54', '507d766f-0941-4e5c-9382-c900b43bb8e5', '（メールで）田中です。先日お話があったスピーチの件なんですが、ぜひわたしにやらせていただけないでしょうか。', '（メールで）たなかです。せんじつお話があったスピーチの件なんですが、ぜひわたしにやらせていただけないでしょうか。', '我是田中。有关前些天提及的演讲一事，能否让我来做呢？', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('5b78a822-b459-4763-8812-15f6389a8ebc', '507d766f-0941-4e5c-9382-c900b43bb8e5', '申し訳ありませんが、来週の火曜日休ませていただけませんか。', '申し訳ありませんが、来週の火曜日休ませていただけませんか。', '不好意思，下周二能否让我休息？', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('5854cb57-d9b1-4cd6-ac4f-43a238db4e14', '507d766f-0941-4e5c-9382-c900b43bb8e5', '課長、今度のプロジェクトに参加させていただけないでしょうか。', '課長、今度のプロジェクトに参加させていただけないでしょうか。', '课长，能否让我参加这次的项目？', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('38899084-4a25-4782-8042-4716c15914af', '～（さ）せてやっていただけませんか', NULL, 'N2', '動使役形－て形＋やっていただけませんか', '動使役形－て形＋やっていただけませんか', '表示委婉的请求，“能否让……做呢？”', '常用来请求对方将某件事交给第三者来做，第三者多为自己一方的人。也可用「～させてやっていただけないでしょうか」。', 372, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('564dc064-865a-4cce-adeb-1e880fd95412', '38899084-4a25-4782-8042-4716c15914af', 'この仕事はうちの弟に担当させてやっていただけませんか。', 'この仕事はうちの弟にたんとうさせてやっていただけませんか。', '这份工作能否让我弟弟去负责呢？', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('883fc9fc-5945-4f7e-9ee3-e58af1c19090', '38899084-4a25-4782-8042-4716c15914af', 'リフォームの件は竹下さんに企画させてやっていただけませんか。', 'リフォームのけんはたけしたさんにきかくさせてやっていただけませんか。', '重新装修的事能否让竹下来策划呢？', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('974e8e05-5104-4928-a805-a8e71a7df9f9', '38899084-4a25-4782-8042-4716c15914af', '今回のスピーチ大会は吉田君に出場させてやっていただけませんか。', '今回のスピーチ大会はよしだくんにしゅつじょうさせてやっていただけませんか。', '这次的演讲比赛能否让吉田参加呢？', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('d8a22d2e-1dd9-40ff-8626-e8916e34c71e', '～ていただけるとありがたいんですが', NULL, 'N2', '動て形＋いただけるとありがたいんですが', '動て形＋いただけるとありがたいんですが', '“如果能……那就实在太好了。”', '委婉地向对方表示自己的请求，同时包含了如果请求得以实现的话，说话人对对方的感谢之意。', 373, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('70bca6ad-7c54-4ab1-bb7d-b39d008db2f6', 'd8a22d2e-1dd9-40ff-8626-e8916e34c71e', '（電話で）A「すみません、来週の2時からの会議ですが、その時間、別の用件が入ってしまいまして。もしそちらのご都合がよろしければ4時以降に変更していただけるとありがたいんですが、いかがでしょうか。」B「こちらは大丈夫ですよ。」', '（電話で）A「すみません、来週の2時からの会議ですが、その時間、べつのようけんが入ってしまいまして。もしそちらのごつごうがよろしければ4時いこうにへんこうしていただけるとありがたいんですが、いかがでしょうか。」B「こちらは大丈夫ですよ。」', 'A：“不好意思，有关下周两点开始的会议，因为那个时间有个别的事情，所以如果您方便的话，能否将时间改为四点以后呢？”\nB：“我倒是没什么问题啊。”', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('1e66b894-6b68-4493-b6ac-71f524b76461', 'd8a22d2e-1dd9-40ff-8626-e8916e34c71e', 'A「お手伝いしましょうか。」B「そうしていただけるとありがたいんですが。今から学校へ行かなければならないのではないでしょうか。」', 'A「お手伝いしましょうか。」B「そうしていただけるとありがたいんですが。今から学校へ行かなければならないのではないでしょうか。」', 'A：“我来帮您吧。”\nB：“如果可以的话当然好，但你不是现在就要去学校了吗？”', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('79b03a56-44cd-4f6e-85e9-5e146419c841', 'd8a22d2e-1dd9-40ff-8626-e8916e34c71e', 'ご都合がよろしければ、相談に乗っていただけるとありがたいんですが。', 'ご都合がよろしければ、そうだんにのっていただけるとありがたいんですが。', '您方便的话，如果能跟我商量商量那就实在太好了。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('64b19e3e-edee-4d8d-be72-91bfe14a6cc6', '～ 間[あいだ]', NULL, 'N3', '～ 間[あいだ]', '～ 間[あいだ]', '“在……期间，一直……”。表示在某一段时间里某种动作或状态一直在持续着，谓语是持续动词。', NULL, 374, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('5320120b-3b52-4c0b-9393-bf989d55bced', '64b19e3e-edee-4d8d-be72-91bfe14a6cc6', '山田先生の講演の間、皆熱心に話を聞いていた。', 'やまだせんせいのこうえんあいだ、みんなねっしんにはなしをきいていた。', '山田老师演讲的时候，大家都非常认真地听着。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('a5f4f7ac-3fb1-489e-addc-61461cb4e52d', '64b19e3e-edee-4d8d-be72-91bfe14a6cc6', 'わたしは夏休みの間、ずっと実家にいました。', 'わたしはなつやすあいだ、ずっとじっかにいました。', '暑假期间，我一直待在老家。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('d8e6ec4c-beb7-4ed3-9814-8bab518499e7', '～ 間[あいだ]に', NULL, 'N3', '～ 間[あいだ]に', '～ 間[あいだ]に', '“在……期间，做了……”。表示在持续的某一点或一段时间里发生了某个动作，谓语是瞬间性动词。', NULL, 375, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('99ae904d-0985-4471-9baa-c4ce348fcc80', 'd8e6ec4c-beb7-4ed3-9814-8bab518499e7', '赤ちゃんが寝ている間に、洗濯をしました。', 'あかちゃんがねあいだに、せんたくをしました。', '在宝宝睡觉的时候，洗了衣服。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('b890cf29-c794-4417-8d78-67c97fd70fed', 'd8e6ec4c-beb7-4ed3-9814-8bab518499e7', '日本に留学している間に富士山に登りたい。', 'にほんにりゅうがくあいだふじさんにのぼりたい。', '想在留学日本期间登一次富士山。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('0a0841b9-9e2f-4803-afde-fd6d88c4fa99', '～あがる', NULL, 'N3', '动词「ます形」＋あがる', '动词「ます形」＋あがる', '“……完成了”“……好了”，表示动作的完成。\n“向上……”“……起来”，表示动作、移动等向上。', NULL, 376, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('b5590368-0570-4970-9c9e-e0a6576e86d4', '0a0841b9-9e2f-4803-afde-fd6d88c4fa99', '最新の企画書が出来あがったので、どうぞご覧ください。', 'さいしんのきかくしょができあがったので、どうぞごらんください。', '最新的企划书完成了，请过目。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('fd4cb939-be3b-4787-ac7d-3f182c3e4edf', '0a0841b9-9e2f-4803-afde-fd6d88c4fa99', '彼氏へのマフラーが編みあがった。', 'かれしへのマフラーがあみあがった。', '送给男朋友的围巾织好了。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('95613bb0-b177-4f44-a532-e88640d64f72', '0a0841b9-9e2f-4803-afde-fd6d88c4fa99', '意中の大学に合格したとの知らせに、彼女はすっかり舞い上がった。', 'いちゅうのだいがくにごうかくしたとのしらせに、かのじょはすっかりまあがった。', '得知自己考上了心仪的大学后，她高兴地跳了起来。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('f904554a-6435-46f2-ae64-7425fce0b070', '0a0841b9-9e2f-4803-afde-fd6d88c4fa99', '少しだけ成績が上がると、すっかり思い上がってしまう。', 'すこしだけせいせきがあがると、すっかりおもあがってしまう。', '成绩稍微有些进步，就骄傲自满起来。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('9f90db0d-e1f5-4ffe-a4c9-5fc95bb75d89', '～いい/よい', NULL, 'N3', '动词「ます形」＋いい/よい', '动词「ます形」＋いい/よい', '“容易……”“易于……”。表示某个动作做起来很容易、很舒畅。反义的表达为「～にくい」。', '「～いい/よい」只能用于表示积极评价的场合。而「～やすい」表示对象的客观性质，既可用于积极的场合，也可用于消极的场合，例如「わかりやすい 説[せつ] 明[めい]（通俗易懂的说明）/ 壊[こわ]れやすい（容易坏）」，但是不能说「 壊[こわ]れよい」。', 377, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('4840cd5a-634b-45a3-adf2-79cc65aecf18', '9f90db0d-e1f5-4ffe-a4c9-5fc95bb75d89', 'この町は住みよいです。', 'このまちはすみよいです。', '这座城市很宜居。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('c6d9ee9a-1b99-4403-928f-3e2cd6dfff7b', '9f90db0d-e1f5-4ffe-a4c9-5fc95bb75d89', 'この薬は飲みよいです。', 'このくすりはのみよいです。', '这种药容易吞咽。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('a4642e96-515e-4ddd-94b1-114302fec212', '9f90db0d-e1f5-4ffe-a4c9-5fc95bb75d89', 'この本はわかりいいです。', 'このほんはわかりいいです。', '这本书通俗易懂。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('580c1ec4-ebbc-46a8-8c07-ec034e0f9cd9', '～ 一[いっ] 方[ぽう]（で）', NULL, 'N3', '～ 一[いっ] 方[ぽう]（で）', '～ 一[いっ] 方[ぽう]（で）', '“一方面……，另一方面……”；“……的同时……”。表示同一主语的不同方面。\n“一方面……，另一方面……”；“与……相反”。表示就两个不同主语进行对比说明。', NULL, 378, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('26046f1c-f52b-42fb-a681-f28406571b03', '580c1ec4-ebbc-46a8-8c07-ec034e0f9cd9', '彼は自分は何もしていない一方で、他人のすることによく文句を言う。', 'かれはじぶんはなにいっぽうで、たにんのすることによくもんくをいう。', '他自己什么都不干，却经常对别人做的事情发牢骚。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('ab1eddec-5a84-4671-8e5e-0c35838e0757', '580c1ec4-ebbc-46a8-8c07-ec034e0f9cd9', '田中さんは医科大学の教授である一方、小説家としても有名だ。', 'たなかさんはいかだいがくのきょうじゅいっぽう、しょうせつかとしてもゆうめいだ。', '田中是医科大学的教授，同时作为小说家也很有名。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('db0f5fe0-0ddf-45f3-9bd3-d9c218e0475b', '580c1ec4-ebbc-46a8-8c07-ec034e0f9cd9', '娘ならきっと合格できるだろうと信じる一方で、ちょっと不安なところもある。', 'むすめならきっとごうかくできるだろうとしんいっぽうで、ちょっとふあんなところもある。', '我相信女儿肯定能通过的，同时也抱有一些不安。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('0b9d5cf6-4d5a-4d5c-8083-71441800b09e', '580c1ec4-ebbc-46a8-8c07-ec034e0f9cd9', 'ある宗教を、ほかの人にも進めてまわるくらい熱心に信仰する人がいる。一方で、宗教には全く関心を持たない人もいる。', 'あるしゅうきょうを、ほかのひとにもすすめてまわるくらいねっしんにしんこうするひといっぽうで、しゅうきょうにはまったくかんしんをもたないひともいる。', '有人信仰宗教到了热心地到处劝说别人信教的地步。而另一方面，也有人对宗教漠不关心。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('d71d479c-d516-4eed-8646-f217b77562f7', '580c1ec4-ebbc-46a8-8c07-ec034e0f9cd9', '収入が減る一方で、教育費などの支出は増えていくのだから、節約するしかない。', 'しゅうにゅうがへいっぽうで、きょういくひなどのししゅつはふえていくのだから、せつやくするしかない。', '一方面收入不断减少，而另一方面，教育费等开支不断增加，所以只好节约。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('54eb4b93-6a00-48b6-8582-143db6003ede', '580c1ec4-ebbc-46a8-8c07-ec034e0f9cd9', '姉は明るい一方で、妹は無口だ。', 'あねはあかいっぽうで、いもうとはむくちだ。', '姐姐很开朗，而妹妹却沉默寡言。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('20cc104f-ea6e-411a-9c64-8faee465e7de', '～ 一[いっ] 方[ぽう]だ', NULL, 'N3', '动词辞书形＋一方だ', '动词辞书形＋一方だ', '“不断地……”“越来越……”。表示某种事态朝着某个方向不断地发展。', '既可用于好的事态，也可用于不好的事态。', 379, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('177a1226-3891-4fd6-92e6-fe1ed67a5f89', '20cc104f-ea6e-411a-9c64-8faee465e7de', '田中選手は前大会に続いて、今大会でも優勝を果たした。彼の今後の活躍に周囲の期待は高まる一方だ。', 'たなかせんしゅはぜんたいかいにつづいて、こんたいかいでもゆうしょうをはたした。かれのこんごのかつやくにしゅういのきたいはたかいっぽうだ。', '田中选手自上次比赛获胜以后，在此次比赛中再次夺得冠军。人们对他今后的期望越来越高。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('7b0b5921-0afb-4058-90e0-6ab05e48b24b', '20cc104f-ea6e-411a-9c64-8faee465e7de', '地震の被害についての情報が混乱し、住民の不安は広がる一方だ。', 'じしんのひがいについてのじょうほうがこんらんし、じゅうみんのふあんはひろいっぽうだ。', '关于地震的受灾情况众说纷纭，居民们越来越感到不安。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('ebd8689f-596e-4cd3-b06d-85cb469a2992', '20cc104f-ea6e-411a-9c64-8faee465e7de', 'ここ数年、この町の人口は減る一方だ。', 'ここすうねん、このまちのじんこうはへいっぽうだ。', '最近几年来，这个城市的人口在不断地减少。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('ec1ca20e-2567-4c5b-b5bc-bbd03313e65e', '～ 上[うえ]で（の）', NULL, 'N3', '名词＋の/动词「た形」＋ 上[うえ]で（の）', '名词＋の/动词「た形」＋ 上[うえ]で（の）', '“在……之后”。', '「～ 上[うえ]での」后续名词作定语使用。另外「～ 上[うえ]で」强调的是人的意志，即根据某个结果再做下一个动作。', 380, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('2863540f-022c-4abe-a6ed-8b8df0b93d36', 'ec1ca20e-2567-4c5b-b5bc-bbd03313e65e', 'わたしが皆様のご意見を伺った上で、来週ご報告いたします。', 'わたしがみなさまのごいけんをうかがうえで、らいしゅうごほうこくいたします。', '听取各位意见之后，下周我将做报告。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('9d8632af-193e-403b-a1ff-47a0e54302f1', 'ec1ca20e-2567-4c5b-b5bc-bbd03313e65e', 'それぞれの説明をよく聞いた上で、旅行のコースを選びたいと思います。', 'それぞれのせつめいをよくきうえで、りょこうのコースをえらびたいとおもいます。', '我想仔细听各自说明之后，选择旅行的路线。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('4e9a6970-6116-4bed-850b-d8629815c38c', '～ 上[う え]で（は）/ 上[う え]での', NULL, 'N3', '名词＋の/动词辞书形＋ 上[うえ]で（は）/ 上[うえ]での', '名词＋の/动词辞书形＋ 上[うえ]で（は）/ 上[うえ]での', '“在……方面”“在……上”。表示在某个范围、某个方面或某种场合等。', '「～ 上[うえ]での」后续名词作定语使用。这时的「～ 上[うえ]」可以和「 面[めん]/  場[ば] 合[あい]/  点[てん]」等词替换。', 381, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('9b5c1030-69e5-431d-bc83-921202cf301f', '4e9a6970-6116-4bed-850b-d8629815c38c', '仕事の上では別に問題はない。', 'しごとうえべつにもんだいはない。', '在工作上没有问题。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('51611616-adf7-4d9a-bc61-e1f39b263f8e', '4e9a6970-6116-4bed-850b-d8629815c38c', '外国語を勉強する上で、単語を覚えるのはとても大事なことだ。', 'がいこくごをべんきょううえで、たんごをおぼえるのはとてもだいじなことだ。', '在学习外语时，背单词是很重要的。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('8adc454b-6a23-474a-b9b4-685b8c470aa8', '～ 上[うえ]に', NULL, 'N3', '～ 上[うえ]に', '～ 上[うえ]に', '“不仅……而且……”。表示添加、累加。「～ 上[うえ]（に）」意思相当于「～だけでなく」。', '该句型前后项必须是同一性质的，即前后项同为积极因素或消极因素。', 382, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('c8199dd1-3b7a-469b-a1e0-1c4fe3cef00d', '8adc454b-6a23-474a-b9b4-685b8c470aa8', 'そのスポーツクラブは入会金が要らない上に、わが家から近い。', 'そのスポーツクラブはにゅうかいきんがいうえに、わがやからちかい。', '那家体育俱乐部不仅不需要入会费，而且离我家很近。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('7662c01e-f871-45f1-aa03-b119d5d1e3c2', '8adc454b-6a23-474a-b9b4-685b8c470aa8', '台風が近づいてきて、風が強い上、雨も激しく降っている。', 'たいふうがちかづいてきて、かぜがつようえ、あめもはげしくふっている。', '台风逼近，不仅刮起了大风，雨势也很猛。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('9387d4e6-3d4f-42d6-9065-b3e521d2478b', '8adc454b-6a23-474a-b9b4-685b8c470aa8', 'この商品はデザインがユニークな上に、色もカラフルだ。', 'このしょうひんうえに、いろもカラフルだ。', '这件商品不仅造型别致，颜色也鲜艳。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('47c66407-0deb-476e-89fb-0f0faaa587eb', '～うちは', NULL, 'N3', '～うちは', '～うちは', '“在……的时候”。表示在某时期内一直做某件事情或一直处于某个状态。', '「～うちは」后面是在这个期间内持续的状态，而「～うちに」后面是在这一期间内发生的事情，谓语多数用瞬间性动词。', 383, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('59a080ec-8c97-4bea-965f-e17e377a32fb', '47c66407-0deb-476e-89fb-0f0faaa587eb', '膝に痛みがあるうちは、まだ運動をしないでください。', 'ひざにいたみがあるうちは、まだうんどうをしないでください。', '膝盖还在痛的时候，请不要运动。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('a88d29e3-b8d7-44dd-849c-646f9139ce07', '47c66407-0deb-476e-89fb-0f0faaa587eb', '若いうちはいろいろなことを経験させたほうがいい。', 'わかいうちはいろいろなことをけいけんさせたほうがいい。', '要让孩子在年轻的时候多经风雨见世面。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('083e77df-19ce-433f-9808-c87af85886a1', '47c66407-0deb-476e-89fb-0f0faaa587eb', '初めのうちは失敗が多かった。', 'はじしっぱいがおおかった。', '刚开始的时候时常失败。（うちは：事态持续）', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('1144d330-d308-4948-b117-d4ba32080613', '47c66407-0deb-476e-89fb-0f0faaa587eb', '初めのうちに失敗をした。', 'はじしっぱいをした。', '在开始的时候失败过。（うちに：事态完了）', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('948a60c1-f3ed-4f85-bb9e-c4ef5e7478bc', '～おかげで/おかげだ', NULL, 'N3', '～おかげで/おかげだ', '～おかげで/おかげだ', '“多亏……才……”“托……的福”。表示由于某种原因产生了好的结果。', '「～おかげで」有时也可用于不好的结果，表示反语、挖苦、责难的语气，意思是“都怪……才……”。', 384, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('db274dc9-e7d0-4dcd-a22a-db45d870297e', '948a60c1-f3ed-4f85-bb9e-c4ef5e7478bc', '母は「風邪を引かないのは、毎朝しているジョギングのおかげだ。」とよく言っている。', 'ははは「かぜをひかないのは、まいあさしているジョギングのおかげだ。」とよくいっている。', '妈妈总是说“没感冒，要归功于每天早上慢跑。”', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('f07f49a6-ac16-422f-bb5e-5a299b3fc027', '948a60c1-f3ed-4f85-bb9e-c4ef5e7478bc', '皆様のおかげで無事に閉会式を迎えることができました。', 'みなさまぶじにへいかいしきをむかえることができました。', '多亏了各位，大会得以圆满闭幕。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('cbd8755a-28e2-454b-b0ef-db10924c35e0', '948a60c1-f3ed-4f85-bb9e-c4ef5e7478bc', 'わたしたちが優勝できたのは、応援してくれたみんなのおかげです。', 'わたしたちがゆうしょうできたのは、おうえんしてくれたみんなのおかげです。', '这次我们取得了冠军，多亏了大家的支持。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('194da2b9-624c-4412-b19a-0b39d26d8315', '948a60c1-f3ed-4f85-bb9e-c4ef5e7478bc', '彼の話を信じたおかげで、ひどい目に遭った。', 'かれのはなしをしんじたおかげで、ひどいめにあった。', '就因为信了他的话，才这么倒霉的。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('529867ea-a571-4de6-b675-620a2d8c792b', '～おきに', NULL, 'N3', '数量词＋おきに', '数量词＋おきに', '“每隔……”。表示时间或距离的间隔。', '“～おきに”在表示某种时间轴或一段距离上的一个点的时候，可以与“～ごとに”替换使用。但当数字为“1”时，将“～おきに”替换成“～ごとに”，表达的意思会发生变化。', 385, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('5f1a9f04-1623-4c2b-b198-298fe67c4cc2', '529867ea-a571-4de6-b675-620a2d8c792b', 'この道には5メートルおきに木が植えてある。', 'このみちきがうえてある。', '这条路上每隔五米种一棵树。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('d9b390de-a56c-4893-a058-51cd6feff91e', '529867ea-a571-4de6-b675-620a2d8c792b', '新宿へ向かう電車は3分おきに出ている。', 'しんじゅくへむかうでんしゃは3ぷんでている。', '去新宿的电车每隔三分钟发一辆。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('3b9ea890-182d-4e70-866b-34ffa183d290', '～ 恐[おそ]れがある', NULL, 'N3', '名词＋の/动词辞书形＋ 恐[おそ]れがある', '名词＋の/动词辞书形＋ 恐[おそ]れがある', '“有可能……”“恐怕要……”。表示有可能产生某种不良后果。', '「～ 恐[おそ]れがある」只能用于不好的事情发生的可能性，相当于「～ 心[しん] 配[ぱい]/ 危[き] 険[けん]がある」等。', 386, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('ea1b18c7-38cf-4b46-af6e-066bba9880df', '3b9ea890-182d-4e70-866b-34ffa183d290', '今晩、大型の台風がこの地方へ近づく恐れがあります。', 'こんばん、おおがたのたいふうがこのちほうへちかおそれがあります。', '今晚可能有强台风靠近该地区。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('8e95f158-c18a-4af3-b02a-38e988205a2c', '3b9ea890-182d-4e70-866b-34ffa183d290', 'この欠陥を直さないと、重大な事故が起こる恐れがある。', 'このけっかんをなおさないと、じゅうだいなじこがおおそれがある。', '如果不修好这个缺陷的话，就有可能要发生重大事故。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('fefed9c3-b86a-44e4-a59a-e97145abbb9e', '～がかり', NULL, 'N3', '名词＋がかり', '名词＋がかり', '“花……”“用……”；“……一起”。表示某事花了很多人力或时间。', NULL, 387, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('107c7cee-0fbd-49b9-b758-9f0b449aec64', 'fefed9c3-b86a-44e4-a59a-e97145abbb9e', '3年がかりの調査の結果、工場廃水に含まれている金属物質が住民に危害を及ぼしたことがわかった。', '3ねんがかりのちょうさのけっか、こうじょうはいすいにふくまれているきんぞくぶっしつがじゅうみんにきがいをおよぼしたことがわかった。', '花了三年的时间调查后发现，工业废水中包含的金属物质对人们的健康造成了影响。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('cbbbb69d-d6b3-47dc-96a4-7efd08e2191e', 'fefed9c3-b86a-44e4-a59a-e97145abbb9e', 'その記念碑は重くて、8人がかりで運んでも動かない。', 'そのきねんひはおもくて、8にんがかりではこんでもうごかない。', '那个纪念碑很重，8个人一起抬也抬不动。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('db229b99-af83-45c4-99a6-f654228c64a3', '～がたい', NULL, 'N3', '动词「ます形」＋がたい', '动词「ます形」＋がたい', '“难以……”“很难……”。表示主观上无法做某事，比较侧重于说话人的自我感觉。其活用和い形容词的活用一样。', '常见的有「 信[しん]じがたい（难以置信）/ 許[ゆる]しがたい（不能原谅）/ 決[き]めがたい（难以决定）/ 忘[わす]れがたい（难以忘记）」等。', 388, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('98361ac2-ce7b-4cf4-a76a-844dfdf33436', 'db229b99-af83-45c4-99a6-f654228c64a3', 'これだけ景気が悪いのに、税金を上げようとするのは、わたしたち国民には理解しがたい。', 'これだけけいきがわるいのに、ぜいきんをあげようとするのは、わたしたちこくみんにはりかいしがたい。', '经济如此的不景气，还要提高税金，这对我们国民来说难以理解。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('90278555-d0fe-4962-b579-4c3a3340ae99', 'db229b99-af83-45c4-99a6-f654228c64a3', 'どのコンピューターを買ったらよいか、なかなか一つには決めがたい。', 'どのコンピューターをかったらよいか、なかなかひとつにはきめがたい。', '买哪台电脑好，很难做出决定。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('5b54ad07-07ab-4882-8930-e3473f87e61c', '～か 何[なに]か', NULL, 'N3', '动词普通形/名词＋か 何[なに]か', '动词普通形/名词＋か 何[なに]か', '“……什么的”“……之类的”。表示不明确的指示。', '「～か何か」是指示与其类似、同类的事物时使用。', 389, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('d7bbf2bb-41fd-4e9a-bc7e-76e96ef47ba0', '5b54ad07-07ab-4882-8930-e3473f87e61c', '風で紙が飛んでしまうので、本か何か重いものを載せておこう。', 'かぜでかみがとんでしまうので、ほんなにおもいものをのせておこう。', '纸会被风刮走的，用书什么的重的东西压上面吧。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('4da2d786-d763-410d-858f-9b433039e0f7', '5b54ad07-07ab-4882-8930-e3473f87e61c', 'コーヒーか何か飲みませんか。', 'なにのみませんか。', '喝点咖啡什么的吧。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('7d44843b-5d61-41a5-8cbb-5c376b49fafa', '～から 言[い]うと/から 言[い]えば/から 言[い]って', NULL, 'N3', '名词＋から 言[い]うと/から 言[い]えば/から 言[い]って', '名词＋から 言[い]うと/から 言[い]えば/から 言[い]って', '“从……来说”“从……来讲”。表示站在某立场可以得出某种看法、结论、判断。', '不能直接用「人物名词＋から 言[い]うと」。\n❌ 私[わたし]から 言[い]うと、それは 困[こま]ります。\n✅ 私[わたし]の 立[たち] 場[ば]から 言[い]うと、それは 困[こま]ります。', 390, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('4d2499c6-e2a9-45f7-a749-2cc2061ebddd', '7d44843b-5d61-41a5-8cbb-5c376b49fafa', '記者「ところで、社員に望むことは何でしょうか。」社長「そうですね。経営者の立場から言うと、何でも率直に言ってほしいです。」', 'きしゃ「ところで、しゃいんにのぞむことはなにでしょうか。」しゃちょう「そうですね。けいえいしゃのたちばいうと、なんでもそっちょくにいってほしいです。」', '记者：“那么，您对公司员工的期待是什么？”\n社长：“嗯，从经营者的立场来说，我希望员工能坦率地发表自己的意见。”', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('ec9abd89-d9c0-41f6-98e2-277af747cea9', '7d44843b-5d61-41a5-8cbb-5c376b49fafa', '今の販売状況から言えば、今年の目標達成は厳しいだろう。', 'いまのはんばいじょうきょういえば、ことしのもくひょうたっせいはきびしいだろう。', '从现在的销售状况来看，今年要达成目标有点艰难吧。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('4ac0e42d-75d0-4f23-ab05-88a017109189', '7d44843b-5d61-41a5-8cbb-5c376b49fafa', '実務経験から言って、田中さんがこの仕事に一番ふさわしいと思う。', 'じつむけいけんいって、たなかさんがこのしごとにいちばんふさわしいとおもう。', '从实际业务经验来看，我认为田中最适合做这份工作。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('68783d44-c20b-49e8-9427-f756c3855d89', '～からすると/からすれば', NULL, 'N3', '名词＋からすると/からすれば', '名词＋からすると/からすれば', '“从……来看”“从……来衡量”。表示从某种角度来评价的话，可以得出某种结论、判断。', '和「～から 言[い]うと」用法相同。', 391, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('f956ea99-eaf9-4877-b62c-ee3762f05044', '68783d44-c20b-49e8-9427-f756c3855d89', 'あの雲の様子からすると明日は雨だろう。', 'あのくものようすあしたはあめだろう。', '从云相来看，明天大概会下雨吧。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('d85e07bb-215a-49cd-af99-e2002ea080fa', '68783d44-c20b-49e8-9427-f756c3855d89', 'さっきの態度からすると、あの人はあやまる気は全然なさそうだ。', 'さっきのたいどからすると、あのひとはあやまるきはぜんぜんなさそうだ。', '从他刚才的态度来看，似乎丝毫没有道歉的意思。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('6e1e162f-9d89-4e39-8236-274f4c4cfea0', '68783d44-c20b-49e8-9427-f756c3855d89', 'プロからすると、わたしの技術はまだ未熟です。', 'プロからすると、わたしのぎじゅつはまだみじゅくです。', '从专家的角度来看，我的技术还不纯熟。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('3efa2334-8c95-41cf-a3af-a442f0d0c30d', '～から～にかけて', NULL, 'N3', '名词＋から＋名词＋にかけて', '名词＋から＋名词＋にかけて', '“从……到……”。表示时间、空间的大致范围。', '表示时间、空间的起点和终点不是很明确，在此期间出现的情况、现象多是断断续续的。', 392, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('1b80a74c-ae74-4171-8533-912f768c0426', '3efa2334-8c95-41cf-a3af-a442f0d0c30d', 'あの鳥が日本で見られるのは、11月から3月にかけてです。', 'あのとりがにほんでみられるのは、11がつから3がつにかけてです。', '在日本可以见到那种鸟类，是从十一月份到第二年的三月份。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('9ce139f7-46da-44e9-a7e7-a455b471f440', '3efa2334-8c95-41cf-a3af-a442f0d0c30d', '東北地方から北海道にかけて今夜は大雪になるでしょう。', 'とうほくちほうほっかいどうこんやはおおゆきになるでしょう。', '从东北地区到北海道，今晚会下大雪。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('dc7988f7-e35a-4af1-823f-941286210328', '～から 見[み]ると/から 見[み]れば/から 見[み]て', NULL, 'N3', '名词＋から 見[み]ると/から 見[み]れば/から 見[み]て', '名词＋から 見[み]ると/から 見[み]れば/から 見[み]て', '“从……来看”。表示站在某立场上可以得出某种看法、结论、判断。', '与「～から 言[い]うと」「～からすると」意思相近，但是「～から 見[み]ると」可以直接接在表示人物的名词后面。', 393, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('196ac160-893a-4e90-9da4-c29a928f03c2', 'dc7988f7-e35a-4af1-823f-941286210328', '平凡なわたしから見ると、彼女はあらゆる才能に恵まれているように思える。', 'へいぼんみると、かのじょはあらゆるさいのうにめぐまれているようにおもえる。', '在平凡的我看来，她似乎拥有所有的才能。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('7673129b-bc1b-4e9d-8364-5e9fd223fcc6', 'dc7988f7-e35a-4af1-823f-941286210328', '生け花を習い始めて10年目になる田口さんは、自分ではまだまだ下手だと言っている。しかし、まだ2年目のわたしから見ればあの人の作品は実に見事なものだ。', 'いけばなをならいはじめて10ねんめになるたぐちさんは、じぶんではまだまだへただといっている。しかし、まだ2ねんめみればあのひとのさくひんはじつにみごとなものだ。', '学习插花已经进入第十个年头的田口，对自己的插花技术还不满意。然而，在开始学习插花才刚进入第二个年头的我看来，他的作品的确很出色。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('07580579-c268-4a49-8107-bb3f84c7de06', 'dc7988f7-e35a-4af1-823f-941286210328', '外国人のわたしから見れば、日本は住みよい国だと思う。', 'がいこくじんみれば、にほんはすみよいくにだとおもう。', '在我这个外国人看来，日本是个宜居的国家。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('6e98002f-fbe5-445e-ab88-b4b8307b798b', '～きる/きれる/きれない', NULL, 'N3', '动词「ます形」＋きる/きれる/きれない', '动词「ます形」＋きる/きれる/きれない', '“……完”。表示把某动作做完。\n“十分的……”“非常……”。表示某种状态达到极限。', '「～きれる」表示“能够完成……”，是「～きる」的可能态的表达方式。「～きれない」表示“不能……完”，是「～きる」的可能态的否定形式。\n「わかりきる（十分清楚）/ 弱[よわ]りきる（极度衰弱；非常为难）/ 思[おも]い 切[き]る（下定决心）」等，一般作为固定的动词来使用。', 394, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('c8c0e0cb-2e83-408e-bc9d-99b167046bc2', '6e98002f-fbe5-445e-ab88-b4b8307b798b', 'こんなに長い小説は、1日では読みきれない。', 'こんなにながいしょうせつは、いちにちではよみきれない。', '这么长的小说，一天之内是看不完的。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('5f348c55-2f2c-4aa1-8a5b-fda09a561ed7', '6e98002f-fbe5-445e-ab88-b4b8307b798b', 'お小遣いを使いきってしまった。', 'おこづかいをつかいきってしまった。', '把零花钱用完了。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('52ad56a8-8a67-42f4-91d7-d114fea9d712', '6e98002f-fbe5-445e-ab88-b4b8307b798b', '彼のことを信じきっています。', 'かれのことをしんじきっています。', '我非常相信他。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('341b2a62-d7ae-4064-b7ae-6314664d07d6', '6e98002f-fbe5-445e-ab88-b4b8307b798b', '今日は忙しくて、もう疲れきってしまった。', 'きょうはいそがしくて、もうつかれきってしまった。', '今天非常忙，已经筋疲力尽了。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('946f6181-3fcb-4395-a5bd-b793b1cd2a77', '6e98002f-fbe5-445e-ab88-b4b8307b798b', '彼女のわがままに困りきっている。', 'かのじょのわがままにこまりきっている。', '对她的任性感到非常为难。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('fd279b07-8ddb-4b7e-9f9e-0187fbb04cd8', '～くせに', NULL, 'N3', '～くせに', '～くせに', '表示逆接，“明明……却……”“虽然……但是……”。', '「～くせに」表示指责、抱怨、不满的语气很强。而且在用法上有限制，即主语必须是人，且句子的前后项必须是同一主语。', 395, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('b2cd188b-b3e3-4606-b269-6be2ad1eb4b9', 'fd279b07-8ddb-4b7e-9f9e-0187fbb04cd8', '姉は食事のことで文句ばかり言っているくせに、自分では何も作らない。', 'あねはしょくじのことでもんくばかりいっているくせに、じぶんではなにもつくらない。', '姐姐总是对饭菜挑三拣四，但是自己却什么都不做。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('ad6952db-92b5-4ea0-8aef-1af569a5f80b', 'fd279b07-8ddb-4b7e-9f9e-0187fbb04cd8', 'あの子はあまり食べられないくせにごちそうをたくさん皿にとりたがる。', 'あのこはあまりたべられないくせにごちそうをたくさんさらにとりたがる。', '那个孩子不怎么能吃，可总喜欢往自己的盘子里夹很多菜。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('d553ba1a-57c9-423e-b998-6eb2c8746b8d', '～くらい/ぐらい', NULL, 'N3', '～くらい/ぐらい', '～くらい/ぐらい', '“……得……”“简直……”。表示程度。\n“至少……”“最起码……”。表示最低程度。\n用「～ぐらい～はない」的形式，表示最高的程度。“没有比……更……”“最……”。', '表示动作或状态的程度，可以用「～ほど」替换。\n表示最低程度时，不能使用「～ほど」。\n可以和「～ほど～はない」替换。', 396, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('1ce12fb9-1342-4783-ad0c-84bd8aa52f22', 'd553ba1a-57c9-423e-b998-6eb2c8746b8d', '怖くて怖くて、大声で叫びたいくらいだった。', 'こわくてこわくて、おおごえでさけびたいくらいだった。', '当时害怕得想大声地叫出来。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('3cad1bf7-e6fb-4436-a713-c9ca012efa0e', 'd553ba1a-57c9-423e-b998-6eb2c8746b8d', '今日は朝から仕事が忙しくて、食事をする時間もないくらいだ。', 'きょうはあさからしごとがいそがしくて、しょくじをするじかんもないくらいだ。', '今天从早上开始工作就很忙，连吃饭的时间都没有。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('4783f4d8-4425-44f6-a597-76bf063ad097', 'd553ba1a-57c9-423e-b998-6eb2c8746b8d', 'これは新品だから、安くても5千円ぐらいはするだろう。', 'これはしんぴんだから、やすくても5せんえんぐらいはするだろう。', '这是最新产品，即使便宜，至少也要五千日元吧。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('d5f08153-48d7-4d54-bec1-e3f728af6c18', 'd553ba1a-57c9-423e-b998-6eb2c8746b8d', '自分のことぐらい自分でやりなさい。', 'じぶんじぶんでやりなさい。', '最起码你自己的事情要自己做。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('64cf5195-a2f3-411f-920d-b44abae13345', 'd553ba1a-57c9-423e-b998-6eb2c8746b8d', '彼くらい努力する人はいない。', 'かれどりょくするひとはいない。', '没有比他更努力的人了。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('8c433a18-86fc-4455-bb7f-ca08f91a6580', 'd553ba1a-57c9-423e-b998-6eb2c8746b8d', '戦争ぐらい残酷なものはない。', 'せんそうざんこくなものはない。', '战争是最残酷的。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('a4754581-494f-492f-8486-6b4caf82396d', '～こそ', NULL, 'N3', '名词＋こそ', '名词＋こそ', '“正是……”“才是……”。', '「～こそ」表示强调。', 397, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('5a521fe6-eaad-4e3b-95f3-86da58132d34', 'a4754581-494f-492f-8486-6b4caf82396d', 'A「どうぞよろしくお願いします。」B「いいえ、こちらこそ。」', 'A「どうぞよろしくおねがいします。」B「いいえ、こちらこそ。」', 'A：“请多多关照。”\nB：“不客气（我才要请您多多关照）。”', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('0a6e728a-d657-40fc-8e69-724526fa4489', 'a4754581-494f-492f-8486-6b4caf82396d', 'これこそ本場の日本料理です。', 'ほんばのにほんりょうりです。', '这才是地道的日本料理。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('c881c9c8-50b1-47b7-9197-30e4eba99f63', 'a4754581-494f-492f-8486-6b4caf82396d', '今年こそ試験に合格できるよう、頑張る。', 'ことししけんにごうかくできるよう、がんばる。', '我要好好努力，争取今年一定要通过考试。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('c3052954-d68e-46ce-b9ae-b9431bdfa2ea', '～こと', NULL, 'N3', '动词辞书形·「ない形」＋こと', '动词辞书形·「ない形」＋こと\n句子的普通形·礼貌形＋こと', '“要……”“不要……”。表示命令。\n“……啊”。表示感叹或惊讶的心情。', '多用于书面语。「～こと」的意思相当于「～なさい」；「～ないこと」的意思相当于「～ないでください」。\n是口语，女性用语。有时也用「どんなに/なんと（多么）～だろう/ことだろう」表示感叹。', 398, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('e247cd03-cda9-411c-a8bf-7a310beb848d', 'c3052954-d68e-46ce-b9ae-b9431bdfa2ea', '指定の場所以外に自転車を止めないこと。', 'していのばしょいがいにじてんしゃをとめないこと。', '不要在指定区域以外停放自行车。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('9423de18-ab9c-4227-8826-0bc52dce0d20', 'c3052954-d68e-46ce-b9ae-b9431bdfa2ea', '勝手に実験室に入らないこと。', 'かってにじっけんしつにはいらないこと。', '不许擅自进入实验室！', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('017c317a-82dd-41ec-9f48-809fc1c97af7', 'c3052954-d68e-46ce-b9ae-b9431bdfa2ea', 'まあ、なんてきれいな夕焼けだこと。', 'まあ、なんてきれいなゆうやけだこと。', '啊，多美的晚霞啊！', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('ce19ace7-272c-4b6a-a4cc-606bf2571527', 'c3052954-d68e-46ce-b9ae-b9431bdfa2ea', 'まあ、きれいに咲いたこと。', 'まあ、きれいにさいたこと。', '啊，花开得真美啊！', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('1ef273b8-7a83-407d-8fa1-935486cef922', 'c3052954-d68e-46ce-b9ae-b9431bdfa2ea', 'あら、素敵な洋服ですこと。', 'あら、すてきなようふくですこと。', '哎呀，你这件衣服真漂亮。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('07ec0db4-7077-479c-b34e-168219855a79', 'c3052954-d68e-46ce-b9ae-b9431bdfa2ea', 'なんと立派な家だろう。', 'りっぱないえだろう。', '多么气派的房子啊。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('e4095830-a959-4a15-888d-cc417480f50b', '～ことか', NULL, 'N3', '～ことか', '～ことか', '“多么……啊”。表示感叹或惊讶的心情。经常会与「どんなに/どれほど/どれだけ/なんと」等词呼应使用。', NULL, 399, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('3075e02b-98df-4f00-81fa-e5091d9af7eb', 'e4095830-a959-4a15-888d-cc417480f50b', '自分で野菜を作ってみて、おいしい野菜を育てることがどんなに大変なことかわかりました。', 'じぶんでやさいをつくってみて、おいしいやさいをそだてることがどんなにたいへんなことかわかりました。', '自己试着种了蔬菜之后才明白，要种出好吃的蔬菜是多么困难的事情。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('0a0dfc14-4f30-4c10-a287-86bbab76bad9', 'e4095830-a959-4a15-888d-cc417480f50b', '学生時代、奨学金がもらえてどれほど助かったことか。', 'がくせいじだい、しょうがくきんがもらえてどれほどたすかったことか。', '学生时代，能拿到奖学金，对我来说是多大的帮助啊。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('ccc5c685-721d-48c4-aa07-1c8776c5965f', 'e4095830-a959-4a15-888d-cc417480f50b', '悪い点を注意する親が多いが、子どもにとっては、褒められたほうがどれだけうれしいことか。', 'わるいてんをちゅういするおやがおおいが、こどもにとっては、ほめられたほうがどれだけうれしいことか。', '很多家长会指出孩子的缺点，但是对孩子来说，受到表扬是一件多么高兴的事情啊。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('a9ab8c9b-b815-428b-943e-2052cd37175f', '～ことだ', NULL, 'N3', '动词辞书形·「ない形」＋ことだ', '动词辞书形·「ない形」＋ことだ', '“应该……”“不应该……”。', '「～ことだ」用于提出忠告或建议等。', 400, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('6627f355-d4e2-4b89-8dc1-1af108b4811e', 'a9ab8c9b-b815-428b-943e-2052cd37175f', '上手になりたければ、毎日短い時間でもいいから練習を続けることだ。', 'じょうずになりたければ、まいにちみじかいじかんでもいいかられんしゅうをつづけることだ。', '如果想要变得擅长，就要坚持每天练习，哪怕只是很短的时间。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('bda2d514-97a8-4be2-9d3d-0102e1446f81', 'a9ab8c9b-b815-428b-943e-2052cd37175f', '体を丈夫にしたかったら、好き嫌いをしないで何でも食べることだ。', 'からだをじょうぶにしたかったら、すききらいをしないでなんでもたべることだ。', '如果想让身体变得强壮，就不要挑三拣四，什么东西都要吃。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('4111d2b3-8629-4aa7-ab66-7f30cce2a29d', '～ことに', NULL, 'N3', '～ことに', '～ことに', '“令人……的是……”。表示说话人对后项事物的评价。「～ことに」前面常使用表示感情状态的词。', '「～ことに」前面常使用表示感情状态的词，如「 驚[おどろ]いた/うれしい/ 残[ざん] 念[ねん]な」等。', 401, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('83681f64-ee90-492b-aac4-08fa965a8169', '4111d2b3-8629-4aa7-ab66-7f30cce2a29d', '興味深いことに、昔のおもちゃが再び流行しているそうだ。', 'きょうみぶかいことに、むかしのおもちゃがふたたびりゅうこうしているそうだ。', '令人觉得有趣的是，据说以前的玩具再度流行起来了。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('ed172ada-ddd2-4a94-9282-6dd1c1b3ae3f', '4111d2b3-8629-4aa7-ab66-7f30cce2a29d', '困ったことに、相手の名前がどうしても思い出せなかった。', 'こまったことに、あいてのなまえがどうしてもおもいだせなかった。', '令人为难的是，怎么也想不起来对方的名字。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('28874df4-a626-4abd-9a50-d81e3358eefa', '4111d2b3-8629-4aa7-ab66-7f30cce2a29d', '不思議なことに、会社をやめたら、よく眠れるようになった。', 'ふしぎなことに、かいしゃをやめたら、よくねむれるようになった。', '不可思议的是，从公司辞职后，睡觉睡得安稳了。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('d2dafb42-6fc6-4db3-b198-8cbe6b515415', '～ことにする', NULL, 'N3', '动词辞书形·「ない形」＋ことにする', '动词辞书形·「ない形」＋ことにする', '“（我）决定……”。表示说话人的主观决定，即靠自己的意志决定某事。', '「～ことにしている」表示个人习惯，“坚持……”。', 402, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('62988e82-7363-443e-bf3c-3c785b456484', 'd2dafb42-6fc6-4db3-b198-8cbe6b515415', '小学校に入学して字を書く機会が増えるだろうと思い、孫に文房具をあげることにした。', 'しょうがっこうににゅうがくしてじをかくきかいがふえるだろうとおもい、まごにぶんぼうぐをあげることにした。', '我想孙子上小学之后写字的机会会变多吧，于是给他买了文具。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('8769d29c-5a9d-47a7-af22-e7b2b1d48ff2', 'd2dafb42-6fc6-4db3-b198-8cbe6b515415', 'アルコールはもう飲まないことにする。', 'アルコールはもうのまないことにする。', '我决定不再喝酒了。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('1c9d40c2-15c1-46cb-86c2-33a1ee9c4dc0', 'd2dafb42-6fc6-4db3-b198-8cbe6b515415', '毎日6時に起きることにしています。', 'まいにち6じにおきることにしています。', '我坚持每天早上六点起床。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('f47f3e9b-1e26-4184-8d7d-e5dbb182154f', '～ことになっている/こととなっている', NULL, 'N3', '动词辞书形·「ない形」＋ことになっている/こととなっている', '动词辞书形·「ない形」＋ことになっている/こととなっている', '“预定……”；“规定……”。表示计划、惯例、规章制度等。', '该句型具有客观性，而「～ことにする/ことにしている」则是一种主观上的决定。', 403, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('3412e603-5078-406b-a161-e4a9a3da6516', 'f47f3e9b-1e26-4184-8d7d-e5dbb182154f', '今日は7時東京駅で友だちと会うことになっているので、6時半に会社を出ます。', 'きょうは7じとうきょうえきでともだちとあうことになっているので、6じはんにかいしゃをでます。', '今天和朋友约好七点在东京站见面，所以打算六点半下班。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('80ad3e73-add9-468c-bcdd-8aba1db089e8', 'f47f3e9b-1e26-4184-8d7d-e5dbb182154f', 'この部屋には、関係者以外入ってはいけないことになっている。', 'このへやには、かんけいしゃいがいはいってはいけないことになっている。', '无关人员禁止进入此房间。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('8e85aeac-fd7f-4d07-95b3-d54c6bd12b76', 'f47f3e9b-1e26-4184-8d7d-e5dbb182154f', '日本では車は左側を走ることとなっている。', 'にほんではくるまはひだりがわをはしることとなっている。', '在日本，规定汽车要靠左行驶。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('9e745cd9-b013-4c15-8151-aa486c4bdbbb', '～ことになる', NULL, 'N3', '动词辞书形·「ない形」＋ことになる', '动词辞书形·「ない形」＋ことになる\n动词普通形＋（という）ことになる\n名词＋ということになる', '“决定……”，表示由他人或客观决定。多为公司、学校等的决定。\n“也就是说……”。换一种说法来指出事情的本质。', NULL, 404, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('21c29b0a-aa84-4bc9-a24f-21a2ec3dc852', '9e745cd9-b013-4c15-8151-aa486c4bdbbb', '新しい支店を開くことになった。', 'あたらしいしてんをひらくことになった。', '（公司）决定设立新的分店。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('5af25237-e2cf-448c-aada-f4bf86f79256', '9e745cd9-b013-4c15-8151-aa486c4bdbbb', '来月から授業は8時から始まることになりました。', 'らいげつからじゅぎょうは8じからはじまることになりました。', '从下个月起，八点开始上课。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('51b24c62-fa00-4b2c-825f-d5fd5163108a', '9e745cd9-b013-4c15-8151-aa486c4bdbbb', '家賃は一か月5万円だから、1年で60万円も払うことになる。', 'やちんはいっかげつ5まんえんだから、1ねんで60まんえんもはらうことになる。', '房租一个月是5万日元，也就是说一年要支付60万日元。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('3ce38709-8e7b-4c5b-92c4-9532820ddce9', '9e745cd9-b013-4c15-8151-aa486c4bdbbb', '彼女はおじの娘だから、わたしと彼女はいとこ同士ということになる。', 'かのじょはおじのむすめだから、わたしとかのじょはいとこどうしということになる。', '她是我叔叔的女儿，也就是说我和她是堂兄妹关系。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('eb150957-a912-4d4d-b411-aff17fd78e1b', '9e745cd9-b013-4c15-8151-aa486c4bdbbb', '毎日8時間働くんだから、一週間40時間働くということになるね。', 'まいにち8じかんはたらくんだから、いっしゅうかん40じかんはたらくということになるね。', '每天工作8个小时，也就是说一周要工作40个小时。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('76ec42e3-5e16-4056-907b-b73666991589', '～ことはない/こともない', NULL, 'N3', '动词辞书形＋ことはない/こともない', '动词辞书形＋ことはない/こともない', '“不必……”“用不着……”。表示没必要做某事。', '相当于「～する 必[ひつ] 要[よう]はない」，用于说话人对对方的忠告和劝告等。常和副词「わざわざ（特意）」呼应使用。', 405, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('34799290-295d-499e-971b-71a33a92f3dd', '76ec42e3-5e16-4056-907b-b73666991589', '君が一人で責任を感じることはない。そんなに悩んでいたら体を壊してしまうよ。', 'きみがひとりでせきにんをかんじることはない。そんなになやんでいたらからだをこわしてしまうよ。', '你不必觉得是你一个人的责任。如果那样烦恼下去的话，身体会垮的。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('f5030ea2-5ca6-4099-985d-e68c7705256c', '76ec42e3-5e16-4056-907b-b73666991589', 'その器具は確かに便利そうだが、なくても困らないのだから、わざわざ買うことはない。', 'そのきぐはたしかにべんりそうだが、なくてもこまらないのだから、わざわざかうことはない。', '那个器械似乎的确很方便，但是即使没有也没事，因此没必要特意去买。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('63b6d143-d8a0-4616-9e48-fae6d767c63d', '～ 最[さい] 中[ちゅう]に', NULL, 'N3', '名词＋の/动词「ている形」＋ 最[さい] 中[ちゅう]に', '名词＋の/动词「ている形」＋ 最[さい] 中[ちゅう]に', '“正在……的时候”。表示某个动作正在进行中。', '用「～ 最[さい] 中[ちゅう]に、～た」表示正在做前项时，突然发生了意外的、突发的事情。', 406, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('26726079-7fe2-4295-89a7-85463ec5c1b6', '63b6d143-d8a0-4616-9e48-fae6d767c63d', '電話している最中に、誰かが玄関に来た。', 'でんわさいちゅうに、だれかがげんかんにきた。', '正在打电话的时候，有人进屋了。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('99ae35b1-54e9-4c1c-8632-c78181bc7f96', '63b6d143-d8a0-4616-9e48-fae6d767c63d', '食事の最中に、お客さんが来た。', 'しょくじさいちゅうに、おきゃくさんがきた。', '正在吃饭的时候，客人来了。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('fd1ba238-41e9-4966-bf5c-ab16a151a266', '～さえ', NULL, 'N3', '名词/助词＋さえ', '名词/助词＋さえ\n人物名词（＋で）＋さえ', '“甚至……”“连……都……”。表示举出一个极端的例子，从而类推其他事物。', '「～さえ」相当于「も」，「～でさえ」相当于「～でも」，但语气更为强烈。另外还有「～さえも」「～でさえも」的用法。', 407, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('ee23fff9-c8ac-4e42-a8bc-2fee75c70938', 'fd1ba238-41e9-4966-bf5c-ab16a151a266', '最初は怖くてプールに入ることさえできなかったが、今では50メートルも泳げるようになった。', 'さいしょはこわくてプールにはいることさえできなかったが、いまでは50メートルもおよげるようになった。', '刚开始很害怕，就连进游泳池都不敢。现在已经能游50米了。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('04cd9348-16ef-4a6d-b7e5-cca0c2544d63', 'fd1ba238-41e9-4966-bf5c-ab16a151a266', '中学生の君にその問題が解けたとはすごいことだ。あれは大学生にさえ難しいと言われている。', 'ちゅうがくせいのきみにそのもんだいがとけたとはすごいことだ。あれはだいがくせいむずかしいといわれている。', '作为中学生的你能解出那道题真是不简单。据说那道题连大学生都觉得很难。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('df878e24-3f16-4546-a810-a72f323f022d', 'fd1ba238-41e9-4966-bf5c-ab16a151a266', '日本人でさえ、敬語を間違える場合がある。', 'にほんじんでさえ、けいごをまちがえる場合がある。', '就连日本人也会把敬语用错。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('c9dd0fda-cfb6-4b55-b274-c5f59261a746', '～さえ～ば', NULL, 'N3', '动词「ます形」＋さえ＋すれば/しなければ', '动词「ます形」＋さえ＋すれば/しなければ\nい形容词词干＋く＋さえ＋あれば/なければ\nな形容词词干＋で＋さえ＋あれば/なければ\n名词＋さえ＋各词类「ば形」', '“只要……就……”。', '表示只要具备了该条件，某件事情就能成立。', 408, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('0c6cad18-028f-4d83-91dd-13da3c4ffcd9', 'c9dd0fda-cfb6-4b55-b274-c5f59261a746', '最近、自分さえよければいいという考えの人が増えている。', 'さいきん、じぶんさえよければいいというかんがえのひとがふえている。', '最近，认为只要自己好就行的人多起来了。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('dbc3cfcd-411e-4c1d-af00-011dca52f81a', 'c9dd0fda-cfb6-4b55-b274-c5f59261a746', 'この薬を飲みさえすれば、すぐ治れるというわけではない。', 'このくすりをのみさえすれば、すぐなおれるというわけではない。', '并不是只要吃了这个药，病就马上能好。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('6a926180-b977-4a1c-b293-fb6e4b6aadb0', 'c9dd0fda-cfb6-4b55-b274-c5f59261a746', '仕事が忙しくさえなければ、英語の勉強を続けたい。', 'しごとがいそがしくさえなければ、えいごのべんきょうをつづけたい。', '只要工作不忙，就想继续学习英语。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('290a9cb1-18d2-4468-a108-09d5dd054760', 'c9dd0fda-cfb6-4b55-b274-c5f59261a746', '静かでさえあれば、狭くてもいい。', 'しずかでさえあれば、せまくてもいい。', '只要安静，即使房子小一点也行。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('b4e11bfc-4b96-4b8d-9910-0fb8d46dbca1', '～じゃん/じゃない/じゃないの/じゃないか', NULL, 'N3', '名＋じゃない/じゃないの/じゃないか', '名＋じゃない/じゃないの/じゃないか\n动词意志形＋じゃないか', '“不（是）……吗？”，表示反问的语气，是「～ではない/ではないの/ではないか」等句型更为口语化的表达方式。其中「～じゃん」男女均可使用；「～じゃない/じゃないの」多是女性用语；「～じゃないか」是男性用语。\n表示新的发现或者表达惊讶、愤怒的语气。\n“让我们一起……吧”。表示建议、号召或者劝诱。是「～（よ）うではないか/（よ）うではありませんか」等句型的更为口语化的表达方式。', NULL, 409, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('6a340741-0eb5-4de5-bdb0-5111d23712b2', 'b4e11bfc-4b96-4b8d-9910-0fb8d46dbca1', '本当は彼のことが好きなんじゃないの。だったら直接言えばいいじゃん。（女）', 'ほんとうはかれのことがすきなんじゃないの。だったらちょくせついえばいいじゃん。（女）', '其实你是喜欢他的吧，直接跟他表白不就好了吗？', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('4b42bd34-f4fe-41a7-9f41-35bf61d9f5df', 'b4e11bfc-4b96-4b8d-9910-0fb8d46dbca1', '今度また一緒に遊ぼうじゃないか。', 'こんどまたいっしょにあそぼうじゃないか。', '下次我们再一起玩吧。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('28880adf-2ae8-48df-b506-ccffab5f7271', 'b4e11bfc-4b96-4b8d-9910-0fb8d46dbca1', '皆で一緒に頑張ろうじゃないか。', 'みんなでいっしょにがんばろうじゃないか。', '我们大家一起努力吧。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('92e0c57f-796b-4036-ba82-c114fea30d18', '～ 上[じょう]', NULL, 'N3', '名词＋ 上[じょう]', '名词＋ 上[じょう]', '“在……上”“……方面”。表示在某个范围、某个方面、某种立场。', '「～ 上[じょう]の」后续名词作定语使用。「～ 上[じょう]」前面常接「 教[きょう] 育[いく]/  歴[れき] 史[し]/  仕[し] 事[ごと]/  技[ぎ] 術[じゅつ]/  経[けい] 済[ざい]」等词。', 410, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('19db747b-30fe-4578-8c76-51ba0797ea08', '92e0c57f-796b-4036-ba82-c114fea30d18', '他人の住所を勝手に公表することは、法律上、認められていない。', 'たにんのじゅうしょをかってにこうひょうすることは、ほうりつじょう、みとめられていない。', '随便公开他人的住址，在法律上是不被允许的。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('6d5693c8-1f7c-4562-803a-bdf535f0cb34', '92e0c57f-796b-4036-ba82-c114fea30d18', 'このブラウスは、絹なのかナイロンなのか、見かけ上区別がつかない。', 'このブラウスは、きぬなのかナイロンなのか、みじょうくべつがつかない。', '这件罩衫，从外表来看区分不出是绢丝的还是尼龙的。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('9651b84f-e5b0-4daf-953c-62678dbef1d9', '92e0c57f-796b-4036-ba82-c114fea30d18', 'それは法律上では許されない行為だ。', 'それはほうりつじょうではゆるされないこういだ。', '在法律上那是不被允许的行为。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('2442ab92-2e5f-43ba-b693-4dbd3e6dbdeb', '92e0c57f-796b-4036-ba82-c114fea30d18', '生命倫理上の問題でクローン技術に反対する意見が多い。', 'せいめいりんりじょうのもんだいでクローンぎじゅつにはんたいするいけんがおおい。', '由于生命伦理上的问题，反对克隆技术的意见比较多。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('09ca2b97-83cb-4976-96a5-b96740b76c69', '～ずとも', NULL, 'N3', '动词「ない形」＋ずとも', '动词「ない形」＋ずとも\n（する→せずとも）', '“即使不……也……”。', '后面多为「わかる/いい」等，意思相当于「～なくても」。', 411, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('d97aa80c-7014-4086-b1ae-11525370ad55', '09ca2b97-83cb-4976-96a5-b96740b76c69', '嫌なら行かずともよい。', 'いやならいかずともよい。', '如果不愿意的话，不去也行。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('20fbfd26-2aee-47e0-9a72-a5fbd3eea21d', '09ca2b97-83cb-4976-96a5-b96740b76c69', 'この部分は書かずともよい。', 'このぶぶんはかかずともよい。', '这一部分不写也行。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('a29c5095-8eea-4cf3-8488-7a18d3e5e519', '09ca2b97-83cb-4976-96a5-b96740b76c69', 'そんな簡単なことぐらい聞かずともわかる。', 'そんなかんたんなことぐらいきかずともわかる。', '那么简单的事情，即使不问我也知道。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('9ebf5d8c-b5e8-4e2e-a8dc-e8c1218ea6d8', '～（は）する/（も）する', NULL, 'N3', '名词＋（は）する/（も）する', '名词＋（は）する/（も）する', '“花费……”“用了……”，表示经过的时间或者花费的费用。', '一般用于感叹经过的时间或花费的费用超出预想。', 412, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('b84b720b-b0bd-4f41-87ab-a01d8a2e2531', '9ebf5d8c-b5e8-4e2e-a8dc-e8c1218ea6d8', 'そのホテルは一泊10万円もするそうだ。', 'そのホテルはいっぱく10まんえんもするそうだ。', '听说那家宾馆一晚要花十万日元。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('733e12c8-5115-494d-bf8b-a83ccd1b515a', '9ebf5d8c-b5e8-4e2e-a8dc-e8c1218ea6d8', '入社して半年もしないうちに仕事をやめた。', 'にゅうしゃしてはんとしもしないうちにしごとをやめた。', '入职后不到半年就辞职了。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('b070030a-454d-44fe-b13a-f010598e74fc', '9ebf5d8c-b5e8-4e2e-a8dc-e8c1218ea6d8', '飛行機で行くなら3時間はするでしょう。', 'ひこうきでいくなら3じかんはするでしょう。', '坐飞机去的话要花三个小时吧。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('a99db725-5b54-4afc-b816-7cc3940f16c1', '～せいで/せいだ/せいか', NULL, 'N3', '～せいで/せいだ/せいか', '～せいで/せいだ/せいか', '“都怪……”“因为……”；“大概是因为……吧”。表示因为前项的缘故，造成了后项不好的结果。说话人的责怪、遗憾的语气较强。', '「～せいか」表示并不十分确定的原因。\n「～を～せいにする」表示“把责任归咎于……”。', 413, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('e2f6afac-c1f9-4236-aa2d-a24fb12fddc3', 'a99db725-5b54-4afc-b816-7cc3940f16c1', '今年は気温が高いせいか、冬になってもなかなか雪が降らない。', 'ことしはきおんがたかいせいか、ふゆになってもなかなかゆきがふらない。', '大概是因为今年气温过高的缘故吧，尽管入冬了也没下雪。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('27233a3a-c3f5-48c3-854d-0f038155c0f3', 'a99db725-5b54-4afc-b816-7cc3940f16c1', '原料が安いせいか、この製品は値段が安い。', 'げんりょうがやすいせいか、このせいひんはねだんがやすい。', '大概是原材料便宜，所以这个产品的价格便宜。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('f1d24071-2431-4b3f-b326-e061fda1a628', 'a99db725-5b54-4afc-b816-7cc3940f16c1', '夜眠れないのは騒音のせいだ。', 'よるねむれないのはそうおんのせいだ。', '晚上睡不着，是因为有噪声。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('ff25e7ff-4c71-4770-a92e-00f7ff2d38b0', 'a99db725-5b54-4afc-b816-7cc3940f16c1', '自分の失敗を人のせいにする。', 'じぶんのしっぱいをひとのせいにする。', '把自己的失败归咎于他人。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('ea88eb30-00fb-4632-8a3b-ad6f329e4851', '～そうにない/そうもない', NULL, 'N3', '动词「ます形」＋そうにない/そうもない', '动词「ます形」＋そうにない/そうもない', '“看样子不会……”。表示说话人根据周围的情况或事物的外观而作出的判断。', '「～そうにない/そうもない」前面只能接续动词「ます形」。\n表示样态的助动词「～そうだ」还有一种否定形式是「～そうで（は）ない」。但前面只能接续「い形容词词干/な形容词词干」，用法比较有限。', 414, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('c642df0f-6391-4e48-ac69-f70d4879bd81', 'ea88eb30-00fb-4632-8a3b-ad6f329e4851', '今のわたしの給料では、何年働いても自分の家は買えそうもない。', 'いまのわたしのきゅうりょうでは、なんねんはたらいてもじぶんのいえはかえそうもない。', '就我现在的收入而言，无论工作多少年也买不起自己的房子。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('b7c68e45-51fb-4163-b9fc-21c266f174f1', 'ea88eb30-00fb-4632-8a3b-ad6f329e4851', '雨はまだ止みそうにない。', 'あめはまだやみそうにない。', '雨还没有要停下来的迹象。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('e6339fc9-85db-4282-a00a-723aa8a59e86', '～たきり～ない', NULL, 'N3', '动词「た形」＋きり～ない', '动词「た形」＋きり～ない', '“自从……之后，再也没有……”。表示自从前项的事发生之后，情况再也没有改变过。', '「～きり」通常后续否定表达形式。口语中也有「～っきり」「～ぎり」的说法。', 415, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('60183f3f-9e67-43cf-b41a-f42bfff86f3a', 'e6339fc9-85db-4282-a00a-723aa8a59e86', '彼は出かけたきり、戻ってこない。', 'かれはでかけたきり、もどってこない。', '他出去之后，就没有回来。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('e7c15658-7f82-4c8f-9677-aaf40aa744f8', 'e6339fc9-85db-4282-a00a-723aa8a59e86', 'ピアノは小学生の頃習ったきりで、ほとんど忘れてしまった。', 'ピアノはしょうがくせいのころならったきりで、ほとんどわすれてしまった。', '上小学的时候学过钢琴，（之后再也没有弹过），差不多都忘了。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('aee5e166-f609-4be2-aa8e-e68a49ec50a9', 'e6339fc9-85db-4282-a00a-723aa8a59e86', '彼とは3年前に一度会ったきり、その後、ずっと会っていない。', 'かれとは3ねんまえにいちどあったきり、そのご、ずっとあっていない。', '三年前和他见过一次面之后，就再也没有见过。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('8561cfc5-9520-4da8-96ce-6a4d7016094f', '～だけでなく', NULL, 'N3', '～だけでなく', '～だけでなく', '表示累加，“不但……而且……”。', '相当于「～ばかりでなく」。后项常和助词「も/だって」等呼应使用。', 416, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('b1222121-f533-443f-b5c4-cebd7f937f6b', '8561cfc5-9520-4da8-96ce-6a4d7016094f', '川名寺は桜がきれいなことで有名ですが、桜だけでなく、秋の景色もすばらしいです。', 'かわなでらはさくらがきれいなことでゆうめいですが、さくらだけでなく、あきのけしきもすばらしいです。', '川名寺因樱花美丽而闻名，但其实不只是樱花，那里秋天的景色也是非常不错的。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('d350fd93-2e30-4681-88f7-5b2d960c0945', '8561cfc5-9520-4da8-96ce-6a4d7016094f', '新しい携帯電話は、写真が撮れるだけじゃなくて、テレビだって見られるんだよ。', 'あたらしいけいたいでんわは、しゃしんがとれるだけじゃなくて、テレビだってみられるんだよ。', '新手机不仅能拍照，还可以看电视。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('3cf33c3f-215c-4bbf-bc20-eb3f83895fb2', '8561cfc5-9520-4da8-96ce-6a4d7016094f', 'あの工場は、設備だけでなく周りの環境もすばらしい。', 'あのこうじょうは、せつびまわりのかんきょうもすばらしい。', '那家工厂不仅设备先进，而且周围的环境也很好。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('b400d294-3ffa-45af-8aef-52c49dcff87f', '～だけでは', NULL, 'N3', '～だけでは', '～だけでは', '“光是……的话”，表示只做前项的事很难出现期待的结果。', '「～だけでは」后项多为负面评价，常和副词「ただ（光、仅）」搭配使用。「～だけじゃ」是「～だけでは」的口语。', 417, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('ccc4b45e-d0e5-40e3-aa27-e3b346512398', 'b400d294-3ffa-45af-8aef-52c49dcff87f', 'スポーツはただ見るだけではつまらない。', 'スポーツはただみるだけではつまらない。', '体育运动光看是没有意思的。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('49b58f9a-e68b-482f-8cf5-05a733410121', 'b400d294-3ffa-45af-8aef-52c49dcff87f', '行動せずに口先だけでは成功できない。', 'こうどうせずにくちさきせいこうできない。', '光说不做，是不可能成功的。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('d0d35167-6c9f-4e0d-82f2-5f154e6078ac', '～たことにする', NULL, 'N3', '动词「た形」＋ことにする', '动词「た形」＋ことにする', '“就当作……”。', '该句型表示将某事按照与事实相反的情况处理。', 418, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('f67baf71-d276-480d-a491-eaae602a0576', 'd0d35167-6c9f-4e0d-82f2-5f154e6078ac', 'その話は聞かなかったことにします。', 'そのはなしはきかなかったことにします。', '那件事情就当我没听过。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('082e66d8-e36f-4041-b618-a48fb0f7fed9', 'd0d35167-6c9f-4e0d-82f2-5f154e6078ac', '今までのことはなかったことにしましょう。', 'いままでのことはなかったことにしましょう。', '以前的事就当作没有发生过吧。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('853ac9f0-d579-4e17-81ca-8a3dbd77c03c', '～たって/だって', NULL, 'N3', 'い形容词词干＋く/动词「ます形」＋たって', 'い形容词词干＋く/动词「ます形」＋たって\nな形容词词干/名词＋だって\n疑问词（＋助词）＋だって', '“即使……也……”，表示举出极端的事例，同时暗示其他就更不用说了。\n“无论……都……”。', '与肯定句相呼应时，相当于「～ても/でも」。与否定句相呼应时，相当于「～も」。一般用于口语。', 419, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('e6763ef8-d0f7-4c94-a340-3398b089ad28', '853ac9f0-d579-4e17-81ca-8a3dbd77c03c', '今さら謝りたって許してもらえないかもしれない。', 'いまさらあやまゆるしてもらえないかもしれない。', '事已至此，即使道歉，也不会得到原谅了吧。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('ebd7f51d-cfa1-4846-b503-4e12eff36d90', '853ac9f0-d579-4e17-81ca-8a3dbd77c03c', '難しくたって、この仕事に挑戦してみたいと思う。', 'むずかしくたって、このしごとにちょうせんしてみたいとおもう。', '即使难，我也想挑战一下这项工作。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('ed4a22f5-3009-452f-8179-e36ec8e9f532', '853ac9f0-d579-4e17-81ca-8a3dbd77c03c', '野菜が大嫌いだって、健康のために食べるべきだ。', 'やさいがだいきらいだって、けんこうのためにたべるべきだ。', '即使不喜欢吃蔬菜，为了健康也应该吃。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('9a7e49a7-a1e3-4ddb-9b3a-b9526a3cfcc1', '853ac9f0-d579-4e17-81ca-8a3dbd77c03c', '最近は仕事が忙しくて、日曜日だって休めない。', 'さいきんはしごとがいそがしくて、にちようびやすめない。', '最近工作很忙，即便是周日也不能休息。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('5453b44a-db95-403f-aa38-bab7dfc72b1f', '853ac9f0-d579-4e17-81ca-8a3dbd77c03c', 'わたしの応援が力になるならいくらだって応援します。', 'わたしのおうえんがちからおうえんします。', '我的支持要是有用的话，给你多少都可以。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('958710b7-e629-40fd-8fe3-b88c1cfa35fe', '853ac9f0-d579-4e17-81ca-8a3dbd77c03c', 'あの二人が結婚したと聞けば、誰だってびっくりするよ。', 'あのふたりがけっこんしたときけば、だれだってびっくりするよ。', '要是听说那两个人结婚了的话，无论是谁都会吃惊的。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('256f347a-6c9c-4d9d-940e-e4cd8bacb961', 'たとえ/たとい～ても', NULL, 'N3', 'たとえ/たとい＋动词「て形」＋も', 'たとえ/たとい＋动词「て形」＋も\nたとえ/たとい＋い形容词词干＋く＋ても\nたとえ/たとい＋な形容词词干＋でも\nたとえ/たとい＋名词＋でも', '“即使……也……”。表示就算是前项成立，后项也不会受此影响。', '「たとえ/たとい」是副词，表示“即使（……也……）”的意思。', 420, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('d1eec69d-f362-4957-a481-6c23c4f7cfee', '256f347a-6c9c-4d9d-940e-e4cd8bacb961', 'たとえ不合格だとしても、君の今までの努力はむだではないよ。', 'ふごうかくだとしても、きみのいままでのどりょくはむだではないよ。', '即使不及格，你迄今为止的努力也不是白费啊。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('19fe0669-bd35-49b2-9183-df6e692e5e56', '256f347a-6c9c-4d9d-940e-e4cd8bacb961', 'たとえみんなに反対されても、わたしは絶対にこの計画を実行したい。', 'たとえみんなにはんたいされても、わたしはぜったいにこのけいかくをじっこうしたい。', '即使大家都反对，我也一定要实行这个计划。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('6979f1d6-83b2-4bc1-b327-29ac4f55ac29', '256f347a-6c9c-4d9d-940e-e4cd8bacb961', 'たとえ高くても、必要なものは買わなければならない。', 'たかくても、ひつようなものはかわなければならない。', '即使贵，必要的东西也必须得买。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('46f32049-b6a6-4727-ba11-a4d22b01851a', '～たばかりだ', NULL, 'N3', '动词「た形」＋ばかりだ', '动词「た形」＋ばかりだ', '“刚刚……”，表示刚刚做完某个动作。', '「～たばかりだ」的动作行为结束后间隔时间可长可短。', 421, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('42f37f87-4262-4373-9aaa-886a875fe467', '46f32049-b6a6-4727-ba11-a4d22b01851a', 'さっきご飯を食べたばかりだというのに、もうおなかがすいてきた。', 'さっきごはんをたべたばかりだというのに、もうおなかがすいてきた。', '虽然刚刚才吃过早饭，但肚子又开始饿了。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('e4d65a00-d597-4ed7-a9ab-15c775d998f3', '46f32049-b6a6-4727-ba11-a4d22b01851a', '昨日、動物園に行ったら、先月生まれたばかりのライオンの赤ちゃんを見ることができました。', 'きのう、どうぶつえんにいったら、せんげつうまれたばかりのライオンのあかちゃんをみることができました。', '昨天去了动物园，看到了上个月刚刚出生的小狮子。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('e5a1867e-aa81-475e-814b-fc165e2648dc', '46f32049-b6a6-4727-ba11-a4d22b01851a', 'A「遅くなってすみません。」B「いいえ、わたしも今来たばかりです。」', 'A「おそくなってすみません。」B「いいえ、わたしもいまきたばかりです。」', 'A：“对不起，我来迟了。”\nB：“没关系，我也是刚到。”', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('0e0f2cd0-7b72-4bd4-a078-6030726b43f6', '～たび（に）', NULL, 'N3', '名词＋の/动词辞书形＋たび（に）', '名词＋の/动词辞书形＋たび（に）', '“每当……就……”。', '表示每当进行前项动作、行为时，总是伴随着后项事态的发生。「この 度[たび]」是惯用表达，意思是“这次”。', 422, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('d03bbac5-00c8-47a8-90dd-f0a95d7a5e51', '0e0f2cd0-7b72-4bd4-a078-6030726b43f6', 'うちの犬は、私が出かけようとするたびに、寂しそうな目で私を見る。', 'うちのいぬは、わたしがでかけようとするたびに、さびしそうなめでわたしをみる。', '每次我准备要出门的时候，我家的狗都用一种看起来很不舍的眼神望着我。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('229f3664-b669-49d1-ba8c-07ff34e2f05f', '0e0f2cd0-7b72-4bd4-a078-6030726b43f6', 'わたしは山田さんに会うたびに素敵な人だといつも思う。', 'わたしはやまださんにあすてきなひとだといつもおもう。', '我每次见到山田，都觉得他很出色。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('350f7977-de7a-41ec-bce2-f2ce2adf495f', '0e0f2cd0-7b72-4bd4-a078-6030726b43f6', 'この写真を見るたび、故郷のことを思い出す。', 'このしゃしんをみるたび、こきょうのことをおもいだす。', '每当我看到这张照片，就会想起故乡。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('e1ae2bed-ac28-431a-ba7f-478c57d6bdeb', '0e0f2cd0-7b72-4bd4-a078-6030726b43f6', '木村さんは旅行のたびに、お土産を買ってきてくれる。', 'きむらさんはりょこうのたびに、おみやげをかってきてくれる。', '木村每次旅行，都会给我带礼物。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('cd779a09-9596-4f33-8400-9fac1b0cc0e2', '～たまえ', NULL, 'N3', '动词「ます形」＋たまえ', '动词「ます形」＋たまえ', '表示轻微的命令。', '「～たまえ」是口语，主要用于下级、晚辈或在朋友之间，是男性用语。', 423, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('b56ca8df-275a-4df3-8c80-84aca64e2e9b', 'cd779a09-9596-4f33-8400-9fac1b0cc0e2', '上田君、この方案を説明したまえ。', 'うえだくん、このほうあんをせつめいしたまえ。', '上田，你来说明下这个方案吧。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('36a9c84f-3f14-4ee3-9524-d59c3c13e5e6', 'cd779a09-9596-4f33-8400-9fac1b0cc0e2', '明日は朝7時に来たまえ。', 'あしたはあさ7じにきたまえ。', '你明天早上七点来。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('31cbf6f7-0275-432f-ab1b-9769df93b33e', '～たら/ったら', NULL, 'N3', '名词＋たら/ったら', '名词＋たら/ったら', '“说起……”“谈到……”。表示说明话题，带有说话人亲昵、取笑、告诫、责难等语气。', '相当于「～と 言[い]ったら」，常用于口语。', 424, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('9bab82c0-ffbd-4a28-b87b-6ec91c83b4c4', '31cbf6f7-0275-432f-ab1b-9769df93b33e', '李さんったら、また遅刻した。', 'りさんったら、またちこくした。', '说到小李，他又迟到了。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('0cf01807-e377-4b5f-92e6-9773ef4e3574', '31cbf6f7-0275-432f-ab1b-9769df93b33e', 'この時間たら、どこも込んでるよ。', 'このじかんたら、どこもこんでるよ。', '这个时间的话，不论哪里都很挤的。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('897615c5-2e75-4366-ace4-e8af9e2bcc74', '～だらけ', NULL, 'N3', '名词＋だらけ', '名词＋だらけ', '“净是……”“满是……”，表示净是不愉快的东西或事情。一般用于贬义。', '惯用搭配有「ごみだらけ/ 借[しゃっ] 金[きん]だらけ/ 血[ち]だらけ/ 欠[けっ] 点[てん]だらけ/ 間[ま] 違[ちが]いだらけ」等。', 425, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('c15bde13-6ca0-49fc-88bf-26a249927aee', '897615c5-2e75-4366-ace4-e8af9e2bcc74', '昨日からの雨がようやく止んだが、運動場はまだ濡れていた。試合を終えたサッカー選手の顔はみんな泥だらけだ。', 'きのうからのあめがようやくやんだが、うんどうじょうはまだぬれていた。しあいをおえたサッカーせんしゅのかおはみんなどろだらけだ。', '昨天开始下的雨总算停了，但运动场上还是一片泥泞，踢完足球比赛的选手们脸上都是泥。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('1bd7616c-a2ca-49d8-a90e-f99cb657217b', '897615c5-2e75-4366-ace4-e8af9e2bcc74', 'この部屋は何年も住んでいないので、埃だらけだ。', 'このへやはなんねんもすんでいないので、ほこりだらけだ。', '这间屋子好多年没有住人了，都是灰尘。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('cda8d8d7-7b3f-4499-bf8b-a7f5916e3cfa', '～たらどうですか', NULL, 'N3', '动词「た形」＋らどうですか', '动词「た形」＋らどうですか', '“……那样做怎么样”。表示提议或劝诱。', '「～たらどうですか」有时也可以说成「～たら（どう）」，但是一般用于关系亲密的人之间。其委婉说法是「～たらどうでしょうか/いかがですか/たらいかがでしょうか。」', 426, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('0804bee7-2a36-4437-a64e-b9f23393eca2', 'cda8d8d7-7b3f-4499-bf8b-a7f5916e3cfa', 'A「昨日からずっと頭が痛いんですが、どこかいい病院を知りませんか。」B「そうですねえ、ABC病院に行ってみたらどうでしょう。」', 'A「きのうからずっとあたまがいたいんですが、どこかいいびょういんをしりませんか。」B「そうですねえ、ABCびょういんにいってみたらどうでしょう。」', 'A：“我从昨天开始一直头痛，你知道什么比较好的医院吗？”\nB：“这样啊，那你去ABC医院看看吧。”', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('d732c9f1-4b2b-4043-b016-94d81f72476f', 'cda8d8d7-7b3f-4499-bf8b-a7f5916e3cfa', '上田「来週、兄の誕生日なんだけど、プレゼントに何を買おうかな。」山本「ネクタイでも買ってあげたらどう？上田さんからのプレゼント、お兄さん、喜ぶと思うよ。」', 'うえだ「らいしゅう、あにのたんじょうびなんだけど、プレゼントになにをかおうかな。」やまもと「ネクタイでもかってあげたらどう？うえださんからのプレゼント、おにいさん、よろこぶとおもうよ。」', '上田：“下周就是哥哥的生日了，买什么礼物好呢？”\n山本：“买领带什么的怎么样？我想你哥哥收到你送的礼物，一定会高兴的。”', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('d1ea3437-214c-4eeb-b8ea-2ca1eaf8adaa', '～だろうか', NULL, 'N3', '～だろうか', '～だろうか', '“能……吗”；“会是……吗”。表示询问、推测、怀疑等。', NULL, 427, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('b5ab71b4-6a26-4024-b311-e88fce31fc8d', 'd1ea3437-214c-4eeb-b8ea-2ca1eaf8adaa', '明日の実験は成功するだろうか。', 'あしたのじっけんはせいこうするだろうか。', '明天的实验能成功吗？', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('5efb8ac7-1e10-4fc5-a8bf-6d57e3fc6035', 'd1ea3437-214c-4eeb-b8ea-2ca1eaf8adaa', '山田君が学校を休んだ。病気だろうか。', 'やまだくんががっこうをやすんだ。びょうきだろうか。', '山田没来学校。是不是生病了？', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('c3e98b9e-5d71-4be5-b3fb-011650d0b9d8', '～っけ', NULL, 'N3', '～っけ', '～っけ', '“（是不是）……来着”，表示向对方确认或表示回忆。', '「～っけ」是终助词，用于关系亲密的熟人、朋友之间的会话中。其礼貌用语是「～ましたっけ/でしたっけ」。', 428, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('e45d5fd7-02b4-48c2-bea6-8cf14baafc0c', 'c3e98b9e-5d71-4be5-b3fb-011650d0b9d8', '鈴木さんの出身校は早稲田大学だったっけ。', 'すずきさんのしゅっしんこうはわせだだいがくだったっけ。', '铃木毕业的大学是早稻田大学？', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('952a0c16-6be6-41ee-81b7-0a4f242c0c28', 'c3e98b9e-5d71-4be5-b3fb-011650d0b9d8', 'レポートの締め切りはあさってだったっけ。', 'レポートのしめきりはあさってだったっけ。', '小报告的截止日期是不是后天来着？', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('5fad06a9-427d-4edf-b525-ca56a7fc1cd1', 'c3e98b9e-5d71-4be5-b3fb-011650d0b9d8', '明日の会議、何時からだっけ。', 'あしたのかいぎ、なんじからだっけ。', '明天会议几点开始来着？', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('82562189-6fbd-4e9f-abc2-07333525cbce', '～って', NULL, 'N3', '名词＋って＋名词', '名词＋って＋名词\n名词/句子的普通形＋って\n句子的普通形＋って\n句子的普通形+って+「 言[い]う/ 思[おも]う/ 書[か]く/ 聞[き]く」等', '“叫……的……”，表示称谓。\n“……的是……”。表示说明主题或话题，相当于「～は/というのは/とは」。\n“听说……”。表示传闻。\n表示引用。', '是「～という」的口语表达形式。\n表示说明主题或话题，相当于「～は/というのは/とは」。\n用于句末，相当于「～そうだ/らしい/という」。\n是「と」的口语表达形式。', 429, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('8f848191-9304-48ce-84f5-a810a9d7156f', '82562189-6fbd-4e9f-abc2-07333525cbce', 'さっき、高橋さんって人から電話がありました。', 'さっき、たかはしひとからでんわがありました。', '刚刚，有个叫高桥的人打来电话了。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('86495ecd-b24f-446c-8e96-5a70932cd459', '82562189-6fbd-4e9f-abc2-07333525cbce', '「オジギソウ」って草を見たことがある？', 'くさをみたことがある？', '你见过叫作“含羞草”的草吗？', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('31d559ab-9fa1-4226-8599-618cd06d544a', '82562189-6fbd-4e9f-abc2-07333525cbce', '嵐ってアイドルグループを知らないの。', 'あらしってアイドルグループをしらないの。', '你不知道岚这个偶像团体吗？', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('89265d2f-286d-49e4-8970-9451196e4042', '82562189-6fbd-4e9f-abc2-07333525cbce', 'A「ねえ、田中さんってどんな人？」B「とても親切でいい人だよ。」', 'A「ねえ、たなかさんってどんなひと？」B「とてもしんせつでいいひとだよ。」', 'A：“那个，田中人怎么样啊？”\nB：“他是个非常热心的人。”', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('657729d7-f054-4597-80c3-90b6e53dbebc', '82562189-6fbd-4e9f-abc2-07333525cbce', '来年、関西地区に支店を出すって、本当ですか。', 'らいねん、かんさいちくにしてんをだすって、ほんとうですか。', '明年要在关西地区开分店，这是真的吗？', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('a9c76d40-0a16-4488-922e-3482cfbe410b', '82562189-6fbd-4e9f-abc2-07333525cbce', '部長は来週アメリカへ出張するって。', 'ぶちょうはらいしゅうアメリカへしゅっちょうするって。', '听说部长下周去美国出差。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('e6029dd5-35ef-4e1e-85a4-b32c67b22509', '82562189-6fbd-4e9f-abc2-07333525cbce', '森さんは期末試験に落ちたって。', 'もりさんはきまつしけんにおちたって。', '听说森同学没通过期末考试。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('eb56ff97-0c9a-4963-815a-93af64544e08', '82562189-6fbd-4e9f-abc2-07333525cbce', '明日は雨だって。', 'あしたはあめだって。', '听说明天会下雨。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('72ce635e-9de5-4e5d-bc4e-85b0bf552684', '82562189-6fbd-4e9f-abc2-07333525cbce', 'A「田中さんは今日もアルバイトでしょうか。」B「今日はないって言ってましたよ。」', 'A「たなかさんはきょうもアルバイトでしょうか。」B「きょういってましたよ。」', 'A：“田中今天也要打工吗？”\nB：“他说今天休息。”', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('6cc88b28-1c81-425e-8696-87abbdd55b4b', '82562189-6fbd-4e9f-abc2-07333525cbce', '壁の張り紙に「禁煙」って書いてある。', 'かべのはりがみに「きんえんかいてある。', '墙上贴纸上写着“禁烟”。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('01963536-1415-4b4f-a7fa-de162d081156', '～つもり', NULL, 'N3', '～つもり', '～つもり', '“自以为……”，表示主语自己的想法。', '表示说话人自己那样认为，未必与别人的想法或事实相符。', 430, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('3e13c73e-527a-4557-b1ed-57b37b2044b6', '01963536-1415-4b4f-a7fa-de162d081156', 'わたしは彼女にいろいろ親切にしたつもりなんですが、感謝されるどころか、恨まれている。', 'わたしはかのじょにいろいろしんせつにしたつもりなんですが、かんしゃされるどころか、うらまれている。', '我自认为对她已经很好了，可别说感谢了，反倒遭她怨恨。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('d78caf88-1072-4e22-9948-80f52c22f7db', '01963536-1415-4b4f-a7fa-de162d081156', 'A「中村さん、ずいぶん年とったわね。」B「うん、でも、自分じゃまだまだ若いつもりでいるよ。」', 'A「なかむらさん、ずいぶんとしとったわね。」B「うん、でも、じぶんじゃまだまだわかいつもりでいるよ。」', 'A：“中村，你老了很多嘛。”\nB：“嗯，不过我自我感觉还很年轻呢。”', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('eafd52ea-8ae4-4aba-ba34-9c0aa06ad918', '～で', NULL, 'N3', '动词普通形＋こと/名词＋で', '动词普通形＋こと/名词＋で', '“因为……”；“通过……”。', '表示原因或依据。', 431, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('7cb9d6a3-d2ba-476d-b308-69bbd85061d1', 'eafd52ea-8ae4-4aba-ba34-9c0aa06ad918', 'A「ねえ、来週の日曜日、北町の美術館に行かない？」B「いいね。あ、私、そこの割引券を持ってるよ。その割引券1枚で3人まで2割引になるんだ。」', 'A「ねえ、らいしゅうのにちようび、きたまちのびじゅつかんにいかない？」B「いいね。あ、わたし、そこのわりびきけんをもってるよ。そのわりびきけん1まいで3にんまで2わりびきになるんだ。」', 'A：“那个，下周日一起去北町的美术馆吧？”\nB：“好啊。啊，我有那里的折扣券。凭一张折扣券最多可以让3个人打八折。”', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('491c4ff9-9893-4a97-8d54-4caff62a9059', 'eafd52ea-8ae4-4aba-ba34-9c0aa06ad918', 'A「最近、山田さん元気ないね。」B「うん。将来のことで悩んでるらしいよ。」', 'A「さいきん、やまださんげんきないね。」B「うん。しょうらいなやんでるらしいよ。」', 'A：“最近山田没什么精神啊。”\nB：“是啊，好像在为将来的事情烦恼着呢。”', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('588e55ee-749a-4e77-8f47-f5f1367bcc50', 'eafd52ea-8ae4-4aba-ba34-9c0aa06ad918', '子どもが生まれたことで食べ物の安全を気にするようになった。', 'こどもがうたべもののあんぜんをきにするようになった。', '因为生了孩子，所以就变得关注食物安全了。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('8ebb3289-61eb-4eee-96f4-732791d04138', 'eafd52ea-8ae4-4aba-ba34-9c0aa06ad918', '留学したことで、異なる文化に興味を持つようになった。', 'りゅうがくしたことで、ことなるぶんかにきょうみをもつようになった。', '通过留学，对异国文化产生了兴趣。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('87d8096c-9e11-4874-bec3-d6c6dc60414a', '～て 以[い] 来[らい]', NULL, 'N3', '动词「て形」＋ 以[い] 来[らい]', '动词「て形」＋ 以[い] 来[らい]', '“自从……以来”。表示自从过去发生的某一事件之后直到现在。', '一般不用在刚刚发生不久的事。', 432, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('7a4f321a-cc36-47fa-b1f4-c3a53e446014', '87d8096c-9e11-4874-bec3-d6c6dc60414a', '彼とは10年前のクラス会で会って以来、一度も連絡を取っていない。', 'かれとは10ねんまえのクラスかいであいらい、いちどもれんらくをとっていない。', '自从十年前和他在同学聚会上见面之后，再也没有联系过。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('201c0329-6408-4446-bdff-a46b9bbf8b7a', '87d8096c-9e11-4874-bec3-d6c6dc60414a', '兄は会社に入って以来、一度も休んだことはありません。', 'あにはかいしゃにはいいらい、いちどもやすんだことはありません。', '哥哥自从进了公司之后，从未请过假。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('b2b9ba6e-59fb-4cd6-adc7-599bcdc494af', '87d8096c-9e11-4874-bec3-d6c6dc60414a', '結婚して以来、体重が増え続けている。', 'けっこんいらい、たいじゅうがふえつづけている。', '自从结婚之后，体重不断增加。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('797c9f54-51a5-4a59-a742-f0f75a31e6d6', '～てごらん', NULL, 'N3', '动词「て形」＋ごらん', '动词「て形」＋ごらん', '“请……试试”。表示说话人让对方尝试做某件事情。', '「ご覧」是「見ること」的敬语。「～てごらん」相当于「～てみなさい」。', 433, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('d37a4a63-b64c-47e5-b275-ee5d2fef851f', '797c9f54-51a5-4a59-a742-f0f75a31e6d6', 'これ、食べてごらん。おいしいよ。', 'これ、たべてごらん。おいしいよ。', '吃吃看这个。很好吃哦。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('b004a38c-8108-4edc-b334-73a63892cb24', '797c9f54-51a5-4a59-a742-f0f75a31e6d6', 'もう一度やってごらん。', 'もういちどやってごらん。', '你再做一次试试看。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('1dca6120-dd26-4834-a118-e129ef1c4bbb', '～てしかた（が）ない/てしようがない/てしょうがない', NULL, 'N3', '～てしかた（が）ない/てしようがない/てしょうがない', '～てしかた（が）ない/てしようがない/てしょうがない', '“……得不得了”“非常……”。', '用于表达说话人的某种感情、感觉。主语是第三人称时，要在句末加上「～らしい/そうだ/ようだ」等。', 434, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('e91551d4-af1a-4870-851a-12302c6a38a1', '1dca6120-dd26-4834-a118-e129ef1c4bbb', '友達の中には、仕事が休みの日はすることがなくて、暇でしょうがないと言う人もいる。', 'ともだちのなかには、しごとがやすみのひはすることがなくて、ひまいう人もいる。', '朋友当中，有人说休息天没有工作要做，闲得发慌。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('05f511bb-8980-4095-a4a4-45c8691b2e0d', '1dca6120-dd26-4834-a118-e129ef1c4bbb', '夕べ徹夜したので、眠くてしょうがない。', 'ゆうべてつやしたので、ねむくてしょうがない。', '昨晚熬夜了，所以困得不得了。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('819876fa-6169-4a29-b291-f0116a26b3bb', '1dca6120-dd26-4834-a118-e129ef1c4bbb', '試合の最後の3分で相手に逆転された。残念でしかたがない。', 'しあいのさいごの3ぷんであいてにぎゃくてんされた。ざんねんでしかたがない。', '在比赛最后三分钟输给了对手，实在是遗憾呀！', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('5b965074-ebf8-48d3-a9fc-4479778fedce', '～て 済[す]む/で 済[す]む', NULL, 'N3', '～て 済[す]む/で 済[す]む', '～て 済[す]む/で 済[す]む', '“……就解决了”“……就好办了”。', '该句型的否定形式为「～て 済[す]むことではない」。', 435, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('98bfb946-3909-4b2e-878b-d382bb4807a3', '5b965074-ebf8-48d3-a9fc-4479778fedce', 'これは謝って済む問題ではない。', 'これはあやますもんだいではない。', '这不是道歉就能解决的问题。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('f9fdb05c-92ac-43a2-9a38-e2792af698fb', '5b965074-ebf8-48d3-a9fc-4479778fedce', '薬で済む病気だから、入院する必要はない。', 'くすりすびょうきだから、にゅういんするひつようはない。', '这病吃药就能治好，用不着住院。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('7e51450d-cf74-44aa-a5af-79a4348ec17f', '5b965074-ebf8-48d3-a9fc-4479778fedce', '大事な書類をなくしてしまったなんて、謝って済むことではない。', 'だいじなしょるいをなくしてしまったなんて、あやますむことではない。', '把那么重要的文件弄丢了，光是说声对不起是解决不了的。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('b6536a13-34da-4bb1-8614-e71426eb0c9c', '～てたまらない', NULL, 'N3', '～てたまらない', '～てたまらない', '“……得不得了”“非常……”。表示说话人强烈的感情、感觉、欲望等。', '「～たまらない」源于动词「 堪[たま]る（忍受）」的否定形式。', 436, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('76892a30-18f9-4354-8157-0799e4afaf28', 'b6536a13-34da-4bb1-8614-e71426eb0c9c', '私は3年も国へ帰っていないので、早く家族に会いたくてたまらない。', 'わたしは3ねんもくにへかえっていないので、はやくかぞくにあいたくてたまらない。', '我已经三年没有回家了，非常想早点见到家人。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('8aae9cf2-9979-4f86-a86f-e030207fe1f5', 'b6536a13-34da-4bb1-8614-e71426eb0c9c', '昨日の歌の練習では何度も間違えてみんなに笑われ、恥ずかしくてたまらなかった。', 'きのうのうたのれんしゅうではなんどもまちがえてみんなにわらわれ、はずかしくてたまらなかった。', '昨天在练习唱歌的时候，我好几次都唱错，因此被大家取笑，别提有多难为情了。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('ed8f9a24-8313-483a-80b4-5e8ed825fce0', '～てならない', NULL, 'N3', '～てならない', '～てならない', '“……得不得了”；“不由得……”。表示情不自禁地产生某种感情或感觉，连自己都控制不了。', '一般前接表示情感、感觉、欲望等方面的词语，如「 寂[さび]しい/ 悔[くや]しい」等。', 437, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('e8698b19-aa9d-47a8-8137-b1a32069f804', 'ed8f9a24-8313-483a-80b4-5e8ed825fce0', '学校を休んでいる友だちに何度も電話をしたが通じない。何かあったのか、心配でならない。', 'がっこうをやすんでいるともだちになんどもでんわをしたがつうじない。なにかあったのか、しんぱいでならない。', '给没来上课的朋友打了好几次电话都打不通。我不由得担心，他是不是出什么事情了。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('217ec0a2-cc75-439d-81a4-e8a8f3160af8', 'ed8f9a24-8313-483a-80b4-5e8ed825fce0', '世界中を旅行して回れるなんて、羨ましくてならない。', 'せかいじゅうをりょこうしてまわれるなんて、うらやましくてならない。', '能够周游全世界，真是让我羡慕得不得了。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('ff758520-c7af-493f-90d0-004339537624', '～ては', NULL, 'N3', '动词「て形」＋は', '动词「て形」＋は', '“一……就……”。\n“如果……的话”。', '表示动作的反复。\n后项一般是不好的结果。', 438, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('60606df1-2187-4f41-852c-7486ce47a9e8', 'ff758520-c7af-493f-90d0-004339537624', '息子は小学生の頃、よくお腹が痛いといっては学校を休んでいた。', 'むすこはしょうがくせいのころ、よくおなかがいたがっこうをやすんでいた。', '儿子上小学的时候，经常说肚子疼，然后请假不去学校。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('32f8bfae-51d4-4d78-a086-5965e0e463cf', 'ff758520-c7af-493f-90d0-004339537624', '彼は本屋へ行っては本をたくさん買ってくる。', 'かれはほんやへいほんをたくさんかってくる。', '他一到书店就会买很多书。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('8ce6aadd-07dd-471e-bd24-85cff514cfa9', 'ff758520-c7af-493f-90d0-004339537624', 'そんな暗い部屋で本を読んでいては目が悪くなるから、電気をつけなさい。', 'そんなくらいへやでほんをよめがわるくなるから、でんきをつけなさい。', '在那么暗的屋子里看书的话，对眼睛不好。把灯打开吧。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('1559dd33-ca3a-4d69-8af6-61c146bc6583', 'ff758520-c7af-493f-90d0-004339537624', '本やインターネットの資料を写しただけではレポートを書いたことにはならない。', 'ほんやインターネットのしりょうをうつしただけではレポートをかいたことにはならない。', '如果光是抄袭书本或网上资料的话，不能算是写报告。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('22393778-b4f0-46d0-a438-a1b5b5d0b7e6', '～ではないか', NULL, 'N3', '～ではないか', '～ではないか', '“不是……吗？”。表示征求对方同意、反问或惊讶。', '「～じゃないか」是「～ではないか」的口语表现。', 439, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('6b693945-4a90-41ad-96b3-947b5f9317dc', '22393778-b4f0-46d0-a438-a1b5b5d0b7e6', 'ほら、できるではないか。', 'ほら、できるではないか。', '瞧，你不是行的吗？', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('4741993f-2f87-4c91-ad71-223ddb6b51b2', '22393778-b4f0-46d0-a438-a1b5b5d0b7e6', 'A「遅かったではないか。」B「あの、道が込んでいたんです。」', 'A「おそかったではないか。」B「あの、みちがこんでいたんです。」', 'A：“怎么这么晚啊。”\nB：“因为路太堵了。”', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('4486dcd7-e695-4a69-82d8-ff54f9a3fc5e', '～（の）ではないか', NULL, 'N3', '～（の）ではないか', '～（の）ではないか', '“是不是……吗”“恐怕……吧”“或许……吧”。表示说话人的推测、判断、主张。', '更礼貌的说法是「～（の）ではないでしょうか」。口语中可以说「～（ん）じゃないか」，如第三个例文。', 440, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('2b4b05ee-0759-410d-bbaa-f1c9f53ab5ca', '4486dcd7-e695-4a69-82d8-ff54f9a3fc5e', 'このままでは病気はひどくなるのではないか。', 'このままではびょうきはひどくなるのではないか。', '这样下去，病恐怕会变重的吧。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('66c2eb36-a177-4418-a42b-de0c0961edb5', '4486dcd7-e695-4a69-82d8-ff54f9a3fc5e', '彼一人でこの仕事を終わらせるのは無理ではないかと思います。', 'かれひとりでこのしごとをおわらせるのはむりではないかとおもいます。', '我觉得他一个人完成这项工作有些难呢。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('98a1d75e-ff1f-4e96-a4cc-ef2efacc0955', '4486dcd7-e695-4a69-82d8-ff54f9a3fc5e', '田中さんはうれしそうな顔をしている。なんかいいことがあったんじゃないか。', 'たなかさんはうれしそうなかおをしている。なんかいいことがあったんじゃないか。', '田中看起来很高兴。是不是发生什么好事情了呀？', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('74aee80e-07ed-4294-bba2-5e6d6400390c', '～てはならない', NULL, 'N3', '动词「て形」＋はならない', '动词「て形」＋はならない', '“不能……”“不可以……”，表示禁止、训诫。', '注意该句型和「～てならない」句型的区别。', 441, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('93c85005-ebbb-4b08-a863-a1ff9562989c', '74aee80e-07ed-4294-bba2-5e6d6400390c', 'そんな小さなことで自分の人生を諦めてはならない。', 'そんなちいさなことでじぶんのじんせいをあきらめてはならない。', '不能因为这一点小事就放弃自己的人生。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('612b9a15-0f8d-47a8-aec7-7fe4459820f5', '74aee80e-07ed-4294-bba2-5e6d6400390c', '既に決まったことを勝手に変えてはならない。', 'すでにきまったことをかってにかえてはならない。', '已经定好的事情不能随意更改。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('4bcc9de8-b732-4654-8e25-a633b58d972b', '～てほしい', NULL, 'N3', '人物名词＋に＋动词「て形」＋ほしい', '人物名词＋に＋动词「て形」＋ほしい\n人物名词＋に＋动词「ない形」＋で＋ほしい\n~が动词「て形」＋ほしい', '“希望……”，表示对对方或他人的希望或要求。\n“希望……”，表示对出现某种事态的期待。', '相当于「～てもらいたい」，希望的动作对象用助词「に」表示。\n希望的对象用助词「が」表示。', 442, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('f467cc43-f44b-454a-8910-ef671b1e59e9', '4bcc9de8-b732-4654-8e25-a633b58d972b', 'A「今度のさよならパーティーで、みんなで歌う歌は、これでいいですか。」B「すみません。この歌は好きなんですが、少し難しいですからほかのにしてほしいです。」', 'A「こんどのさよならパーティーで、みんなでうたううたは、これでいいですか。」B「すみません。このうたはすきなんですが、すこしむずかしいですからほかのにしてほしいです。」', 'A：“这次告别派对上大家合唱的曲目就选这首可以吗？”\nB：“不好意思。这首歌我虽然喜欢，但是有些难，我希望可以换成其他的。”', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('383d694f-6756-4b46-ab6a-3fd09f63018b', '4bcc9de8-b732-4654-8e25-a633b58d972b', 'わたしの気持ちは、きっとあなたにわからないだろうし、あなたにわかってほしくもない。', 'わたしのきもちは、きっとあなたにわからないだろうし、あなたにわかってほしくもない。', '我的心情，你肯定不明白，而且我也不想让你明白。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('180573a5-f1fa-4900-bec9-293bd99c618c', '4bcc9de8-b732-4654-8e25-a633b58d972b', 'お正月が早く来てほしい。', 'おしょうがつがはやくきてほしい。', '希望新年快点到来。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('941a8eec-55be-4504-a431-6e4924cd2361', '4bcc9de8-b732-4654-8e25-a633b58d972b', 'イベントが無事に終わってほしい。', 'イベントがぶじにおわってほしい。', '希望活动顺利结束。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('dbf9e7c5-b304-4871-9731-c4c20feda552', '～てみせる', NULL, 'N3', '动词「て形」＋みせる', '动词「て形」＋みせる', '“做给……看”；“一定要……”。', '表示做某动作给对方看或表示决心、意志。', 443, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('f85c281e-dd18-4b28-b41f-414cfca03c39', 'dbf9e7c5-b304-4871-9731-c4c20feda552', '彼はみんなの前で歌ってみせた。', 'かれはみんなのまえでうたってみせた。', '他在大家面前一展歌喉。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('2519c7c8-7493-4a59-b8a3-dcc8331df87b', 'dbf9e7c5-b304-4871-9731-c4c20feda552', '今度こそ、絶対試験に合格してみせる。', 'こんどこそ、ぜったいしけんにごうかくしてみせる。', '这次，我绝对会考上的。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('040028b4-c3e0-45d5-902c-2d6177522244', '～てもしかたがない/てもしようがない', NULL, 'N3', '～てもしかたがない/てもしようがない', '～てもしかたがない/てもしようがない', '“即使……也没用”“即使……也无可奈何”。', '表示“即使……也无济于事”，在口语中「～ても」常用「～たって」代替。要注意的是句型中没有「も」的「～てしかた（が）ない/てしようがない」表示程度，意思为“非常……”。', 444, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('cc2d188b-6468-4ab4-8f74-8ff8dfc1102f', '040028b4-c3e0-45d5-902c-2d6177522244', '今更文句を言ってもしかたがない。', 'いまさらもんくをいってもしかたがない。', '事到如今，发牢骚也无济于事。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('97235c42-2bde-4601-87a5-3a86c35dd4fc', '040028b4-c3e0-45d5-902c-2d6177522244', 'このところ雨ばかりだから、お客が少なくてもしかたがない。', 'このところあめばかりだから、おきゃくがすくなくてもしかたがない。', '最近总是下雨，客人少也无可奈何。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('e53c5ca3-5084-49f3-816c-670126aac1e3', '040028b4-c3e0-45d5-902c-2d6177522244', '後悔したってしかたがない。', 'こうかいしたってしかたがない。', '即使后悔也无济于事。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('24e5306a-68a3-4982-835b-5048667a9698', '～てやってくれないか', NULL, 'N3', '动词「て形」＋やってくれないか', '动词「て形」＋やってくれないか', '“可否给……做……”，请求对方为第三者做某事。第三者用“に”表示。', NULL, 445, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('f356e333-862c-4ea2-8dc3-71d4a2946d1e', '24e5306a-68a3-4982-835b-5048667a9698', '娘に英語を教えてやってくれないか。', 'むすめにえいごをおしえてやってくれないか。', '可否请你教我女儿学英语？', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('75d4effc-6a57-41f4-a5f6-671926c701c7', '24e5306a-68a3-4982-835b-5048667a9698', '渡辺君、この資料を佐藤君に渡してやってくれないか。', 'わたなべくん、このしりょうをさとうくんにわたしてやってくれないか。', '渡边，你能不能帮我把这份资料交给佐藤？', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('9ea14202-a91f-4b64-9aee-6a41f6081524', '～てよかった/なくてよかった', NULL, 'N3', '动词「て形」＋よかった', '动词「て形」＋よかった\n动词「ない形」＋なくてよかった', '“太好了……”；“没有做……太好了”。表示事情结束后的评价。', '「よかった」是「いい」的过去时，但是表达的是说话人现在的心情。', 446, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('c3939c3a-35eb-49b4-b148-2a1c477e6cac', '9ea14202-a91f-4b64-9aee-6a41f6081524', '先輩の話を聞いてよかった。', 'せんぱいのはなしをきいてよかった。', '幸好听了前辈的话。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('d1dc9e0e-d2c8-4180-bbf6-c2762d279689', '9ea14202-a91f-4b64-9aee-6a41f6081524', '午後になって雨が降り出した。傘を持ってきてよかった。', 'ごごになってあめがふりだした。かさをもってきてよかった。', '下午下起雨来了，幸亏我带了伞。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('2b3d13af-3dfe-4502-ac10-e623df768aab', '9ea14202-a91f-4b64-9aee-6a41f6081524', '怖い思いをしたが、取りあえず死ななくてよかった。', 'こわいおもいをしたが、とりあえずしななくてよかった。', '虽然很害怕，但是好在没死。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('781f44ad-48a6-4b61-bc2f-02d37d70f896', '～ということだ', NULL, 'N3', '～によると/の 話[はなし]では＋句子的普通形＋ということだ', '～によると/の 話[はなし]では＋句子的普通形＋ということだ\n名词/动词普通形＋ということだ', '“听说……”“据说……”，表示传闻。\n“也就是说……”。表示就某种情况加以解释、推测或者得出的某种结论。', '相当于传闻助动词「～そうだ」，但是「～ということだ」表示直接引用的语感很强。另外有时以「～ということだった」表示过去时态。会话中也可以使用「～とのことだ/～んだって」。\n常与「～ということは/つまり～ということだ」呼应使用。与「～という 意[い] 味[み]だ/～（という）ことになる」意思相同。', 447, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('bc87bf83-f531-4174-ae7e-22612a1bf7d5', '781f44ad-48a6-4b61-bc2f-02d37d70f896', 'コーチの話では、彼が試合に出れば、優勝は間違いないということだ。', 'コーチのはなしでは、かれがしあいにでれば、ゆうしょうはまちがいないということだ。', '据教练说，如果他参加比赛的话，一定能拿冠军。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('3f87dc24-61bf-4802-b4d5-ef349998953d', '781f44ad-48a6-4b61-bc2f-02d37d70f896', '天気予報によると、明日は雨が降るということだ。', 'てんきよほうによると、あしたはあめがふるということだ。', '据天气预报说，明天会下雨。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('026079b5-a6f3-4332-b976-3742ffc9710a', '781f44ad-48a6-4b61-bc2f-02d37d70f896', '鈴木さんは行けないだろうということだった。', 'すずきさんはいけないだろうということだった。', '听说铃木大概不能去了。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('e34ab0ff-bb47-424d-8b7c-01fa3e087e0c', '781f44ad-48a6-4b61-bc2f-02d37d70f896', '明日から会社に来なくてもいい。つまり君はクビということだ。', 'あしたからかいしゃにこなくてもいい。つまりきみはクビということだ。', '从明天开始你不用来公司了。也就是说你被解雇了。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('24d42ee8-483f-42b6-86eb-4e0d4cdbe499', '781f44ad-48a6-4b61-bc2f-02d37d70f896', '手紙が戻ってきたということは、彼女はもうこの住所にいないということだ。', 'てがみがもどってきたということは、かのじょはもうこのじゅうしょにいないということだ。', '信退回来了，也就是说她已经不住那里了。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('b5521b2a-cbcc-4f9c-876e-9e22d3fb7bee', '781f44ad-48a6-4b61-bc2f-02d37d70f896', '彼女はまだ来ていませんか。つまり、また遅刻ということだ。', 'かのじょはまだきていませんか。つまり、またちこくということだ。', '她还没来吗？也就是说她又迟到了。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('1a9a2f0b-e60b-4966-a0b3-2ef264699387', '～というと/といえば/といったら', NULL, 'N3', '名词＋というと/といえば', '名词＋というと/といえば\n名词＋というと\n名词＋といったら', '“说起……”“谈到……”。表示提出话题，即提到某事马上就联想到别的事物。\n“你说的……（就是……吧）”。\n“要说……”“说起……”。', '「 何[なに]かと 言[い]えば/ 何[なに]かと 言[い]うと」是固定用法，表示“一开口就……”。\n表示借对方的话题，进一步进行确认。\n用于提出话题，表达说话人感动、惊讶等心情。', 448, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('da5298a9-7fa0-4acd-a9ea-28c4e32c91ac', '1a9a2f0b-e60b-4966-a0b3-2ef264699387', '日本といえば、わたしは桜を連想します。', 'にほんといえば、わたしはさくらをれんそうします。', '说起日本，我就想到樱花。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('a49df00a-7be6-4e0b-b23b-e504db7fe871', '1a9a2f0b-e60b-4966-a0b3-2ef264699387', '田中さんといえば、卒業以来、会っていないなあ。', 'たなかさんといえば、そつぎょういらい、あっていないなあ。', '说起田中，毕业之后就再也没有见过他。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('4a00a308-1934-49b4-9dd0-7838c6f036dc', '1a9a2f0b-e60b-4966-a0b3-2ef264699387', 'A「先週、小林さんに会いました。」B「小林さんというと、アメリカに行ったあの人ですか。」', 'A「せんしゅう、こばやしさんにあいました。」B「こばやしさんというと、アメリカにいったあのひとですか。」', 'A：“上周，我遇见小林了。”\nB：“你说的小林，就是去了美国的那个人吧。”', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('76b56302-398e-4dbc-9cba-92803841fcc9', '1a9a2f0b-e60b-4966-a0b3-2ef264699387', '桜の美しさといったら、とても言葉では表現できないほどです。', 'さくらのうつくしさといったら、とてもことばではひょうげんできないほどです。', '说起樱花的美丽，是无法用言语形容的。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('f84da6a3-8bfe-4765-8a7f-080988d45c6a', '1a9a2f0b-e60b-4966-a0b3-2ef264699387', '隣の娘といったら、たいしたものです。', 'となりのむすめといったら、たいしたものです。', '说起邻居家的女孩，那真是了不起啊。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('c7d2f527-f1b4-4cc3-acd9-c725adf32a59', '1a9a2f0b-e60b-4966-a0b3-2ef264699387', 'うちの妻は何かと言うと、すぐ文句だ。', 'うちのつまなにいうと、すぐもんくだ。', '我妻子一开口就发牢骚。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('eaaaf277-20c7-467e-b024-5ab177c1762b', '～というのは/とは', NULL, 'N3', '名词＋というのは/とは', '名词＋というのは/とは\nというのは～からだ/のだ', '“所谓的……”。\n“……是因为……”，表示原因。', '表示对事物的定义。\n和「なぜなら～からだ」意思相同，但是「というのは～からだ/のだ」多用于口语，「なぜなら～からだ」一般用于书面语。', 449, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('dd55afd9-747b-46b5-a320-6133d89c12ba', 'eaaaf277-20c7-467e-b024-5ab177c1762b', '「下水」というのは、台所などで使った汚れた水のことである。', '「げすい」というのは、だいどころなどでつかったよごれたみずのことである。', '所谓的污水就是指厨房等排出的脏水。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('46c5b088-ae96-42eb-9e62-63a99bd4cb32', 'eaaaf277-20c7-467e-b024-5ab177c1762b', '東大とは東京大学のことだ。', 'とうだいとうきょうだいがくのことだ。', '所谓的东大，就是指东京大学。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('5f644d23-3e2f-4426-a3b9-184c0141af73', 'eaaaf277-20c7-467e-b024-5ab177c1762b', '残念ですが、明日のパーティーは参加できません。というのは、急に出張することになったんです。', 'ざんねんですが、あしたのパーティーはさんかできません。というのは、きゅうにしゅっちょうすることになったんです。', '很遗憾，我不能参加明天的宴会了，因为公司突然派我去出差。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('0329fc90-5c97-45e5-9624-278cdab1c42b', 'eaaaf277-20c7-467e-b024-5ab177c1762b', '今年の夏休みは旅行どころではなかった。というのは、父が病気で入院してしまったからだ。', 'ことしのなつやすみはりょこうどころではなかった。というのは、ちちがびょうきでにゅういんしてしまったからだ。', '今年暑假根本谈不上去旅行，因为父亲生病住院了。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('0e3d7875-50b5-4beb-9f83-5b9d0f2067c6', '～というほどではない/というほどでもない', NULL, 'N3', '～というほどではない/というほどでもない', '～というほどではない/というほどでもない', '“并没有达到……程度”。', '表示程度并非那么高。', 450, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('34071761-42b6-4229-ae7c-69ec5083178c', '0e3d7875-50b5-4beb-9f83-5b9d0f2067c6', '日本語はできるが、会議の通訳が務まるというほどではない。', 'にほんごはできるが、かいぎのつうやくがつとまるというほどではない。', '日语会是会，不过还没到能担当会议口译的水平。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('27933bd5-45e5-4c08-889d-13b9153b10b9', '0e3d7875-50b5-4beb-9f83-5b9d0f2067c6', 'ちょっと辛いが、食べられないというほどでもない。', 'ちょっとからいが、たべられないというほどでもない。', '虽然有些辣，不过没有到不能吃的地步。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('b2f06ce0-19a3-4ed3-9638-eb19824c51b1', '～というものは', NULL, 'N3', '名词＋というものは', '名词＋というものは', '“……这种东西”，表示一般性的叙述。', '「～というものは」一般用于普遍真理、公认的事实等。', 451, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('55221cbb-0283-4526-9c69-49c71631919c', 'b2f06ce0-19a3-4ed3-9638-eb19824c51b1', '戦争というものは、残酷なものです。', 'せんそうというものは、ざんこくなものです。', '战争是非常残酷的。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('7440c530-8808-408d-8ef2-6545e7778915', 'b2f06ce0-19a3-4ed3-9638-eb19824c51b1', '薬というものは、間違って飲むと大変なことになる。', 'くすりというものは、まちがってのむとたいへんなことになる。', '药如果吃错了就麻烦了。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('f38239f1-cd59-4ab9-831b-abf1d2800f0c', '～（や）～といった', NULL, 'N3', '（名词＋や＋）名词＋といった', '（名词＋や＋）名词＋といった', '“……这样的……”，表示举例。', '前面常和助词「～や」呼应使用，和「～や～など/～ような」意思相近。', 452, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('e0218721-7b4c-4a6d-9372-72f2af55324b', 'f38239f1-cd59-4ab9-831b-abf1d2800f0c', 'この人形は、「こんにちは」「さようなら」といった簡単な言葉を話します。', 'このにんぎょうかんたんなことばをはなします。', '这个人偶会讲“你好”“再见”之类简单的话。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('3a6502a2-ddb3-490e-95d0-c19274eb35c4', 'f38239f1-cd59-4ab9-831b-abf1d2800f0c', 'この会社はタオルや洗剤といった様々な日用品を扱っている。', 'このかいしゃせんざいさまざまなにちようひんをあつかっている。', '这家公司经营毛巾、洗涤剂等各种各样的日用品。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('894ec290-7890-4a06-9130-a87f25587025', '～といっても', NULL, 'N3', '～といっても', '～といっても', '“虽说……但是……”，表示转折。「といっても」可以直接作为接续词使用。', '即对前项叙述的内容，后项补充说明实际还达不到该程度。', 453, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('89afd045-6cf9-4a20-9380-601ecd2cf9f9', '894ec290-7890-4a06-9130-a87f25587025', 'A「4月から外国語の学校に通ってるの。」B「へえ、頑張ってるね。」A「といっても、週に1回だけだけど。」', 'A「4がつからがいこくごのがっこうにかよってるの。」B「へえ、がんばってるね。」A「といっても、しゅうに1かいだけだけど。」', 'A：“我从四月份开始在外语学校上学。”\nB：“啊，你真用功啊。”\nA：“虽说如此，也只不过是一周上一次课而已。”', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('5f6561d5-6fa2-4c3e-8a38-ffdeccc1d79f', '894ec290-7890-4a06-9130-a87f25587025', '女優といっても、有名ではありません。', 'じょゆうといっても、ゆうめいではありません。', '她虽然是演员，但没什么名气。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('24e27547-8952-4709-be55-0a6dc3d682b2', '894ec290-7890-4a06-9130-a87f25587025', 'プールで泳いだといっても、数メートルだけです。', 'プールでおよいだといっても、すうメートルだけです。', '尽管说在游泳池里游泳了，也不过是游几米而已。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('0c20e0c4-75d7-4f44-9551-930994a3e34b', '～とおり（に）/とおりの/どおり（に）/どおりの', NULL, 'N3', '动词辞书形·「た形」＋とおり（に）/とおりの', '动词辞书形·「た形」＋とおり（に）/とおりの\n名词＋の＋とおり（に）/とおりの\n名词＋どおり（に）/どおりの', '“如……那样”“按照……”。', '「～とおりの」后续名词作定语使用，注意前面直接接名词时只能用「～どおり（に/の）」的形式。', 454, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('a6cb4853-9def-44e7-9b27-53181f51a6f3', '0c20e0c4-75d7-4f44-9551-930994a3e34b', 'これからわたしが言うとおりにパソコンを操作してください。', 'これからわたしがいうとおりにパソコンをそうさしてください。', '接下来请按照我所说的来操作电脑。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('2d63e2da-04e5-45b6-86eb-cd0bdb388eb9', '0c20e0c4-75d7-4f44-9551-930994a3e34b', '説明書どおりに組み立ててみたのですが、動かないんです。', 'せつめいしょくみたててみたのですが、うごかないんです。', '我按照说明书去组装的，但是（机器）不能启动。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('0b6c43d6-b8d3-440a-a595-83b5c4b3509f', '0c20e0c4-75d7-4f44-9551-930994a3e34b', 'おっしゃるとおりです。', 'おっしゃるとおりです。', '您所言极是。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('59e772ed-3fb2-4c6c-be03-bd0826f50071', '～とされている', NULL, 'N3', '句子普通形＋とされている', '句子普通形＋とされている', '“被视为……”“人们认为……”。表示对于事情或结果的推断，多用于书面语。', '相当于「～と 見[み]られている」。', 455, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('cbe2d424-bf4b-4534-badd-a98a7dd22db5', '59e772ed-3fb2-4c6c-be03-bd0826f50071', '今の時代では定期的な知識の更新が必要だとされている。', 'いまのじだいではていきてきなちしきのこうしんがひつようだとされている。', '在如今这个时代，人们认为定期进行知识的更新是有必要的。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('28000b68-614a-486d-a47f-72dc88f6eba6', '59e772ed-3fb2-4c6c-be03-bd0826f50071', '当時、漫画は低俗文化の一種だとされていた。', 'とうじ、まんがはていぞくぶんかのいっしゅだとされていた。', '当时，漫画被视为低俗文化的一种。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('241f570e-9b91-4e6a-8332-686da7eae627', '～として/としての/としても', NULL, 'N3', '名词＋として/としての/としても', '名词＋として/としての/としても\n句子的普通形＋としても', '“作为……”“作为……也……”，表示某种身份、资格或立场等。\n“即使……也……”，表示假定或确定的逆接条件。', '「～としての」后续名词作定语使用。\n表示假定或确定的逆接条件，后项多是消极的或否定的内容。', 456, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('832ed39c-5453-4ae9-ab9d-5b60e09f7826', '241f570e-9b91-4e6a-8332-686da7eae627', '来週、社長が日本に出張するので、わたしも通訳として一緒に行きます。', 'らいしゅう、しゃちょうがにほんにしゅっちょうするので、わたしもつうやくいっしょにいきます。', '下周，社长要去日本出差，我也作为翻译同行。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('bbe90dfb-8f55-44ad-8fed-e78c0550c02f', '241f570e-9b91-4e6a-8332-686da7eae627', '参加者に連絡のメールを送るのは幹事としての仕事だ。', 'さんかしゃにれんらくのメールをおくるのはかんじしごとだ。', '给参加人员发通知邮件是作为干事的工作。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('94a9c02e-fb80-49d0-90db-9cd5325d49d8', '241f570e-9b91-4e6a-8332-686da7eae627', '山田さんは詩人としても有名です。', 'やまださんはしじんゆうめいです。', '山田作为诗人也很有名。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('381b9c73-3867-4972-8b31-d7bb8b00b264', '241f570e-9b91-4e6a-8332-686da7eae627', '明日、もし雨が降ったとしても、予定されているスポーツ大会は行います。', 'あした、もしあめがふったとしても、よていされているスポーツたいかいはおこないます。', '明天即使下雨，计划好的运动会也会举行。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('d0baa4cc-57ea-491e-a1a6-4c060ee99ed1', '241f570e-9b91-4e6a-8332-686da7eae627', 'たとえ不合格だとしても、君の今までの努力は無駄ではないよ。', 'たとえふごうかくだとしても、きみのいままでのどりょくはむだではないよ。', '即使不及格，你之前的努力也不是白费的。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('c1bb3979-fb48-4b18-99c2-4b19e29e6f83', '～と（は） 反[はん] 対[たい]に', NULL, 'N3', '～と（は） 反[はん] 対[たい]に', '～と（は） 反[はん] 対[たい]に', '“与……相反”。', '用于比较两个对照性的事物。「それとは 反[はん] 対[たい]に」可以作为接续词使用。', 457, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('01e32859-2615-476b-8830-4175e9f2e823', 'c1bb3979-fb48-4b18-99c2-4b19e29e6f83', '投資家の予想とは反対に、株価は下がっている。', 'とうしかのよそうはんたいに、かぶかはさがっている。', '与投资家们的预料相反，股票价格正在下跌。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('8e02a9b7-bd3e-4f99-92a0-539d05d7af1a', 'c1bb3979-fb48-4b18-99c2-4b19e29e6f83', '姉は勤勉なのと反対に、妹は遊び好きだ。', 'あねはきんべんはんたいに、いもうとはあそびずきだ。', '姐姐非常勤奋，而妹妹喜欢玩。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('24d53333-cdc2-46a4-89ea-c6904690c566', 'c1bb3979-fb48-4b18-99c2-4b19e29e6f83', '兄は文系が好きだ。それとは反対に、弟は理系が好きだ。', 'あにはぶんけいがすはんたいに、おとうとはりけいがすきだ。', '哥哥喜欢文科。与之相反，弟弟喜欢理科。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('a65584aa-c2ed-4a57-922f-431e0f65f4fe', '～ないかな', NULL, 'N3', '动词「ない形」＋ないかな', '动词「ない形」＋ないかな', '“多希望……啊”。', '前接表示动作、变化等动词的否定形，表示说话人的希望和愿望。女性委婉表达为「～ないかしら」。', 458, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('d7aa7316-6d06-43e3-8149-2b11360dc815', 'a65584aa-c2ed-4a57-922f-431e0f65f4fe', '社長のスピーチ、早く終わらないかな、いつも長くて困るよ。', 'しゃちょうのスピーチ、はやくおわらないかな、いつもながくてこまるよ。', '社长的演讲能不能早点结束啊。总是说个不停，真让人头疼。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('076466e8-17a6-4261-81eb-8a0e1353b013', 'a65584aa-c2ed-4a57-922f-431e0f65f4fe', '採用試験の結果を早く知らせてくれないかな。', 'さいようしけんのけっかをはやくしらせてくれないかな。', '真希望录用考试的结果早点公布。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('2421e1d6-f03a-4b4a-80e0-465bcae62014', '～ 直[な お]す', NULL, 'N3', '动词「ます形」＋ 直[なお]す', '动词「ます形」＋ 直[なお]す', '“重新……”。', '表示对前面的行为结果不满意，所以重新做一次。', 459, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('a1e7f1d3-d4be-404f-86c2-55a86f800e8b', '2421e1d6-f03a-4b4a-80e0-465bcae62014', '字が汚いので、書き直す。', 'じがきたないので、かなおす。', '因为字迹潦草，所以重写。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('e5fec67d-9bde-4cec-81cf-fd33e5f8090e', '2421e1d6-f03a-4b4a-80e0-465bcae62014', '何か別の方法はないか考え直してみよう。', 'なにかべつのほうほうはないかかんがなおしてみよう。', '再想想有没有其他的什么办法。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('2541e555-63a3-4efd-a031-27ef8df43e67', '2421e1d6-f03a-4b4a-80e0-465bcae62014', '提出する前にもう一度作文を見直した。', 'ていしゅつするまえにもういちどさくぶんをみなおした。', '在提交之前重新检查了一遍作文。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('e5e708ee-d2be-4522-91dd-352e91525fc8', 'なにしろ～から', NULL, 'N3', 'なにしろ＋句子的普通形·礼貌形＋から', 'なにしろ＋句子的普通形·礼貌形＋から', '“因为……”。', '多用此形式陈述理由。', 460, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('80ddd866-9fed-4373-a3f7-e092e0ba4bae', 'e5e708ee-d2be-4522-91dd-352e91525fc8', 'なにしろここは田舎だから、買い物には不便だ。', 'なにしろここは田いなかだから、かいものにはふべんだ。', '因为这里是农村，买东西不方便。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('0f2297f1-4a15-4e3a-a92a-2bd5ba16762c', 'e5e708ee-d2be-4522-91dd-352e91525fc8', 'なにしろ大きなミスだから、そう簡単には解決できそうもない。', 'おおきなミスだから、そうかんたんにはかいけつできそうもない。', '因为是个重大的过失，看样子不能那么轻易地解决。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('27e7d73b-6f63-46c3-a739-fb40569c756a', '～なんか/なんて', NULL, 'N3', '～なんか/なんて', '～なんか/なんて', '“……之类的”。表示列举。\n“……之类的，……什么的”。用于自己时，含有谦逊的语气；用于他人表示轻蔑。\n“竟然……”。表示惊讶或意外。\n用「名词＋なんて＋名词」的形式，表示例示。', '是「など」的口语形式。', 461, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('88fd6e81-a10f-4033-be85-6e328d749f3c', '27e7d73b-6f63-46c3-a739-fb40569c756a', 'これなんか似合うと思うよ。', 'にあうとおもうよ。', '我觉得这个挺适合你的。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('0c5c640a-3a4c-4c9e-bca4-8adfc0da77d7', '27e7d73b-6f63-46c3-a739-fb40569c756a', 'ドラマなんてめったに見ないよ。', 'ドラマなんてめったにみないよ。', '我平时很少看电视剧。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('cbed4436-bb6a-494a-849c-dd61da5d66f8', '27e7d73b-6f63-46c3-a739-fb40569c756a', '（デパートでシャツを選びながら）山田「明るい色のシャツが欲しいんだけど……。」田中「だったら、これなんかどう？山田さんにすごく似合うと思うよ。」', '（デパートでシャツをえらびながら）やまだ「あかるいいろのシャツがほしいんだけど……。」たなか「だったら、これなんかどう？やまださんにすごくにあうとおもうよ。」', '（在百货公司挑选衬衫）山田：“我想买件亮色的衬衫……”\n田中：“那么，这件怎么样？我觉得非常适合山田你呢。”', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('0e4f0372-7b8a-4a5c-9193-dfb1a7e194a1', '27e7d73b-6f63-46c3-a739-fb40569c756a', '君になんかわからない。', 'きみになんかわからない。', '你怎么会明白。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('ccf8ca62-dd2c-483e-9642-23bdf09ed974', '27e7d73b-6f63-46c3-a739-fb40569c756a', 'A「日本語お上手ですね。」B「いいえ、私なんかまだまだです。」', 'A「にほんごおじょうずですね。」B「いいえ、わたしなんかまだまだです。」', 'A：“你日语说得真好啊。”\nB：“哪里，我的日语还不行。”', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('a41b4391-e7ea-4180-8dd6-1d9531613355', '27e7d73b-6f63-46c3-a739-fb40569c756a', 'こんなところで先生に会うなんて、思ってもみなかった。', 'こんなところでせんせいにあうなんて、おもってもみなかった。', '真没想到竟然在这里遇见老师。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('d65ec69f-67e4-48d6-90b0-24b1ded2e5d3', '27e7d73b-6f63-46c3-a739-fb40569c756a', 'あの人が一番だなんて、驚いてしまった。', 'あのひとがいちばんだなんて、おどろいてしまった。', '那个人竟然考了第一名，真让人惊讶。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('c09e9796-fe6e-4de4-9477-737478442961', '27e7d73b-6f63-46c3-a739-fb40569c756a', '田中なんてやつは知らない。', 'たなかなんてやつはしらない。', '我不认识田中这个人。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('93bf7600-e3b3-4d31-8fec-2a78bc0097f0', '27e7d73b-6f63-46c3-a739-fb40569c756a', 'タバコなんてものは百害あって一利なしだ。', 'タバコなんてものはひゃくがいあっていちりなしだ。', '香烟这东西是有百害而无一利。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('099ccc03-1ef5-4697-becf-a0e193679cf1', '～において/における', NULL, 'N3', '名词＋において/における', '名词＋において/における', '“在……”“在……方面”，表示场合、时间、范围等意思。', '「～においての/における」后续名词作定语使用。表示时间时相当于「～に」，表示地点时相当于「～で」。一般用于书面语。', 462, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('92d532b9-42d3-48fc-94e9-61a697041426', '099ccc03-1ef5-4697-becf-a0e193679cf1', 'このメーカーのヘルメットは、安全性において、他のどのメーカーの製品よりも優れている。', 'このメーカーのヘルメットは、あんぜんせいにおいて、ほかのどのメーカーのせいひんよりもすぐれている。', '这个厂家生产的安全帽，在安全性方面，比其他任何一家的产品都要好。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('6e68b8d4-6856-45d7-a9a6-6718f9ca1861', '099ccc03-1ef5-4697-becf-a0e193679cf1', '当時においては、海外旅行など夢のようなことだった。', 'とうじにおいては、かいがいりょこうなどゆめのようなことだった。', '在当时，海外旅行什么的简直就像做梦一样。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('a6f0fb31-0999-4216-bdea-99e913d8fdb7', '099ccc03-1ef5-4697-becf-a0e193679cf1', '最近は職場だけでなく家庭においてもパソコンが使われている。', 'さいきんはしょくばだけでなくかていにおいてもパソコンがつかわれている。', '最近，不仅在职场，即使在家里也使用电脑了。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('e3273cc3-7d0e-4353-9942-cfc1e7114cc6', '099ccc03-1ef5-4697-becf-a0e193679cf1', 'ロンドンにおける国際会議が終わりました。', 'こくさいかいぎがおわりました。', '在伦敦举行的国际会议结束了。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('f80071cd-6f0b-43ac-b059-64f9e33686bc', '～にかわって/にかわり', NULL, 'N3', '名词＋にかわって/にかわり', '名词＋にかわって/にかわり', '“代替……”。', '表示代替前者做某事。类似于「名词＋の＋かわりに」。', 463, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('74c06251-cb6d-4796-899f-f2d13b949711', 'f80071cd-6f0b-43ac-b059-64f9e33686bc', '入院した先生にかわって、今は新しい先生が授業をしている。', 'にゅういんしたせんせいにかわって、いまはあたらしいせんせいがじゅぎょうをしている。', '老师住院了，所以现在由新老师代课。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('0a15171f-35ee-4614-a6e0-cc05401193ea', 'f80071cd-6f0b-43ac-b059-64f9e33686bc', '田中さんにかわり、中村さんがアメリカへ出張する。', 'たなかさんにかわり、なかむらさんがアメリカへしゅっちょうする。', '中村代替田中去美国出差。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('902adcd9-49d3-462b-beb1-f8f0d2f75799', '～に 関[かん]して（は）/に 関[かん]しても/に 関[かん]する', NULL, 'N3', '名词＋に 関[かん]して（は）/に 関[かん]しても/に 関[かん]する', '名词＋に 関[かん]して（は）/に 関[かん]しても/に 関[かん]する', '“关于……”“有关……”，表示事物和行为所涉及的对象。', '类似于「～について」，不过「～に 関[かん]して」的表达更为郑重，多用于书面语中。「～に 関[かん]する」后续名词作定语使用。', 464, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('75a34534-326c-4444-8d96-df849cd3c3ac', '902adcd9-49d3-462b-beb1-f8f0d2f75799', 'コンピューターの使い方に関して、質問がある方は、わたしのところまでどうぞ。', 'コンピューターのつかいかたかんして、しつもんがあるかたは、わたしのところまでどうぞ。', '有关电脑的使用方法，有问题的话，可以问我。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('edcbc101-db25-4a9f-ab58-092883af9e9e', '902adcd9-49d3-462b-beb1-f8f0d2f75799', '環境に関する諸問題を検討します。', 'かんきょうかんしょもんだいをけんとうします。', '讨论有关环境方面的问题。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('1f44a6e1-926f-4ab3-80e5-e2e0c0dd9c8a', '902adcd9-49d3-462b-beb1-f8f0d2f75799', 'その件に関してはまったく興味がない。', 'そのけんかんしてはまったくきょうみがない。', '我对那件事情一点兴趣都没有。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('2a21137a-95fc-4fff-952e-2b55977377b2', '～に 比[く ら]べ（て）/と 比[く ら]べ（て）', NULL, 'N3', '名词＋に 比[くら]べ（て）/と 比[くら]べ（て）', '名词＋に 比[くら]べ（て）/と 比[くら]べ（て）', '“和……相比”。表示比较。', '和「～と 比[ひ] 較[かく]して」意思相同。', 465, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('f55b1c03-2586-400b-9912-cc89acdca3be', '2a21137a-95fc-4fff-952e-2b55977377b2', '隣の町と比べて、私の住んでいる町は水道代が高い。', 'となりのまちくらべて、わたしのすんでいるまちはすいどうだいがたかい。', '和临近城市相比，我居住的这座城市水费比较贵。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('9c01de96-e5dd-4359-83aa-c5d3a84e1726', '2a21137a-95fc-4fff-952e-2b55977377b2', '今回発売されたパソコンは、今までのものに比べてかなり軽くなったので、持ち運びが楽だ。', 'こんかいはつばいされたパソコンは、いまくらべてかなりかるくなったので、もちはこびがらくだ。', '这次发售的电脑，比之前所有机型都轻得多，便于携带。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('138d82e7-ca6e-49c9-9290-139b74087c51', '2a21137a-95fc-4fff-952e-2b55977377b2', '今年の花火大会の観客数は去年と比べて10パーセント以上多い17万人だった。', 'ことしのはなびたいかいのかんきゃくすうはきょねんくらべて10パーセントいじょうおおい17まんにんだった。', '今年观赏烟火大会的游客数目，较去年增加了10％以上，为17万人次。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('9b5c323b-64b1-4246-aa42-1715d00825e7', '～にしろ～にしろ/～にせよ～にせよ/～にしても～にしても', NULL, 'N3', '～にしろ～にしろ/～にせよ～にせよ/～にしても～にしても', '～にしろ～にしろ/～にせよ～にせよ/～にしても～にしても', '“无论是……还是……都……”。', '举出具有相反和对立意义的两个事物，表示无论是哪种情况都无一例外。', 466, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('148106f7-2b62-4f41-b1fa-501262f62227', '9b5c323b-64b1-4246-aa42-1715d00825e7', '出席するにしろ欠席するにしろ、招待状の返事は早く出したほうがいい。', 'しゅっせきけっせきするにしろ、しょうたいじょうのへんじははやくだしたほうがいい。', '无论是参加还是不参加，最好尽快回信。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('bfea90cd-4136-4975-b36f-487eb59ae1fa', '9b5c323b-64b1-4246-aa42-1715d00825e7', '引き受けるにしろ引き受けないにしろ、なるべく早く決めたほうがいい。', 'ひきうひきうけないにしろ、なるべくはやくきめたほうがいい。', '无论是接受还是不接受，最好尽快作决定。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('2f8dc1f8-5e32-465c-a248-47a0394c2ce9', '9b5c323b-64b1-4246-aa42-1715d00825e7', '好きにしても、嫌いにしても、健康のため、毎日野菜を食べなければならない。', 'すきにしても、きらいにしても、けんこうのため、まいにちやさいをたべなければならない。', '无论喜不喜欢，为了健康，每天都必须吃蔬菜。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('3546c135-fb61-42ea-a9a8-ee69a1bd3349', '～に 対[たい]して/に 対[たい]する', NULL, 'N3', '名词＋に 対[たい]して/に 対[たい]する', '名词＋に 対[たい]して/に 対[たい]する\n名词＋に 対[たい]して', '“对……”。表示动作的对象。\n“每……”。\n“与……相反”；“而……”。表示对比。', '「～に 対[たい]する/に 対[たい]しての」后续名词作定语使用。\n表示数量的比例。', 467, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('88b77214-802f-4a52-ab0d-f49d16c66bf5', '3546c135-fb61-42ea-a9a8-ee69a1bd3349', '戦争に対して、批判の声が次第に高まっている。', 'せんそうたいして、ひはんのこえがしだいにたかまっている。', '反战的呼声逐渐高涨。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('0bd55647-a669-4a20-bb23-3b65b952002e', '3546c135-fb61-42ea-a9a8-ee69a1bd3349', '先日の会議では彼の説明に対して質問が集中した。', 'せんじつのかいぎではかれのせつめいたいしつもんがしゅうちゅうした。', '在上次的会议上，提问集中在他所做的说明上。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('6910ec08-526a-4d7b-ada3-3e0551f5f5bc', '3546c135-fb61-42ea-a9a8-ee69a1bd3349', '出席者一人に対して、資料を2部配る。', 'しゅっせきしゃひとりたいして、しりょうを2ぶくばる。', '对每一位出席的人发两份资料。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('ad430f6d-2860-42bd-a1de-92e454c5dccc', '3546c135-fb61-42ea-a9a8-ee69a1bd3349', '醤油3に対して酢1の割合で混ぜる。', 'しょうゆたいす1のわりあいでまぜる。', '把酱油和醋以三比一的比例混合。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('07be404a-e9ed-4a1c-85b6-87fe9ab7e0cb', '3546c135-fb61-42ea-a9a8-ee69a1bd3349', '地方では人口が減っているのに対して、都市部では人口が急激に増えている。', 'ちほうではじんこうがへたいして、としぶではじんこうがきゅうげきにふえている。', '地方的人口在减少，与之相对，城市的人口在急剧增加。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('88936885-7331-4529-8201-13928188e7d9', '3546c135-fb61-42ea-a9a8-ee69a1bd3349', '最近、沿海地区では雨が多いのに対して、内陸地区では干ばつが続いている。', 'さいきん、えんかいちくではあめがおおたいして、ないりくちくではかんばつがつづいている。', '最近，沿海地区多雨，而内陆地区却持续干旱。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('50c4fb84-1be6-47fb-b079-33741117df9e', '3546c135-fb61-42ea-a9a8-ee69a1bd3349', '姉の部屋はきれいなのに対して、妹の部屋は散らかっている。', 'あねのへやたいして、いもうとのへやはちらかっている。', '姐姐的房间很整洁，而妹妹的房间却很乱。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('96472e8c-e4ae-472d-b739-deb728b3fa6b', '～について/についての', NULL, 'N3', '名词＋について/についての', '名词＋について/についての', '“关于……”。', '「～についての」后续名词作定语使用。「～について」类似于「～に 関[かん]して」，但是「～について」更口语化。', 468, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('142dd038-4f0b-4ef0-82a5-0cefc85c351f', '96472e8c-e4ae-472d-b739-deb728b3fa6b', '『プレゼント』という映画を見て、この映画ほど人生について考えさせられる映画はないと思った。', '『プレゼント』というえいがをみて、このえいがほどじんせいかんがえさせられるえいがはないとおもった。', '看了叫作《礼物》的电影，我觉得没有什么电影比这部更能引起我对人生的思索了。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('65bcfdd3-3bca-40fb-8fa0-f666d3366426', '96472e8c-e4ae-472d-b739-deb728b3fa6b', '大学では日本文学史について研究したいと思っています。', 'だいがくではにほんぶんがくしけんきゅうしたいとおもっています。', '我想在大学研究日本文学史。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('7cfad4b6-4ab6-4b6c-b33b-cbe5a3146734', '96472e8c-e4ae-472d-b739-deb728b3fa6b', '業務改善についての勉強会を行った。', 'ぎょうむかいぜんべんきょうかいをおこなった。', '开了关于改善业务的学习会。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('6bbda1e4-486a-48ac-a476-c2c0d2101382', '～につれて/につれ', NULL, 'N3', '动词辞书形/名词＋につれて/につれ', '动词辞书形/名词＋につれて/につれ', '“随着……”。', '表示随着前项发生变化，后项也相应地发生变化。其中「～につれ」多用于书面语。', 469, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('01039be7-879c-4342-9038-ce454aac8a70', '6bbda1e4-486a-48ac-a476-c2c0d2101382', '農業技術が発達するにつれて、人々の暮らしは豊かになっていった。', 'のうぎょうぎじゅつがはったつするにつれて、ひとびとのくらしはゆたかになっていった。', '随着农业技术的发达，人们的生活变得富裕起来。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('d88215e9-f046-4149-974a-a320b1c2875d', '6bbda1e4-486a-48ac-a476-c2c0d2101382', '辺りが暗くなるにつれて、だんだん眠くなってきた。', 'あたりがくらくなるにつれて、だんだんねむくなってきた。', '随着夜幕降临，渐渐有了睡意。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('4898c035-9101-46af-8d41-1f66fdd48099', '6bbda1e4-486a-48ac-a476-c2c0d2101382', '原材料価格の上昇につれて、会社の経営は厳しくなってきた。', 'げんざいりょうかかくのじょうしょうにつれて、かいしゃのけいえいはきびしくなってきた。', '随着原材料价格的上涨，公司经营变得艰难起来。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('b0986b19-447b-49c7-8c7d-8695c235ce8a', '～にて', NULL, 'N3', '名词＋にて', '名词＋にて', '“在……”。\n“用……”“以……”。\n“于……”。', '表示事情发生的场所，主要用于郑重的书信等，是书面语。和表示动作进行场所的「～で」意思相同。\n表示工具、方法、材料、手段，是书面语，意思相当于「～で/～によって」。\n是书面语，表示结束的时间。', 470, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('0c3d9a84-9c03-4141-93de-654edd03421d', 'b0986b19-447b-49c7-8c7d-8695c235ce8a', '新人教育は本社にて行います。', 'しんじんきょういくはほんしゃおこないます。', '新员工培训在总部进行。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('e00f8cf8-e6f9-4f0e-9106-611022b45fd3', 'b0986b19-447b-49c7-8c7d-8695c235ce8a', 'キャンパスにてイベントを行う。', 'キャンパスにてイベントをおこなう。', '在校园内举行活动。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('79b2fb52-d32f-402e-a12e-725bb10e72de', 'b0986b19-447b-49c7-8c7d-8695c235ce8a', '飛行機にて香港へ行く。', 'ひこうきホンコンへいく。', '乘飞机去香港。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('f3a14b8f-064f-4be8-aebb-f68d33874ca1', 'b0986b19-447b-49c7-8c7d-8695c235ce8a', '面接の結果は書面にてお知らせいたします。', 'めんせつのけっかはしょめんにておしらせいたします。', '用书面形式通知面试的结果。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('c4dc844b-e029-4232-98d2-daa2e34eea27', 'b0986b19-447b-49c7-8c7d-8695c235ce8a', '本日は夜8時にて閉館します。', 'ほんじつはよる8じへいかんします。', '今晚八点闭馆。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('bcb24134-76d5-4c2f-8837-30c51c210273', 'b0986b19-447b-49c7-8c7d-8695c235ce8a', '本大会は本日にて終了します。', 'ほんたいかいはほんじつしゅうりょうします。', '本次大会到今天结束。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('ec1fb68e-00cc-4b89-82d1-d98504783578', '～にとって', NULL, 'N3', '名词＋にとって', '名词＋にとって', '“对……来说”，表示站在某立场来说。', '「～にとって」句型可以后续副助词「は」「も」来加强语气；「～にとっての」后续名词作定语使用。后项多为表示评价的形容词，如「 大[たい] 切[せつ]だ/ 重[じゅう] 要[よう]だ/ 難[むずか]しい/うれしい」等。', 471, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('98cb75c5-d371-41c8-89e7-f13f78201a31', 'ec1fb68e-00cc-4b89-82d1-d98504783578', 'ガソリンの値段が高くなった。毎日車を運転する私にとってこれは大きな問題だ。', 'ガソリンのねだんがたかくなった。まいにちくるまをうんてんするわたしにとってこれはおおきなもんだいだ。', '汽油涨价了。这对每天开车的我来说，是个大问题。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('e8c79133-4043-4447-93e1-b83712228198', 'ec1fb68e-00cc-4b89-82d1-d98504783578', 'わたしにとって、今一番大切なものは、飼っている犬です。', 'わたしにとって、いまいちばんたいせつなものは、かっているいぬです。', '对于我来说，现在最重要的东西，就是我养的狗。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('a463ec38-dab3-4ded-aac4-061d8d7a6866', 'ec1fb68e-00cc-4b89-82d1-d98504783578', '今回改正された法律は、ほとんどの国民にとってあまり役に立たない。', 'こんかいかいせいされたほうりつは、ほとんどのこくみんにとってあまりやくにたたない。', '此次修改的法律，对大多数国民来说没有多大的用处。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('636da3d7-3b16-4eee-9bab-b33fe7b894cf', '～には', NULL, 'N3', '动词辞书形＋には', '动词辞书形＋には', '“要……（就得……）”，表示目的。', '「～には」的前项表示目的，后项表示达到这个目的所需要做的事情。意思相当于「～ためには」。', 472, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('24e02a84-11ff-42f9-8e61-332af1aeb88f', '636da3d7-3b16-4eee-9bab-b33fe7b894cf', '会議で使う資料に間違いがあったが、今から作り直すには時間が足りない。', 'かいぎでつかうしりょうにまちがいがあったが、いまからつくりなおじかんがたりない。', '开会要用的资料中存在错误，但是要现在重新做的话时间不够了。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('194a0057-032b-478f-a487-a14e37e829a9', '636da3d7-3b16-4eee-9bab-b33fe7b894cf', '東京駅に行くには、そこの角を右に曲がったほうが近いですよ。', 'とうきょうえきにいくには、そこのかどをみぎにまがったほうがちかいですよ。', '要去东京站的话，最好从那里的拐角处往右拐，这样比较近。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('962c1f31-89f7-4695-b4ca-19948db69266', '636da3d7-3b16-4eee-9bab-b33fe7b894cf', '日本へ行くには、ビザを取らなければならない。', 'にほんへいくには、ビザをとらなければならない。', '要去日本，必须要获得签证。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('06644877-7a3c-43f8-b2af-ecfb4a291da5', '～によって/により/による', NULL, 'N3', '名词＋によって/により/による', '名词＋によって/により/による', '“因……（而）”“根据……（而）”。表示因前项不同而导致不同结果。\n“根据……”“由……”，表示依据。\n“通过……”“凭借……”。表示手段。\n“因为……”“由于……”。表示客观原因。\n“被……”“由……”。表示动作的主体，一般用在被动句中。', '「～によって/により」用在句中中顿，「～による」可以后续名词作定语。\n「～によって」表示手段时，不能用于表示日常生活中的工具。\n❌ 毎[まい] 日[にち] 電[でん] 車[しゃ]によって 会[かい] 社[しゃ]に 通[かよ]います。\n✅ 毎[まい] 日[にち] 電[でん] 車[しゃ]で 会[かい] 社[しゃ]に 通[かよ]います。\n由于前项的客观原因，造成了后项的结果。多用于书面语，谓语一般为过去时。后项不能用表示推测、命令、劝诱等的内容。\n表示被动句中的动作主体时，「によって」不能用「に」替换。', 473, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('94b386c5-a9eb-470f-af03-0849ac03d4ff', '06644877-7a3c-43f8-b2af-ecfb4a291da5', 'あの美術館は曜日によって閉まる時間が違うから窓口で確認したほうがいいよ。', 'あのびじゅつかんはようびしまるじかんがちがうからまどぐちでかくにんしたほうがいいよ。', '那家美术馆因日期不同闭馆时间也有所不同，所以最好在窗口确认一下。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('6b76397e-cf80-422f-97a6-02d7650b7adb', '06644877-7a3c-43f8-b2af-ecfb4a291da5', 'いくつかの国を旅してみて、食事の習慣が国によって違うことに驚いた。', 'いくつかのくにをたびしてみて、しょくじのしゅうかんがくにちがうことにおどろいた。', '我去了几个国家旅行，因各国饮食习惯的差异而感到很吃惊。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('ba03c293-62e9-4a70-94eb-0b266dc8e422', '06644877-7a3c-43f8-b2af-ecfb4a291da5', 'ボーナスが出るかどうかは、この夏の売り上げ状況による。', 'ボーナスがでるかどうかは、このなつのうりあげじょうきょうによる。', '是否发奖金，要根据这个夏天的销售情况而定。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('8839af31-de52-41e0-8dff-5dae984f60c5', '06644877-7a3c-43f8-b2af-ecfb4a291da5', '恒例によって、新入社員の歓迎会を行うことになった。', 'こうれいによって、しんにゅうしゃいんのかんげいかいをおこなうことになった。', '根据惯例，决定举行新员工的欢迎宴会。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('1be8676b-f8ec-4f97-bea1-a8b6b09464ed', '06644877-7a3c-43f8-b2af-ecfb4a291da5', '社会の安定は法律によって守られている。', 'しゃかいのあんていはほうりつまもられている。', '社会安定由法律守护。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('fe2a7576-0bfb-43f5-8444-f94cc2db7fe5', '06644877-7a3c-43f8-b2af-ecfb4a291da5', '関係者の皆様のご協力によって、無事この会を終了することができました。', 'かんけいしゃのみなさまのごきょうりょくによって、ぶじこのかいをしゅうりょうすることができました。', '通过大家的齐心协力，大会圆满地落幕了。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('16a590b2-0797-41e7-9ae0-88ece84b6f1f', '06644877-7a3c-43f8-b2af-ecfb4a291da5', 'この工場ではすべて機械による生産を行っている。', 'このこうじょうではすべてきかいせいさんをおこなっている。', '这个工厂全是通过机器进行生产的。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('062bdc71-2f1f-43e5-af7f-07a3b48f9549', '06644877-7a3c-43f8-b2af-ecfb4a291da5', '大雨によって、運動会は中止になった。', 'おおあめによって、うんどうかいはちゅうしになった。', '由于大雨，运动会取消了。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('0a142bdb-65e8-45bd-be32-e5ee45d9dc6c', '06644877-7a3c-43f8-b2af-ecfb4a291da5', '事故による交通渋滞は3時間も続いた。', 'じここうつうじゅうたいは3じかんもつづいた。', '由于交通事故，交通堵塞竟持续了三个小时。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('36533b2d-a834-49b8-821f-56d982df7629', '06644877-7a3c-43f8-b2af-ecfb4a291da5', '大地震により家を失った人が多い。', 'だいじしんいえをうしなったひとがおおい。', '很多人因大地震而失去家园。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('86f7d199-b6e7-4154-b64b-f0fd569bef4a', '06644877-7a3c-43f8-b2af-ecfb4a291da5', 'この美術館には、19世紀の画家たちによって描かれた絵がたくさんあります。', 'このびじゅつかんには、19せいきのがかえがかれたえがたくさんあります。', '这个美术馆中，有很多幅由十九世纪的画家们所作的画。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('af2c5ff2-8cc0-4dfa-ade1-e518850025a6', '06644877-7a3c-43f8-b2af-ecfb4a291da5', 'この劇場はイタリアのデザイナーによって設計された。', 'このげきじょうせっけいされた。', '该剧院是由意大利的设计师设计的。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('4d5694bd-3518-4b5a-8f48-e80a78a624fe', '06644877-7a3c-43f8-b2af-ecfb4a291da5', 'アメリカ大陸はコロンブスによって発見された。', 'アメリカたいりくはっけんされた。', '美洲大陆是由哥伦布发现的。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('be2b895e-e426-401d-97bc-7dee1c162145', '～ぬ/ん', NULL, 'N3', '动词「ない形」＋ぬ/ん', '动词「ない形」＋ぬ/ん\n（～）しない→（～）せぬ', '“不……”。表示否定。', '「ぬ/ん」是否定助动词，其中「ぬ」是书面语，「ん」是口语。和否定助动词「ない」意思相同。', 474, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('95af5aa8-6b43-4481-b75e-21874a469add', 'be2b895e-e426-401d-97bc-7dee1c162145', 'そのことについて、僕はさっぱりわからぬ。', 'そのことについて、ぼくはさっぱりわからぬ。', '关于那件事情，我什么都不知道。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('4916a54d-e2e3-45fd-8407-b0837af9a927', 'be2b895e-e426-401d-97bc-7dee1c162145', '彼はわが社にとってなくてはならぬ人だ。', 'かれはわがしゃひとだ。', '他对我们公司而言是不可或缺的。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('7b5624dd-abf4-4df5-881a-7ba0547724b2', 'be2b895e-e426-401d-97bc-7dee1c162145', '予期せぬ事が起きた。', 'よきことがおきた。', '发生了意想不到的事。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('d1b20392-2d03-4427-b446-dc51ee655f4e', '～ねばならない/ねばならぬ', NULL, 'N3', '动词「ない形」＋ねばならない/ねばならぬ', '动词「ない形」＋ねばならない/ねばならぬ\n（～する→～せねばならない/せねばならぬ）', '“必须……”。', '是「～なければならない」的书面语。', 475, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('c9635a3a-6a24-40f3-8b0d-71a8f6dbd5be', 'd1b20392-2d03-4427-b446-dc51ee655f4e', '金曜日までに書類を用意せねばならない。', 'きんようびまでにしょるいをよういせねばならない。', '在星期五之前必须要准备好资料。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('741da2ae-cf48-44cc-9731-f4dcc6ace788', 'd1b20392-2d03-4427-b446-dc51ee655f4e', '彼が来るまで待たねばならぬ。', 'かれがくるまでまたねばならぬ。', '必须要等到他来。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('2eebc01b-b2ab-406a-a48d-8d306a58d729', '～の', NULL, 'N3', '～の', '～の', '表示疑问，“……吗”。\n表示轻微的断定，“是……的”。\n表示轻微的命令，“你得……”“你要……”。', '读升调，语气比终助词「か」柔和。主要为女性和儿童使用。\n读降调，还可以使用「のよ」「のね」的形式。\n表示命令，语气较强。', 476, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('52376729-c394-42ea-b7ef-1c0cd882aac7', '2eebc01b-b2ab-406a-a48d-8d306a58d729', 'ヤンさんはいつ国に帰るの？', 'ヤンさんはいつくににかえるの？', '小杨什么时候回国？', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('3b786dbe-3393-480e-a63e-240a46f99ef4', '2eebc01b-b2ab-406a-a48d-8d306a58d729', '顔色が悪いけど、どうしたの？', 'かおいろがわるいけど、どうしたの？', '你的脸色不好，怎么啦？', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('57561365-5a35-4049-a479-313014d5b6d1', '2eebc01b-b2ab-406a-a48d-8d306a58d729', '誰に聞いたの？', 'だれにきいたの？', '你是听谁说的？', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('2e238858-940b-4ecf-b24c-8c878fa266b6', '2eebc01b-b2ab-406a-a48d-8d306a58d729', '今日は休みなのよ。', 'きょうはやすみなのよ。', '今天休息。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('b7793ae1-8441-45b0-90da-7a470d391d96', '2eebc01b-b2ab-406a-a48d-8d306a58d729', 'わたしはああいうタイプの人が好きなの。', 'わたしはああいうタイプのひとがすきなの。', '我喜欢那种类型的人。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('3bd8a575-dbdd-464b-8b2f-b9bda50387bf', '2eebc01b-b2ab-406a-a48d-8d306a58d729', 'これは吉田さんからもらったの。', 'これはよしださんからもらったの。', '这是吉田给我的。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('b743ef59-48e5-48a4-a0ab-f49a1966e06b', '2eebc01b-b2ab-406a-a48d-8d306a58d729', 'さっさと着替えるの。', 'さっさときかえるの。', '快点换衣服。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('6149543a-e696-4be0-af52-049dc43b37ad', '2eebc01b-b2ab-406a-a48d-8d306a58d729', '強い子どもは泣かないの。', 'つよいこどもはなかないの。', '坚强的孩子不能哭鼻子。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('0de6ebb2-2c93-4298-a567-7d302248a1d6', '～のに', NULL, 'N3', '动词辞书形＋のに', '动词辞书形＋のに', '“用于……”“为了……”，表示用途、目的。', '「～のに」的后项常用「 使[つか]う/かかる/ 必[ひつ] 要[よう]だ/ 不[ふ] 可[か] 欠[けつ]だ/ 役[やく] 立[だ]つ」等词。', 477, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('3a4db5b5-e95f-4085-9eac-2d96e2b13462', '0de6ebb2-2c93-4298-a567-7d302248a1d6', 'パスポートを申請するのにいろいろな書類や写真を用意する必要がある。', 'パスポートをしんせいするのにいろいろなしょるいやしゃしんをよういするひつようがある。', '申请护照，需要准备各种各样的资料和照片。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('b1845dec-3f44-4a52-bbfb-eab36b4bd23d', '0de6ebb2-2c93-4298-a567-7d302248a1d6', '料理を作るのに1時間かかります。', 'りょうりをつくるのに1じかんかかります。', '做饭要花一个小时。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('3688ab28-e544-4de7-b89b-c288edde3456', '～の 話[はなし]では', NULL, 'N3', '名词＋の 話[はなし]では', '名词＋の 話[はなし]では', '“据……说”。表示传闻的根据、消息的来源。', '常和「～そうだ/ということだ/とのことだ/んだって」等表示传闻的句型以及「～らしい/だろう」等表示推测的句型呼应使用。与N4的第79个语法条目「～によると/によれば」用法基本相同。', 478, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('f75113dd-1393-44ff-b9eb-3a25d560c2c2', '3688ab28-e544-4de7-b89b-c288edde3456', '友だちの話では、新しい辞書はとてもいいそうです。', 'ともはなしでは、あたらしいじしょはとてもいいそうです。', '听朋友说，新出的词典特别好。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('ffe8f708-ea98-43af-91df-7537135b1e32', '3688ab28-e544-4de7-b89b-c288edde3456', '吉田さんの話では、鈴木さんは風邪を引いたので、会社を休んだそうだ。', 'よしだはなしでは、すずきさんはかぜをひいたので、かいしゃをやすんだそうだ。', '据吉田说，铃木因为患了感冒，所以没来上班。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('8762e2c0-228b-42ba-9411-f4aaff2fd41e', '～ばかりだ', NULL, 'N3', '动词辞书形＋ばかりだ', '动词辞书形＋ばかりだ', '“越来越……”“不断地……”。表示某种事态朝着不好的方向不断地发展。', '「～ばかりだ」一般接在表示变化的动词之后，和「～ 一[いっ] 方[ぽう]だ」意思相同，但「～ 一[いっ] 方[ぽう]だ」既可以用于好的事态，也可以用于不好的事态。', 479, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('58d07d39-63bd-445b-9ede-c5e4bc5401df', '8762e2c0-228b-42ba-9411-f4aaff2fd41e', '物価は上がるばかりで生活は少しも楽にならない。', 'ぶっかはあせいかつはすこしもらくにならない。', '物价不断地上涨，生活没法轻松。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('24b60390-ab41-45c2-8ccf-2dc5e7a53e8e', '8762e2c0-228b-42ba-9411-f4aaff2fd41e', '彼の病状は悪化するばかりだ。', 'かれのびょうじょうはあっかするばかりだ。', '他的病情不断地在恶化。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('6c198100-a34c-49dd-abb7-5ce115347144', '8762e2c0-228b-42ba-9411-f4aaff2fd41e', '大気汚染はますますひどくなるばかりだ。', 'たいきおせんはますますひどくなるばかりだ。', '空气污染越来越严重。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('53073d27-6ac1-4423-b759-fd140ea97a97', '～ば～ほど', NULL, 'N3', '动词「ば形」＋同一动词的辞书形＋ほど', '动词「ば形」＋同一动词的辞书形＋ほど\nい形容词词干＋ければ＋同一い形容词辞书形＋ほど\nな形容词词干＋なら＋同一な形容词词干＋な＋ほど', '“越……越……”。', '表示随着前项的变化，后项也相应地发生变化。注意这时候不能替换成「～くらい」。', 480, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('75d0ea4f-b6a2-4566-a60b-f72d06ba6ada', '53073d27-6ac1-4423-b759-fd140ea97a97', '店員「どんなお部屋をお探しですか。」客「駅に近くて安い部屋がいいんです。」店員「ううん、難しいですね。駅に近ければ近いほど、高くなりますので。」', 'てんいん「どんなおへやをおさがしですか。」きゃく「えきにちかくてやすいへやがいいんです。」てんいん「ううん、むずかしいですね。えきにちかちかいほど、たかくなりますので。」', '店员：“您想找什么样的房子？”\n客人：“最好能离车站近，而且又便宜。”\n店员：“嗯，这个有点难呢。因为离车站越是近价钱就越贵。”', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('0b6a2149-9357-48f2-879c-155ed7994db9', '53073d27-6ac1-4423-b759-fd140ea97a97', 'この問題について考えれば考えるほど、頭の中が混乱してきた。', 'このもんだいについてかんがかんがえるほど、あたまのなかがこんらんしてきた。', '越想这个问题头脑就越混乱。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('6baf58f8-a375-46d6-a5e6-9e513f17afee', '53073d27-6ac1-4423-b759-fd140ea97a97', 'この本は初心者向けですから、文法の説明は簡単なら簡単なほどいい。', 'このほんはしょしんしゃむけですから、ぶんぽうのせつめいはかんたんかんたんなほどいい。', '这本书是面向初学者的，所以语法的解释越简单越好。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('a1311cc7-2cb6-43bd-a30a-5739e1a832c2', '～ばよかった/なければよかった', NULL, 'N3', '动词「ば形」＋よかった', '动词「ば形」＋よかった\n动词「ない形」＋なければよかった', '“要是……的话，就好了”；“要是不……就好了”。「～なければよかった」在口语中可以说成「～なきゃよかった」。', '表示说话人对于实际没有发生的事情或者与期待不符的现状抱有的一种遗憾或责备的心情。', 481, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('d33698c1-b8d3-47da-a554-cbcdbe8994c3', 'a1311cc7-2cb6-43bd-a30a-5739e1a832c2', '先週の学園祭は本当に楽しかった。鈴木君も参加すればよかったのに。', 'せんしゅうのがくえんさいはほんとうにたのしかった。すずきくんもさんかすればよかったのに。', '上周的学园节真的很开心，要是铃木你也参加就好了。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('4efec398-e823-4bfb-b6ed-ac158d3eaf9c', 'a1311cc7-2cb6-43bd-a30a-5739e1a832c2', '彼女はわたしの話に傷ついたみたい。あんなことを言わなきゃよかった。', 'かのじょはわたしのはなしにきずついたみたい。あんなことをいわなきゃよかった。', '她好像因为我的话受伤了。早知道不那样说就好了。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('7fd0dea9-55f5-428e-9427-d97d4be96c36', '～ぶり', NULL, 'N3', '名词＋ぶり（に）', '名词＋ぶり（に）\n动词「ます形」/名词＋ぶり', '“经过……之后又……”。\n“……的样子”“……的状态”。', '接在表示时间的名词后，表示隔了一段时间之后重新做某事。「～ぶりの」后续名词作定语使用，「～ぶりだ」用于结句。\n表示事物存在的样态和动作进行的方式、方法。常用的有「 話[はな]しぶり（说话的样子）/ 慌[あわ]てぶり（慌张的样子）/ 飲[の]みぶり（喝酒的样子）/ 生[せい] 活[かつ]ぶり（生活状态）」等。', 482, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('63306838-bc4d-4c39-aba3-e73fdaadbf6d', '7fd0dea9-55f5-428e-9427-d97d4be96c36', '台風で電車が不通になっていたが、10時間ぶりに運転を始めたそうだ。', 'たいふうででんしゃがふつうになっていたが、10じかんうんてんをはじめたそうだ。', '听说因为台风造成电车全线瘫痪，不过十个小时之后又恢复运营了。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('8a0ad14a-9911-46ea-aef2-ffcdc6eda3b4', '7fd0dea9-55f5-428e-9427-d97d4be96c36', '5年ぶりの帰国だから、家族がとても喜んだ。', '5ねんぶりのきこくだから、かぞくがとてもよろこんだ。', '因为时隔五年才回国，所以家里人都十分高兴。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('af21c2b1-5cf2-4d7e-a837-f4dc2c774119', '7fd0dea9-55f5-428e-9427-d97d4be96c36', '彼女に会うのは10年ぶりだった。', 'かのじょにあうのは10ねんぶりだった。', '时隔十年和她重逢。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('f346e5fb-8c47-485a-9f17-a9416d91a605', '7fd0dea9-55f5-428e-9427-d97d4be96c36', '彼の話しぶりが気に入らない。', 'かれのはなしぶりがきにいらない。', '不喜欢他说话的口气。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('c093c5e4-6fd4-49ab-a5ca-c327053f7135', '7fd0dea9-55f5-428e-9427-d97d4be96c36', '今朝の電車の混雑ぶりは異常だ。', 'けさのでんしゃのこんざつぶりはいじょうだ。', '今天早上的电车不是一般的挤。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('55c03212-7bb4-4816-bc8b-a5755e80185f', '～べき/べきだ/べきではない', NULL, 'N3', '～べき/べきだ/べきではない', '～べき/べきだ/べきではない', '“应该……”；“不应该……”。', '「～べきだ」表示说话人认为理应如此或有义务这样做；否定形式「～べきではない」表示禁止、不允许的意思；「～べき」后接名词作定语使用。', 483, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('c608d2ee-cbf9-48eb-92ca-a139ba228d76', '55c03212-7bb4-4816-bc8b-a5755e80185f', '約束は守るべきです。そうしないと、信用を失いますよ。', 'やくそくはまもるべきです。そうしないと、しんようをうしないますよ。', '我们应该遵守约定，否则就会失去信用。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('fbd7fd84-7ca7-4b0e-a628-2f48f437b85e', '55c03212-7bb4-4816-bc8b-a5755e80185f', '大学院は自分で研究を進めるところだから、先生に頼ろうとするべきではない。', 'だいがくいんはじぶんでけんきゅうをすすめるところだから、せんせいにたよろうとするべきではない。', '研究生院是自己进行研究的地方，所以不应该试图依靠老师。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('2d23127c-cba1-4dcf-8ab8-e47adf0a7e79', '55c03212-7bb4-4816-bc8b-a5755e80185f', 'これからやるべきことはたくさんある。', 'これからやるべきことはたくさんある。', '接下来还有很多事情要做。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('ba3f1946-b690-48a3-ad46-4a0e2c284e9b', '～ほど', NULL, 'N3', '名词＋ほど～ない', '名词＋ほど～ない\n名词＋ほど～はない', '“没有……那么……”“不如……”。\n“几乎……”“简直……”，表示动作或状态的程度。\n“没有达到……地步”。\n“没有比……更……”。', '「～ほど」用在句中；「～ほどだ」用在句末结句；「～ほどの」后接名词作定语使用，相当于「～ぐらい」。但「～ほど」是书面语，而「～ぐらい」是口语。\n这时候不能用「～ぐらい」替换使用。\n表示最高程度。相当于「～くらい～はない」。', 484, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('8bab369a-018d-48bd-933b-0bc40e39c45f', 'ba3f1946-b690-48a3-ad46-4a0e2c284e9b', '料理をするのがそれほど得意ではない私でも、ハンバーグだけはおいしく作れる。', 'りょうりとくいではないわたしでも、ハンバーグだけはおいしくつくれる。', '即使是不那么擅长做饭的我，汉堡牛肉饼的话还是可以做得很好吃的。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('947c5cf2-c7d4-499d-8402-390291dbac92', 'ba3f1946-b690-48a3-ad46-4a0e2c284e9b', 'きょうはきのうほど風が強くない。', 'かぜがつよくない。', '今天的风没有昨天大。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('e98cc1a3-8ca9-436c-b644-f5e2965c38e8', 'ba3f1946-b690-48a3-ad46-4a0e2c284e9b', 'わたしの部屋は姉の部屋ほど広くない。', 'わたしのへやはあねのへやひろくない。', '我的房间没姐姐的房间大。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('53e6f2d8-024b-479b-8aaf-8e3ffe0f3a65', 'ba3f1946-b690-48a3-ad46-4a0e2c284e9b', '「わたし、辛いものを食べると、必ずといっていいほどせきが出るんです。」', '「わたし、からいものをたべると、かならずといっていいほどせきがでるんです。」', '“几乎可以说我一吃辣的东西就肯定会咳嗽。”', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('c92da4ff-544e-41c3-abf9-93f0f07c6adf', 'ba3f1946-b690-48a3-ad46-4a0e2c284e9b', '5歳の娘は音楽の才能があるようだ。ピアノを習い始めて1年も経たないうちに、コンクールで優勝を争うほどになった。', '5さいのむすめはおんがくのさいのうがあるようだ。ピアノをならいはじめて1ねんもたたないうちに、コンクールでゆうしょうをあらそうほどになった。', '五岁的女儿似乎有音乐方面的天分。学习钢琴还不到一年，就已经到了能在比赛中争夺冠军的程度了。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('1e0be2ec-2b2a-4c4b-bca8-5ac7f315ef68', 'ba3f1946-b690-48a3-ad46-4a0e2c284e9b', 'この料理はとても辛くて、体じゅうから汗が出るほどだ。', 'このりょうりはとてもからくて、からだじゅうからあせがでるほどだ。', '这道菜辣得浑身冒汗。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('529f9f38-e9f5-40e6-84ed-33004d2b2828', 'ba3f1946-b690-48a3-ad46-4a0e2c284e9b', '病状は手術が必要なほどではない。', 'びょうじょうはしゅじゅつがひつようなほどではない。', '病情还没有发展到非要动手术的程度。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('bdb1af57-5fee-4dee-ac80-901b0fd06ee1', 'ba3f1946-b690-48a3-ad46-4a0e2c284e9b', '心配するほどの怪我ではない。', 'しんぱいするほどのけがではない。', '这伤不是很重，不用担心。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('3acff63b-4e6b-4c91-94d6-6160b1d2d8f4', 'ba3f1946-b690-48a3-ad46-4a0e2c284e9b', 'わざわざ行くほどのことではない。', 'わざわざいくほどのことではない。', '用不着特意去。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('33f393d7-d70b-4359-bd12-fb76f3900a61', 'ba3f1946-b690-48a3-ad46-4a0e2c284e9b', 'これほど悲しいことはない。', 'かなしいことはない。', '没有比这件事情更令人伤心了。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('9d785026-f406-4b85-bf81-eea15ef88d81', 'ba3f1946-b690-48a3-ad46-4a0e2c284e9b', '彼女ほど頭のいい人はいない。', 'かのじょあたまのいいひとはいない。', '没有比她更聪明的人了。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('0e8aa509-a4d8-4367-b17d-b4d8e203885b', '～ 向[む]きだ/ 向[む]きに/ 向[む]きの', NULL, 'N3', '名词＋ 向[む]きだ/ 向[む]きに/ 向[む]きの', '名词＋ 向[む]きだ/ 向[む]きに/ 向[む]きの', '“适合于……”，表示适合于某对象。', '相当于「～に 適[てき]している」。「～ 向[む]きだ」用于结句；「～ 向[む]きに」作状语；「～ 向[む]きの」后接名词作定语使用。', 485, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('8d5ad1d6-20d9-4187-8787-3c1e8e8971a2', '0e8aa509-a4d8-4367-b17d-b4d8e203885b', 'この服はキャンプ向きだ。', 'このふくむきだ。', '这件衣服适合野营。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('a2bb3f26-1ffc-4a0b-a689-c4cb0b9fd77e', '0e8aa509-a4d8-4367-b17d-b4d8e203885b', '日本人向きに作られた中華料理は味がさっぱりだ。', 'にほんじんむつくられたちゅうかりょうりはあじがさっぱりだ。', '为适合日本人口味所做的中餐，味道很清淡。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('64bf5489-334a-4efd-bf3a-4bd9781ed84c', '0e8aa509-a4d8-4367-b17d-b4d8e203885b', 'このアルバイトは女性向きの仕事ではない。', 'このアルバイトはじょせいむしごとではない。', '这不是适合女性的兼职工作。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('3ec53bf2-484a-4cdd-9e89-1b9f167aa074', '～ 向[む]けだ/ 向[む]けに/ 向[む]けの', NULL, 'N3', '名词＋ 向[む]けだ/ 向[む]けに/ 向[む]けの', '名词＋ 向[む]けだ/ 向[む]けに/ 向[む]けの', '“面向……”“以……为对象”。表示针对的对象。', '「～ 向[む]けだ」用于结句；「～ 向[む]けに」作状语；「～ 向[む]けの」后接名词作定语使用。', 486, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('0acbe5e5-4385-4ee2-b7c1-fd1cf02ebe64', '3ec53bf2-484a-4cdd-9e89-1b9f167aa074', 'この映画は大人向けなので、子どもは見てもつまらない。', 'このえいがはおとなむけなので、こどもはみてもつまらない。', '这部电影是以大人为对象的，小孩子即使看了也觉得无趣。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('c3596724-1154-4821-9390-a0939e72d041', '3ec53bf2-484a-4cdd-9e89-1b9f167aa074', '当社は法人向けに金融サービスを提供します。', 'とうしゃはほうじんむきんゆうサービスをていきょうします。', '本公司提供面向法人的金融服务。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('90033c2b-c8f1-49dc-8392-2baad64f5f37', '3ec53bf2-484a-4cdd-9e89-1b9f167aa074', '外国人向けの放送は夜9時から始まる。', 'がいこくじんむほうそうはよる9じからはじまる。', '面向外国人的广播从晚上九点开始。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('c854bf17-770b-48c3-9cae-2f466eac8a26', '～もの/もん', NULL, 'N3', '～もの/もん', '～もの/もん', '“因为……”。用于说明理由，陈述自己的观点。', '多用于对自己的行为进行辩解，常和「だって」呼应使用。是口语的表达方式，多为女性和儿童使用，带有撒娇、辩解的语气。「～もん」比「～もの」更加口语化。', 487, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('568be90d-ff57-4b26-b058-da8f67b6a801', 'c854bf17-770b-48c3-9cae-2f466eac8a26', 'A「どうして食べないの？」B「だって嫌いなんだもん。」', 'A「どうしてたべないの？」B「だってきらいなんだもん。」', 'A：“你为什么不吃啊？”\nB：“因为人家不喜欢吃呀。”', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('1a83fc72-00bd-4045-896a-13a465cd5c69', 'c854bf17-770b-48c3-9cae-2f466eac8a26', 'A「どうしてパーティーに来なかったの？」B「だって知らなかっただもの。」', 'A「どうしてパーティーにこなかったの？」B「だってしらなかっただもの。」', 'A：“你为什么没来参加聚会呢？”\nB：“因为我不知道啊。”', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('09f303f1-229c-4702-95ea-6a0727631995', '～ものだ', NULL, 'N3', '动词「た形」＋ものだ', '动词「た形」＋ものだ\n动词「ます形」＋たい＋ものだ\n名词＋が/动词「て形」＋ほしい＋ものだ', '“理应……”；“本来就是……”。表示一般常识。\n表示感慨地回忆过去。\n表示强烈的感情。\n“真想……”，表示强烈的愿望。', NULL, 488, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('4bd0a34e-b5f3-481d-aa18-f056515a5f38', '09f303f1-229c-4702-95ea-6a0727631995', '今年の夏は暑いのに、クーラーがさっぱり売れない。暑い夏ほどクーラーは売れるものだと言われているが、違うんだろうか。', '今ことしのなつはあついのに、クーラーがさっぱりうれない。あついなつほどクーラーはうれるものだといわれているが、ちがうんだろうか。', '今年夏天很热，但空调卖得很不好。都说夏天越热空调卖得越好，难道不是吗？', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('7559091d-9978-4178-a131-35b46ca369de', '09f303f1-229c-4702-95ea-6a0727631995', '人間は年を取ると記憶力が衰えるものだ。', 'にんげんはとしをとるときおくりょくがおとろえるものだ。', '人一上了年纪，记忆力就会衰退。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('55bb6d36-4ff6-4634-a8e6-7d9b25c99b13', '09f303f1-229c-4702-95ea-6a0727631995', '子どもの頃はよくこの川で遊んだものだ。', 'こどものころはよくこのかわであそんだものだ。', '小时候经常在这条河边玩。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('6a75e15e-990d-44c6-80a2-7777180dcd5a', '09f303f1-229c-4702-95ea-6a0727631995', '小学生の時、よく学校をサボって母に叱られたものだ。', 'しょうがくせいのとき、よくがっこうをサボってははにしかられたものだ。', '读小学的时候经常逃课，被妈妈训斥。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('c3b14082-455e-426f-a1aa-00d97ff72096', '09f303f1-229c-4702-95ea-6a0727631995', '時間の経つのは早いものですね。', 'じかんのたつのははやいものですね。', '时间过得真快啊。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('9074dd2e-e93f-4910-b840-39f3df3c14c6', '09f303f1-229c-4702-95ea-6a0727631995', 'もう70歳なのに、よくあんなに走れるものだ。', 'もう70さいなのに、よくあんなにはしれるものだ。', '都已经70岁了，却还那么能跑。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('e2c4533a-d26a-4842-8b07-49ec9c5662b0', '09f303f1-229c-4702-95ea-6a0727631995', 'ぜひハワイへ旅行に行きたいものだ。', 'ぜひハワイへりょこうにいきたいものだ。', '真想去夏威夷旅行。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('b8130647-4d13-41e6-8822-0425ef33539c', '09f303f1-229c-4702-95ea-6a0727631995', '拘束された人質が無事であってほしいものだ。', 'こうそくされたひとじちがぶじであってほしいものだ。', '真希望被扣留的人质可以平安无事。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('ea72f97f-0306-4384-908f-08658c7bdf55', '～やら～やら', NULL, 'N3', '动词辞书形/い形容词辞书形/名词＋やら～やら', '动词辞书形/い形容词辞书形/名词＋やら～やら', '“……啦……啦”“又是……又是……”。表示列举两个有代表性的事例，暗示还有其他。', '所举出的事例多为消极内容，带有「たいへん」的语气。是口语的表达方式。', 489, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('e33579b6-cb89-4f01-b8f3-10c43a7cb5ec', 'ea72f97f-0306-4384-908f-08658c7bdf55', '今月はレポートやら試験やらでひどく忙しかった。', 'こんげつしけんやらでひどくいそがしかった。', '这个月又是写报告，又是考试，忙得团团转。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('6d92800f-77db-4cac-b244-3209135ff31f', 'ea72f97f-0306-4384-908f-08658c7bdf55', '同窓会は飲むやら、歌うやらの大騒ぎだった。', 'どうそうかいはのむやら、うたうやらのおおさわぎだった。', '同学会上，又是喝酒又是唱歌的，一片喧闹。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('82941c1d-9f43-4715-a983-5f6b0a63f6d7', '～ようがない/ようもない', NULL, 'N3', '名词＋の/动词「ます形」＋ようがない/ようもない', '名词＋の/动词「ます形」＋ようがない/ようもない', '“无法……”“没有办法……”。', '「よう」接在动词「ます形」后，表示做某事的方法。「どうしようもない」为惯用表达，表示“毫无办法”。', 490, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('1944022c-9151-48b1-a793-da1ea26e7579', '82941c1d-9f43-4715-a983-5f6b0a63f6d7', '（カメラ店で）客「このカメラ直りますか。」店員「うーん、こんなにひどく壊れていると、直しようがないですね。」', '（カメラてんで）きゃく「このカメラなおりますか。」てんいん「うーん、こんなにひどくこわれていると、なおしようがないですね。」', '（在相机店）客人：“这个相机能修吗？”\n店员：“嗯，坏成这样的话，没有办法修了。”', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('878c3f2b-9cc1-4683-8de3-8e696d2e3803', '82941c1d-9f43-4715-a983-5f6b0a63f6d7', '故障した機械を直してくれと頼まれたが、部品がなくては修理しようがない。', 'こしょうしたきかいをなおしてくれとたのまれたが、ぶひんがなくてはしゅうりしようがない。', '别人请我修机器，但是没有零部件的话没法修。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('4312db0f-2f65-48cb-81a7-bc9fbc27aa9e', '82941c1d-9f43-4715-a983-5f6b0a63f6d7', 'なぜ彼女を好きになってしまったのかは、説明のしようがない。', 'なぜかのじょをすきになってしまったのかは、せつめいのしようがない。', '为什么会喜欢上她，我自己也说不清楚。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('226c6c5c-ab59-44b6-a2ce-e33452ee7d16', '～ように', NULL, 'N3', '动词普通形＋ように', '动词普通形＋ように', '“希望……”“请……”。\n“请你（转告/转达）……”。', '表示希望、要求。\n表示间接引用，后项常与「 言[い]う/ 伝[つた]える」等动词呼应使用。', 491, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('e33c54c2-2319-4afe-a8eb-e1707ba738b2', '226c6c5c-ab59-44b6-a2ce-e33452ee7d16', 'この話は他人に話さないように。', 'このはなしはたにんにはなさないように。', '这件事不要告诉别人。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('a7f3f34b-bcc6-4431-9003-6a721ed2b7b3', '226c6c5c-ab59-44b6-a2ce-e33452ee7d16', 'どうか彼の病気が治るように。', 'どうかかれのびょうきがなおるように。', '希望他能早日康复。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('6c9b6f76-d677-4839-a3ba-b7b6f7a9c430', '226c6c5c-ab59-44b6-a2ce-e33452ee7d16', '彼に早く来るように言ってください。', 'かれにはやくくいってください。', '请你叫他快点来。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('94c503ec-7480-4e6f-b44a-4afa5614c3ed', '226c6c5c-ab59-44b6-a2ce-e33452ee7d16', '戻りましたら、家に電話するようにお伝えください。', 'もどりましたら、いえにでんわするようにおつたえください。', '他回来之后，请转告他给家里打个电话。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('ba480160-a9dc-4cf8-99fb-9c68342d5e52', '～ようになっている', NULL, 'N3', '动词辞书形＋ようになっている', '动词辞书形＋ようになっている', '表示正在发生某种变化。', '表示某种状态的变化正在进行，并且可能还将持续下去。', 492, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('e27c6910-2ecf-4131-8992-a40cd3f6900a', 'ba480160-a9dc-4cf8-99fb-9c68342d5e52', '（ABC子ども新聞の宣伝）「わたしたちが作ったABC子ども新聞は、すべての漢字に振り仮名をつけてあるので、小学1年生からでも読めるようになっています。」', '（ABCこどもしんぶんのせんでん）「わたしたちがつくったABCこどもしんぶんは、すべてのかんじにふりがなをつけてあるので、しょうがく1ねんせいからでもよめるようになっています。」', '我们制作的ABC儿童报纸，所有的汉字都有注音，所以即使小学一年级学生也可以阅读。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('cc43e1e7-ee88-4176-94cb-204a569b88b4', 'ba480160-a9dc-4cf8-99fb-9c68342d5e52', '当店はお買い物の際、カードもご利用いただけるようになっております。', 'とうてんはおかいもののさい、カードもごりよういただけるようになっております。', '您可以在本店刷卡购物。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('e1f5cfe7-1c9e-4d4f-a98f-63afd5d01cf1', 'ba480160-a9dc-4cf8-99fb-9c68342d5e52', '火事が起こった場合は、このベルは自動的に鳴るようになっています。', 'かじがおこったばあいは、このベルはじどうてきになるようになっています。', '发生火灾时，这个电铃会自动响。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('957f1ffd-b9b2-4810-ac14-7e53e3c0e173', '～ように 見[み]える', NULL, 'N3', '～ように 見[み]える', '～ように 見[み]える', '“看上去像是……”，用于说话人根据自己所看到的情况进行判断。', '表示让人觉得或表面看上去是那样。', 493, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('5819bddd-f580-467a-bcdc-83d1268050f0', '957f1ffd-b9b2-4810-ac14-7e53e3c0e173', '着物を着て化粧をした彼女は別人のように見える。', 'きものをきてけしょうをしたかのじょはべつじんみえる。', '穿上和服、化了妆的她，看上去像变了个人一样。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('ba6c6274-daba-485c-9e3b-ab3d4e99b771', '957f1ffd-b9b2-4810-ac14-7e53e3c0e173', '妻は僕のことを許してくれたように見えたが、実際はそうではなかった。', 'つまはぼくのことをゆるみえたが、じっさいはそうではなかった。', '妻子看起来似乎原谅了我，但实际上并没有。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('b55bca0e-935f-44af-82f9-39b7198d381d', '～（ら）れる（自发态）', NULL, 'N3', 'Ⅰ类动词「ない形」＋れる', 'Ⅰ类动词「ない形」＋れる\nⅡ类动词「ない形」＋られる\nⅢ类动词（～する→～される）', '“不由得……”。表示心理自然而然地产生某种活动或变化。', '能构成自发态的动词大多是和情感有关的动词，如「 感[かん]じる（感到）/ 案[あん]じる（担心）/ 思[おも]い 出[だ]す（想起）」等，并且动词前面的助词一般用「が」表示。', 494, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('9503a19d-0c63-4264-9df1-41db57ca0387', 'b55bca0e-935f-44af-82f9-39b7198d381d', 'この写真を見るたびに、子ども頃のことが思い出される。', 'このしゃしんをみるたびに、こどもころのことがおもいだされる。', '每当看到这张照片，就不由得想起小时候的事情。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('5ea0a3a8-1691-4872-8cee-8cb0693ae90a', 'b55bca0e-935f-44af-82f9-39b7198d381d', 'なんだか不思議に思われる。', 'なんだかふしぎにおもわれる。', '总觉得有点不可思议。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('b438741b-069b-4c6f-84cd-89196e854ea8', 'b55bca0e-935f-44af-82f9-39b7198d381d', '娘の将来のことが案じられます。', 'むすめのしょうらいのことがあんじられます。', '女儿的前途令人担忧。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('2afbae16-4349-49fe-b164-815654a1beb2', '～わけがない/わけはない', NULL, 'N3', '～わけがない/わけはない', '～わけがない/わけはない', '“不可能……”“不会……”。', '表示说话人主观上的一种强烈的否定。即说话人根据前项的很充分、很确定的理由，理所当然地得出后项的结论。', 495, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('9d1f2ac7-015d-4b31-ba5a-a740c950763f', '2afbae16-4349-49fe-b164-815654a1beb2', '（会社で）A「あれ？あそこにいるの、山田さんかな。」B「山田さんは出張中だよ。今ここにいるわけないじゃない。」', '（かいしゃで）A「あれ？あそこにいるの、やまださんかな。」B「やまださんはしゅっちょうちゅうだよ。いまここにいるわけないじゃない。」', '（在公司里）A：“咦？在那里的那个人，是不是山田啊。”\nB：“山田在出差呢。怎么可能现在在这里啊。”', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('1bd500bf-102f-4b26-b4b0-ad0916e68690', '2afbae16-4349-49fe-b164-815654a1beb2', 'このマンガは若い人の間ですごく流行っているので、高校生が知らないわけがないよ。', 'このマンガはわかいひとのあいだですごくはやっているので、こうこうせいがしらないわけがないよ。', '这本漫画在年轻人当中非常流行，所以高中生不可能不知道。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('c95f2039-c445-4126-be72-fc6ac7a0e984', '2afbae16-4349-49fe-b164-815654a1beb2', 'お酒の好きな田中さんが来るんだから、これだけで足りるわけがない。', 'おさけのすきなたなかさんがくるんだから、これだけでたりるわけがない。', '喜欢喝酒的田中要来，所以光这些酒不可能够。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('6b5550c1-53c5-4715-99d6-47810281aa92', '～わけだ', NULL, 'N3', '～わけだ', '～わけだ', '“当然……”“难怪……”。\n“也就是说……”“换句话说……”，表示换而言之。', '表示根据某既定事实，做出理所当然的结论。常和「だから/ので」搭配使用。\n常和「ということは/つまり～」等搭配使用。和「～ということだ/～ということになる」意思相同。', 496, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('181c5445-2734-415c-a6f3-eea1e4bdc289', '6b5550c1-53c5-4715-99d6-47810281aa92', '暑いわけだ。38度もある。', 'あついわけだ。38どもある。', '难怪那么热，气温高达38度。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('467ffb8f-6b27-4318-b1f0-e136c4c4f582', '6b5550c1-53c5-4715-99d6-47810281aa92', '食べ物があると食べてしまう。太るわけだ。', 'たべものがあるとたべてしまう。ふとるわけだ。', '一有东西就吃，难怪这么胖。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('450131d6-82a1-49e7-a82d-a96ef2673ea6', '6b5550c1-53c5-4715-99d6-47810281aa92', '彼女は日本に10年もいたから、日本語が上手なわけです。', 'かのじょはにほんに10ねんもいたから、にほんごがじょうずなわけです。', '她在日本住了十年了，难怪日语这么好。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('a0494d03-ecea-442f-8ff5-73c038818c46', '6b5550c1-53c5-4715-99d6-47810281aa92', 'つまり、もう昼ごはんを食べたわけですね。', 'つまり、もうひるごはんをたべたわけですね。', '也就是说你已经吃过午饭了。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('b06384ed-f01e-4df0-b82a-b467760b20f3', '6b5550c1-53c5-4715-99d6-47810281aa92', 'A「社長がアメリカへ出張に行ったそうです。」B「ということは、明日の会議に出られないわけですね。」', 'A「しゃちょうがアメリカへしゅっちょうに行ったそうです。」B「ということは、あしたのかいぎにでられないわけですね。」', 'A：“听说社长去美国出差了。”\nB：“也就是说，他不能出席明天的会议了是吧。”', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('9a7739c0-308e-476b-a5ad-98b042b23897', '6b5550c1-53c5-4715-99d6-47810281aa92', '彼女の父親はわたしの母の弟だ。つまり彼女とわたしは従兄弟同士なわけだ。', 'かのじょのちちおやはわたしのははのおとうとだ。つまりかのじょとわたしはいとこどうしなわけだ。', '她的父亲是我妈的弟弟，也就是说她和我是表姐妹关系。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('10b52fb5-6ac4-425e-975a-4336b50e414d', '～わけではない/わけでもない', NULL, 'N3', '～わけではない/わけでもない', '～わけではない/わけでもない', '“并不是……”。表示虽然并不全盘否定，但是有一部分是那样。', NULL, 497, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('91a8c882-fab8-424d-a88b-061a4b39c272', '10b52fb5-6ac4-425e-975a-4336b50e414d', '現在、建設作業はスムーズに進んでいるが、必ずしも最初から順調だったわけではない。', 'げんざい、けんせつさぎょうはスムーズにすすんでいるが、かならずしもさいしょからじゅんちょうだったわけではない。', '现在建设工程进展顺利，但并不是一开始就很顺利。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('232638ea-b1d8-4ab0-8cfc-3407a4f3b5e8', '10b52fb5-6ac4-425e-975a-4336b50e414d', 'スポーツが苦手だと言っても、スポーツ番組を見るのが嫌いだと言うわけではない。', 'スポーツがにがてだといっても、スポーツばんぐみをみるのがきらいだというわけではない。', '虽说我不擅长运动，但并不是说我不喜欢看体育节目。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('da183a9b-3c25-4ae5-b5e8-570ae43d37ae', '10b52fb5-6ac4-425e-975a-4336b50e414d', '最近の子どもはテレビゲームばかりしているようだが、必ずしも外で遊ばないわけではない。', 'さいきんのこどもはテレビゲームばかりしているようだが、かならずしもそとであそばないわけではない。', '最近的孩子好像一味地在玩游戏，但也并不是不出去玩。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('68b2622d-833f-4dab-8499-4ff59e713770', '～わけにはいかない', NULL, 'N3', '动词辞书形＋わけにはいかない', '动词辞书形＋わけにはいかない', '“不能……”“不可以……”。', '表示从一般常识、社会共识或过去的经验来看，不能做某事。', 498, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('998c1bdc-a418-4da0-9898-20c11fec4493', '68b2622d-833f-4dab-8499-4ff59e713770', '夫「行ってきます。」妻「え？会社、行くの？まだ熱があるんでしょう？」夫「大事な会議があるから、休むわけにはいかないんだ。」', 'おっと「いってきます。」つま「え？かいしゃ、いくの？まだねつがあるんでしょう？」おっと「だいじなかいぎがあるから、やすむわけにはいかないんだ。」', '丈夫：“我出门了。”\n妻子：“啊？你是去公司吗？你不是还在发着烧吗？”\n丈夫：“因为有非常重要的会议，我不能休息。”', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('faf205bf-cea1-49bc-ac26-7b8bc9579e8b', '68b2622d-833f-4dab-8499-4ff59e713770', '重要な会議だから、責任者のわたしが遅れていくわけにはいかない。', 'じゅうようなかいぎだから、せきにんしゃのわたしがおくれていくわけにはいかない。', '因为是重要会议，所以我身为负责人不能迟到。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('6f0fef83-5edb-41bf-9673-9a9bf06d36a8', '68b2622d-833f-4dab-8499-4ff59e713770', '明日はほかの仕事をしなければならないのだから、この仕事をやりかけのまま、帰るわけにはいかない。', 'あしたはほかのしごとをしなければならないのだから、このしごとをやりかけのまま、かえるわけにはいかない。', '明天必须做别的工作，所以这项工作不能没做完就回家。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('2a40e3f3-d1eb-43db-a396-3e97cc3951b6', '～を 込[こ]めて', NULL, 'N3', '名词＋を 込[こ]めて', '名词＋を 込[こ]めて', '“充满……”“怀着……”。表示某种感情倾注于某件事物之中。', '有「 心[こころ]/  願[ねが]い/ 愛[あい]を 込[こ]めて」等常用的表达方式。「～を 込[こ]めた」后接名词作定语使用。', 499, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('40861011-813f-4272-9d56-6d76bbec676a', '2a40e3f3-d1eb-43db-a396-3e97cc3951b6', '母の誕生日に、心を込めてセーターを編んだ。', 'ははのたんじょうびに、こころこめてセーターをあんだ。', '我用心给妈妈织了一件毛衣作生日礼物。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('225584a6-065b-42e8-b43b-e42148e49098', '2a40e3f3-d1eb-43db-a396-3e97cc3951b6', '感謝の気持ちを込めて、このカードを作りました。', 'かんしゃのきもこめて、このカードをつくりました。', '满怀着感激的心情，制作了这张卡片。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('5c80c43a-a3dc-4a3e-802e-fc7bb6bbc728', '2a40e3f3-d1eb-43db-a396-3e97cc3951b6', '愛を込めて、彼女にこの指輪を送りました。', 'あいこめて、かのじょにこのゆびわをおくりました。', '将这枚饱含爱意的戒指送给了她。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('e01ebdb2-0c27-49ee-9c54-df8ec08f4295', '～を～として/とする/とした', NULL, 'N3', '名词＋を＋名词＋として/とする/とした', '名词＋を＋名词＋として/とする/とした', '“把……当作……”。', '「～を～とする/とした」后续名词。', 500, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('c667028c-8d75-49ff-bbcd-bc93b5cfdbb1', 'e01ebdb2-0c27-49ee-9c54-df8ec08f4295', '投票の結果、山田氏を会長とすることに決定しました。', 'とうひょうのけっか、やまだしかいちょうとすることにけっていしました。', '根据投票结果，大家一致决定让山田担任会长。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('b506ba56-8492-49da-bd98-5b24a835aac4', 'e01ebdb2-0c27-49ee-9c54-df8ec08f4295', '田中さんをリーダーとしてサークルを作った。', 'たなかさんをリーダーとしてサークルをつくった。', '以田中为领导成立了小组。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('72fd5578-c70c-4dfd-9d03-dca6c5750eb2', 'e01ebdb2-0c27-49ee-9c54-df8ec08f4295', '石油を原料とする製品はいろいろあります。', 'せきゆげんりょうせいひんはいろいろあります。', '以石油为原料的产品有很多。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('38bbd04f-c4e2-48e8-aff2-bf15a506c250', '～をはじめ（として）/をはじめとする', NULL, 'N3', '名词＋をはじめ（として）/をはじめとする', '名词＋をはじめ（として）/をはじめとする', '“以……为首”“以……为代表”。表示前述事项在同类事物中最为重要，最具代表性。', '「～をはじめ（として）」用在句中作中顿；「～をはじめとする」后接名词作定语使用。', 501, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('b2166271-1eaa-4777-8675-6457e3d1751f', '38bbd04f-c4e2-48e8-aff2-bf15a506c250', '（北川先生へのメールで）昨日無事に帰国しました。日本滞在中は、北川先生をはじめ多くの方々にお世話になり、本当にありがとうございました。', '（きたがわせんせいへのメールで）きのうぶじにきこくしました。にほんたいざいちゅうは、きたがわせんせいおおくのかたがたにおせわになり、ほんとうにありがとうございました。', '（在给北川老师的邮件中）昨天我顺利回国了。\n在日本期间，受到了北川老师等各位老师的多方关照，实在是非常感谢。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('620406d5-920a-47a7-95da-6ac988afea7b', '38bbd04f-c4e2-48e8-aff2-bf15a506c250', 'わたしたちの町にはこのお寺をはじめ、いろいろな古い建物がある。', 'わたしたちのまちにはこのおてらをはじめ、いろいろなふるいたてものがある。', '在我们的城镇里，以这座寺庙为代表，有很多古老的建筑。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('e6a1b845-988c-4649-ac57-ff09fed5c588', '38bbd04f-c4e2-48e8-aff2-bf15a506c250', '首相をはじめとする代表団がアメリカを訪問した。', 'しゅしょうだいひょうだんがアメリカをほうもんした。', '以首相为首的代表团访问了美国。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('db3c429f-2c5d-434f-8374-610215251d62', '～んじゃない', NULL, 'N3', '动词辞书形＋んじゃない', '动词辞书形＋んじゃない', '“不是……吗？”。读升调，表示征求对方同意或反问、惊讶。\n“不要……”“不许……”。读降调，表示禁止对方的某种行为。', '是「～のではないか」的口语表达方式。\n「～んじゃない」多为男性使用，女性多使用礼貌体「～んじゃありません」。相当于「～するな/～してはいけない」', 502, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('8ff5cc21-37e8-4e5d-ac71-c04da8d7398e', 'db3c429f-2c5d-434f-8374-610215251d62', 'A「このテレビ、ずいぶん古いね。」B「15年前に買ったんだ。」A「えっ？15年前？そろそろ買い替えてもいいんじゃない？」B「まだ見られるから、必要ないよ。」', 'A「このテレビ、ずいぶんふるいね。」B「15ねんまえにかったんだ。」A「えっ？15ねんまえ？そろそろかいかえてもいいんじゃない？」B「まだみられるから、ひつようないよ。」', 'A：“这部电视机很旧了嘛。”\nB：“是15年前买的了。”\nA：“啊!15年前？是不是该换新的了。”\nB：“还可以看的，没必要啦。”', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('2a9d4552-79c9-4b7e-a0ee-7c67220fa756', 'db3c429f-2c5d-434f-8374-610215251d62', 'あそこに座っている人、鈴木さんなんじゃない？', 'あそこにすわっているひと、すずきさんなんじゃない？', '坐在那儿的人，不是铃木吗？', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('6d832fec-6215-4f38-991f-66157bae79df', 'db3c429f-2c5d-434f-8374-610215251d62', '由紀ちゃんのことが好きなんじゃない？正直に言って。', 'ゆきちゃんのことがすきなんじゃない？しょうじきにいって。', '你不是喜欢由纪吗？那就直接告诉她呀。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('2407f1ed-cdc6-447d-97ac-9d84119188fe', 'db3c429f-2c5d-434f-8374-610215251d62', '部長は京都へ行ったんじゃない？', 'ぶちょうはきょうとへいったんじゃない？', '部长不是去京都了吗？', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('a837201a-9f5a-497f-b16a-5deafcda9434', 'db3c429f-2c5d-434f-8374-610215251d62', '勝手に人の日記を読むんじゃない。', 'かってにひとのにっきをよむんじゃない。', '不要擅自读别人的日记。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('19f9e417-d6ca-4ed8-9315-9b9a6f89a8b0', 'db3c429f-2c5d-434f-8374-610215251d62', '一日中テレビばかりを見るんじゃありませんよ。', 'いちにちじゅうテレビばかりをみるんじゃありませんよ。', '不要整天光看电视。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('da593187-b8bc-4ac7-ba75-f4de6d9c9e45', 'お/ご～です', NULL, 'N3', 'お＋Ⅰ类动词、Ⅱ类动词「ます形」＋です', 'お＋Ⅰ类动词、Ⅱ类动词「ます形」＋です\nお/ご＋Ⅲ类动词词干＋です', '尊他语的固定表达形式。', '用法比较受限制，常用于一些固定的用法。', 503, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('3f477ed2-9d9c-4187-9e9a-e14f623fa20c', 'da593187-b8bc-4ac7-ba75-f4de6d9c9e45', '社長がお呼びです。', 'しゃちょうよびです。', '社长叫您（去一趟）。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('8250123b-e1a8-41f2-aade-be3739a1fc6d', 'da593187-b8bc-4ac7-ba75-f4de6d9c9e45', '部長、お帰りですか。', 'ぶちょうかえりですか。', '部长，您这就要回去了吗？', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('50b78cae-98d7-43f5-ba96-e9602db74964', 'da593187-b8bc-4ac7-ba75-f4de6d9c9e45', '田中教授は午後の会議にご欠席ですか。', 'たなかきょうじゅはごごのかいぎけっせきですか。', '田中教授不出席下午的会议吗？', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('ad95c83f-905c-4e7c-a2b5-290c42fc35f2', 'お/ご～になれる', NULL, 'N3', 'お＋Ⅰ类动词、Ⅱ类动词「ます形」＋になれる', 'お＋Ⅰ类动词、Ⅱ类动词「ます形」＋になれる\nご＋Ⅲ类动词词干＋になれる', '“您能够……”“您可以……”，尊他语的固定表达形式「お/ご～になる」的可能形。', NULL, 504, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('1724ec53-59e0-4783-8010-5cd3b8791f69', 'ad95c83f-905c-4e7c-a2b5-290c42fc35f2', 'グリーン車だとゆっくりお座りになれます。', 'グリーンしゃすわりになれます。', '坐软座车厢的话能更宽敞舒适一些。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('8b3115e7-cbc5-43b6-acc6-ebda362f4448', 'ad95c83f-905c-4e7c-a2b5-290c42fc35f2', '市民図書館は祝日でも通常どおりにご利用になれます。', 'しみんとしょかんはしゅくじつでもつうじょうりようになれます。', '市民图书馆在节假日也照常开放。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('dd73fa62-e140-4962-827d-c11a07bf21c1', '～ていらっしゃる/ておいでになる', NULL, 'N3', '～ていらっしゃる/ておいでになる', '～ていらっしゃる/ておいでになる', '是「～です/である/ている/てくる/ていく」等句型的尊他语的表达方式。', NULL, 505, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('194fd373-874d-44c3-9077-25cadb5a0a4b', 'dd73fa62-e140-4962-827d-c11a07bf21c1', '（田中先生の研究室で）学生「田中先生はいらっしゃいますか。」秘書「今、ほかの学生と話していらっしゃいますから、少々お待ちください。」', '（たなかせんせいのけんきゅうしつで）がくせい「たなかせんせいはいらっしゃいますか。」ひしょ「いま、ほかのがくせいとはなしていらっしゃいますから、しょうしょうおまちください。」', '（在田中老师的研究室）学生：“请问田中老师在吗？”\n秘书：“田中老师现在正在和其他学生谈话，请稍等一会儿。”', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('86275ec4-e3d4-4898-9fd3-28de46895296', 'dd73fa62-e140-4962-827d-c11a07bf21c1', 'お久しぶりです。お元気でいらっしゃいますか。', 'おひさしぶりです。おげんきでいらっしゃいますか。', '好久不见，您还好吗？', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('0c226b6b-f49f-45eb-90dd-036c1ebeb07f', 'dd73fa62-e140-4962-827d-c11a07bf21c1', '佐藤教授は東アジアの経済について研究しておいでになります。', 'さとうきょうじゅはひがしアジアのけいざいについてけんきゅうしておいでになります。', '佐藤教授在研究东亚经济。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('b15733dd-613d-4996-abe7-bbf9e315b094', 'お/ご～できる', NULL, 'N3', 'お＋Ⅰ类动词、Ⅱ类动词「ます形」＋できる', 'お＋Ⅰ类动词、Ⅱ类动词「ます形」＋できる\nお/ご＋Ⅲ类动词词干＋できる', '“可以……”“能够……”，是自谦语的可能形的表达方式。', NULL, 506, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('8581dee6-1b86-4d22-989d-bed3f0edc123', 'b15733dd-613d-4996-abe7-bbf9e315b094', 'あの先生は気軽にご相談できる方です。', 'あのせんせいはきがるそうだんかたです。', '那位老师是可以轻松进行商量的人。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('745f6ae9-7883-41f5-be7a-b076b1cc00c1', 'b15733dd-613d-4996-abe7-bbf9e315b094', '着物の試着をご体験できる場所を探しています。', 'きもののしちゃくたいけんばしょをさがしています。', '在找可以体验和服试穿的地方。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('6dd80906-6765-4ba3-8c69-0e6c851f2ec4', 'b15733dd-613d-4996-abe7-bbf9e315b094', '今週末ならご注文の品をお宅までお届けできますが、いかがでしょうか。', 'こんしゅうまつならごちゅうもんのしなをおたくとどけできますが、いかがでしょうか。', '这个周末的话，我们能够将您订购的商品配送到府上，您觉得如何呢？', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('5c453951-4f43-4753-ba0f-4c5727976c2a', 'お/ご～いただく', NULL, 'N3', 'お＋Ⅰ类动词、Ⅱ类动词「ます形」＋いただく', 'お＋Ⅰ类动词、Ⅱ类动词「ます形」＋いただく\nご＋Ⅲ类动词词干＋いただく', '“承蒙您……”“承请您……”。是自谦用语的固定表达方式，表示对别人行为的感谢。', NULL, 507, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('3a64f63e-2468-4a87-a8bf-e2bd09a4e1c0', '5c453951-4f43-4753-ba0f-4c5727976c2a', 'この度、お招きいただきまして、ありがとうございます。', 'このたびまねきいただきまして、ありがとうございます。', '感谢您之前的款待。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('c127b3d8-f924-4f60-82db-c6a3ddbc4d50', '5c453951-4f43-4753-ba0f-4c5727976c2a', 'この書類を佐藤さんにお渡しいだだきたいんですが。', 'このしょるいをさとうわたしいだだきたいんですが。', '想拜托您把这份文件交给佐藤。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('00be9789-2837-4033-aecd-d35dbcc91eae', '5c453951-4f43-4753-ba0f-4c5727976c2a', '中村先生にはぜひご出席いただきたく、ご連絡いたしました。', 'なかむらせんせいしゅっせきいただきたく、ごれんらくいたしました。', '我联系中村老师了，请他务必出席。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('046cd599-8b64-4b22-972d-818791624240', 'お/ご～ 願[ねが]う', NULL, 'N3', 'お＋Ⅰ类动词、Ⅱ类动词「ます形」＋ 願[ねが]う', 'お＋Ⅰ类动词、Ⅱ类动词「ます形」＋ 願[ねが]う\nご＋Ⅲ类动词词干＋ 願[ねが]う', '“能否请您……”，表示委婉的请求。常用「お/ご～ 願[ねが]えませんか/ 願[ねが]えないでしょうか」的形式。', NULL, 508, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('fc00384b-089f-45a8-93fc-213a1c238386', '046cd599-8b64-4b22-972d-818791624240', '先生に推薦状をお書き願います。', 'せんせいにすいせんじょうかねがいます。', '承请老师给我写推荐信。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('79e2c6e0-5fa8-4542-95e0-be7bca9795ba', '046cd599-8b64-4b22-972d-818791624240', 'すみません、これを社長にお渡し願いたいですが。', 'すみません、これをしゃちょうわたねがいたいですが。', '不好意思，劳烦您将这个交给社长。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('71ce1c48-5550-486a-974f-576b2b095268', '046cd599-8b64-4b22-972d-818791624240', '来月の結婚式にご出席願いたいのですが、ご都合はいかがでしょうか。', 'らいげつのけっこんしきしゅっせきねがいたいのですが、ごつごうはいかがでしょうか。', '我想请您参加下个月的结婚典礼，您有空吗？', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('ad339391-283f-4794-ab26-7fbe0d71da07', '～ていただけますか', NULL, 'N3', '动词「て形」＋いただけますか', '动词「て形」＋いただけますか', '“请您……”。表示请求对方为自己做某事。', '「～ていただけないでしょうか」是比「～ていただけませんか」更谦虚的表达方式。', 509, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('16e37e74-eaf3-4ccf-a0cc-862da265e5a3', 'ad339391-283f-4794-ab26-7fbe0d71da07', '学生「先生、日本語で文章を書いたんですが、わたしの作文を見ていただけませんか。」先生「ええ、いいですよ。」', 'がくせい「せんせい、にほんごでぶんしょうをかいたんですが、わたしのさくぶんをみていただけませんか。」せんせい「ええ、いいですよ。」', '学生：“老师，我用日语写了一篇作文，能请您帮我看一下吗？”\n老师：“好的，可以啊。”', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('3cd7fd4a-c9f8-4a8a-9fab-4b733bcf340a', 'ad339391-283f-4794-ab26-7fbe0d71da07', 'これ、贈り物にしたいんですが、包んでいただけますか。', 'これ、おくりものにしたいんですが、つつんでいただけますか。', '这是送人的礼物，麻烦您包装一下。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('a4ee5784-216b-4e98-b48d-38dd1b83c96d', '～てもよろしいでしょうか', NULL, 'N3', '动词「て形」＋もよろしいでしょうか', '动词「て形」＋もよろしいでしょうか', '“……可以吗？”“……行吗？”。表示委婉的询问、请求。', NULL, 510, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('9018ec2b-cd80-4dcc-8907-593428e7e2a2', 'a4ee5784-216b-4e98-b48d-38dd1b83c96d', 'お客様、このお皿をさげてもよろしいでしょうか。', 'おきゃくさま、このおさらをさげてもよろしいでしょうか。', '客人您好，这个盘子我可以撤下去了吗？', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('e62a27a8-26d2-4a8b-9f68-9a0fdc6497e9', 'a4ee5784-216b-4e98-b48d-38dd1b83c96d', '先生、ちょっと体調が崩れて、午後の授業は早退させていただいてもよろしいでしょうか。', 'せんせい、ちょっとたいちょうがくずれて、ごごのじゅぎょうはそうたいさせていただいてもよろしいでしょうか。', '老师，我有点不舒服，下午的课我可以先回去吗？', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('eddce58a-80de-4a0e-b73e-789840b43491', 'a4ee5784-216b-4e98-b48d-38dd1b83c96d', 'すみません、ちょっと辞書を借りてもよろしいでしょうか。', 'すみません、ちょっとじしょをかりてもよろしいでしょうか。', '不好意思，可以借用一下您的词典吗？', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('a36afc6a-7a54-41b7-ac83-12b9f93863d6', '～（さ）せていただく', NULL, 'N3', 'Ⅰ类动词「ない形」＋せていただく', 'Ⅰ类动词「ない形」＋せていただく\nⅡ类动词「ない形」＋させていただく\nⅢ类动词：（～）する→（～）させていただく； 来[く]る→ 来[こ]させていただく', '“请让我……”“请允许我……”。自谦用语的固定表达形式，表示请求上级或者长辈允许自己做什么事情。', NULL, 511, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('224cf86d-aa8f-4c3a-add3-981588e1b6b6', 'a36afc6a-7a54-41b7-ac83-12b9f93863d6', '（メールで）田中です。先日お話があったスピーチの件なんですが、ぜひわたしにやらせていただけないでしょうか。', '（メールで）たなかです。せんじつおはなしがあったスピーチのけんなんですが、ぜひわたしにやらせていただけないでしょうか。', '（邮件中）我是田中。有关前些天说到的演讲的事情，能否请您让我来做呢？', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('b83c7116-7885-4a53-8aa1-3974cba71c24', 'a36afc6a-7a54-41b7-ac83-12b9f93863d6', '資料をコピーしたいんですが、コピー機を使わせていただいてもよろしいですか。', 'しりょうをコピーしたいんですが、コピーきをつかわせていただいてもよろしいですか。', '我想要复印资料，能让我用一下复印机吗？', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('4725a0af-b134-4112-8252-50c38e1b3b8a', 'a36afc6a-7a54-41b7-ac83-12b9f93863d6', 'ドアのとこに私のかさを置かせていただいてもいいですか。', 'ドアのとこにわたしのかさをおかせていただいてもいいですか。', '我能把我的伞放在门口吗？', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('5a351100-de62-4a6a-9c1f-41f3c6b4d3ec', '敬语的特殊形式', NULL, 'N3', '敬语的特殊形式', '敬语的特殊形式', NULL, NULL, 512, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('22e7f0a7-ff79-4424-b936-0d740539eb69', '5a351100-de62-4a6a-9c1f-41f3c6b4d3ec', 'わたしたちは、先生にプレゼントを用意して、最後の授業の日にさしあげる計画を立てています。', 'わたしたちは、せんせいにプレゼントをよういして、さいごのじゅぎょうのひけいかくをたてています。', '我们为老师准备了礼物，准备最后上课的那一天送上。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('9a8bbf3f-7dfc-4e6f-8241-66670948f3ab', '5a351100-de62-4a6a-9c1f-41f3c6b4d3ec', '先生は山下さんのご住所をご存知ですか。', 'せんせいはやましたさんのごじゅうしょぞんじですか。', '老师您知道山下住在哪里吗？', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('67d5f726-92bc-4f16-8b72-9214b5b33f83', '5a351100-de62-4a6a-9c1f-41f3c6b4d3ec', 'どなたか質問のある方はいらっしゃいませんか。', 'どなたかしつもんのあるかたはいらっしゃいませんか。', '谁有疑问吗？', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('d8c7f7ec-b209-476d-ae0a-121bcea059fe', '5a351100-de62-4a6a-9c1f-41f3c6b4d3ec', '意見がある方は、おっしゃってください。', 'いけんがあるかたは、おっしゃってください。', '有意见的人，请发言。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('023f3e0b-c116-499e-a768-150214c0e354', '5a351100-de62-4a6a-9c1f-41f3c6b4d3ec', 'A「先生はいつ見えますか。」B「まだおいでになるまで少し時間がありますから、そこで待っていてください。」', 'A「せんせいみえますか。」B「まだおいでになるまですこしじかんがありますから、そこでまっていてください。」', 'A：“老师什么时候来？”\nB：“老师来还需要一些时间，请在那里稍等一下。”', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('b4303aca-9c33-4f48-b548-ea6c525994dc', '5a351100-de62-4a6a-9c1f-41f3c6b4d3ec', '山口「中川先生。」中川先生「あ、山口さん。偶然ですね。」山口「はい。わたしもこのパーティーで先生にお目にかかれるとは思いませんでした。」', 'やまぐち「なかがわせんせい。」なかがわせんせい「あ、やまぐちさん。ぐうぜんですね。」やまぐち「はい。わたしもこのパーティーでせんせいめにかかれるとはおもいませんでした。」', '山口：“中川老师。”\n中川老师：“啊，是山口啊。真巧啊。”\n山口：“是啊，我也没想到在这个聚会上能碰到老师。”', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('328e28f5-d86e-4a50-af4a-3ddc60ccd338', '5a351100-de62-4a6a-9c1f-41f3c6b4d3ec', '学生「先生、ご相談したいことがあるのですが、授業の後、先生の研究室にうかがってもよろしいでしょうか。」先生「はい。いいですよ。」', 'がくせい「せんせい、ごそうだんしたいことがあるのですが、じゅぎょうのあと、せんせいのけんきゅうしつにうかがってもよろしいでしょうか。」せんせい「はい。いいですよ。」', '学生：“老师，我有事想和您商量，下课之后我能去您的研究室拜访吗？”\n老师：“好的。可以。”', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('58eb9667-c636-408b-bcc0-f8b7a880b8e5', '5a351100-de62-4a6a-9c1f-41f3c6b4d3ec', '客「すみません、コーヒーとサンドイッチをお願いします。」店員「はい、かしこまりました。」', 'きゃく「すみません、コーヒーとサンドイッチをおねがいします。」てんいん「はい、かしこまりました。」', '客人：“麻烦你，我要咖啡和三明治。”\n店员：“好的，我知道了。”', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('6e7e24df-e47e-42f5-8dea-74c01d9e149c', '5a351100-de62-4a6a-9c1f-41f3c6b4d3ec', '私は、先生のお宅でおいしいお酒をいただきました。', 'わたしは、せんせいのおたくでおいしいおさけをいただきました。', '我在老师家里喝到了美味的酒。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('6c430252-7a25-4d9f-be2d-efae8b687951', '5a351100-de62-4a6a-9c1f-41f3c6b4d3ec', 'A「どうぞご覧ください。」B「では、拝見します。」', 'A「どうぞごらんください。」はいけんします。」', 'A：“请过目。”\nB：“好的，那我看一下。”', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('6068731d-fdd9-489d-94c2-3e976202eb6d', '～ず（に）', NULL, 'N4', '动词「ない形」＋ず（に）', '动词「ない形」＋ず（に）\n（～）する→（～）せず（に）', '“不……，没……”；“因为没有……而……”。表示对动作状态的否定或者表示原因。', '「～ず」表示否定，主要用于书面语，相当于「～なくて（表示原因）」或「～ないで（表示动作、状态的否定）」。「～ずに」相当于「～ないで（表示动作、状态的否定）」。', 513, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('b1af7ebc-2323-48e9-8282-37b23ce78754', '6068731d-fdd9-489d-94c2-3e976202eb6d', '昨日は忙しくて、夜10時まで何も食べずに働いた。', 'きのうはいそがしくて、よるじゅうじまでなにもたはたらいた。', '昨天太忙了，什么都没吃一直工作到晚上十点。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('ba438782-13a8-459e-a212-568e5dc8f82b', '6068731d-fdd9-489d-94c2-3e976202eb6d', '辞書を使わずに日本語の新聞を読むことができますか。', 'じしょをつかにほんごのしんぶんをよむことができますか。', '你不查词典的话能读日语报纸吗？', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('578bf4b4-e9d1-40b0-80fb-f3108005810a', '～たがる', NULL, 'N4', '动词「ます形」＋たがる', '动词「ます形」＋たがる', '“想要……”“愿意……”。', '「～たがる」表示第三人称的要求或愿望；第一人称的情况下使用「～たい」。', 514, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('56b3a66b-f17b-4767-9f18-da243823e26f', '578bf4b4-e9d1-40b0-80fb-f3108005810a', 'A「うちの息子は肉より野菜のほうが好きなんですよ。」B「いいですね。うちの子どもは野菜を食べたがらなくて困っているんですよ。」', 'A「うちのむすこはにくよりやさいのほうがすきなんですよ。」B「いいですね。うちのこどもはやさいをたべたがらなくてこまっているんですよ。」', 'A：“比起肉来我儿子更喜欢吃蔬菜。”\nB：“真好啊。我们家的孩子不想吃蔬菜，真是伤脑筋。”', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('d13b9c3f-500a-4294-8e13-cc3d040b6d7d', '578bf4b4-e9d1-40b0-80fb-f3108005810a', 'A「あの映画、面白そうですね。」B「ええ。わたしの友だちも見たがっています。」', 'A「あのえいが、おもしろそうですね。」B「ええ。わたしのともだちもみたがっています。」', 'A：“那部电影好像很有趣。”\nB：“是的，我的朋友也想看。”', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('68950ee9-de33-4080-b854-a59683a6b68e', '～がる', NULL, 'N4', 'い形容词词干/な形容词词干＋がる', 'い形容词词干/な形容词词干＋がる', '“感到……”“觉得……”。表示第三人称的感情、感受。', '「～がる」属于Ⅰ类动词活用规则变化，其否定形式是「～がらない」。', 515, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('6a95ee0c-c6e5-4c7e-90a4-51cd4dfe8978', '68950ee9-de33-4080-b854-a59683a6b68e', '妹は、最初は「水泳教室に行きたくない」と嫌がっていたが、今では友だちもできて、楽しそうに通っている。', 'いもうとは、さいしょは「すいえいきょうしつにいきたくない」といやがっていたが、いまではともだちもできて、たのしそうにかよっている。', '妹妹刚开始的时候厌恶地说“我不想去游泳培训班”，而现在呢，又交到了朋友，很开心地上着培训班。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('03fed324-2692-4ebb-acd2-3e3e73cf8eee', '68950ee9-de33-4080-b854-a59683a6b68e', '（スーパーで）母親「今、お菓子を買った子がタケルくん？」子ども「違うよ。あそこで泣いて、お菓子を欲しがっている子だよ。」', '（スーパーで）ははおや「いま、おかしをかったこがタケルくん？」こども「ちがうよ。あそこでないて、おかしをほしがっているこだよ。」', '母亲：“刚刚买了点心的小孩是小武吗？”\n儿子：“不是啊，小武是那边那个哭着要点心的小孩。”', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('5e340543-14de-4c16-9974-274f13fef46d', '～そうだ', NULL, 'N4', '句子普通形＋そうだ', '句子普通形＋そうだ', '“听说……”“据说……”。是传闻助动词。\n“好像……”“似乎……”“眼看就要……”。是样态助动词。', '「～そうだ」表示间接获得的信息，因此不能用否定式和过去时；如果要表示否定的意思，则应该在「～そうだ」前面的内容上加否定形式。且传闻助动词「～そうだ」经常与表示信息来源的「～によると/によれば/の 話[はなし]では」等搭配使用。\n「～そうだ」表示说话人根据自己的所见所闻而做出的判断，所以不能接视觉上的直接评价，如「きれい」等。「いい」和「ない」接「～そうだ」的形式比较特殊，分别为「よさそうだ」和「なさそうだ」。', 516, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('d7eb2196-9fa4-4893-a69d-9d78fb20d780', '5e340543-14de-4c16-9974-274f13fef46d', '来週うちの近くでお祭りがあるそうです。', 'らいしゅううちのちかくでおまつりがあるそうです。', '据说下周在我家附近有庙会。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('773cec28-44b6-4436-b868-372ff7264d8b', '5e340543-14de-4c16-9974-274f13fef46d', '友だちによると、去年の試験は簡単だったそうです。', 'ともだちによると、きょねんのしけんはかんたんだったそうです。', '据朋友说，去年的考试很简单。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('2e5e2847-90b5-48a4-abbd-bed84905d694', '5e340543-14de-4c16-9974-274f13fef46d', '友だちの話では新しい辞書はとてもいいそうです。', 'ともだちのはなしではあたらしいじしょはとてもいいそうです。', '听朋友说新的字典很不错。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('280ec870-c053-480b-aa87-df52831755ef', '5e340543-14de-4c16-9974-274f13fef46d', '山田先生はいつも難しそうな本を読んでいます。', 'やまだせんせいはいつもむずかほんをよんでいます。', '山田老师总在看貌似很晦涩难懂的书。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('272fdd2d-3c81-4566-80bd-3baa259a44ff', '5e340543-14de-4c16-9974-274f13fef46d', '石田さんが忙しそうだから、手伝いましょう。', 'いしださんがいそがしそうだから、てつだいましょう。', '石田看上去很忙，我们帮帮他吧。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('c2be1409-fa68-45d7-a698-f813e161d6a9', '5e340543-14de-4c16-9974-274f13fef46d', 'ポケットから財布が落ちそうだよ。', 'ポケットからさいふがおちそうだよ。', '钱包快从口袋里掉出来了。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('7796c464-15d9-4704-8be0-8c6d594d973e', '～ようだ', NULL, 'N4', '～ようだ', '～ようだ', '“像……一样”“宛如……”。表示比喻。\n“像……那样”。表示举例、列举。\n“好像……”“似乎……”。表示主观推测，带有不确定的语气。', NULL, 517, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('9fac3fd3-cf58-491f-90d5-04005f373040', '7796c464-15d9-4704-8be0-8c6d594d973e', '母ははじめて飛行機に乗って、子どものように喜んだ。', 'ははははじめてひこうきにのって、こよろこんだ。', '妈妈第一次坐飞机，高兴得像个孩子。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('da8aa556-e1e6-4e6d-a58c-fa3d78de05d6', '7796c464-15d9-4704-8be0-8c6d594d973e', '彼女の笑顔は太陽のように明るく輝いている。', 'かのじょのえがおはたいようあかるくかがやいている。', '她笑得像太阳那么灿烂。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('fefe3318-4c70-4010-8cf1-c64cc8a7d393', '7796c464-15d9-4704-8be0-8c6d594d973e', 'みんなが子どものように元気に歌い始めた。', 'みんながこげんきにうたいはじめた。', '大家像孩子般精神饱满地唱了起来。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('19252035-763b-4c21-a4db-62bda92d8669', '7796c464-15d9-4704-8be0-8c6d594d973e', 'わたしは田中さんのような優しい人が好きです。', 'わたしはたなかやさしいひとがすきです。', '我喜欢像田中那样温柔的人。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('94136bd6-13b3-4746-a29c-f419afa0820d', '7796c464-15d9-4704-8be0-8c6d594d973e', 'あの時はしかたなかったのだが、彼を怒らせるようなことを言ってしまって悪かったと思った。', 'あのときはしかたなかったのだが、かれをおこらせるようなことをいってしまってわるかったとおもった。', '那时候是没有办法，不过似乎说了使他生气的话，所以觉得很不好意思。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('da5080fc-637e-4a59-87f7-4b94ce18eedc', '7796c464-15d9-4704-8be0-8c6d594d973e', '先週は図書館が休みだったようだ。', 'せんしゅうはとしょかんがやすみだったようだ。', '上周图书馆好像闭馆。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('23f9c073-efc9-4b53-8693-9033b5129caf', '～らしい', NULL, 'N4', '名词＋らしい', '名词＋らしい', '“好像……”。表示根据各种客观情况、传闻做出可能性很高的推测、判断。\n“像……似的”“地道的……”。「らしい」属于い形容词活用，接在名词后面，表示主体充分具备了「～らしい」前面的名词应该具有的特点、性质、风格等。', '「～らしい」常与副词「どうも」（似乎）、「どうやら」（大概）搭配使用。\n「～らしく」为连用修饰，后面接动词或形容词；「～らしい」后面接名词充当连体修饰语或直接用于结句。', 518, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('0574227b-33dc-4bf1-8b61-5190987b5d5b', '23f9c073-efc9-4b53-8693-9033b5129caf', '二人は来年結婚するらしいです。', 'ふたりはらいねんけっこんするらしいです。', '他们两个人好像明年结婚。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('db1494ed-51c8-498e-bac6-e95eafbbf4f2', '23f9c073-efc9-4b53-8693-9033b5129caf', '明日はいい天気らしい。', 'あしたはいいてんきらしい。', '明天似乎天气不错。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('79d1d11b-e6d1-4399-ac6b-59485f0a31ca', '23f9c073-efc9-4b53-8693-9033b5129caf', 'この家には誰もいないらしく、いつ行っても静かだ。', 'このうちにはだれもいないらしく、いついってもしずかだ。', '这个房子里好像没人住，无论什么时候去都很安静。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('aa42c4e2-15e6-4492-b868-8c42aa5b6a40', '23f9c073-efc9-4b53-8693-9033b5129caf', '学生らしくもっと勉強しなさい。', 'がくせいらしくもっとべんきょうしなさい。', '要更加努力学习，像个学生的样子。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('b4bd0a7c-60d9-4b5a-8dcd-65187ac3cbc1', '23f9c073-efc9-4b53-8693-9033b5129caf', '日本語らしい日本語を身につけたい。', 'にほんごにほんごをみにつけたい。', '我想掌握地道的日语。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('696c3266-6dc4-4c76-a49d-4833ddf222f5', '23f9c073-efc9-4b53-8693-9033b5129caf', '今日は涼しくて、秋らしい天気です。', 'きょうはすずしくて、あきてんきです。', '今天很凉爽，像是秋天了。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('2b2a04f3-f5f1-4240-bcea-f074f48ae1e7', '～みたいだ', NULL, 'N4', '～みたいだ', '～みたいだ', '“好像……”“似乎……”。表示说话人通过分析自己所感知的信息做出的主观判断，多用于口语。\n“像……一样”“宛如……”。表示比喻，经常和副词「まるで」等搭配使用。其活用形式与な形容词相同，主要用于口语。\n“像……那样”，表示列举。', NULL, 519, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('23f80646-593f-4172-9b42-7284da160552', '2b2a04f3-f5f1-4240-bcea-f074f48ae1e7', '誰か教室にいるみたいだ。電気が付いている。', 'だれかきょうしつにいるみたいだ。でんきがついている。', '好像教室里有人。灯开着呢。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('3cede157-730a-4bc2-abd3-36fe6dedae64', '2b2a04f3-f5f1-4240-bcea-f074f48ae1e7', '新しいカメラは高画質みたいだ。', 'あたらしいカメラはこうがしつみたいだ。', '新的相机似乎是高清画质。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('2de1efde-ae63-4d15-a412-6e3a47a69ece', '2b2a04f3-f5f1-4240-bcea-f074f48ae1e7', 'あの雲の形はまるで馬みたいだね。', 'あのくものかたちうまみたいだね。', '那片云的形状真像一匹马啊！', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('e436461e-c556-4c2b-a429-02b8d413d853', '2b2a04f3-f5f1-4240-bcea-f074f48ae1e7', '赤ちゃんはりんごみたいな顔をしている。', 'あかかおをしている。', '婴儿的脸蛋儿像苹果似的。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('69524ac4-e9b2-419c-ae90-b125c9fb649f', '2b2a04f3-f5f1-4240-bcea-f074f48ae1e7', '10キロも痩せた彼女はまるで別人みたいになっている。', 'じゅっキロもやせたかのじょはまるでべつじんみたいになっている。', '她瘦了十公斤，看起来都不像她了。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('6150b0de-da69-48d4-b442-2a60c5eceae9', '2b2a04f3-f5f1-4240-bcea-f074f48ae1e7', '妹は、体操の選手みたいに体が柔らかい。', 'いもうとは、たいそうのせんしゅからだがやわらかい。', '妹妹身体的柔韧性很好，像体操运动员一样。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('b38da210-7287-444c-86ee-066f4ecae825', '2b2a04f3-f5f1-4240-bcea-f074f48ae1e7', '大きくなったら、イチローさんみたいな野球選手になりたいです。', 'おおやきゅうせんしゅになりたいです。', '长大之后，我想成为像一郎那样的棒球运动员。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('f4713311-e33e-4092-94d0-8284d7f29bec', '可能助动词「れる/られる」', NULL, 'N4', 'Ⅰ类动词把词尾改为同行「え段」假名＋る', 'Ⅰ类动词把词尾改为同行「え段」假名＋る\nⅡ类动词「ない形」＋られる\nⅢ类动词：（～）する→（～）できる； 来[く]る→ 来[こ]られる', '“能……”“会……”“可以……”。', '表示具有某种能力或可能性，前面的助词一般用「が」。', 520, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('8e19c6b4-fd52-46f8-aab8-36c7f8b55207', 'f4713311-e33e-4092-94d0-8284d7f29bec', 'この店で日本のお金が使えますか。', 'このみせでにほんのおかねつかえますか。', '这家店可以用日元吗？', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('7c004ef4-5a1e-4d36-be1c-654240b7e0e8', 'f4713311-e33e-4092-94d0-8284d7f29bec', 'この辞書で漢字の読み方が調べられます。', 'このじしょでかんじのよみかたしらべられます。', '这本词典可以查汉字的读音。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('4ed20d0e-39ff-4bd9-8638-5fae5c97a1a0', '使役助动词「せる/させる」', NULL, 'N4', 'Ⅰ类动词「ない形」＋せる', 'Ⅰ类动词「ない形」＋せる\nⅡ类动词「ない形」＋させる\nⅢ类动词：（～）する→（～）させる； 来[く]る→ 来[こ]させる', '“让……”“使……”。', '使役表示让某人去做某事，在实际的使用中也表示强制命令、指示等意思。', 521, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('4dc08492-ee83-4cb5-b93f-9b2a0bba370a', '4ed20d0e-39ff-4bd9-8638-5fae5c97a1a0', 'A「娘が留学に行きたいって言うんですが、いろいろと心配で、わたしは反対なんです。」B「心配でしょうけど、いい経験になると思うから、行かせてあげたらどうですか。」', 'A「むすめがりゅうがくにいきたいっていうんですが、いろいろとしんぱいで、わたしははんたいなんです。」B「しんぱいでしょうけど、いいけいけんになるとおもうから、いかせてあげたらどうですか。」', 'A：“我女儿说想要去留学，但我很担心，反对她去。”\nB：“我理解你的担心，但是我觉得留学会成为很好的经历，所以让她去吧，怎么样？”', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('6d8afeaf-3dcd-4af7-95d4-37c2255aae6a', '4ed20d0e-39ff-4bd9-8638-5fae5c97a1a0', '（会社の説明会で）会社の人「これで、私からの説明は終わりますが、質問がある人はいますか。」学生「はい、二つ、質問させてください。」', '（かいしゃのせつめいかいで）かいしゃのひと「これで、わたしからのせつめいはおわりますが、しつもんがあるひとはいますか。」がくせい「はい、ふたつ、しつもんさせてください。」', '公司人员：“我的说明到此为止，有什么问题吗？”\n学生：“有，请允许我问两个问题。”', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('588c1f6e-4acc-4198-b0eb-9aa2345a9894', '被动助动词「れる/られる」', NULL, 'N4', 'Ⅰ类动词「ない形」＋れる', 'Ⅰ类动词「ない形」＋れる\nⅡ类动词「ない形」＋られる\nⅢ类动词：（～）する→（～）される； 来[く]る→ 来[こ]られる', '“被……”“受到……”。主语是人的直接被动句，动作的承受者用「は」表示，动作的发出者用「に」或「から」表示。\n带宾语的间接被动句。被动者作主语用「は」表示，主语在句中可省略；受到影响的事物用「を」表示。\n自动词构成的间接被动句。被动者用「は」表示，动作的发出者用「に」表示。这类被动句的特点是谓语动词是自动词，其动作间接地给主语带来不良的影响。\n主语是事或物的直接被动句。主要用于描写客观事实或新闻报道。这类句型主语一般被省略，或者用「～によって」来表示。', NULL, 522, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('7067d924-bb91-4181-a911-eca1214e25f7', '588c1f6e-4acc-4198-b0eb-9aa2345a9894', '今日わたしは先生に褒められました。', 'きょうわたしはせんせいほめられました。', '今天我被老师表扬了。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('dd862c45-2b75-4da5-bd78-4fde9f4fd544', '588c1f6e-4acc-4198-b0eb-9aa2345a9894', '田中さんは会議に遅れて、社長に注意されました。', 'たなかさんはかいぎにおくれて、しゃちょうちゅういされました。', '田中开会迟到，被社长警告了。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('83a270fb-2673-42f1-b13f-569d0d4a22dd', '588c1f6e-4acc-4198-b0eb-9aa2345a9894', 'このメールを誰かに見られると困る。', 'このメールをだれみられるとこまる。', '这封邮件如果被谁看到的话，就麻烦了。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('aa98724f-14b0-4d59-a0d1-14382ad95106', '588c1f6e-4acc-4198-b0eb-9aa2345a9894', 'わたしはルームメートに日記を見られた。', 'わたしはルームメートににっきみられた。', '我的日记被室友看了。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('c6377c7b-0e29-4cbf-baa3-887589286667', '588c1f6e-4acc-4198-b0eb-9aa2345a9894', '父もわたしも、今日は傘がなくても大丈夫だろうと思って出かけたのだが、帰りは雨に降られてしまった。', 'ちちもわたしも、きょうはかさがなくてもだいじょうぶだろうとおもってでかけたのだが、かえりはあめふられてしまった。', '爸爸和我都觉得今天不带伞也没关系便出门了，结果在回家的路上都被雨淋了。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('a5f372e7-5401-4a8c-bd22-b136c6f2c2e4', '588c1f6e-4acc-4198-b0eb-9aa2345a9894', '父に入院されて、わたしは困っています。', 'ちちにゅういんされて、わたしはこまっています。', '父亲住院了，我很伤脑筋。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('41017148-7032-4b58-944e-7f6060948bb4', '588c1f6e-4acc-4198-b0eb-9aa2345a9894', '明日、もし雨が降ったとしても、予定されているスポーツ大会は行います。', 'あした、もしあめがふよていされているスポーツたいかいはおこないます。', '明天即使下雨，计划好的运动会也会举行。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('17df57eb-a0ad-4fce-96df-e9d0541af48b', '588c1f6e-4acc-4198-b0eb-9aa2345a9894', '最近は日本の漫画がいろいろな国で読まれています。', 'さいきんはにほんのまんががいろいろなくによまれています。', '最近很多国家的人都在看日本的漫画。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('7fc3573d-2533-4f41-b690-60c0f3e01855', '使役被动助动词「される/させられる」', NULL, 'N4', 'Ⅰ类动词「ない形」＋される/せられる', 'Ⅰ类动词「ない形」＋される/せられる\nⅡ类动词「ない形」＋させられる\nⅢ类动词：（～）する→（～）させられる； 来[く]る→ 来[こ]させられる', '“被迫……”。强调主体并非出于自身意愿，而是迫于压力或无奈“不得不”做某事。', '使役被动表示受到强迫而做某事。', 523, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('87730061-2bb0-4ca1-a9ec-fb1f51b94354', '7fc3573d-2533-4f41-b690-60c0f3e01855', 'お腹が痛くて病院へ行ったら、1時間も待たされた。', 'おなかがいたくてびょういんへいったら、いちじかんまたされた。', '肚子疼去医院，居然让我等了一个小时。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('f825d5fb-4d1a-4b70-a400-d60223fb0e16', '7fc3573d-2533-4f41-b690-60c0f3e01855', 'わたしは、母に買い物に行かせられました。', 'わたしは、ははにかいものいかせられました。', '我被妈妈派去买东西。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('711b63d0-6a5a-407f-b47d-06179f1028aa', '7fc3573d-2533-4f41-b690-60c0f3e01855', '僕は父に謝らせられた。', 'ぼくはちちあやまらせられた。', '我被爸爸逼着道歉。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('6a8ccfa2-d78f-4684-8279-ab5cee9e5f07', '命令助动词「れ/ろ」', NULL, 'N4', 'Ⅰ类动词把词尾改为同行「え段」假名', 'Ⅰ类动词把词尾改为同行「え段」假名\nⅡ类动词「ない形」＋ろ\nⅢ类动词：（～）する→（～）しろ； 来[く]る→ 来[こ]い', '“去做……”。', '命令句主要用于上级对下级或者长辈对晚辈，表示指使别人做某事的强烈语气。', 524, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('03fd9286-0045-4c74-8fd0-91c8484f87d6', '6a8ccfa2-d78f-4684-8279-ab5cee9e5f07', '電車に遅れる。急げ。', 'でんしゃにおくいそげ。', '要赶不上电车了，快点儿。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('6936a3bd-7195-4467-9bc2-d7a83f3ae7fe', '6a8ccfa2-d78f-4684-8279-ab5cee9e5f07', '早く起きろ。学校に遅れるよ。', 'はやおきろ。がっこうにおくれるよ。', '快点起来，上学要迟到了。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('86c83747-7ca5-4285-960c-5a7193685644', '6a8ccfa2-d78f-4684-8279-ab5cee9e5f07', 'テレビを見ないで、勉強しろ。', 'テレビをみないで、べんきょうしろ。', '别看电视了，快去学习。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('92e64dd9-55b7-42fe-a26a-85766ba526b9', '禁止助动词「な」', NULL, 'N4', '动词辞书形＋な', '动词辞书形＋な', '“不准……”。', '「な」用在句末，表示禁止做某事，语气较强。', 525, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('d5aa9a2a-0e6a-4817-9498-aee99781c928', '92e64dd9-55b7-42fe-a26a-85766ba526b9', '「ここにごみを捨てるな！」と書いてある。', '「ここにごみをすてるな！」とかいてある。', '写着“此处严禁扔垃圾！”。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('0662ad4d-febf-4c4d-93e7-0b8a03b92cb9', '92e64dd9-55b7-42fe-a26a-85766ba526b9', 'ここに車を止めるな。邪魔だ。', 'ここにくるまをとめるな。じゃまだ。', '别在这里停车，挡住路了。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('5d6755f5-9100-4f2b-b09f-438a52029302', '～ておく/とく', NULL, 'N4', '动词「て形」＋おく', '动词「て形」＋おく\n动词「て形」＋とく', '“事先……”。', '「～ておく/とく」表示事先做好某事。「～とく」多用于口语。', 526, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('8ba53d8c-5f54-4204-bae6-7396d5d487a5', '5d6755f5-9100-4f2b-b09f-438a52029302', 'あとで捨てるから、ごみを集めておいてください。', 'あとですてるから、ごみをあつめておいてください。', '请把垃圾事先放在一起，之后会拿去扔掉的。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('32683fc2-722f-4db6-8a3f-71c9a50061c3', '5d6755f5-9100-4f2b-b09f-438a52029302', 'お客さんが来るからテーブルの上にお皿を並べておきます。', 'おきゃくさんがくるからテーブルのうえにおさらをならべておきます。', '有客人要来，先在桌子上摆好盘子。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('d18c8712-aa6a-4b56-a7fd-564c3e26de02', '～ていく', NULL, 'N4', '动词「て形」＋いく', '动词「て形」＋いく', '“……而去”。指朝着远离自己的一方而去。\n“……下去”。', '「～ていく」表示空间上远去的状态。\n「～ていく」表示某种状态或行为从现在持续到将来。', 527, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('35d50a5b-e4a8-4df9-b314-7607c57c04ef', 'd18c8712-aa6a-4b56-a7fd-564c3e26de02', '課長「山田さん、明日の会議の資料、もう部長に届けた？」山田「はい、届けました。ついさっき、持っていったところです。」', 'かちょう「やまださん、あしたのかいぎのしりょう、もうぶちょうにとどけた？」やまだ「はい、とどけました。ついさっき、もっていったところです。」', '课长：“山田，明天开会的资料你已经送去给部长了吗？”\n山田：“是的，给了。我刚刚拿过去的。”', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('b98fdda8-06df-4a4d-b58a-7a61dc9923da', 'd18c8712-aa6a-4b56-a7fd-564c3e26de02', '鳥が飛んでいきました。', 'とりがとんでいきました。', '鸟儿飞走了。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('5b848ceb-e254-4a25-aa24-c7f59db0d204', 'd18c8712-aa6a-4b56-a7fd-564c3e26de02', '学校を卒業しても、日本語の勉強を続けていくつもりだ。', 'がっこうをそつぎょうしても、にほんごのべんきょうをつづけていくつもりだ。', '即使毕业了，（我）也打算继续学习日语。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('14bc01e7-1768-4767-94cd-5c1a60c93dc1', 'd18c8712-aa6a-4b56-a7fd-564c3e26de02', '秋になると、だんだん木の葉の色が変わっていく。', 'あきになると、だんだんこのはのいろがかわっていく。', '秋天到了，树叶的颜色也在渐渐转变。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('10e3b31f-1392-4145-8925-4d14deb1d643', '～てくる', NULL, 'N4', '动词「て形」＋くる', '动词「て形」＋くる', '“去去就来”。表示在空间范围内回到原点。\n“朝着这里来”。指朝着靠近自己的一方而来。\n“一直……到现在”。', '「～てくる」表示“去去就来”，即做完某个动作之后再回来。常与「ちょっと」等副词搭配使用，表示离开的距离或时间并不是很长。\n「～てくる」表示空间上靠近的状态。\n「～てくる」以当前这一时间点为基准，着重描述从过去某个时间点到现在说话这个时间点的发展变化，经常以过去时「～てきた」的形式出现。', 528, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('9295081c-fb51-463b-92d1-070ca774e69a', '10e3b31f-1392-4145-8925-4d14deb1d643', 'ちょっと手紙を出してきます。', 'ちょっとてがみをだしてきます。', '（我）寄封信就回来。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('21d6a52b-b8f7-439c-8a3c-055b81eb2c57', '10e3b31f-1392-4145-8925-4d14deb1d643', '近くのスーパーまで行ってきます。', 'ちかくのスーパーまでいってきます。', '（我）去一下附近超市就回来。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('69fcbd19-30a8-4139-ac3c-e0701daab129', '10e3b31f-1392-4145-8925-4d14deb1d643', '（A市場で）「このA市場には、新鮮な野菜が近くの畑からたくさん運ばれてきます。」', '（Aいちばで）「このAいちばには、しんせんなやさいがちかくのはたけからたくさんはこばれてきます。」', '（在A市场）“在A市场有很多新鲜的蔬菜，都是从附近的农地运来的。”', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('495af4b6-da50-45d1-868a-3052d3ea010b', '10e3b31f-1392-4145-8925-4d14deb1d643', '（会社で）内田「高田さんがしている指輪、すごく高そうだよね。」森山「いや、高い指輪だったら、会社にしてこないはずだよ。」', '（かいしゃで）うちだ「たかださんがしているゆびわ、すごくたかそうだよね。」もりやま「いや、たかいゆびわだったら、かいしゃにしてこないはずだよ。」', '内田：“高田戴的戒指看起来很贵呢。”\n森山：“不，要是很贵的戒指，应该不会戴来公司的。”', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('63a623b8-0426-4dde-be9a-7d9fe2a01291', '10e3b31f-1392-4145-8925-4d14deb1d643', 'この伝統は百年も続いてきた。', 'このでんとうはひゃくねんもつづいてきた。', '这个传统到现在已经持续了一百年。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('5e871a1b-9f7c-4595-8937-3686da9d9126', '10e3b31f-1392-4145-8925-4d14deb1d643', '高校生の時からずっと生け花を習ってきた。', 'こうこうせいのときからずっといけばなをならってきた。', '（我）从高中开始就一直学习插花。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('da96a244-c308-463c-85de-bc674ac2d59e', '～てしまう/ちゃう', NULL, 'N4', '动词「て形」＋しまう', '动词「て形」＋しまう\n动词「て形」＋ちゃう', '“……完了”。', '「～てしまう」表示动作已经结束，常与「もう」等副词搭配使用，表示遗憾、懊悔的语气。「～ちゃう」是「～てしまう」在口语中的简略说法。', 529, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('7e5bc782-09df-4994-a499-3a5015f810c9', 'da96a244-c308-463c-85de-bc674ac2d59e', 'あ、大変、急いで来たから財布を忘れちゃった。', 'あ、たいへん、いそいできたからさいふをわすれちゃった。', '啊，糟糕，急匆匆赶过来，结果钱包忘带了。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('3d48b228-0ac4-45d2-a97d-d38c02a73f66', 'da96a244-c308-463c-85de-bc674ac2d59e', 'わたしは、昨日夜の11時に友だちに来られて、困ってしまった。', 'わたしは、きのうよるのじゅういちじにともだちにこられて、こまってしまった。', '昨晚十一点朋友来家里，真让我为难。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('3c260ec3-53b0-47ab-ad4d-b9eb04a7a488', '～てみる', NULL, 'N4', '动词「て形」＋みる', '动词「て形」＋みる', '“试着……看”。', '「～てみる」表示尝试做某事。', 530, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('fd15c3b4-1ec6-4f30-abe3-b880d0896ecb', '3c260ec3-53b0-47ab-ad4d-b9eb04a7a488', '友だちがけがで入院したと聞き、慌てて病院に行ってみると思っていたよりも元気で安心した。', 'ともだちがけがでにゅういんしたときき、あわててびょういんにいってみるとおもっていたよりもげんきであんしんした。', '我听说朋友受伤住院了，急忙到医院去看他，发现他比想象中精神，我也就放心了。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('6e891cbc-888b-434e-bf42-a834f24029be', '3c260ec3-53b0-47ab-ad4d-b9eb04a7a488', 'わたしがもっとも行ってみたい寺の一つに京都の高山寺がある。', 'わたしがもっともいってみたいてらのひとつにきょうとのこうさんじがある。', '我最想去看看的寺庙之中，便有京都的高山寺。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('e1f5b6cb-bace-4538-977a-1f64112cd329', '～もの', NULL, 'N4', '～もの', '～もの', '指代句中已经出现或者即将要提及的具体事物。', '指代什么物品要从上下文判断，不用于指代事情。此种用法一般情况下可以用「の」替换，但不能用「こと」替换。', 531, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('ea56ea4d-616d-4874-be99-bc1858c44eb9', 'e1f5b6cb-bace-4538-977a-1f64112cd329', 'メニューの中からどれでも好きなものを一つ選んでください。', 'メニューのなかからどれでもすきなものをひとつえらんでください。', '请从菜单中任选一份你喜欢吃的东西。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('c779a759-6df7-44cc-8678-f432bdadf65e', 'e1f5b6cb-bace-4538-977a-1f64112cd329', 'A「あ、これおいしそうだね。食べてもいいの。」B「だめよ。お客様にさしあげるものだから。」', 'A「あ、これおいしそうだね。たべてもいいの。」B「だめよ。おきゃくさまにさしあげるものだから。」', 'A：“啊，这个看起来很诱人呀。我能吃吗？”\nB：“不行，因为这是要送给客人的礼物。”', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('d173e677-d917-4f40-bce1-8f22afba08ac', '～こと', NULL, 'N4', '～こと', '～こと', '形式体言，其作为实质名词的意义已经相对薄弱，故在句中通常不翻译出来。', '「～こと」属于形式体言。惯用搭配有「～ことがある/ことができる/ことにする/ことになる」等。大部分时候可以与形式体言「～の」互换，但是在惯用句型中不可替换，如第二个例句，而且在充当句子的谓语部分，即「AはBです/だ/である」这种句型时，B部分的形式体言只能用「～こと」，如第三个例句。', 532, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('9e772095-4af0-46e5-a96e-b8f900410482', 'd173e677-d917-4f40-bce1-8f22afba08ac', '銀行の名前が変わったことを知りませんでした。', 'ぎんこうのなまえがかわったことをしりませんでした。', '我不知道银行的名字变了。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('29e609ac-ccbb-4738-bbbf-4b3f9b7fc381', 'd173e677-d917-4f40-bce1-8f22afba08ac', '日本へ行ったことがありますか。', 'にほんへいったことがありますか。', '你去过日本吗？', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('2c99081e-db88-44a3-913a-22ec46c7cdd6', 'd173e677-d917-4f40-bce1-8f22afba08ac', 'わたしの趣味は切手を集めることです。', 'わたしのしゅみはきってをあつめることです。', '我的兴趣爱好是集邮。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('97e2e182-4041-4969-ad78-104f61e248ef', '～ということ', NULL, 'N4', '句子普通形＋ということ', '句子普通形＋ということ', '“……的事……”。', '表示内容，主要用于归纳较长的句子。', 533, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('18609373-5244-447e-9312-a867866dabd1', '97e2e182-4041-4969-ad78-104f61e248ef', '友だちからのメールが来るまで今日がレポートの締め切り日だったということをすっかり忘れていた。', 'ともだちからのメールがくるまできょうがレポートのしめきりびだったということをすっかりわすれていた。', '朋友发来邮件之前，我完全忘记了今天是提交小论文的截止日期。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('6ffd7278-b512-4e7a-abb8-2c8cd55f5241', '97e2e182-4041-4969-ad78-104f61e248ef', '彼は来月結婚するということを、まだ誰にも知らせていない。', 'かれはらいげつけっこんするということを、まだだれにもしらせていない。', '他下个月结婚的事，还没有通知任何人。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('c44566fa-2a10-42be-ba0e-994bff92bcc5', '97e2e182-4041-4969-ad78-104f61e248ef', 'いろいろ調べて、その駅が一番便利だということがわかった。', 'いろいろしらべて、そのえきがいちばんべんりだということがわかった。', '我做了很多调查，得知那个车站是最方便的。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('24d4a6de-3e7b-43bd-b0d0-34bfb3d30a5c', '97e2e182-4041-4969-ad78-104f61e248ef', 'この法律を知っている人が少ないということは、大きな問題だ。', 'このほうりつをしっているひとがすくないということは、おおきなもんだいだ。', '很少有人知道这条法律，这可是个大问题。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('e72fe85f-36e7-4ab7-9edb-f505248bb355', '～の/んです', NULL, 'N4', '～の/んです', '～の/んです', '“（原因）是……”，表示说明、强调。「～のだ」用于解释说明前项事实、情况发生的原因、理由。用在疑问句中表示说话人要求对方做出某些说明。「～のだ」是书面语，「～んだ」是口语。', '「～の/んです」用于句末，表示强调说明或者提出说话人的主张。「～んです」多用于会话中，使表达更加委婉。', 534, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('7b9bb41a-51f8-46b1-a9ee-5662c09f0499', 'e72fe85f-36e7-4ab7-9edb-f505248bb355', 'A「明日、一緒に出かけませんか。」B「明日は友だちがうちに来る予定なんです。」', 'A「あした、いっしょにでかけませんか。」B「あしたはともだちがうちにくるよていなんです。」', 'A：“明天我们一起出去吧？”\nB：“不好意思，明天朋友要来我家。”', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('a2858767-b69c-4513-90b9-f805b4821370', 'e72fe85f-36e7-4ab7-9edb-f505248bb355', 'その写真はどこで撮ったんですか。', 'そのしゃしんはどこでとったんですか。', '那张照片是在哪儿拍的呀？', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('9235998b-30d4-4c65-a68b-008baede32aa', '～のに', NULL, 'N4', '～のに', '～のに', '“却……”。表示转折。', '「～のに」表示因为结果与预想的不同而感到遗憾的心情。', 535, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('af24f14a-0744-4550-a356-fec2bef742cc', '9235998b-30d4-4c65-a68b-008baede32aa', 'A「何回も電話したのに、どうして出てくれなかったんですか。」B「すみません。」', 'A「なんかいもでんわしたのに、どうしてでてくれなかったんですか。」B「すみません。」', 'A：“打了好几通电话，你为什么不接？”\nB：“对不起。”', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('e341f619-04f4-4066-9525-750ad89b84de', '9235998b-30d4-4c65-a68b-008baede32aa', '田中さんは遅刻をしないと言ったのに、また遅刻をした。', 'たなかさんはちこくをしないといったのに、またちこくをした。', '田中说了不会迟到，却还是迟到了。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('1c47355b-8901-4a24-9a98-3756654df127', '～てもいい', NULL, 'N4', '动词「て形」＋もいい', '动词「て形」＋もいい', '“可以……”。', '「～てもいい」表示许可，常用「～てもいいですか」的句型表示请求许可。「～てもよろしい」是其更为礼貌的表达方式。', 536, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('e90921e2-772d-448b-91b6-d6413b5616ce', '1c47355b-8901-4a24-9a98-3756654df127', '客「すみません、この帽子、被ってみてもいいですか。」店員「はい、どうぞ。」', 'きゃく「すみません、このぼうし、かぶってみてもいいですか。」てんいん「はい、どうぞ。」', '客人：“不好意思，这顶帽子我可以戴戴看吗？”\n店员：“可以，请试戴。”', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('01544400-e3dc-48f3-aebc-060996f7a5e4', '1c47355b-8901-4a24-9a98-3756654df127', '明日はテキストを持ってこなくてもいいです。', 'あしたはテキストをもってこなくてもいいです。', '明天不带教材来也不要紧。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('8e5522f0-ea1c-473e-a91d-5ea0f4236c58', '～てもかまわない', NULL, 'N4', '～てもかまわない', '～てもかまわない', '“……也行”“……也可以”。表示“不妨碍，无伤大雅”等意思。', '「～てもかまわない」表示宽恕、容忍前项行为。', 537, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('04590686-6882-4a1d-9030-f308a5013e58', '8e5522f0-ea1c-473e-a91d-5ea0f4236c58', '遅くてもかまわないので電話してください。', 'おそくてもかまわないのででんわしてください。', '再晚也不要紧，一定要打电话来。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('d103d624-9a23-4f13-b8e9-70cb9786fdfb', '8e5522f0-ea1c-473e-a91d-5ea0f4236c58', 'カメラは持って来なくてもかまいません。', 'カメラはもってこなくてもかまいません。', '不带相机来也不要紧。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('2fe0b3a4-987b-4f11-8147-3b234ed3aca7', '～てはいけない', NULL, 'N4', '动词「て形」＋はいけない', '动词「て形」＋はいけない', '“不可以……”“不能……”。', '「～てはいけない」表示禁止，通常用于上对下，语气较为强烈。', 538, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('587c3717-7f0c-4746-9f64-57011a262edd', '2fe0b3a4-987b-4f11-8147-3b234ed3aca7', 'この部屋に入ってはいけません。', 'このへやにはいってはいけません。', '不准进入这个房间。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('a4455aeb-45ff-454c-ba18-0daae844b8fd', '2fe0b3a4-987b-4f11-8147-3b234ed3aca7', '授業中、電話をかけてはいけません。', 'じゅぎょうちゅう、でんわをかけてはいけません。', '上课时间不准打电话。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('24f17f92-929a-4363-af9e-84d625c62e37', '～なければならない/なければいけない', NULL, 'N4', '～なければならない/なければいけない', '～なければならない/なければいけない', '“必须……”“不……是不行的”。表示从社会常识或事情本身性质来看，有某种义务或必要性。', '「～なければ」的口语形式是「なきゃ」；「～なくては」的口语形式是「なくちゃ」。口语中有时候可以省略后半部分的「ならない/いけない」。', 539, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('6d063fd2-ab03-40f6-8bef-1cb013abf676', '24f17f92-929a-4363-af9e-84d625c62e37', '食事の前には必ず手を洗わなければなりません。', 'しょくじのまえにはかならずてをあらわなければなりません。', '吃饭前必须洗手。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('1d1ee492-b7cc-474c-8749-0f6eaab6949d', '24f17f92-929a-4363-af9e-84d625c62e37', '部屋は明るくなければいけない。', 'へやはあかるくなければいけない。', '房间必须采光好。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('8e621e79-bc0a-4a17-bc37-d8f766416b35', '～なくてもいい', NULL, 'N4', '～なくてもいい', '～なくてもいい', '“不……也行”。', '「～なくてもいい」表示不必做某事，意思相近的还有「～なくてもかまわない」。', 540, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('bd9f5b90-29ed-4ad9-91ee-bf4286b7da30', '8e621e79-bc0a-4a17-bc37-d8f766416b35', '電話をかけなくてもいいです。', 'でんわをかけなくてもいいです。', '不打电话也行。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('236e294f-e679-4707-95c3-3300d9e242cd', '8e621e79-bc0a-4a17-bc37-d8f766416b35', '病気が治ったから、薬を飲まなくてもいいです。', 'びょうきがなおったから、くすりをのまなくてもいいです。', '因为病已经好了，不吃药也不要紧的。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('4896a30c-c377-4080-96ff-fb729defff34', '～なくてはならない/なくてはいけない', NULL, 'N4', '～なくてはならない/なくてはいけない', '～なくてはならない/なくてはいけない', '“必须……”。', '「～なくてはならない」在口语中也可以简略为「～なくちゃならない」。「～なくてはいけない」比起「～なければならない」更侧重于针对个别事情或在某种具体场合下必须做某事。', 541, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('2216d16f-fddd-4f0c-a541-a6120a433127', '4896a30c-c377-4080-96ff-fb729defff34', '寝る前に必ず歯を磨かなくてはいけません。', 'ねるまえにかならずはをみがかなくてはいけません。', '睡前必须刷牙。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('9c467b74-7324-474a-81f3-73dfd926371a', '4896a30c-c377-4080-96ff-fb729defff34', '嫌でもテストは受けなくてはいけません。', 'いやでもテストはうけなくてはいけません。', '再讨厌也要参加考试。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('262ae4d2-7c85-4ddb-9f88-527771d17a72', '～すぎる', NULL, 'N4', '～すぎる', '～すぎる', '“过于……”。表示某种行为或状态过度。', '「～すぎる」的活用跟Ⅱ类动词的活用一致。常见用法是其名词形式，即「～すぎ」。如「 飲[の]みすぎ」（喝多了）、「 言[い]いすぎ」（话说得过分了）、「 食[く]いすぎ」（吃撑了）等。', 542, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('bf5645b4-34a2-454b-a5cb-41134f5522a4', '262ae4d2-7c85-4ddb-9f88-527771d17a72', 'この花は、土が乾いたら水をやる必要があるが、やりすぎるのもよくない。水が多いと根が腐ってしまう。」', 'このはなは、つちがかわいたらみずをやるひつようがあるが、やりすぎるのもよくない。みずがおおいとねがくさってしまう。」', '这种花在泥土干燥的情况下需要浇水，但浇过头的话也不好。水太多会导致根部腐烂。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('98faa36e-140a-4a8a-8d11-3b59cf79e91d', '262ae4d2-7c85-4ddb-9f88-527771d17a72', 'たばこの吸いすぎはよくないですよ。', 'たばこのすいすぎはよくないですよ。', '抽太多烟不好的。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('f55d64c6-7660-4aca-bf9e-c559e24dd852', '262ae4d2-7c85-4ddb-9f88-527771d17a72', 'コピーの字が薄すぎで、読めません。', 'コピーのじがうすすぎで、よめません。', '复印出来的字颜色太浅，读不了。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('70979980-20c7-4982-a194-720092ba6eda', '～だす', NULL, 'N4', '动词「ます形」＋だす', '动词「ます形」＋だす', '“开始……”。', '「～だす」还有“……出来”的意思。如「 探[さが]しだす」（找出来）、「 飛[と]びだす」（跳出来）、「 照[て]らしだす」（照出来）等等。', 543, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('773e1710-fa53-430c-bae4-4d3e75be1e6a', '70979980-20c7-4982-a194-720092ba6eda', '今まで寝ていた赤ちゃんが急に泣きだした。', 'いままでねていたあかちゃんがきゅうになきだした。', '一直睡着的婴儿突然哭了起来。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('5c84857e-ffbc-4ffd-9de2-64854d7d047e', '70979980-20c7-4982-a194-720092ba6eda', '先生がなかなか来ないので、学生が騒ぎだした。', 'せんせいがなかなかこないので、がくせいがさわぎだした。', '老师总是不来，学生就开始嚷嚷了。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('f696d722-8acd-40ec-abcc-1db9fd15e5bd', '～つづける', NULL, 'N4', '动词「ます形」＋つづける', '动词「ます形」＋つづける', '“持续……”。表示某个动作或事情已经开始尚未结束，正在维持某种状态。', '「～つづける」表示动作或状态的持续，前面的动词为持续性动词。', 544, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('17605473-f22a-4e5f-a4f9-73a9a210f367', 'f696d722-8acd-40ec-abcc-1db9fd15e5bd', '1時間ぐらい話しつづけたので、のどが渇いた。', 'いちじかんぐらいはなしつづけたので、のどがかわいた。', '因为一直说了将近一个小时，嗓子干了。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('4d7f3bf9-e62b-45a2-bf2d-e5b586759bbc', 'f696d722-8acd-40ec-abcc-1db9fd15e5bd', '長い時間テレビを見つづけると、目が痛くなる。', 'ながいじかんテレビをみつづけると、めがいたくなる。', '长时间看电视的话，眼睛会觉得疼的。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('7e7f527d-1a05-42e9-892d-8826d4e3e5d5', '～やすい', NULL, 'N4', '动词「ます形」＋やすい', '动词「ます形」＋やすい', '“容易……”“易于……”。表示某个动作很容易做，或某件事情很容易实现。', '「～やすい」可以看作是「～にくい」的反义表达，表示某事物在性质上容易有那样的倾向。「～やすい」的活用跟い形容词的活用一致。', 545, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('1be4feb0-f5d7-43bf-b7ca-622c3eabbf3d', '7e7f527d-1a05-42e9-892d-8826d4e3e5d5', 'この季節はたくさんの人が病気になりやすい。', 'このきせつはたくさんのひとがびょうきになりやすい。', '这个季节很多人都容易生病。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('c896153b-e557-4d78-b63b-782ca0fe7743', '7e7f527d-1a05-42e9-892d-8826d4e3e5d5', 'このペンは書きやすいですね。', 'このペンはかきやすいですね。', '这支笔很好写。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('69c84544-a3aa-4625-9b4a-41964afafb92', '～にくい', NULL, 'N4', '动词「ます形」＋にくい', '动词「ます形」＋にくい', '“难以……”“不容易……”。表示因为客观条件导致做某事很难。', '「～にくい」多表示从事物或事情本身性质而言，不容易做、不容易发生或不容易有那的倾向。如「 燃[も]えにくい」（不易燃）、「 書[か]きにくい」（难写）、「 食[た]べにくい」（难吃）等。「～にくい」的活用跟い形容词的活用一致。', 546, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('25befee0-955d-48c2-9f8e-bccc24e89ac4', '69c84544-a3aa-4625-9b4a-41964afafb92', '夜は暗くて歩いている人が見えにくいので、注意して運転します。', 'よるはくらくてあるいているひとがみえにくいので、ちゅういしてうんてんします。', '晚上很黑，很难看到行人，所以要小心驾驶。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('2c1fb461-5fa0-4caf-b64d-6e4492c19981', '69c84544-a3aa-4625-9b4a-41964afafb92', '彼の名前は長くて覚えにくい。', 'かれのなまえはながくておぼえにくい。', '他的名字很长，很难记。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('e9f95eb7-8f13-4bba-ad05-9081b836e834', '～ 方[か た]', NULL, 'N4', '动词「ます形」＋ 方[か た]', '动词「ます形」＋ 方[か た]', '“……的方法”。', '「～ 方[かた]」表示某种方法，通常都会构成固定搭配。如「 書[か]き 方[かた]」（写法）、「 使[つか]い 方[かた]」（用法）、「 話[はな]し 方[かた]」（说话方式）等。', 547, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('e3ce62cd-72b5-4c17-a4a2-6373e99d7c9d', 'e9f95eb7-8f13-4bba-ad05-9081b836e834', 'この漢字は読み方が難しいです。', 'このかんじはよかたがむずかしいです。', '这个汉字的读法很难。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('1ac1546c-5213-46e2-a9a0-bbad1e9055ff', 'e9f95eb7-8f13-4bba-ad05-9081b836e834', '授業で手紙の書き方を習いました。', 'じゅぎょうでてがみのかかたをならいました。', '在课堂上学习了书信的写法。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('f57f48c3-44b8-4878-9d39-9d5af2fe69be', '～さ', NULL, 'N4', 'い形容词词干/な形容词词干＋さ', 'い形容词词干/な形容词词干＋さ', '“……度”“……之大”。表示性质和状态的程度。', '形容词词干接「～さ」，可构成表示程度的名词。', 548, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('6a4cfdff-d50e-454d-a49a-0a530b805d17', 'f57f48c3-44b8-4878-9d39-9d5af2fe69be', 'わたしの部屋の広さはこの部屋と大体同じです。', 'わたしのへやのひろさはこのへやとだいたいおなじです。', '我房间的大小和这个房间差不多。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('99feb860-6fa0-4b25-9cca-e2b7beb6173e', 'f57f48c3-44b8-4878-9d39-9d5af2fe69be', 'その鞄の軽さに驚いた。', 'そのかばんのかるさにおどろいた。', '令我吃惊的是那个包那么轻。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('e173c28c-4923-4d90-8c3a-0947c86948cd', '～うちに/ないうちに', NULL, 'N4', '动词「ない形」＋うちに', '动词「ない形」＋うちに', '“在……之内”“趁着……的时候”。\n“趁不……”“趁没……”。表示趁着前项的动作或现象还没有发生，赶快做后项的事情。', '「～うちに」表示在某时间内做某事；或者在做某事的时候，发生了与前项主语意志无关的另外一件事情。', 549, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('f26892d5-ca38-4a41-8875-a545908e20ec', 'e173c28c-4923-4d90-8c3a-0947c86948cd', 'どうぞ、温かいうちにお召し上がりください。', 'どうぞ、あたたかいうちにおめしあがりください。', '请趁热吃吧。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('1d3c267b-dde9-4ec9-b534-8bf58e1065f8', 'e173c28c-4923-4d90-8c3a-0947c86948cd', '若いうちに、いろいろな国へ旅行したいです。', 'わかいうちに、いろいろなくにへりょこうしたいです。', '想趁着年轻去很多国家旅游。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('2e72c301-d1c4-452a-a51e-5654e77f665d', 'e173c28c-4923-4d90-8c3a-0947c86948cd', '彼女の話を聞いているうちに、涙が出てきた。', 'かのじょのはなしをきいているうちに、なみだがでてきた。', '听她讲着讲着，（我的）眼泪就流了出来。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('c8cb7a03-480b-4df3-b7ad-bb2305f17b8b', 'e173c28c-4923-4d90-8c3a-0947c86948cd', '昨日のパーティーは、友だちと話していたら、ほとんど何も食べないうちに終わってしまって、後でおなかがすいてしまった。', 'きのうのパーティーは、ともだちとはなしていたら、ほとんどなにもたおわってしまって、あとでおなかがすいてしまった。', '昨天的派对上，一直和朋友聊天，结果基本上说明都没吃派对就结束了，之后独自就饿了。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('2e5f2573-7b96-42f0-97bb-1a48c9f016db', 'e173c28c-4923-4d90-8c3a-0947c86948cd', '弟と妹がいると集中できないから、今日は二人が帰ってこないうちに、宿題をやってしまおう。', 'おとうとといもうとがいるとしゅうちゅうできないから、きょうはふたりがかえってこないうちに、しゅくだいをやってしまおう。', '因为弟弟和妹妹在旁边的时候，集中不了注意力。所以今天想趁两个人还没有回来的时候把作业做完。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('98f88361-2f7d-406a-86c2-f68d12bb731b', '～ところ', NULL, 'N4', '动词辞书形＋ところ', '动词辞书形＋ところ', '“正要……”“正打算……”。', '「～ところ」接在动词辞书形后面表示现在处于动作刚要发生而还未发生的阶段，常与「ちょうど」（正好）、「 今[いま]」（马上就要）、「これから」（接下来）等副词搭配使用。', 550, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('f7415be6-5018-436a-8e74-9fd96de576d8', '98f88361-2f7d-406a-86c2-f68d12bb731b', 'これから食事に行くところなんですが、一緒にいかがですか。', 'これからしょくじにいくところなんですが、いっしょにいかがですか。', '我正打算去吃饭，你也一起去吗？', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('7672ed3d-68fe-44fa-9bce-f8fae424e9b2', '98f88361-2f7d-406a-86c2-f68d12bb731b', 'これからパンを焼くところです。', 'これからパンをやくところです。', '正打算要烤面包。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('9880e359-78b1-4d98-8a43-68bdb9aa70c6', '～ているところだ', NULL, 'N4', '动词「ている形」＋ところだ', '动词「ている形」＋ところだ', '“正在……”。', '「～ているところだ」表示动作正在进行的阶段。', 551, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('328d8560-b035-40de-ba26-e49c0e32f9af', '9880e359-78b1-4d98-8a43-68bdb9aa70c6', 'わたしは今、家で日本語を勉強しているところです。', 'わたしはいま、いえでにほんごをべんきょうしているところです。', '我现在正在家里学习日语。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('41601d35-cbdb-4193-b350-52db3b8b6eeb', '9880e359-78b1-4d98-8a43-68bdb9aa70c6', '山田社長は電話をかけているところです。', 'やまだしゃちょうはでんわをかけているところです。', '山田社长正在打电话。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('df7f8f0f-2f45-4df0-a13d-758fff3723ab', '～たところだ', NULL, 'N4', '动词「た形」＋ところだ', '动词「た形」＋ところだ', '“刚刚……”。「～たところだ」表示动作或变化刚刚结束的阶段。', '「～たところだ」表示动作或变化刚刚结束的阶段，与现在这个时间点间隔很短。常与「 今[いま]」（刚刚）、「さっき」（刚才）、「ちょっと 前[まえ]」（稍前）等副词搭配使用。', 552, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('36c3125f-2c1a-4c9a-af06-86987ee33292', 'df7f8f0f-2f45-4df0-a13d-758fff3723ab', '課長「山田さん、明日の会議の資料、もう部長に届けた？」山田「はい、届けました。ついさっき、持って行ったところです。」', 'かちょう「やまださん、あしたのかいぎのしりょう、もうぶちょうにとどけた？」やまだ「はい、とどけました。ついさっき、もっていったところです。」', '课长：“山田，明天会议的资料，你已经给部长送去了吗？”\n山田：“是的，送去了。刚刚我拿过去的。”', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('7d1a0547-6f54-45c9-a269-10b5f4559919', 'df7f8f0f-2f45-4df0-a13d-758fff3723ab', '今、お茶を入れたところなんです。', 'いま、おちゃをいれたところなんです。', '我刚泡好茶。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('fcef0878-94e4-461c-b56d-153190820ad1', '～ばかり', NULL, 'N4', '动词辞书形/名词＋ばかり', '动词辞书形/名词＋ばかり', '“只……”“光是……”。', '「～ばかり」表示除此以外没有别的，用于描述很多个相同的事物或者是多次重复同样的行为。在表示“只……”的时候与「～だけ」相似，但是表示“多次重复”或者是“总是”“全部”的时候不可以用「～だけ」替换。', 553, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('b7856b60-74d1-4125-a3a4-4b505827db3e', 'fcef0878-94e4-461c-b56d-153190820ad1', '田中さんはいつも人のやることに文句を言うばかりで自分では何もしない。', 'たなかさんはいつもひとのやることにもんくをいうばかりでじぶんではなにもしない。', '田中总是对别人做的事说长道短，自己却什么都不做。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('f76dbfcc-d5cc-4ebe-a506-4c42d71694e0', 'fcef0878-94e4-461c-b56d-153190820ad1', 'あの子は肉ばかり食べて、野菜を全然食べません。', 'あのこはにくたべて、やさいをぜんぜんたべません。', '那孩子只吃肉，完全不吃蔬菜。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('50253087-6966-4243-af05-0dfca7f3591c', '～てばかり', NULL, 'N4', '动词「て形」＋ばかり', '动词「て形」＋ばかり', '“总是……”“只……”“一个劲儿地……”。', '「～てばかり」表示某种行为或状态反复出现，说话人对此感到不满。', 554, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('9843a2b0-e553-402e-8b94-bf84e241c6ca', '50253087-6966-4243-af05-0dfca7f3591c', '息子は毎日遊んでばかりで勉強をしない。', 'むすこはまいにちあそんでばかりでべんきょうをしない。', '儿子每天只顾着玩都不学习。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('00fe896a-6e02-44da-97a1-a10fe84c497e', '50253087-6966-4243-af05-0dfca7f3591c', 'テレビを見てばかりいると、目が悪くなりますよ。', 'テレビをみてばかりいると、めがわるくなりますよ。', '光顾着看电视的话，视力会下降的。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('b32f2b63-e139-43e2-9afd-355e23b71b6b', '～たばかり', NULL, 'N4', '动词「た形」＋ばかり', '动词「た形」＋ばかり', '“刚……”，表示刚刚做完某个动作。', '「～たところだ」只能用于眼前刚刚做完的事情，而「～たばかり」对实际上经过的时间长短并无特殊限制，只要说话人觉得时间短就可以使用。', 555, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('9cd281c4-6d95-4d21-8d1d-d972299fbf98', 'b32f2b63-e139-43e2-9afd-355e23b71b6b', 'さっき起きたばかりで、まだ眠いです。', 'さっきおきたばかりで、まだねむいです。', '刚起床，还很困。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('12a31c38-dc52-4dda-8b65-a7558360abaf', 'b32f2b63-e139-43e2-9afd-355e23b71b6b', '昼ごはんを食べたばかりなので、今は何も食べられない。', 'ひるごはんをたべたばかりなので、いまはなにもたべられない。', '刚吃过午饭，现在什么都吃不下。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('7f021ffd-02ad-42f5-851e-f3c09e58c292', '～までに', NULL, 'N4', '动词辞书形/名词＋までに', '动词辞书形/名词＋までに', '“到……为止”“在……之前”。', '「～までに」放在表示时间的名词或表示状况的短句之后，表示后项动作的截止时间或期限。其后接瞬间性动词。', 556, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('f9898f75-0c81-4da8-8076-0f367d443672', '7f021ffd-02ad-42f5-851e-f3c09e58c292', '（会社で）A「すみません、山田さんはどこですか。」B「山田さんは会議中ですが、会議は11時半までには終わると思いますよ。」', '（かいしゃで）A「すみません、やまださんはどこですか。」B「やまださんはかいぎちゅうですが、かいぎは11じはんおわるとおもいますよ。」', 'A：“不好意思，山田在哪里啊？”\nB：“山田正在开会，我想11点半之前会议应该会结束的。”', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('545d5ee1-f2bc-4058-ac58-bade4d139f98', '7f021ffd-02ad-42f5-851e-f3c09e58c292', '明日の朝は9時までにここへ来てください。', 'あしたのあさはくじまでにここへきてください。', '请在明天早上九点前到这里。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('1cb8ce32-b02c-4fa4-9a03-42f40f1162c7', '～でも', NULL, 'N4', '名词＋でも', '名词＋でも', '“……之类的”。', '「～でも」在这种情况下表示举例，虽然除了举出来的例子之外还有类似的其他选择，但一般就是指其前项的事物。', 557, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('94181794-3bec-4fea-8c42-91a85c991505', '1cb8ce32-b02c-4fa4-9a03-42f40f1162c7', 'A「今週末、よかったら一緒に食事でもしませんか。」B「いいですね。そうしましょう。」', 'A「こんしゅうまつ、よかったらいっしょにしょくじでもしませんか。」B「いいですね。そうしましょう。」', 'A：“这周末要是方便的话，一起吃个饭吧？”\nB：“好啊，就这么定了。”', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('f7626de2-1d98-4062-8955-f94a4522eb2c', '1cb8ce32-b02c-4fa4-9a03-42f40f1162c7', '暇だからゲームでもしましょう。', 'ひまだからゲームでもしましょう。', '正好有时间，（我们）玩玩游戏之类的吧。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('346de2f1-104f-444a-b37e-1bd5d0905e54', '～とか', NULL, 'N4', '动词辞书形/名词＋とか', '动词辞书形/名词＋とか', '“……之类的”，表示列举。', '「～とか」接在名词之后，用于举出典型的例子，暗示还有其他。', 558, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('1de0e50a-84a4-4731-a01a-8604f6c0e907', '346de2f1-104f-444a-b37e-1bd5d0905e54', '引き出しにはスプーンとかナイフとかが入っています。', 'ひきだしにはスプーンとかナイフとかがはいっています。', '抽屉里放着勺子和餐刀之类的。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('723ff9c5-7bb4-4eb2-bb68-83966d3f3699', '346de2f1-104f-444a-b37e-1bd5d0905e54', 'A「デパートで何か買いましたか。」B「ええ、シャツとか靴下とか、いろいろ買いました。」', 'A「デパートでなにかかいましたか。」くつしたとか、いろいろかいました。」', 'A：“你在百货商店买了什么？”\nB：“嗯，买了衬衫、袜子等很多东西。”', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('ba7908ab-cedf-416c-8377-895548a32ace', '346de2f1-104f-444a-b37e-1bd5d0905e54', 'かばんには財布とかがあります。', 'かばんにはさいふとかがあります。', '包里放着钱包等物品。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('97a898d5-c907-4c11-9677-1a9bc078abb3', '疑问词＋か', NULL, 'N4', '疑问词＋か', '疑问词＋か', '“哪个……”“某……”。表示不确定。', '「疑问词＋か」常构成固定搭配，如「いつか」（何时）、「どこか」（何地）、「 誰[だれ]か」（某人）、「 何[なに]か」（某物）等。', 559, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('e4a68d1f-beb0-496d-ada6-a608f4b8d8fd', '97a898d5-c907-4c11-9677-1a9bc078abb3', '何か飲みながら、話をしましょう。', 'なにのみながら、はなしをしましょう。', '边喝点东西边聊吧。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('b0956f60-1b80-45d9-8f91-a241a78f95a4', '97a898d5-c907-4c11-9677-1a9bc078abb3', 'いつかまた日本へ来たいです。', 'いつかまたにほんへきたいです。', '什么时候还想再来日本。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('3bff652f-6a20-41ca-9cda-f21809277c99', '97a898d5-c907-4c11-9677-1a9bc078abb3', '誰か手伝ってください。', 'だれてつだってください。', '谁能来帮帮我。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('17e0098a-a541-4754-8c32-ccdf9dc05d38', '疑问词＋も', NULL, 'N4', '疑问词＋も', '疑问词＋も', '“都（不）……”。用于否定句中表示全盘否定。', '「疑问词＋でも」用于肯定句中，表示无一例外。', 560, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('00fea3a1-640b-417b-bd34-bb3e4d4fc5f1', '17e0098a-a541-4754-8c32-ccdf9dc05d38', 'かばんを買いに行ったが、どれも高くて買えなかった。', 'かばんをかいにいたかくてかえなかった。', '去买包，可是哪个都贵，都买不起。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('45d07484-0ccf-4b47-a3b7-afb71687425c', '17e0098a-a541-4754-8c32-ccdf9dc05d38', '教室には誰もいない。', 'きょうしつだれもいない。', '教室里一个人都没有。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('1ab0c22b-4f6a-4af4-a0f2-b793e4a77a22', '～または', NULL, 'N4', '～または', '～または', '意为“或者”。', '「または」表示两者之间随便哪一个都可以。', 561, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('6651c543-aff7-4909-aac4-55ea3fa99752', '1ab0c22b-4f6a-4af4-a0f2-b793e4a77a22', '1番の部屋、または2番の部屋に行ってください。', 'いちばんのへやにばんのへやにいってください。', '请去一号房或二号房。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('0dd5cc2c-4966-4565-a874-40ea7354ee70', '1ab0c22b-4f6a-4af4-a0f2-b793e4a77a22', '自己紹介は中国語で、または日本語でお願いします。', 'じこしょうかいはちゅうごくごにほんごでおねがいします。', '请用中文或者日语进行自我介绍。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('f909dcc8-1388-4c92-a2cb-67a1693e4771', '～たり/～たり～たり', NULL, 'N4', '名词/な形容词词干＋だったり', '名词/な形容词词干＋だったり\nい形容词词干＋かったり\n动词「た形」＋り', '“有时……有时……”“又……又……”。列举两个或两个以上的动作，暗示还有其他同类动作。若前后是两个意思对立的动词，则表示动作的反复进行。', '用「～たり（など）する」的形式，只举出一个代表性例子，暗示还有其他的动作。', 562, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('b49db36f-d765-47d6-81b9-82e91b93642a', 'f909dcc8-1388-4c92-a2cb-67a1693e4771', '昨日は散歩をしたり、料理を作ったりしました。', 'きのうはさんぽをしたり、りょうりをつくったりしました。', '昨天散了会儿步，又做了饭什么的。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('24a20a37-8b3c-472b-98be-a82e81ad7c6f', 'f909dcc8-1388-4c92-a2cb-67a1693e4771', '図書館で本を読んだり勉強したりします。', 'としょかんでほんをよべんきょうしたりします。', '在图书馆看看书、学习学习。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('304f07cc-1eb3-431a-b3e1-1f5afecf17cb', 'f909dcc8-1388-4c92-a2cb-67a1693e4771', '学生たちは、教室を出たり入ったりしています。', 'がくせいたちは、きょうしつをではいったりしています。', '学生们从教室进进出出。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('e217c99a-23b7-4377-9180-2a8c10c9dbc6', 'f909dcc8-1388-4c92-a2cb-67a1693e4771', '休みの日は映画を見たり（など）しています。', 'やすみのひはえいがをみたり（など）しています。', '休息的时候就看电影什么的。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('9d507849-df4e-4716-a48e-5870267d631c', '～し/～し～し', NULL, 'N4', '句子普通形＋し', '句子普通形＋し', '“既……又……”。', '此句型可以用来列举两个或者两个以上的原因，暗示还有其他原因的存在，如第一、第二个例句。也可以用来列举两个或两个以上的事项，言外之意还有其他同类的事项，如第三个例句。', 563, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('0f6cfbe7-397e-4a3c-85a5-4685d4d1e3b9', '9d507849-df4e-4716-a48e-5870267d631c', 'お金もないし、時間もないから、遊びに行けない。', 'おかねもないし、じかんもないから、あそびにいけない。', '既没钱又没时间，所以没法儿去玩。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('0392a300-316b-43ec-b41d-fea6aaabf2f9', '9d507849-df4e-4716-a48e-5870267d631c', 'はじめは言葉もわからないし、友だちもいないし、本当に大変でした。', 'はじめはことばもわからないし、ともだちもいないし、ほんとうにたいへんでした。', '一开始语言也不通，又没有朋友，真是很辛苦。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('eb5a85f9-c9cc-452d-9386-f1a91a93d83a', '9d507849-df4e-4716-a48e-5870267d631c', '山田さんのアパートはきれいだし、広いし、駅からも近い。', 'やまださんのアパートはきれいだし、ひろいし、えきからもちかい。', '山田的公寓既漂亮又宽敞，离车站还很近。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('6b49e144-6f64-462d-bbae-17f154a0258a', '～ほど～ない', NULL, 'N4', '名词＋ほど～ない', '名词＋ほど～ない', '“没有……那么……”“不如……”。后续否定，表示比较的基准。', '「～ほど～ない」表示比较的双方有着共同的属性，但是在这个属性的程度上有差异。\n「ほど」前面的内容表示比较的基准。', 564, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('d2839a98-61c1-431a-a09f-5b8eb780984c', '6b49e144-6f64-462d-bbae-17f154a0258a', '料理をするのがそれほど得意ではないわたしでもハンバーグだけはおいしく作れる。', 'りょうりとくいではないわたしでもハンバーグだけはおいしくつくれる。', '即使是不那么擅长做饭的我，汉堡牛肉饼的话还是可以做得很好吃的。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('aa3e21d3-616d-42a1-85fe-463bb1505f88', '6b49e144-6f64-462d-bbae-17f154a0258a', '今日は昨日ほど風が強くない。', 'きょうはきのうかぜがつよくない。', '今天的风没有昨天大。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('fd06b900-fbef-4314-a526-796d50e665dd', '6b49e144-6f64-462d-bbae-17f154a0258a', 'わたしの部屋は姉の部屋ほど広くない。', 'わたしのへやはあねのへやひろくない。', '我的房间没有姐姐的大。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('925393bb-a2fd-4bd8-9200-da933565935a', '～より', NULL, 'N4', '动词普通形/名词＋より', '动词普通形/名词＋より', '“比……”。用于两者之间的比较。', '「～より」的前项表示比较的基准，后项为重点要描述的对象。', 565, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('27333605-d686-4855-9c8b-41f1add83b97', '925393bb-a2fd-4bd8-9200-da933565935a', '兄より弟のほうが背が高い。', 'あにおとうとのほうがせがたかい。', '弟弟比哥哥个儿高。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('2ce01967-4b6c-495a-a184-cf3d42c8ee41', '925393bb-a2fd-4bd8-9200-da933565935a', 'わたしの国は、日本より大きいです。', 'わたしのくには、にほんおおきいです。', '我的祖国的面积面积比日本大。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('d9d8c45e-e0e6-45fb-a744-a7c2139c39cd', '925393bb-a2fd-4bd8-9200-da933565935a', '息子が思ったより立派になった。', 'むすこがおもりっぱになった。', '儿子变得比我想象的还要优秀。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('180ecdfa-edf2-4c0b-bf0f-46059273727a', '～まま', NULL, 'N4', '～まま', '～まま', '“就那样……”“维持……的原样”。', '「～まま」表示在前一个动作或状态没有发生改变的情况下，就发生后项的动作。', 566, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('8bb7a5bd-7398-47c8-97e5-da1714851615', '180ecdfa-edf2-4c0b-bf0f-46059273727a', 'テレビをつけたまま寝てしまいました。', 'ねてしまいました。', '开着电视睡着了。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('59f6ca4c-febd-4186-b089-f0e4b23cece0', '180ecdfa-edf2-4c0b-bf0f-46059273727a', '靴を履いたまま部屋に入ってしまった。', 'くつをはへやにはいってしまった。', '就那样穿着鞋子进了房间。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('3613caa4-b799-4e86-87e0-e97dc9617de7', '～のうち', NULL, 'N4', '～のうち', '～のうち', '「～のうち」意为“在……之中”“……当中”。', '「～のうち」表示限定范围，与「～のなか」意思相近。前面列举多个名词时，可使用「～と～と～のうち」的形式。', 567, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('8cb563f2-9678-46ca-aa73-6711f3a91d0c', '3613caa4-b799-4e86-87e0-e97dc9617de7', '天ぷらと寿司とすき焼きのうちでどれが一番食べたいですか。', 'てんぷらとすしとすきやきのうちでどれがいちばんたべたいですか。', '天妇罗、寿司和寿喜锅中，你最想吃哪个？', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('e207b168-7c15-458d-a6e0-54bae71b2f91', '3613caa4-b799-4e86-87e0-e97dc9617de7', '昨日もらったプレゼントのうち、ピンクのワンピースが一番好きだ。', 'きのうもらったプレゼントのうち、ピンクのワンピースがいちばんすきだ。', '昨天收到的礼物中，最喜欢粉色的连衣裙。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('249f1137-43e5-4920-bb85-911364691da8', '必[かなら]ず', NULL, 'N4', '必[かなら]ず', '必[かなら]ず', '「 必[かなら]ず」意为“一定，必须，务必”。', '「 必[かなら]ず」表示没有例外，用于表示强烈的意志，后面接推测表达时则表示很有把握。', 568, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('d9650a89-0ba0-450e-a02f-e8270c2b9b68', '249f1137-43e5-4920-bb85-911364691da8', '食事の前に必ず手を洗わなければなりません。', 'しょくじのまえかならてをあらわなければなりません。', '吃饭前必须洗手。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('e50b7833-9890-4f59-94a4-cd68dae9b11d', '249f1137-43e5-4920-bb85-911364691da8', '鈴木さんは必ず来ると思います。', 'すずきかならくるとおもいます。', '我觉得铃木一定会来的。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('adca65b5-865e-4c34-97d1-7b01669c7fd4', '～かもしれない', NULL, 'N4', '～かもしれない', '～かもしれない', '“也许……”“可能……”。', '「～かもしれない」表示说话人的推测，但是可能性较低。常与「もしかして/もしかすると」（也许/或许）搭配使用。', 569, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('883f5a17-5a78-483b-baa7-8fb6ae306915', 'adca65b5-865e-4c34-97d1-7b01669c7fd4', 'スーパーに、トマトのジャムという珍しいものがあった。ジャムだったら甘いから、トマトのすっぱさが苦手な私にも食べられるかもしれないと思って、買ってみた。', 'スーパーに、トマトのジャムというめずらしいものがあった。ジャムだったらあまいから、トマトのすっぱさがにがてなわたしにもたべられるかもしれないとおもって、かってみた。', '超市里有番茄果酱这种罕见的东西。我想，果酱是甜的，那么对于不喜欢番茄的酸味的我来说或许也可以吃，所以就试着买了一罐。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('dfec89c1-a52a-48eb-976e-bc659d6fb97a', 'adca65b5-865e-4c34-97d1-7b01669c7fd4', '途中で雨が降るかもしれないから、傘を持って行きましょう。', 'とちゅうであめがふるかもしれないから、かさをもっていきましょう。', '半路上可能会下雨，所以带着伞去吧。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('60e7aafd-6359-4f73-8a2b-6092fb45919a', 'adca65b5-865e-4c34-97d1-7b01669c7fd4', '大木さんは今日も大学に来なかった。病気かもしれない。', 'おおきさんはきょうもだいがくにこなかった。びょうきかもしれない。', '大木今天也没来上学，可能是生病了。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('915c300b-96a1-4685-ad16-9223eb7bb22b', '～つもりだ', NULL, 'N4', '动词辞书形＋つもりだ', '动词辞书形＋つもりだ', '“打算……”。', '「～つもり」表示打算做某事的意志，可以用于第一人称，也可以用于第三人称。', 570, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('8f9ac926-43d4-4785-89cb-ec22fbee5fe1', '915c300b-96a1-4685-ad16-9223eb7bb22b', '会社をやめてどうするつもりですか。', 'かいしゃをやめてどうするつもりですか。', '你辞职是打算怎样呢？', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('a6f4924c-a74f-47f5-9ffb-3e261776bfd7', '915c300b-96a1-4685-ad16-9223eb7bb22b', '明日からたばこをやめるつもりです。', 'あしたからたばこをやめるつもりです。', '我打算明天开始戒烟。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('74d9d532-28ad-4b58-b596-dd3fad6ad66a', '～たつもりで', NULL, 'N4', '动词「た形」＋つもりで', '动词「た形」＋つもりで', '“就算是……”“当作……一样”。表示虽然实际上没那样，权当是那样。', NULL, 571, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('26a66579-bf54-4a77-9fbf-0ccf5b7ddc7c', '74d9d532-28ad-4b58-b596-dd3fad6ad66a', '歌手になったつもりで、みんなの前で歌を歌う。', 'かしゅになったつもりで、みんなのまえでうたをうたう。', '就当自己是歌手，在大家面前唱起歌来。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('19d626ae-143f-4f7c-9bef-eb401072d3a3', '74d9d532-28ad-4b58-b596-dd3fad6ad66a', '旅行に行ってきたつもりで、そのお金を貯めておいた。', 'りょこうにいってきたつもりで、そのおかねをためておいた。', '就当作去过旅游了，把那笔钱存了起来。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('bbc8c1f2-fb7a-4a59-9736-4737f9faa0d8', '～はずだ/はずがない', NULL, 'N4', '～はずだ/はずがない', '～はずだ/はずがない', '“理应……”“应该……”。表示说话人根据事物的一般常理或发展趋势进行推断、预测。\n“不可能……”“不会……”。表示说话人根据某种情理或经验，推断完全没有出现某种情况的可能性。', '「～はず」表示说话人根据某种情理或经验，推断完全没有出现某种情况的可能性。不可以用在自己主观意志可以决定的事情上。', 572, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('cbcc5f0c-2292-456c-a114-238782843506', 'bbc8c1f2-fb7a-4a59-9736-4737f9faa0d8', '（会社で）内田「高田さんがしている指輪、すごく高そうだよね。」森山「いや、高い指輪だったら、会社にしてこないはずだよ。」', '（かいしゃで）うちだ「たかださんがしているゆびわ、すごくたかそうだよね。」もりやま「いや、たかいゆびわだったら、かいしゃにしてこないはずだよ。」', '内田：“高田戴的戒指看起来很贵呢。”\n森山：“不，要是很贵的戒指，应该不会戴来公司的。”', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('8b1f6c97-d391-4f73-a408-aecfd2264067', 'bbc8c1f2-fb7a-4a59-9736-4737f9faa0d8', 'この薬を飲めば病気は治るはずです。', 'このくすりをのめばびょうきはなおるはずです。', '吃这种药的话，病应该会好。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('05d3f749-6c6f-476b-a6fa-9cf9ced2053f', 'bbc8c1f2-fb7a-4a59-9736-4737f9faa0d8', '山下「ねえ、わたし、この問題全然わかんないだけど、田中さん、解けた？」田中「わたしに解けるはずがないじゃない。わたしが数学苦手なの知ってるでしょ。」', 'やました「ねえ、わたし、このもんだいぜんぜんわかんないだけど、たなかさん、とけた？」たなか「わたしにとけるはずがないじゃない。わたしがすうがくにがてなのしってるでしょ。」', '山下：“哎，这道题我一点儿都不懂。田中，你会做吗？”\n田中：“我怎么可能做得出来，你知道我数学很差的。”', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('d7fdadd6-5cc6-4f9a-90e8-135ca17edd17', 'bbc8c1f2-fb7a-4a59-9736-4737f9faa0d8', 'あの人は入院しているので、明日の旅行に来るはずがない。', 'あのひとはにゅういんしているので、あしたのりょこうにくるはずがない。', '那个人住院了，不可能来参加明天的旅游的。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('4dd43993-9dc3-4288-92ee-6f4d17002fee', '～たら', NULL, 'N4', '～たら', '～たら', '“如果……的话”，表示假定条件。经常和助词「もし」（假如）搭配使用。\n“……之后”。表示前项事情发生后，就去做后项动作。\n“……一看”，表示后项事态的发生出乎意料或表示意外发现。', NULL, 573, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('bde25083-4737-44ad-acc3-ce952700858c', '4dd43993-9dc3-4288-92ee-6f4d17002fee', 'もしわからないことがあったら、参考書、インターネットなど何を使ってもいいですから、調べておいてください。', 'もしわからないことがあったら、さんこうしょ、インターネットなどなにをつかってもいいですから、しらべておいてください。', '如果有不懂的地方，请使用参考书，或者上网查询等。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('9230faba-9630-4c33-8b06-e7ae527aa59b', '4dd43993-9dc3-4288-92ee-6f4d17002fee', '道で近所の人に会ったら、挨拶しましょう。', 'みちできんじょのひとにあったら、あいさつしましょう。', '如果在路上碰到邻居的话，就打个招呼吧。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('69763e9f-10a0-44e7-9e58-2630ade3cd9e', '4dd43993-9dc3-4288-92ee-6f4d17002fee', '出席するかどうかを決めたら、すぐ連絡してください。', 'しゅっせきするかどうかをきめたら、すぐれんらくしてください。', '决定是否出席之后，请立刻跟我联络。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('6b8ba64b-2bbe-4b9d-adbf-42dc3be89193', '4dd43993-9dc3-4288-92ee-6f4d17002fee', '今日の仕事が終わったら、飲みに行こう。', 'きょうのしごとがおわったら、のみにいこう。', '今天的工作结束后，咱们去喝一杯吧。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('7a09fa60-6efa-479a-8e50-fa67f25be3de', '4dd43993-9dc3-4288-92ee-6f4d17002fee', '庭に植えたスイカは、これまでなかなかうまく育たなかったが、あきらめないで毎年チャレンジしていたら、ようやく今年になっておいしいのができた。', 'にわにうえたスイカは、これまでなかなかうまくそだたなかったが、あきらめないでまいとしチャレンジしていたら、ようやくことしになっておいしいのができた。', '种在院子里的西瓜过去都没有好好长大，但是我没放弃，每年都进行挑战，终于在今年结出了好吃的西瓜。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('47ebfc16-7aae-454b-9bc0-3921d9dffdbe', '4dd43993-9dc3-4288-92ee-6f4d17002fee', '昨日、駅前の本屋に行ったら、偶然、学生時代の友人に会った。', 'きのう、えきまえのほんやにいったら、ぐうぜん、がくせいじだいのゆうじんにあった。', '昨天，我去了车站附近的书店，偶然遇到了学生时代的朋友。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('1ad44817-4159-42a5-bb55-93fce9e22e23', '～なら', NULL, 'N4', '～なら', '～なら', '“如果……的话”。表示假定条件，后项一般是说话人的判断或决定。\n“……的话”。表示提起话题，主要是针对对方提出的话题或问题做出回答，或者是向对方提出自己的意见、建议等。', NULL, 574, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('de10419e-0544-43b4-af3b-4b837b71f0bc', '1ad44817-4159-42a5-bb55-93fce9e22e23', '子ども「何か食べるもの、ある？」母親「おなかがすいているならドーナツがあるよ。」', 'こども「なにかたべるもの、ある？」ははおや「おなかがすいているならドーナツがあるよ。」', '儿子：“有什么吃的吗？”\n母亲：“肚子饿了的话，有甜甜圈哟。”', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('db4498f0-b319-4cfb-8547-53715afb022c', '1ad44817-4159-42a5-bb55-93fce9e22e23', 'わたしの応援が力になるならいくらだって応援します。', 'わたしのおうえんがちからになるならいくらだっておうえんします。', '我的支持要是有用的话，给你多少都可以。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('353c7b45-d44a-4ba5-8c12-645a099fb6fe', '1ad44817-4159-42a5-bb55-93fce9e22e23', 'A「カメラを買いたいんですが、どこがいいですか。」B「カメラを買うなら、駅のそばの店が安くていいですよ。」', 'A「カメラをかいたいんですが、どこがいいですか。」B「カメラをかうなら、えきのそばのみせがやすくていいですよ。」', 'A：“我想买照相机，去哪里买好呢？”\nB：“买照相机的话，车站旁边的商店又便宜质量又好。”', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('6235fbae-7bec-46bb-82bf-83542ee0ec75', '1ad44817-4159-42a5-bb55-93fce9e22e23', '「もしもし。美智子さん、いらっしゃいますか。」「美智子ですか。美智子ならもう出かけましたけれど。」', '「もしもし。みちこさん、いらっしゃいますか。」「みちこですか。みちこならもうでかけましたけれど。」', '“喂，请问美智子在吗？”\n“是找美智子吗？美智子她已经出去了。”', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('f8977946-fadd-4ff1-99ae-4b83b75794b8', '～ば', NULL, 'N4', 'Ⅰ类动词把词尾改为同行「え段」假名＋ば', 'Ⅰ类动词把词尾改为同行「え段」假名＋ば\nⅡ类动词「ない形」＋れば\nⅢ类动词：（～）する→（～）すれば； 来[く]る→ 来[く]れば\nい形容词词干＋ければ；名词＋であれば；な形容词词干＋であれば', '“如果……的话”“假如……的话”。表示假定。\n“一……就……”“如果……就……”。表示必然的恒定条件，一般用来表示事物的真理、自然规律及生活习惯等。', NULL, 575, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('ce6a4e14-61e0-4cb7-aa81-1f2062b98ecd', 'f8977946-fadd-4ff1-99ae-4b83b75794b8', '山下「田中君、明日、研究室の片付けに来られる？」田中「午後は予定があるんだ。午前中だけでよければ大丈夫だよ。」', 'やました「たなかくん、あした、けんきゅうしつのかたづけにこられる？」たなか「ごごはよていがあるんだ。ごぜんちゅうだいじょうぶだよ。」', '山下：“田中，你明天能不能来整理研究室啊？”\n田中：“我下午有事。光上午来也可以的话就没问题。”', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('d2279533-99a9-4f97-aedf-8dd62eaca979', 'f8977946-fadd-4ff1-99ae-4b83b75794b8', 'このケーキは冷たくなければ、おいしくありません。', 'このケーキはつめたくなければ、おいしくありません。', '这种蛋糕冷的好吃。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('f8d50acc-471e-4153-9378-da7f8627dcef', 'f8977946-fadd-4ff1-99ae-4b83b75794b8', '温度を0度以上にすれば、氷が水となる。', 'おんどをれいどいじょうにすれば、こおりがみずとなる。', '温度升至零度以上的话，冰就会化为水。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('f5ff704d-296a-4f32-884e-1e8aa35c2797', 'f8977946-fadd-4ff1-99ae-4b83b75794b8', 'この地域では3月中旬になれば、桜が咲きます。', 'このちいきではさんがつちゅうじゅんになれば、さくらがさきます。', '这个地方到了三月中旬，樱花就会开放。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('2400d7bc-e472-49f3-9f78-e953da3a43b8', '～と', NULL, 'N4', '～と', '～と', '“一……就……”，表示必然的恒定条件或习惯。\n“如果……的话……”，表示假定条件。如果具备了前项的条件，可能就会产生后项的结果。\n“刚一……就……”。表示刚做前项，就发生了后项，后项事情是自然而然的状态或结果。\n“一……立即……”，表示同一主体相继进行的两项动作。', NULL, 576, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('21ee8a50-816d-4b8c-905d-b84c59de1e9e', '2400d7bc-e472-49f3-9f78-e953da3a43b8', '仕事から帰って、娘に笑顔で「おかえり。」と言われるとこんなかわいい娘がいるわたしは本当に幸せだといつも思う。', 'しごとからかえって、むすめにえがおで「おかえり。」といわれるとこんなかわいいむすめがいるわたしはほんとうにしあわせだといつもおもう。', '工作结束回到家之后，一听到女儿笑着对我说“你回来了啊”，我总是觉得有这么可爱的女儿，我真是幸福啊。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('ccf413dc-a992-4c6a-ac25-52df2ca41b1b', '2400d7bc-e472-49f3-9f78-e953da3a43b8', 'わたしはこの音楽を聞くと必ず眠くなります。', 'わたしはこのおんがくをきかならずねむくなります。', '我只要一听这个音乐就会犯困。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('172efe6b-4509-4af3-98be-50006d16822c', '2400d7bc-e472-49f3-9f78-e953da3a43b8', '高速道路は今のところ渋滞していないから、この調子だと、あと30分で目的地に着くだろう。', 'こうそくどうろはいまのところじゅうたいしていないから、このちょうしだと、あとさんじゅっぷんでもくてきちにつくだろう。', '目前高速公路很畅通，如果按这种情况的话，30分钟后将到达目的地。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('4386f89c-239e-422b-a07e-642c1a26f350', '2400d7bc-e472-49f3-9f78-e953da3a43b8', '人生の短さを花にたとえると、桜の花だ。', 'じんせいのみじかさをはなにたとえると、さくらのはなだ。', '如果把短暂的人生比作花的话，那就是樱花。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('8c01e191-1e30-4088-8bf1-7817910b7667', '2400d7bc-e472-49f3-9f78-e953da3a43b8', '友だちがけがで入院したと聞き、慌てて病院に行ってみると思っていたよりも元気で安心した。', 'ともだちがけがでにゅういんしたときき、あわててびょういんにいおもっていたよりもげんきであんしんした。', '我听说朋友受伤住院了，急忙到医院去看他，发现他比想象中精神，我也就放心了。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('435b9904-7ad1-408a-a0af-8b3f6c7b41b5', '2400d7bc-e472-49f3-9f78-e953da3a43b8', '朝、カーテンを開けると、外は一面の銀世界だった。', 'あさ、カーテンをあけると、そとはいちめんのぎんせかいだった。', '早上，一打开窗帘，外边是一片银装素裹的世界。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('d6f44d4f-c6ff-440c-a38e-14879975a1e4', '2400d7bc-e472-49f3-9f78-e953da3a43b8', '田中さんはご飯を食べ終わると、すぐに勉強を始めました。', 'たなかさんはごはんをたべおわると、すぐにべんきょうをはじめました。', '田中刚吃完饭就开始学习了。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('7d1800e2-b5de-4d34-ae6d-6c4f226e5e88', '2400d7bc-e472-49f3-9f78-e953da3a43b8', '兄は学校から帰ると、何も言わないまま自分の部屋に入った。', 'あにはがっこうからかえると、なにもいわないままじぶんのへやにはいった。', '哥哥从学校回来，什么也没说就进了自己的房间。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('dd510d76-6ade-450d-be37-9ff6329bc847', 'もし', NULL, 'N4', 'もし＋句子', 'もし＋句子', '“如果……”。', '「もし」多用于句首，后面接表示假设的句子，常与「たら」「なら」「ば」搭配使用。', 577, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('ddd77080-5c92-4b0a-8aa2-d9d9fcc08f24', 'dd510d76-6ade-450d-be37-9ff6329bc847', 'もし彼が来たら、知らせてください。', 'かれがきたら、しらせてください。', '他如果来的话，请告诉我。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('561a1a16-a014-4470-9aa7-1905a9165d12', 'dd510d76-6ade-450d-be37-9ff6329bc847', 'もし明日は雨ならば、試合が中止になります。', 'あしたはあめならば、しあいがちゅうしになります。', '如果明天下雨的话，比赛就取消。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('e8a4c08e-362c-4e54-ba07-5468d6e98e82', 'もし～ても', NULL, 'N4', 'もし～ても', 'もし～ても', '“就算……”。', '「もし～ても」表示表示即使前项成立，也不能改变后项情况；往往含有“虽然那种情况不大会出现，不过……”这样一种情绪。', 578, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('b1576bd1-9f1f-4b44-a1c0-c5f97477c6fe', 'e8a4c08e-362c-4e54-ba07-5468d6e98e82', '加藤「明日はサッカーの試合です。もし雨が降っても試合をします。頑張ってください。」みんな「はい、頑張ります。」', 'かとう「あしたはサッカーのしあいあめがふしあいをします。がんばってください。」みんな「はい、がんばります。」', '加藤：“明天就是足球比赛了。就算下雨也会比赛。请大家加油。”\n大家：“嗯，我们会努力的。”', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('f45a5d67-1519-483a-8203-c5e98e8c96a1', 'e8a4c08e-362c-4e54-ba07-5468d6e98e82', 'もし失敗しても、がっかりしないでください。', 'しっぱいしても、がっかりしないでください。', '就算失败了，也请不要泄气。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('bf4599c6-3496-48b4-b697-5f4a517c0a86', '～といい', NULL, 'N4', '～といい', '～といい', '“……的话就好了”。表示愿望。', '「～といい」常用于表示现实的情况可能与预期不符，或表示说话人的愿望等。常与「が」「けど」「のに」等表示转折的词搭配使用。', 579, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('39de222a-393b-4fe7-845e-0d6cc1fc7700', 'bf4599c6-3496-48b4-b697-5f4a517c0a86', '病気が早くよくなるといいですね。', 'びょうきがはやくよくなるといいですね。', '要是能快点痊愈的话就好了。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('f9e020f4-f140-4a19-a258-3646b80ac7b5', 'bf4599c6-3496-48b4-b697-5f4a517c0a86', '部屋がもっと広いといいのになあ。', 'へやがもっとひろいといいのになあ。', '房间要再大点儿就好了。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('187a1fb5-6548-4bb7-86ae-dcc4874b0058', '～ため（に）', NULL, 'N4', '名词＋の/动词辞书形＋ために', '名词＋の/动词辞书形＋ために', '“由于……”“因为……”。表示客观原因。\n“为了……”。', '「～ため（に）」的后项大多是消极的结果，而且不能接表示推测、命令、劝诱等内容的句子。\n「～ために」表示目的时，前后两句的主语要一致。', 580, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('92af4409-a9bc-4843-91a4-ef9f59d15ec1', '187a1fb5-6548-4bb7-86ae-dcc4874b0058', '携帯電話を忘れたために、連絡できませんでした。', 'けいたいでんわをわすれたために、れんらくできませんでした。', '因为忘带手机，所以无法联络。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('227837ff-7425-4b88-9f84-dfd1290f7195', '187a1fb5-6548-4bb7-86ae-dcc4874b0058', '雪がたくさん降ったため試合が中止された。', 'ゆきがたくさんふしあいがちゅうしされた。', '因为降雪量太大，所以比赛取消了。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('6de29ff5-b984-4051-bc90-a6c1870d2616', '187a1fb5-6548-4bb7-86ae-dcc4874b0058', '高山選手は試合前のインタビューで、「いつも応援してくれているファンのためにも勝ちたい。」と語った。', 'たかやませんしゅはしあいまえのインタビューで、「いつもおうえんかちたい。」とかたった。', '高山选手在比赛前接受采访时说道：“即便是为了一直以来支持我的粉丝，我也想赢得这场比赛”。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('04fb562b-60c8-417c-9995-dd1e8f465e5a', '187a1fb5-6548-4bb7-86ae-dcc4874b0058', '日本で働くために日本語を勉強している。', 'にほんではたらにほんごをべんきょうしている。', '为了在日本工作而学习日语。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('d6c3d7e4-4184-4eda-b161-e25c9e1e8592', '～よう（に）', NULL, 'N4', '动词辞书形/动词「ない形」/动词可能形＋よう（に）', '动词辞书形/动词「ない形」/动词可能形＋よう（に）', '“为了……”，表示目的。', '「～よう（に）」表示将某种状态作为目标，并朝着它努力。「～よう（に）」的前面要用非意志性动词，如「できる」（可以）、「わかる」（明白）、「 見[み]える」（看到）、「 聞[き]こえる」（听到）等。前后短句的主语可以一致也可以不一致。', 581, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('5b6e828a-cffb-4d29-863c-0a64c98fbb81', 'd6c3d7e4-4184-4eda-b161-e25c9e1e8592', '高木「山村さんは、いつもポケットにメモ帳を入れているんですか。」山村「はい。思いついたアイデアを忘れてしまわないように必ず持ち歩くようにしているんです。」', 'こうぼく「やまむらさんは、いつもポケットにメモちょうをいれているんですか。」やまむら「はい。おもいついたアイデアをわすかならずもちあるくようにしているんです。」', '高木：“山村，你口袋里一直放着便签吗？”\n山村：“是的，我肯定要随身带着的，以免把想到的点子给忘了。”', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('3d980ef1-ab52-4d11-9511-920059179b36', 'd6c3d7e4-4184-4eda-b161-e25c9e1e8592', '今度の試合に勝てるように一生懸命頑張ります。', 'こんどのしあいにかいっしょうけんめいがんばります。', '为了能在这次的比赛中取胜而拼命努力。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('16aba303-831c-49de-9c3f-e069ad8439e0', '～ようになる', NULL, 'N4', '动词辞书形/动词「ない形」/动词可能形＋ようになる', '动词辞书形/动词「ない形」/动词可能形＋ようになる', '“变得……”“逐渐会……”。', '「～ようになる」表示某种状态的变化，从不可能到可能的转变。', 582, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('ec075afc-2db5-4b6d-9c4b-3ea4be1fa744', '16aba303-831c-49de-9c3f-e069ad8439e0', '私の娘は、小さい時は体が弱かったが、小学校に入学したころからは、だんだん風邪を引いたり熱を出したりしないようになった。', 'わたしのむすめは、ちいさいときはからだがよわかったが、しょうがっこうににゅうがくしたころからは、だんだんかぜをひいたりねつをだしたりしないようになった。', '我女儿小时候身体很差，但自从上了小学之后，渐渐变得不太会感冒或者发烧了。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('bcdc820b-b910-48f5-ae0a-89b85a9a35f5', '16aba303-831c-49de-9c3f-e069ad8439e0', '子どもが生まれたことで、食べ物の安全を気にするようになった。', 'こどもがうまれたことで、たべもののあんぜんをきにするようになった。', '孩子的出生让我开始注意食品安全。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('dc0bca90-1c20-4b10-8137-00bc5f9ee71c', '～ようにする', NULL, 'N4', '动词辞书形/动词「ない形」＋ようにする', '动词辞书形/动词「ない形」＋ようにする', '“要做到……”“设法做到……”。', '「～ようにする」表示为了实现某种状态而做或者不做某事。', 583, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('26f49622-a8bc-43b1-9786-f0c0aecbd0ae', 'dc0bca90-1c20-4b10-8137-00bc5f9ee71c', '高木「山村さんは、いつもポケットにメモ帳を入れているんですか。」山村「はい。思いついたアイデアを忘れてしまわないように必ず持ち歩くようにしているんです。」', 'こうぼく「やまむらさんは、いつもポケットにメモちょうをいれているんですか。」やまむら「はい。おもいついたアイデアをわすれてしまわないようにかならずもちあるくようにしているんです。」', '高木：“山村，你口袋里一直放着便签吗？”\n山村：“是的，我肯定要随身带着的，以免把想到的点子给忘了。”', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('f9a5fd5d-dbf8-4071-b80f-8b0bac8ae011', 'dc0bca90-1c20-4b10-8137-00bc5f9ee71c', '夜は甘いものを食べないようにしています。', 'よるはあまいものをたべないようにしています。', '晚上努力做到不吃甜食。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('395e5333-2fb1-40e3-b52d-0b69599c4bd7', '～（よ）うとする', NULL, 'N4', '动词意志形＋とする', '动词意志形＋とする', '“打算……”“想要……”。', '「～（よ）うとする」前面接动词意志形，表示为实现该动作而进行努力或尝试。', 584, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('1968a0da-413d-476a-bdbc-365c195b77ea', '395e5333-2fb1-40e3-b52d-0b69599c4bd7', '一番になろうとして、みんな一生懸命走る。', 'いちばんになろうとして、みんないっしょうけんめいはしる。', '因为想得第一名，大家都在全力奔跑。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('ccf1def2-822f-4651-be93-9305ade64a05', '395e5333-2fb1-40e3-b52d-0b69599c4bd7', '家を出ようとした時、電話がかかってきました。', 'いえをでとき、でんわがかかってきました。', '正打算出门的时候打来了电话。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('ed795947-45d3-4594-af1e-a975aad048ad', '～ではなく', NULL, 'N4', '～ではなく', '～ではなく', '「～ではなく」意为“不是……（而是……）”。', '「～ではなく」表示否定前项，肯定后项；口语中通常用「～じゃなく」。', 585, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('28d7c6c2-9e66-4a61-80c8-e177fe7dbafe', 'ed795947-45d3-4594-af1e-a975aad048ad', 'わたしは雨ではなく、風が強いほうが天気が悪いと思う。', 'わたしはあめではなく、かぜがつよいほうがてんきがわるいとおもう。', '我觉得不是雨天，而是刮大风的天气才是坏天气。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('fa46325b-68b8-4c22-8745-59aad0e1eaf7', 'ed795947-45d3-4594-af1e-a975aad048ad', 'A「Bさんの地図はいいですね。どこで買ったんですか。」B「買ったんじゃなくて、ホテルの人がくれたんです。」', 'A「Bさんのちずはいいですね。どこでかったんですか。」B「かったんじゃなくて、ホテルのひとがくれたんです。」', 'A：“你的地图很不错啊，哪里买的啊？”\nB：“不是买的，是宾馆的人给我的。”', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('e4164cdd-4f2f-491e-b0c7-554d96b47203', '～かわりに', NULL, 'N4', '～かわりに', '～かわりに', '“代替……”。\n“取代……”。\n“不……而……”。\n“……同时，（条件是）……”。\n表示转折，“虽然……但是……”。', '表示代替某人做某事。\n表示取代某事物。\n表示不做某事而做另外一件事。\n表示补偿、报答或交换条件。「そのかわりに」可以作为接续词使用。\n表示事物相反的两面，即表示某事物既有积极的一面，又有消极的一面，而且两者是相互关联的。', 586, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('4a6d1ed2-57bd-49e7-88b8-09d29bacf0c7', 'e4164cdd-4f2f-491e-b0c7-554d96b47203', '社長のかわりに、副社長が挨拶をした。', 'しゃちょうのかわりに、ふくしゃちょうがあいさつをした。', '副社长代替社长致辞。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('1e46383b-082f-4c86-ae70-2d57561e699a', 'e4164cdd-4f2f-491e-b0c7-554d96b47203', 'わたしが課長のかわりに、会議に出た。', 'わたしがかちょうのかわりに、かいぎにでた。', '我代替课长出席了会议。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('7fda607e-297a-49b9-8f3b-8017b1487d98', 'e4164cdd-4f2f-491e-b0c7-554d96b47203', 'お酒のかわりに、お茶を飲みましょう。', 'おさけのかわりに、おちゃをのみましょう。', '让我们以茶代酒吧。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('3053220c-61df-4333-824f-f949ebe6a60d', 'e4164cdd-4f2f-491e-b0c7-554d96b47203', '現金で払うかわりに、カードで払う。', 'げんきんではらうかわりに、カードではらう。', '不用现金，用信用卡付款。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('7fb52ad3-1eff-4b5d-8f46-95eface212aa', 'e4164cdd-4f2f-491e-b0c7-554d96b47203', '大学に行くかわりに、専門学校に行く。', 'だいがくにいくかわりに、せんもんがっこうにいく。', '没上大学，而去读了专科学校。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('c27d7911-8722-49fa-a9cf-c28164a3ed4d', 'e4164cdd-4f2f-491e-b0c7-554d96b47203', '映画を見に行くかわりに、うちでテレビを見る。', 'えいがをみにいくかわりに、うちでテレビをみる。', '不去看电影，而是在家里看电视。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('5bb476b6-77ef-4e87-ac1a-d75427c0dbbd', 'e4164cdd-4f2f-491e-b0c7-554d96b47203', 'ノートを貸してもらったかわりに、昼ごはんをごちそうしよう。', 'ノートをかしてもらったかわりに、ひるごはんをごちそうしよう。', '你借给我笔记，我请你吃午饭吧。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('579f7778-231c-4915-ab9b-841854e36f2c', 'e4164cdd-4f2f-491e-b0c7-554d96b47203', '日本語を教えてあげるから、そのかわりに、英語を教えてください。', 'にほんごをおしえてあげるから、そのかわりに、えいごをおしえてください。', '我教你日语，（作为交换），请你教我英语。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('2512f6a6-c44b-41bf-b080-54604fa22a14', 'e4164cdd-4f2f-491e-b0c7-554d96b47203', 'この料理はおいしいかわりに、値段が高い。', 'このりょうりはおいしいかわりに、ねだんがたかい。', '这道菜很好吃，但是价格太贵了。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('ac5e40d9-723a-4f1d-9b2d-f8834bdf5136', 'e4164cdd-4f2f-491e-b0c7-554d96b47203', '彼はスポーツが得意なかわりに、勉強が苦手だ。', 'かれはスポーツがとくいなかわりに、べんきょうがにがてだ。', '他虽然擅长体育，但学习成绩不好。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('9d1c3bde-6ce6-46ea-a54d-39550640a2cd', 'ちっとも～ない', NULL, 'N4', 'ちっとも＋い形容词词干＋く/动词「ない形」/な形容词词干＋で＋ない', 'ちっとも＋い形容词词干＋く/动词「ない形」/な形容词词干＋で＋ない', '“一点也不……”。', '「ちっとも～ない」表示完全否定。', 587, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('7c9dca9d-edf8-49d4-9d70-4f4a5a4eeb6a', '9d1c3bde-6ce6-46ea-a54d-39550640a2cd', '彼が作った料理はちっともおいしくない。', 'かれがつくったりょうりはちっともおいしくない。', '他做的菜一点也不好吃。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('428eb483-2618-4ad2-a8de-2863a3b186ff', '9d1c3bde-6ce6-46ea-a54d-39550640a2cd', '彼女の気持ちをちっとも気付かなかった。', 'かのじょのきもきづかなかった。', '完全没有注意到她的想法。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('a23139ab-d38b-49c0-96c8-349da3b26839', 'おもに', NULL, 'N4', 'おもに', 'おもに', '“主要”。', '「おもに」用于表示大部分的情况。', 588, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('ace552dc-eee1-4ef6-9d99-0acebe0ef4ad', 'a23139ab-d38b-49c0-96c8-349da3b26839', 'この村ではおもに米を生産しています。', 'このむらこめをせいさんしています。', '这个村子主要生产大米。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('4e8e2011-f847-4105-9ac7-cc775335bb96', 'a23139ab-d38b-49c0-96c8-349da3b26839', '朝ご飯はおもにお粥を食べます。', 'あさごはんはおもにおかゆをたべます。', '早饭主要喝粥。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('49dbc52a-61ac-47d5-8c1b-e7e4ed06bda8', '～ないで', NULL, 'N4', '动词「ない形」＋で', '动词「ない形」＋で', '“不……而……”“没……就……”。', '「～ないで」表示在没有发生前项的情况下就发生了后项，前后主语一致。', 589, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('dd7734f4-a1e0-403a-8adb-6d6d9fe217d2', '49dbc52a-61ac-47d5-8c1b-e7e4ed06bda8', 'ボールペンで書かないで、鉛筆で書きます。', 'ボールペンでかかないで、えんぴつでかきます。', '不要用圆珠笔写，用铅笔写。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('edf31269-ce83-42f7-a200-613ba174ed3f', '49dbc52a-61ac-47d5-8c1b-e7e4ed06bda8', '昨日は歯を磨かないで寝ました。', 'きのうははをみがねました。', '昨天没刷牙就睡了。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('021dc362-7eb4-4024-bdcd-6dc6f8fde21e', '49dbc52a-61ac-47d5-8c1b-e7e4ed06bda8', 'わたしはコーヒーに砂糖を入れないで飲みます。', 'わたしはコーヒーにさとうをいのみます。', '我喝咖啡不加糖。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('e0e13d84-3d08-49c3-94c8-77ba428b372b', '～なくて', NULL, 'N4', '～なくて', '～なくて', '“不……”“没……”。', '「～なくて」表示前后事项的并列，只不过前项是表示否定的；前后句主语可以不一致。', 590, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('26d6aee1-23f5-47b7-920a-93954f0b7dc0', 'e0e13d84-3d08-49c3-94c8-77ba428b372b', 'あの店はあまり高くなくて、店員も親切です。', 'あのみせはあまりたかくなくて、てんいんもしんせつです。', '那家店又不贵，店员还很热情。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('8cc6f28a-69c6-4af8-a97c-a5923dcf92ec', 'e0e13d84-3d08-49c3-94c8-77ba428b372b', '子どもが勉強しなくて、親が心配している。', 'こどもがべんきょうしなくて、おやがしんぱいしている。', '孩子不学习，父母很担心。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('cdc42053-3e74-4c9d-8138-2916366183d2', '～によると/によれば', NULL, 'N4', '名词＋によると/によれば', '名词＋によると/によれば', '“根据……”。表示传闻的出处或消息的来源等。', '「～によると/によれば」表示传闻的出处或信息的来源，常与「～そうだ」（听说）、「～らしい」（好像）、「～だろう」（大概）等表示推测的句型搭配使用。', 591, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('f6d7194d-81e1-4c50-8c67-0ab54c1fdd97', 'cdc42053-3e74-4c9d-8138-2916366183d2', '天気予報によると今夜は雪が降るそうです。', 'てんきよほうこんやはゆきがふるそうです。', '据天气预报说，今晚会下雪。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('598c93ed-e4b9-4364-a4b9-242ca8116157', 'cdc42053-3e74-4c9d-8138-2916366183d2', '吉田さんによれば、鈴木さんは風邪を引いたので、会社を休んだそうだ。', 'よしださんによれば、すずきさんはかぜをひいたので、かいしゃをやすんだそうだ。', '据吉田说，铃木因为患了感冒，所以没来上班。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('67219754-9566-41f9-a6d0-0cf8fbf53347', '～がする', NULL, 'N4', '名词＋がする', '名词＋がする', '“感觉到……”。', '「～がする」接在表示触觉、味觉、听觉、嗅觉等类型的名词后，表示有某种感觉。', 592, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('fc0fe329-e78e-4956-8f3c-ddb6caa33140', '67219754-9566-41f9-a6d0-0cf8fbf53347', '台所からいいにおいがします。', 'だいどころからいいにおいがします。', '从厨房飘来了香味。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('962bfe2d-dea9-4a4f-a6f5-33932156631f', '67219754-9566-41f9-a6d0-0cf8fbf53347', '隣の家でピアノの音がしている。', 'となりのいえでピアノのおとがしている。', '从邻居家传来钢琴声。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('4d859278-0e82-4912-b367-4f18c7e35961', '67219754-9566-41f9-a6d0-0cf8fbf53347', '今、隣の部屋で変な音がしました。', 'いま、となりのへやでへんなおとがしました。', '刚才隔壁房间发出了奇怪的声响。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('7d4d6499-5fcc-4e6f-9c35-0fd58f5b2dcc', '～か～ないか', NULL, 'N4', '动词辞书形＋か＋动词「ない形」＋か', '动词辞书形＋か＋动词「ない形」＋か', '“做……还是不做……”。', '「～か～ないか」表示做或不做某事的两种选择。', 593, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('56c2a833-2225-465e-867f-648bf63edb9f', '7d4d6499-5fcc-4e6f-9c35-0fd58f5b2dcc', 'その日の天気を見て、帽子を被るか被らないか決めています。', 'そのひのてんきをみて、ぼうしをかぶかぶきめています。', '视那天的天气情况决定戴不戴帽子。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('8c10c8b6-9b85-4a47-afc2-ee87f8a5060f', '7d4d6499-5fcc-4e6f-9c35-0fd58f5b2dcc', '留学に行くか行かないかを迷っています。', 'りゅうがくにいいかないかをまよっています。', '为究竟去不去留学而苦恼。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('6413db7a-464e-4b58-b184-6d1b84f5b921', '～かどうか', NULL, 'N4', '～かどうか', '～かどうか', '“是否……”。表示疑问或难以作出判断。', '「～かどうか」表示选择疑问，与「～か～ないか」意思相近。是将「～ないか」的部分替换成了表示不确定的疑问的「～どうか」。「～かどうか」多用于口语。', 594, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('088fa12c-b356-48c6-8d84-9491b3e2e216', '6413db7a-464e-4b58-b184-6d1b84f5b921', '中田さんが大学を卒業できたかどうか知っていますか。', 'なかださんがだいがくをそつぎょうしっていますか。', '你知道中田是否从大学顺利毕业了吗？', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('41fe3761-299d-4bff-bde8-8842026e290e', '6413db7a-464e-4b58-b184-6d1b84f5b921', '彼がこのプレゼントを喜ぶかどうかわかりません。', 'かれがこのプレゼントをよろこぶかどうかわかりません。', '我不知道他喜欢不喜欢这个礼物。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('2f8f7500-8fac-484e-90dd-46f4c4deb5d0', '～だい/かい', NULL, 'N4', '句子普通形＋だい/かい', '句子普通形＋だい/かい', '表示疑问。其中「～だい」需与疑问词搭配使用。', '「～だい/かい」表示疑问，是男子的口语表达方式。', 595, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('ff4b20aa-c8a9-41e7-b878-beaece029599', '2f8f7500-8fac-484e-90dd-46f4c4deb5d0', '今何時だい。', 'いまなんじだい。', '现在几点啊？', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('f38e2c79-d428-4f21-9a47-c7a6ac8bd9a2', '2f8f7500-8fac-484e-90dd-46f4c4deb5d0', 'どうだい。元気かい。', 'どうだい。げんきかい。', '怎么样？（你）身体还好吗？', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('b9b4cd86-5ffc-4eed-b804-f6a6f199a6c5', '2f8f7500-8fac-484e-90dd-46f4c4deb5d0', '行くかい。', 'いくかい。', '（你）去吗？', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('8b988cc6-2d75-4d4c-9e55-d9e479f7e775', '～ことがある', NULL, 'N4', '动词「た形」＋ことがある', '动词「た形」＋ことがある\n动词辞书形/动词「ない形」＋ことがある', '“有过……”。表示曾经有过某种经历，或曾经出现过某种现象。\n“有时……”“偶尔……”。', '「～ことがある」前面接动词过去时的时候，表示曾经做过某事。要表示没做过某事的情况时，否定形式加在「ある」上，即「～ことがない」。', 596, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('e11f75b3-2615-41dd-a3c3-85a0ff4ec779', '8b988cc6-2d75-4d4c-9e55-d9e479f7e775', '山下「田中さん、ABC大学のリュウ先生を知っていますか。」田中「お名前は聞いたことがありますが会ったことはありません。」', 'やました「たなかさん、ABCだいがくのリュウせんせいをしっていますか。」たなか「おなまえはきいたことがありますがあったことはありません。」', '山下：“田中，你认识ABC大学的刘老师吗？”\n田中：“名字听说过，但是没见过。”', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('cc951250-0800-48e5-a49f-496864d1396f', '8b988cc6-2d75-4d4c-9e55-d9e479f7e775', 'まだこのマンガを読んだことがありません。', 'まだこのマンガをよんだことがありません。', '我还没看过这本漫画。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('7c61f642-338c-4e9b-aa4c-b0506145676b', '8b988cc6-2d75-4d4c-9e55-d9e479f7e775', '時々日本の歌を歌うことがあります。', 'ときどきにほんのうたをうたうことがあります。', '我有时会唱日语歌。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('18d4125a-8ba1-4757-b513-392222cf75fa', '8b988cc6-2d75-4d4c-9e55-d9e479f7e775', '天気がいい日は、ここから遠くの山が見えることがあります。', 'てんきがいいひは、ここからとおくのやまがみえることがあります。', '天气好的话，从这儿能看到远处的山。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('fe572bd3-d0de-4ff8-afe8-25f52016af21', '8b988cc6-2d75-4d4c-9e55-d9e479f7e775', 'たまに朝ごはんを食べないことがあります。', 'たまにあさごはんをたべないことがあります。', '我偶尔会不吃早饭。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('b1a457dc-485e-4686-97fa-57e0a2020c6e', '～ことができる', NULL, 'N4', '动词辞书形＋ことができる', '动词辞书形＋ことができる', '“可以……”“能……”“会……”。表示某种能力或可能性。', '「～ことができる」表示可以做某事；其否定形式为「～ことができない」。', 597, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('696fda2b-4d2d-41ba-986a-db596617c313', 'b1a457dc-485e-4686-97fa-57e0a2020c6e', '昨日動物園に行ったら、先月生まれたばかりのライオンの赤ちゃんを見ることができました。', 'きのうどうぶつえんにいったら、せんげつうまれたばかりのライオンのあかちゃんをみることができました。', '昨天去了动物园，看到了上个月刚出生的小狮子。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('d22d5953-d14d-4567-b779-78982a00f13e', 'b1a457dc-485e-4686-97fa-57e0a2020c6e', '図書館でこの町の歴史を調べることができます。', 'としょかんでこのまちのれきしをしらべることができます。', '可以在图书馆里查阅这座城市的历史。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('3214dfd6-a240-4c4a-8c7b-d667beac921c', '～という', NULL, 'N4', '名词＋という＋名词', '名词＋という＋名词\n句子普通形＋という', '“叫作……”。表示下定义或对某事物进行解释说明。\n“说……”。', '「～という」前面接名词的时候，常用来表示事物的名称。\n「～という」前面接说的具体内容的时候表示引用，多用于引用第三人称的话。', 598, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('1da4ed91-f924-43e0-9c51-13b581603bca', '3214dfd6-a240-4c4a-8c7b-d667beac921c', 'ジョン「この『りかい』という言葉はどういう意味ですか。」アリ「ああ、確か『わかる』というような意味だったと思うんですけど。」', 'ことばはどういういみですか。」アリ「ああ、たしか『わかる』というようないみだったとおもうんですけど。」', '约翰：“‘りかい’这个单词是什么意思呢？”\n阿丽：“啊，我想它是‘明白’的意思。”', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('c1808689-2692-468f-898d-71adae977ea2', '3214dfd6-a240-4c4a-8c7b-d667beac921c', 'A「草色というのはどんな色ですか。」B「今わたしが着ているシャツのような、こんな色です。」', 'A「くさいろというのはどんないろですか。」B「いまわたしがきているシャツのような、こんないろです。」', 'A“所谓的草色是怎样的颜色呢？”\nB“就像我现在穿着的衬衫这样的颜色。”', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('2efa1506-3009-43fe-b299-516afefa86e3', '3214dfd6-a240-4c4a-8c7b-d667beac921c', '山下さんは「また電話します。」と言っていました。', 'やましたさんは「またでんわいっていました。', '山下说“我会再打电话的”。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('8e1701b1-db0c-4a51-9181-79766e0abf6e', '3214dfd6-a240-4c4a-8c7b-d667beac921c', '佐藤さんは日本料理がおいしいと言いました。', 'さとうさんはにほんりょうりいいました。', '佐藤说日本菜很好吃。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('ad7ee35d-c5c9-4bef-a7e2-51a70d894d8e', '～（よ）うと 思[おも]う', NULL, 'N4', '动词意志形＋と 思[おも]う', '动词意志形＋と 思[おも]う', '“我想……”“我打算……”。表示说话人的打算或计划。', '「～（よ）うと 思[おも]う」用于婉转地表达出自己的意愿，在疑问句中可以表示询问对方的意愿。', 599, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('930ba902-7dc0-42cf-8ea8-17144c35c03c', 'ad7ee35d-c5c9-4bef-a7e2-51a70d894d8e', '田中「山川さん、今日の夕食は何にするんですか。」山川「これから買い物に行って、カレーを作ろうと思います。」', 'たなか「やまかわさん、きょうのゆうしょくはなににするんですか。」やまかわ「これからかいものにいって、カレーをつくおもいます。」', '田中：“山川，今天晚饭打算吃什么？”\n山川：“我现在去买东西，准备做咖喱。”', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('950f831a-1ef4-4690-8973-7c1efc8de075', 'ad7ee35d-c5c9-4bef-a7e2-51a70d894d8e', '来月富士山に登ろうと思っています。', 'らいげつふじさんにのぼおもっています。', '我打算下个月爬富士山。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('4003ed54-b342-4a25-b4d1-ccc69a34dffb', 'あげる/さしあげる', NULL, 'N4', 'あげる/さしあげる', 'あげる/さしあげる', '“给……”，“送上……”。', '「あげる」表示自己或己方的人给别人东西，主语是自己或己方的人，通常可以省略。「さしあげる」表示把东西给地位比自己高的人，是「あげる」的自谦语。', 600, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('132878f7-9cdd-45b8-b6cf-df08e86ee5d4', '4003ed54-b342-4a25-b4d1-ccc69a34dffb', '私たちは、先生にプレゼントを用意して、最後の授業の日にさしあげる計画を立てています。', 'わたしたちは、せんせいにプレゼントをよういして、さいごのじゅぎょうのひけいかくをたてています。', '我们为老师准备了礼物，计划最后一堂课的时候送给他。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('8cf801f2-bc8e-4183-861e-bbe927cf2e60', '4003ed54-b342-4a25-b4d1-ccc69a34dffb', 'A「山川さんの誕生日にこの財布をあげるつもりです。」B「そうですか。きっと喜んで使ってくれるでしょう。」', 'A「やまかわさんのたんじょうびにこのさいふをあげるつもりです。」B「そうですか。きっとよろこんでつかってくれるでしょう。」', 'A：“山川生日的时候，我准备送他这个钱包。”\nB：“这样啊，他肯定会很高兴地用的吧。”', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('b0c5f288-4c58-45ea-a094-303d3a98bf59', '～てあげる/てさしあげる', NULL, 'N4', '动词「て形」＋あげる/さしあげる', '动词「て形」＋あげる/さしあげる', '“帮别人……”；“为您……”。', '「～てあげる」表示自己或己方的人为别人做某事，主语是自己或己方的人。「～てさしあげる」表示自己为地位比自己高的人做某事，是「～てあげる」的自谦语。', 601, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('aae9d406-08b4-4bd3-85e5-c11db867f17b', 'b0c5f288-4c58-45ea-a094-303d3a98bf59', 'A「けしゴム持ってる？」B「うん、持ってるよ。貸してあげるよ。」', 'A「けしゴムもってる？」B「うん、もってるよ。かしてあげるよ。」', 'A：“你有橡皮吗？”\nB：“嗯，有的。我借给你。”', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('ba70e99e-0a99-4ed2-a84b-a5a216b5dd56', 'b0c5f288-4c58-45ea-a094-303d3a98bf59', '吉田先生を駅まで車で送ってさしあげた。', 'よしだせんせいをえきまでくるまでおくってさしあげた。', '我开车把吉田老师送到了车站。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('88e970a9-7ec2-4137-beda-b2e1c0b578ac', 'もらう/いただく', NULL, 'N4', 'もらう/いただく', 'もらう/いただく', '“得到……”。', '「もらう」表示自己从别人那里获得东西，主语是自己或己方的人。「いただく」表示自己从地位比自己高的人那里获得东西，是「もらう」的自谦语。', 602, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('da36f9be-2cd7-4276-bc5c-3b57b0db45fb', '88e970a9-7ec2-4137-beda-b2e1c0b578ac', 'これは姉にもらった本です。', 'これはあねほんです。', '这是姐姐给我的书。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('c9dc713b-bbf5-4df0-bae5-0e4b12e70a40', '88e970a9-7ec2-4137-beda-b2e1c0b578ac', '誕生日に友だちからプレゼントをたくさんもらった。', 'たんじょうびにともだちからプレゼントをたくさんもらった。', '生日的时候从朋友那里收到了很多礼物。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('5eabc461-04a6-4639-a6c8-92a009e741f8', '88e970a9-7ec2-4137-beda-b2e1c0b578ac', '上司から指示をいただきました。', 'じょうしからしじをいただきました。', '从上司那里得到了指示。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('8c5559ce-2caa-4d2d-a877-e11277d1968d', '～てもらう/ていただく', NULL, 'N4', '动词「て形」＋もらう/いただく', '动词「て形」＋もらう/いただく', '“请……做……”，表示某人为自己或己方的人做某事。授予者用「に」或「から」表示。', '「～てもらう」一般用于平辈及家庭人员之间，「～ていただく」一般用于长辈、上司、客户等。当授予者不是人，而是国家、学校、公司等团体时，只能用「から」。', 603, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('87006ef2-879e-4943-9b8b-c8419fa3e57e', '8c5559ce-2caa-4d2d-a877-e11277d1968d', '山口「すみませんが、この書類を広田さんに渡しておいてもらえませんか。お願いします。」北川「いいですよ。」', 'やまぐち「すみませんが、このしょるいをひろたさんにわたしておいてもらえませんか。おねがいします。」きたがわ「いいですよ。」', '山口：“不好意思，能不能帮我把这份资料交给广田？拜托了。”\n北川：“好的。”', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('1727a511-14bb-45df-b9f7-402909050735', '8c5559ce-2caa-4d2d-a877-e11277d1968d', '学生「申し訳ありません。先週、本田先生に貸していただいた本を家に忘れて来てしまって……。」本田先生「ああ、明日でも大丈夫ですよ。」', 'がくせい「もうしわけありません。せんしゅう、ほんだせんせいにかほんをいえにわすれてきてしまって……。」ほんだせんせい「ああ、あしたでもだいじょうぶですよ。」', '学生：“对不起，我把上周让您借给我的书放在家里忘记拿来了。”\n本田先生：“啊，明天还我也不要紧。”', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('98979b5b-1adb-4f20-bbd9-d7ea0acab79e', 'くれる/くださる', NULL, 'N4', 'くれる/くださる', 'くれる/くださる', '“给……”。', '「くれる」表示别人给自己或己方的人某物，主语是别人。「くださる」是「くれる」的尊他语。', 604, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('b9c1b894-ba87-492f-8211-b2767e941122', '98979b5b-1adb-4f20-bbd9-d7ea0acab79e', '木田さんは、わたしに本をくれました。', 'きださんは、わたしにほんをくれました。', '木田给了我一本书。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('72f2a317-30c2-4bb8-a3b6-3141d6c28b1e', '98979b5b-1adb-4f20-bbd9-d7ea0acab79e', '彼女はチョコレートをくれました。', 'かのじょはチョコレートをくれました。', '她给了我巧克力。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('b0cd8685-93fd-469e-b3d4-8b1af19d1872', '98979b5b-1adb-4f20-bbd9-d7ea0acab79e', 'おじは万年筆をくださいました。', 'おじはまんねんひつをくださいました。', '叔叔给了我一支笔。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('a16f0834-b4e0-46ad-b497-7d41eb247868', '～てくれる/てくださる', NULL, 'N4', '动词「て形」＋くれる/くださる', '动词「て形」＋くれる/くださる', '“给我（们）做……”。', '「～てくれる」表示别人为自己或己方的人做某事。简体多用于地位比自己低或关系比较密切的人之间；也可以用于提醒对方做某事。「～てくださる」是「～てくれる」的尊他语。「くださる」接「ます」的形式是「くださいます」。', 605, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('1ee97930-f417-4fa3-b5ad-4f83cb75f41f', 'a16f0834-b4e0-46ad-b497-7d41eb247868', 'そちらの方がわたしの荷物を持ってくださいました。', 'そちらのかたがわたしのにもつをもってくださいました。', '是那位把我的行李拿过来的。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('ee703c05-55f3-4fe6-bf47-2a3ca609137b', 'a16f0834-b4e0-46ad-b497-7d41eb247868', '友だちが掃除を手伝ってくれた。', 'ともだちがそうじをてつだってくれた。', '朋友帮我一起打扫了。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('dc8aea31-5df7-4f4b-b499-5371c6de7441', 'やる', NULL, 'N4', 'やる', 'やる', '“给……”。', '「やる」表示自己把东西给地位比自己低的人或者是动植物，主语是自己。', 606, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('b0b97b78-8b18-4cc7-b4d2-d0a736064adc', 'dc8aea31-5df7-4f4b-b499-5371c6de7441', '金魚に餌をやる。', 'きんぎょにえさをやる。', '给金鱼喂饲料。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('37afee81-bc30-4e39-8221-300be55f03a2', 'dc8aea31-5df7-4f4b-b499-5371c6de7441', '庭にある木に水をやる。', 'にわにあるきにみずをやる。', '给庭院里的树浇水。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('8dc46e0c-d326-48d4-ad49-ad0dc360d611', 'dc8aea31-5df7-4f4b-b499-5371c6de7441', '時々部下に褒美をやる。', 'ときどきぶかにほうびをやる。', '时不时给部下褒奖。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('a0f4b02d-9e99-4f94-991b-f707634fa425', '～てやる', NULL, 'N4', '动词「て形」＋やる', '动词「て形」＋やる', '“给……”。', '「～てやる」表示自己为身份比自己低的人或动植物做某事，主语是自己。', 607, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('146e19d4-8837-4c88-bf29-cab6fd3c5ea6', 'a0f4b02d-9e99-4f94-991b-f707634fa425', '最近、子どもがピアノを習いたいと言い出した。私は、子どもがしたいと思うことはやらせてやりたいと思っている。', 'さいきん、こどもがピアノをならいたいといいだした。わたしは、こどもがしたいとおもうことはやらせてやりたいとおもっている。', '最近孩子提出来说想要学钢琴。我想让孩子去做自己想做的事情。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('f332aeb0-0407-4ac5-a787-da041dd07d6d', 'a0f4b02d-9e99-4f94-991b-f707634fa425', 'わたしが弟のシャツを洗ってやった。', 'わたしがおとうとのシャツをあらってやった。', '我帮弟弟洗了衬衫。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('9aa1b357-79ca-4d3c-8ea8-1d935b3aba87', 'a0f4b02d-9e99-4f94-991b-f707634fa425', '水泳は僕が教えてやるよ。', 'すいえいはぼくがおしえてやるよ。', '我教你游泳。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('d6698f2a-e1cd-4214-8068-356f404b0e71', '～てちょうだい', NULL, 'N4', '动词「て形」＋ちょうだい', '动词「て形」＋ちょうだい', '“请……”。', '「～てちょうだい」表示向对方提出某种请求；常见于女性或儿童对关系密切的人使用，正式场合一般不用。', 608, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('164a56e7-7154-493b-8afd-3e0a3aded7b6', 'd6698f2a-e1cd-4214-8068-356f404b0e71', 'その単語の読み方を教えてちょうだい。', 'そのたんごのよみかたをおしえてちょうだい。', '告诉我那个单词怎么念嘛。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('5ec682bb-caa2-4b8f-bdc3-207489252e64', 'd6698f2a-e1cd-4214-8068-356f404b0e71', 'お菓子を買ってちょうだい。', 'おかしをかってちょうだい。', '帮我买点心。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('6481e2b1-4c19-4f06-bae2-d2761c083144', 'd6698f2a-e1cd-4214-8068-356f404b0e71', 'その新聞を取ってちょうだい。', 'そのしんぶんをとってちょうだい。', '帮我拿下报纸。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('103e5300-2fcc-4236-ad4e-68f86f417d77', '～（さ）せてください/（さ）せないでください', NULL, 'N4', 'Ⅰ类动词「ない形」＋せてください/せないでください', 'Ⅰ类动词「ない形」＋せてください/せないでください\nⅡ类动词「ない形」＋させてください/させないでください\nⅢ类动词：（～）する→（～）させてください/させないでください 来[く]る→ 来[こ]させてください/させないでください', '“请让……”；“请不要让……”。', '「～（さ）せてください」表示请求对方让自己或第三方做某事，主语是对方。', 609, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('7adff61f-19a0-4726-927b-a77c8d351a8c', '103e5300-2fcc-4236-ad4e-68f86f417d77', 'その仕事はぜひわたしにやらせてください。', 'そのしごとはぜひわたしにやらせてください。', '那份工作请一定交给我来做。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('19d20c50-c651-40a1-ac5e-c17ef3c8737c', '103e5300-2fcc-4236-ad4e-68f86f417d77', '危ないですから、子どもを一人で遊ばせないでください。', 'あぶないですから、こどもをひとりであそばせないでください。', '很危险的，请不要让孩子单独玩耍。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('441a6936-88c7-4d37-87c0-883b2d1024c5', '103e5300-2fcc-4236-ad4e-68f86f417d77', '兄が怪我をしたので、明日はアルバイトを休ませてください。', 'あにがけがをしたので、あしたはアルバイトをやすませてください。', '因为哥哥受伤了，明天的打工请允许我请假。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('8b6eac22-7a5a-4c51-afa8-e46797b0463d', 'いらっしゃる', NULL, 'N4', 'いらっしゃる', 'いらっしゃる', '“在”“去”“来”。', '「いらっしゃる」是「いる」、「 行[い]く」和「 来[く]る」的尊他语。', 610, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('d2e3886d-6ef3-4bfe-895a-379efe5de93d', '8b6eac22-7a5a-4c51-afa8-e46797b0463d', '（田中先生の研究室で）学生「田中先生はいらっしゃいますか。」秘書「今、ほかの学生と話していらっしゃいますから、少々お待ちください。」', '（たなかせんせいのけんきゅうしつで）がくせい「たなかせんせいはいらっしゃいますか。」ひしょ「いま、ほかのがくせいとはなしていらっしゃいますから、しょうしょうおまちください。」', '学生：“请问田中老师在吗？”\n秘书：“田中老师现在正在和其他学生谈话，请稍等。”', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('0a24e3e9-ab2c-4bd4-8a7d-5ca58100d525', '8b6eac22-7a5a-4c51-afa8-e46797b0463d', 'どなたか質問のある方はいらっしゃいませんか。', 'どなたかしつもんのあるかたはいらっしゃいませんか。', '哪位要提问吗？', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('a50396d6-2a3b-4010-86c4-fa3c553ce4a9', '見[み]える/お 見[み]えになる', NULL, 'N4', '見[み]える/お 見[み]えになる', '見[み]える/お 見[み]えになる', '“来”。', '「 見[み]える/お 見[み]えになる」是「 来[く]る」的尊他语。', 611, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('aeb25c38-5322-4b51-8233-c789fc865245', 'a50396d6-2a3b-4010-86c4-fa3c553ce4a9', 'お客さまがお見えになりました。', 'おきゃくみえになりました。', '客人来了。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('a98ac078-566a-4f57-934c-570041299861', 'a50396d6-2a3b-4010-86c4-fa3c553ce4a9', '部長がお見えになりました。', 'ぶちょうみえになりました。', '部长来了。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('92a4f1bc-e6d2-45f4-bdad-36f8c773bb7f', 'おいでになる', NULL, 'N4', 'おいでになる', 'おいでになる', '“来”“去”“在”。', '「おいでになる」是「 来[く]る」「 行[い]く」「いる」的尊他语。', 612, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('a165bb90-135b-4feb-915a-2c11595d0077', '92a4f1bc-e6d2-45f4-bdad-36f8c773bb7f', 'A「先生はいつ見えますか。」B「まだおいでになるまで少し時間がありますから、そこで待っていてください。」', 'A「せんせいはいつみえますか。」B「まだおいでになるまですこしじかんがありますから、そこでまっていてください。」', 'A：“老师什么时候来？”\nB：“老师来还需要一些时间，请在那里稍等一下。”', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('ba695036-18bb-48a0-a9f5-e81aacb9f1a6', '92a4f1bc-e6d2-45f4-bdad-36f8c773bb7f', 'ゴールデンウィークはどこかへおいでになりますか。', 'ゴールデンウィークはどこかへおいでになりますか。', '黄金周您要去哪里玩吗？', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('b520af88-7d2f-4c23-80f1-7d2a35a69088', '92a4f1bc-e6d2-45f4-bdad-36f8c773bb7f', '先生は教室においでになりますか。', 'せんせいはきょうしつにおいでになりますか。', '老师在教室里吗？', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('f302d0d4-7b45-4ec2-a045-82e2b6215304', 'お 越[こ]しになる', NULL, 'N4', 'お 越[こ]しになる', 'お 越[こ]しになる', '“来”。', '「お 越[こ]しになる」是「 来[く]る」的尊他语。', 613, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('d48eb9db-1df1-47ac-91c3-6275e355d3fe', 'f302d0d4-7b45-4ec2-a045-82e2b6215304', '鈴木さんは日本からお越しになりました。', 'すずきさんはにほんこしになりました。', '铃木来自日本。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('1a0a5bfc-fa82-4c55-b185-1abc77ccd8c5', 'f302d0d4-7b45-4ec2-a045-82e2b6215304', '奥さまも一緒にお越しになりましたか。', 'おくさまもいっしょこしになりましたか。', '尊夫人也一同来了吗？', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('1c8c262b-2c1d-4d01-8690-4c677c8f2e16', 'おっしゃる', NULL, 'N4', 'おっしゃる', 'おっしゃる', '“说”。', '「おっしゃる」是「 言[い]う」的尊他语。', 614, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('53b3a1d9-5af1-4a5b-9038-65ce2b77f3ef', '1c8c262b-2c1d-4d01-8690-4c677c8f2e16', '意見がある方は、おっしゃってください。', 'いけんがあるかたは、おっしゃってください。', '有意见的请说出来。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('1b9ab1a5-0f2f-49c4-ae60-5f575bb01348', '1c8c262b-2c1d-4d01-8690-4c677c8f2e16', 'お名前は何とおっしゃいますか。', 'おなまえはなんとおっしゃいますか。', '您怎么称呼？', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('82e5d6aa-ce69-4f6e-b541-ce2e893643e2', 'ご 存[ぞん] 知[じ]です', NULL, 'N4', 'ご 存[ぞん] 知[じ]です', 'ご 存[ぞん] 知[じ]です', '“知道”。', '「ご 存[ぞん] 知[じ]です」是「 知[し]っている」的尊他语。', 615, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('115562d2-5f6b-4789-9ef8-f47abea04c24', '82e5d6aa-ce69-4f6e-b541-ce2e893643e2', '先生は山下さんの住所をご存知ですか。', 'せんせいはやましたさんのじゅうしょぞんじですか。', '老师知道山下住哪儿吗？', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('ec448e64-15e8-48b5-909a-eb007f4dc451', '82e5d6aa-ce69-4f6e-b541-ce2e893643e2', 'あの方をご存知ですか。', 'あのかたぞんじですか。', '您认识那位吗？', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('3d78c5a2-ea75-4663-9274-d971c9236f14', 'ご 覧[らん]になる', NULL, 'N4', 'ご 覧[らん]になる', 'ご 覧[らん]になる', '“看”“阅读”。', '「ご 覧[らん]になる」是「 見[み]る」和「 読[よ]む」的尊他语。', 616, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('888652dc-1b7e-4bc0-95e0-4390e82b0807', '3d78c5a2-ea75-4663-9274-d971c9236f14', '先輩「西田さん、先生が西田さんの論文が載っている雑誌をご覧になって、よく頑張っているねとおっしゃっていましたよ。」西田「え、先輩、本当ですか。」', 'せんぱい「にしださん、せんせいがにしださんのろんぶんがのっているざっしをご覧になって、よくがんばっているねとおっしゃっていましたよ。」にしだ「え、せんぱい、ほんとうですか。」', '学长：“西田，老师看了刊登了你的论文的杂志，说你很努力呢。”\n西田：“哦？学长，是真的吗？”', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('69e4a3aa-4195-4e75-9a72-34fe6327737a', '3d78c5a2-ea75-4663-9274-d971c9236f14', '中川さんが描いた絵をご覧になりましたか。', 'なかがわさんがかいたえらんになりましたか。', '您看了中川画的画了吗？', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('9de87531-9b6e-4854-bc18-ad008fe3d1b7', 'ご 覧[らん]ください', NULL, 'N4', 'ご 覧[らん]ください', 'ご 覧[らん]ください', '“请看”。', '「ご 覧[らん]ください」是「 見[み]てください」的尊他语。', 617, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('6b925116-1c45-4a1d-856c-6708844627bd', '9de87531-9b6e-4854-bc18-ad008fe3d1b7', '添付ファイルをご覧ください。', 'てんぷらんください。', '请看附件。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('62889232-04a0-4136-9d72-10f08705c106', '9de87531-9b6e-4854-bc18-ad008fe3d1b7', '詳しくはこちらをご覧ください。', 'くわらんください。', '具体事宜请看此处。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('87d2a37b-8c16-4160-9bbb-2fa84bb037d1', '召[め]す', NULL, 'N4', '召[め]す', '召[め]す', '“吃”“喝”“穿”。', '「 召[め]す」是「 食[た]べる」「 飲[の]む」「 着[き]る」的尊他语。', 618, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('7d9ccc9f-1187-4ea6-8f96-feff72a44aab', '87d2a37b-8c16-4160-9bbb-2fa84bb037d1', '朝ご飯をお召しになりましたか。', 'あさごはんめしになりましたか。', '您吃过早饭了吗？', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('80fb7d6a-3df8-43f0-ab35-94c7e95a7128', '87d2a37b-8c16-4160-9bbb-2fa84bb037d1', '梅酒をお召しになってください。', 'うめしゅめしになってください。', '请喝梅酒。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('6a1d6bd4-549f-4512-904d-acd97a01b96f', '87d2a37b-8c16-4160-9bbb-2fa84bb037d1', '奥さま、素敵なお着物をお召しになっていますね。', 'おくさま、すてきなおきものめしになっていますね。', '夫人，您穿的和服真漂亮。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('78b962e0-4df2-44f6-aae9-40720a46d0e1', 'あがる', NULL, 'N4', 'あがる', 'あがる', '“吃”“喝”。', '「あがる」是「 食[た]べる」「 飲[の]む」的尊他语。', 619, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('a4646432-6111-4669-b7bf-306494a57cdd', '78b962e0-4df2-44f6-aae9-40720a46d0e1', '先生は毎日お魚をあがりますか。', 'せんせいはまいにちおさかなをあがりますか。', '老师每天都吃鱼吗？', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('d467b1da-a466-4fc0-9534-8d10153a0a1a', '78b962e0-4df2-44f6-aae9-40720a46d0e1', '新しい課長はどのくらいお酒があがれますか。', 'あたらしいかちょうはどのくらいおさけがあがれますか。', '新课长能喝多少酒？', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('33811a90-d2d1-4576-a78f-efb639d9e47b', '召[め]し 上[あ]がる', NULL, 'N4', '召[め]し 上[あ]がる', '召[め]し 上[あ]がる', '“吃”“喝”。', '「 召[め]し 上[あ]がる」是「 食[た]べる」和「 飲[の]む」的尊他语。', 620, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('c88a675b-6a1e-47a6-99f7-be0bee8cc04f', '33811a90-d2d1-4576-a78f-efb639d9e47b', 'どうぞ、温かいうちにお召し上がりください。', 'どうぞ、あたためあがりください。', '请趁热吃。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('d0aa11ae-71d6-419d-a703-80ee0bf87980', '33811a90-d2d1-4576-a78f-efb639d9e47b', 'どうぞケーキを召し上がってください。', 'めあがってください。', '请尝尝蛋糕。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('c7c68a22-9399-479b-9198-8d7906b46a06', 'お/ご～なさる', NULL, 'N4', 'お＋Ⅰ类动词、Ⅱ类动词「ます形」＋なさる', 'お＋Ⅰ类动词、Ⅱ类动词「ます形」＋なさる\nご＋Ⅲ类动词词干＋なさる', '用法比「お/ご～になる」陈旧。', '表达对尊长等的行为的敬意。「～なさる」接「ます」的形式是「～なさいます」。', 621, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('bede6018-cdad-437d-bfc6-bc629ba3c33f', 'c7c68a22-9399-479b-9198-8d7906b46a06', '部長は新企画についてお話しなさいました。', 'ぶちょうはしんきかくはなしなさいました。', '部长谈论了新的企划。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('fc4c5ae0-556b-4611-b218-dd82249eb536', 'c7c68a22-9399-479b-9198-8d7906b46a06', '事前にご予約なさったほうがいいと思います。', 'じぜんよやくなさったほうがいいとおもいます。', '我认为最好事先预约好。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('bda533cf-ca22-496e-835c-4e91d27625a6', 'お/ご～になる', NULL, 'N4', 'お＋Ⅰ类动词、Ⅱ类动词「ます形」＋になる', 'お＋Ⅰ类动词、Ⅱ类动词「ます形」＋になる\nご＋Ⅲ类动词词干＋になる', '对动作主体的尊敬。', '相比「れる/られる」敬意程度更高。词干只有一个假名的Ⅱ类动词以及「 来[く]る」不能用于本句型。', 622, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('6d2664ac-0f79-4b3c-a382-4e68bbd112a0', 'bda533cf-ca22-496e-835c-4e91d27625a6', '（病院で）村山「すみません。予約をした村山ですが。」受付「はい、村山さんですね。では、そちらの椅子におかけになってお待ちください。」', '（びょういんで）むらやま「すみません。よやくをしたむらやまですが。」うけつけ「はい、むらやまさんですね。では、そちらのいすにおかけになっておまちください。」', '村山：“不好意思，我是预约过的村山。”\n前台：“好的，村山先生是吧？那请您坐在那里等一下。”', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('c4dda2ae-6b0c-4a24-a780-79d993cdc4e0', 'bda533cf-ca22-496e-835c-4e91d27625a6', '先生はもうお帰りになりました。', 'せんせいかえりになりました。', '老师已经回去了。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('fa3456aa-3c12-4a6f-a588-1700fb52ee79', 'お/ご～ください', NULL, 'N4', 'お＋Ⅰ类动词、Ⅱ类动词「ます形」＋ください', 'お＋Ⅰ类动词、Ⅱ类动词「ます形」＋ください\nご＋Ⅲ类动词词干＋ください', '请求别人做某事的尊敬说法。', '表达的意思与「～てください」一样，但是敬意程度更高。词干只有一个假名的Ⅱ类动词以及「 来[く]る」不能用于本句型。', 623, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('328f2448-d804-443c-b543-c30502a2b9a2', 'fa3456aa-3c12-4a6f-a588-1700fb52ee79', '（病院で）村山「すみません。予約をした村山ですが。」受付「はい、村山さんですね。では、そちらの椅子におかけになってお待ちください。」', '（びょういんで）むらやま「すみません。よやくをしたむらやまですが。」うけつけ「はい、むらやまさんですね。では、そちらのいすまちください。」', '村山：“不好意思，我是预约过的村山。”\n前台：“好的，村山先生是吧？那请您坐在那里等一下。”', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('d465bc1f-1cbd-405a-b38c-fec573cce026', 'fa3456aa-3c12-4a6f-a588-1700fb52ee79', 'では、お元気で。ご両親にもどうぞよろしくお伝えください。', 'では、おげんきで。ごりょうしんつたえください。', '那么，祝您身体健康，请代我向您父母问好。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('8f119ba7-64ee-486c-8db6-c739bfc3e9e4', '敬语助动词「れる/られる」', NULL, 'N4', 'Ⅰ类动词「ない形」＋れる', 'Ⅰ类动词「ない形」＋れる\nⅡ类动词「ない形」＋られる\nⅢ类动词（～）する→（～）される； 来[く]る→ 来[こ]られる', '尊他语的固定表达形式。', '「～れる/られる」是敬意程度比较低的尊他语。', 624, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('594335dd-da36-4c18-9639-235b6bd4ee4b', '8f119ba7-64ee-486c-8db6-c739bfc3e9e4', '佐藤さんは何時に帰られましたか。', 'さとうさんはなんじにかえられましたか。', '佐藤几点回来的？', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('653a4180-495f-4d43-9283-ddb5f0c67db7', '8f119ba7-64ee-486c-8db6-c739bfc3e9e4', '部長は来週アメリカに行かれるそうです。', 'ぶちょうはらいしゅうアメリカにいかれるそうです。', '据说部长下周去美国。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('d87775ea-44da-4008-be21-4e4d3fa0eadb', 'いたす', NULL, 'N4', 'いたす', 'いたす', '“做”。', '「いたす」是「する」的自谦语。', 625, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('91c5ba4d-eae5-4c93-9c7a-34024f3a4b49', 'd87775ea-44da-4008-be21-4e4d3fa0eadb', 'ご指示どおりにいたします。', 'ご指示どおりにいたします。', '按照您的指示去办。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('51ac23d2-c824-45e4-8f1a-a63958adefd6', 'd87775ea-44da-4008-be21-4e4d3fa0eadb', 'いかがいたしましょうか。', 'いかがいたしましょうか。', '怎么做好呢？', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('896536b8-d724-4bcf-8806-d83d824daf05', 'おる', NULL, 'N4', 'おる', 'おる', '“在”。', '「おる」是「いる」的自谦语。', 626, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('c679412f-d3d8-4691-a9be-d91ac1d16227', '896536b8-d724-4bcf-8806-d83d824daf05', '5時までに会社におります。', 'ごじまでにかいしゃにおります。', '我会在公司一直待到五点。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('6061599c-b7b5-42b5-9951-6219eb2a995b', '896536b8-d724-4bcf-8806-d83d824daf05', '日本に何年もおりました。', 'にほんになんねんもおりました。', '在日本待了很多年。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('5ba7c212-5b3d-4ca3-bab6-09ca053e14ff', '参[まい]る', NULL, 'N4', '参[まい]る', '参[まい]る', '“来”“去”。', '「 参[まい]る」是「 行[い]く」和「 来[く]る」的自谦语。', 627, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('2b813f3e-8ca7-412c-bf92-853da75908d0', '5ba7c212-5b3d-4ca3-bab6-09ca053e14ff', '毎年必ずおじいさんのお墓に参る。', 'まいとしかならずおじいさんのおはかまいる。', '每年都一定要去给爷爷扫墓。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('328b5bc0-5285-4399-91cf-559dc534f36a', '5ba7c212-5b3d-4ca3-bab6-09ca053e14ff', '明日、先生のお宅に参ります。', 'あした、せんせいのおたくまいります。', '明天去老师家拜访。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('318c80d3-4aef-4779-8f8b-714408fc15e8', '申[もう]す', NULL, 'N4', '申[もう]す', '申[もう]す', '“说”。', '「 申[もう]す」是「 言[い]う」的自谦语。', 628, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('440c16d4-aec7-424f-914a-40da0cf36a8d', '318c80d3-4aef-4779-8f8b-714408fc15e8', '私は、中川と申します。', 'わたくしは、なかがわもうします。', '我叫中川。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('0bb7c336-3eb2-4898-bc5b-93aeaffcb189', '318c80d3-4aef-4779-8f8b-714408fc15e8', '父がこのように申しております。', 'ちちもうしております。', '我父亲说了这样的话。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('c4a0f86c-3e53-4aef-8c39-a4c5b6f40cea', '申[もう]し 上[あ]げる', NULL, 'N4', '申[もう]し 上[あ]げる', '申[もう]し 上[あ]げる', '“致以……”；“说”。', '「 申[もう]し 上[あ]げる」的自谦程度比「 申[もう]す」高。', 629, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('dcd4d711-aa09-443a-824b-9d8be226826a', 'c4a0f86c-3e53-4aef-8c39-a4c5b6f40cea', '心よりお詫び申し上げます。', 'こころよりおわもうあげます。', '诚心诚意向您致以歉意。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('eadbf321-812f-4a46-89c4-b27911fd6a8e', 'c4a0f86c-3e53-4aef-8c39-a4c5b6f40cea', '一言お礼を申し上げます。', 'ひとことおれいもうあげます。', '向您致以诚挚的谢意。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('83ec5428-9e7b-41b6-b266-e5f5178aee3f', '存[ぞん]じている', NULL, 'N4', '存[ぞん]じている', '存[ぞん]じている', '“知道”。', '「 存[ぞん]じている」是「 知[し]っている」的自谦语。', 630, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('580a8f66-5bb6-46c6-a1e2-e70a48b66a42', '83ec5428-9e7b-41b6-b266-e5f5178aee3f', '社長の電話番号は存じています。', 'しゃちょうのでんわばんごうぞんじています。', '我知道社长的电话号码。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('708e0413-1e9d-488d-ba0f-73c23c59c3db', '83ec5428-9e7b-41b6-b266-e5f5178aee3f', 'わたしは先生のご住所を存じています。', 'わたしはせんせいのごじゅうしょぞんじています。', '我知道老师住在哪儿。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('5acb7a60-1f4a-45df-a729-7a2eadf383c7', '存[ぞん]じあげる', NULL, 'N4', '存[ぞん]じあげる', '存[ぞん]じあげる', '“知道”。', '「 存[ぞん]じ 上[あ]げる」是「 知[し]っている」的自谦语。', 631, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('f97e0e85-a7d2-4289-9dc4-2f43268a86f9', '5acb7a60-1f4a-45df-a729-7a2eadf383c7', 'お名前はよく存じ上げております。', 'おなまえぞんあげております。', '久仰大名。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('add0faeb-7a6c-4086-b106-1b6b3826b6d4', '5acb7a60-1f4a-45df-a729-7a2eadf383c7', 'ますますご活躍のことと存じ上げます。', 'ますますごかつやくぞんあげます。', '一直听说您很活跃。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('58d83981-5e61-497e-853b-c4ad631339be', 'お 目[め]にかかる', NULL, 'N4', 'お 目[め]にかかる', 'お 目[め]にかかる', '“见到”。', '「お 目[め]にかかる」是「 会[あ]う」的自谦语。', 632, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('166c335e-8505-41ff-a6b3-1fdd93d1db03', '58d83981-5e61-497e-853b-c4ad631339be', '山口「中川先生。」中川先生「あ、山口さん。偶然ですね。」山口「はい。わたしもこのパーティーで先生にお目にかかれるとは思いませんでした。」', 'やまぐち「なかがわせんせい。」なかがわせんせい「あ、やまぐちさん。ぐうぜんですね。」やまぐち「はい。わたしもこのパーティーでせんせいめにかかれるとはおもいませんでした。」', '山口：“中川老师。”\n中川老师：“啊，是山口啊。真是太巧了。”\n山口：“是啊，我也没想到在这个派对上能碰到老师。”', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('ddc7f2b4-0936-49f1-b1a8-fe5b440d8e26', 'ご 覧[らん]いただく', NULL, 'N4', 'ご 覧[らん]いただく', 'ご 覧[らん]いただく', '“请……看……”。', '「ご 覧[らん]いただく」是「 見[み]てもらう」的自谦语。', 633, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('7c331524-ed1d-4cef-8119-0756e5e628e3', 'ddc7f2b4-0936-49f1-b1a8-fe5b440d8e26', 'この絵をご覧いただき、ありがとうございます。', 'このえらんいただき、ありがとうございます。', '非常感谢您看了这幅画。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('d6eefc08-4fe6-473a-b8d6-180402ee0b82', 'ddc7f2b4-0936-49f1-b1a8-fe5b440d8e26', '書いたレポートを先生にご覧いただきました。', 'かいたレポートをせんせいらんいただきました。', '写好的小论文请老师看了。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('b6fb7dcc-1679-4dbd-8616-c1417cf3ee6e', '拝[はい] 見[けん]する', NULL, 'N4', '拝[はい] 見[けん]する', '拝[はい] 見[けん]する', '“看”。', '「 拝[はい] 見[けん]する」是「 見[み]る」的自谦语。', 634, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('c2a4fae7-40fc-42a5-9f2f-c6afbd4e4730', 'b6fb7dcc-1679-4dbd-8616-c1417cf3ee6e', 'A「どうぞご覧ください。」B「では、拝見します。」', 'A「どうぞごらんください。」はいけんします。」', 'A：“请过目。”\nB：“好的，那我就看了。”', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('027831c1-66a0-4d37-94ab-272a6b408ce2', 'b6fb7dcc-1679-4dbd-8616-c1417cf3ee6e', 'あなたのお姿を拝見していました。', 'あなたのおすがたはいけんしていました。', '我看到您了。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('fa0bfea8-6040-4e28-9987-53a1a13c04a8', '拝[はい] 借[しゃく]する', NULL, 'N4', '拝[はい] 借[しゃく]する', '拝[はい] 借[しゃく]する', '“借”。', '「 拝[はい] 借[しゃく]する」是「 借[か]りる」的自谦语。', 635, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('b2b9eb39-121e-4866-968c-9d67f5728302', 'fa0bfea8-6040-4e28-9987-53a1a13c04a8', '先生の辞書を拝借してもよろしいですか。', 'せんせいのじしょはいしゃくしてもよろしいですか。', '老师可以把词典借给我吗？', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('5f4edda1-b8f1-4dad-8484-29a668be862d', 'fa0bfea8-6040-4e28-9987-53a1a13c04a8', 'お知恵を拝借したいです。', 'おちえはいしゃくしたいです。', '我想请您帮我出个主意。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('f4c0124d-414e-4814-8dc3-b7504cf89710', 'うかがう', NULL, 'N4', 'うかがう', 'うかがう', '“问”；“造访”。', '「うかがう」是「 行[い]く」「 来[く]る」「 聞[き]く」「 訪[たず]ねる」和「 訪[ほう] 問[もん]する」的特殊自谦表达。', 636, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('2143e01c-c642-4749-83fe-88fa52fd0a31', 'f4c0124d-414e-4814-8dc3-b7504cf89710', '（電話で）A「すみません、そちらのアルバイトの募集についてちょっと伺いたいんですが。」B「はい。どんなことでしょうか。」', '（でんわで）A「すみません、そちらのアルバイトのぼしゅううかがいたいんですが。」B「はい。どんなことでしょうか。」', 'A：“不好意思，我想请教一下有关贵店招聘兼职的事情。”\nB：“嗯，您想问什么呢？”', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('52ad244a-affa-431c-9fb7-0094cebf6476', 'f4c0124d-414e-4814-8dc3-b7504cf89710', '学生：「先生、ご相談したいことがあるのですが、授業の後、先生の研究室にうかがってもよろしいでしょうか。」先生：「はい。いいですよ。」', 'がくせい：「せんせい、ごそうだんしたいことがあるのですが、じゅぎょうのあと、せんせいのけんきゅうしつにうかがってもよろしいでしょうか。」せんせい：「はい。いいですよ。」', '学生：“老师，我有事要和您商量，下课后，去您的研究室可以吗？”\n老师：“好的，没问题。”', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('030d3645-7da4-48a5-89ec-ba9ebfc522b6', '承[うけたまわ]る', NULL, 'N4', '承[うけたまわ]る', '承[うけたまわ]る', '“接受”；“听”。', '「 承[うけたまわ]る」是「 受[う]ける」「 聞[き]く」的自谦语。', 637, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('737f9aa1-975c-4763-99f7-3b1b9d8e53d4', '030d3645-7da4-48a5-89ec-ba9ebfc522b6', '先生のご意見を承りました。', 'せんせいのごいけんうけたまわりました。', '听取了老师的意见。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('c42e3c95-fa6d-48f7-9fbb-541f20a0df99', '030d3645-7da4-48a5-89ec-ba9ebfc522b6', '上司の命令を承らなければなりません。', 'じょうしのめいれいうけたまわらなければなりません。', '必须服从上级的命令。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('3162ac3f-85d5-4790-a5b5-5544bfa77720', 'お/ご～する', NULL, 'N4', 'お＋Ⅰ类动词、Ⅱ类动词「ます形」＋する', 'お＋Ⅰ类动词、Ⅱ类动词「ます形」＋する\nご＋Ⅲ类动词词干＋する', '表示动作主体的自谦。', '「お/ご～する」是「～する」的自谦表达，表示自己做某事。词干只有一个假名的Ⅱ类动词以及「 来[く]る」不能用于本句型。', 638, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('5fecf50b-0f26-406a-9444-b7dcb6e5514e', '3162ac3f-85d5-4790-a5b5-5544bfa77720', '先生、わたしがその荷物をお持ちします。', 'せんせい、わたしがそのにもつもちします。', '老师，我来拿那件行李吧。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('23087a64-3b24-4226-987a-b72ad5d9bb6a', '3162ac3f-85d5-4790-a5b5-5544bfa77720', 'わたしがビデオを先生にお返しします。', 'わたしがビデオをせんせいかえしします。', '我把录像带还给老师。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('ce25c410-94bc-4fa0-91a3-c3e6ecbbc046', 'お/ご～いたす', NULL, 'N4', 'お＋Ⅰ类动词、Ⅱ类动词「ます形」＋いたす', 'お＋Ⅰ类动词、Ⅱ类动词「ます形」＋いたす\nご＋Ⅲ类动词词干＋いたす', '表示动作主体的自谦。', '「お/ご～いたす」的自谦程度比「お/ご～する」更高，动词「いたす」为「する」的自谦语。词干只有一个假名的Ⅱ类动词以及「 来[く]る」不能用于本句型。', 639, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('b3ffd50b-dbe8-41cb-b640-7b10919b3d33', 'ce25c410-94bc-4fa0-91a3-c3e6ecbbc046', '9月の会社説明会の日程をお知らせいたします。', '9がつのかいしゃせつめいかいのにっていしらせいたします。', '我来宣布一下9月份公司说明会的日程安排。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('1002e910-5e04-483a-a4b2-65dd9efe7a04', 'ce25c410-94bc-4fa0-91a3-c3e6ecbbc046', 'チケットは後でお渡しいたします。', 'チケットはあとわたしいたします。', '票我之后给您。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('3f17a43a-0fb4-4b48-ac44-9adc7c331ca1', '～ておる', NULL, 'N4', '动词「て形」＋おる', '动词「て形」＋おる', '“正在……”。', '「～ておる」是「～ている」的自谦表达。', 640, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('13730baa-2321-4a7b-b78a-46c5c5b461a4', '3f17a43a-0fb4-4b48-ac44-9adc7c331ca1', '社長は今電話に出ておりますので、しばらくお待ちください。', 'しゃちょうはいまでんわにでておりますので、しばらくおまちください。', '社长现在正在打电话，请稍等。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('9e6b0523-aa75-4f3a-9f10-059453fbcdf5', '3f17a43a-0fb4-4b48-ac44-9adc7c331ca1', '荷物はわたしがお持ちしております。', 'にもつはわたしがおもちしております。', '我拿着行李。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('31c3dc12-e729-4ba0-8cc9-d81a513542e6', '3f17a43a-0fb4-4b48-ac44-9adc7c331ca1', '今、上海に住んでおります。', 'いま、しゃんはいにすんでおります。', '我现在住在上海。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('86c21dcd-59d4-47fe-a3fb-35b6922e68d7', 'ございます', NULL, 'N4', 'ございます', 'ございます', '「ございます」是「ある」的礼貌语。', '「～ございます」比「～ある」语气更恭敬也更客气，其否定形式是「～ございません」。', 641, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('3d7f25cf-36f6-4320-ba00-9678de44c369', '86c21dcd-59d4-47fe-a3fb-35b6922e68d7', '（デパートで）客「すみません、トイレはどこですか」？店員「はい。あちらの階段の近くにございます。」', '（デパートで）きゃく「すみません、トイレはどこですか」？てんいん「はい。あちらのかいだんのちかくにございます。」', '顾客：“不好意思，请问卫生间在哪里？”\n店员：“在那里的楼梯附近。”', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('2a150e1c-c8d0-4be7-83d4-5e61031efe9e', '86c21dcd-59d4-47fe-a3fb-35b6922e68d7', '客「すみません。レストランは何階ですか。」案内の人「はい、5階にございます。」', 'きゃく「すみません。レストランはなんかいですか。」あんないのひと「はい、ごかいにございます。」', '顾客：“请问餐厅在几楼？”\n工作人员：“在5楼。”', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('5edcf445-44ba-49bc-873d-61f346d95e75', '～でございます', NULL, 'N4', '～でございます', '～でございます', '「～でございます」是「～だ/です/である」的礼貌语。', '「～でございます」比「～です/である」语气更恭敬也更客气，其否定形式是「～でございません」。', 642, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('07eef8c9-873c-4bec-9c59-827341684657', '5edcf445-44ba-49bc-873d-61f346d95e75', '（家電売り場で）こちらのカメラは新製品でございます。', '（かでんうりばで）こちらのカメラはしんせいひんでございます。', '（家电销售专柜）这个照相机是新产品。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('2d2f668d-dc22-4f99-a111-5fce771b75a7', '5edcf445-44ba-49bc-873d-61f346d95e75', '（レストランで）お待たせいたしました、天ぷらうどんでございます。', '（レストランで）おまたせいたしました、てんぷらうどんでございます。', '（在餐厅）让您久等了。这是天妇罗乌冬面。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('48df2ba0-c823-41e6-befd-c3aaec550736', '名词1＋は＋名词2＋です/ではありません', NULL, 'N5', '名词1＋は＋名词2＋です/ではありません', '名词1＋は＋名词2＋です/ではありません', '此句型是名词谓语句的敬体形的现在时，表示对主语作出肯定或者否定的判断，相当于汉语的“……是……”或者“……不是……”。名词2是对名词1作出的解释或说明的具体内容。肯定形句末是「です」，否定形句末为「ではありません」。', '在不造成误解的情况下，「名词1＋は」部分可以省略。另外，「では」的口语形式为「じゃ」，因此「ではありません」也可以说成「じゃありません」。', 643, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('742b2c66-7688-4187-b441-0bf8d47a9fef', '48df2ba0-c823-41e6-befd-c3aaec550736', 'これは去年買ったカメラです。', 'きょねんかったカメラです。', '这是去年买的照相机。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('582da937-0b04-4c65-913a-cda0c67cbeab', '48df2ba0-c823-41e6-befd-c3aaec550736', '田中さんの来る日は火曜日です。', 'たなかさんのくるひかようびです。', '田中要来的日子是周二。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('a4f729cf-73ed-466c-ae69-6c5b30706236', '48df2ba0-c823-41e6-befd-c3aaec550736', '妹は学生じゃありません。会社員です。', 'いもうとがくせいじゃありません。かいしゃいんです。', '我妹妹不是学生。是公司职员。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('69d5c79a-6cd9-40a4-95fb-996105c9686f', '名词1＋は＋名词2＋でした/ではありませんでした', NULL, 'N5', '名词1＋は＋名词2＋でした/ではありませんでした', '名词1＋は＋名词2＋でした/ではありませんでした', '此句型是句型1的过去时。「です」的过去时是「でした」，「ではありません」的过去时是「ではありませんでした」。', '「ではありませんでした」在口语中也可以说成「じゃありませんでした」。', 644, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('29de47bf-9718-4c7e-b4a9-1592051e2254', '69d5c79a-6cd9-40a4-95fb-996105c9686f', 'おとといは雨で、昨日は雪でした。', 'あめで、きのうはゆきでした。', '前天下雨，昨天下雪了。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('060ea8bd-af14-4f63-8c11-792404fb7aa9', '69d5c79a-6cd9-40a4-95fb-996105c9686f', '昔、ここは遊園地ではありませんでした。公園でした。', 'むかしゆうえんちではありませんでした。こうえんでした。', '以前这里不是游乐场，是公园。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('f86ad8f7-4d1e-4859-b64b-551f26b4d136', '名词1＋は＋名词2＋だ/ではない', NULL, 'N5', '名词1＋は＋名词2＋だ/ではない', '名词1＋は＋名词2＋だ/ではない', '此句型是与句型1对应的简体形，「です」简体形为「だ」，「ではありません」简体形为「ではない」。', '此句型中「ではない」在口语中也可以说成「じゃない」。', 645, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('488d711a-8c30-47a2-a4a2-7fdba7811419', 'f86ad8f7-4d1e-4859-b64b-551f26b4d136', 'あれは日本語の教科書だ。', 'にほんごのきょうかしょだ。', '那是日语教科书。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('9d242948-424a-4195-8f18-274b45e54fd9', 'f86ad8f7-4d1e-4859-b64b-551f26b4d136', '林さんは上海人ではない。', 'はやしシャンハイじんではない。', '小林不是上海人。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('a38a4d65-859d-4dd2-b1e0-cd572adfc19a', '名词1＋は＋名词2＋だった/ではなかった', NULL, 'N5', '名词1＋は＋名词2＋だった/ではなかった', '名词1＋は＋名词2＋だった/ではなかった', '此句型是与句型2对应的普通体，是句型3对应的过去时。「だ」的过去时为「だった」，「ではない」的过去时为「ではなかった」。', '「ではなかった」在口语中也可以说成「じゃなかった」。', 646, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('c06843e4-2659-4d18-8d5f-40d52a982682', 'a38a4d65-859d-4dd2-b1e0-cd572adfc19a', '3年前、あの人はこの会社の社長だった。', 'さんねんまえ、あのひとはこのかいしゃのしゃちょうだった。', '三年前，那个人是这家公司的社长。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('319e8644-b77f-4df3-a371-b7b22d6bf6a3', 'a38a4d65-859d-4dd2-b1e0-cd572adfc19a', 'それは夢ではなかった。', 'ゆめではなかった。', '那不是做梦。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('57d29387-a49d-4b1c-8860-bfcff6b626f0', '名词1＋は＋名词2＋ですか/でしたか', NULL, 'N5', '名词1＋は＋名词2＋ですか/でしたか', '名词1＋は＋名词2＋ですか/でしたか', '此句型是疑问句，相当于汉语的“……是……吗？”。肯定回答用「はい」起句，否定回答用「いいえ」起句。', '日语疑问句的特征之一是句末一般不用问号，而用句号。', 647, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('417c382c-7e95-493c-8bd7-877f7e0b9c43', '57d29387-a49d-4b1c-8860-bfcff6b626f0', 'A「あの人は山下さんですか。」B「いいえ、違います。田中さんです。」', 'A「あのひとやましたさんですか。」B「いいえ、ちがいます。たなかさんです。」', 'A：“那个人是山下吗？”\nB：“不，不是。那是田中。”', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('36dafb19-7787-47ae-a989-385bb80e335d', '57d29387-a49d-4b1c-8860-bfcff6b626f0', 'A「王さんのお母さんは昔、日本語の教師でしたか。」B「はい、そうでした。」', 'A「おうさんのおかあむかし、にほんごのきょうしでしたか。」B「はい、そうでした。」', 'A：“小王的妈妈以前是日语老师吗？”\nB：“是，以前是的。”', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('9ff97b0b-ecea-4c9f-9d98-3745de105507', '名词1＋は＋名词2＋で、名词3です', NULL, 'N5', '名词1＋は＋名词2＋で、名词3です', '名词1＋は＋名词2＋で、名词3です', '「で」用来连接两个内容相关的名词句。', '前后两个短句的主语是一致的。', 648, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('b204e8b4-1328-4dc8-afb4-a98b38b6d7c7', '9ff97b0b-ecea-4c9f-9d98-3745de105507', 'わたしは寮の管理人で、小野です。', 'りょうのかんりにんで、おのです。', '我是宿舍管理员小野。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('1cb6f327-3dc0-40ea-a24f-c5c0b407dac3', '9ff97b0b-ecea-4c9f-9d98-3745de105507', 'あの人は歌手で、アナウンサーです。', 'あのひとかしゅで、アナウンサーです。', '那个人是歌手，也是播音员。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('0c29fffd-bc16-42e5-a5f4-b1746265be0c', 'これ、それ、あれ、どれ', NULL, 'N5', 'これ、それ、あれ、どれ', 'これ、それ、あれ、どれ', '指示事物的指示代词。\n「これ」，“这个”，近称，指离说话人近的物品或事物。\n「それ」，“那个”，中称，指离听话人近的物品或事物。\n「あれ」，“那个”，远称，指离听话人和说话人都比较远的物品或事物。\n「どれ」，“哪一个”，不定称，指说话人不知道或不明确的物品和事物。', NULL, 649, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('1660ed19-2340-49aa-9556-8ade5a2e9fb5', '0c29fffd-bc16-42e5-a5f4-b1746265be0c', '駅の近くの店でこれを買いました。', 'えきのちかくのみせでこれをかいました。', '在车站附近的店里买了这个。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('b8cd1175-4045-4e4e-9c67-8f6fe04ebc73', '0c29fffd-bc16-42e5-a5f4-b1746265be0c', 'これは日本語の辞書で、あれは英語の辞書です。', 'これはにほんごのじしょで、あれはえいごのじしょです。', '这本是日语词典，那本是英语词典。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('63fb8005-5410-4684-bb85-6ad07e0ab7f2', '0c29fffd-bc16-42e5-a5f4-b1746265be0c', 'A「これは去年買ったカメラです。撮った写真はきれいですよ。」B「そうですか。今度一緒に遊びに行くとき、それを持って行ってね。」', 'A「これはきょねんかったカメラです。とったしゃしんはきれいですよ。」B「そうですか。こんどいっしょにあそびにいくとき、それをもっていってね。」', 'A：“这是我去年买的相机，拍出来的相片不错呢。”\nB：“这样啊，下次一起去玩的时候，要带上它啊。”', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('18508fd0-a457-42aa-8d51-5d0f469a5cce', '0c29fffd-bc16-42e5-a5f4-b1746265be0c', '日本では一番有名な山はどれですか。', 'にほんではいちばんゆうめいなやまはどれですか。', '在日本，最有名的山是哪一座？', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('33da8703-e8e9-4251-9a6f-8319dc2ac8da', 'この、その、あの、どの', NULL, 'N5', 'この、その、あの、どの', 'この、その、あの、どの', '这四个词均为连体词，后续名词可指定物品或事物。\n「この＋名词」，“这个……”，近称，指离说话人近的物品或事物。\n「その＋名词」，“那个……”，中称，指离听话人近的物品或事物。\n「あの＋名词」，“那个……”，远称，指离听话人和说话人都比较远的物品或事物。\n「どの＋名词」，“哪一个……”，不定称，指说话人不知道或不明确的物品或事物。', '连体词必须后续名词才能构成独立的句子成分。', 650, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('08dfdafa-e854-4e2c-886c-64d601d71b67', '33da8703-e8e9-4251-9a6f-8319dc2ac8da', 'この雑誌を見てもいいですか。', 'ざっしをみてもいいですか。', '我可以看这本杂志吗？', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('e26d1184-0515-42bc-999e-7ee9e635597c', '33da8703-e8e9-4251-9a6f-8319dc2ac8da', 'あの部屋が日本語の教室です。', 'へやがにほんごのきょうしつです。', '那间房间是日语教室。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('6b8a2e9e-43e0-4614-b535-c9e875dcdcff', '33da8703-e8e9-4251-9a6f-8319dc2ac8da', 'どの人が山下さんですか。', 'ひとがやましたさんですか。', '哪位是山下先生（小姐）？', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('861a8d0b-117b-4d95-bb34-c261a43782e8', '33da8703-e8e9-4251-9a6f-8319dc2ac8da', 'その大きい荷物はわたしのです。', 'おおきいにもつはわたしのです。', '那件大行李是我的。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('29c004cf-a31d-4bbf-ae92-eadee9e70674', 'ここ、そこ、あそこ、どこ', NULL, 'N5', 'ここ、そこ、あそこ、どこ', 'ここ、そこ、あそこ、どこ', '这一组词用来指示位置、场所。\n「ここ」，“这儿、这里”，近称，指离说话人近的位置、场所。\n「そこ」，“那儿、那里”，中称，指离听话人近的位置、场所。\n「あそこ」，“那儿、那里”，远称，指离听话人、说话人都有距离的位置、场所。\n「どこ」，“哪里、哪儿”，不定称，指说话人不知道或不明确的位置、场所。', '可以用「～はどこですか」的形式提问，回答时可以用「～はここ/そこ/あそこです」的形式。', 651, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('acdab4fb-cdb6-418f-a35d-f9109236d78a', '29c004cf-a31d-4bbf-ae92-eadee9e70674', '遊びに行きましょう。どこがいいですか。', 'あそびにいきましょう。どこがいいですか。', '（我们）出去玩吧，（去）哪里比较好呢？', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('dad059fc-e5fc-438d-9fbf-329c34e003eb', '29c004cf-a31d-4bbf-ae92-eadee9e70674', 'ここで写真を撮ってもいいですか。', 'ここでしゃしんをとってもいいですか。', '可以在这儿拍照吗？', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('77d49183-29f3-4c64-853e-d7ab8e52205b', '29c004cf-a31d-4bbf-ae92-eadee9e70674', 'あそこに女の人がいますね。', 'あそこにおんなのひとがいますね。', '那里有一个女子吧。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('80808ce5-49ba-49d3-94af-285597c2163a', '29c004cf-a31d-4bbf-ae92-eadee9e70674', 'そこの机にボールペンが置いてあります。', 'そこのつくえにボールペンがおいてあります。', '那里书桌上放着一支圆珠笔。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('f5d587b6-f5f7-425d-a5dc-32a6e5df6cb4', 'こう、そう、ああ、どう', NULL, 'N5', 'こう、そう、ああ、どう', 'こう、そう、ああ、どう', '表示方式，方法。\n「こう＋动词」，“这样……”“如此……”，用于与说话人相关的事情。\n「そう＋动词」，“那样……”，用于与听话人相关的事情。\n「ああ＋动词」，“那样……”，用于谈论存在于谈话双方认知范围内的事情。\n「どう＋动词」，“怎样……”，用于询问做事的方式。', '「そう」除了上述用法外，后续否定时，可以译为“（不）那么……”，如「この 服[ふく]はそう 高[たか]くはありません。（这件衣服没那么贵。）」。「こう/ああ」均无此用法。', 652, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('efcd2234-c706-410c-8ceb-448a750614c4', 'f5d587b6-f5f7-425d-a5dc-32a6e5df6cb4', 'このゲームはこうやって遊びます。', 'このゲームはこうやってあそびます。', '这个游戏是这样玩的。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('49419f0c-b324-4d1b-a045-5acd9991b264', 'f5d587b6-f5f7-425d-a5dc-32a6e5df6cb4', 'これからどうするのかゆっくり考えなさい。', 'これからどうするのかゆっくりかんがえなさい。', '好好考虑一下今后应该怎么办。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('eb51479a-1939-4ac2-b53a-9c420a6b916a', 'f5d587b6-f5f7-425d-a5dc-32a6e5df6cb4', 'ああいうタイプの人があまり好きではありません。', 'ああいうタイプのひとがあまりすきではありません。', '我不太喜欢那种类型的人。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('b2597c65-3e46-41fb-8593-35db01ef8ccf', 'f5d587b6-f5f7-425d-a5dc-32a6e5df6cb4', 'この服はそう高くはありません。', 'このふくたかくはありません。', '这件衣服没那么贵。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('73ec90c6-b7e2-4083-9607-bba0c72d843a', 'こちら、そちら、あちら、どちら', NULL, 'N5', 'こちら、そちら、あちら、どちら', 'こちら、そちら、あちら、どちら', '可以和「これ、それ、あれ、どれ」一样指示物品；也可以和「ここ、そこ、あそこ、どこ」一样指示场所；还可以用来指示人物、公司、商店等，是较为礼貌的表达方式。', '「こちら、そちら、あちら、どちら」在口语中可以说成「こっち、そっち、あっち、どっち」，表达较为随意，敬意程度稍轻。', 653, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('75464f7f-f67b-492d-8adb-fd0d4523cca8', '73ec90c6-b7e2-4083-9607-bba0c72d843a', '先生の部屋はこちらです。', 'せんせいのへやはこちらです。', '老师的房间在这里。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('d7b62dc2-b9e9-4ffd-9ab1-8e0cd6830243', '73ec90c6-b7e2-4083-9607-bba0c72d843a', '今からあなたのうちへ行きますが、そちらまでどれぐらいかかりますか。', 'いまからあなたのうちへいきますが、そちらまでどれぐらいかかりますか。', '现在我去您家，到那儿大概要花多长时间？', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('bf3fbefe-074b-41eb-b8a0-495a7c5f17c2', '73ec90c6-b7e2-4083-9607-bba0c72d843a', 'あちらはどちらさまですか。', 'あちらはどちらさまですか。', '那位是谁啊？', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('b110660d-1047-47bb-925c-fc23751741ce', 'こんな、そんな、あんな、どんな', NULL, 'N5', 'こんな/そんな/あんな/どんな＋名词', 'こんな/そんな/あんな/どんな＋名词\nこんな/そんな/あんな/どんな＋形容词＋名词', '表示从某一类事物中选择其中之一，意思是“这种……”“那种……”“哪种……”。\n用来指代某人或者某物的性质和状态，意思是“这样的……”“那样的……”“怎样的……”。', NULL, 654, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('303cbb73-7797-481d-809d-f3acbf0bc953', 'b110660d-1047-47bb-925c-fc23751741ce', 'そんな人と付き合いたくない。', 'ひととつきあいたくない。', '不想和那种人交往。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('4a285b65-087d-4ed2-9273-ce41f9a3ccb4', 'b110660d-1047-47bb-925c-fc23751741ce', 'どんな音楽を聞きますか。', 'おんがくをききますか。', '你听什么类型的音乐？', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('04b6572f-d558-4eb8-adc3-c605e9d311a2', 'b110660d-1047-47bb-925c-fc23751741ce', 'こんな馬鹿なことは二度としません。', 'ばかなことはにどとしません。', '再也不会做这种蠢事。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('6c91bcd4-536c-48bd-b31a-f4ae708b219a', 'b110660d-1047-47bb-925c-fc23751741ce', 'あんないいこともありますか。', 'あんないいこともありますか。', '有那样的好事吗？', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('f770de50-c52a-4aea-95d9-ad2ef6969f90', '基数词', NULL, 'N5', '基数词', '基数词', '基数词是单纯用以计数的数词，表示事物的具体数量。十以内的基数词的读法有音读和训读两种，十以上采取音读的读法。', '十以内的训读\n一[ひと]つ・ 二[ふた]つ・ 三[みっ]つ・ 四[よっ]つ・ 五[いつ]つ・ 六[むっ]つ・ 七[なな]つ・ 八[やっ]つ・ 九[ここの]つ・ 十[とお]', 655, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('14b7d6a9-527a-45d4-ac23-8403bf8dd6a7', '序数词', NULL, 'N5', '序数词', '序数词', '序数词是表示事物顺序的数词。序数词一般由基数词前加表示顺序的接头词「 第[だい]」等，或其后加表示顺序的接尾词「 番[ばん]」「 目[め]」等构成。', '第[だい] 一[いち]（第一）\n第[だい] 二[に]（第二）\n第[だい] 三[さん]（第三）\n第[だい] 5[ご] 課[か]（第5课）\n第[だい] 3[さん] 回[かい]（第3次）\n1[いち] 番[ばん]（1号）\n2[に] 番[ばん]（2号）\n一[ひと]つ 目[め]（第一个）\n第[だい] 5[ご] 行[ぎょう] 目[め]（第5行）', 656, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('69fbc601-334e-4246-8fcb-e025121e5588', '常用助数词', NULL, 'N5', '常用助数词', '常用助数词', '助数词是表示事物计量名称的数词，也就是中文中通常所称的量词。基数词一般借助于助数词，才能准确地表达事物的数量。', '基数词与助数词结合的读法\n常用助数词表', 657, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('cb25bd7e-c364-43c6-a2d2-4dab83c92752', '常用数量的读法', NULL, 'N5', '常用数量的读法', '常用数量的读法', NULL, '人数的读法\n一人[ひとり]・ 二人[ふたり]・ 三[さん] 人[にん]・ 四[よ] 人[にん]・ 五[ご] 人[にん]・ 六[ろく] 人[にん]・ 七[しち·なな] 人[にん]・ 八[はち] 人[にん]・ 九[く·きゅう] 人[にん]・ 十[じゅう] 人[にん] 十[じゅう] 一[いち] 人[にん]・ 十[じゅう] 二[に] 人[にん]・ 十[じゅう] 三[さん] 人[にん]… 何[なん] 人[にん]\n月份的读法\n一[いち] 月[がつ]・ 二[に] 月[がつ]・ 三[さん] 月[がつ]・ 四[し] 月[がつ]・ 五[ご] 月[がつ]・ 六[ろく] 月[がつ]・ 七[しち] 月[がつ]・ 八[はち] 月[がつ]・ 九[く] 月[がつ]・ 十[じゅう] 月[がつ]・ 十[じゅう] 一[いち] 月[がつ]・ 十[じゅう] 二[に] 月[がつ]・ 何[なん] 月[がつ]\n月数的读法\n一[いっ]か 月[げつ]・ 二[に]か 月[げつ]・ 三[さん]か 月[げつ]・ 四[よん]か 月[げつ]・ 五[ご]か 月[げつ]・ 六[ろっ]か 月[げつ]・ 七[しち·なな]か 月[げつ]・ 八[はっ·はち]か 月[げつ]・ 九[きゅう·く]か 月[げつ]・ 十[じっ]か 月[げつ]・ 十[じゅう] 一[いっ]か 月[げつ]・ 十[じゅう] 二[に]か 月[げつ]… 何[なん]か 月[げつ]\n日期的读法\n1日[ついたち]・ 2日[ふつか]・ 3日[みっか]・ 4日[よっか]・ 5日[いつか]・ 6日[むいか]・ 7日[なのか]・ 8日[ようか]・ 9日[ここのか]・ 10日[とおか]・ 11日[じゅういちにち]・ 12日[じゅうににち]・ 13日[じゅうさんにち]・ 14日[じゅうよっか]・ 15日[じゅうごにち]・ 16日[じゅうろくにち]・ 17日[じゅうしちにち]・ 18日[じゅうはちにち]・ 19日[じゅうくにち]・ 20日[はつか]・ 21日[にじゅういちにち]・ 22日[にじゅうににち]・ 23日[にじゅうさんにち]・ 24日[にじゅうよっか]・ 25日[にじゅうごにち]・ 26日[にじゅうろくにち]・ 27日[にじゅうしちにち]・ 28日[にじゅうはちにち]・ 29日[にじゅうくにち]・ 30日[さんじゅうにち]・ 31日[さんじゅういちにち]・ 何[なん] 日[にち]\n天数的读法\n1日間[いちにちかん]・ 2日間[ふつかかん]・ 3日間[みっかかん]・ 4日間[よっかかん]・ 5日間[いつかかん]… 10日[とおか] 間[かん]・ 11日間[じゅういちにちかん]・ 12日間[じゅうににちかん]・ 20日間[はつかかん]・ 21日間[にじゅういちにちかん]・ 30日間[さんじゅうにちかん]・ 31日間[さんじゅういちにちかん]… 何[なん] 日[にち] 間[かん]\n时间的读法\n1時[いちじ]・ 2時[にじ]・ 3時[さんじ]・ 4時[よじ]・ 5時[ごじ]・ 6時[ろくじ]・ 7時[しちじ]・ 8時[はちじ]・ 9時[くじ]・ 10時[じゅうじ]・ 11時[じゅういちじ]・ 12時[じゅうにじ]… 何時[なんじ]\n1分[いっぷん]・ 2分[にふん]・ 3分[さんぷん]・ 4分[よんぷん]・ 5分[ごふん]・ 6分[ろっぷん]・ 7分[ななふん]・ 8分[はっぷん]・ 9分[きゅうふん]・ 10分[じゅっぷん]・ 11分[じゅういっぷん]・ 15分[じゅうごふん]… 何分[なんぷん]', 658, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('167837f5-bed0-4639-86b0-cf00ea50a593', '三类动词的区分', NULL, 'N5', '三类动词的区分', '三类动词的区分', '根据动词词尾的活用变形，可以把动词分为Ⅰ类动词（五段动词）、Ⅱ类动词（一段动词）、Ⅲ类动词（サ变动词/カ变动词）三种类型。\nⅠ类动词，词尾是「う、く、ぐ、す、つ、ぬ、ぶ、む、る」。\nⅡ类动词，词尾必须为「る」，且倒数第二个假名要在「い」段或「え」段上。\nⅢ类动词，包括サ变动词和カ变动词。サ变动词一般指「する」，但「する」可与一些动词性名词一起构成サ变复合词，我们把这些词也称作サ变动词。カ变动词只有一个，即「 来[く]る」，其活用变形比较特殊。', '日语中有些动词满足以上Ⅱ类动词的规则，却是Ⅰ类动词，这些词语需要我们特别记忆。如「 焦[あせ]る・ 要[い]る・ 入[い]る・ 帰[かえ]る・ 返[かえ]る・ 限[かぎ]る・ 切[き]る・ 蹴[け]る・ 茂[しげ]る・ 知[し]る・ 喋[しゃべ]る・ 滑[すべ]る・ 散[ち]る・ 入[はい]る・ 走[はし]る・ 減[へ]る　…」。', 659, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('a3d72385-9c52-4a6e-b64b-d7b341529d2d', '167837f5-bed0-4639-86b0-cf00ea50a593', '①Ⅰ类动词', '①Ⅰ类动词', '買[か]う・ 行[い]く・ 防[ふせ]ぐ・ 生[い]かす・ 立[た]つ・ 死[し]ぬ・ 飛[と]ぶ・ 読[よ]む・ 撮[と]る　…', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('9e6f51da-5547-483d-b47d-b48749301341', '167837f5-bed0-4639-86b0-cf00ea50a593', '②Ⅱ类动词', '②Ⅱ类动词', '起[お]きる・ 食[た]べる・ 見[み]る・ 寝[ね]る　…', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('15513104-5b75-4632-95e9-c66c00f56ba9', '167837f5-bed0-4639-86b0-cf00ea50a593', '③Ⅲ类动词', '③Ⅲ类动词', 'サ变动词：する・ 運[うん] 動[どう]する・ 勉[べん] 強[きょう]する　…\nカ变动词： 来[く]る', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('05bac129-efd1-4cc3-a850-69b11a070bd4', '自动词和他动词', NULL, 'N5', '自动词和他动词', '自动词和他动词', '根据动词是否需要宾语，日语动词又可以分为自动词和他动词。自动词表示自发的、不掺杂主观意图的动作、行为，一般情况下格助词要用「が」；他动词需要宾语才能完整地表达主语的动作或作用，格助词要用「を」。有一些动词既可作自动词又可作他动词。', NULL, 660, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('8bee9e7e-65de-4a12-bb8e-fa3f96ed53f7', '05bac129-efd1-4cc3-a850-69b11a070bd4', '①没有对应他动词的自动词', '①没有对应他动词的自动词', 'ある・いる・ 行[い]く・ 来[く]る　…', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('78a19833-8244-44b5-8e5e-4fb68add56ca', '05bac129-efd1-4cc3-a850-69b11a070bd4', '②没有对应自动词的他动词', '②没有对应自动词的他动词', '話[はな]す・ 読[よ]む・ 書[か]く・ 飲[の]む　…', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('94394cc9-849d-4a7c-8294-29f3ad052ec3', '05bac129-efd1-4cc3-a850-69b11a070bd4', '③既可以作自动词又可以作他动词的单词', '③既可以作自动词又可以作他动词的单词', '開[ひら]く・ 休[やす]む・ 吹[ふ]く・ 笑[わら]う・ 終[お]わる　…', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('b52ff198-343a-4913-975a-7fa4f894367c', '动词「ます形」及敬体形', NULL, 'N5', '动词「ます形」及敬体形', '动词「ます形」及敬体形', '动词后面加「ます」为礼貌用语。一般和认识不久的人或者长辈、上司等说话时，要用敬体形。「ます」对应的过去时为「ました」，否定形为「ません」，过去时否定形为「ませんでした」。', NULL, 661, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('0df4041e-5eef-4d60-b3d8-e70df360a10e', 'b52ff198-343a-4913-975a-7fa4f894367c', '朝シャワーを浴びました。', 'あさシャワーをあびました。', '今早洗了澡。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('0fa01c4b-6f20-4dd4-b0c8-94bc45306342', 'b52ff198-343a-4913-975a-7fa4f894367c', '昨日誰と一緒に帰りましたか。', 'きのうだれといっしょにかえりましたか。', '昨天和谁一起回去的？', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('479a61a6-e529-44d9-ac56-2e7f04225957', 'b52ff198-343a-4913-975a-7fa4f894367c', 'わたしはおじいさんとよく散歩をします。', 'わたしはおじいさんとよくさんぽをします。', '我经常和爷爷一起散步。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('2fb86156-320b-43b5-9a1e-b3aa8ccaf284', 'b52ff198-343a-4913-975a-7fa4f894367c', '30分ぐらい待ちましたが、バスは来ませんでした。', 'さんじゅっぷんぐらいまちましたが、バスはきませんでした。', '等了大概三十分钟，公交车也没来。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('98a09e6b-2dca-4f7f-b2a4-c8805e08d428', '动词「て形」', NULL, 'N5', '动词「て形」', '动词「て形」', '表示动作或状态同时进行。\n表示动作或行为相继发生。\n表示行为的方法和手段。\n表示原因。', '「 行[い]く」这个词的「て形」比较特别，是「 行[い]って」，而不是「 行[い]いて」。', 662, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('ed5980d2-96a4-4d16-9c02-ce5ffffdbb5d', '98a09e6b-2dca-4f7f-b2a4-c8805e08d428', '辞書を見て漢字を覚えます。', 'じしょをみかんじをおぼえます。', '看着词典背汉字。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('3c7336cc-bef4-4c3b-af7e-0d3c66caf393', '98a09e6b-2dca-4f7f-b2a4-c8805e08d428', '昨日の夜は6時に帰って、ご飯を作りました。', 'きのうのよるはろくじにかえって、ごはんをつくりました。', '昨晚六点回家，然后做了饭。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('82d01e26-0184-4f0c-9f5e-845780eae3a6', '98a09e6b-2dca-4f7f-b2a4-c8805e08d428', 'バスに乗って、海へ行きました。', 'バスにのって、うみへいきました。', '坐公共汽车去了海边。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('d65216ae-a5ce-42e9-a1c6-5f26b5476c2a', '98a09e6b-2dca-4f7f-b2a4-c8805e08d428', '財布をなくして困りました。', 'さいふこまりました。', '弄丢了钱包，很苦恼。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('5d180df4-8a79-4c25-91d4-58729a5e963b', '动词「た形」', NULL, 'N5', '动词「た形」', '动词「た形」', '从表格中可以看出，动词「た形」变形规则与「て形」完全相同。动词「た形」为动词的过去时，表示过去的时态或者动作的完了。动词「た形」是与动词「ました形」对应的普通形。另外，动词「た形」也可以在句中修饰名词、代词等。', '和「て形」一样，「 行[い]く」这个词的「た形」是「 行[い]った」，而不是「 行[い]いた」。', 663, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('cf859a17-b851-46fd-9ba8-8e77811237f0', '5d180df4-8a79-4c25-91d4-58729a5e963b', 'これは去年買ったカメラです。', 'これはきょねんかったカメラです。', '这是去年买的照相机。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('b5b514e1-7953-4ce5-8d5e-42492a03e1e4', '5d180df4-8a79-4c25-91d4-58729a5e963b', 'わたしは玄関のドアを開けた。', 'わたしはげんかんのドアをあけた。', '我打开了大门。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('721aba5c-7462-4675-a777-8aad9f7264bf', '动词「ない形」', NULL, 'N5', '动词「ない形」', '动词「ない形」', '动词的「ない形」表示动词的现在时否定形，其对应的过去时否定形为「なかった」，分别与敬体形中的「ません」和「ませんでした」对应。参照上述表格可以知道，Ⅱ类动词以及Ⅲ类动词中「する」的「ない形」的变形规则和「ます形」一样，「 来[く]る」和Ⅰ类动词的变形规则不一样。', '词尾是「う」的动词是将词尾变成「わ」而不是「あ」；「ある」没有「ない形」，对应的否定形就是「ない」。', 664, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('36d383ab-c05b-4fc7-a7f8-6664f41684cc', '721aba5c-7462-4675-a777-8aad9f7264bf', '明日雨が降るか降らないかわかりません。', 'あしたあめがふるかふらないかわかりません。', '不知道明天下不下雨。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('e41db577-611a-4218-815c-5c4c5ef57bd6', '721aba5c-7462-4675-a777-8aad9f7264bf', '朝は忙しくて新聞は読まない。', 'あさはいそがしくてしんぶんはよまない。', '早上太忙不读报纸。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('ed7758e0-cddf-4c7c-b65c-44df21ad2d06', '721aba5c-7462-4675-a777-8aad9f7264bf', '今日、朝ご飯は食べませんでした。朝寝坊をしましたから。', 'きょう、あさごはんはたべませんでした。あさねぼうをしましたから。', '今天没吃早饭。因为睡懒觉了。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('a587eed6-7367-49a9-9bcc-1829df3131ad', '动词敬体形和普通形', NULL, 'N5', '动词敬体形和普通形', '动词敬体形和普通形', '上面介绍了动词的敬体形和普通形。敬体形一般用于交流的双方还不太熟悉，或者当对方是应该尊敬的人（如长辈、上司等）的场合，普通形多用于亲人、朋友之间的对话。日文书信中多用敬体形，而一般的书面文章更多使用普通形。\n对应关系', NULL, 665, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('1cd19342-62be-42ec-b881-7fd707cc717c', 'する', NULL, 'N5', 'する', 'する', '以「をする」形式接在表示动作或行为的名词之后，意为“做……”。\n「する」前面接带有行为性质的名词，构成Ⅲ类动词。\n「する」表示身上戴着小饰品，如领带、围巾、皮带等。', '虽然「する」的意思写为“做”，但是随着前面宾语的变化，「する」的意思也会随之改变，需要根据句子灵活翻译。\n「 旅[りょ] 行[こう]/ 食[しょく] 事[じ]/ 結[けっ] 婚[こん]」这样没有动作对象，表示自发性动作的名词搭配「する」构成的三类动词属于自动词；「 勉[べん] 強[きょう]/ 運[うん] 転[てん]/ 紹[しょう] 介[かい]」等可以有动作对象的名词搭配「する」构成的三类动词则属于他动词。\n「する」表示此时穿戴着装饰物的状态，因此大多是以「している」的形式出现。', 666, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('910080a0-6c76-4f15-95cc-d50684d3e4af', '1cd19342-62be-42ec-b881-7fd707cc717c', '運動をしてもいいですか。', 'うんどうをしてもいいですか。', '我可以做运动吗？', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('eca33372-c29e-4834-ac17-670c1efa76cc', '1cd19342-62be-42ec-b881-7fd707cc717c', 'わたしが子どもの世話をしますから、安心してください。', 'わたしがこどものせわをしますから、あんしんしてください。', '有我照顾孩子们，请你放心吧。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('9f63f5b4-5ebe-43c0-9193-7b7d3caaff4d', '1cd19342-62be-42ec-b881-7fd707cc717c', '卒業してから何をするつもりですか。', 'そつぎょうしてからなにをするつもりですか。', '毕业后打算干什么呢？', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('9abe0592-24d1-4dd1-9624-4b8552f0679b', '1cd19342-62be-42ec-b881-7fd707cc717c', '今年試験に失敗しても、また来年頑張ります。', 'ことししけんにしっぱいしても、またらいねんがんばります。', '就算今年考砸了，明年也会继续努力。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('c1b770c3-7d93-4ebc-b77a-0d8f66397815', '1cd19342-62be-42ec-b881-7fd707cc717c', '上田さんは左手に指輪をしています。', 'うえださんはひだりてにゆびわをしています。', '上田左手上戴着戒指。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('c8686611-f774-47e5-9a55-e746a9633383', '1cd19342-62be-42ec-b881-7fd707cc717c', '先生は毎日ネクタイをしています。', 'せんせいはまいにちネクタイをしています。', '老师每天都打着领带。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('65966d22-07bd-4a70-8960-81a333c4801a', 'やる', NULL, 'N5', 'やる', 'やる', '「やる」意为“做”，一般情况下可以与「する」互换，不过相比「する」语气上更为随意。', '「やる」只有他动词的用法，但是「を」前面通常不接「 心[しん] 配[ぱい]/  注[ちゅう] 意[い]」这类与心理状态有关的词汇。', 667, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('2ac7202f-a2cd-4d15-bfe8-8275070d94ae', '65966d22-07bd-4a70-8960-81a333c4801a', 'ですから、学生はあまりこのアルバイトはやりません。', 'ですから、がくせいはあまりこのアルバイトはやりません。', '因此很少有学生（愿意）做这种兼职。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('378914b7-3658-46fb-b3db-63e79a29858d', '65966d22-07bd-4a70-8960-81a333c4801a', '今日は、うちでどんなことをやりましたか。', 'きょうは、うちでどんなことをやりましたか。', '今天在家里干了什么？', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('236c1d5b-7d20-4409-a11c-477e54116b36', 'できる', NULL, 'N5', 'できる', 'できる', '「できる」意为“可以做到”，表示能力。\n「できる」意为“完成，做完”。\n「できる」意为“新建成，新成立，产生，交”。', '「できる」前面用「が」。\n「できる」前面加「よく」、「うまく」等，意思是“做得很好”。\n「できる」可以表示具体事物的出现和产生，也可以表示虚拟的关系或概念的建立。', 668, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('3e4a53d9-90fb-46d9-87c8-ff7ddf8c83d7', '236c1d5b-7d20-4409-a11c-477e54116b36', '辞書を使わずに日本語の新聞を読むことができますか。', 'じしょをつかわずににほんごのしんぶんをよむことができますか。', '你不用词典的话，可以看日文报纸吗？', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('63cfbf51-c3eb-46ba-a8e8-915485b52541', '236c1d5b-7d20-4409-a11c-477e54116b36', 'この仕事は日本語ができなくても大丈夫です。', 'このしごとはにほんごができなくてもだいじょうぶです。', '这份工作就算不会日语也不要紧。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('31410a0d-6510-4631-bba1-e0a52d4b263f', '236c1d5b-7d20-4409-a11c-477e54116b36', '青木「川田さんはケーキを作ったことがありますか。」川田「はい、一度だけ。でも、うまくできませんでした。」', 'あおき「かわたさんはケーキをつくったことがありますか。」かわた「はい、いちどだけ。でも、うまくできませんでした。」', '青木：“川田你做过蛋糕吗？”\n川田：“嗯，只做过一次。但是，没做好。”', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('c431fddd-b95c-4192-a6a3-1c0e81b8b44f', '236c1d5b-7d20-4409-a11c-477e54116b36', '今日の宿題はできましたか。', 'きょうのしゅくだいはできましたか。', '今天的作业做完了吗？', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('a74896b9-3b96-44d6-96d1-020a9037ef79', '236c1d5b-7d20-4409-a11c-477e54116b36', '駅前に新しいレストランができた。', 'えきまえにあたらしいレストランができた。', '车站前新建成了一家餐厅。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('2952f176-f615-4323-921a-5e82d4574db5', '236c1d5b-7d20-4409-a11c-477e54116b36', 'おばさんに子どもができた。', 'おばさんにこどもができた。', '阿姨怀了孩子。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('13e94b9d-f3b6-4fb7-812b-cef41deb3243', '236c1d5b-7d20-4409-a11c-477e54116b36', '先週、新しい友だちができた。', 'せんしゅう、あたらしいともだちができた。', '上周交了新朋友。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('779e8ed3-3002-4896-85f7-b81f144ea733', 'ある', NULL, 'N5', 'ある', 'ある', '「ある」表示存在。\n「ある」表示拥有物品、知识、财产等。\n「ある」表示事情的发生。', '「ある」通常用于无意识的物体，否定形式为「ない」或「ありません」。\n「ある」此处表示的是物品或抽象事物的所有权。\n「ある」可以表示会议的召开、考试的举办以及事件、事故等的发生。', 669, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('b9ada492-f9de-4b7b-afc3-ec75dc745c24', '779e8ed3-3002-4896-85f7-b81f144ea733', 'その角を右に曲がると郵便局があります。', 'そのかどをみぎにまがるとゆうびんきょくがあります。', '那个路口右转有家邮局。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('0eccef2d-2dfa-4d58-9f63-919da9755484', '779e8ed3-3002-4896-85f7-b81f144ea733', '棚の上に本が3冊あります。', 'たなのうえにほんがさんさつあります。', '架子上有三本书。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('baa26e1a-c9bc-420a-b63b-676d68f9e48a', '779e8ed3-3002-4896-85f7-b81f144ea733', 'わたしは留学の経験があります。', 'わたしはりゅうがくのけいけんがあります。', '我有留学的经历。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('4a32f159-8dce-4cb0-bfd3-23096e5fc3c9', '779e8ed3-3002-4896-85f7-b81f144ea733', '鈴木さんはお金がありません。', 'すずきさんはおかねがありません。', '铃木没有钱。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('3ea762d3-cd36-4046-b5c5-5a0cc2d2767f', '779e8ed3-3002-4896-85f7-b81f144ea733', '昨日近所で火事があった。', 'きのうきんじょでかじがあった。', '昨天附近发生了火灾。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('bed6a034-7f60-4209-b4cf-7b13cce3b51f', '779e8ed3-3002-4896-85f7-b81f144ea733', '昨日から少し熱があって頭が痛いです。', 'きのうからすこしねつあたまがいたいです。', '昨天开始有点发烧头疼。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('404ec2a2-8ef6-4d12-99aa-71dee90e7bab', 'いる', NULL, 'N5', 'いる', 'いる', '「いる」表示存在。', '「いる」指有意识、有生命的生物的存在。', 670, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('e640888b-f093-498d-ad6b-39ba1307f38f', '404ec2a2-8ef6-4d12-99aa-71dee90e7bab', '田中さんがどこにいるかわかりません。', 'たなかさんがどこにいるかわかりません。', '我不知道田中在哪里。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('f9fdfe04-17bd-4e9a-87d6-0c1e1ec3b7ba', '404ec2a2-8ef6-4d12-99aa-71dee90e7bab', 'ずっと外にいたので、体が冷えてしまいました。', 'ずっとそとにいたので、からだがひえてしまいました。', '因为一直在外面，所以身体都冻僵了。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('95d741f0-927a-46b1-a4ab-b024dc3b976d', 'な形容词普通形', NULL, 'N5', 'な形容词普通形', 'な形容词普通形', 'な形容词又叫作形容动词，基本构成为「な形容词词干＋だ（词尾）」，可以充当普通形句子的谓语部分，其过去时为「な形容词词干＋だった」。其对应的现在时否定形为「な形容词词干＋ではない」，过去时否定形为「な形容词词干＋ではなかった」。', '「では」的口语形式为「じゃ」，因此否定形也可以说成「な形容词词干＋じゃない」。', 671, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('c4a83524-e2ce-41dd-a9f1-ac4382a32fb8', '95d741f0-927a-46b1-a4ab-b024dc3b976d', '明日は暇だから、遊びに行きませんか。', 'あしたはひまだから、あそびにいきませんか。', '明天有空，一起去玩吧？', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('fca3db22-4b04-40b1-8de3-916593800b02', '95d741f0-927a-46b1-a4ab-b024dc3b976d', '公園の花はとてもきれいだった。', 'こうえんのはなはとてもきれいだった。', '公园的花很漂亮。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('055f3ceb-ea8f-4d5f-b129-149ba15ff883', '95d741f0-927a-46b1-a4ab-b024dc3b976d', 'この映画はあまり好きではない（じゃない）。', 'このえいがはあまりすきではない（じゃない）。', '我不太喜欢这部电影。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('e3632b5e-d031-4451-a68c-4d8cef5660e3', '95d741f0-927a-46b1-a4ab-b024dc3b976d', '別に嫌いじゃなかったが…。', 'べつにきらいじゃなかったが…。', '虽说也不讨厌，可是……', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('79b481ff-d7fb-49a3-8f8b-fff9dfa72ebe', 'な形容词敬体形', NULL, 'N5', 'な形容词敬体形', 'な形容词敬体形', '上面介绍了な形容词的普通形，而与之对应的敬体形的现在时和过去时的肯定形分别为「な形容词词干＋です」和「な形容词词干＋でした」。现在时否定形有两种，即「な形容词词干＋ではありません/ではないです」。过去时否定形也有两种，即「な形容词词干＋ではありませんでした/ではなかったです」。', '句型中出现的「では」在口语中都能换成「じゃ」。', 672, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('0d026c8d-793a-4e51-a98b-6a7e8c79747a', '79b481ff-d7fb-49a3-8f8b-fff9dfa72ebe', 'わたしの部屋はきれいじゃないです。', 'わたしのへやはきれいじゃないです。', '我的房间不整洁。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('fb57de84-1ca1-48d9-b10c-4c42c1ef4c79', '79b481ff-d7fb-49a3-8f8b-fff9dfa72ebe', 'ホテルの部屋は静かではありませんでした。', 'ホテルのへやはしずかではありませんでした。', '宾馆的房间不安静。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('6aeb13e8-c7e9-42d9-95f1-029a8fab3b24', '79b481ff-d7fb-49a3-8f8b-fff9dfa72ebe', '兄はサッカーが好きです。', 'あにはサッカーがすきです。', '哥哥喜欢踢足球。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('7533b79e-5158-41bd-a806-1793b6198252', '79b481ff-d7fb-49a3-8f8b-fff9dfa72ebe', '先週は宿題が多くて大変でした。', 'せんしゅうはしゅくだいがおおくてたいへんでした。', '上周作业很多，忙死了。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('589d9b3e-ba92-4be4-a82f-ca2121334d6a', '79b481ff-d7fb-49a3-8f8b-fff9dfa72ebe', 'お菓子はあまり好きではありません。', 'おかしはあまりすきではありません。', '（我）不太喜欢吃点心。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('bd215f05-4f8b-4be5-a05f-206b3ab4b2d4', '79b481ff-d7fb-49a3-8f8b-fff9dfa72ebe', 'ホテルの部屋はきれいではなかったです。', 'ホテルのへやはきれいではなかったです。', '宾馆的房间不干净。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('3d14e91f-2214-479e-9cd8-4f5cae0cfffe', 'な形容词＋名词', NULL, 'N5', 'な形容词＋名词', 'な形容词＋名词', 'な形容词修饰名词的时候，要把词尾的「だ」改为「な」，再接名词。', 'な形容词简体形的过去时也可以修饰名词，表示该物体、事物过去的性质、状态等。', 673, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('55f4d494-fb35-48e2-b370-e8cf8b9d5264', '3d14e91f-2214-479e-9cd8-4f5cae0cfffe', '一番大変な仕事は何ですか。', 'いちばんたいへんしごとはなんですか。', '最困难的工作是什么？', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('2ae74bd9-b3d0-469e-9440-b1aa9de81ba2', '3d14e91f-2214-479e-9cd8-4f5cae0cfffe', '有名だった彼の作品を一つ言ってください。', 'ゆうめいかれのさくひんをひとついってください。', '请说出他曾经很有名的一部作品。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('610df146-7125-4cfc-acd2-3a37fb027b63', 'な形容词「て形」', NULL, 'N5', 'な形容词「て形」', 'な形容词「て形」', 'な形容词在句中表示并列或者中顿的时候，要把词尾的「だ」变成「で」。', NULL, 674, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('b8425eca-c36c-49c9-a071-6c4004db4d98', '610df146-7125-4cfc-acd2-3a37fb027b63', 'わたしのアパ－トは静かでいいです。', 'わたしのアパ－トはしずかでいいです。', '我住的公寓安静而舒服。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('3d6a959f-505c-43bb-984b-301da7999d06', '610df146-7125-4cfc-acd2-3a37fb027b63', 'この町は賑やかで便利なところです。', 'このまちはにぎべんりなところです。', '这条街又热闹又方便。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('a0b3a700-f5ae-469f-9d42-39367c7ed9a7', '610df146-7125-4cfc-acd2-3a37fb027b63', 'この辺りはとても静かで、風景もきれいです。', 'このあたりはとてもしずかで、ふうけいもきれいです。', '这附近很安静，风景也美丽。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('8184f52a-69b3-45e7-b6e5-dbe7e4012699', 'な形容词＋动词', NULL, 'N5', 'な形容词＋动词', 'な形容词＋动词', 'な形容词修饰动词的时候，要把词尾的「だ」变成「に」，再接动词。这种用法又可以称作な形容词的副词用法。', NULL, 675, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('cb132b87-b137-401c-9e74-41a68ce48d25', '8184f52a-69b3-45e7-b6e5-dbe7e4012699', 'もう少し静かにしてくださいませんか。', 'もうすこししずかにしてくださいませんか。', '能再安静一点吗？', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('5e60edea-ffe1-4932-af16-ed82c96fb83c', '8184f52a-69b3-45e7-b6e5-dbe7e4012699', '体が丈夫になりました。', 'からだがじょうぶになりました。', '身体变壮了。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('403ff219-c529-4e1c-b704-fb37e0ae5d05', 'い形容词普通形', NULL, 'N5', 'い形容词普通形', 'い形容词普通形', 'い形容词基本构成为「い形容词词干＋い（词尾）」，可以直接充当简体形句子的谓语部分，其过去时要把词尾「い」变成「かった」，即变成「い形容词词干＋かった」的形式。其对应的现在时否定形要把词尾「い」变为「く」之后，再接「ない」，即「い形容词词干＋く＋ない」；过去时否定形为「い形容词词干＋く＋なかった」。', '「いい」的变形比较特别，不仅词尾变化，词干也有所变化，它的几种简体形分别为「いい（基本形）」「よかった（过去时）」「よくない（现在时否定形）」「よくなかった（过去时否定形）」。', 676, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('70d01b56-385a-4b4b-bd89-707c49af9770', '403ff219-c529-4e1c-b704-fb37e0ae5d05', 'この小説はつまらない。', 'このしょうせつはつまらない。', '这本小说很无趣。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('93b867f3-8f08-44c8-9b8c-b63a6ed8cd09', '403ff219-c529-4e1c-b704-fb37e0ae5d05', '英語のテストはあまり難しくない。', 'えいごのテストはあまりむずかしくない。', '英语考试不怎么难。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('73f61f3f-93c6-4a86-beec-0b43ca664691', '403ff219-c529-4e1c-b704-fb37e0ae5d05', '先月はとても忙しかった。', 'せんげつはとてもいそがしかった。', '上个月很忙。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('41708998-a3a7-4b01-80ea-c52107fe2a72', '403ff219-c529-4e1c-b704-fb37e0ae5d05', 'あのケーキは美味しくなかったよ。', 'あのケーキはおいしくなかったよ。', '那种蛋糕不好吃。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('7efde86a-87ac-4285-80d3-520f808c1ec9', 'い形容词敬体形', NULL, 'N5', 'い形容词敬体形', 'い形容词敬体形', '上面介绍了い形容词的普通形，而与之对应的敬体形的现在时和过去时的肯定形分别为「い形容词词干＋い＋です」和「い形容词词干＋かった＋です」；现在时否定形有两种，即「い形容词词干＋く＋ないです/ありません」；过去时否定形也有两种，即「い形容词词干＋く＋なかったです/ありませんでした」。', 'い形容词的活用变形发生在い形容词本身，而不发生在句末的「です」上。', 677, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('06f3793f-3a29-4211-9d54-8d4b1373b322', '7efde86a-87ac-4285-80d3-520f808c1ec9', 'ここで写真を撮ってもいいですか。', 'ここでしゃしんをとってもいいですか。', '可以在这里拍照吗？', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('3181b792-ea4b-4342-96b3-dfd15727828c', '7efde86a-87ac-4285-80d3-520f808c1ec9', '昨日は天気がよくなかったですね。', 'きのうはてんきがよくなかったですね。', '昨天天气不太好啊。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('5aeb2e65-4c1b-4916-ab2f-a12e13536df2', '7efde86a-87ac-4285-80d3-520f808c1ec9', 'この料理はあまり辛くないですよ。', 'このりょうりはあまりからくないですよ。', '这道菜不太辣。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('a8bd88fa-50c0-47da-892b-2c30b9717351', '7efde86a-87ac-4285-80d3-520f808c1ec9', '去年の冬は暖かかったです。', 'きょねんのふゆはあたたかかったです。', '去年冬天很暖和。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('dc02a398-27d5-49f0-a09e-211bc4af2930', 'い形容词＋名词', NULL, 'N5', 'い形容词＋名词', 'い形容词＋名词', 'い形容词修饰名词的时候，直接接续名词，形式为「い形容词普通形＋名词」。', 'い形容词简体形的过去时（い形容词词干＋かった）修饰名词时，表示该物体、事物过去的性质、状态等。', 678, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('18511712-a53e-4587-a388-ad51d30eea46', 'dc02a398-27d5-49f0-a09e-211bc4af2930', '暑いとき、冷たいコーヒーを飲みます。', 'あついとき、つめたいコーヒーをのみます。', '热的时候喝冰咖啡。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('dae5c484-3079-4a55-8f4e-62639a5425a5', 'dc02a398-27d5-49f0-a09e-211bc4af2930', '窓から涼しい風が入りますよ。', 'まどからすずかぜがはいりますよ。', '从窗户吹进凉爽的风。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('128c4cb4-a3d5-411f-bff2-34b9cdaaa227', 'い形容词「て形」', NULL, 'N5', 'い形容词「て形」', 'い形容词「て形」', 'い形容词用来表示同一事物的各种性质、特征时，「て」前后的词语属于并列或递进的关系。词尾「い」变成「く」再加「て」，即「い形容词词干＋く＋て」。', 'な形容词和い形容词可以在同一句话中并列使用。\n另外，多个形容词用于对同一主体（的性质、状态等）进行描述，且属于并列关系时，「て」可以省略。此种用法多见于书面语。', 679, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('7c5092cc-ae3b-4b6e-bdef-db14c615dcfe', '128c4cb4-a3d5-411f-bff2-34b9cdaaa227', 'この辺は夏は涼しくて、冬は暖かいです。', 'このへんはなつはすずしくて、ふゆはあたたかいです。', '这一带冬暖夏凉。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('f6c9d232-b441-4f3d-8e15-728ba891eee2', '128c4cb4-a3d5-411f-bff2-34b9cdaaa227', '兄の新しいカメラは小さくて軽い。', 'あにのあたらしいカメラはちいかるい。', '哥哥的新照相机小而轻巧。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('1258f2de-935d-4a50-8622-9b7d8fa015f9', '128c4cb4-a3d5-411f-bff2-34b9cdaaa227', '田中さんは優しくて静かな人です。', 'たなかさんはやさしずかなひとです。', '田中是一位温柔、安静的人。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('e2670859-32bf-49e5-ae50-677ab45231e1', 'い形容词＋动词', NULL, 'N5', 'い形容词＋动词', 'い形容词＋动词', 'い形容词修饰动词的时候，要把词尾的「い」变成「く」，再接动词。这种用法可以称作い形容词的副词用法。', NULL, 680, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('d1333c21-ae38-4c15-a822-986847d5e9eb', 'e2670859-32bf-49e5-ae50-677ab45231e1', 'パンを薄く切ります。', 'パンをうすきります。', '把面包切成薄片。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('1dd598ff-18f6-4095-8cb9-f23fa25d9a6d', 'e2670859-32bf-49e5-ae50-677ab45231e1', '天気がよくなりました。', 'てんきがよくなりました。', '天气变好了。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('ea906cdf-dffb-44fa-8c95-3f7d28dad14a', 'いくつ', NULL, 'N5', 'いくつ', 'いくつ', '可以用于询问小东西的个数，意为“几个，多少”；还可以用于询问年龄，此用法和「 何[なん] 歳[さい]」类似。', '「いくつ」一般用于询问小孩子的年龄或者用于老年人询问年轻人的年龄的场合。当面对面问对方孩子的年龄时，最好在「いくつ」前面加美化语「お」。', 681, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('e54802b2-e1a5-41ad-b611-66db407dcf3c', 'ea906cdf-dffb-44fa-8c95-3f7d28dad14a', 'A「妹さんはいくつですか。」B「19歳です。」', 'A「いもうとさんはいくつですか。」B「じゅうきゅうさいです。」', 'A：“你妹妹几岁了？”\nB：“19岁。”', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('8b2b818c-d1ef-4751-9016-89f801bec7e3', 'ea906cdf-dffb-44fa-8c95-3f7d28dad14a', 'りんごはいくつありますか。', 'りんごはいくつありますか。', '有几个苹果？', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('86000675-9593-429d-abfb-c34590e84c05', 'いつ', NULL, 'N5', 'いつ', 'いつ', '用来询问时间，意为“什么时候”。「いつか」可以表示不确定的日子。', NULL, 682, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('e43db47a-3ee8-4b38-83ee-a1c7bc0e06df', '86000675-9593-429d-abfb-c34590e84c05', 'パ－ティ－はいつがいいですか。', 'パ－ティ－はいつがいいですか。', '聚会安排在什么时候好呢？', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('44804edd-7814-440f-9516-d324a176bab4', '86000675-9593-429d-abfb-c34590e84c05', 'いつかまた日本へ来たいです。', 'いつかまたにほんへきたいです。', '以后还想再来日本。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('1c03f64a-adc4-4207-b5a2-9a828a4dc936', '誰[だれ]/どの 人[ひと]/どなた/どの 方[かた]', NULL, 'N5', '誰[だれ]/どの 人[ひと]/どなた/どの 方[かた]', '誰[だれ]/どの 人[ひと]/どなた/どの 方[かた]', '相当于汉语的“谁”，用于说话人不认识或者不明确第三者是谁的场合。从敬意程度看，「 誰[だれ]」最低。「どの 人[ひと]」「どなた」带有敬意，为礼貌用语。「どの 方[かた]」敬意程度最高。', '当对方用「 誰[だれ]/どなた/どの 人[ひと]/どの 方[かた]＋が…か」询问时，回答时也应该用「…が…」的形式。', 683, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('6a6c4d4b-8269-47e2-bbc9-98bd1d505d35', '1c03f64a-adc4-4207-b5a2-9a828a4dc936', '昨日誰と一緒に帰りましたか。', 'きのうだれといっしょにかえりましたか。', '昨天和谁一起回家的？', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('5f11d8ed-f5ca-48e9-b056-433fc0113251', '1c03f64a-adc4-4207-b5a2-9a828a4dc936', 'どの人が山下さんですか。', 'ひとがやましたさんですか。', '哪位是山下先生？', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('ea36bc66-ded4-4b66-af00-53fa6d087b99', '1c03f64a-adc4-4207-b5a2-9a828a4dc936', 'あの方はどなたですか。', 'あのかたはどなたですか。', '那位先生（小姐）是谁？', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('38ffe5d6-b21e-447a-883d-6b585503d913', '1c03f64a-adc4-4207-b5a2-9a828a4dc936', '次期社長はどの方に決めましたか。', 'じきしゃちょうかたにきめましたか。', '下任社长决定是哪位？', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('2ae3bacf-a9bf-4ec3-897c-a9bc0aa1b852', 'どう/いかが', NULL, 'N5', 'どう/いかが', 'どう/いかが', '用来询问对方的想法或事物的性质、状态等，回答中多会出现形容词对其进行说明。意为“……怎么样”。\n表示委婉地向对方提出某项建议，意为“……怎么样”“……如何”。\n用来询问某事应该怎么做，“怎么……”“如何……”。此用法不能用「いかが」替换。', '「いかが」是「どう」的礼貌说法，但是在「どう」的第三种用法里，不能用「いかが」替换。', 684, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('ae02673b-3ee3-4f66-96e5-f9e851373328', '2ae3bacf-a9bf-4ec3-897c-a9bc0aa1b852', 'そのレストランの料理はどう/いかがですか。', 'そのレストランのりょうりはどう/いかがですか。', '那家西餐厅的料理味道怎么样？', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('888a0dbf-c2a4-48b8-9c2e-163256023726', '2ae3bacf-a9bf-4ec3-897c-a9bc0aa1b852', '紅茶をいっぱいいかが/どうですか。', 'こうちゃをいっぱいいかが/どうですか。', '来杯红茶怎么样？', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('db82de0f-897c-4112-8950-13cad2e299ec', '2ae3bacf-a9bf-4ec3-897c-a9bc0aa1b852', '日本語の手紙をどう書きますか。', 'にほんごのてがみかきますか。', '日语的书信怎么写？', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('0471da84-6f50-4283-be46-a91cfbb0fe69', 'どのぐらい/どれぐらい', NULL, 'N5', 'どのぐらい/どれぐらい', 'どのぐらい/どれぐらい', '可以用来询问时间、距离、程度、具体数量等，意为“多久……”“……多远”等。', NULL, 685, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('b6f7615a-58e4-4b9e-9c0d-b977d078c09b', '0471da84-6f50-4283-be46-a91cfbb0fe69', 'A「昨日はどのぐらい走りましたか。」B「5キロ走りました。」', 'A「きのうはしりましたか。」B「ごキロはしりました。」', 'A：“昨天你跑了多远？”\nB：“跑了五千米。”', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('99a3bf5b-3fee-4670-9af9-806202641220', '0471da84-6f50-4283-be46-a91cfbb0fe69', '春休みはどのぐらいありますか。', 'はるやすみはどのぐらいありますか。', '春假放多少天？', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('746df95a-8cb2-4694-9d08-df6a60225dd5', '0471da84-6f50-4283-be46-a91cfbb0fe69', '今からあなたのうちへ行きますが、そちらまでどれぐらいかかりますか。', 'いまからあなたのうちへいきますが、そちらまでどれぐらいかかりますか。', '现在我去你家，到你那里大概要花费多长时间？', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('87552513-5b32-4417-9863-586cf3315724', '何[なに/なん]', NULL, 'N5', '何[なに/なん]', '何[なに/なん]', '用来向对方询问自己不了解的内容、情况等，意为“什么”。\n读「なに」的场合：一般「何」后续「が」「を」「から」「まで」「も」「は」「より」时。\n读「なん」的场合：后续「だ」、「の」以及「助数词」时。\n两种读法都可以的场合：后续「か」「に」「と」「で」时。', '后续「と」的时候，一般情况下两种读法都可以，但是「何という」中，只发「なん」的音。\n后续「で」时，「何で（なにで）」侧重于询问方式，「何で（なんで）」侧重于询问理由。', 686, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('a04a3c34-e22d-4bda-9a4a-f08826cac321', '87552513-5b32-4417-9863-586cf3315724', 'お金がなかったから、何も買いませんでした。', 'おかねなにもかいませんでした。', '因为没钱，所以什么都没买。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('3628ac56-f5e4-42db-9ea1-dd0d25ba56ec', '87552513-5b32-4417-9863-586cf3315724', '昨日のパーティーで何をしましたか。', 'きのうなにをしましたか。', '昨天聚会上你做什么了？', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('c41dc93c-b46b-4bb7-9526-276b04dc553f', '87552513-5b32-4417-9863-586cf3315724', '何か運動をしていますか。', 'なにかうんどうをしていますか。', '你做什么运动吗？', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('59ba9b66-2ed5-4a20-9f51-04810e5623a5', '87552513-5b32-4417-9863-586cf3315724', '映画は何時に終わりますか。', 'えいがなんじにおわりますか。', '电影几点结束？', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('9dd9a2dc-9204-4eb8-9ffe-60ebf34c2920', '87552513-5b32-4417-9863-586cf3315724', 'この耳の大きい動物は何ですか。', 'このみみのおおきいどうぶつなんですか。', '这个大耳朵的动物是什么动物啊？', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('3cdd655a-e4de-4c78-bfae-296c35777637', 'なぜ/どうして/なんで', NULL, 'N5', 'なぜ/どうして/なんで', 'なぜ/どうして/なんで', '用于询问原因、理由的疑问词。意为“为什么……”。', '「なんで」多用于口语表达。', 687, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('51cb79e3-0376-445b-b380-bb7cdc66b185', '3cdd655a-e4de-4c78-bfae-296c35777637', '昨日はどうして早く帰りましたか。', 'きのうはやくかえりましたか。', '昨天为什么回去那么早啊？', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('7dd81e03-e941-4efb-b235-b1f00fed55be', '3cdd655a-e4de-4c78-bfae-296c35777637', 'なぜ会社を辞めましたか。', 'かいしゃをやめましたか。', '为什么辞职了？', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('75b894db-0567-44d7-b38c-13d72d15c0d8', '3cdd655a-e4de-4c78-bfae-296c35777637', 'なんで来なかったの？約束したのに。', 'こなかったの？やくそくしたのに。', '为什么没来啊？明明都约好了。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('0090dddc-d3e4-424a-842e-b66e512cefcc', '格助词', NULL, 'N5', '格助词', '格助词', '格助词接在体言（名词、数词、代名词）或者相当于体言性质的词语后面，表明该体言或者相当于体言性质的词语与句中其他词语的关系，也就是说格助词决定了其前面的体言或相当于体言的词语在句中的地位。根据格助词的用法，可以把它们分为四种类型：\n主格助词：が、の。体言或者相当于体言性质的词语加上主格助词可以构成句子主语。\n宾格助词：が、を。体言或者相当于体言性质的词语加上宾格助词可以构成句中宾语。\n领格助词：が、の。体言或者相当于体言性质的词语加上领格助词可以构成定语，修饰后面体言。\n补格助词：から、で、と、に、へ、まで、より、を。体言或者相当于体言性质的词语加上补格助词可以构成补语，修饰用言，表示时间、地点、方式等。', NULL, 688, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('9204006a-e27c-4fc7-9740-9aa8e47c5f55', 'が', NULL, 'N5', 'が', 'が', '提示主语，表示客观现象、事物的状态、性质等；或者表示话题中首次出现的事物。\n表示整体的一部分或者从句中的主语。\n表示疑问句中的主语。\n表示好恶、希望、技能好坏等的对象。', '从初级阶段的学习开始，就要特别注意「が」与「は」的区别。', 689, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('098b31f1-20cf-4168-88d3-ac86243c752d', '9204006a-e27c-4fc7-9740-9aa8e47c5f55', 'この大学に留学生がいますか。', 'このだいがくにりゅうがくせいがいますか。', '这所大学里有留学生吗？', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('4f9c3b4d-75b7-4f19-8ab4-8173b964e579', '9204006a-e27c-4fc7-9740-9aa8e47c5f55', 'あ、あそこで鳥が鳴いていますよ。', 'あ、あそこでとりないていますよ。', '啊，那里有鸟儿在叫。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('856b3232-808c-4ada-a80b-1a8c23ea980c', '9204006a-e27c-4fc7-9740-9aa8e47c5f55', 'あの部屋が日本語の教室です。', 'あのへやにほんごのきょうしつです。', '那间房间是日语教室。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('57d57ca3-8898-4845-b0f5-997c29d9df4f', '9204006a-e27c-4fc7-9740-9aa8e47c5f55', '兄は背が高いです。', 'あにはせたかいです。', '哥哥个子高。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('4c4052dc-404c-439e-b486-c0f22bc4a95c', '9204006a-e27c-4fc7-9740-9aa8e47c5f55', '母が作るサンドイッチはおいしいです。', 'ははつくるサンドイッチはおいしいです。', '妈妈做的三明治好吃。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('a64fdd04-cb7c-4c99-bbef-1383c76b4707', '9204006a-e27c-4fc7-9740-9aa8e47c5f55', 'パ－ティ－はいつがいいですか。', 'パ－ティ－はいつがいいですか。', '聚会安排在什么时候好呢？', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('2ca427ed-1e3c-4a37-a1ae-eb7762318927', '9204006a-e27c-4fc7-9740-9aa8e47c5f55', 'どの人が山下さんですか。', 'どのひとやましたさんですか。', '哪位是山下先生（小姐）？', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('0170b53e-d8ce-4fd7-9ffb-bf40f0a3c365', '9204006a-e27c-4fc7-9740-9aa8e47c5f55', 'わたしはカメラがほしいです。', 'わたしはカメラがほしいです。', '我想要照相机。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('5bd9f17d-d781-411a-9674-923d03b2403b', '9204006a-e27c-4fc7-9740-9aa8e47c5f55', '田中さんは多分歌が上手でしょう。', 'たなかさんはたぶんうたじょうずでしょう。', '田中唱歌大概还不错吧。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('f3f9fac7-3bc6-4873-aed6-7ed4e39c474e', '9204006a-e27c-4fc7-9740-9aa8e47c5f55', '兄はサッカーが好きです。', 'あにすきです。', '哥哥喜欢踢足球。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('b03aa827-3c7a-40de-a93e-1b0d63d5250a', 'から', NULL, 'N5', '名词＋から', '名词＋から', '表示空间、场所的起点。\n表示时间的起点。\n表示动作的经过点。\n表示动作的主体、起点等。', NULL, 690, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('35d69688-5b18-4f3b-8ff7-f5bfd3a70508', 'b03aa827-3c7a-40de-a93e-1b0d63d5250a', 'あなたの家は学校から遠いですか。', 'あなたのいえはがっこうとおいですか。', '你家离学校远吗？', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('ad6992a6-152f-4471-a275-5b8f23ccae43', 'b03aa827-3c7a-40de-a93e-1b0d63d5250a', '次の映画は5時から始まります。', 'つぎのえいがはごじはじまります。', '下场电影从五点开始。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('b893875e-2dc6-4220-b6d6-bc0cc5a7b712', 'b03aa827-3c7a-40de-a93e-1b0d63d5250a', '窓から涼しい風が入りますよ。', 'まどすずしいかぜがはいりますよ。', '从窗户吹进凉爽的风。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('b44ed3c8-34c9-46a8-aee2-d9d267819c6d', 'b03aa827-3c7a-40de-a93e-1b0d63d5250a', 'わたしは家族から手紙をもらいました。', 'わたしはかぞくてがみをもらいました。', '我收到家里寄来的信。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('4d096ee3-c84e-48ec-87cb-890bf1bb8e8f', 'で', NULL, 'N5', '名词/数量词＋で', '名词/数量词＋で', '表示动作进行的场所。\n表示手段、方式方法、工具等。\n表示动作的基准，或者数量的合计等。\n表示原材料。\n表示范围。\n表示原因、理由。', NULL, 691, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('17e30468-6ae8-4c54-aad6-a39ed14f152a', '4d096ee3-c84e-48ec-87cb-890bf1bb8e8f', 'ここで写真を撮ってもいいですか。', 'しゃしんをとってもいいですか。', '可以在这里拍照吗？', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('467144b6-2ccc-4fb8-a2c8-c00a57a871ab', '4d096ee3-c84e-48ec-87cb-890bf1bb8e8f', '大きな声で話さないでください。', 'おおきなこえはなさないでください。', '请不要大声说话。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('96adb320-5653-4ed8-94ad-1835b815719f', '4d096ee3-c84e-48ec-87cb-890bf1bb8e8f', 'ナイフでパンを切りました。', 'ナイフでパンをきりました。', '用刀把面包切开了。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('b6089e5f-65fa-4bf2-bff7-f7b91fcb65bb', '4d096ee3-c84e-48ec-87cb-890bf1bb8e8f', '日本語で話しましょう。', 'にほんごはなしましょう。', '用日语说吧。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('8489682d-b8f2-4a6c-aecc-e17f0480d1e9', '4d096ee3-c84e-48ec-87cb-890bf1bb8e8f', 'ノートは5冊で300円です。', 'ノートはごさつさんびゃくえんです。', '笔记本五本共300日元。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('8da0d48d-aa6a-4693-bad3-d41f7b4036e8', '4d096ee3-c84e-48ec-87cb-890bf1bb8e8f', '病院へ一人で行きました。', 'びょういんへひとりいきました。', '一个人去了医院。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('887ef515-a08e-4d0c-9674-589e39271ab2', '4d096ee3-c84e-48ec-87cb-890bf1bb8e8f', 'わたしの家族は、全部で8人です。', 'わたしのかぞくは、ぜんぶはちにんです。', '我家一共八个人。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('5a7fb66d-a7f0-43ec-8324-65b7eb154780', '4d096ee3-c84e-48ec-87cb-890bf1bb8e8f', 'この料理は肉と野菜で作ります。', 'このりょうりはにくとやさいつくります。', '这道菜要用肉和蔬菜做。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('a91ea183-fe6b-4588-b516-52c0dffb44c0', '4d096ee3-c84e-48ec-87cb-890bf1bb8e8f', 'この町で一番賑やかなのはこの辺です。', 'このまちいちばんにぎやかなのはこのへんです。', '这一带是这个小镇最热闹的地方。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('16b400a7-cfcd-4cbd-af0e-f51c544b4cfb', '4d096ee3-c84e-48ec-87cb-890bf1bb8e8f', '去年、仕事で外国へ行きました。', 'きょねん、しごとがいこくへいきました。', '去年，因工作关系去了国外。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('5708673d-0a2a-427b-ad99-d63555a69bbf', '4d096ee3-c84e-48ec-87cb-890bf1bb8e8f', '風邪で学校を休みました。', 'かぜがっこうをやすみました。', '因感冒没去学校。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('64b16e41-8109-47cc-a6c3-fa1dac3b0b72', 'と', NULL, 'N5', 'と', 'と', '和某人共同做某事，可以用「と 一[いっ] 緒[しょ]に」的形式。\n和某人互相进行某事，此事必须有对方参与才能完成。\n表示说话或引用的内容等。', '句中的「 一[いっ] 緒[しょ]に」可省略，可参考第1个例句。\n「と」的这种用法，后面经常会出现「 言[い]う、 思[おも]う、 考[かんが]える、 書[か]く」等词。', 692, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('4f56dcec-4f8d-4471-a620-345965baaae8', '64b16e41-8109-47cc-a6c3-fa1dac3b0b72', 'わたしはおじいさんとよく散歩をします。', 'わたしはおじいさんとよくさんぽをします。', '我经常和爷爷一起散步。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('296ec37b-5390-410f-939b-0137c016c80a', '64b16e41-8109-47cc-a6c3-fa1dac3b0b72', '昨日誰と一緒に帰りましたか。', 'きのうだれいっしょにかえりましたか。', '昨天和谁一起回去的？', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('b604c46d-5044-4b02-a900-e69599f2ec24', '64b16e41-8109-47cc-a6c3-fa1dac3b0b72', 'わたしは先生と30分話しました。', 'わたしはせんせいさんじゅっぷんはなしました。', '我和老师谈了30分钟。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('648dcc42-c58c-4225-9309-0693f693bc5c', '64b16e41-8109-47cc-a6c3-fa1dac3b0b72', '友だちと電話で話しました。', 'ともでんわではなしました。', '和朋友在电话里聊了聊。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('3ddad06f-b0f2-4e45-af2b-0a94eeb25a06', '64b16e41-8109-47cc-a6c3-fa1dac3b0b72', 'この猫は何という名前ですか。', 'このねこはなんというなまえですか。', '这只猫叫什么名字？', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('a2789614-cb56-4316-8ede-ddf9c0ed4e5f', '64b16e41-8109-47cc-a6c3-fa1dac3b0b72', '漢字のテストは大変だったとみんな言っていました。', 'かんじのテストはたいへんだったとみんないっていました。', '大家都说汉字考试太难了。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('315b6cc7-ed54-480a-a773-99a0111b08a4', 'に', NULL, 'N5', 'に', 'に', '表示事物存在或者静态的动作、作用的场所。\n表示动作、作用的到达点、着落点等。\n表示动作、作用的具体时间。\n表示动作、作用的目的。\n表示动作、作用涉及的对象。\n表示某一时间范围内的数量或次数。\n用于提示用途，“作为……”，相当于「～として」的用法。\n“因……而……”“由于……感到……”。表示原因、理由。\n表示比较、评价的基准。\n“和……”，表示同类事物的叠加。', '因为「に」前一般为具体时间，所以像「 毎[まい] 年[とし]、 毎[まい] 月[つき]、 毎[まい] 週[しゅう]、 毎[まい] 日[にち]、 先[せん] 週[しゅう]、 今[こん] 週[しゅう]、 来[らい] 週[しゅう]、 先[せん] 月[げつ]、 今[こん] 月[げつ]、 来[らい] 月[げつ]、 去[きょ] 年[ねん]、今 年[ことし]、 来[らい] 年[ねん]」这样的词语后面都不能用「に」。另外，对时间提问的「いつ」后不能加「に」，「 何[なん] 時[じ]」后面应该加「に」。', 693, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('a94eac92-319b-46e4-b502-4b9c3c184e8b', '315b6cc7-ed54-480a-a773-99a0111b08a4', '学校のそばに郵便局があります。', 'がっこうゆうびんきょくがあります。', '学校附近有家邮局。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('178a0b72-28fb-4d2c-bb76-fd0a6f2f150b', '315b6cc7-ed54-480a-a773-99a0111b08a4', '机の上に本が5冊あります。', 'つくえのうえほんがごさつあります。', '桌上有五本书。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('0105f002-1bce-45f4-8e0e-d8de3407e815', '315b6cc7-ed54-480a-a773-99a0111b08a4', '車の中に鍵を忘れました。', 'くるまのなかかぎをわすれました。', '把钥匙忘在车里了。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('6c9f4761-9f5d-4a48-892b-00358a001cb9', '315b6cc7-ed54-480a-a773-99a0111b08a4', 'ここにかばんを置かないでください。', 'ここにかばんをおかないでください。', '不要把包放在这里。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('e2ee054d-f265-419e-a4b4-a8e736f651f6', '315b6cc7-ed54-480a-a773-99a0111b08a4', '映画は何時に終わりますか。', 'えいがはなんじおわりますか。', '电影几点结束？', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('38ac334b-f0cc-4a34-9a86-e7284cfb8316', '315b6cc7-ed54-480a-a773-99a0111b08a4', '日曜日に掃除や洗濯をします。', 'にちようびそうじやせんたくをします。', '周日打扫房间、洗衣服什么的。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('20f97cc6-131d-4b13-ace1-99f96e97dd09', '315b6cc7-ed54-480a-a773-99a0111b08a4', '明日わたしの部屋へ遊びに来ませんか。', 'あしたわたしのへやへあそきませんか。', '明天来我房间玩吧？', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('63b1f5a4-880b-4c56-8516-9b14a2654b35', '315b6cc7-ed54-480a-a773-99a0111b08a4', '図書館へ本を返しに行きます。', 'としょかんへほんをかえいきます。', '去图书馆还书。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('a7d857c4-d1e8-4d05-87a4-349ae973d200', '315b6cc7-ed54-480a-a773-99a0111b08a4', 'わたしは友だちに電話をしました。', 'わたしはともでんわをしました。', '我给朋友打了电话。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('727060fc-342a-4c3a-9028-09d0b5071204', '315b6cc7-ed54-480a-a773-99a0111b08a4', 'わからないときは、先生に聞きます。', 'わからないときは、せんせいききます。', '不明白的时候，问老师。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('e50e3420-9fe7-41ac-9b2d-cd30c5dae0cc', '315b6cc7-ed54-480a-a773-99a0111b08a4', '父は一日に3回歯を磨きます。', 'ちちはいちにちさんかいはをみがきます。', '爸爸一天刷三次牙。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('43260d77-fb91-4ac6-b712-95cb7bd1880b', '315b6cc7-ed54-480a-a773-99a0111b08a4', '友だちの結婚祝いにおしゃれな食器を贈った。', 'ともだちのけっこんいわいにおしゃれなしょっきをおくった。', '作为朋友结婚的贺礼，我赠送了一套漂亮的餐具。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('131b430f-71c9-4bb8-8431-f8787a8f1898', '315b6cc7-ed54-480a-a773-99a0111b08a4', '案内してくれたお礼にお土産をあげた。', 'あんないしてくれたおれいにお土みやげをあげた。', '作为为我们做向导的谢礼，赠送了礼物。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('8b75441d-117b-4771-9073-829634a72372', '315b6cc7-ed54-480a-a773-99a0111b08a4', '東京に来て、電車を使う人がとても多いのにびっくりしました。', 'とうきょうにきて、でんしゃをつかうひとがとてもおおいのにびっくりしました。', '来到东京之后，因乘坐电车的人很多而感到吃惊。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('77d6e7d8-0bcb-40d1-8800-ca59bf4911d5', '315b6cc7-ed54-480a-a773-99a0111b08a4', 'あまりの恐ろしさに、声も出なかった。', 'あまりのおそろしさに、こえもでなかった。', '因为太恐惧，连声音也发不出了。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('d8012a2a-fbf5-4f58-b7dd-d4fa705263a8', '315b6cc7-ed54-480a-a773-99a0111b08a4', 'A社の商品が腰の痛みにどのぐらい効果があるのかについて詳しく知りたい。', 'Aしゃのしょうひんがこしのいたみにどのぐらいこうかがあるのかについてくわしくしりたい。', '我想详细了解一下A公司的商品对于腰痛有怎样的效果。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('1c05e8c1-b923-4344-8385-a6f2607e1c31', '315b6cc7-ed54-480a-a773-99a0111b08a4', 'このシャツがあなたにすごく似合うと思うよ。', 'このシャツがあなたにすごくにあうとおもうよ。', '我觉得这件衬衫非常适合你。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('2174667a-fb7d-420b-8313-c583ff2654a7', '315b6cc7-ed54-480a-a773-99a0111b08a4', 'A「これから行くおすし屋さんは、おすしにカレーにラーメン、なんでもありますよ。」B「面白い店ですね。」', 'A「これからいくおすしやさんは、おすしにカレーにラーメン、なんでもありますよ。」B「おもしろいみせですね。」', 'A：“现在要去的寿司店，提供寿司、咖喱饭和拉面，应有尽有呢。”\nB：“真是一家有趣的店呀。”', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('74868dcc-1948-4180-925f-f9691dddf30d', '315b6cc7-ed54-480a-a773-99a0111b08a4', 'スーパーでお米に野菜に果物を買ってきた。', 'スーパーでおこめやさいくだものをかってきた。', '从超市里买回了大米、蔬菜和水果。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('ac8a0b89-d64a-453e-b176-a66266cd55bf', 'の', NULL, 'N5', '名词＋の＋名词', '名词＋の＋名词\nな形容词词干＋な/い形容词辞书形＋の\n名词＋の…\n动词普通形＋の…', '表示所属、性质、限定、同位语等。\n在句中可以明确名词所指何物的情况下，可以用「の」代替该名词。\n作句子的修饰成分。\n形式体言，在句中通常不翻译出来。', '「の」的此种用法不一定翻译成汉语的“……的”。另外在所属物品相当明确的情况下，「の」后面再次出现的具体物品可省略。\n此种用法的「の」是由从句中主格助词「が」变过来的。\n「～の」在第一个例文中是代替宾语部分；第二个例文中是代替主语部分。', 694, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('fcf0f2e0-fabd-47fe-803e-cccf599d4483', 'ac8a0b89-d64a-453e-b176-a66266cd55bf', '日本の古い映画を見ました。', 'にほんふるいえいがをみました。', '看了日本的老电影。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('0da4d507-38c4-4d0a-bdd2-075507614645', 'ac8a0b89-d64a-453e-b176-a66266cd55bf', '今年の夏は海で泳ぎたいです。', 'ことしなつはうみでおよぎたいです。', '今年夏天想在海里游泳。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('28d928d9-a96e-491d-add3-d50ab94e5f09', 'ac8a0b89-d64a-453e-b176-a66266cd55bf', '花の写真を10枚ぐらい撮りました。', 'はなしゃしんをじゅうまいぐらいとりました。', '拍了大约十张花儿的照片。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('95c1a2f4-ef59-413c-812d-65982fad7204', 'ac8a0b89-d64a-453e-b176-a66266cd55bf', '息子の太郎は今年、17歳です。', 'むすこたろうはことし、じゅうななさいです。', '我儿子太郎今年17岁。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('aa2c1ed5-b177-400b-aede-86f9c9cc59c6', 'ac8a0b89-d64a-453e-b176-a66266cd55bf', 'この町で一番賑やかなのはこの辺です。', 'このまちでいちばんにぎやかなのはこのへんです。', '这一带是这个小镇最热闹的地方。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('c01642ff-c20a-4abf-bc6f-7843575dd99d', 'ac8a0b89-d64a-453e-b176-a66266cd55bf', 'もうちょっと安いのを、見せてください。', 'もうちょっとやすいのを、みせてください。', '请给我看看再便宜一些的。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('5d39f6d5-cd9e-4019-8b72-718b00838e43', 'ac8a0b89-d64a-453e-b176-a66266cd55bf', '田中さんの来る日は火曜日です。', 'たなかくるひはかようびです。', '田中周二来。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('0578b113-c3f0-426e-995a-f3070dd42362', 'ac8a0b89-d64a-453e-b176-a66266cd55bf', '今日の授業は休みだと誰かが言っているのを聞きました。', 'きょうのじゅぎょうはやすみだとだれかがいっているのをききました。', '我好像听谁说今天停课。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('80d748b3-00d4-44eb-aeff-52b3df497687', 'ac8a0b89-d64a-453e-b176-a66266cd55bf', '空を鳥が飛んでいるのが見えます。', 'そらをとりがとんでいるのがみえます。', '可以看到天空中有鸟在飞翔。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('1952f0fb-8fd5-4f2a-b5d9-b360e9f539b2', 'ac8a0b89-d64a-453e-b176-a66266cd55bf', 'その大きい荷物はわたしのです。', 'そのおおきいにもつはわたしのです。', '那件大行李是我的。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('baf584b1-6ae7-4c41-a79d-4b1448b18d44', 'へ', NULL, 'N5', 'へ', 'へ', '动作、作用的方向或目的地。\n动作、作用所涉及的对象。', '注意此种用法和「に」的区别。「へ」比「に」更强调动作的方向。', 695, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('c77cadfa-f0c1-4699-b1eb-f93b7964d73c', 'baf584b1-6ae7-4c41-a79d-4b1448b18d44', '会社へ行く前に、銀行へ行きました。', 'かいしゃいくまえに、ぎんこういきました。', '去公司之前，去了趟银行。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('6919da42-5d09-4b66-b58e-70c9c86531eb', 'baf584b1-6ae7-4c41-a79d-4b1448b18d44', '母は風邪で病院へ行きました。', 'はははかぜでびょういんいきました。', '妈妈因感冒去医院了。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('e8d15877-2ae0-4670-81e2-7de80a842740', 'baf584b1-6ae7-4c41-a79d-4b1448b18d44', 'これは田中さんへのプレゼントです。', 'これはたなかさんへのプレゼントです。', '这是给田中的礼物。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('b99ca166-0062-46a3-8f56-db3446c88ac7', 'まで', NULL, 'N5', 'まで', 'まで', '“到……”。表示动作、作用的时间或场所的终点。', '与「から」连用，构成「～から～まで」的形式，表示空间或时间上的起点和终点。', 696, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('f22abb98-a868-478b-8b7b-f4f225fb834d', 'b99ca166-0062-46a3-8f56-db3446c88ac7', 'A「先週の授業、どこまで進んだ？」B「3課の文法の練習問題を解いたところまでで終わったよ。」', 'A「せんしゅうのじゅぎょうすすんだ？」B「さんかのぶんぽうのれんしゅうもんだいをといたところまででおわったよ。」', 'A：“上周的课，上到哪里了？”\nB：“第三课的语法练习已经上完了。”', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('20c2157e-1b7c-465e-9136-03f21cd43720', 'b99ca166-0062-46a3-8f56-db3446c88ac7', '大学まで電車で30分かかります。', 'だいがくでんしゃでさんじゅっぷんかかります。', '坐电车到大学需要花费30分钟。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('fc85405a-75cc-475c-8d1f-a8ecd4bcea23', 'b99ca166-0062-46a3-8f56-db3446c88ac7', '銀行は9時から3時までです。', 'ぎんこうはくじからさんじまでです。', '银行的营业时间是从早上九点到下午三点。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('cb89d27b-7c29-477d-9389-765ac6167b09', 'を', NULL, 'N5', 'を', 'を', '表示动作所涉及的对象，即通常所说的宾语。\n表示动作经过的场所。\n表示动作的起点、出发点。', '此种情况下，「を」后的动词为他动词。\n此类动词还有「 歩[ある]く」「 泳[およ]ぐ」「 散[さん] 歩[ぽ]する」「 飛[と]ぶ」「 登[のぼ]る」「 走[はし]る」「 旅[りょ] 行[こう]する」等。\n此类动词还有「 降[お]りる」「 卒[そつ] 業[ぎょう]する」「 立[た]つ」等。', 697, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('b4f3c8da-8205-453a-ac0f-834c3507ee44', 'cb89d27b-7c29-477d-9389-765ac6167b09', '朝シャワーを浴びました。', 'あさあびました。', '早上洗了淋浴。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('27caad82-0fc1-48e1-9ebf-998e9e1b3c3b', 'cb89d27b-7c29-477d-9389-765ac6167b09', '忙しいから、ご飯を食べる時間がありません。', 'いそがしいから、ごはんたべるじかんがありません。', '因为太忙了，没有吃饭的时间。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('d0e9087c-9b99-4ff1-a154-b84e63073561', 'cb89d27b-7c29-477d-9389-765ac6167b09', 'この橋を渡って向こうに行きましょう。', 'このはしわたってむこうにいきましょう。', '走过这座桥去对面吧。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('1c08f6e4-2806-46b0-81bf-df34f14bec28', 'cb89d27b-7c29-477d-9389-765ac6167b09', 'わたしは今日6時に会社を出ます。', 'わたしはきょうろくじにかいしゃでます。', '我今天六点离开公司。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('e842fc48-a7b8-42b6-a937-6b105ce8ffa6', 'cb89d27b-7c29-477d-9389-765ac6167b09', '7時に家を出ます。', 'しちじにいえでます。', '七点从家里出门。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('6ec9f5fb-4b16-4409-8b01-6e739638b5d2', '并列助词、提示助词', NULL, 'N5', '并列助词、提示助词', '并列助词、提示助词', '并列助词连接两个或者两个以上的词语、文节，使它们构成并列关系。由并列助词连接的词语、文节，可以看作具有体言性质的整体，后面可以加助词等充当句子成分。\n提示助词接在体言、用言（动词、形容词、形容动词）、助词或其他词之后，用于突出提示句中的某一成分，句子后面会对该成分进行叙述或说明。', NULL, 698, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('07cf910d-d70b-4804-be3e-3991f77cc7db', '～と', NULL, 'N5', '名词＋と＋名词', '名词＋と＋名词', '“……和……”“……跟……”。表示物品或者事物的并列。', '用来表示完全列举，一般在列举的事物数目不超过3个时使用。', 699, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('581250b3-cc9f-4dee-a5c4-87ad4b89b4d9', '07cf910d-d70b-4804-be3e-3991f77cc7db', 'この料理は肉と野菜で作ります。', 'このりょうりはにくやさいでつくります。', '这道菜是用肉和蔬菜做的。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('df784e3e-028f-44a6-bbdb-433ebfa01b55', '07cf910d-d70b-4804-be3e-3991f77cc7db', '机の上に鉛筆とノートと教科書があります。', 'つくえのうえにえんぴつきょうかしょがあります。', '书桌上有铅笔、笔记本和课本。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('26d12d5f-6008-4725-85d9-b798b5328ff6', '～や', NULL, 'N5', '名词＋や＋名词（＋など）', '名词＋や＋名词（＋など）', '“……和……”“……或……”。表示对代表性事物的部分列举，暗示还有其他。构成句型为「～や（～や）（～など）」，只列举两个事物时，后面的「～や」和「～など」可以省略。', '相对于「と」的完全列举，「や」为不完全列举，一般在所列举的事物超过3个时使用。', 700, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('51a2eede-897f-4f13-8f07-973006565bf5', '26d12d5f-6008-4725-85d9-b798b5328ff6', '日曜日に掃除や洗濯をします。', 'にちようびにそうじせんたくをします。', '周日就在家打扫房间或洗衣服什么的。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('13a71199-3cdd-48b5-96a4-76bdb0b4e6d6', '26d12d5f-6008-4725-85d9-b798b5328ff6', '兄の部屋にはラジオやテレビなどがあります。', 'あにのへやにはラジオやテレビなどがあります。', '哥哥房间里有收音机和电视机等电器。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('0f67e93b-cf9a-4e0b-a3f0-6b3bbf08d0fa', '～か', NULL, 'N5', '名词＋か、名词（＋か）＋格助词', '名词＋か、名词（＋か）＋格助词', '表示从2个或者3个事物中选取一个，表示选择。', '并列助词「と、や」都没有表示选择的意思。另外「～か～か」接具有相反意义的词或同一个词的肯定形与否定形，意为“是……还是……”。', 701, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('134a9c82-2bea-4292-884d-e6b950b74e72', '0f67e93b-cf9a-4e0b-a3f0-6b3bbf08d0fa', '今日か明日、一緒にご飯を食べませんか。', 'きょうあした、いっしょにごはんをたべませんか。', '今天或明天，一起吃个饭吧。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('71ab8d6e-e784-4f55-8520-d16cea0eacee', '0f67e93b-cf9a-4e0b-a3f0-6b3bbf08d0fa', 'この料理は牛肉か豚肉を使います。', 'このりょうりはぎゅうにくぶたにくをつかいます。', '做这道菜要用牛肉或者猪肉。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('736ff97d-ecb0-4b16-be23-e94172ecfabe', '0f67e93b-cf9a-4e0b-a3f0-6b3bbf08d0fa', '明日雨が降るか降らないかはわかりません。', 'あしたあめがふふらないかはわかりません。', '不知道明天下不下雨。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('d34a74fb-049a-416d-ba0b-dc73ba7ca506', '～も', NULL, 'N5', '名词＋も', '名词＋も\n数量词＋も', '“……也……”“……都……”，表示同类事物的列举或叠加。\n“……也……”“……竟……”，强调数量之多或者数量之少。', '此用法的「も」出现在肯定句中表示全盘肯定，出现在否定句中表示全盘否定。', 702, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('a5f56a63-a40f-4b3c-aa8e-6b84e57af1f4', 'd34a74fb-049a-416d-ba0b-dc73ba7ca506', 'ご飯もパンもよく食べます。', 'ごはんもパンもよくたべます。', '饭和面包都经常吃。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('03fe5dc5-87e4-4cac-a91c-f9b5a88db3a4', 'd34a74fb-049a-416d-ba0b-dc73ba7ca506', '銀行へもデパ－トへも行きませんでした。', 'ぎんこういきませんでした。', '银行和商场都没去。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('8e61a937-7afe-4592-9a42-2a08435d1076', 'd34a74fb-049a-416d-ba0b-dc73ba7ca506', '一つのクラスには学生が50人もいました。', 'ひとつのクラスにはがくせいがごじゅうにんもいました。', '一个班级里竟然有五十个学生。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('cb460346-9912-4eda-9c76-150bc9b4cc3c', 'd34a74fb-049a-416d-ba0b-dc73ba7ca506', 'パーティーに日本人は一人も来ていません。', 'パーティーににほんじんはひとりきていません。', '聚会上一个日本人也没来。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('70c669d9-5937-4ddb-bdba-4396b4625754', 'は', NULL, 'N5', '名词（＋に/へ/で/と/から/まで）＋は', '名词（＋に/へ/で/と/から/まで）＋は', '「は」用来提示主题，并对主题进行说明和判断。\n「～は～が～」句型可以用来说明主题的某种状态。\n「～は～（が）、～は～」句型可以用来进行两种事物的比较。', '「は」和「が」的区别\n提示主题用「は」，提示主语用「が」。\n对主题进行说明判断时用「は」，陈述眼前看到的、听到的、实际感受到的事情时用「が」。\n提示已知事物用「は」，未知事物用「が」。\n「は」的指示范围涉及全句，即关联句末的谓语，可以说是句子的大主语；「が」可指示从句中的主语，也可以称作小主语。', 703, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('2c4bb6f7-160b-4fe7-a3bb-5f1b7269847a', '70c669d9-5937-4ddb-bdba-4396b4625754', 'わたしの部屋はあまりきれいじゃありません。', 'わたしのへやはあまりきれいじゃありません。', '我的房间不太整洁。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('05c9b178-5faa-47fd-b3f3-a27456c900dc', '70c669d9-5937-4ddb-bdba-4396b4625754', '一番大変な仕事は何ですか。', 'いちばんたいへんなしごとなんですか。', '最困难的工作是什么？', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('bc21633b-5351-41cc-9599-2ea3eddad66f', '70c669d9-5937-4ddb-bdba-4396b4625754', '兄は背が高いです。', 'あにせたかいです。', '哥哥个子高。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('9c7ea5da-10a9-4615-8b66-5f04d6bc04e7', '70c669d9-5937-4ddb-bdba-4396b4625754', '明日は雪が降るでしょう。', 'あしたゆきふるでしょう。', '明天会下雪吧。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('624f9442-58fe-4b8f-b3aa-2579e7789b61', '70c669d9-5937-4ddb-bdba-4396b4625754', '山田さんはテニスはしますが、ゴルフはしません。', 'やまださんはテニスはしますが、ゴルフはしません。', '山田打网球，不过不打高尔夫。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('8665653f-b758-477e-a40d-d916c29f7b77', '70c669d9-5937-4ddb-bdba-4396b4625754', '象は鼻が長いです。', 'ぞうはなながいです。', '大象鼻子长。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('5e8683fa-272f-43b6-8ba7-ccb4b9248304', '70c669d9-5937-4ddb-bdba-4396b4625754', '東北地方の雪は多いです。', 'とうほくちほうのゆきおおいです。', '东北地区雪下得多。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('a78c4657-e1dd-499b-baa5-e9400ac2bc4f', '70c669d9-5937-4ddb-bdba-4396b4625754', '今、雪が降っています。', 'いま、ゆきふっています。', '现在正在下雪。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('01bdbb7b-ada5-4e24-97a2-1ee9b73d2b14', '70c669d9-5937-4ddb-bdba-4396b4625754', '机の上に日本語の教科書があります。それは王さんのです。', 'つくえのうえににほんごのきょうかしょおうさんのです。', '桌上有本日语教科书，那是小王的。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('78a54380-d7a2-416a-b328-434b5394c81c', '70c669d9-5937-4ddb-bdba-4396b4625754', 'どの人が山下さんですか。', 'どのひとやましたさんですか。', '哪位是山下先生（小姐）？', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('1e0f3695-8010-4c1e-a773-dc9e9ac3b15b', '70c669d9-5937-4ddb-bdba-4396b4625754', '母が作るサンドイッチはおいしいです。', 'ははつくるサンドイッチはおいしいです。', '妈妈做的三明治很好吃。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('7fc99d0f-0c31-4d5f-a7f8-8583808126fd', '70c669d9-5937-4ddb-bdba-4396b4625754', '先週は宿題が多くて大変でした。', 'せんしゅうしゅくだいおおくてたいへんでした。', '上周作业很多，忙死了。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('1986563d-69b5-48df-bd1e-4b8fa30a0061', '～しか～ない', NULL, 'N5', '名词（＋助词）＋しか＋动词「ない形」', '名词（＋助词）＋しか＋动词「ない形」', '“只有……”，表示限定。', '此句型含有说话人感觉不满意的语感，所以一般用于消极场合。', 704, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('8e14da52-09d2-4b6d-8f35-19033bc0b33a', '1986563d-69b5-48df-bd1e-4b8fa30a0061', '雪がたくさん降ったから、一人しか来ませんでした。', 'ゆきがたくさんふったから、ひとりきませんでした。', '因为下了大雪，所以只来了一个人。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('84f4d5ac-daec-4a9e-9044-c8698f396d7d', '1986563d-69b5-48df-bd1e-4b8fa30a0061', 'この部屋には椅子が一つしかありません。', 'このへやにはいすがひとつしかありません。', '这个房间里只有一把椅子。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('ce29e447-8a79-4c69-8088-dd62c4b1b137', '1986563d-69b5-48df-bd1e-4b8fa30a0061', 'このパーティーはチケットを買った人しか入れません。', 'このパーティーはチケットをかったひとはいれません。', '这个派对只有买了票的人才能入场。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('b964b579-d4ab-4ea7-adb9-21a8e4c5b197', '～だけ', NULL, 'N5', '名词＋だけ', '名词＋だけ', '“只有”，表示限定。', '此句型包含说话人不满的语气很少，更多的用于描述客观事实。', 705, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('8d55580b-13e8-4b05-bd15-fd423c8c1b82', 'b964b579-d4ab-4ea7-adb9-21a8e4c5b197', '高いケーキを1つだけ買いました。', 'たかいケーキをひとかいました。', '就买了一个昂贵的蛋糕。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('c5cde454-7121-4514-93cc-87456d4106ca', 'b964b579-d4ab-4ea7-adb9-21a8e4c5b197', '小川さんだけお酒を飲みます。', 'おがわさんだけおさけをのみます。', '只有小川喝酒。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('dbf54dc8-5f4b-43ee-a12e-5383b733fca4', '～くらい/ぐらい', NULL, 'N5', '名词＋くらい/ぐらい', '名词＋くらい/ぐらい', '“大约……”“大概……”“……左右”等。可用来表示大概的时间、数量、程度等。', '「～くらい/ぐらい」表示程度的用法，详见N3第23条语法条目。', 706, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('b0e324cb-f0b9-4659-80bc-e937daccebe5', 'dbf54dc8-5f4b-43ee-a12e-5383b733fca4', '駅で友だちを1時間ぐらい待ちました。', 'えきでともだちをいちじかんまちました。', '在车站等了朋友一个小时左右。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('85714ac2-d47f-4234-a96e-2f100f6fe6c9', 'dbf54dc8-5f4b-43ee-a12e-5383b733fca4', '花の写真を10枚ぐらい撮りました。', 'はなのしゃしんをじゅうまいとりました。', '拍了大约十张花儿的照片。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('b3f58133-b3f0-41e7-bbce-40a9bf3f565d', '～など', NULL, 'N5', '名词＋など', '名词＋など', '“……等等”。用于列举，暗示除此之外还有其他事物存在。经常和「や」一起使用，构成「～や～など」的句型。', '人物并列时，不能用「など」。另外，一个句子中只能用一个「など」，即没有「～など、～など」的用法。', 707, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('4b0018fb-3b12-48aa-9c3d-9ed27a8ee3bc', 'b3f58133-b3f0-41e7-bbce-40a9bf3f565d', '兄の部屋にはラジオやテレビなどがあります。', 'あにのへやにはラジオやテレビなどがあります。', '哥哥房间里有收音机和电视机等。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('2d98d664-4ee4-455d-9781-e4e368f3aa8c', 'b3f58133-b3f0-41e7-bbce-40a9bf3f565d', 'かばんの中に財布や鍵などがあります。', 'かばんのなかにさいふかぎなどがあります。', '包里有钱包和钥匙等。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('304e3f46-9061-4f5a-a015-cb4c0e0f1483', '接续助词、终助词', NULL, 'N5', '接续助词、终助词', '接续助词、终助词', '接续助词连接用言、用言性词组或者句子，表示它们之间的关系，在句子中有承上启下的作用。一般可以表示条件、让步、因果、转折、并列等逻辑关系。\n终助词，一般出现在句子的末尾（有时也出现在从句的末尾），表示感叹、疑问、禁止等语气。', NULL, 708, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('b64f4a76-5338-4d44-84d9-eae7bb8c4398', 'が', NULL, 'N5', 'が', 'が', '表示逆接，即后项内容与前项预想的结果不符。\n前后两个句子互为对照。\n用于引出话题。', NULL, 709, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('1c70941e-f429-4f84-86db-8ed14398158f', 'b64f4a76-5338-4d44-84d9-eae7bb8c4398', '30分ぐらい待ちましたが、バスは来ませんでした。', 'さんじゅっぷんぐらいまちましたが、バスはきませんでした。', '等了30分钟，公交车却没来。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('cef04ef6-8700-4258-9e08-11cf41c74240', 'b64f4a76-5338-4d44-84d9-eae7bb8c4398', '山田さんはテニスはしますが、ゴルフはしません。', 'やまださんはテニスはしますが、ゴルフはしません。', '山田打网球，不过不打高尔夫。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('0c470f51-3133-4c99-b987-de5a75e5b2db', 'b64f4a76-5338-4d44-84d9-eae7bb8c4398', 'わたしはよく旅行をしますが、兄はあまりしません。', 'わたしはよくりょこうをしますが、あにはあまりしません。', '我经常旅游，不过哥哥不太去。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('993b3599-dfba-4f87-974c-2544dea08534', 'b64f4a76-5338-4d44-84d9-eae7bb8c4398', 'すみませんが、少し静かにしてください。', 'すみませんが、すこししずかにしてください。', '不好意思，请稍微安静点。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('f377b073-4280-4d96-bb51-d60df4886cd8', 'ても/でも', NULL, 'N5', '动词「て形」＋も', '动词「て形」＋も\n疑问词＋でも', '“但是……”。「でも」作为接续词使用时，表示逆接。\n“不管……都……”“就算……也……”。\n“无论……”“不管……”。', '「～ても」表示让步，前项的条件不会对后项造成影响。\n「～でも」在这种情况下表示在某一类事物中不特指某一个。', 710, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('32458611-a313-4954-bc26-23f12c54a021', 'f377b073-4280-4d96-bb51-d60df4886cd8', '図書館で3時間勉強しました。でも、うちではしませんでした。', 'としょかんでさんじかんべんきょうしました。でも、うちではしませんでした。', '在图书馆学习了三个小时。不过，在家里没有学习。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('d3843864-5a25-4f82-a68a-7068abc623e7', 'f377b073-4280-4d96-bb51-d60df4886cd8', '父に電話をしました。でも、友だちにはしませんでした。', 'ちちにでんわをしました。でも、ともだちにはしませんでした。', '给爸爸打了电话。但是，没有给朋友打。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('ffb892b6-54f8-4d63-9ca8-2446c46924e3', 'f377b073-4280-4d96-bb51-d60df4886cd8', 'あの美術館はいつ行っても人がたくさんいます。', 'あのびじゅつかんはいついひとがたくさんいます。', '无论何时去那座美术馆都有很多人。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('c251048e-69f5-43d8-a0ab-40f25b28af73', 'f377b073-4280-4d96-bb51-d60df4886cd8', '学校を卒業しても、日本語の勉強を続けていくつもりだ。', 'がっこうをそつぎょうしても、にほんごのべんきょうをつづけていくつもりだ。', '就算毕业了也打算继续学日语。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('73b29f09-e90d-4f41-b84d-b15003b364bf', 'f377b073-4280-4d96-bb51-d60df4886cd8', '私はどこでも寝られます。', 'わたしねられます。', '我不管在哪儿都能睡着。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('5a09c311-d38e-46f3-870b-e01fa1c63453', 'f377b073-4280-4d96-bb51-d60df4886cd8', '私は何でも食べられます。', 'わたしはなんたべられます。', '我什么都能吃。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('d352ce76-73d6-4423-bf66-af720fda01ad', 'けれども/けど/けれど', NULL, 'N5', 'けれども/けど/けれど', 'けれども/けど/けれど', '“但是……”“可是……”。', '「けれども/けど/けれど」意思跟表示转折的「が」很相似，多用于口语。', 711, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('22e0547a-fd05-4c0c-a77c-3d4c35df583b', 'd352ce76-73d6-4423-bf66-af720fda01ad', '玄関のベルが鳴ったけれど今頃誰だろう。', 'げんかんのベルがないまごろだれだろう。', '门铃响了，可都到这时候了，会是谁呢？', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('4d5c0d8b-a702-4232-a15f-b247a8899cb4', 'd352ce76-73d6-4423-bf66-af720fda01ad', '友だちとの約束を守りたいけれども、突然のことで行けなくなりました。', 'ともだちとのやくそくをまもりたいけれども、とつぜんのことでいけなくなりました。', '虽然想要遵守和朋友的约定，但是因为突发的事情而去不了了。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('7cabe4b6-cecc-4c67-8ca2-9f5f9b140931', 'しかし', NULL, 'N5', 'しかし', 'しかし', '“但是……”“不过……”，表示转折。', NULL, 712, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('3c563755-ae12-46bb-bdd7-17315921ea2d', '7cabe4b6-cecc-4c67-8ca2-9f5f9b140931', '飛行機はスピードが速いです。しかし、値段が高いです。', 'ひこうきはスピードがはやいです。しかし、ねだんがたかいです。', '飞机速度很快，但是票价太贵了。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('96ada479-f94e-46f5-a50f-dbf27c9a55b2', '7cabe4b6-cecc-4c67-8ca2-9f5f9b140931', 'この部屋はきれいです。しかし、ちょっと狭いです。', 'このへやはきれいです。しかし、ちょっとせまいです。', '这间房间很漂亮，但是有点小。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('4b72a1e2-dec2-418c-bfcf-a3117ce032d2', '7cabe4b6-cecc-4c67-8ca2-9f5f9b140931', 'この仕事は忙しいです。しかし、面白いです。', 'このしごとはいそがしいです。しかし、おもしろいです。', '这份工作很忙碌，但是很有意思。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('da387c81-d352-4fef-8599-ff2be21d89ed', '～から', NULL, 'N5', '句子的简体形/敬体形＋から', '句子的简体形/敬体形＋から', '“因为……”“由于……”，表示原因、理由。', '「から」提示的原因、理由主要是说话人的主观理由，因此后面的句子也多为表示说话人的请求、愿望、推测、主张等的内容。', 713, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('1156167d-6336-4207-a111-3ec36c742d55', 'da387c81-d352-4fef-8599-ff2be21d89ed', '今日はいい天気だから、洗濯しましょう。', 'きょうはいいてんきだから、せんたくしましょう。', '今天是好天气，那就洗衣服吧。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('74d42933-a0ae-430d-9b52-147cc55bc86d', 'da387c81-d352-4fef-8599-ff2be21d89ed', '忙しいから、ご飯を食べる時間がありません。', 'いそがしいから、ごはんをたべるじかんがありません。', '因为太忙了，没有吃饭的时间。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('00d78ac0-0083-4f5b-b446-07b5cf40a339', 'da387c81-d352-4fef-8599-ff2be21d89ed', '電車が止まりました。雪がたくさん降ったからです。', 'でんしゃがとまりました。ゆきがたくさんふったからです。', '电车停了，因为雪下得太大了。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('39319064-04b8-40b3-9b38-f28a14d5486b', '～ので', NULL, 'N5', '动词普通形＋ので', '动词普通形＋ので\nい形容词普通形＋ので\nな形容词词干＋な＋ので\n名词＋な＋ので\n句子的简体形·敬体形＋ので', '“因为……”“由于……”，表示客观的原因、理由。语气比「から」委婉。', '「ので」提示的原因、理由比较客观，因此后项不能用命令、禁止等表达方式。', 714, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('aadfd8dd-b5cb-4c5b-9b3e-3ab91be61599', '39319064-04b8-40b3-9b38-f28a14d5486b', '主人が今出張中なので、うちにはいません。', 'しゅじんがいましゅっちょうちゅうなので、うちにはいません。', '我老公去出差了，所以不在家。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('ddd926c1-ea48-4d58-924a-1df9f2250803', '39319064-04b8-40b3-9b38-f28a14d5486b', '今度の試験がとても難しかったので、合格しませんでした。', 'こんどのしけんがとてもむずかしかったので、ごうかくしませんでした。', '这次考试太难了，所以没有及格。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('c6bd5704-bc07-491e-84ac-0442d74b4954', '39319064-04b8-40b3-9b38-f28a14d5486b', '風邪を引いたので、病院へ行きました。', 'かぜをひいたので、びょういんへいきました。', '感冒了，所以去医院了。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('4bc7fc7e-7059-417f-bf18-78c78cf6aa62', 'て/で', NULL, 'N5', 'い形容词词干＋くて', 'い形容词词干＋くて\n名词/な形容词词干＋で', '表示中顿。\n表示并列。\n表示轻微的原因。', NULL, 715, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('9e878255-6480-4eaf-a14f-83b5037cd292', '4bc7fc7e-7059-417f-bf18-78c78cf6aa62', 'この辺は夏は涼しくて、冬は暖かいです。', 'このへんはなつはすずしくて、ふゆはあたたかいです。', '这一带冬暖夏凉。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('e3aa739e-139a-425c-8a0f-2551fd613d22', '4bc7fc7e-7059-417f-bf18-78c78cf6aa62', '妹は17歳で、学生です。', 'いもうとはじゅうななさいで、がくせいです。', '我妹妹17岁，是学生。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('3acc32d8-28d9-4139-bf3c-ef6519fe717b', '4bc7fc7e-7059-417f-bf18-78c78cf6aa62', 'わたしのアパ－トは静かでいいです。', 'わたしのアパ－トはしずかでいいです。', '我住的公寓安静又舒适。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('c75bcb8e-e199-463d-929a-8a5837810294', '4bc7fc7e-7059-417f-bf18-78c78cf6aa62', 'この道は暗くて危ないです。', 'このみちはくらあぶないです。', '这条路很黑，有点危险。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('a2a62521-9ba8-4f45-afca-d94ca82e702a', '4bc7fc7e-7059-417f-bf18-78c78cf6aa62', '先週は宿題が多くて大変でした。', 'せんしゅうはしゅくだいがおおたいへんでした。', '上周作业很多，真够呛。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('bf09ad8a-335b-4a4b-ba6e-8dd178b59a75', '～ながら', NULL, 'N5', '动词「ます形」＋ながら', '动词「ます形」＋ながら', '“一边……，一边……”。表示进行某项动作、行为的同时，进行另一项动作、行为。', NULL, 716, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('9642f4ae-cde2-4ca6-87b6-43940968dc17', 'bf09ad8a-335b-4a4b-ba6e-8dd178b59a75', '何か飲みながら、話をしましょう。', 'なにかのみながら、はなしをしましょう。', '边喝点东西边谈吧。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('ca3401d2-e0e9-43f0-ac9e-32c94a725228', 'bf09ad8a-335b-4a4b-ba6e-8dd178b59a75', 'わたしは音楽を聞きながら勉強をします。', 'わたしはおんがくをきべんきょうをします。', '我一边听音乐一边学习。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('de149a19-1469-46fe-9d62-ca9a922b52d7', 'それに', NULL, 'N5', 'それに', 'それに', '“而且……”“还有……”。', '「それに」表示并列或累加。', 717, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('9aa4f806-6200-4611-90b3-79379d771687', 'de149a19-1469-46fe-9d62-ca9a922b52d7', 'この道は狭い。それに、車が多くて危ない。', 'このみちはせまい。それに、くるまがおおくてあぶない。', '这条路很窄，而且车很多，很危险。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('feaf7b9c-2fd0-44af-949a-6bc0383ff9da', 'de149a19-1469-46fe-9d62-ca9a922b52d7', '東京は人が多いし、それに物価も高いので、住みにくいです。', 'とうきょうはひとがおおぶっかもたかいので、すみにくいです。', '东京人很多，物价又贵，不适合居住。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('424daa12-7ec8-4aa2-83d4-753fafbb756a', 'それとも', NULL, 'N5', 'それとも', 'それとも', '“是……还是……？”，连接两个疑问句。', '「それとも」只用于选择疑问句。', 718, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('e2bd4d71-ca7d-4366-ada2-62ef2eb95e93', '424daa12-7ec8-4aa2-83d4-753fafbb756a', '明日は雨ですか。それとも、晴れですか。', 'あしたはあめですか。それとも、はれですか。', '明天是下雨天还是晴天？', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('3eabc993-8dc3-4ee4-8321-f2e933109126', '424daa12-7ec8-4aa2-83d4-753fafbb756a', 'これは豚肉ですか。それとも、牛肉ですか。', 'これはぶたにくですか。それとも、ぎゅうにくですか。', '这是猪肉还是牛肉？', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('6a32a753-3d7a-4736-973e-315489d7e538', 'それから', NULL, 'N5', 'それから', 'それから', '“然后……”。表示前项动作结束之后，接着做后项的事情。', NULL, 719, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('591d765c-536d-4061-9726-10d420abc325', '6a32a753-3d7a-4736-973e-315489d7e538', '朝新聞を読みます。それから、会社へ行きます。', 'あさしんぶんをよみます。それから、かいしゃへいきます。', '早上看报纸，然后去公司。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('ee0a9180-3d25-4622-a235-b7305060fc3e', '6a32a753-3d7a-4736-973e-315489d7e538', '田中さんは5時まで会社で働きます。それから、飲み会に行きます。', 'たなかさんはごじまでかいしゃではたらきます。それから、のみかいにいきます。', '田中在公司工作到五点，然后去参加聚餐。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('59d81876-c2c7-44a1-aa3d-809050335ce2', 'ところで', NULL, 'N5', 'ところで', 'ところで', '“对了……”“话说……”。', '「ところで」用于转移话题，常用在段落开头或是对话中途停顿后的开头。', 720, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('2f29861d-001c-4343-b0db-8863f1b6377c', '59d81876-c2c7-44a1-aa3d-809050335ce2', 'A「お久しぶりですね。」B「そうですね。」A「ところで、もう結婚したと聞きましたわ、おめでとう。」', 'A「おひさしぶりですね。」B「そうですね。」A「ところで、もうけっこんしたとききましたわ、おめでとう。」', 'A：“好久不见。”\nB：“是啊。”\nA：“对了，听说你已经结婚了，恭喜啊。”', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('6b3ada09-27e0-4a36-af21-8bcd065b6900', '59d81876-c2c7-44a1-aa3d-809050335ce2', '会議はこれで終わります。ところで、取引先のお客さんはまだ来ませんか。', 'かいぎはこれでおわります。ところで、とりひきさきのおきゃくさんはまだきませんか。', '会议到此结束。话说，客户还没来吗？', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('3a63d715-2b19-44fb-a7d5-7e3808f012b7', 'それで', NULL, 'N5', 'それで', 'それで', '“所以……”“因此……”。', '「それで」表示前后句之间的因果关系。', 721, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('bb514568-609f-4ad9-9916-a5e59df30171', '3a63d715-2b19-44fb-a7d5-7e3808f012b7', '医者「川田さん、晩ご飯を食べ過ぎませんでしたか。」川田「ああ…。おいしかったから、ご飯を5杯食べました。」医者「ああ、それで痛くなったんですよ。」', 'いしゃ「かわたさん、ばんごはんをたべすぎませんでしたか。」かわた「ああ…。おいしかったから、ごはんをごはいたべました。」いしゃいたくなったんですよ。」', '医生：“川田，晚饭是不是吃多了？”\n川田：“啊……因为太好吃了，就吃了五碗饭。”\n医生：“啊，所以才疼的呀。”', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('2e1a45e0-db42-45c7-8e81-3c9ff0cf43ce', '3a63d715-2b19-44fb-a7d5-7e3808f012b7', 'ずっと日本に住むつもりです。それで今、日本語を勉強しています。', 'ずっとにほんにすいま、にほんごをべんきょうしています。', '我打算一直住在日本，因此现在正在学日语。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('7cb522ed-1fc1-4425-b461-fd271a2b4f3e', 'か', NULL, 'N5', 'か', 'か', '「か」作为终助词，读升调，可以表示疑问、再次确认等语气。读降调，可以表示惊讶、感叹等语气。', '可以用「～ですか、～ですか」或者「～ますか、～ますか」的句型表示选择疑问。', 722, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('4a397d59-6a2c-4aab-8146-44e3c65fc87b', '7cb522ed-1fc1-4425-b461-fd271a2b4f3e', 'その本をどこで買ったか覚えていますか。', 'そのほんをどこでかったかおぼえていますか。', '还记得那本书是在哪里买的吗？', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('8ec9c778-e69d-4897-93c4-1548d830b82b', '7cb522ed-1fc1-4425-b461-fd271a2b4f3e', 'また遅刻ですか。', 'またちこくですか。', '又迟到了！', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('98f59b93-5003-4e26-a275-108bfc3fd3d5', '7cb522ed-1fc1-4425-b461-fd271a2b4f3e', '郵便局は、レストランの右ですか、左ですか。', 'ゆうびんきょくは、レストランのみぎですか、ひだりですか。', '邮局在餐厅右边还是左边？', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('110be313-9055-4587-82d0-1a06795ed233', 'ね', NULL, 'N5', 'ね', 'ね', '可以用来表示轻微的感叹或者征求对方的同意，还可以用来表示叮嘱。', NULL, 723, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('cb582d00-eaf7-4fa4-b0b7-bb999f9e20f5', '110be313-9055-4587-82d0-1a06795ed233', '高いですね。もっと安くしてください。', 'たかいですね。もっとやすくしてください。', '真贵，再便宜点吧。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('1385f16b-8cab-4a02-b15f-52978af07a1a', '110be313-9055-4587-82d0-1a06795ed233', '昨日は天気がよくなかったですね。', 'きのうはてんきがよくなかったですね。', '昨天天气不好啊。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('cf5734c2-bd76-4f74-a410-ce35cd56af1a', '110be313-9055-4587-82d0-1a06795ed233', '子どもが寝ているから、大きい声で歌わないでね。', 'こどもがねているから、おおきいこえでうたわないでね。', '孩子在睡觉，不要大声唱歌啊。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('0b3ae350-5d9d-45eb-897b-f06e1d32e0bc', 'よ', NULL, 'N5', 'よ', 'よ', '用于提醒对方或向对方提出自己的主张，句末用「よ」来加强语气。', NULL, 724, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('8eeaaf1c-1dd9-4870-a3b4-4bd795b8a2f0', '0b3ae350-5d9d-45eb-897b-f06e1d32e0bc', 'あ、あそこで鳥が鳴いていますよ。', 'あ、あそこでとりがないていますよ。', '啊，那里有鸟儿在叫。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('efbba77b-bd8b-4d99-9142-80319f51fa48', '0b3ae350-5d9d-45eb-897b-f06e1d32e0bc', 'もう少し待ったほうがいいですよ。', 'もうすこしまったほうがいいですよ。', '再稍微等一下比较好。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('80c5012d-8e85-4da9-b3a4-88c453debd0f', '0b3ae350-5d9d-45eb-897b-f06e1d32e0bc', 'あのケーキはおいしくなかったよ。', 'あのケーキはおいしくなかったよ。', '那种蛋糕不好吃。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('562eb110-23c8-41cc-b44e-b0255a273688', 'わ', NULL, 'N5', 'わ', 'わ', '向对方表示自己的判断、决心。', '女性用语，用在句末可以使语气委婉、柔和。', 725, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('b50e41c0-5101-4a2e-9641-05d086504b77', '562eb110-23c8-41cc-b44e-b0255a273688', 'それは知りませんわ。', 'それはしりませんわ。', '我不知道那件事。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('84574d63-041f-4e01-8246-22df6fdf5445', '562eb110-23c8-41cc-b44e-b0255a273688', '昼ご飯はカレーにしますわ。', 'ひるごはんはカレーにしますわ。', '午饭我吃咖喱。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('f4c38551-0db7-48e1-a21b-7934e1c5df3f', 'かな/かしら', NULL, 'N5', 'かな/かしら', 'かな/かしら', '“……吗？”', '「かな」用于句末，表示疑惑和不确定的态度；多用于自言自语，用于对话时则表示间接提出请求或期望，此时常用“～ないかな”的形式。是比较随意的口语形式，前面不接礼貌体。「かしら」属于女性用语。', 726, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('ba8db6e3-5a8b-44a4-b376-58cb52ba2cd1', 'f4c38551-0db7-48e1-a21b-7934e1c5df3f', '山田選手は今回の試合に出るかな。', 'やまだせんしゅはこんかいのしあいにでるかな。', '山田选手会参加这次比赛吗？', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('20029ea4-46dc-4cd2-a14a-782eab8f7de7', 'f4c38551-0db7-48e1-a21b-7934e1c5df3f', 'その荷物を持ってくれないかな。', 'そのにもつをもってくれないかな。', '能帮我拿一下那件行李吗？', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('b050b4b8-c04a-4f9d-90b8-b019eadc5527', 'f4c38551-0db7-48e1-a21b-7934e1c5df3f', '今度の休みはどこへ行こうかしら。', 'こんどのやすみはどこへいこうかしら。', '这次假期要去哪里呢？', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('2e01e884-5528-4158-88cb-b559cfeca546', '时间＋すぎ/まえ', NULL, 'N5', '时间＋すぎ/まえ', '时间＋すぎ/まえ', '「すぎ/まえ」接在表示时间的词后面，表示时间上的偏差。「すぎ」表示过了参照时间，「まえ」表示还没到参照时间。', NULL, 727, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('727c25aa-d29e-4c97-948a-599b53ea1664', '2e01e884-5528-4158-88cb-b559cfeca546', '10時すぎに王さんが来ました。', 'じゅうじすぎにおうさんがきました。', '十点多的时候，小王来了。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('7506bd9d-b541-4d98-b9e8-acd6e9649247', '2e01e884-5528-4158-88cb-b559cfeca546', '今9時10分まえです。', 'いまくじじゅっぷんまえです。', '现在是九点差十分。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('35eb632d-b1ab-46e0-a3c2-11cac5f049f3', '2e01e884-5528-4158-88cb-b559cfeca546', '今9時10分すぎです。', 'いまくじじゅっぷんすぎです。', '现在是九点过十分。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('12c1f1ea-87ea-45f9-86e6-a880f5594237', '～たち/がた', NULL, 'N5', '～たち/がた', '～たち/がた', '“……们”。「たち/がた」接在人称词或表示称谓的名词后面，表示复数。', '「がた」的尊敬语气更强，因此只能接在表示第二、第三人称的词后面。', 728, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('40014cf5-cd47-4bee-820b-2bb229e96822', '12c1f1ea-87ea-45f9-86e6-a880f5594237', '子どもたちが歌を上手に歌っています。', 'こどもたちがうたをじょうずにうたっています。', '孩子们娴熟地唱着歌。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('01381e63-d6b6-4da8-af02-ef5c5da8e76d', '12c1f1ea-87ea-45f9-86e6-a880f5594237', 'ここが、あなた方の部屋です。', 'がたのへやです。', '这里是你们的房间。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('5fe69abd-eb4a-4a55-b272-f8936159add5', '12c1f1ea-87ea-45f9-86e6-a880f5594237', '先生方、おはようございます。', 'せんせいがた、おはようございます。', '老师们，早上好。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('51b89718-9955-4845-8ebd-ef201bebc5f6', '～ 中[ちゅう/じゅう]', NULL, 'N5', '～ 中[ちゅう/じゅう]', '～ 中[ちゅう/じゅう]', '读作「ちゅう」的场合：接在一定时间内可以持续的动作性名词后，表示动作正在进行中；接在表示时间、空间的词语之后，表示“之内、之中”的意思。\n读作「じゅう」的场合：接在表示时间、空间的词语之后，表示“整个、全部”的意思。', '常见的「～ちゅう」的词汇\n運[うん] 転[てん]ちゅう　 営[えい] 業[ぎょう]ちゅう　お 話[はなし]ちゅう　 会[かい] 議[ぎ]ちゅう　 検[けん] 討[とう]ちゅう　 工[こう] 事[じ]ちゅう　 仕[し] 事[ごと]ちゅう　 受[じゅ] 験[けん]ちゅう　 出[しゅっ] 張[ちょう]ちゅう　 食[しょく] 事[じ]ちゅう　 調[ちょう] 査[さ]ちゅう　 電[でん] 話[わ]ちゅう　 病[びょう] 気[き]ちゅう　 勉[べん] 強[きょう]ちゅう　 休[やす]みちゅう　～ 月[がつ]ちゅう　 午[ご] 前[ぜん]ちゅう　 今[こん] 月[げつ]ちゅう　 水[すい]ちゅう\n常见的「～じゅう」的词汇\n家[いえ]じゅう　 教[きょう] 室[しつ]じゅう　 学[がっ] 校[こう]じゅう　 世[せ] 界[かい]じゅう　パートじゅう　 部[へ] 屋[や]じゅう　 町[まち]じゅう　 店[みせ]じゅう　 村[むら]じゅう\n一[いっ]か 月[げつ]じゅう　 一[いち] 年[ねん]じゅう　 今[こん] 月[げつ]じゅう　 今[こん] 週[しゅう]じゅう　 半[はん] 年[とし]じゅう　 一[ひと] 晩[ばん]じゅう　 年[ねん]じゅう', 729, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('3fe0c9fb-8084-48ef-93c8-9b673965ebb3', '51b89718-9955-4845-8ebd-ef201bebc5f6', '授業中だから、静かにしてください。', 'じゅぎょうちゅうだから、しずかにしてください。', '上课期间，请保持安静。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('ab7ce3fe-89f5-44fb-bc34-58cccb95353a', '51b89718-9955-4845-8ebd-ef201bebc5f6', 'あの山には一年じゅう雪があります。', 'あのやまにはいちねんゆきがあります。', '那山上一年四季都有雪。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('e8c82aff-3bcd-4296-8cd1-c6f2fc5a0ff8', '51b89718-9955-4845-8ebd-ef201bebc5f6', '1日じゅう仕事をして、疲れました。', 'いちにちしごとをして、つかれました。', '工作了整整一天，累了。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('b8499852-2ff3-453e-9752-6e33d7008858', '～ 人[にん/じん/ひと]', NULL, 'N5', '～ 人[にん/じん/ひと]', '～ 人[にん/じん/ひと]', '「にん」的前面多接数词，而「じん」的前面大多接国名或地名，「ひと」通常单独使用。', '一个人和两个人有特殊说法，即「ひとり」「ふたり」。', 730, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('1000cb43-2cd1-499d-8585-8e01412fcaec', 'b8499852-2ff3-453e-9752-6e33d7008858', '1つの会議室に20人入れます。', 'ひとつのかいぎしつににじゅうにんはいれます。', '一间会议室可容纳20人。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('af2c22ac-4351-4988-9c68-721819f0e004', 'b8499852-2ff3-453e-9752-6e33d7008858', '山田さんは日本人です。', 'やまださんはにほんじんです。', '山田是日本人。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('4a7880e3-81e0-48b2-ba94-2374030b2f64', 'b8499852-2ff3-453e-9752-6e33d7008858', 'あのレストランは予約した人しか入れません。', 'あのレストランはよやくひとしかはいれません。', '那家餐厅只接待预约过的顾客。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('678d4074-c47c-47a4-aa41-1be79e99e657', '～ずつ', NULL, 'N5', '～ずつ', '～ずつ', '“每……”；“一点一点地……”。', '「ずつ」表示“等比例地分发”和“以相同的数量或程度反复”。', 731, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('6637dbff-9549-4d28-9b4e-d36e89e9b10e', '678d4074-c47c-47a4-aa41-1be79e99e657', '1人に1つずつ、ケーキを分けましょう。', 'ひとりにひとつずつ、ケーキをわけましょう。', '一人一个把蛋糕分了吧。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('afa62938-eeae-4392-b4c0-dc6acc33d2d7', '678d4074-c47c-47a4-aa41-1be79e99e657', '毎日漢字を15ずつ習います。', 'まいにちかんじをじゅうごならいます。', '每天学15个汉字。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('4752e184-0b43-4081-9a56-2c83cb2776b9', '678d4074-c47c-47a4-aa41-1be79e99e657', '日本語が少しずつ上手になりました。', 'にほんごがすこじょうずになりました。', '日语一点一点地进步了。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('17855373-151b-4d75-8432-12599dcbf4f5', 'とても', NULL, 'N5', 'とても', 'とても', '后面接肯定表达，意为“非常……”。\n后面接否定表达，意为“怎么也（不）……”“无论如何也（不）……”。', NULL, 732, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('773a64a8-dd8c-4c13-bcc3-c31d8da10540', '17855373-151b-4d75-8432-12599dcbf4f5', '公園の花はとてもきれいだった。', 'こうえんのはなはとてもきれいだった。', '公园里的花很漂亮。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('4be79831-d2a0-44a2-87d6-c443d5ece15f', '17855373-151b-4d75-8432-12599dcbf4f5', '今日はとても暑いですね。', 'きょうあついですね。', '今天真热啊。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('18369ea7-ed4f-4b51-b108-d97d52fea111', '17855373-151b-4d75-8432-12599dcbf4f5', 'とても50歳には見えない。', 'ごじゅっさいにはみえない。', '一点看不出是50岁了。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('04c49f8d-5614-4713-9c89-9f6f0e6d76ca', 'あまり', NULL, 'N5', 'あまり', 'あまり', '后面接肯定表达，意为“非常……”“太……”。\n后面接否定表达，意为“（不）怎么……”“（不）太……”。', '「あまり」的口语说法为「あんまり」。', 733, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('a6807c83-0e58-4c42-bf6b-ddad8ecc2604', '04c49f8d-5614-4713-9c89-9f6f0e6d76ca', 'あまりおいしかったので、つい食べ過ぎてしまった。', 'あまりおいしかったので、ついたべすぎてしまった。', '因为太好吃了，所以不小心就吃多了。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('1dcd84df-e9cf-437a-8a9b-0fb04f357f37', '04c49f8d-5614-4713-9c89-9f6f0e6d76ca', 'あまり慌てると失敗するよ。', 'あわてるとしっぱいするよ。', '太慌张的话，会失败的哦。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('a544d07e-a00e-4877-8d64-335b43d06cf8', '04c49f8d-5614-4713-9c89-9f6f0e6d76ca', 'たくさんコピーしたから、紙があまりありません。', 'たくさんコピーしたから、かみがあまりありません。', '因为复印了很多，所以纸剩得不多了。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('9ebd5fbc-6636-4cda-ae2a-f575c9d7f1dc', '04c49f8d-5614-4713-9c89-9f6f0e6d76ca', 'わたしの部屋はあまりきれいじゃありません。', 'わたしのへやはあまりきれいじゃありません。', '我的房间不太整洁。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('0666c07d-c09d-44a3-a021-0fc9402c7da2', '04c49f8d-5614-4713-9c89-9f6f0e6d76ca', '昨日はあまり寒くありませんでした。', 'きのうさむくありませんでした。', '昨天不怎么冷。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('21838b53-14ed-440d-89f8-2f28fb8aa1e2', '少[すこ]し', NULL, 'N5', '少[すこ]し', '少[すこ]し', '“稍微，暂时；不远，一点”，表示程度轻。', NULL, 734, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('fb4e1cd3-f907-4e91-a390-e33e64b38acb', '21838b53-14ed-440d-89f8-2f28fb8aa1e2', 'もう少し静かにしてくださいませんか。', 'すこしずかにしてくださいませんか。', '能稍微安静点吗？', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('06931e3c-3ff1-47f7-a88d-671be1f9fce0', '21838b53-14ed-440d-89f8-2f28fb8aa1e2', '会社から少し行くと、銀行があります。', 'かいしゃすこいくと、ぎんこうがあります。', '公司前面不远处有一家银行。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('7aebbf2b-6470-412b-9c88-ed5842891107', 'ぜんぜん', NULL, 'N5', 'ぜんぜん', 'ぜんぜん', '「ぜんぜん」后接否定表达，表示完全否定。意为“完全（不）……”“根本（不）……”。', NULL, 735, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('49329026-9a54-4ab8-8859-79aa8a37d88b', '7aebbf2b-6470-412b-9c88-ed5842891107', 'そのことはぜんぜん知りません。', 'しりません。', '我根本不知道那件事。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('c6dcbdae-e096-4d86-9e86-a91bacca4ee8', '7aebbf2b-6470-412b-9c88-ed5842891107', '政治についてはぜんぜん興味がない。', 'せいじきょうみがない。', '对政治完全没兴趣。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('a360ad19-87a6-4e7d-9c5c-e70872c0f0ae', 'ほとんど', NULL, 'N5', 'ほとんど', 'ほとんど', '作为副词使用，可以表示“大体上”“差不多”的意思，也可以表示“差一点儿……”“几乎……”的意思。', NULL, 736, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('4758413d-4c1a-4c4f-8dc7-f7871fcda703', 'a360ad19-87a6-4e7d-9c5c-e70872c0f0ae', '仕事はほとんど終わりました。', 'しごとおわりました。', '工作差不多完成了。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('ac9d331b-dd29-4f73-ac8c-1dcd1ebe8755', 'a360ad19-87a6-4e7d-9c5c-e70872c0f0ae', '昨日は忙しくて、ほとんど寝なかった。', 'きのうはいそがねなかった。', '昨天太忙了，几乎没睡觉。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('4289806f-80d5-4add-af79-412d014d2400', 'いつも', NULL, 'N5', 'いつも', 'いつも', '“经常，总是”，表示一般的状态或习惯等。', NULL, 737, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('e84f071f-086d-4689-a858-b25a22283ee7', '4289806f-80d5-4add-af79-412d014d2400', 'トイレの掃除はいつもわたしがします。', 'トイレのそうじはいつもわたしがします。', '厕所的打扫一直是我做。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('9c7b8bf0-1ec6-4f87-b6a8-0af573fc6ed4', '4289806f-80d5-4add-af79-412d014d2400', 'このレストランはいつもたくさん人が並んでいますね。', 'このレストランはいつもたくさんひとがならんでいますね。', '这家餐厅总是排着很多人啊。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('63060e54-5b9c-44e6-9fd5-fdcaab0d16aa', 'どうぞ', NULL, 'N5', 'どうぞ', 'どうぞ', '“请……”。', '「どうぞ」表示请对方做某事，后面往往接尊敬的表达方式；关系较亲密的人之间根据前文可以省略后面的部分，直接用「どうぞ」结句。', 738, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('fd96fc23-9fdc-4fd1-bb40-f4fdd4bb1609', '63060e54-5b9c-44e6-9fd5-fdcaab0d16aa', 'どうぞご覧ください。', 'どうぞごらんください。', '请看。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('55e03317-9ebf-412b-8775-ecfbe669d27f', '63060e54-5b9c-44e6-9fd5-fdcaab0d16aa', 'お茶をどうぞ。', 'おちゃをどうぞ。', '请喝茶。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('3d1312f6-8d3b-4674-a7d8-38070f3b9e33', '63060e54-5b9c-44e6-9fd5-fdcaab0d16aa', 'A「この自転車を借りてもいいですか。」B「ええ、どうぞ。」', 'A「このじてんしゃをかりてもいいですか。」B「ええ、どうぞ。」', 'A：“我可以借用一下这辆自行车吗？”\nB：“嗯，你用吧。”', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('b6b6c35b-751a-4206-82e2-8b02f8ab347f', 'やっと', NULL, 'N5', 'やっと', 'やっと', '“终于……”。', '「やっと」表示经过艰苦的努力或是漫长的时间，愿望终于实现；后面经常接动词过去时。多用于表达喜悦、解脱、松了口气等情绪。', 739, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('9f11cb0d-85ee-432a-94bc-bc47a7a5ab5a', 'b6b6c35b-751a-4206-82e2-8b02f8ab347f', '難しい問題でしたが、やっと答えがわかりました。', 'むずかしいもんだいこたえがわかりました。', '问题很难，但是终于知道答案了。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('e412e419-19e0-4a99-8234-320631acc94a', 'b6b6c35b-751a-4206-82e2-8b02f8ab347f', '午後5時頃、雨がやっとやんだ。', 'ごごごじごろ、あめがやっとやんだ。', '下午五点左右，雨终于停了。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('df175731-7921-47a4-bafb-e259c11fb74b', 'b6b6c35b-751a-4206-82e2-8b02f8ab347f', '何週間も勉強しつづけて、やっと試験に合格できるようになりました。', 'なんしゅうかんもべんきょうしけんにごうかくできるようになりました。', '连着学了几周，终于能够及格了。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('bd3d8ed7-fc15-4cb0-9cfb-a0dcbfa183b0', 'ぜひ', NULL, 'N5', 'ぜひ', 'ぜひ', '“务必……”“一定……”。', '「ぜひ」用于自身时表示一定要做某事的强烈愿望，用于对方则表示非常希望对方做某事。', 740, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('cf370436-a5f3-4609-b691-2ee8f797d08f', 'bd3d8ed7-fc15-4cb0-9cfb-a0dcbfa183b0', '今度の試合はぜひ見たいです。', 'こんどのしあいみたいです。', '这次的比赛我非常想看。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('253cf824-7a9c-4c85-b90d-4f34ba5a771d', 'bd3d8ed7-fc15-4cb0-9cfb-a0dcbfa183b0', 'こちらにいらっしゃる機会があったら、ぜひお寄りください。', 'こちらにいらっしゃるきかいがあったら、ぜひおよりください。', '有机会到这里来的话，请一定要过来啊。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('373770ec-368c-416d-9999-46debc2cb06d', 'そろそろ', NULL, 'N5', 'そろそろ', 'そろそろ', '“差不多该……”。', '「そろそろ」表示时间上的迫近，即到时间该做某事了。', 741, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('a4ba2a21-1378-423a-ac6c-06c0a7ea7b95', '373770ec-368c-416d-9999-46debc2cb06d', '寒くなったのでそろそろ暖房がほしいですね。', 'さむだんぼうがほしいですね。', '天气转冷了，差不多也该要个电暖气了。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('d5fcca51-d413-4aa6-817c-8e1c6cabcc06', '373770ec-368c-416d-9999-46debc2cb06d', 'そろそろ食事にしましょう。', 'しょくじにしましょう。', '差不多是时间去吃饭了。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('39f07e92-799b-4402-83c8-eecbdb0950de', '373770ec-368c-416d-9999-46debc2cb06d', 'そろそろ失礼いたします。', 'しつれいいたします。', '差不多该告辞了。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('53679064-c973-48a6-8daf-234f16dceee5', '～をください', NULL, 'N5', '名词＋をください', '名词＋をください', '“给我……”“我要……”。表示向他人索取或购买某物。', '更礼貌的说法是「～をくださいませんか」。', 742, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('1be0375c-cfc8-4c4c-8da4-40d31477fe14', '53679064-c973-48a6-8daf-234f16dceee5', 'すみません、お水をください。', 'すみません、おみずをください。', '不好意思，请给我水。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('4fa26c96-90b8-43a2-9774-024ddfb4108a', '53679064-c973-48a6-8daf-234f16dceee5', '奨学金の申請用紙をくださいませんか。', 'しょうがくきんのしんせいようしをくださいませんか。', '能给我奖学金的申请表格吗？', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('7ecda4b0-abcb-49f2-85a5-3d678e938695', '～てください/ないでください', NULL, 'N5', '动词「て形」＋ください动词', '动词「て形」＋ください动词\n「ない形」＋でください', '“请（不要）……”。表示面对面的请求、命令或指示对方做某事或者不做某事。', '虽然表示礼貌的请求，但因其本身也带有命令的口气，所以一般不能对上司、长辈等要尊敬的人使用。', 743, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('47160512-f428-44e0-a272-678d84fa420c', '7ecda4b0-abcb-49f2-85a5-3d678e938695', '高いですね。もっと安くしてください。', 'たかいですね。もっとやすくしてください。', '太贵了，请给我便宜些吧。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('db98a461-e684-4c6e-b254-cd5b35887e06', '7ecda4b0-abcb-49f2-85a5-3d678e938695', 'この言葉を覚えてください。', 'このことばをおぼえてください。', '请记住这句话。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('01486c68-75bb-44d9-9d5d-95c04f2b9427', '7ecda4b0-abcb-49f2-85a5-3d678e938695', 'テストをしていますから静かにしてください。', 'テストをしていますからしずかにしてください。', '正在考试，所以请保持安静。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('a43bbd82-c993-4bea-b25a-364d26dad740', '7ecda4b0-abcb-49f2-85a5-3d678e938695', '大きな声で話さないでください。', 'おおきなこえではなさないでください。', '请不要大声说话。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('5035d75d-9f54-4de0-96af-58d5470c6ca5', '～てくださいませんか/ないでくださいませんか', NULL, 'N5', '动词「て形」＋くださいませんか', '动词「て形」＋くださいませんか\n动词「ない形」＋でくださいませんか', '“能否请您……”。', '此句型是「～てください/ないでください」更礼貌的说法。', 744, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('20449720-f442-4a9b-9ed6-87bb72f9f7b0', '5035d75d-9f54-4de0-96af-58d5470c6ca5', 'すみません、砂糖を取ってくださいませんか。', 'すみません、さとうをとってくださいませんか。', '不好意思，能递给我糖吗？', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('8a171c27-5be2-43d6-951a-b121be964e26', '5035d75d-9f54-4de0-96af-58d5470c6ca5', 'もう少し静かにしてくださいませんか。', 'もうすこししずかにしてくださいませんか。', '能稍微安静一点吗？', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('db27e3a7-41fa-4d1a-8d24-e67a76f5371e', '5035d75d-9f54-4de0-96af-58d5470c6ca5', 'わたしのものに触らないでくださいませんか。', 'わたしのものにさわらないでくださいませんか。', '请不要动我的东西，好吗？', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('c88a3057-edc2-4497-8e61-71c652e29023', '～ませんか', NULL, 'N5', '动词「ます形」＋ませんか', '动词「ます形」＋ませんか', '可以用于委婉的建议、劝诱，意为“一起做……好吗？”表示疑问时，意为“（你）不……吗？”。', NULL, 745, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('2f1f7758-c224-4de2-b15e-68b63c1dc7b8', 'c88a3057-edc2-4497-8e61-71c652e29023', '今日か明日、一緒にご飯を食べませんか。', 'きょうかあした、いっしょにごはんをたべませんか。', '今天或明天，一起吃个饭吧？', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('84c29167-5358-401d-8fe5-56ed8992224d', 'c88a3057-edc2-4497-8e61-71c652e29023', '昼ご飯の時間をもっと遅くしませんか。', 'ひるごはんのじかんをもっとおそくしませんか。', '把午饭时间稍微推后一点吧？', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('2281bcdb-7203-46ce-886d-05dc4e409cfa', '～ましょうか', NULL, 'N5', '动词「ます形」＋ましょうか', '动词「ます形」＋ましょうか', '“一起……吧”，用于邀请对方做某事。\n“……呢”“……啊”，表示委婉的疑问。', '此种用法和「～ますか」的语法意义基本相同。', 746, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('5da105b2-d3ba-4b31-96c1-45254b4ea35a', '2281bcdb-7203-46ce-886d-05dc4e409cfa', '中山「いますぐ出かけましょうか。」', 'なかやま「いますぐでかけましょうか。」', '“现在就出发吧。”', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('9ad7d3f5-fea3-4bb7-9ea2-0ba364c3c7f0', '2281bcdb-7203-46ce-886d-05dc4e409cfa', '上田「いいえ、掃除をしてから出かけましょう。」', 'うえだ「いいえ、そうじをしてからでかけましょう。」', '“不，打扫完再出发吧。”', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('733d2ecc-1f13-45ff-aacf-08664fe9d8e0', '2281bcdb-7203-46ce-886d-05dc4e409cfa', '結婚式に誰を招待しましょうか。', 'けっこんしきにだれをしょうたいしましょうか。', '婚礼要邀请哪些人啊？', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('e3a223c0-6507-4536-b902-b7fc5c6aa3f2', '2281bcdb-7203-46ce-886d-05dc4e409cfa', '明日のパーティーは、どんな飲み物を準備しましょうか。', 'あしたのパーティーは、どんなのみものをじゅんびしましょうか。', '明天的派对，该准备什么饮料呢？', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('a9aaa59f-64a1-41c7-9021-020a2d6259a8', '～ましょう', NULL, 'N5', '动词「ます形」＋ましょう', '动词「ます形」＋ましょう', '“……吧”，用于邀请、建议对方做某事。语气比「～ましょうか」强烈。\n“（我）……吧”，用于说话人主动提起做某事。', NULL, 747, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('7027dbc6-6d5f-4b8e-8b85-fc71c2c135da', 'a9aaa59f-64a1-41c7-9021-020a2d6259a8', 'この橋を渡って向こうに行きましょう。', 'このはしをわたってむこうにいきましょう。', '过了这座桥去对面吧。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('450d168b-55d1-4ace-9803-0dc4135fe060', 'a9aaa59f-64a1-41c7-9021-020a2d6259a8', '駅まで一緒に帰りましょう。', 'えきまでいっしょにかえりましょう。', '一起走到车站吧。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('6dad57c5-906b-4577-9e1c-8c18df84fb06', 'a9aaa59f-64a1-41c7-9021-020a2d6259a8', 'わたしの傘をお貸ししましょう。', 'わたしのかさをおかししましょう。', '我把伞借给你吧。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('baa70753-f57b-42b8-a8c7-a0efbe3fafa3', '～たい', NULL, 'N5', '动词「ます形」＋たい', '动词「ます形」＋たい', '“（我）想……”。表示第一人称的愿望、想法。', '疑问句「～たいですか」可以用在第二、第三人称上。另外，「～たいですか」一般不用来面对面询问上司、长辈等理应尊敬的人的愿望、欲望。', 748, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('84d45795-37d9-4aea-9d27-908f2ca4ea3d', 'baa70753-f57b-42b8-a8c7-a0efbe3fafa3', 'いつかまた日本へ来たいです。', 'いつかまたにほんへきたいです。', '什么时候想再来日本。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('d64b23c2-979d-48fa-a3e8-6208dea27549', 'baa70753-f57b-42b8-a8c7-a0efbe3fafa3', '今年の夏は海で泳ぎたいです。', 'ことしのなつはうみでおよぎたいです。', '今年夏天想在海里游泳。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('ecf7aee3-2891-4e25-8908-854a43fd97c1', 'baa70753-f57b-42b8-a8c7-a0efbe3fafa3', '果物が食べたいです。', 'くだものがたべたいです。', '我想吃水果。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('a101e0ce-3aea-4754-9e89-9647e49a2e05', '～がほしい', NULL, 'N5', '名词＋がほしい', '名词＋がほしい', '表示第一人称想要得到某种东西的愿望。', '同「～たいですか」一样，「～がほしいですか」也可以用在第二、第三人称上，而且一般不用来面对面询问上司、长辈等理应尊敬的人的愿望、欲望。', 749, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('0ff546aa-b730-436e-aa50-b0aa3e73fc37', 'a101e0ce-3aea-4754-9e89-9647e49a2e05', 'わたしは自転車がほしいです。', 'わたしはじてんしゃがほしいです。', '我想要自行车。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('5e1d684e-3b52-4155-9143-f3bd78f28500', 'a101e0ce-3aea-4754-9e89-9647e49a2e05', '新しい洋服がほしいです。', 'あたらしいようふくがほしいです。', '我想要新衣服。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('efa583fa-1bf7-43e2-b748-f6bf968a8327', '～だろう/でしょう', NULL, 'N5', '～だろう/でしょう', '～だろう/でしょう', '常和确信程度不高的「たぶん」「おそらく」等副词呼应使用，表示说话人的主观推测。和确信程度较高的「 必[かなら]ず」「きっと」等副词呼应使用，表示说话人较为肯定的判断。', '「でしょう」是「だろう」的礼貌用法。', 750, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('65817837-529c-4ef8-83f8-ff351f74ac5f', 'efa583fa-1bf7-43e2-b748-f6bf968a8327', '田中さんはたぶん歌が上手でしょう。', 'たなかさんはたぶんうたがじょうずでしょう。', '田中唱歌应该很好听吧。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('67c696a8-3adc-439c-9764-887a6d224a30', 'efa583fa-1bf7-43e2-b748-f6bf968a8327', '部屋の電気が消えているということは、たぶんもう寝たのでしょう。', 'へやのでんきがきえているということは、たぶんもうねたのでしょう。', '房间的灯关了，或许是已经睡了吧。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('ca952776-6cad-4bec-8dd1-39cc6995c111', 'efa583fa-1bf7-43e2-b748-f6bf968a8327', 'たぶん明日も風が強いだろう。', 'たぶんあしたもかぜがつよいだろう。', '或许明天也会刮大风吧。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('f68c8a3d-4e69-4eb3-baa9-226b277a109d', '～にする/くする', NULL, 'N5', 'な形容词词干/名词＋にする', 'な形容词词干/名词＋にする\nい形容词词干＋くする', '表示人为的改变、改造，使其达到期望的结果。', '「～にする」还可以表示选择。', 751, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('950f7ddd-d6be-48b0-bc37-f4b8bc5ab7f9', 'f68c8a3d-4e69-4eb3-baa9-226b277a109d', 'すみませんが、少し静かにしてください。', 'すみませんが、すこししずかにしてください。', '不好意思，请保持安静。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('eeb3afc5-ab11-4ef8-b6f9-45b47f676e89', 'f68c8a3d-4e69-4eb3-baa9-226b277a109d', 'バナナを半分にして一緒に食べましょう。', 'バナナをはんぶんいっしょにたべましょう。', '把香蕉分成两半一起吃吧。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('e6b76fdd-662f-488b-86c6-3f8d957877e5', 'f68c8a3d-4e69-4eb3-baa9-226b277a109d', '高いですね。もっと安くしてください。', 'たかいですね。もっとやすくしてください。', '太贵了，请再便宜点。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('f932213c-c0b0-4367-80fb-95814860193e', 'f68c8a3d-4e69-4eb3-baa9-226b277a109d', '母の誕生日のプレゼントはセーターにしました。', 'ははのたんじょうびのプレゼントはセーターにしました。', '选了毛衣作为妈妈的生日礼物。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('06ea7d95-98e1-4205-9951-0becd4f32e33', '～になる/くなる', NULL, 'N5', 'な形容词词干/名词＋になる', 'な形容词词干/名词＋になる\nい形容词词干＋くなる', '表示事物自然而然变化的结果。', '与「～にする/くする」强调人为的作用相比，「～になる/くなる」更强调事物变化产生的结果。另外，「～になる」还有表示客观决定的用法。', 752, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('9dea85c6-419d-425e-93e5-eb427e34ab07', '06ea7d95-98e1-4205-9951-0becd4f32e33', '寿司が好きになりました。', 'すしがすきになりました。', '变得喜欢吃寿司了。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('152437a9-c95c-4839-bf30-eaafcb758539', '06ea7d95-98e1-4205-9951-0becd4f32e33', '大学の友だちは、英語の先生になりました。', 'だいがくのともだちは、えいごのせんせいになりました。', '大学时的朋友成了一名英语老师。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('6d9c875f-99bd-427d-afbc-7684aa67affa', '06ea7d95-98e1-4205-9951-0becd4f32e33', 'たくさん歩いたから、足が痛くなりました。', 'たくさんあるいたから、あしがいたくなりました。', '走了很多路，脚痛了。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('27f25b8d-9a67-4ecd-a01e-8bf30f7668bd', '06ea7d95-98e1-4205-9951-0becd4f32e33', '今度国に帰ることになりました。', 'こんどくににかえることになりました。', '这次决定回国。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('710e3531-afc6-4d1a-9413-0b70a14a7e61', '～ている', NULL, 'N5', '动词「て形」＋いる', '动词「て形」＋いる', '“（正）在……”。表示动作正在进行，或者表示平时反复进行的某种习惯性行为。\n“……了”“……着”。表示动作、作用完成之后所呈现的状态，或者其作用后的结果还保留着的状态。', '此种用法前接持续性动词。\n此用法前接瞬间性动词。', 753, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('5148de64-1791-47b6-8441-696583b20eb7', '710e3531-afc6-4d1a-9413-0b70a14a7e61', '子どもたちが歌を上手に歌っています。', 'こどもたちがうたをじょうずにうたっています。', '孩子们娴熟地唱着歌。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('d26bfd3e-1b96-40f3-b58e-08f5cbdbbff7', '710e3531-afc6-4d1a-9413-0b70a14a7e61', '何か運動をしていますか。', 'なにかうんどうをしていますか。', '你平时在做什么运动吗？', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('2ff64190-87ad-455d-a43d-68218f7c7014', '710e3531-afc6-4d1a-9413-0b70a14a7e61', '先生は眼鏡をかけています。', 'せんせいはめがねをかけています。', '老师戴着眼镜。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('ddd668ac-8d6f-4c64-bc77-60ec5aa5149a', '710e3531-afc6-4d1a-9413-0b70a14a7e61', '図書館の本はまだ返していません。', 'としょかんのほんはまだかえしていません。', '图书馆的书还没还。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('b4bce938-17d1-433a-9e4f-c25931a8878a', '710e3531-afc6-4d1a-9413-0b70a14a7e61', 'ドアが閉まっています。', 'ドアがしまっています。', '门关着呢。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('168d2dbd-979f-49ff-bff7-e2274df509b6', '～てある', NULL, 'N5', '～が/は＋他动词「て形」＋ある', '～が/は＋他动词「て形」＋ある', '“……着”。表示有目的性地完成某项动作、行为后，其结果或状态依旧保留。', '「～てある」表示动作完成后形成的某种状态。原本出现在他动词前面的宾格助词「を」，在此句型中需改为「が/は」。', 754, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('09df420a-3fa9-44eb-901e-2498b2d02fd5', '168d2dbd-979f-49ff-bff7-e2274df509b6', '教室に試験の時間割が貼ってあります。', 'きょうしつにしけんのじかんわりがはってあります。', '教室里贴着考试时间表。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('02ad23e7-ab14-49eb-9194-6188d7a7e4b8', '168d2dbd-979f-49ff-bff7-e2274df509b6', '冷蔵庫にはビールが2本入れてあります。', 'れいぞうこにはビールがにほんいれてあります。', '冰箱里放着两罐啤酒。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('adcdd158-cf34-45a0-b30b-6119711e9447', '168d2dbd-979f-49ff-bff7-e2274df509b6', '部屋に花が飾ってあります。', 'へやにはながかざってあります。', '房间里装饰着花。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('9b489abc-344a-4a3f-8019-332cf9ed84ab', 'もう～', NULL, 'N5', 'もう～', 'もう～', '“已经……了”。后面接动词「た形」，表示动作的完了。这种情况下「もう」的声调为①。\n“已经（不）……”“再也（不）……”，后面接否定表达。这种情况下「もう」的声调为①。\n「もう＋数量词/副词」，意为“再，另外”，表示在原来基础上再累加一些数量或程度。这种情况下「もう」的声调为⓪。', NULL, 755, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('2bd3a595-052a-4843-855f-bf889c8a21ee', '9b489abc-344a-4a3f-8019-332cf9ed84ab', '子どもたちはもう公園に行ったから、うちにはいません。', 'ここうえんにいったから、うちにはいません。', '孩子们已经去公园了，所以不在家。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('1f5e11d2-f8b7-4e1f-a0f1-ec3e1023abaa', '9b489abc-344a-4a3f-8019-332cf9ed84ab', 'みんながたくさん飲みましたから、もうお酒はありません。', 'みんながたくさんのみましたから、もうおさけはありません。', '大家都喝了很多，所以酒已经没了。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('0e7b18af-309a-4f34-be1f-95eeb2179b56', '9b489abc-344a-4a3f-8019-332cf9ed84ab', '牛乳は全部飲みました。もうありません。', 'ぎゅうにゅうはぜんぶのみました。もうありません。', '牛奶全喝完了，已经没了。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('e11e3ff6-6f32-4166-b025-0ab03f268496', '9b489abc-344a-4a3f-8019-332cf9ed84ab', 'これからもうたばこを吸いません。', 'これからもうたばこをすいません。', '从今以后再也不吸烟了。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('8c889df0-be74-4451-a877-e7bfaa06ca63', '9b489abc-344a-4a3f-8019-332cf9ed84ab', 'もう少し待ったほうがいいですよ。', 'すこしまったほうがいいですよ。', '再稍微等一下比较好。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('1adf26f5-e356-4115-aa71-6efcc090bfeb', '9b489abc-344a-4a3f-8019-332cf9ed84ab', 'もう少し静かにしてくださいませんか。', 'すこししずかにしてくださいませんか。', '能稍微再安静点吗？', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('efca57d8-ccdd-4948-b580-6cfcdb49a81c', 'まだ～', NULL, 'N5', 'まだ～', 'まだ～', '“还……”。后面接肯定表达，表示某状态到目前为止还持续着或某动作到现在还在继续。\n“还（未）……”“还（没有）……”。后面接否定表达，表示动作尚未发生或者尚未结束，暗示接下来将做该动作或者该动作即将结束。', '除了名词句和表示存在的动词「ある/いる」之外，动词一般要用「まだ～ている/ています」的形式。\n此种情况下，若动词是持续性动词，一般要用「まだ～ていない/ていません」的形式。', 756, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('c782b205-15cd-4127-992a-e535e7b4099b', 'efca57d8-ccdd-4948-b580-6cfcdb49a81c', 'まだ郵便局は開いています。早く行きましょう。', 'ゆうびんきょくはあいています。はやくいきましょう。', '邮局还开着呢。快点去吧。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('d634eb28-eea8-4649-83f5-0071cf0b6836', 'efca57d8-ccdd-4948-b580-6cfcdb49a81c', '次のバスまでまだ1時間あるから、喫茶店に行きましょう。', 'つぎいちじかんあるから、きっさてんにいきましょう。', '到下一班公交车来还有一个小时呢，去咖啡店坐坐吧。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('9823bd7e-a4d1-4a8b-8982-aaf0a6a5454e', 'efca57d8-ccdd-4948-b580-6cfcdb49a81c', 'ジュースはもうありませんが、コーヒーはまだあります。', 'ジュースはもうありませんが、コーヒーはまだあります。', '果汁已经没了，咖啡还有。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('069ac896-06fa-48e6-b657-c463c57c80e1', 'efca57d8-ccdd-4948-b580-6cfcdb49a81c', 'パーティーはまだ始まりません。', 'はじまりません。', '聚会还没开始。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('caf41397-ce3f-4e08-8c9d-aff1e88e5790', 'efca57d8-ccdd-4948-b580-6cfcdb49a81c', '図書館の本はまだ返していません。', 'としょかんのほんかえしていません。', '图书馆的书还没还呢。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('1fb08dfe-655e-42de-a3d9-c24bd2945148', '～ほうが～', NULL, 'N5', '～ほうが～', '～ほうが～', '“还是……比较……”。', '「～ほうが」表示做出选择。后面常接「いい」等，表示委婉的劝告或建议。', 757, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('4fe9827b-d2dc-4a1b-8c4d-69a0c206b766', '1fb08dfe-655e-42de-a3d9-c24bd2945148', 'もう少し待ったほうがいいですよ。', 'もうすこしまったほうがいいですよ。', '再稍微等一下比较好。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('2d9d13e2-21f8-4674-ab72-3fd3484453c6', '1fb08dfe-655e-42de-a3d9-c24bd2945148', '熱が高いときは、無理をしないほうがいい。', 'ねつがたかいときは、むりをしないほうがいい。', '发烧的时候还是不要硬撑了。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('c8d63b14-7de7-4545-9c9e-765f3119a9a1', '1fb08dfe-655e-42de-a3d9-c24bd2945148', '風がとても強いので、外に出ないほうが安全だ。', 'かぜがとてもつよいので、そとにであんぜんだ。', '风很大，还是不出去比较安全。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('6377a1e8-b7e6-420e-a763-cde385667d60', '～ 前[まえ]に', NULL, 'N5', '名词＋の/动词辞书形＋ 前[まえ]に', '名词＋の/动词辞书形＋ 前[まえ]に', '表示做前项动作之前，先把后项的动作做完。', '后项动词即使是过去时，「 前[まえ]に」前面的动词也要用辞书形。', 758, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('71ad6431-52f4-46dc-9452-5d19bbd7d3b9', '6377a1e8-b7e6-420e-a763-cde385667d60', '面接の前にいろいろ準備をしました。', 'めんせつまえにいろいろじゅんびをしました。', '面试之前，做了各种各样的准备。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('63870df2-5082-4fd8-bc20-c85461253c4b', '6377a1e8-b7e6-420e-a763-cde385667d60', '寝る前に歯を磨いてください。', 'ねまえはをみがいてください。', '睡觉之前请刷牙。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('a3297ac7-fb22-4499-84d2-e5d71cbc47d4', '～とき', NULL, 'N5', '～とき', '～とき', '“在……的时候”。', NULL, 759, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('5e2d97ac-101e-403e-8f6b-dcd57b600716', 'a3297ac7-fb22-4499-84d2-e5d71cbc47d4', 'わからないときは、先生に聞きます。', 'わからないときは、せんせいにききます。', '不明白的时候，问老师。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('60e7a99c-cf4d-4344-ba99-5df0b46b8ddb', 'a3297ac7-fb22-4499-84d2-e5d71cbc47d4', '妹が生まれたとき、父は外国にいました。', 'いもうとがうまれたとき、ちちはがいこくにいました。', '妹妹出生的时候，爸爸在国外。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('6deb965e-ce43-4efc-b0ec-bb4cdf944f80', 'a3297ac7-fb22-4499-84d2-e5d71cbc47d4', '暑いとき、冷たいコーヒーを飲みます。', 'あついとき、つめたいコーヒーをのみます。', '热的时候喝冰咖啡。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('d73ceac7-0e8b-4e33-a67f-7e1a9986fc77', 'a3297ac7-fb22-4499-84d2-e5d71cbc47d4', '子どものとき野菜が好きではありませんでした。', 'こやさいがすきではありませんでした。', '小时候不喜欢吃蔬菜。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('97be30c7-3bed-4ead-98d7-795951b2f4a4', '場[ば] 合[あい]', NULL, 'N5', '場[ば] 合[あい]', '場[ば] 合[あい]', '“在……情况下”，后项大多为采取相应措施或对策的句子。', '「 場[ば] 合[あい]」前项大多是负面情况或不希望出现的事情，较少用于积极或有利的情况。', 760, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('33a041c2-5930-43a0-ae72-8c517c10214a', '97be30c7-3bed-4ead-98d7-795951b2f4a4', '財布が盗まれた場合、すぐ警察を呼んでください。', 'さいふがぬすばあい、すぐけいさつをよんでください。', '钱包被偷的情况，请立刻报警。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('baca5e4e-7f76-4d3b-a09a-dc70f855ff23', '97be30c7-3bed-4ead-98d7-795951b2f4a4', '体の調子が悪い場合は、少し休んだほうがいいです。', 'からだのちょうしがわるばあいは、すこしやすんだほうがいいです。', '身体不舒服的话，稍微休息一下比较好。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('4a00943f-686e-4954-a9fb-475cb69f4c7a', '97be30c7-3bed-4ead-98d7-795951b2f4a4', '雨の場合は、試合を中止にします。', 'あめばあいは、しあいをちゅうしにします。', '下雨的话，就取消比赛。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('cb6143ad-40d7-43b3-aab7-cb2b61405b8e', '～てから', NULL, 'N5', '动词「て形」＋から', '动词「て形」＋から', '表示前后两个动作发生时间的既定性，即一定是先发生前项，接着出现后项。', '「～てから」前后两个动作之间的间隔时间不能太长。', 761, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('1f022d1f-88b5-48ee-8f45-0a2aef6cfe25', 'cb6143ad-40d7-43b3-aab7-cb2b61405b8e', '毎日お風呂に入ってから寝ます。', 'まいにちおふろにはいねます。', '每天都洗完澡后，再上床睡觉。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('383936af-0680-4308-bb5d-9e7a4d1659c9', 'cb6143ad-40d7-43b3-aab7-cb2b61405b8e', 'テープを入れてから、一番右のボタンを押します。', 'テープをいれてから、いちばんみぎのボタンをおします。', '磁带放进去之后，再按一下最右边的按钮。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('0ae5252e-5cee-4105-b10f-86fde8efe226', '～あとで', NULL, 'N5', '动词「た形」＋あとで', '动词「た形」＋あとで\n名词＋の＋あとで', '表示做完一件事情后做另外一件事，用于客观地叙述事情发生的顺序。强调在前项发生之后进行后项的动作，行为。', '「～あとで」前后两个动作之间的间隔时间可长可短。要重点掌握它和「～てから」接续的区别。', 762, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('b7202739-3bd4-4b76-9b0d-c4829c31059d', '0ae5252e-5cee-4105-b10f-86fde8efe226', '家族が出かけたあとで、部屋の掃除をします。', 'かぞくがでかけたあとで、へやのそうじをします。', '家人都出门后，再打扫房间。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('a06a1c3b-91ac-46bb-9de9-6efb4850cb54', '0ae5252e-5cee-4105-b10f-86fde8efe226', '食事のあとで、映画を見に行きませんか。', 'しょくじのあとで、えいがをみにいきませんか。', '吃完饭后，去看电影吧？', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('f4ddfc78-d691-4a9a-a445-f602903c00a6', '～ほかに（は）', NULL, 'N5', '名词＋の＋ほかに（は）', '名词＋の＋ほかに（は）', '“除了……以外”。', NULL, 763, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('9850a062-60e5-446b-baac-2ce2b6a692d6', 'f4ddfc78-d691-4a9a-a445-f602903c00a6', 'ペンのほかに、何か必要なものがありますか。', 'ペンのほかに、なにかひつようなものがありますか。', '除了钢笔还有什么需要的东西吗？', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('72905e21-3824-4cda-b7ce-2393d56c66b1', 'f4ddfc78-d691-4a9a-a445-f602903c00a6', 'ピアノのほかには、ギターも弾けますよ。', 'ピアノのほかには、ギターもひけますよ。', '除了钢琴我还会弹吉他哟。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('8873a97a-b746-4f7c-ab35-24283d9d2327', '～と～とどちらが～か', NULL, 'N5', '～と～とどちらが～か', '～と～とどちらが～か', '“……和……哪个……？”。', '「～と～とどちらが～か」属于选择疑问句，只对两者进行比较。', 764, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('6614d515-dbf8-4f24-a19e-9640dab13c2b', '8873a97a-b746-4f7c-ab35-24283d9d2327', 'スポーツをするのと、見るのとどちらが好きですか。', 'スポーツをするのと、みすきですか。', '对于体育活动，你是喜欢参与其中呢，还是喜欢观看呢？', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('cc420833-44c7-463e-870b-327833be121d', '8873a97a-b746-4f7c-ab35-24283d9d2327', 'この大学とあの大学とどちらが近いですか。', 'このだいがくとあのだいがくちかいですか。', '这所大学和那所大学，哪一所更近？', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('42164b5e-90d0-4919-8b4d-200bf3f6a99a', '8873a97a-b746-4f7c-ab35-24283d9d2327', 'バスと電車とどちらがいいですか。', 'でんしゃとどちらがいいですか。', '公交车和电车哪个比较好？', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('f7617493-983a-4a56-be49-4229f8217740', '～で～がいちばん～', NULL, 'N5', '～で～がいちばん～', '～で～がいちばん～', '“在……当中，……是最……的”。', '「～で～がいちばん～」表示限定的范围内的最高级。', 765, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('8da04e9d-bd45-4da1-9762-54fea0a29e96', 'f7617493-983a-4a56-be49-4229f8217740', 'クラスで王さんがいちばん背が高い人です。', 'おうせがたかい人です。', '小王是班里个子最高的。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('f605b207-a2a9-4f07-a8cf-39f2567fbff8', 'f7617493-983a-4a56-be49-4229f8217740', '日本で富士山がいちばん有名な山です。', 'にほんふじさんゆうめいなやまです。', '富士山是日本最有名的山。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('994ab194-4cfa-40bb-822d-2076938525ba', 'f7617493-983a-4a56-be49-4229f8217740', '学校で上田先生がいちばん優しいです。', 'がっこううえだせんせいやさしいです。', '学校里上田老师最温柔。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('11c4d890-6b31-42ea-b859-a00ea6a9489d', '常用寒暄用语 - 1', NULL, 'N5', '常用寒暄用语 - 1', '常用寒暄用语 - 1', NULL, NULL, 766, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('97fe88f2-ed61-47eb-af7d-9ac351c6158e', '11c4d890-6b31-42ea-b859-a00ea6a9489d', 'ありがとうございます。', 'ありがとうございます。', 'ありがとうございます。 → 谢谢。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('8d0bf0e5-a3ac-4d61-bec5-72c1d78dc610', '11c4d890-6b31-42ea-b859-a00ea6a9489d', 'いいえ、かまいません。', 'いいえ、かまいません。', 'いいえ、かまいません。 → 没关系。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('86036f3e-3df3-4955-b52f-b24e1dc805fa', '11c4d890-6b31-42ea-b859-a00ea6a9489d', 'いただきます。', 'いただきます。', 'いただきます。 → 我开始吃饭了；我收下了。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('c0131431-f26f-4ea3-adae-f163a4b763da', '11c4d890-6b31-42ea-b859-a00ea6a9489d', 'いってきます。', 'いってきます。', 'いってきます。 → 我出去了。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('d8b8034a-ef85-437a-8fb0-47823e5cdf9c', '11c4d890-6b31-42ea-b859-a00ea6a9489d', 'いってらっしゃい。', 'いってらっしゃい。', 'いってらっしゃい。 → 您走好。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('52afa1a1-039a-4cee-beac-e788fdb8c737', '11c4d890-6b31-42ea-b859-a00ea6a9489d', 'いらっしゃいませ。', 'いらっしゃいませ。', 'いらっしゃいませ。 → 欢迎光临。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('d1cd418e-d689-4437-8fbf-da16c88adca0', '11c4d890-6b31-42ea-b859-a00ea6a9489d', 'お帰りなさい。', 'おかえりなさい。', 'お 帰[かえ]りなさい。 → 您回来了。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('76c48cac-e360-47b5-a546-cedcb986bb19', '11c4d890-6b31-42ea-b859-a00ea6a9489d', 'おかげさまで、元気です。', 'おかげさまで、げんきです。', 'おかげさまで、 元[げん] 気[き]です。 → 托您的福，我很好。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('60a3dd22-2083-4a90-ae00-e386df37ffc9', '11c4d890-6b31-42ea-b859-a00ea6a9489d', 'お元気で。', 'おげんきで。', 'お 元[げん] 気[き]で。 → 多保重。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('ab897f7d-f0dc-41b0-974f-2cd1a7b04cd1', '11c4d890-6b31-42ea-b859-a00ea6a9489d', 'お大事に。', 'おだいじに。', 'お 大[だい] 事[じ]に。 → 多保重。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('86af9933-ec0b-492e-9f10-ae5336ea1afd', '11c4d890-6b31-42ea-b859-a00ea6a9489d', 'お願いします。', 'おねがいします。', 'お 願[ねが]いします。 → 拜托了。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('95dee728-81ce-4d1f-842c-63d2a8f89026', '11c4d890-6b31-42ea-b859-a00ea6a9489d', 'おはようございます。', 'おはようございます。', 'おはようございます。 → 早上好。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('f3fc192c-3879-4bc7-b6d9-da02dbf36914', '11c4d890-6b31-42ea-b859-a00ea6a9489d', 'お休みなさい。', 'おやすみなさい。', 'お 休[やす]みなさい。 → 晚安。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('2bad2d6b-8ea7-46b5-be23-20ad96d580a0', '11c4d890-6b31-42ea-b859-a00ea6a9489d', 'かしこまりました。', 'かしこまりました。', 'かしこまりました。 → 我知道了。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('de3d24c7-37c7-4d54-8604-bae8122f3617', '11c4d890-6b31-42ea-b859-a00ea6a9489d', 'ごちそうさまでした。', 'ごちそうさまでした。', 'ごちそうさまでした。 → 多谢款待。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('4368c2c0-d02e-42cd-8f06-f08487c3bdad', '11c4d890-6b31-42ea-b859-a00ea6a9489d', 'こちらこそ。', 'こちらこそ。', 'こちらこそ。 → 哪里哪里。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('44f6dcf7-043a-4a45-90d6-273990c69fa1', '11c4d890-6b31-42ea-b859-a00ea6a9489d', 'ごめんなさい。', 'ごめんなさい。', 'ごめんなさい。 → 对不起。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('756a8642-00ab-4862-abdc-92eb61d2f031', '11c4d890-6b31-42ea-b859-a00ea6a9489d', 'こんにちは。', 'こんにちは。', 'こんにちは。 → 你好。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('4faf152c-c0cf-401b-b50b-ec4785d4c68f', '11c4d890-6b31-42ea-b859-a00ea6a9489d', 'こんばんは。', 'こんばんは。', 'こんばんは。 → 晚上好。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('b7db4d06-19d9-4296-95fb-cac31a23c8f4', '11c4d890-6b31-42ea-b859-a00ea6a9489d', 'さようなら。', 'さようなら。', 'さようなら。 → 再见。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('b1cb48f3-2eaa-458f-b8d6-f28d943bfed3', '11c4d890-6b31-42ea-b859-a00ea6a9489d', '失礼します。', 'しつれいします。', '失[しつ] 礼[れい]します。 → 再见。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('b117508d-1537-45fb-bfbb-d1c5b99a6d18', '11c4d890-6b31-42ea-b859-a00ea6a9489d', 'すみません。', 'すみません。', 'すみません。 → 对不起；请问……', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('2107ef03-b989-4336-81af-e717b343e726', '11c4d890-6b31-42ea-b859-a00ea6a9489d', 'ただいま。', 'ただいま。', 'ただいま。 → 我回来了。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('c7154de4-8e85-4840-a644-3d7701bb3f34', '11c4d890-6b31-42ea-b859-a00ea6a9489d', 'では、また（あした）。', 'では、また（あした）。', 'では、また（あした）。 → 回头见（明天见）。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('403111a6-b4ab-43b9-8f0c-aeccbc8ea169', '11c4d890-6b31-42ea-b859-a00ea6a9489d', 'どういたしまして。', 'どういたしまして。', 'どういたしまして。 → 不用谢。', NULL, NOW(), NOW());
INSERT INTO grammar_lessons (id, title, title_zh, jlpt_level, pattern, explanation, explanation_zh, usage_notes, order_index, created_at, updated_at) VALUES ('98169018-085f-445d-98e6-773d3e26e28b', '常用寒暄用语 - 2', NULL, 'N5', '常用寒暄用语 - 2', '常用寒暄用语 - 2', NULL, NULL, 766, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('f79b07a6-34dd-40ba-80e7-501c6ecb1c7d', '98169018-085f-445d-98e6-773d3e26e28b', 'どうぞよろしく。', 'どうぞよろしく。', 'どうぞよろしく。 → 请多关照。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('b52e2a86-21b9-4839-a803-41490f5ab9d5', '98169018-085f-445d-98e6-773d3e26e28b', 'はじめまして。', 'はじめまして。', 'はじめまして。 → 初次见面。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('ac6749f4-b1e8-495c-9fc3-9ecd03266bed', '98169018-085f-445d-98e6-773d3e26e28b', '久しぶりです。', 'ひさしぶりです。', '久[ひさ]しぶりです。 → 好久不见。', NULL, NOW(), NOW());
INSERT INTO grammar_examples (id, grammar_lesson_id, sentence, reading, meaning_zh, audio_url, created_at, updated_at) VALUES ('61e61e8b-6c72-44e5-8356-3cdea3da7d46', '98169018-085f-445d-98e6-773d3e26e28b', 'わかりました。', 'わかりました。', 'わかりました。 → 明白了。', NULL, NOW(), NOW());
